# ── 1. DEPENDENCIES ───────────────────────────────────────────────────────────

required_packages <- c("shiny", "shinydashboard", "DT", "DBI", "ggplot2",
                        "jsonlite", "survival", "scales", "broom",
                        "survminer", "car")

# v10.13: Schema overlap Venn diagram uses eulerr for proportional layout.
# Soft import - Venn falls back to a count-only legend if not installed.
overlap_optional_packages <- c("eulerr")

# AIRA integration (v10) - optional soft-imports. The cohort builder works
# fully without AIRA; the natural-language cohort drafting feature is hidden
# when any of these packages, or AIRA itself, is unavailable.
aira_optional_packages <- c("ellmer", "promises", "future")

# v10.14: OHDSI Tools tab - optional soft-imports. cohortbuilder runs its own
# SQL against the workspace DB for every other tab; the OHDSI Tools tab uses
# the community-standard R ecosystem (RPostgres + CDMConnector + OmopSketch) to
# demonstrate interoperability. The app runs identically when these are absent;
# the tab then shows a "not installed" state. NEVER added to the guard loop.
ohdsi_optional_packages <- c("RPostgres", "CDMConnector", "omopgenerics", "OmopSketch",
                             "visOmopResults", "gt", "CohortCharacteristics")

# ── Self-provisioning: install any missing packages at startup ────────────────
# Attempts to install missing dependencies when the app starts. This assumes the
# workspace can reach a package repository. If it cannot, each install fails
# quietly and the requireNamespace guards below handle the outcome, so startup
# is never blocked by a failed install. Only missing packages are installed, so
# a warm workspace pays no cost; a cold one pays it once. omopdependencies.R
# remains the canonical provisioning script (it also covers dev/test packages
# such as omock, duckdb and Eunomia); keep the two in step when adding packages.
local({
  manifest <- unique(c(
    required_packages, overlap_optional_packages, aira_optional_packages,
    ohdsi_optional_packages,
    # darwin-eu / OHDSI standards packages used by the survival, incidence and
    # diagnostics features (guarded individually elsewhere via requireNamespace).
    "dplyr", "dbplyr", "CohortConstructor", "PatientProfiles",
    "CodelistGenerator", "PhenotypeR", "IncidencePrevalence",
    "CohortSurvival", "flextable"
  ))
  missing <- manifest[!vapply(manifest, requireNamespace, logical(1),
                              quietly = TRUE)]
  if (length(missing) > 0) {
    repos <- getOption("repos")
    if (is.null(repos) || length(repos) == 0 || any(repos %in% c("@CRAN@", "", NA)))
      repos <- c(CRAN = Sys.getenv("CRAN_MIRROR", "https://cloud.r-project.org"))
    options(repos = repos)

    # CRAN-only packages take no GitHub fallback; the OHDSI tidy stack falls back
    # to darwin-eu/<pkg>, with explicit overrides for packages hosted elsewhere.
    cran_only <- c("shiny", "shinydashboard", "DT", "DBI", "ggplot2", "jsonlite",
                   "survival", "scales", "broom", "survminer", "car", "eulerr",
                   "ellmer", "promises", "future", "dplyr", "dbplyr", "RPostgres",
                   "gt", "flextable")
    github_override <- c(PhenotypeR = "OHDSI/PhenotypeR")
    gh_source <- function(pkg) {
      if (pkg %in% cran_only) return(NA_character_)
      if (pkg %in% names(github_override)) return(unname(github_override[[pkg]]))
      paste0("darwin-eu/", pkg)
    }

    message("[ cohort builder ] installing missing packages: ",
            paste(missing, collapse = ", "))
    for (pkg in missing) {
      ok <- tryCatch({
        suppressWarnings(utils::install.packages(pkg, quiet = TRUE))
        requireNamespace(pkg, quietly = TRUE)
      }, error = function(e) FALSE)

      if (!ok) {
        gh <- gh_source(pkg)
        if (!is.na(gh)) {
          if (!requireNamespace("remotes", quietly = TRUE))
            tryCatch(utils::install.packages("remotes", quiet = TRUE),
                     error = function(e) NULL)
          if (requireNamespace("remotes", quietly = TRUE))
            tryCatch(remotes::install_github(gh, upgrade = "never", quiet = TRUE),
                     error = function(e) NULL)
        }
      }
      if (!requireNamespace(pkg, quietly = TRUE))
        message("[ cohort builder ] could not install '", pkg,
                "'; the feature that needs it will show as unavailable.")
    }
  }
})

for (pkg in required_packages) {
  if (!requireNamespace(pkg, quietly = TRUE))
    stop(sprintf(
      "[ cohort builder ] Required package '%s' is not installed. DRE workspaces are network-isolated - contact your workspace administrator.", pkg))
  suppressPackageStartupMessages(library(pkg, character.only = TRUE))
}


# ── 2. HELPERS ────────────────────────────────────────────────────────────────

`%||%` <- function(a, b) if (!is.null(a) && length(a) > 0) a else b

# Person ID safe coercion - use numeric (double) rather than integer so that
# bigint person_ids from large OMOP datasets (MIMIC, SynPUF) are not silently
# truncated. All OMOP person IDs are < 2^53 so double precision is exact.
# Use as_pid() everywhere a person_id vector needs to be coerced for R use,
# and pid_sql() to format a vector as a comma-separated SQL literal list.
# as_pid: converts person_id vectors to numeric safely.
# Goes via as.character() first so that bit64::integer64 values returned
# by RPostgreSQL for bigint columns are not reinterpreted as IEEE 754
# doubles (which produces massive negative numbers).
as_pid   <- function(x) {
  if (inherits(x, "integer64")) return(as.numeric(as.character(x)))
  suppressWarnings(as.numeric(as.character(x)))
}
pid_sql  <- function(x) {
  vals <- if (inherits(x, "integer64")) as.character(x)
          else sprintf("%.0f", suppressWarnings(as.numeric(as.character(x))))
  paste(vals, collapse = ",")
}

cid_sql <- function(x) {
  vals <- suppressWarnings(as.character(x))
  vals <- vals[!is.na(vals) & vals != "NA" & nzchar(vals)]
  if (length(vals) == 0) return("NULL")
  paste(vals, collapse = ",")
}

# ── Multi-schema helpers ──────────────────────────────────────────────────────

# Primary schema: first selected schema for backwards-compatible single-schema
# functions. All multi-schema-aware code iterates over all selected schemas.
primary_schema <- function(schemas) {
  if (length(schemas) == 0) return(NULL)
  schemas[[1]]
}

# Ensure omop_browser_scratch schema exists for cohort persistence.
ensure_scratch_schema <- function() {
  tryCatch({
    db_execute("CREATE SCHEMA IF NOT EXISTS omop_browser_scratch")
    # Cohort registry table
    db_execute("
      CREATE TABLE IF NOT EXISTS omop_browser_scratch.cohort_registry (
        cohort_id    SERIAL PRIMARY KEY,
        cohort_name  TEXT NOT NULL,
        created_at   TIMESTAMP DEFAULT NOW(),
        source_schemas TEXT NOT NULL,
        n_total      INTEGER,
        n_by_schema  TEXT,
        criteria_json TEXT,
        cohort_table TEXT NOT NULL
      )
    ")
    TRUE
  }, error = function(e) { message("[scratch] ", e$message); FALSE })
}

# Vocabulary consistency check across a list of schemas.
# Returns list(status = "green"|"amber"|"red", detail = character)
check_vocab_consistency <- function(schemas, col_maps) {
  if (length(schemas) < 2)
    return(list(status = "green", detail = character(0)))
  issues <- character(0)
  # Step 1: vocabulary_id set comparison
  voc_sets <- lapply(schemas, function(sch) {
    cm <- col_maps[[sch]]
    if (is.null(cm)) return(character(0))
    tbls <- tryCatch(tolower(get_tables(sch)), error=function(e) character(0))
    if (!"vocabulary" %in% tbls) return(character(0))
    # vocabulary not in OMOP_TABLES_OF_INTEREST so col_map never has it.
    # Look up actual column name from information_schema to handle any case.
    vcol_r <- tryCatch(db_query(sprintf(
      "SELECT column_name FROM information_schema.columns
       WHERE table_schema = '%s' AND lower(table_name) = 'vocabulary'
         AND lower(column_name) = 'vocabulary_id' LIMIT 1", sch)),
      error=function(e) NULL)
    vcol <- if (!is.null(vcol_r) && nrow(vcol_r) > 0)
      vcol_r[[1]][1] else "vocabulary_id"
    r <- tryCatch(db_query(sprintf(
      'SELECT DISTINCT "%s" AS vid FROM "%s"."vocabulary" ORDER BY 1', vcol, sch)),
      error=function(e) NULL)
    if (!is.null(r)) r$vid else character(0)
  })
  names(voc_sets) <- schemas
  non_empty <- voc_sets[sapply(voc_sets, length) > 0]
  if (length(non_empty) >= 2) {
    ref <- non_empty[[1]]
    for (s in names(non_empty)[-1]) {
      missing_in_s  <- setdiff(ref, non_empty[[s]])
      extra_in_s    <- setdiff(non_empty[[s]], ref)
      if (length(missing_in_s) > 3 || length(extra_in_s) > 3)
        issues <- c(issues, sprintf("Vocabulary mismatch between %s and %s (%d vocabularies differ)",
                                    names(non_empty)[1], s,
                                    length(union(missing_in_s, extra_in_s))))
    }
  }
  # Step 2: spot-check top concept IDs from condition_occurrence
  spot_results <- lapply(schemas, function(sch) {
    cm <- col_maps[[sch]]
    if (is.null(cm)) return(data.frame())
    tbls <- tryCatch(tolower(get_tables(sch)), error=function(e) character(0))
    if (!all(c("condition_occurrence","concept") %in% tbls)) return(data.frame())
    cid_co  <- cm[["condition_occurrence"]][["condition_concept_id"]] %||% "condition_concept_id"
    cid_c   <- cm[["concept"]][["concept_id"]]   %||% "concept_id"
    cname_c <- cm[["concept"]][["concept_name"]] %||% "concept_name"
    r <- tryCatch(db_query(sprintf(
      'SELECT c."%s" AS cid, c."%s" AS cname
       FROM "%s"."condition_occurrence" co
       JOIN "%s"."concept" c ON c."%s" = co."%s"
       WHERE co."%s" > 0 GROUP BY 1,2 ORDER BY COUNT(*) DESC LIMIT 20',
      cid_c, cname_c, sch, sch, cid_c, cid_co, cid_co)),
      error=function(e) NULL)
    if (!is.null(r)) r else data.frame()
  })
  names(spot_results) <- schemas
  # Compare concept names for shared concept IDs
  non_empty_sp <- spot_results[sapply(spot_results, nrow) > 0]
  if (length(non_empty_sp) >= 2) {
    ref_sp <- non_empty_sp[[1]]
    for (s in names(non_empty_sp)[-1]) {
      comp <- merge(ref_sp, non_empty_sp[[s]], by="cid", suffixes=c(".a",".b"))
      if (nrow(comp) > 0) {
        mismatches <- sum(comp$cname.a != comp$cname.b, na.rm=TRUE)
        if (mismatches > 2)
          issues <- c(issues, sprintf("Concept name mismatches for shared IDs between %s and %s (%d of %d checked)",
                                      names(non_empty_sp)[1], s, mismatches, nrow(comp)))
      } else if (length(non_empty_sp) >= 2) {
        issues <- c(issues, sprintf("No shared top concept IDs between %s and %s - vocabulary may be incompatible",
                                    names(non_empty_sp)[1], s))
      }
    }
  }
  status <- if (length(issues) == 0) "green"
            else if (length(issues) <= 2) "amber"
            else "red"
  list(status = status, detail = issues)
}

# Observation period overlap analysis across schemas.
# Returns list(overlap="full"|"partial"|"none", min_overlap, max_overlap,
#              ranges=list(schema=list(min,max)))
check_obs_overlap <- function(schemas, col_maps) {
  if (length(schemas) < 2) return(list(overlap="full", ranges=list()))
  ranges <- lapply(schemas, function(sch) {
    cm <- col_maps[[sch]]
    if (is.null(cm)) return(list(min=NA, max=NA))
    tbls <- tryCatch(tolower(get_tables(sch)), error=function(e) character(0))
    if (!"observation_period" %in% tbls) return(list(min=NA, max=NA))
    sd <- cm[["observation_period"]][["observation_period_start_date"]] %||% "observation_period_start_date"
    ed <- cm[["observation_period"]][["observation_period_end_date"]]   %||% "observation_period_end_date"
    r <- tryCatch(db_query(sprintf(
      'SELECT MIN("%s"::date) AS min_d, MAX("%s"::date) AS max_d FROM "%s"."observation_period"',
      sd, ed, sch)), error=function(e) NULL)
    if (!is.null(r))
      list(min = as.Date(r$min_d[1]), max = as.Date(r$max_d[1]))
    else list(min=NA, max=NA)
  })
  names(ranges) <- schemas
  valid <- ranges[!is.na(sapply(ranges, `[[`, "min"))]
  if (length(valid) < 2) return(list(overlap="full", ranges=ranges))
  overlap_start <- max(sapply(valid, function(r) as.numeric(r$min)), na.rm=TRUE)
  overlap_end   <- min(sapply(valid, function(r) as.numeric(r$max)), na.rm=TRUE)
  overlap_days  <- max(0, overlap_end - overlap_start)
  overlap_type  <- if (overlap_days >= 180) "full"
                  else if (overlap_days > 0) "partial"
                  else "none"
  list(
    overlap       = overlap_type,
    overlap_days  = overlap_days,
    overlap_start = if (overlap_days > 0) as.Date(overlap_start, origin="1970-01-01") else NA,
    overlap_end   = if (overlap_days > 0) as.Date(overlap_end,   origin="1970-01-01") else NA,
    ranges        = ranges
  )
}

pg_str  <- function(s) paste0("'", gsub("'", "''", as.character(s)), "'")
fq      <- function(schema, table) sprintf('"%s"."%s"', schema, table)
qq      <- function(x) sprintf('"%s"', x)


# ══════════════════════════════════════════════════════════════════════════════
# ── 2b. AIRA INTEGRATION ──────────────────────────────────────────────────────
# ══════════════════════════════════════════════════════════════════════════════
#
# Optional natural-language cohort drafting via the workspace AIRA framework.
# Disabled by default. Enabled per workspace via cfg$aira$enabled. When
# disabled, the entire feature is hidden from the UI - no surprise behaviour.
#
# Design rules (from project R-AIRA-* conventions):
#   - R-AIRA-01: single source of truth gate (aira_is_enabled)
#   - R-AIRA-02: canonical 6-field response shape on every status path
#   - R-AIRA-03: frozen, versioned prompts; once shipped never edited
#   - R-AIRA-08: strip markdown fences before validation
#   - R-AIRA-09: status-based event logging
#   - R-AIRA-12: test seam via client override
#   - R-AIRA-13: safe defaults; enabled = FALSE
#   - R-AIRA-14: disable model "thinking" for predictable latency
#   - R-AIRA-15: response_validator keyed by shape, not version

AIRA_BASE_URL_DEFAULT <- "https://api.uksouth.saas.aridhia.io/api/aira/v1"

# Default config. v10.3: enabled is hardcoded TRUE - no env vars, no
# options() resolution. The cfg gate always passes; only the packages and
# API key gates remain. To disable AIRA, remove the relevant code paths
# or set this constant to FALSE manually.
aira_default_cfg <- function() {
  list(
    enabled            = TRUE,
    base_url           = AIRA_BASE_URL_DEFAULT,
    model              = "workspace-chat",
    timeout_s_drafting = 300L,
    disable_thinking   = TRUE                        # R-AIRA-14
  )
}

# Single source of truth for whether AIRA can be used in this session. Checks:
#   1. cfg explicitly enables it
#   2. The three optional packages are installed
#   3. WORKSPACE_API_KEY env var is set
# Any failure → FALSE. Never re-implement at call sites.
#
# v10.1: instrumentation. When AIRA_DEBUG env var is "1", every gate decision
# is logged to the console with which specific check passed or failed. Off by
# default to avoid noise.
#
# v10.2: defensive merge with defaults - partial cfg from options() no longer
# leaves base_url/model/timeout unset.
aira_resolve_cfg <- function(cfg = NULL) {
  defaults <- aira_default_cfg()
  if (is.null(cfg)) cfg <- getOption("aira_cfg", NULL)
  if (is.null(cfg)) return(defaults)
  # Overlay any user-supplied keys onto defaults
  for (k in names(cfg)) defaults[[k]] <- cfg[[k]]
  defaults
}

aira_is_enabled <- function(cfg = NULL) {
  cfg   <- aira_resolve_cfg(cfg)
  debug <- isTRUE(Sys.getenv("AIRA_DEBUG") == "1") ||
           isTRUE(getOption("aira_debug", FALSE))

  gate_cfg <- isTRUE(cfg$enabled)
  if (debug) message(sprintf("[AIRA][DEBUG] gate 1 cfg$enabled = %s", gate_cfg))
  if (!gate_cfg) return(FALSE)

  pkg_status <- vapply(aira_optional_packages,
                       function(p) requireNamespace(p, quietly = TRUE),
                       logical(1))
  pkgs_ok <- all(pkg_status)
  if (debug) {
    message(sprintf("[AIRA][DEBUG] gate 2 packages: %s",
                     paste(sprintf("%s=%s", names(pkg_status), pkg_status),
                            collapse = "; ")))
  }
  if (!pkgs_ok) return(FALSE)

  key_set <- nzchar(Sys.getenv("WORKSPACE_API_KEY"))
  if (debug) message(sprintf("[AIRA][DEBUG] gate 3 WORKSPACE_API_KEY set = %s",
                              key_set))
  if (!key_set) return(FALSE)

  if (debug) message("[AIRA][DEBUG] all gates passed; AIRA is enabled")
  TRUE
}

aira_status_summary <- function(cfg = NULL) {
  cfg <- aira_resolve_cfg(cfg)
  list(
    cfg_enabled     = isTRUE(cfg$enabled),
    packages_ok     = all(vapply(aira_optional_packages,
                                  function(p) requireNamespace(p, quietly = TRUE),
                                  logical(1))),
    api_key_present = nzchar(Sys.getenv("WORKSPACE_API_KEY")),
    base_url        = cfg$base_url %||% "",
    model           = cfg$model %||% "",
    enabled_overall = aira_is_enabled(cfg)
  )
}

# Canonical empty response for any status path (R-AIRA-02). Every public AIRA
# function returns a list with exactly these keys. Consumers switch() on
# status; never assume "ok".
aira_empty_response <- function(status, prompt_version = "", reason = "",
                                duration_ms = 0L, timing_ms = NULL) {
  list(
    status         = status,
    text           = "",
    draft          = NULL,
    prompt_version = prompt_version,
    duration_ms    = as.integer(duration_ms),
    reason         = reason,
    timing_ms      = timing_ms %||% list(
      client_construction_ms = NA_integer_,
      inference_ms           = NA_integer_,
      parse_ms               = NA_integer_,
      future_overhead_ms     = NA_integer_
    )
  )
}

# ── PROMPT REGISTRY (R-AIRA-03) ──────────────────────────────────────────────
# Once shipped, never edited. New version on any text change. Each prompt has
# version, system text, user_builder, model_params, response_validator.
PROMPTS <- list()

# Cohort drafting v1 - initial release with the structured JSON output.
PROMPTS$cohort_drafting <- list()
PROMPTS$cohort_drafting$v1 <- list(
  version = "v1",
  system = paste(
    "You are a cohort-definition assistant for OMOP-based observational",
    "research. Your job is to translate a researcher's plain-English cohort",
    "description into a structured JSON definition. Another system will use",
    "your output to populate criterion cards in a cohort-building tool.",
    "",
    "CRITICAL RULES:",
    "1. You DO NOT pick OMOP concept IDs. You produce plain-English search",
    "   terms; the downstream system resolves them via its own concept",
    "   search.",
    "2. Return ONLY valid JSON matching the schema below. No prose, no",
    "   markdown fences, no explanation outside the JSON.",
    "3. If the request is incoherent or not a cohort description, return",
    "   {\"error\": \"<short reason>\"} instead of guessing.",
    "",
    "SCHEMA:",
    "{",
    "  \"name\": \"<short snake_case name, e.g. nsaid_new_users>\",",
    "  \"description\": \"<one-sentence summary>\",",
    "  \"prior_observation_days\": <integer, default 365>,",
    "  \"criteria\": [",
    "    {",
    "      \"type\": \"inclusion\" or \"exclusion\",",
    "      \"domain\": \"drug\", \"condition\", \"procedure\", \"measurement\", \"visit\", or \"observation\",",
    "      \"search_terms\": [<one or more strings>],",
    "      \"include_descendants\": <boolean>,",
    "      \"occurrence\": \"at_least_one\" or \"any\",",
    "      \"time_window\": \"before_index\", \"after_index\", or null",
    "    }",
    "  ],",
    "  \"demographics\": {",
    "    \"age_at_index_min\": <integer or null>,",
    "    \"age_at_index_max\": <integer or null>,",
    "    \"gender\": \"female\", \"male\", or null",
    "  },",
    "  \"rationale\": \"<one paragraph explaining design choices>\"",
    "}",
    "",
    "GUIDANCE:",
    "- Default prior_observation_days to 365 unless specified otherwise.",
    "- Set include_descendants=true for parent/class concepts (e.g. \"NSAIDs\",",
    "  \"diabetes\"), false for specific named products.",
    "- For exclusions of prior history, use time_window=\"before_index\".",
    "- Make reasonable epidemiological assumptions for ambiguous inputs and",
    "  document them in rationale.",
    sep = "\n"),
  user_builder = function(text) {
    sprintf("Researcher's cohort description:\n\n%s\n\nReturn the JSON.",
            as.character(text))
  },
  model_params = list(
    temperature = 0.2,
    max_tokens  = 1500
  ),
  response_validator = function(text) {
    # R-AIRA-08: strip markdown fences before parsing
    stripped <- text
    if (grepl("^```", stripped))
      stripped <- gsub("^```(json)?\\s*|\\s*```\\s*$", "", stripped, perl = TRUE)
    json <- tryCatch(jsonlite::fromJSON(stripped, simplifyVector = FALSE),
                     error = function(e) NULL)
    if (is.null(json))
      return(list(ok = FALSE, reason = "json_parse_failed"))
    if (!is.null(json$error))
      return(list(ok = FALSE,
                  reason = paste0("aira_returned_error: ", json$error)))
    required <- c("name", "description", "criteria")
    missing  <- setdiff(required, names(json))
    if (length(missing) > 0)
      return(list(ok = FALSE,
                  reason = paste("missing_fields:",
                                  paste(missing, collapse = ","))))
    if (length(json$criteria) == 0)
      return(list(ok = FALSE, reason = "no_criteria"))
    valid_domains <- c("drug", "condition", "procedure",
                       "measurement", "visit", "observation")
    for (i in seq_along(json$criteria)) {
      c1 <- json$criteria[[i]]
      if (!isTRUE(c1$domain %in% valid_domains))
        return(list(ok = FALSE,
                    reason = sprintf("criterion_%d_invalid_domain:%s",
                                      i, c1$domain %||% "NULL")))
      if (length(c1$search_terms) == 0)
        return(list(ok = FALSE,
                    reason = sprintf("criterion_%d_empty_search_terms", i)))
    }
    list(ok = TRUE, draft = json)
  }
)

# v2 (v10.5): leaner system prompt for faster inference. Same response shape
# as v1, so reuses v1's response_validator (R-AIRA-15). max_tokens cut from
# 1500 to 800; typical drafts use ~400-600 tokens. The trade-off is slightly
# tighter guidance for ambiguous inputs - v2 still produces correct cohorts
# for normal descriptions but may handle edge cases less gracefully than v1.
# To roll back: change ACTIVE_PROMPT$cohort_drafting to "v1".
PROMPTS$cohort_drafting$v2 <- list(
  version = "v2",
  system = paste(
    "Translate a researcher's plain-English cohort description into JSON.",
    "Return ONLY valid JSON. No prose, no markdown fences.",
    "",
    "Schema:",
    "{",
    "  \"name\": \"<snake_case>\",",
    "  \"description\": \"<one sentence>\",",
    "  \"prior_observation_days\": <integer, default 365>,",
    "  \"criteria\": [{",
    "    \"type\": \"inclusion\" | \"exclusion\",",
    "    \"domain\": \"drug\" | \"condition\" | \"procedure\" | \"measurement\" | \"visit\" | \"observation\",",
    "    \"search_terms\": [<strings>],",
    "    \"include_descendants\": <boolean>,",
    "    \"occurrence\": \"at_least_one\" | \"any\",",
    "    \"time_window\": \"before_index\" | \"after_index\" | null",
    "  }],",
    "  \"demographics\": {",
    "    \"age_at_index_min\": <integer|null>,",
    "    \"age_at_index_max\": <integer|null>,",
    "    \"gender\": \"female\" | \"male\" | null",
    "  },",
    "  \"rationale\": \"<one paragraph>\"",
    "}",
    "",
    "Rules: do NOT pick OMOP concept IDs (downstream resolves names via",
    "search). include_descendants=true for parent concepts (e.g. NSAIDs,",
    "diabetes), false for specific products. If incoherent, return",
    "{\"error\": \"<reason>\"}.",
    sep = "\n"),
  user_builder = function(text) {
    sprintf("Cohort description:\n%s\n\nReturn the JSON.", as.character(text))
  },
  model_params = list(
    temperature = 0.2,
    max_tokens  = 800
  ),
  # Reuse v1's validator - same response shape (R-AIRA-15)
  response_validator = PROMPTS$cohort_drafting$v1$response_validator
)

# ── Concept summary v1 ────────────────────────────────────────────────────────
# Used by the Browse Concepts AIRA tab. Takes structured concept info
# (name, ID, vocab, domain, hierarchy snippet) and produces a plain-language
# clinical context summary the user can read while deciding whether to add
# the concept to a cohort.
PROMPTS$concept_summary <- list()
PROMPTS$concept_summary$v1 <- list(
  version = "v1",
  system = paste(
    "You are AIRA, a clinical informatics assistant helping a researcher",
    "decide whether an OMOP concept fits their cohort. You will be given",
    "structured information about a single OMOP concept including its name,",
    "ID, vocabulary, domain, and (when available) parent and child concepts.",
    "",
    "Produce a concise clinical context summary the researcher can read in",
    "under 30 seconds. Use Markdown for structure. Do NOT use H1 (#)",
    "headings; use H4 (####) for section headers since this renders inside",
    "a small panel.",
    "",
    "STRUCTURE (use exactly these four section headings, in order):",
    "",
    "#### Clinical meaning",
    "Two or three sentences describing what this concept captures clinically.",
    "Use accessible language; assume a researcher who knows medicine but may",
    "not know this specific term's coding conventions.",
    "",
    "#### Typical patient / setting",
    "Two sentences on who typically receives this code: age range, acuity,",
    "inpatient vs outpatient, specialty context.",
    "",
    "#### Coding caveats",
    "Two to four bullet points on common pitfalls: ambiguity with related",
    "concepts, under- or over-coding patterns, descendants worth considering,",
    "differences between vocabularies, anything a researcher might miss.",
    "",
    "#### Related concepts to consider",
    "Three to five bullets, each naming a related concept the researcher",
    "might also want (or might want to exclude). Use plain concept names,",
    "NOT IDs. The app will look up names against the local vocabulary.",
    "",
    "CRITICAL RULES:",
    "- Do not invent concept IDs. Refer to concepts by name only.",
    "- Do not invent statistics, prevalence figures, or patient counts.",
    "- Do not produce more than the four sections above. No preamble, no",
    "  closing remarks.",
    "- If the supplied concept information is malformed or empty, return",
    "  one line: 'Cannot summarise: insufficient concept information.'",
    sep = "\n"),
  user_builder = function(concept_info) {
    # concept_info is a list with: name, concept_id, vocabulary,
    # concept_class, domain, standard_concept, parents (list of names),
    # children (list of names, limited to first ~10).
    lines <- c(
      sprintf("Concept name:    %s", concept_info$name %||% "(unknown)"),
      sprintf("Concept ID:      %s", concept_info$concept_id %||% "(unknown)"),
      sprintf("Vocabulary:      %s", concept_info$vocabulary %||% "(unknown)"),
      sprintf("Concept class:   %s", concept_info$concept_class %||% "(unknown)"),
      sprintf("Domain:          %s", concept_info$domain %||% "(unknown)"),
      sprintf("Standard:        %s", concept_info$standard_concept %||% "(unknown)")
    )
    if (length(concept_info$parents) > 0)
      lines <- c(lines, "",
                 "Parent concepts:",
                 paste0("  - ", concept_info$parents))
    if (length(concept_info$children) > 0)
      lines <- c(lines, "",
                 "Child concepts (sample):",
                 paste0("  - ", concept_info$children))
    paste(c(lines, "",
            "Please provide the four-section clinical context summary."),
          collapse = "\n")
  },
  model_params = list(
    temperature = 0.3,
    max_tokens  = 700
  ),
  # Simple validator: response must be non-empty character. Reject obvious
  # error sentinels from the system prompt.
  response_validator = function(text) {
    if (!is.character(text) || length(text) == 0 || !nzchar(trimws(text)))
      return(list(ok = FALSE, reason = "empty_response"))
    if (grepl("^Cannot summarise:", text))
      return(list(ok = FALSE, reason = "model_declined"))
    list(ok = TRUE)
  }
)

# ── PHENOTYPE REVIEW (v11) ────────────────────────────────────────────────────
# Markdown critique of a cohort definition from its aggregate diagnostics.
# Aggregate counts only ever reach the model; never patient-level rows.
PROMPTS$phenotype_review$v1 <- list(
  version = "v1",
  system = paste(
    "You are AIRA, a senior OMOP phenotype reviewer. You are given AGGREGATE,",
    "de-identified diagnostics about a cohort definition (counts only, never",
    "patient-level data): the definition in plain English, cohort size and",
    "basic demographics, an attrition waterfall, an index-event breakdown, and",
    "a list of orphan concepts (codes in the data related to the definition but",
    "not captured by it).",
    "",
    "Write the critique a senior reviewer would give at a phenotype review. Use",
    "Markdown. Do NOT use H1 (#); use H4 (####) for section headers since this",
    "renders in a small panel. Keep it readable in under a minute.",
    "",
    "STRUCTURE (use exactly these three sections, in order):",
    "",
    "#### Verdict",
    "Two or three sentences: is this definition sound in shape, and what is the",
    "single most important thing to address?",
    "",
    "#### Findings",
    "A short list. Start each line with a bold severity tag - **Address**,",
    "**Review**, or **Note** - then the issue in one or two sentences, grounded",
    "in the numbers provided. When you name a concept, give its concept_id in",
    "parentheses so the researcher can verify. Cover, where the data supports",
    "it: entry-criterion composition (does the index breakdown show unexpected",
    "concepts driving entry?), orphan concepts worth adding or consciously",
    "excluding, and attrition steps that remove a large share or bias the",
    "cohort toward prevalent cases.",
    "",
    "#### What is sound",
    "One or two sentences on what looks correct, so the researcher knows what",
    "not to change.",
    "",
    "CRITICAL RULES:",
    "- Ground every quantitative claim in the numbers you were given. Do NOT",
    "  invent counts, percentages, concept IDs, or prevalence figures.",
    "- Cite only concept_ids that appear in the provided data; never invent one.",
    "- If a diagnostic was not provided, do not speculate about it.",
    "- If the cohort was imported (no stored definition), say plainly that",
    "  orphan and attrition review are unavailable and focus on the demographics",
    "  and the index breakdown.",
    "- No preamble, no closing remarks. Only the three sections above.",
    "- If the supplied diagnostics are empty, return one line:",
    "  'Cannot review: insufficient diagnostics.'",
    sep = "\n"),
  user_builder = function(diag) {
    fmt_n <- function(x) if (is.null(x) || (length(x) == 1 && is.na(x))) "?" else format(x, big.mark = ",")
    pct   <- function(x) if (is.null(x) || (length(x) == 1 && is.na(x))) "?" else paste0(x, "%")
    lines <- c(
      sprintf("Cohort name: %s", if (nzchar(diag$cohort_name %||% "")) diag$cohort_name else "(unnamed)"),
      sprintf("Imported (no stored definition): %s", if (isTRUE(diag$is_imported)) "yes" else "no"),
      sprintf("Definition: %s", diag$definition %||% "(none)"),
      "", "Cohort summary:",
      sprintf("  Persons: %s", fmt_n(diag$n_persons)),
      sprintf("  Female: %s", pct(diag$pct_female)),
      sprintf("  Median age at index: %s", fmt_n(diag$median_age)),
      sprintf("  Median follow-up (years): %s", diag$median_fu_y %||% "?"))
    if (!is.null(diag$attrition) && nrow(diag$attrition) > 0)
      lines <- c(lines, "", "Attrition (persons remaining after each step, in order):",
        paste0("  ", diag$attrition$label, ": ",
               ifelse(is.na(diag$attrition$n), "n/a", format(diag$attrition$n, big.mark = ","))))
    else lines <- c(lines, "", "Attrition: not computed or not available.")
    if (!is.null(diag$index_breakdown) && nrow(diag$index_breakdown) > 0) {
      ib <- diag$index_breakdown
      lines <- c(lines, "", "Index-event breakdown (concept, share of cohort recorded on index date):",
        paste0("  ", ib$concept_name, " (", ib$concept_id, "): ", ib$pct, "%"))
    } else lines <- c(lines, "", "Index-event breakdown: not computed.")
    if (!is.null(diag$orphans) && nrow(diag$orphans) > 0) {
      og <- diag$orphans
      lines <- c(lines, "", "Orphan concepts (related codes in the data not captured):",
        paste0("  ", og$concept_name, " (", og$concept_id, "), ", og$relationship, ", ",
               format(og$n_persons, big.mark = ","), " persons"))
    } else lines <- c(lines, "", "Orphan concepts: none found, not computed, or not applicable.")
    paste(c(lines, "", "Write the phenotype review."), collapse = "\n")
  },
  model_params = list(temperature = 0.3, max_tokens = 900),
  response_validator = function(text) {
    if (!is.character(text) || length(text) == 0 || !nzchar(trimws(text)))
      return(list(ok = FALSE, reason = "empty_response"))
    if (grepl("^Cannot review:", text))
      return(list(ok = FALSE, reason = "model_declined"))
    list(ok = TRUE)
  }
)

# ACTIVE_PROMPT points at the live version for each use case
ACTIVE_PROMPT <- list(
  cohort_drafting  = "v2",
  concept_summary  = "v1",
  phenotype_review = "v1"
)

# ── CLIENT CONSTRUCTION + TEST SEAM (R-AIRA-12) ───────────────────────────────
# Test-seam functions: set_aira_client_override / get_aira_client_override
# allow injecting a mock chat client during testing. Not called from the app
# itself; documented here so they aren't mistaken for dead code.
.aira_client_override <- NULL
set_aira_client_override <- function(fn) { .aira_client_override <<- fn }
get_aira_client_override <- function() .aira_client_override

# Constructs the ellmer chat client for ellmer >= 0.4.0.
#
# Two important behavioural notes:
#   1. The deprecated `api_key` argument has been replaced by `credentials`
#      (a function returning auth headers). We construct one that wraps
#      WORKSPACE_API_KEY in a Bearer header.
#   2. ellmer 0.4.0's chat() method takes plain strings, not the
#      OpenAI list-of-lists format. The system prompt is set at client
#      construction time via system_prompt= and never passed in chat().
#
# v10.4: aligned with ellmer 0.4.0 after observing the deprecation warning
# and "must be made up of strings" error in the workspace.
aira_build_client <- function(cfg, system_prompt = NULL, model_params = NULL) {
  override <- get_aira_client_override()
  if (!is.null(override)) return(override(cfg))
  # Base api_args: thinking-off control
  api_args <- if (isTRUE(cfg$disable_thinking))
    list(chat_template_kwargs = list(enable_thinking = FALSE))
  else
    list()
  # v10.5: merge prompt-level model_params (e.g. max_tokens, temperature).
  # Caps generation length and gives AIRA a budget to stop generating early.
  if (is.list(model_params))
    for (k in names(model_params)) api_args[[k]] <- model_params[[k]]
  credentials_fn <- function() {
    list(Authorization = paste("Bearer", Sys.getenv("WORKSPACE_API_KEY")))
  }
  # Try modern ellmer (>= 0.4.0) signature first; fall back to old api_key
  # signature for older workspaces.
  client <- tryCatch(
    ellmer::chat_openai_compatible(
      base_url      = cfg$base_url,
      model         = cfg$model,
      credentials   = credentials_fn,
      system_prompt = system_prompt,
      api_args      = api_args),
    error = function(e) {
      # Old signature fallback (no credentials, no system_prompt args)
      tryCatch(
        ellmer::chat_openai_compatible(
          base_url = cfg$base_url,
          model    = cfg$model,
          api_key  = Sys.getenv("WORKSPACE_API_KEY"),
          api_args = api_args),
        error = function(e2) {
          # Final fallback: drop api_args too
          tryCatch(
            ellmer::chat_openai_compatible(
              base_url = cfg$base_url,
              model    = cfg$model,
              api_key  = Sys.getenv("WORKSPACE_API_KEY")),
            error = function(e3) NULL)
        })
    })
  client
}

# Returns TRUE/FALSE/NA per R-AIRA-14. NA when no client has been constructed.
.aira_thinking_state <- NA
aira_thinking_disabled <- function() .aira_thinking_state

# ── MAIN PUBLIC API ──────────────────────────────────────────────────────────
# Sync version. Returns canonical 6-field response on every path.
aira_draft_cohort <- function(text, cfg = NULL) {
  cfg <- aira_resolve_cfg(cfg)
  if (!aira_is_enabled(cfg))
    return(aira_empty_response("disabled", reason = "aira_not_enabled"))
  if (!nzchar(trimws(as.character(text %||% ""))))
    return(aira_empty_response("malformed", reason = "empty_input"))

  prompt_version <- ACTIVE_PROMPT$cohort_drafting
  prompt         <- PROMPTS$cohort_drafting[[prompt_version]]
  if (is.null(prompt))
    return(aira_empty_response("unavailable",
                                reason = sprintf("prompt_version_%s_not_found",
                                                  prompt_version)))

  t0 <- proc.time()[["elapsed"]]
  timing <- list(client_construction_ms = NA_integer_,
                 inference_ms           = NA_integer_,
                 parse_ms               = NA_integer_,
                 future_overhead_ms     = NA_integer_)

  # Client construction (system prompt set at build time per ellmer 0.4.0,
  # model params merged into api_args per v10.5)
  tc0    <- proc.time()[["elapsed"]]
  client <- aira_build_client(cfg,
                               system_prompt = prompt$system,
                               model_params  = prompt$model_params)
  timing$client_construction_ms <- as.integer(round((proc.time()[["elapsed"]] - tc0) * 1000))
  if (is.null(client))
    return(aira_empty_response("unavailable",
                                prompt_version = prompt_version,
                                reason = "client_construction_failed",
                                duration_ms = as.integer(round((proc.time()[["elapsed"]] - t0) * 1000)),
                                timing_ms = timing))

  # Inference: ellmer 0.4.0 takes a plain string. The system prompt was
  # already wired in at construction, so chat() receives only the user
  # message body.
  ti0     <- proc.time()[["elapsed"]]
  raw_txt <- tryCatch({
    setTimeLimit(elapsed = cfg$timeout_s_drafting, transient = TRUE)
    on.exit(setTimeLimit(elapsed = Inf, transient = FALSE), add = TRUE)
    user_msg <- prompt$user_builder(text)
    resp <- client$chat(user_msg)
    # ellmer's chat() may return a character string directly, or a content
    # object whose printed form is the text. Coerce defensively.
    if (is.character(resp)) resp
    else if (!is.null(resp$content)) as.character(resp$content)
    else if (!is.null(resp$message$content)) as.character(resp$message$content)
    else as.character(resp)
  }, error = function(e) {
    msg <- conditionMessage(e)
    if (grepl("reached elapsed time limit|time limit", msg, ignore.case = TRUE))
      return(structure(NA_character_, status = "timeout", reason = msg))
    structure(NA_character_, status = "unavailable", reason = msg)
  })
  timing$inference_ms <- as.integer(round((proc.time()[["elapsed"]] - ti0) * 1000))

  if (is.na(raw_txt)) {
    return(aira_empty_response(
      attr(raw_txt, "status") %||% "unavailable",
      prompt_version = prompt_version,
      reason = attr(raw_txt, "reason") %||% "inference_failed",
      duration_ms = as.integer(round((proc.time()[["elapsed"]] - t0) * 1000)),
      timing_ms = timing))
  }

  # Validate
  tp0       <- proc.time()[["elapsed"]]
  validated <- prompt$response_validator(raw_txt)
  timing$parse_ms <- as.integer(round((proc.time()[["elapsed"]] - tp0) * 1000))
  dur_total <- as.integer(round((proc.time()[["elapsed"]] - t0) * 1000))

  if (!isTRUE(validated$ok)) {
    out <- aira_empty_response("malformed",
                               prompt_version = prompt_version,
                               reason = validated$reason %||% "unknown_validation_failure",
                               duration_ms = dur_total,
                               timing_ms = timing)
    out$text <- raw_txt   # preserve raw for debugging
    return(out)
  }

  list(
    status         = "ok",
    text           = raw_txt,
    draft          = validated$draft,
    prompt_version = prompt_version,
    duration_ms    = dur_total,
    reason         = "",
    timing_ms      = timing
  )
}

# Async variant - for use in Shiny so the UI stays responsive. Returns a
# promise that resolves to the canonical 6-field response. Promise rejection
# translates to status = "unavailable" per R-AIRA-02.
aira_draft_cohort_async <- function(text, cfg = NULL) {
  if (!requireNamespace("promises", quietly = TRUE) ||
      !requireNamespace("future",   quietly = TRUE))
    return(promises::promise_resolve(
      aira_empty_response("unavailable", reason = "async_packages_missing")))
  cfg_local <- aira_resolve_cfg(cfg)
  text_local <- text
  t_outer <- proc.time()[["elapsed"]]
  prom <- promises::future_promise({
    aira_draft_cohort(text_local, cfg_local)
  }, seed = NULL)
  prom <- promises::then(prom,
    onFulfilled = function(resp) {
      if (is.list(resp) && !is.null(resp$timing_ms)) {
        resp$timing_ms$future_overhead_ms <- as.integer(round(
          (proc.time()[["elapsed"]] - t_outer) * 1000 - (resp$duration_ms %||% 0L)))
      }
      resp
    },
    onRejected = function(e) {
      aira_empty_response("unavailable",
                          reason = paste0("async_rejection: ",
                                           conditionMessage(e)))
    })
  prom
}

# ── AIRA: concept clinical summary (v10.13 / R-AIRA-16) ──────────────────────
# Single-concept clinical context for the Browse Concepts AIRA tab. Takes a
# structured concept_info list (see PROMPTS$concept_summary$v1$user_builder)
# and returns plain Markdown text via an aira_empty_response-shaped object.
#
# Concept_info must contain: name, concept_id, vocabulary, domain. Parents
# and children are optional; the prompt handles their absence gracefully.
aira_concept_summary <- function(concept_info, cfg = NULL) {
  cfg <- aira_resolve_cfg(cfg)
  if (!aira_is_enabled(cfg))
    return(aira_empty_response("disabled", reason = "aira_not_enabled"))
  if (!is.list(concept_info) || !nzchar(trimws(as.character(concept_info$name %||% ""))))
    return(aira_empty_response("malformed", reason = "empty_concept_info"))

  prompt_version <- ACTIVE_PROMPT$concept_summary
  prompt         <- PROMPTS$concept_summary[[prompt_version]]
  if (is.null(prompt))
    return(aira_empty_response("unavailable",
                                reason = sprintf("prompt_version_%s_not_found",
                                                  prompt_version)))

  t0     <- proc.time()[["elapsed"]]
  timing <- list(client_construction_ms = NA_integer_,
                 inference_ms           = NA_integer_,
                 parse_ms               = NA_integer_,
                 future_overhead_ms     = NA_integer_)

  tc0    <- proc.time()[["elapsed"]]
  client <- aira_build_client(cfg,
                               system_prompt = prompt$system,
                               model_params  = prompt$model_params)
  timing$client_construction_ms <- as.integer(round(
    (proc.time()[["elapsed"]] - tc0) * 1000))
  if (is.null(client))
    return(aira_empty_response("unavailable",
                                prompt_version = prompt_version,
                                reason = "client_construction_failed",
                                duration_ms = as.integer(round(
                                  (proc.time()[["elapsed"]] - t0) * 1000)),
                                timing_ms = timing))

  ti0     <- proc.time()[["elapsed"]]
  raw_txt <- tryCatch({
    setTimeLimit(elapsed = cfg$timeout_s_drafting, transient = TRUE)
    on.exit(setTimeLimit(elapsed = Inf, transient = FALSE), add = TRUE)
    user_msg <- prompt$user_builder(concept_info)
    resp     <- client$chat(user_msg)
    if (is.character(resp)) resp
    else if (!is.null(resp$content))         as.character(resp$content)
    else if (!is.null(resp$message$content)) as.character(resp$message$content)
    else as.character(resp)
  }, error = function(e) {
    msg <- conditionMessage(e)
    if (grepl("reached elapsed time limit|time limit", msg, ignore.case = TRUE))
      structure("", aira_error = "timeout", aira_msg = msg)
    else
      structure("", aira_error = "inference_failed", aira_msg = msg)
  })
  timing$inference_ms <- as.integer(round(
    (proc.time()[["elapsed"]] - ti0) * 1000))

  if (is.null(raw_txt) || !is.character(raw_txt) || !nzchar(trimws(raw_txt))) {
    err <- attr(raw_txt, "aira_error") %||% "empty_response"
    return(aira_empty_response(
      if (identical(err, "timeout")) "timeout" else "unavailable",
      prompt_version = prompt_version,
      reason         = attr(raw_txt, "aira_msg") %||% err,
      duration_ms    = as.integer(round((proc.time()[["elapsed"]] - t0) * 1000)),
      timing_ms      = timing))
  }

  # Validate the response shape via the prompt's validator
  tp0 <- proc.time()[["elapsed"]]
  val <- tryCatch(prompt$response_validator(raw_txt),
                   error = function(e) list(ok = FALSE,
                                             reason = conditionMessage(e)))
  timing$parse_ms <- as.integer(round((proc.time()[["elapsed"]] - tp0) * 1000))
  if (!isTRUE(val$ok))
    return(aira_empty_response("malformed",
                                prompt_version = prompt_version,
                                reason         = val$reason %||% "validation_failed",
                                duration_ms    = as.integer(round(
                                  (proc.time()[["elapsed"]] - t0) * 1000)),
                                timing_ms      = timing,
                                raw_response   = raw_txt))

  list(
    status         = "ok",
    prompt_version = prompt_version,
    duration_ms    = as.integer(round((proc.time()[["elapsed"]] - t0) * 1000)),
    timing_ms      = timing,
    content        = raw_txt,
    concept_id     = concept_info$concept_id %||% NA_integer_
  )
}

# v11: synchronous phenotype review. Takes a `diag` list of aggregate cohort
# diagnostics (see PROMPTS$phenotype_review$v1$user_builder) and returns
# Markdown via the canonical response shape. Same client/timeout/validate path
# as aira_concept_summary.
aira_phenotype_review <- function(diag, cfg = NULL) {
  cfg <- aira_resolve_cfg(cfg)
  if (!aira_is_enabled(cfg))
    return(aira_empty_response("disabled", reason = "aira_not_enabled"))
  if (!is.list(diag) || is.null(diag$n_persons))
    return(aira_empty_response("malformed", reason = "empty_diagnostics"))

  prompt_version <- ACTIVE_PROMPT$phenotype_review
  prompt         <- PROMPTS$phenotype_review[[prompt_version]]
  if (is.null(prompt))
    return(aira_empty_response("unavailable",
            reason = sprintf("prompt_version_%s_not_found", prompt_version)))

  t0     <- proc.time()[["elapsed"]]
  client <- aira_build_client(cfg, system_prompt = prompt$system,
                              model_params = prompt$model_params)
  if (is.null(client))
    return(aira_empty_response("unavailable", prompt_version = prompt_version,
            reason = "client_construction_failed",
            duration_ms = as.integer(round((proc.time()[["elapsed"]] - t0) * 1000))))

  raw_txt <- tryCatch({
    setTimeLimit(elapsed = cfg$timeout_s_drafting, transient = TRUE)
    on.exit(setTimeLimit(elapsed = Inf, transient = FALSE), add = TRUE)
    resp <- client$chat(prompt$user_builder(diag))
    if (is.character(resp)) resp
    else if (!is.null(resp$content))         as.character(resp$content)
    else if (!is.null(resp$message$content)) as.character(resp$message$content)
    else as.character(resp)
  }, error = function(e) {
    msg <- conditionMessage(e)
    if (grepl("reached elapsed time limit|time limit", msg, ignore.case = TRUE))
      structure("", aira_error = "timeout", aira_msg = msg)
    else structure("", aira_error = "inference_failed", aira_msg = msg)
  })

  if (is.null(raw_txt) || !is.character(raw_txt) || !nzchar(trimws(raw_txt))) {
    err <- attr(raw_txt, "aira_error") %||% "empty_response"
    return(aira_empty_response(if (identical(err, "timeout")) "timeout" else "unavailable",
            prompt_version = prompt_version,
            reason         = attr(raw_txt, "aira_msg") %||% err,
            duration_ms    = as.integer(round((proc.time()[["elapsed"]] - t0) * 1000))))
  }

  val <- tryCatch(prompt$response_validator(raw_txt),
                  error = function(e) list(ok = FALSE, reason = conditionMessage(e)))
  if (!isTRUE(val$ok))
    return(aira_empty_response("malformed", prompt_version = prompt_version,
            reason       = val$reason %||% "validation_failed",
            duration_ms  = as.integer(round((proc.time()[["elapsed"]] - t0) * 1000)),
            raw_response = raw_txt))

  list(status = "ok", prompt_version = prompt_version,
       duration_ms = as.integer(round((proc.time()[["elapsed"]] - t0) * 1000)),
       content = raw_txt)
}

# Async variant - future-based, returns a promise like aira_draft_cohort_async.
aira_concept_summary_async <- function(concept_info, cfg = NULL) {
  if (!requireNamespace("promises", quietly = TRUE) ||
      !requireNamespace("future",   quietly = TRUE))
    return(promises::promise_resolve(
      aira_empty_response("unavailable", reason = "async_packages_missing")))
  cfg_local <- aira_resolve_cfg(cfg)
  ci_local  <- concept_info
  t_outer   <- proc.time()[["elapsed"]]
  prom <- promises::future_promise({
    aira_concept_summary(ci_local, cfg_local)
  }, seed = NULL)
  promises::then(prom,
    onFulfilled = function(resp) {
      if (is.list(resp) && !is.null(resp$timing_ms))
        resp$timing_ms$future_overhead_ms <- as.integer(round(
          (proc.time()[["elapsed"]] - t_outer) * 1000 - (resp$duration_ms %||% 0L)))
      resp
    },
    onRejected = function(e)
      aira_empty_response("unavailable",
                          reason = paste0("async_rejection: ", conditionMessage(e))))
}

# ── EVENT LOGGING HELPER (R-AIRA-09) ─────────────────────────────────────────
# Logs an AIRA call to the existing app activity stream. The Shiny layer
# wraps every aira_* call with this. Payload always includes prompt_version,
# duration_ms, and per-phase timings.
aira_log_event <- function(call_name, resp, input_chars = NA_integer_,
                            extra = list()) {
  ev <- switch(resp$status %||% "",
    "ok"          = list(level = "INFO", name = paste0(call_name, "_completed")),
    "timeout"     = list(level = "WARN", name = paste0(call_name, "_timeout")),
    "unavailable" = list(level = "WARN", name = paste0(call_name, "_unavailable")),
    "malformed"   = list(level = "WARN", name = paste0(call_name, "_malformed_output")),
    "disabled"    = list(level = "INFO", name = paste0(call_name, "_disabled_by_config")),
    list(level = "WARN", name = paste0(call_name, "_unknown_status")))
  payload <- c(list(
    prompt_version = resp$prompt_version %||% "",
    duration_ms    = resp$duration_ms    %||% 0L,
    status         = resp$status         %||% "",
    reason         = resp$reason         %||% "",
    input_chars    = as.integer(input_chars),
    client_construction_ms = resp$timing_ms$client_construction_ms %||% NA_integer_,
    inference_ms           = resp$timing_ms$inference_ms           %||% NA_integer_,
    parse_ms               = resp$timing_ms$parse_ms               %||% NA_integer_,
    future_overhead_ms     = resp$timing_ms$future_overhead_ms     %||% NA_integer_
  ), extra)
  message(sprintf("[AIRA][%s] %s - %s",
                   ev$level, ev$name,
                   paste(sprintf("%s=%s", names(payload), payload),
                         collapse = "; ")))
  invisible(list(event = ev, payload = payload))
}

# v10.1 instrumentation: announce that AIRA helpers were sourced. If you don't
# see this line at app startup, the AIRA block didn't execute at all (likely
# a parse error somewhere above, or you're running a different file). The
# startup status dump shows the result of every gate check at this moment in
# time. Setting AIRA_DEBUG=1 in the environment or aira_debug=TRUE in options
# turns on per-call gate-decision logging.
local({
  message("[AIRA] module loaded - helpers defined: ",
          paste(c("aira_is_enabled", "aira_default_cfg",
                  "aira_status_summary", "aira_draft_cohort",
                  "aira_draft_cohort_async",
                  "aira_concept_summary", "aira_concept_summary_async",
                  "PROMPTS", "ACTIVE_PROMPT"),
                collapse = ", "))
  st <- aira_status_summary()
  message(sprintf("[AIRA] startup status: cfg_enabled=%s packages_ok=%s api_key_present=%s base_url=%s model=%s enabled_overall=%s",
                   st$cfg_enabled, st$packages_ok, st$api_key_present,
                   st$base_url, st$model, st$enabled_overall))
  if (!st$enabled_overall) {
    reasons <- character(0)
    if (!st$cfg_enabled)
      reasons <- c(reasons,
        "cfg$aira$enabled is not TRUE - set AIRA_ENABLED=1 in the workspace environment (or options(aira_cfg=list(enabled=TRUE,...)) for interactive use)")
    if (!st$packages_ok)
      reasons <- c(reasons,
        sprintf("at least one of [%s] is not installed",
                paste(aira_optional_packages, collapse = ", ")))
    if (!st$api_key_present)
      reasons <- c(reasons,
        "WORKSPACE_API_KEY env var is not set in the app's R process")
    for (r in reasons) message("[AIRA] -> ", r)
  }
})


# ══════════════════════════════════════════════════════════════════════════════


# ── 3. DATABASE CONNECTION ────────────────────────────────────────────────────

# v10.14: RPostgres (used only by the OHDSI Tools tab) fails on date columns
# when the R session has no valid timezone ("CCTZ: Unrecognized output
# timezone"). DRE R sessions can start with TZ unset. Fill that gap with UTC,
# the correct canonical default for OMOP date handling; never override a TZ the
# workspace has deliberately configured. Set once here so it does not leak in
# implicitly later. The existing xap.conn path is indifferent to this.
if (!nzchar(Sys.getenv("TZ"))) Sys.setenv(TZ = "UTC")

DRE_CONN <- tryCatch(
  { library(xaputils); message("[ cohort builder ] connected via xap.conn"); xap.conn },
  error = function(e) {
    message("[ cohort builder ] xaputils not available - no DB connection")
    NULL
  }
)

conn_valid <- function() !is.null(DRE_CONN)

db_query <- function(sql) {
  if (!conn_valid()) stop("No database connection.")
  # Always lowercase column names so results work regardless of whether the
  # schema stores them uppercase (e.g. MIMIC after ETL) or lowercase (Synthea).
  # RPostgreSQL preserves the stored case for bare column references but folds
  # unquoted AS aliases to lowercase - lowercasing here is idempotent and safe.
  result <- withCallingHandlers(
    DBI::dbGetQuery(DRE_CONN, sql),
    warning = function(w) {
      if (grepl("unrecognized PostgreSQL|unknown data type", conditionMessage(w), ignore.case = TRUE))
        invokeRestart("muffleWarning")
    }
  )
  if (is.data.frame(result) && ncol(result) > 0)
    names(result) <- tolower(names(result))
  result
}

db_execute <- function(sql) {
  if (!conn_valid()) stop("No database connection.")
  DBI::dbExecute(DRE_CONN, sql)
}


# ── 3b. OHDSI / CDMConnector BRIDGE (v10.14) ──────────────────────────────────
# The OHDSI R ecosystem (CDMConnector, OmopSketch) drives a modern DBI
# connection and generates its own SQL through dbplyr. It cannot use xap.conn:
# that is the legacy RPostgreSQL driver (class PostgreSQLConnection), which does
# not implement the DBI surface CDMConnector needs (dbIsValid and friends).
# So the OHDSI Tools tab opens a SECOND connection via RPostgres to the same
# database, alongside the xap.conn every other tab uses. This is additive and
# optional: nothing else in the app touches it, and the app runs identically
# when the packages are absent.

ohdsi_pkgs_available <- function() {
  all(vapply(ohdsi_optional_packages,
             function(p) requireNamespace(p, quietly = TRUE), logical(1)))
}

# Single source of truth for whether the OHDSI path is usable at all: packages
# present AND a base DB connection exists. The RPostgres connection itself is
# opened lazily so a packages-present but connect-failing workspace still loads
# the app and shows a clear state rather than erroring at startup.
ohdsi_is_available <- function() ohdsi_pkgs_available() && conn_valid()

# Assemble RPostgres connection parameters from the live xap.conn (host, dbname,
# user, port via dbGetInfo) with PG* env vars as fallback. The password is never
# read here: RPostgres picks it up from PGPASSWORD or ~/.pgpass exactly as the
# workspace already provides it. xap.conn is referenced inline, never captured.
ohdsi_conn_params <- function() {
  nz <- function(x) if (!is.null(x) && length(x) == 1 && !is.na(x) &&
                        nzchar(as.character(x))) as.character(x) else NULL
  info <- tryCatch(DBI::dbGetInfo(xaputils::xap.conn), error = function(e) list())
  env  <- as.list(Sys.getenv(c("PGHOST", "PGPORT", "PGDATABASE", "PGUSER")))
  list(
    host   = nz(info$host)   %||% nz(env$PGHOST),
    dbname = nz(info$dbname) %||% nz(env$PGDATABASE),
    user   = nz(info$user)   %||% nz(env$PGUSER),
    port   = as.integer(nz(info$port) %||% nz(env$PGPORT) %||% "5432")
  )
}

# Open a fresh RPostgres connection for OHDSI tooling. Returns a PqConnection or
# NULL on failure. timezone fixed to UTC (see the startup TZ guard in section 3).
ohdsi_open_connection <- function() {
  if (!ohdsi_pkgs_available()) return(NULL)
  p <- ohdsi_conn_params()
  if (is.null(p$host) || is.null(p$dbname) || is.null(p$user)) {
    message("[ohdsi] connection params incomplete; cannot open RPostgres connection")
    return(NULL)
  }
  tryCatch(
    DBI::dbConnect(RPostgres::Postgres(),
                   host = p$host, dbname = p$dbname, user = p$user,
                   port = p$port, timezone = "UTC", timezone_out = "UTC"),
    error = function(e) {
      message("[ohdsi] RPostgres connect failed: ", conditionMessage(e))
      NULL
    }
  )
}

# Build a cdm_reference for a schema on an existing RPostgres connection.
# Returns the cdm object or NULL. .softValidation = TRUE so schemas that are
# imperfect but usable still build; OmopSketch surfaces conformance problems
# (e.g. text-typed dates) downstream rather than failing the whole reference.
ohdsi_build_cdm <- function(con, schema) {
  if (is.null(con)) return(NULL)
  tryCatch(
    CDMConnector::cdmFromCon(con, cdmSchema = schema, writeSchema = schema,
                             cdmName = schema, .softValidation = TRUE),
    error = function(e) {
      message("[ohdsi] cdmFromCon failed for ", schema, ": ", conditionMessage(e))
      NULL
    }
  )
}

# Build a cdm_reference with an existing cohort table attached, for read-only
# cohort characterisation. cohortTables reads the named table (and its
# _set/_attrition companions if present) from the schema and wraps it as a
# cohort_table; the cohort is then at cdm[[cohort_table]]. Separate from the
# profiling cdm so nothing else is disturbed.
ohdsi_build_cohort_cdm <- function(con, schema, cohort_table) {
  if (is.null(con) || !nzchar(cohort_table)) return(NULL)
  tryCatch(
    CDMConnector::cdmFromCon(con, cdmSchema = schema, writeSchema = schema,
                             cohortTables = cohort_table, cdmName = schema,
                             .softValidation = TRUE),
    error = function(e) {
      message("[ohdsi] cohort cdmFromCon failed for ", schema, "/", cohort_table,
              ": ", conditionMessage(e))
      NULL
    }
  )
}

# Discover cohort tables in a schema: any table carrying all four standard
# cohort columns (cohort_definition_id, subject_id, cohort_start_date,
# cohort_end_date). Uses the live xap.conn and information_schema, lower-casing
# column names so it works regardless of schema column casing. Read-only.
ohdsi_discover_cohort_tables <- function(schema) {
  if (!conn_valid() || !nzchar(schema %||% "")) return(character(0))
  sch <- DBI::dbQuoteString(DRE_CONN, schema)
  sql <- sprintf(
    "SELECT table_name FROM information_schema.columns
      WHERE table_schema = %s
        AND lower(column_name) IN
            ('cohort_definition_id','subject_id','cohort_start_date','cohort_end_date')
      GROUP BY table_name
      HAVING COUNT(DISTINCT lower(column_name)) = 4
      ORDER BY table_name", sch)
  r <- tryCatch(DBI::dbGetQuery(DRE_CONN, sql), error = function(e) NULL)
  if (is.null(r) || nrow(r) == 0) character(0) else as.character(r[[1]])
}

# Of the given schemas, which contain a cohort table (a table with all four
# standard cohort columns)? One batched information_schema query, used to badge
# cohort schemas in the selector. Read-only, no OHDSI packages.
ohdsi_cohort_schema_set <- function(schema_names) {
  schema_names <- unique(schema_names[nzchar(schema_names %||% "")])
  if (!conn_valid() || length(schema_names) == 0) return(character(0))
  inlist <- paste(DBI::dbQuoteString(DRE_CONN, schema_names), collapse = ", ")
  sql <- sprintf(
    "SELECT table_schema FROM (
       SELECT table_schema, table_name
       FROM information_schema.columns
       WHERE table_schema IN (%s)
         AND lower(column_name) IN
             ('cohort_definition_id','subject_id','cohort_start_date','cohort_end_date')
       GROUP BY table_schema, table_name
       HAVING COUNT(DISTINCT lower(column_name)) = 4
     ) t GROUP BY table_schema", inlist)
  r <- tryCatch(DBI::dbGetQuery(DRE_CONN, sql), error = function(e) NULL)
  if (is.null(r) || nrow(r) == 0) character(0) else as.character(r[[1]])
}

# OmopSketch returns omopgenerics 'summarised_result' objects in long format.
# They inherit from data.frame, but coerce defensively in case a version
# differs - returns a plain data.frame or NULL.
ohdsi_sr_to_df <- function(x) {
  df <- tryCatch(as.data.frame(x, stringsAsFactors = FALSE), error = function(e) NULL)
  if (is.data.frame(df)) df else NULL
}

# Project the standard summarised_result columns when present for a readable
# table; fall back to all columns if the shape is not what we expect.
ohdsi_sr_tidy <- function(df) {
  if (is.null(df) || nrow(df) == 0) return(df)
  # summarised_result is long format. Keep the descriptive columns plus the
  # time/detail that lives in additional_* (where summariseTrend puts the year),
  # then drop any column constant across all rows (e.g. strata "overall", a
  # single repeated variable_name) so only the dimensions that actually vary
  # remain. This keeps trend years visible and declutters the flat summaries.
  want <- c("group_level", "strata_level", "variable_name", "variable_level",
            "additional_level", "estimate_name", "estimate_value")
  have <- intersect(want, names(df))
  if (length(have) < 3) return(df)
  out <- df[, have, drop = FALSE]
  if ("additional_level" %in% names(out)) {
    an  <- unique(df[["additional_name"]])
    lbl <- if (length(an) == 1 && !is.na(an) && nzchar(an) && an != "overall")
             an else "detail"
    names(out)[names(out) == "additional_level"] <- lbl
    vals <- out[[lbl]]
    if (all(is.na(vals) | vals %in% c("", "overall"))) out[[lbl]] <- NULL
  }
  keepcol <- function(nm) nm %in% c("estimate_name", "estimate_value") ||
                          length(unique(out[[nm]])) > 1
  out[, vapply(names(out), keepcol, logical(1)), drop = FALSE]
}

# snake_case / dotted column names to Title case for display.
ohdsi_humanise <- function(nm) vapply(nm, function(x) {
  x <- trimws(gsub("[._]+", " ", x))
  if (!nzchar(x)) return(x)
  paste0(toupper(substr(x, 1, 1)), substr(x, 2, nchar(x)))
}, character(1), USE.NAMES = FALSE)

# Clean wide frame from a summarised_result for display when a formatted table
# renderer is unavailable or errors. omopgenerics::tidy splits the group, strata,
# and additional name-level pairs into real columns (removing the &&& joins) and
# pivots the estimates into columns; then drop bookkeeping and constant columns
# and humanise the names. Falls back to the raw long projection if tidy is
# unavailable, so this never errors itself.
ohdsi_sr_clean <- function(result) {
  df <- tryCatch(as.data.frame(omopgenerics::tidy(result), check.names = FALSE,
                               stringsAsFactors = FALSE), error = function(e) NULL)
  if (is.null(df)) df <- ohdsi_sr_tidy(ohdsi_sr_to_df(result))
  if (is.null(df) || nrow(df) == 0) return(df)
  df <- as.data.frame(df, check.names = FALSE, stringsAsFactors = FALSE)
  admin    <- names(df) %in% c("result_id", "estimate_type", "cdm_name")
  is_const <- vapply(df, function(col) length(unique(col)) <= 1, logical(1))
  drop     <- admin | is_const
  if (all(drop)) drop <- rep(FALSE, ncol(df))
  df <- df[, !drop, drop = FALSE]
  names(df) <- ohdsi_humanise(names(df))
  df
}

# Render a result as a gt table through the ecosystem layer: visOmopResults
# visOmopTable() when it is a summarised_result, falling back to a plain gt of
# the tidy frame if the formatted renderer fails or the input is a plain data
# frame (e.g. omopgenerics::bind was unavailable). Always returns a gt object so
# the Shiny output type stays uniform.
# OHDSI tables render through a single switchable type, so the whole tab can
# move between gt (static), reactable, and DT (interactive) by changing one
# setting. Interactive types need their package; if absent we fall back to gt so
# the tab still renders. visOmopResults / CohortCharacteristics do the pivoting
# and formatting first, then hand off to the chosen renderer, so the structure
# is identical across types - only the interactivity differs.
OHDSI_TABLE_TYPE <- "reactable"   # "reactable" | "datatable" | "gt"

ohdsi_tbl_mode <- function() {
  t <- OHDSI_TABLE_TYPE
  if (identical(t, "reactable") && requireNamespace("reactable", quietly = TRUE)) "reactable"
  else if (identical(t, "datatable") && requireNamespace("DT", quietly = TRUE)) "datatable"
  else "gt"
}

# UI output slot matching the active mode.
ohdsi_tbl_out <- function(id) switch(ohdsi_tbl_mode(),
  reactable = reactable::reactableOutput(id),
  datatable = DT::dataTableOutput(id),
  gt::gt_output(id))

# Dark reactable theme matching the dashboard palette, so the search bar, header,
# body, and pagination read on the dark cards instead of the default white.
ohdsi_reactable_theme <- function() reactable::reactableTheme(
  color = "#E8F4F8", backgroundColor = "#0D2A4A",
  borderColor = "rgba(255,255,255,0.10)", stripedColor = "#0F2F52",
  highlightColor = "#133660", cellPadding = "6px 8px",
  style = list(fontSize = "0.84rem"),
  headerStyle = list(backgroundColor = "#0B2341", color = "#E8F4F8",
    fontWeight = 600, borderColor = "rgba(255,255,255,0.12)"),
  searchInputStyle = list(backgroundColor = "#0B2341", color = "#E8F4F8",
    border = "1px solid rgba(255,255,255,0.15)", borderRadius = "4px"),
  inputStyle = list(backgroundColor = "#0B2341", color = "#E8F4F8"),
  filterInputStyle = list(backgroundColor = "#0B2341", color = "#E8F4F8"),
  selectStyle = list(backgroundColor = "#0B2341", color = "#E8F4F8"),
  paginationStyle = list(color = "#E8F4F8"),
  pageButtonHoverStyle = list(backgroundColor = "#133660"),
  pageButtonActiveStyle = list(backgroundColor = "#133660"),
  pageButtonCurrentStyle = list(backgroundColor = "#133660", color = "#E8F4F8"))

# Render a prepared data frame in the active table type. The dark theme applies
# to reactable; DT is themed by the app CSS and gt is a static fallback.
ohdsi_render_df <- function(df, mode = ohdsi_tbl_mode()) switch(mode,
  reactable = reactable::reactable(df, searchable = TRUE, sortable = TRUE,
    defaultPageSize = 12, striped = TRUE, highlight = TRUE, compact = TRUE,
    resizable = TRUE, theme = ohdsi_reactable_theme()),
  datatable = DT::datatable(df, rownames = FALSE, filter = "none",
    options = list(pageLength = 12, scrollX = TRUE, dom = "ftip")),
  gt::gt(df))

# Collapse a visOmopResults header path (levels joined by the newline delimiter
# for non-spanning backends) to its leaf label, so multi-level headers do not
# stack into one cell.
ohdsi_clean_header <- function(nm) vapply(nm, function(x) {
  parts <- trimws(strsplit(x, "\n", fixed = TRUE)[[1]])
  parts <- parts[nzchar(parts)]
  if (length(parts) == 0) x else parts[length(parts)]
}, character(1), USE.NAMES = FALSE)

# Build a table for an OHDSI summarised_result. visOmopResults formats the data
# (type = "tibble", cdm_name level hidden, header names off); the app renders the
# widget itself so it is dark-themed with clean single-line headers. A retry
# without the formatting args, then the raw tidy frame, keeps this resilient to
# renderers that reject the args or to plain-frame input.
ohdsi_make_table <- function(result, kind = "visomop", mode = ohdsi_tbl_mode()) {
  if (is.null(result)) return(NULL)
  flat <- list(hide = "cdm_name", .options = list(includeHeaderName = FALSE))
  to_tibble <- function(extra) switch(kind,
    characteristics = do.call(CohortCharacteristics::tableCharacteristics,
                              c(list(result, type = "tibble"), extra)),
    attrition       = CohortCharacteristics::tableCohortAttrition(result, type = "tibble"),
    code_use        = do.call(CodelistGenerator::tableCodeUse,
                              c(list(result, type = "tibble"), extra)),
    snapshot        = do.call(OmopSketch::tableOmopSnapshot,
                              c(list(result, type = "tibble"), extra)),
    person          = do.call(OmopSketch::tablePerson,
                              c(list(result, type = "tibble"), extra)),
    obsperiod       = do.call(OmopSketch::tableObservationPeriod,
                              c(list(result, type = "tibble"), extra)),
    concept_counts  = do.call(OmopSketch::tableConceptIdCounts,
                              c(list(result, type = "tibble"), extra)),
    survival        = CohortSurvival::tableSurvival(result, type = "tibble"),
    incidence       = IncidencePrevalence::tableIncidence(result, type = "tibble"),
    prevalence      = IncidencePrevalence::tablePrevalence(result, type = "tibble"),
    do.call(visOmopResults::visOmopTable, c(list(result, type = "tibble"), extra)))
  df <- NULL
  if (inherits(result, "summarised_result")) {
    df <- tryCatch(to_tibble(flat), error = function(e) NULL)
    if (is.null(df)) df <- tryCatch(to_tibble(list()), error = function(e) NULL)
  }
  if (is.null(df)) df <- ohdsi_sr_clean(result)
  if (is.null(df)) df <- data.frame(note = "Unrenderable result.")
  df <- as.data.frame(df, check.names = FALSE, stringsAsFactors = FALSE)
  names(df) <- ohdsi_clean_header(names(df))
  ohdsi_render_df(df, mode)
}

# Assign a render of the active type for an OHDSI table. get_result() reads the
# relevant reactiveVal (evaluated inside the reactive render, so reactivity
# holds); kind selects the renderer. mode is fixed per session.
ohdsi_table_render <- function(get_result, kind = "visomop") {
  mode  <- ohdsi_tbl_mode()
  build <- function() { r <- get_result(); req(!is.null(r)); ohdsi_make_table(r, kind, mode) }
  switch(mode,
    reactable = reactable::renderReactable(build()),
    datatable = DT::renderDataTable(build()),
    gt::render_gt(build()))
}

# xlsx export for the OHDSI summaries. openxlsx/writexl are optional (never in
# the hard guard): if a writer is present the export is a multi-sheet .xlsx, one
# sheet per summary; otherwise it falls back to a .zip of per-sheet CSVs (zip is
# available in the DRE, as the compare-export already uses it). All exports are
# mirrored to DOWNLOADS_DIR by the download handler, per app convention.
ohdsi_xlsx_writer <- function() {
  if (requireNamespace("openxlsx", quietly = TRUE)) return("openxlsx")
  if (requireNamespace("writexl",  quietly = TRUE)) return("writexl")
  NA_character_
}
ohdsi_export_ext <- function() if (!is.na(ohdsi_xlsx_writer())) "xlsx" else "zip"

# Write a named list of data frames to `file`. Returns the extension written.
ohdsi_write_export <- function(sheets, file) {
  w <- ohdsi_xlsx_writer()
  nm31 <- function(x) substr(x, 1, 31)                 # Excel sheet-name limit
  if (identical(w, "openxlsx")) {
    wb <- openxlsx::createWorkbook()
    for (nm in names(sheets)) {
      s <- nm31(nm); openxlsx::addWorksheet(wb, s)
      openxlsx::writeData(wb, s, sheets[[nm]])
    }
    openxlsx::saveWorkbook(wb, file, overwrite = TRUE); return("xlsx")
  }
  if (identical(w, "writexl")) {
    names(sheets) <- vapply(names(sheets), nm31, character(1))
    writexl::write_xlsx(sheets, file); return("xlsx")
  }
  # Fallback: zip one CSV per sheet.
  tmp <- tempfile("ohdsi_export_"); dir.create(tmp)
  for (nm in names(sheets))
    utils::write.csv(sheets[[nm]], file.path(tmp, paste0(nm, ".csv")), row.names = FALSE)
  old <- setwd(tmp); on.exit(setwd(old), add = TRUE)
  utils::zip(file, list.files(".", pattern = "\\.csv$")); "zip"
}

# Is a named function exported by the installed OmopSketch? Guards against
# version drift (e.g. summariseConceptIdCounts absent or renamed).
ohdsi_has_fn <- function(fn) {
  isTRUE(tryCatch(fn %in% getNamespaceExports("OmopSketch"),
                  error = function(e) FALSE))
}

# summariseConceptIdCounts() requires an explicit omopTableName vector - it does
# not default to "all clinical tables". Derive the list as the OmopSketch
# supported clinical tables (clinicalTables()) intersected with the tables
# actually present in this cdm, so each schema counts what it has. Falls back to
# a standard clinical-table list if clinicalTables() is absent in this version.
ohdsi_count_tables <- function(cdm) {
  supported <- tryCatch({
    if (ohdsi_has_fn("clinicalTables")) {
      v <- OmopSketch::clinicalTables()
      if (is.character(v)) v else as.character(unlist(v, use.names = FALSE))
    } else NULL
  }, error = function(e) NULL)
  if (is.null(supported) || length(supported) == 0)
    supported <- c("observation_period", "visit_occurrence", "visit_detail",
                   "condition_occurrence", "drug_exposure", "procedure_occurrence",
                   "device_exposure", "measurement", "observation", "death",
                   "note", "specimen", "drug_era", "dose_era", "condition_era")
  present <- tryCatch(names(cdm), error = function(e) character(0))
  # observation_period carries no domain concept-id, so concept counting over it
  # fails inside OmopSketch's rename; exclude it explicitly.
  setdiff(intersect(supported, present), "observation_period")
}


# ── 4. SCHEMA / TABLE HELPERS ─────────────────────────────────────────────────

# get_schemas uses xaputils::xap.conn directly so it always reflects the live
# connection state.  Returns a data.frame: schema_name, table_count, omop_hits.
# omop_hits is the count of OMOP_CORE_TABLES present in the schema; used to
# filter the schema selector to OMOP-only schemas.
# Excludes pg internals and the public housekeeping schema.
get_schemas <- function() {
  conn <- tryCatch(
    { if (exists("xap.conn", envir = .GlobalEnv, inherits = FALSE))
        get("xap.conn", envir = .GlobalEnv)
      else
        DRE_CONN },
    error = function(e) DRE_CONN
  )
  if (is.null(conn)) return(data.frame(schema_name = character(0),
                                        table_count  = integer(0),
                                        omop_hits    = integer(0),
                                        stringsAsFactors = FALSE))
  # Build a quoted IN-list of OMOP core table names for the sub-query
  omop_in <- paste(sapply(OMOP_CORE_TABLES, pg_str), collapse = ", ")
  tryCatch({
    DBI::dbGetQuery(conn, sprintf(
      "SELECT s.schema_name,
              COUNT(t.table_name)::int AS table_count,
              COUNT(CASE WHEN lower(t.table_name) IN (%s) THEN 1 END)::int AS omop_hits
       FROM   information_schema.schemata s
       LEFT JOIN information_schema.tables t
              ON  t.table_schema = s.schema_name
              AND t.table_type   = 'BASE TABLE'
       WHERE  s.schema_name NOT IN (
                'information_schema','pg_catalog','pg_toast',
                'pg_temp_1','pg_toast_temp_1','public'
              )
         AND  s.schema_name NOT LIKE 'pg_%%'
       GROUP  BY s.schema_name
       ORDER  BY s.schema_name",
      omop_in))
  }, error = function(e) {
    message("[ cohort builder ] get_schemas error: ", e$message)
    data.frame(schema_name = character(0), table_count = integer(0),
               omop_hits = integer(0), stringsAsFactors = FALSE)
  })
}

get_tables <- function(schema) {
  tryCatch({
    r <- db_query(sprintf(
      "SELECT table_name FROM information_schema.tables
       WHERE table_schema = %s AND table_type = 'BASE TABLE'
       ORDER BY table_name", pg_str(schema)))
    r$table_name
  }, error = function(e) character(0))
}

# ── 5. OMOP DETECTION ─────────────────────────────────────────────────────────

OMOP_CORE_TABLES <- c(
  "person", "observation_period", "visit_occurrence",
  "condition_occurrence", "drug_exposure", "procedure_occurrence",
  "measurement", "observation", "concept"
)

detect_omop <- function(schema) {
  tbls <- tolower(get_tables(schema))
  hits <- intersect(tbls, OMOP_CORE_TABLES)
  list(is_omop = length(hits) >= 5, hits = hits, n_total = length(tbls))
}

# ── 5b. OMOP COLUMN NAME MAP ──────────────────────────────────────────────────
# RPostgreSQL returns uppercase column names from PostgreSQL when columns were
# created with double-quoted identifiers (e.g. "PERSON_ID").  All generated SQL
# must use the actual stored name, not the logical lowercase name.
#
# get_omop_col_map() fetches actual column names for all OMOP tables in one
# query and returns a nested list:  map[[table]][[lower_col]] = actual_col
#
# ac(map, table, col) returns qq(actual_col) ready for insertion into SQL.

WORKSPACE_FILES <- "/home/workspace/files"
DOWNLOADS_DIR   <- file.path(WORKSPACE_FILES, "Downloads")

# v9.2: global plot resolution. Shiny's renderPlot defaults to ~72 DPI which
# makes ggplot text render at ~10-13 pixels for typical theme sizes. Bumping
# to 110 multiplies on-screen text size by ~1.5x without changing the plot
# container size. Every renderPlot in this file passes res = PLOT_RES.
PLOT_RES <- 110L

OMOP_TABLES_OF_INTEREST <- c(
  "observation_period", "person", "concept", "concept_ancestor",
  "condition_occurrence", "drug_exposure", "procedure_occurrence",
  "measurement", "observation", "visit_occurrence", "death"
)

# Maximum total records for always-on live estimate (Step 6).
LIVE_ESTIMATE_MAX_RECORDS <- 50e6

get_omop_col_map <- function(schema) {
  # Query information_schema for actual stored column names.
  # RPostgreSQL uppercases result column headers, so we normalise names(r)
  # immediately. The VALUES (actual column names) are returned as stored -
  # lowercase for unquoted DDL, exact case for quoted DDL.
  sql <- sprintf(
    "SELECT lower(table_name) AS tbl, column_name AS col
     FROM   information_schema.columns
     WHERE  table_schema = %s
       AND  lower(table_name) IN (%s)",
    pg_str(schema),
    paste(sapply(OMOP_TABLES_OF_INTEREST, pg_str), collapse = ","))
  r <- tryCatch(db_query(sql), error = function(e) NULL)
  if (is.null(r) || nrow(r) == 0) return(list())
  # Normalise result column headers to lowercase so r$tbl / r$col always work
  # regardless of whether RPostgreSQL returns TBL/COL or tbl/col.
  names(r) <- tolower(names(r))
  # After normalisation r$tbl and r$col are accessible. If the alias was
  # returned under a different name, fall back to positional access.
  tbl_vec <- if (!is.null(r$tbl)) r$tbl else r[[1]]
  col_vec <- if (!is.null(r$col)) r$col else r[[2]]
  result <- list()
  for (i in seq_len(nrow(r))) {
    tbl <- tbl_vec[i]
    col <- col_vec[i]
    if (is.na(tbl) || is.na(col)) next
    if (is.null(result[[tbl]])) result[[tbl]] <- list()
    # Key: always lowercase for lookup; value: actual stored name for quoting
    result[[tbl]][[tolower(col)]] <- col
  }
  result
}

# Resolve actual column name from map, fall back to logical name, always quoted
ac <- function(col_map, table, col) {
  actual <- col_map[[tolower(table)]][[tolower(col)]]
  qq(actual %||% col)
}

# ── 5c. SCHEMA DATA SUMMARY ───────────────────────────────────────────────────
# Loads person count, observation period range, and per-domain row counts.
# Returns NULL on any connection failure.

get_schema_summary <- function(schema, col_map = list()) {
  tryCatch({
    # Fetch list of actual tables once
    existing_tbls <- tryCatch({
      tolower(get_tables(schema))
    }, error = function(e) character(0))

    op_tbl <- "observation_period"
    obs <- if ("observation_period" %in% existing_tbls)
      tryCatch(db_query(sprintf(
        "SELECT COUNT(DISTINCT %s)::int       AS n_persons,
                MIN(%s)                        AS min_date,
                MAX(%s)                        AS max_date
         FROM   %s",
        ac(col_map, op_tbl, "person_id"),
        ac(col_map, op_tbl, "observation_period_start_date"),
        ac(col_map, op_tbl, "observation_period_end_date"),
        fq(schema, op_tbl))),
        error = function(e) NULL)
    else NULL

    domain_counts <- lapply(names(DOMAINS), function(key) {
      dom <- DOMAINS[[key]]
      if (!tolower(dom$table) %in% existing_tbls)
        return(list(n_persons = NA_integer_, n_records = NA_integer_))
      r <- tryCatch(db_query(sprintf(
        "SELECT COUNT(DISTINCT %s)::int AS n_persons,
                COUNT(*)::int           AS n_records
         FROM   %s",
        ac(col_map, dom$table, dom$person_col),
        fq(schema, dom$table))),
        error = function(e) NULL)
      list(
        n_persons = if (!is.null(r)) as.integer(r$n_persons[1]) else NA_integer_,
        n_records = if (!is.null(r)) as.integer(r$n_records[1]) else NA_integer_
      )
    })
    names(domain_counts) <- names(DOMAINS)

    list(
      n_persons = if (!is.null(obs)) as.integer(obs$n_persons[1]) else NA_integer_,
      min_date  = if (!is.null(obs)) as.character(obs$min_date[1])  else NA_character_,
      max_date  = if (!is.null(obs)) as.character(obs$max_date[1])  else NA_character_,
      domains   = domain_counts
    )
  }, error = function(e) NULL)
}

# ── 5c2. SCHEMA PROFILE (v10.12) ──────────────────────────────────────────────
# Extended schema introspection for the Schema Profile card.
# Returns:
#   $cdm_version    character  CDM version string or "unknown"
#   $ancestor_status character "green" / "amber" / "red"
#   $ancestor_rows  integer    row count in concept_ancestor (or 0)
#   $vocab_mix_df   data.frame vocabulary_id / n_records (top 5 across domains)
#   $domain_stats_df data.frame key / n_persons / n_records / min_date / max_date
#   $total_records  numeric    sum of all domain record counts
schema_profile <- function(schema, col_map) {
  tryCatch({
    existing_tbls <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))

    # ── CDM version ────────────────────────────────────────────────────────────
    cdm_version <- tryCatch({
      # vocabulary is NOT in OMOP_TABLES_OF_INTEREST; look up its columns directly
      vcol_r <- db_query(sprintf(
        "SELECT column_name FROM information_schema.columns
         WHERE  table_schema = %s AND lower(table_name) = 'vocabulary'
           AND  lower(column_name) = 'cdm_version' LIMIT 1", pg_str(schema)))
      if (nrow(vcol_r) == 0) {
        "unknown"
      } else {
        vcol <- vcol_r[[1]][1]
        r <- db_query(sprintf('SELECT "%s" AS cdm_ver FROM %s LIMIT 1', vcol, fq(schema, "vocabulary")))
        if (nrow(r) > 0 && !is.na(r[[1]][1])) as.character(r[[1]][1]) else "unknown"
      }
    }, error = function(e) "unknown")

    # ── Concept ancestor availability ──────────────────────────────────────────
    ancestor_rows <- 0L
    ancestor_status <- "red"
    if ("concept_ancestor" %in% existing_tbls) {
      cnt <- tryCatch({
        r <- db_query(sprintf("SELECT COUNT(*)::int AS n FROM %s", fq(schema, "concept_ancestor")))
        as.integer(r$n[1])
      }, error = function(e) 0L)
      ancestor_rows <- cnt %||% 0L
      ancestor_status <- if (ancestor_rows > 10000L) "green"
                         else if (ancestor_rows > 0L) "amber"
                         else "red"
    }

    # ── Vocabulary mix across populated domain tables ───────────────────────────
    vocab_mix_df <- tryCatch({
      has_concept <- "concept" %in% existing_tbls
      if (!has_concept) return(data.frame(vocabulary_id = character(0), n_records = integer(0)))
      cid_col_concept <- ac(col_map, "concept", "concept_id")
      vocab_col_concept <- ac(col_map, "concept", "vocabulary_id")
      # Build UNION of concept_id columns across all populated domain tables
      domain_parts <- vapply(names(DOMAINS), function(key) {
        dom <- DOMAINS[[key]]
        if (!tolower(dom$table) %in% existing_tbls) return(NA_character_)
        sprintf("SELECT %s AS cid FROM %s",
                ac(col_map, dom$table, dom$concept_col),
                fq(schema, dom$table))
      }, character(1))
      domain_parts <- domain_parts[!is.na(domain_parts)]
      if (length(domain_parts) == 0) return(data.frame(vocabulary_id = character(0), n_records = integer(0)))
      union_sql <- paste(domain_parts, collapse = "
      UNION ALL
      ")
      sql <- sprintf(
        "SELECT c.%s AS vocabulary_id, COUNT(*) AS n_records
         FROM (%s) d
         JOIN %s c ON c.%s = d.cid
         GROUP BY 1
         ORDER BY 2 DESC
         LIMIT 5",
        vocab_col_concept, union_sql, fq(schema, "concept"), cid_col_concept)
      r <- db_query(sql)
      names(r) <- tolower(names(r))
      data.frame(vocabulary_id = as.character(r$vocabulary_id),
                 n_records = as.integer(r$n_records),
                 stringsAsFactors = FALSE)
    }, error = function(e) data.frame(vocabulary_id = character(0), n_records = integer(0)))

    # ── Per-domain stats with date range ───────────────────────────────────────
    domain_date_cols <- list(
      condition  = "condition_start_date",
      drug       = "drug_exposure_start_date",
      procedure  = "procedure_date",
      measurement = "measurement_date",
      observation = "observation_date",
      visit      = "visit_start_date",
      death      = "death_date"
    )
    domain_stats_list <- lapply(names(DOMAINS), function(key) {
      dom <- DOMAINS[[key]]
      if (!tolower(dom$table) %in% existing_tbls)
        return(data.frame(key=key, n_persons=NA_integer_, n_records=NA_integer_,
                          min_date=NA_character_, max_date=NA_character_,
                          stringsAsFactors=FALSE))
      date_col_logical <- domain_date_cols[[key]]
      has_date <- !is.null(date_col_logical) && !is.null(col_map[[tolower(dom$table)]][[tolower(date_col_logical)]])
      if (has_date) {
        dc <- ac(col_map, dom$table, date_col_logical)
        sql <- sprintf(
          "SELECT COUNT(DISTINCT %s)::int AS n_persons,
                  COUNT(*)::int           AS n_records,
                  MIN(%s)::text           AS min_date,
                  MAX(%s)::text           AS max_date
           FROM   %s",
          ac(col_map, dom$table, dom$person_col),
          dc, dc, fq(schema, dom$table))
      } else {
        sql <- sprintf(
          "SELECT COUNT(DISTINCT %s)::int AS n_persons,
                  COUNT(*)::int           AS n_records,
                  NULL::text              AS min_date,
                  NULL::text              AS max_date
           FROM   %s",
          ac(col_map, dom$table, dom$person_col),
          fq(schema, dom$table))
      }
      r <- tryCatch(db_query(sql), error = function(e) NULL)
      names(r) <- tolower(names(r))
      data.frame(
        key        = key,
        n_persons  = if (!is.null(r)) as.integer(r$n_persons[1]) else NA_integer_,
        n_records  = if (!is.null(r)) as.integer(r$n_records[1]) else NA_integer_,
        min_date   = if (!is.null(r) && !is.null(r$min_date)) as.character(r$min_date[1]) else NA_character_,
        max_date   = if (!is.null(r) && !is.null(r$max_date)) as.character(r$max_date[1]) else NA_character_,
        stringsAsFactors = FALSE
      )
    })
    domain_stats_df <- do.call(rbind, domain_stats_list)

    total_records <- sum(domain_stats_df$n_records, na.rm = TRUE)

    list(
      cdm_version     = cdm_version,
      ancestor_status = ancestor_status,
      ancestor_rows   = ancestor_rows,
      vocab_mix_df    = vocab_mix_df,
      domain_stats_df = domain_stats_df,
      total_records   = total_records
    )
  }, error = function(e) {
    message("[schema_profile] error: ", conditionMessage(e))
    NULL
  })
}


# ── 6a. CONCEPT BROWSER QUERY HELPERS (v10.12) ────────────────────────────────

# browse_concepts_by_prevalence
# Returns a df of concepts ranked by n_persons in the relevant domain table.
# Uses the primary schema only (multi-schema browsing is additive complexity
# deferred to later steps).
browse_concepts_by_prevalence <- function(schema, col_map,
                                          domain_key   = NULL,
                                          vocab_id     = NULL,
                                          standard_only = TRUE,
                                          has_data_only = TRUE,
                                          search_text  = NULL,
                                          limit        = 200L,
                                          offset       = 0L,
                                          order_by     = "persons:desc") {
  tryCatch({
    # Distinguish "get_tables errored" from "schema is empty". Without this,
    # a transient DB blip silently falls through to the no-JOIN branch and
    # returns 200 concepts alphabetically with NULL person counts.
    existing_tbls <- tryCatch(tolower(get_tables(schema)),
                              error = function(e) {
                                message("[browse_prevalence] get_tables failed for schema='",
                                        schema, "': ", conditionMessage(e))
                                NA_character_
                              })
    if (length(existing_tbls) == 1 && is.na(existing_tbls)) return(NULL)
    if (!"concept" %in% existing_tbls) {
      message("[browse_prevalence] schema='", schema,
              "' has no concept table (n_tbls=", length(existing_tbls), ")")
      return(NULL)
    }

    cid_col   <- ac(col_map, "concept", "concept_id")
    cname_col <- ac(col_map, "concept", "concept_name")
    cdom_col  <- ac(col_map, "concept", "domain_id")
    cvoc_col  <- ac(col_map, "concept", "vocabulary_id")
    ccode_col <- ac(col_map, "concept", "concept_code")
    cclass_col <- ac(col_map, "concept", "concept_class_id")
    cstd_col  <- ac(col_map, "concept", "standard_concept")
    cinv_col  <- ac(col_map, "concept", "invalid_reason")

    # Determine which domain table to JOIN for prevalence
    dom <- if (!is.null(domain_key) && domain_key %in% names(DOMAINS))
      DOMAINS[[domain_key]] else NULL
    has_dom_table <- !is.null(dom) && tolower(dom$table) %in% existing_tbls
    message(sprintf("[browse_prevalence] schema=%s dom=%s dom_table=%s has_dom_table=%s n_tbls=%d search='%s'",
                    schema, domain_key %||% "NULL",
                    if (is.null(dom)) "NULL" else dom$table,
                    has_dom_table, length(existing_tbls),
                    search_text %||% ""))

    if (has_dom_table) {
      t_pid <- ac(col_map, dom$table, dom$person_col)
      t_cid <- ac(col_map, dom$table, dom$concept_col)
      freq_sel  <- sprintf(", COUNT(DISTINCT t.%s)::int AS n_persons,\n               COUNT(*)::int AS n_records", t_pid)
      # INNER JOIN when has_data_only: only concepts that actually appear in
      # the domain table are returned. LEFT JOIN used only for exploration mode.
      join_type <- if (has_data_only) "JOIN" else "LEFT JOIN"
      freq_from <- sprintf("FROM %s c\n       %s %s t ON t.%s = c.%s",
                           fq(schema, "concept"), join_type,
                           fq(schema, dom$table), t_cid, cid_col)
      freq_grp  <- sprintf("\n       GROUP BY c.%s, c.%s, c.%s, c.%s, c.%s, c.%s, c.%s",
                           cid_col, cname_col, cdom_col, cvoc_col, ccode_col, cclass_col, cstd_col)
      # v10.13: parameterised ORDER BY. Format: "<column>:<dir>" where
      # column is one of persons, records, name, vocab, code; dir asc|desc.
      # n_schemas_present is intentionally not supported here (it doesn't
      # exist at the per-schema layer) - caller's multi merge re-sorts.
      order_by  <- {
        parts <- strsplit(order_by, ":", fixed = TRUE)[[1]]
        col_k <- if (length(parts) >= 1) parts[1] else "persons"
        dir_k <- if (length(parts) >= 2) toupper(parts[2]) else "DESC"
        if (!dir_k %in% c("ASC","DESC")) dir_k <- "DESC"
        sql_col <- switch(col_k,
          persons  = "n_persons",
          records  = "n_records",
          name     = sprintf("c.%s", cname_col),
          vocab    = sprintf("c.%s", cvoc_col),
          code     = sprintf("c.%s", ccode_col),
          "n_persons")  # default
        # Always tie-break by name asc for stable ordering
        sprintf("ORDER BY %s %s NULLS LAST, c.%s ASC",
                sql_col, dir_k, cname_col)
      }
    } else {
      freq_sel  <- ", NULL::int AS n_persons, NULL::int AS n_records"
      freq_from <- sprintf("FROM %s c", fq(schema, "concept"))
      freq_grp  <- ""
      order_by  <- sprintf("ORDER BY c.%s DESC NULLS LAST, c.%s", cstd_col, cname_col)
    }

    # WHERE clauses
    wheres <- sprintf("c.%s IS NULL", cinv_col)  # exclude invalid concepts
    if (standard_only)
      wheres <- paste0(wheres, sprintf("\n         AND c.%s = 'S'", cstd_col))
    if (!is.null(domain_key) && domain_key %in% names(DOMAINS)) {
      dom_id_val <- switch(domain_key,
        condition   = "Condition",
        drug        = "Drug",
        procedure   = "Procedure",
        measurement = "Measurement",
        observation = "Observation",
        visit       = "Visit",
        death       = "Death",
        NULL)
      if (!is.null(dom_id_val))
        wheres <- paste0(wheres, sprintf("\n         AND c.%s = %s", cdom_col, pg_str(dom_id_val)))
    }
    if (!is.null(vocab_id) && nzchar(vocab_id))
      wheres <- paste0(wheres, sprintf("\n         AND c.%s = %s", cvoc_col, pg_str(vocab_id)))
    if (!is.null(search_text) && nzchar(trimws(search_text)))
      wheres <- paste0(wheres, sprintf("\n         AND lower(c.%s::text) LIKE lower(%s)",
                                       cname_col, pg_str(paste0("%", trimws(search_text), "%"))))

    sql <- sprintf(
      "SELECT c.%s AS concept_id,
              c.%s AS concept_name,
              c.%s AS domain_id,
              c.%s AS vocabulary_id,
              c.%s AS concept_code,
              c.%s AS concept_class_id,
              c.%s AS standard_concept%s
       %s
       WHERE  %s%s
       %s
       LIMIT  %d OFFSET %d",
      cid_col, cname_col, cdom_col, cvoc_col, ccode_col, cclass_col, cstd_col,
      freq_sel, freq_from, wheres, freq_grp, order_by,
      as.integer(limit), as.integer(offset))

    r <- db_query(sql)
    if (is.null(r) || nrow(r) == 0) return(data.frame(
      concept_id=integer(0), concept_name=character(0),
      domain_id=character(0), vocabulary_id=character(0),
      concept_code=character(0), concept_class_id=character(0),
      standard_concept=character(0), n_persons=integer(0), n_records=integer(0),
      stringsAsFactors=FALSE))
    names(r) <- tolower(names(r))
    # Coerce bit64 / integer64 safely
    r$concept_id <- suppressWarnings(as.integer(as.character(r$concept_id)))
    r$n_persons  <- suppressWarnings(as.integer(as.character(r$n_persons %||% NA)))
    r$n_records  <- suppressWarnings(as.integer(as.character(r$n_records %||% NA)))
    r
  }, error = function(e) {
    message("[browse_prevalence] ", conditionMessage(e))
    NULL
  })
}

# schema_short
# Returns a short uppercase code for a schema name, used as the pill label
# in multi-schema browser views (e.g. "eunomia" -> "EUN", "omop" -> "OMO").
schema_short <- function(schema) {
  if (is.null(schema) || !nzchar(schema)) return("?")
  toupper(substr(schema, 1, 3))
}

# browse_concepts_multi_schema
# Calls browse_concepts_by_prevalence once per selected schema (cheap: each
# call is one query against that schema's concept + domain table), then
# merges results on concept_id. Returns a df with the usual concept columns
# plus:
#   per_schema        list-column; each entry is a named integer vector
#                     (names = schema, values = n_persons in that schema)
#   n_schemas_present integer; how many of the selected schemas have data
#                     for this concept
#   n_persons         integer; sum of per-schema person counts (used for sort)
#   n_records         integer; sum of per-schema record counts
# Sort: n_persons DESC NULLS LAST, n_records DESC NULLS LAST.
# Limit applied per-schema then again after merge - so a concept that ranks
# top-200 in one schema but not another is still included.
browse_concepts_multi_schema <- function(schemas, col_maps,
                                         domain_key    = NULL,
                                         vocab_id      = NULL,
                                         standard_only = TRUE,
                                         has_data_only = TRUE,
                                         search_text   = NULL,
                                         limit         = 200L,
                                         order_by      = "persons:desc") {
  if (length(schemas) == 0) return(NULL)
  # Single-schema fast path: keep behaviour identical to the non-multi caller
  # contract but still emit the per_schema column so the renderer can be
  # uniform.
  per_schema_dfs <- list()
  for (sch in schemas) {
    cm <- col_maps[[sch]]
    if (is.null(cm) || length(cm) == 0) {
      message("[browse-multi] skipping schema='", sch, "': no col_map")
      next
    }
    r <- browse_concepts_by_prevalence(
      schema        = sch,
      col_map       = cm,
      domain_key    = domain_key,
      vocab_id      = vocab_id,
      standard_only = standard_only,
      has_data_only = has_data_only,
      search_text   = search_text,
      limit         = limit,
      order_by      = order_by
    )
    if (is.null(r) || nrow(r) == 0) next
    r$schema <- sch
    per_schema_dfs[[sch]] <- r
  }
  if (length(per_schema_dfs) == 0) {
    return(data.frame(
      concept_id=integer(0), concept_name=character(0),
      domain_id=character(0), vocabulary_id=character(0),
      concept_code=character(0), concept_class_id=character(0),
      standard_concept=character(0),
      n_persons=integer(0), n_records=integer(0),
      n_schemas_present=integer(0),
      stringsAsFactors=FALSE))
  }
  all_rows <- do.call(rbind, per_schema_dfs)
  # Aggregate per concept_id. Concept metadata columns should be identical
  # across schemas (same OMOP vocabulary); take the first non-NA.
  ids <- unique(all_rows$concept_id)
  out <- lapply(ids, function(cid) {
    sub <- all_rows[all_rows$concept_id == cid, , drop = FALSE]
    first_non_na <- function(v) {
      vv <- v[!is.na(v) & nzchar(as.character(v))]
      if (length(vv) == 0) NA else vv[1]
    }
    # Per-schema persons as a named integer vector
    np_named <- setNames(
      suppressWarnings(as.integer(sub$n_persons)),
      sub$schema
    )
    nr_named <- setNames(
      suppressWarnings(as.integer(sub$n_records)),
      sub$schema
    )
    # Only count a schema as "present" if it has >0 persons
    present <- !is.na(np_named) & np_named > 0
    data.frame(
      concept_id       = cid,
      concept_name     = first_non_na(sub$concept_name),
      domain_id        = first_non_na(sub$domain_id),
      vocabulary_id    = first_non_na(sub$vocabulary_id),
      concept_code     = first_non_na(sub$concept_code),
      concept_class_id = first_non_na(sub$concept_class_id),
      standard_concept = first_non_na(sub$standard_concept),
      n_persons        = sum(np_named, na.rm = TRUE),
      n_records        = sum(nr_named, na.rm = TRUE),
      n_schemas_present = as.integer(sum(present)),
      stringsAsFactors = FALSE,
      row.names        = NULL
    ) -> base
    # per_schema is attached as an attribute and reattached after rbind below
    attr(base, "per_schema") <- np_named
    base
  })
  # Combine while preserving per_schema. data.frame doesn't carry list-cols
  # natively without I(), so build it after the rbind.
  combined <- do.call(rbind, lapply(out, function(x) { attr(x, "per_schema") <- NULL; x }))
  combined$per_schema <- I(lapply(out, attr, "per_schema"))
  # v10.13: order_by-driven sort across the merged result. Same axes the
  # per-schema query supports, plus n_schemas_present (which only exists
  # post-merge). Always tie-break by concept_name ASC for stable rows.
  {
    parts <- strsplit(order_by, ":", fixed = TRUE)[[1]]
    col_k <- if (length(parts) >= 1) parts[1] else "persons"
    dir_k <- if (length(parts) >= 2) tolower(parts[2]) else "desc"
    is_desc <- !identical(dir_k, "asc")
    key_vec <- switch(col_k,
      persons          = combined$n_persons,
      records          = combined$n_records,
      name             = combined$concept_name,
      vocab            = combined$vocabulary_id,
      code             = combined$concept_code,
      n_schemas_present = combined$n_schemas_present,
      combined$n_persons)
    # Numeric vs character ordering - name/vocab/code are character.
    if (is.numeric(key_vec)) {
      ord <- if (is_desc) order(-key_vec, combined$concept_name)
             else         order(key_vec,  combined$concept_name)
    } else {
      ord <- if (is_desc) order(key_vec, decreasing = TRUE)
             else         order(key_vec)
    }
    combined <- combined[ord, , drop = FALSE]
  }
  if (nrow(combined) > limit) combined <- combined[seq_len(limit), , drop = FALSE]
  rownames(combined) <- NULL
  combined
}

# concept_detail_overview
# Returns a list with concept metadata + aggregate stats for the Overview sub-tab.
concept_detail_overview <- function(schema, domain_key, concept_id, col_map) {
  tryCatch({
    existing_tbls <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
    cid_col   <- ac(col_map, "concept", "concept_id")
    cname_col <- ac(col_map, "concept", "concept_name")
    cdom_col  <- ac(col_map, "concept", "domain_id")
    cvoc_col  <- ac(col_map, "concept", "vocabulary_id")
    ccode_col <- ac(col_map, "concept", "concept_code")
    cclass_col <- ac(col_map, "concept", "concept_class_id")
    cstd_col  <- ac(col_map, "concept", "standard_concept")

    # Concept metadata
    meta_sql <- sprintf(
      "SELECT c.%s AS concept_id, c.%s AS concept_name,
              c.%s AS domain_id, c.%s AS vocabulary_id,
              c.%s AS concept_code, c.%s AS concept_class_id,
              c.%s AS standard_concept
       FROM   %s c WHERE c.%s = %d LIMIT 1",
      cid_col, cname_col, cdom_col, cvoc_col, ccode_col, cclass_col, cstd_col,
      fq(schema, "concept"), cid_col, as.integer(concept_id))
    meta <- tryCatch({
      r <- db_query(meta_sql)
      if (!is.null(r)) names(r) <- tolower(names(r))
      r
    }, error = function(e) NULL)

    # Domain stats (n_persons, n_records, date range)
    stats <- NULL
    if (!is.null(domain_key) && domain_key %in% names(DOMAINS)) {
      dom <- DOMAINS[[domain_key]]
      if (tolower(dom$table) %in% existing_tbls) {
        t_pid  <- ac(col_map, dom$table, dom$person_col)
        t_cid  <- ac(col_map, dom$table, dom$concept_col)
        t_date <- ac(col_map, dom$table, dom$date_col)
        stats_sql <- sprintf(
          "SELECT COUNT(DISTINCT %s)::int AS n_persons,
                  COUNT(*)::int           AS n_records,
                  MIN(%s)::text           AS min_date,
                  MAX(%s)::text           AS max_date
           FROM   %s
           WHERE  %s = %d",
          t_pid, t_date, t_date, fq(schema, dom$table),
          t_cid, as.integer(concept_id))
        stats <- tryCatch({
          r <- db_query(stats_sql)
          if (!is.null(r)) names(r) <- tolower(names(r))
          r
        }, error = function(e) NULL)
      }
    }

    # Age distribution at first event (histogram buckets)
    age_hist_df <- NULL
    if (!is.null(domain_key) && domain_key %in% names(DOMAINS)) {
      dom <- DOMAINS[[domain_key]]
      if (tolower(dom$table) %in% existing_tbls && "person" %in% existing_tbls) {
        t_pid  <- ac(col_map, dom$table, dom$person_col)
        t_cid  <- ac(col_map, dom$table, dom$concept_col)
        t_date <- ac(col_map, dom$table, dom$date_col)
        p_pid  <- ac(col_map, "person", "person_id")
        p_yob  <- ac(col_map, "person", "year_of_birth")
        # Cast date column explicitly: some ETLs (e.g. Synthea) store
        # condition_start_date as text rather than date, which causes
        # EXTRACT to fail with "function pg_catalog.extract(unknown, text)
        # does not exist". The ::date cast handles both cases - date columns
        # are unaffected, text columns are parsed.
        age_sql <- sprintf(
          "WITH person_first AS (
             SELECT t.%s AS person_id,
                    MIN(t.%s::date) AS first_date
             FROM   %s t
             WHERE  t.%s = %d
             GROUP  BY t.%s
           )
           SELECT width_bucket(
                    EXTRACT(YEAR FROM pf.first_date)::int - p.%s,
                    0, 100, 10) AS bucket,
                  COUNT(DISTINCT pf.person_id)::int AS n
           FROM   person_first pf
           JOIN   %s p ON p.%s = pf.person_id
           GROUP  BY bucket ORDER BY bucket",
          t_pid, t_date,
          fq(schema, dom$table),
          t_cid, as.integer(concept_id),
          t_pid,
          p_yob,
          fq(schema, "person"), p_pid)
        age_hist_df <- tryCatch({
          r <- db_query(age_sql)
          if (!is.null(r)) names(r) <- tolower(names(r))
          r
        }, error = function(e) NULL)
      }
    }

    # Gender split
    gender_df <- NULL
    if (!is.null(domain_key) && domain_key %in% names(DOMAINS)) {
      dom <- DOMAINS[[domain_key]]
      if (tolower(dom$table) %in% existing_tbls && "person" %in% existing_tbls) {
        t_pid  <- ac(col_map, dom$table, dom$person_col)
        t_cid  <- ac(col_map, dom$table, dom$concept_col)
        p_pid  <- ac(col_map, "person", "person_id")
        p_gen  <- ac(col_map, "person", "gender_concept_id")
        gen_sql <- sprintf(
          "SELECT p.%s AS gender_concept_id, COUNT(DISTINCT t.%s)::int AS n
           FROM   %s t
           JOIN   %s p ON p.%s = t.%s
           WHERE  t.%s = %d
           GROUP  BY p.%s ORDER BY n DESC",
          p_gen, t_pid,
          fq(schema, dom$table), fq(schema, "person"),
          p_pid, t_pid, t_cid, as.integer(concept_id), p_gen)
        gender_df <- tryCatch({
          r <- db_query(gen_sql)
          if (!is.null(r)) names(r) <- tolower(names(r))
          r
        }, error = function(e) NULL)
      }
    }

    list(concept_meta = meta, stats = stats,
         age_hist_df = age_hist_df, gender_df = gender_df)
  }, error = function(e) {
    message("[concept_detail_overview] ", conditionMessage(e))
    NULL
  })
}

# concept_detail_overview_multi
# Calls concept_detail_overview once per selected schema and aggregates.
# Returns:
#   $concept_meta     concept metadata from the first schema that has it
#   $per_schema       named list of per-schema $stats / $gender_df / $age_hist_df
#   $stats_combined   df with one row: summed n_persons, n_records, min/max dates
#                     across schemas (NULL if no schema has data)
#   $gender_combined  df aggregated across schemas (gender_concept_id, n)
#   $age_hist_combined df aggregated across schemas (bucket, n)
#
# NOTE: combined n_persons is a SUM, not a distinct count. Person IDs are not
# stable across schemas (see browse_concepts_multi_schema design note), so a
# true cross-schema distinct count is not meaningful without an identity map.
concept_detail_overview_multi <- function(schemas, domain_key, concept_id, col_maps) {
  if (length(schemas) == 0) return(NULL)
  per_schema <- list()
  meta_first <- NULL
  for (sch in schemas) {
    cm <- col_maps[[sch]]
    if (is.null(cm) || length(cm) == 0) {
      message("[detail-multi] skipping schema='", sch, "': no col_map")
      next
    }
    ov <- concept_detail_overview(sch, domain_key, concept_id, cm)
    if (is.null(ov)) next
    per_schema[[sch]] <- ov
    if (is.null(meta_first) && !is.null(ov$concept_meta) && nrow(ov$concept_meta) > 0)
      meta_first <- ov$concept_meta
  }

  # Combine stats (sum counts, min/max dates)
  stats_combined <- NULL
  stats_rows <- lapply(per_schema, function(x) x$stats)
  stats_rows <- stats_rows[!sapply(stats_rows, function(x) is.null(x) || nrow(x) == 0)]
  if (length(stats_rows) > 0) {
    all_stats <- do.call(rbind, lapply(stats_rows, function(r) r[1, , drop = FALSE]))
    min_d <- suppressWarnings(min(as.Date(all_stats$min_date), na.rm = TRUE))
    max_d <- suppressWarnings(max(as.Date(all_stats$max_date), na.rm = TRUE))
    stats_combined <- data.frame(
      n_persons = sum(as.integer(all_stats$n_persons), na.rm = TRUE),
      n_records = sum(as.integer(all_stats$n_records), na.rm = TRUE),
      min_date  = if (is.finite(min_d)) as.character(min_d) else NA_character_,
      max_date  = if (is.finite(max_d)) as.character(max_d) else NA_character_,
      stringsAsFactors = FALSE
    )
  }

  # Combine gender (sum n per gender_concept_id)
  gender_combined <- NULL
  gender_rows <- lapply(per_schema, function(x) x$gender_df)
  gender_rows <- gender_rows[!sapply(gender_rows, function(x) is.null(x) || nrow(x) == 0)]
  if (length(gender_rows) > 0) {
    all_g <- do.call(rbind, gender_rows)
    agg <- aggregate(n ~ gender_concept_id, data = all_g, FUN = sum)
    agg <- agg[order(-agg$n), , drop = FALSE]
    rownames(agg) <- NULL
    gender_combined <- agg
  }

  # Combine age histogram (sum n per bucket)
  age_combined <- NULL
  age_rows <- lapply(per_schema, function(x) x$age_hist_df)
  age_rows <- age_rows[!sapply(age_rows, function(x) is.null(x) || nrow(x) == 0)]
  if (length(age_rows) > 0) {
    all_a <- do.call(rbind, age_rows)
    agg <- aggregate(n ~ bucket, data = all_a, FUN = sum)
    agg <- agg[order(agg$bucket), , drop = FALSE]
    rownames(agg) <- NULL
    age_combined <- agg
  }

  list(
    concept_meta       = meta_first,
    per_schema         = per_schema,
    stats_combined     = stats_combined,
    gender_combined    = gender_combined,
    age_hist_combined  = age_combined
  )
}

# concept_sample_records_multi
# Returns a df of sample records for a concept, UNION ALL'd across selected
# schemas with a 'schema' column. Limit is per-schema (so caller sees a fair
# sample from each, not just the first).
concept_sample_records_multi <- function(schemas, domain_key, concept_id, col_maps,
                                         per_schema_limit = 20L) {
  if (length(schemas) == 0 || is.null(domain_key) || !(domain_key %in% names(DOMAINS)))
    return(NULL)
  dom <- DOMAINS[[domain_key]]
  parts <- list()
  for (sch in schemas) {
    cm <- col_maps[[sch]]
    if (is.null(cm) || length(cm) == 0) next
    existing_tbls <- tryCatch(tolower(get_tables(sch)), error = function(e) character(0))
    if (!tolower(dom$table) %in% existing_tbls) next
    t_pid  <- ac(cm, dom$table, dom$person_col)
    t_cid  <- ac(cm, dom$table, dom$concept_col)
    t_date <- ac(cm, dom$table, dom$date_col)
    sql <- sprintf(
      "SELECT %s AS person_id, %s AS event_date, %s AS concept_id, %s AS schema
       FROM   %s
       WHERE  %s = %d
       ORDER  BY %s DESC
       LIMIT  %d",
      t_pid, t_date, t_cid, pg_str(sch),
      fq(sch, dom$table),
      t_cid, as.integer(concept_id),
      t_date, as.integer(per_schema_limit))
    r <- tryCatch(db_query(sql), error = function(e) {
      message("[sample-records] schema=", sch, " err=", conditionMessage(e)); NULL
    })
    if (is.null(r) || nrow(r) == 0) next
    names(r) <- tolower(names(r))
    # Coerce types defensively
    r$person_id <- suppressWarnings(as.character(r$person_id))
    r$concept_id <- suppressWarnings(as.integer(as.character(r$concept_id)))
    r$event_date <- substr(as.character(r$event_date), 1, 10)
    r$schema    <- as.character(r$schema)
    parts[[sch]] <- r
  }
  if (length(parts) == 0)
    return(data.frame(person_id=character(0), event_date=character(0),
                      concept_id=integer(0), schema=character(0),
                      stringsAsFactors=FALSE))
  do.call(rbind, parts)
}

# concept_cooccurring_multi
# Returns concepts that co-occur with the target concept (same person, same
# domain table) ranked by co-occurrence person count. UNION ALL'd across
# schemas with a 'schema' column then aggregated by co-occurring concept_id
# (summing per-schema person counts the same way browse_concepts_multi_schema
# does). Limit is applied AFTER aggregation.
concept_cooccurring_multi <- function(schemas, domain_key, concept_id, col_maps,
                                      limit = 50L) {
  if (length(schemas) == 0 || is.null(domain_key) || !(domain_key %in% names(DOMAINS)))
    return(NULL)
  dom <- DOMAINS[[domain_key]]
  per_schema_parts <- list()
  for (sch in schemas) {
    cm <- col_maps[[sch]]
    if (is.null(cm) || length(cm) == 0) next
    existing_tbls <- tryCatch(tolower(get_tables(sch)), error = function(e) character(0))
    if (!tolower(dom$table) %in% existing_tbls) next
    if (!"concept" %in% existing_tbls) next
    t_pid  <- ac(cm, dom$table, dom$person_col)
    t_cid  <- ac(cm, dom$table, dom$concept_col)
    c_cid  <- ac(cm, "concept", "concept_id")
    c_name <- ac(cm, "concept", "concept_name")
    c_voc  <- ac(cm, "concept", "vocabulary_id")
    c_code <- ac(cm, "concept", "concept_code")
    sql <- sprintf(
      "WITH target_persons AS (
         SELECT DISTINCT %s AS person_id FROM %s WHERE %s = %d
       )
       SELECT t.%s AS concept_id,
              c.%s AS concept_name,
              c.%s AS vocabulary_id,
              c.%s AS concept_code,
              COUNT(DISTINCT t.%s)::int AS n_persons,
              COUNT(*)::int AS n_records,
              %s AS schema
       FROM   %s t
       JOIN   target_persons tp ON tp.person_id = t.%s
       JOIN   %s c ON c.%s = t.%s
       WHERE  t.%s <> %d
       GROUP  BY t.%s, c.%s, c.%s, c.%s
       ORDER  BY n_persons DESC
       LIMIT  %d",
      t_pid, fq(sch, dom$table), t_cid, as.integer(concept_id),
      t_cid, c_name, c_voc, c_code, t_pid, pg_str(sch),
      fq(sch, dom$table), t_pid,
      fq(sch, "concept"), c_cid, t_cid,
      t_cid, as.integer(concept_id),
      t_cid, c_name, c_voc, c_code,
      as.integer(limit) * 2L  # over-fetch per schema before merge
    )
    r <- tryCatch(db_query(sql), error = function(e) {
      message("[cooccur] schema=", sch, " err=", conditionMessage(e)); NULL
    })
    if (is.null(r) || nrow(r) == 0) next
    names(r) <- tolower(names(r))
    r$concept_id <- suppressWarnings(as.integer(as.character(r$concept_id)))
    r$n_persons  <- suppressWarnings(as.integer(as.character(r$n_persons)))
    r$n_records  <- suppressWarnings(as.integer(as.character(r$n_records)))
    r$schema     <- as.character(r$schema)
    per_schema_parts[[sch]] <- r
  }
  if (length(per_schema_parts) == 0)
    return(data.frame(concept_id=integer(0), concept_name=character(0),
                      vocabulary_id=character(0), concept_code=character(0),
                      n_persons=integer(0), n_records=integer(0),
                      n_schemas_present=integer(0),
                      stringsAsFactors=FALSE))
  all_rows <- do.call(rbind, per_schema_parts)
  # Aggregate across schemas
  ids <- unique(all_rows$concept_id)
  out <- lapply(ids, function(cid) {
    sub <- all_rows[all_rows$concept_id == cid, , drop = FALSE]
    first_non_na <- function(v) {
      vv <- v[!is.na(v) & nzchar(as.character(v))]
      if (length(vv) == 0) NA else vv[1]
    }
    np_named <- setNames(as.integer(sub$n_persons), sub$schema)
    present <- !is.na(np_named) & np_named > 0
    base <- data.frame(
      concept_id    = cid,
      concept_name  = first_non_na(sub$concept_name),
      vocabulary_id = first_non_na(sub$vocabulary_id),
      concept_code  = first_non_na(sub$concept_code),
      n_persons     = sum(np_named, na.rm = TRUE),
      n_records     = sum(as.integer(sub$n_records), na.rm = TRUE),
      n_schemas_present = as.integer(sum(present)),
      stringsAsFactors = FALSE, row.names = NULL
    )
    attr(base, "per_schema") <- np_named
    base
  })
  combined <- do.call(rbind, lapply(out, function(x) { attr(x, "per_schema") <- NULL; x }))
  combined$per_schema <- I(lapply(out, attr, "per_schema"))
  combined <- combined[order(-combined$n_persons, -combined$n_records), , drop = FALSE]
  if (nrow(combined) > limit) combined <- combined[seq_len(limit), , drop = FALSE]
  rownames(combined) <- NULL
  combined
}

# ── 5b1. HIERARCHY + VOCABULARY HELPERS (v10.13) ────────────────────────────

# .hierarchy_aggregate_across_schemas
# Shared post-processing for the hierarchy helpers below. Takes a list of
# per-schema dfs each with columns concept_id, concept_name, vocabulary_id,
# concept_code, concept_class_id, standard_concept, n_persons, n_records,
# n_children, schema. Aggregates by concept_id (sum prev counts, max
# n_children), attaches per_schema list-column, sorts by n_persons DESC.
.hierarchy_aggregate_across_schemas <- function(per_schema_parts, limit) {
  if (length(per_schema_parts) == 0)
    return(data.frame(concept_id=integer(0), concept_name=character(0),
                      vocabulary_id=character(0), concept_code=character(0),
                      concept_class_id=character(0), standard_concept=character(0),
                      n_persons=integer(0), n_records=integer(0),
                      n_children=integer(0), n_schemas_present=integer(0),
                      stringsAsFactors=FALSE))
  all_rows <- do.call(rbind, per_schema_parts)
  ids <- unique(all_rows$concept_id)
  out <- lapply(ids, function(cid) {
    sub <- all_rows[all_rows$concept_id == cid, , drop = FALSE]
    first_non_na <- function(v) {
      vv <- v[!is.na(v) & nzchar(as.character(v))]
      if (length(vv) == 0) NA else vv[1]
    }
    np_named <- setNames(as.integer(sub$n_persons), sub$schema)
    present <- !is.na(np_named) & np_named > 0
    base <- data.frame(
      concept_id       = cid,
      concept_name     = first_non_na(sub$concept_name),
      vocabulary_id    = first_non_na(sub$vocabulary_id),
      concept_code     = first_non_na(sub$concept_code),
      concept_class_id = first_non_na(sub$concept_class_id),
      standard_concept = first_non_na(sub$standard_concept),
      n_persons        = sum(np_named, na.rm = TRUE),
      n_records        = sum(as.integer(sub$n_records), na.rm = TRUE),
      n_children       = max(as.integer(sub$n_children), na.rm = TRUE),
      n_schemas_present = as.integer(sum(present)),
      stringsAsFactors = FALSE, row.names = NULL
    )
    if (!is.finite(base$n_children)) base$n_children <- 0L
    attr(base, "per_schema") <- np_named
    base
  })
  combined <- do.call(rbind, lapply(out, function(x) { attr(x, "per_schema") <- NULL; x }))
  combined$per_schema <- I(lapply(out, attr, "per_schema"))
  combined <- combined[order(-combined$n_persons, -combined$n_records,
                             combined$concept_name), , drop = FALSE]
  if (nrow(combined) > limit) combined <- combined[seq_len(limit), , drop = FALSE]
  rownames(combined) <- NULL
  combined
}

# browse_hierarchy_roots_multi
# Returns a list of "root-like" concepts for the chosen domain: standard
# concepts in the domain with no parent in the same domain (or, pragmatically,
# the concepts with the most descendants in this domain - which surface the
# broadest entry points without an expensive root-detection query).
#
# Strategy: rank standard concepts in the domain by descendant count
# (via concept_ancestor) DESC, where the concept itself appears in the
# domain table at least once. Top N. Limit per-schema then aggregate.
browse_hierarchy_roots_multi <- function(schemas, col_maps, domain_key,
                                         limit = 50L) {
  if (length(schemas) == 0 || is.null(domain_key) || !(domain_key %in% names(DOMAINS)))
    return(NULL)
  dom <- DOMAINS[[domain_key]]
  parts <- list()
  for (sch in schemas) {
    cm <- col_maps[[sch]]
    if (is.null(cm) || length(cm) == 0) next
    existing_tbls <- tryCatch(tolower(get_tables(sch)), error = function(e) character(0))
    if (!"concept" %in% existing_tbls) next
    if (!"concept_ancestor" %in% existing_tbls) next
    if (!tolower(dom$table) %in% existing_tbls) next

    cid_col   <- ac(cm, "concept", "concept_id")
    cname_col <- ac(cm, "concept", "concept_name")
    cdom_col  <- ac(cm, "concept", "domain_id")
    cvoc_col  <- ac(cm, "concept", "vocabulary_id")
    ccode_col <- ac(cm, "concept", "concept_code")
    cclass_col<- ac(cm, "concept", "concept_class_id")
    cstd_col  <- ac(cm, "concept", "standard_concept")
    cinv_col  <- ac(cm, "concept", "invalid_reason")
    anc_col   <- ac(cm, "concept_ancestor", "ancestor_concept_id")
    desc_col  <- ac(cm, "concept_ancestor", "descendant_concept_id")
    mls_col   <- ac(cm, "concept_ancestor", "min_levels_of_separation")
    t_pid     <- ac(cm, dom$table, dom$person_col)
    t_cid     <- ac(cm, dom$table, dom$concept_col)

    dom_id_val <- switch(domain_key,
      condition = "Condition", drug = "Drug", procedure = "Procedure",
      measurement = "Measurement", observation = "Observation",
      visit = "Visit", death = "Death", NULL)
    if (is.null(dom_id_val)) next

    # Roots = standard concepts in this domain with no same-domain standard
    # ancestor. The query uses a `desc_counts` CTE that pre-aggregates
    # n_persons / n_records across the full descendant subtree (via
    # concept_ancestor) for every concept_id in this domain. The pill the
    # user sees is the descendant rollup, not the direct count - this is
    # what lets abstract nodes (e.g. ingredients) show meaningful counts.
    #
    # Note on rollup semantics: COUNT(DISTINCT t.PERSON_ID) within one
    # ancestor row gives the true distinct person count for that node's
    # subtree. Summing pills across sibling rows would double-count people
    # who have records under multiple ancestors - that's a user
    # responsibility, not a query bug.
    sql <- sprintf(
      "WITH desc_counts AS (
         SELECT ca.%s AS concept_id,
                COUNT(DISTINCT t.%s)::int AS n_persons,
                COUNT(t.%s)::int           AS n_records
         FROM   %s ca
         JOIN   %s t ON t.%s = ca.%s
         GROUP  BY ca.%s
       ),
       roots AS (
         SELECT c.%s AS concept_id, c.%s AS concept_name,
                c.%s AS vocabulary_id, c.%s AS concept_code,
                c.%s AS concept_class_id, c.%s AS standard_concept
         FROM   %s c
         WHERE  c.%s IS NULL
           AND  c.%s = 'S'
           AND  c.%s = %s
           AND  NOT EXISTS (
             SELECT 1 FROM %s ca
             JOIN   %s p ON p.%s = ca.%s
             WHERE  ca.%s = c.%s
               AND  ca.%s > 0
               AND  p.%s = 'S'
               AND  p.%s = %s
           )
       ),
       root_child_min_lvls AS (
         -- For each root, smallest MIN_LEVELS_OF_SEPARATION > 0 with any
         -- standard same-domain descendant + count at that level. Used to
         -- drive the n_children indicator on each root row (replaces the
         -- old level-1-only count, which is wrong for vocabularies where
         -- the level-1 layer is empty - e.g. RxNorm ingredients).
         SELECT ml.concept_id, ml.min_lvl,
                (SELECT COUNT(*)::int
                 FROM   %s ca3
                 JOIN   %s d3 ON d3.%s = ca3.%s
                 WHERE  ca3.%s = ml.concept_id
                   AND  ca3.%s = ml.min_lvl
                   AND  d3.%s IS NULL
                   AND  d3.%s = 'S'
                   AND  d3.%s = %s) AS n_at_min_lvl
         FROM (
           SELECT ca.%s AS concept_id,
                  MIN(ca.%s) AS min_lvl
           FROM   %s ca
           JOIN   %s d ON d.%s = ca.%s
           WHERE  ca.%s > 0
             AND  d.%s IS NULL
             AND  d.%s = 'S'
             AND  d.%s = %s
             AND  ca.%s IN (SELECT concept_id FROM roots)
           GROUP  BY ca.%s
         ) ml
       )
       SELECT r.concept_id, r.concept_name, r.vocabulary_id, r.concept_code,
              r.concept_class_id, r.standard_concept,
              COALESCE(dc.n_persons, 0)::int       AS n_persons,
              COALESCE(dc.n_records, 0)::int       AS n_records,
              COALESCE(rcml.n_at_min_lvl, 0)::int  AS n_children,
              %s AS schema
       FROM   roots r
       LEFT JOIN desc_counts         dc   ON dc.concept_id   = r.concept_id
       LEFT JOIN root_child_min_lvls rcml ON rcml.concept_id = r.concept_id
       ORDER  BY n_persons DESC NULLS LAST, r.concept_name
       LIMIT  %d",
      # desc_counts CTE
      anc_col, t_pid, t_pid,
      fq(sch, "concept_ancestor"),
      fq(sch, dom$table), t_cid, desc_col,
      anc_col,
      # roots CTE
      cid_col, cname_col, cvoc_col, ccode_col, cclass_col, cstd_col,
      fq(sch, "concept"),
      cinv_col, cstd_col, cdom_col, pg_str(dom_id_val),
      fq(sch, "concept_ancestor"),
      fq(sch, "concept"), cid_col, anc_col,
      desc_col, cid_col, mls_col, cstd_col, cdom_col, pg_str(dom_id_val),
      # root_child_min_lvls - n_at_min_lvl correlated subquery
      fq(sch, "concept_ancestor"),
      fq(sch, "concept"), cid_col, desc_col,
      anc_col,
      mls_col,
      cinv_col, cstd_col, cdom_col, pg_str(dom_id_val),
      # root_child_min_lvls - inner ml subquery
      anc_col, mls_col,
      fq(sch, "concept_ancestor"),
      fq(sch, "concept"), cid_col, desc_col,
      mls_col,
      cinv_col, cstd_col, cdom_col, pg_str(dom_id_val),
      anc_col,
      anc_col,
      # main SELECT
      pg_str(sch),
      as.integer(limit) * 2L
    )
    r <- tryCatch(db_query(sql), error = function(e) {
      message("[hier-roots] schema=", sch, " err=", conditionMessage(e)); NULL
    })
    if (is.null(r) || nrow(r) == 0) next
    names(r) <- tolower(names(r))
    r$concept_id <- suppressWarnings(as.integer(as.character(r$concept_id)))
    r$n_persons  <- suppressWarnings(as.integer(as.character(r$n_persons)))
    r$n_records  <- suppressWarnings(as.integer(as.character(r$n_records)))
    r$n_children <- suppressWarnings(as.integer(as.character(r$n_children)))
    r$schema     <- as.character(r$schema)
    parts[[sch]] <- r
  }
  .hierarchy_aggregate_across_schemas(parts, limit)
}

# browse_hierarchy_children_multi
# Direct children (min_levels_of_separation = 1) of a given concept,
# filtered to the chosen domain, standard concepts only, with prevalence
# counts in the domain table and child-count for ▸ markers.
browse_hierarchy_children_multi <- function(schemas, col_maps, domain_key,
                                            parent_concept_id, limit = 200L) {
  if (length(schemas) == 0 || is.null(domain_key) || !(domain_key %in% names(DOMAINS)))
    return(NULL)
  if (is.null(parent_concept_id) || is.na(parent_concept_id)) return(NULL)
  dom <- DOMAINS[[domain_key]]
  parts <- list()
  for (sch in schemas) {
    cm <- col_maps[[sch]]
    if (is.null(cm) || length(cm) == 0) next
    existing_tbls <- tryCatch(tolower(get_tables(sch)), error = function(e) character(0))
    if (!"concept" %in% existing_tbls) next
    if (!"concept_ancestor" %in% existing_tbls) next
    if (!tolower(dom$table) %in% existing_tbls) next

    cid_col   <- ac(cm, "concept", "concept_id")
    cname_col <- ac(cm, "concept", "concept_name")
    cdom_col  <- ac(cm, "concept", "domain_id")
    cvoc_col  <- ac(cm, "concept", "vocabulary_id")
    ccode_col <- ac(cm, "concept", "concept_code")
    cclass_col<- ac(cm, "concept", "concept_class_id")
    cstd_col  <- ac(cm, "concept", "standard_concept")
    cinv_col  <- ac(cm, "concept", "invalid_reason")
    anc_col   <- ac(cm, "concept_ancestor", "ancestor_concept_id")
    desc_col  <- ac(cm, "concept_ancestor", "descendant_concept_id")
    mls_col   <- ac(cm, "concept_ancestor", "min_levels_of_separation")
    t_pid     <- ac(cm, dom$table, dom$person_col)
    t_cid     <- ac(cm, dom$table, dom$concept_col)

    dom_id_val <- switch(domain_key,
      condition = "Condition", drug = "Drug", procedure = "Procedure",
      measurement = "Measurement", observation = "Observation",
      visit = "Visit", death = "Death", NULL)
    if (is.null(dom_id_val)) next

    # Children query: smallest non-empty level of descendants (Athena-style
    # behaviour - RxNorm ingredients typically have no level-1 descendants
    # because the path skips through an empty intermediate level).
    #
    # - parent_min_lvl: scalar subquery, smallest MIN_LEVELS_OF_SEPARATION > 0
    #   for which the parent has any standard same-domain descendant.
    # - child_min_lvls CTE: per-child smallest non-empty level + how many
    #   descendants live at that level (used for n_children on each row so
    #   the drill marker reflects reality even when level-1 is empty).
    # - desc_counts: descendant rollup (n_persons / n_records) as before.
    sql <- sprintf(
      "WITH desc_counts AS (
         SELECT ca.%s AS concept_id,
                COUNT(DISTINCT t.%s)::int AS n_persons,
                COUNT(t.%s)::int           AS n_records
         FROM   %s ca
         JOIN   %s t ON t.%s = ca.%s
         GROUP  BY ca.%s
       ),
       parent_min_lvl AS (
         SELECT MIN(ca.%s) AS min_lvl
         FROM   %s ca
         JOIN   %s d ON d.%s = ca.%s
         WHERE  ca.%s = %d
           AND  ca.%s > 0
           AND  d.%s IS NULL
           AND  d.%s = 'S'
           AND  d.%s = %s
       ),
       child_min_lvls AS (
         SELECT ml.concept_id, ml.min_lvl,
                (SELECT COUNT(*)::int
                 FROM   %s ca3
                 JOIN   %s d3 ON d3.%s = ca3.%s
                 WHERE  ca3.%s = ml.concept_id
                   AND  ca3.%s = ml.min_lvl
                   AND  d3.%s IS NULL
                   AND  d3.%s = 'S'
                   AND  d3.%s = %s) AS n_at_min_lvl
         FROM (
           SELECT ca.%s AS concept_id,
                  MIN(ca.%s) AS min_lvl
           FROM   %s ca
           JOIN   %s d ON d.%s = ca.%s
           WHERE  ca.%s > 0
             AND  d.%s IS NULL
             AND  d.%s = 'S'
             AND  d.%s = %s
             AND  ca.%s IN (
               -- restrict to concept_ids that will appear as rows in this
               -- query: descendants of the requested parent at its min_lvl.
               SELECT inner_ca.%s
               FROM   %s inner_ca
               WHERE  inner_ca.%s = %d
                 AND  inner_ca.%s = (SELECT min_lvl FROM parent_min_lvl)
             )
           GROUP  BY ca.%s
         ) ml
       )
       SELECT c.%s AS concept_id, c.%s AS concept_name,
              c.%s AS vocabulary_id, c.%s AS concept_code,
              c.%s AS concept_class_id, c.%s AS standard_concept,
              COALESCE(dc.n_persons, 0)::int   AS n_persons,
              COALESCE(dc.n_records, 0)::int   AS n_records,
              COALESCE(cml.n_at_min_lvl, 0)::int AS n_children,
              %s AS schema
       FROM   %s c
       JOIN   %s ca ON ca.%s = c.%s
       LEFT JOIN desc_counts    dc  ON dc.concept_id = c.%s
       LEFT JOIN child_min_lvls cml ON cml.concept_id = c.%s
       WHERE  ca.%s = %d
         AND  ca.%s = (SELECT min_lvl FROM parent_min_lvl)
         AND  c.%s IS NULL
         AND  c.%s = 'S'
         AND  c.%s = %s
       ORDER  BY n_persons DESC NULLS LAST, c.%s
       LIMIT  %d",
      # desc_counts CTE
      anc_col, t_pid, t_pid,
      fq(sch, "concept_ancestor"),
      fq(sch, dom$table), t_cid, desc_col,
      anc_col,
      # parent_min_lvl CTE
      mls_col,
      fq(sch, "concept_ancestor"),
      fq(sch, "concept"), cid_col, desc_col,
      anc_col, as.integer(parent_concept_id),
      mls_col,
      cinv_col, cstd_col, cdom_col, pg_str(dom_id_val),
      # child_min_lvls.n_at_min_lvl correlated subquery
      fq(sch, "concept_ancestor"),
      fq(sch, "concept"), cid_col, desc_col,
      anc_col,
      mls_col,
      cinv_col, cstd_col, cdom_col, pg_str(dom_id_val),
      # child_min_lvls inner ml subquery (with restriction to parent's level descendants)
      anc_col, mls_col,
      fq(sch, "concept_ancestor"),
      fq(sch, "concept"), cid_col, desc_col,
      mls_col,
      cinv_col, cstd_col, cdom_col, pg_str(dom_id_val),
      anc_col,
      # Restriction subquery (selects descendant_concept_id from concept_ancestor:
      # these are the actual row concept_ids the outer query will return)
      desc_col,
      fq(sch, "concept_ancestor"),
      anc_col, as.integer(parent_concept_id),
      mls_col,
      anc_col,
      # main SELECT
      cid_col, cname_col, cvoc_col, ccode_col, cclass_col, cstd_col,
      pg_str(sch),
      # FROM + JOINs
      fq(sch, "concept"),
      fq(sch, "concept_ancestor"), desc_col, cid_col,
      cid_col, cid_col,
      # WHERE + ORDER + LIMIT
      anc_col, as.integer(parent_concept_id),
      mls_col,
      cinv_col, cstd_col,
      cdom_col, pg_str(dom_id_val),
      cname_col,
      as.integer(limit) * 2L
    )
    r <- tryCatch(db_query(sql), error = function(e) {
      message("[hier-children] schema=", sch, " err=", conditionMessage(e)); NULL
    })
    if (is.null(r) || nrow(r) == 0) next
    names(r) <- tolower(names(r))
    r$concept_id <- suppressWarnings(as.integer(as.character(r$concept_id)))
    r$n_persons  <- suppressWarnings(as.integer(as.character(r$n_persons)))
    r$n_records  <- suppressWarnings(as.integer(as.character(r$n_records)))
    r$n_children <- suppressWarnings(as.integer(as.character(r$n_children)))
    r$schema     <- as.character(r$schema)
    parts[[sch]] <- r
  }
  .hierarchy_aggregate_across_schemas(parts, limit)
}

# list_vocabularies_with_prevalence_multi
# Returns df(vocabulary_id, n_persons, n_concepts, n_schemas_present, per_schema)
# of vocabularies present in the concept table for selected schemas, with
# total persons-in-domain summed across schemas and concepts in vocab.
# Used as the entry view for "By vocabulary" mode.
list_vocabularies_with_prevalence_multi <- function(schemas, col_maps,
                                                    domain_key = NULL) {
  if (length(schemas) == 0) return(NULL)
  parts <- list()
  for (sch in schemas) {
    cm <- col_maps[[sch]]
    if (is.null(cm) || length(cm) == 0) next
    existing_tbls <- tryCatch(tolower(get_tables(sch)), error = function(e) character(0))
    if (!"concept" %in% existing_tbls) next

    cid_col   <- ac(cm, "concept", "concept_id")
    cvoc_col  <- ac(cm, "concept", "vocabulary_id")
    cdom_col  <- ac(cm, "concept", "domain_id")
    cstd_col  <- ac(cm, "concept", "standard_concept")
    cinv_col  <- ac(cm, "concept", "invalid_reason")

    # Determine domain table for prevalence
    has_dom_table <- FALSE
    dom_table_fq <- NULL; t_cid <- NULL; t_pid <- NULL; dom_id_val <- NULL
    if (!is.null(domain_key) && domain_key %in% names(DOMAINS)) {
      dom <- DOMAINS[[domain_key]]
      if (tolower(dom$table) %in% existing_tbls) {
        has_dom_table <- TRUE
        dom_table_fq <- fq(sch, dom$table)
        t_cid <- ac(cm, dom$table, dom$concept_col)
        t_pid <- ac(cm, dom$table, dom$person_col)
        dom_id_val <- switch(domain_key,
          condition = "Condition", drug = "Drug", procedure = "Procedure",
          measurement = "Measurement", observation = "Observation",
          visit = "Visit", death = "Death", NULL)
      }
    }

    if (has_dom_table && !is.null(dom_id_val)) {
      sql <- sprintf(
        "SELECT c.%s AS vocabulary_id,
                COUNT(DISTINCT c.%s)::int AS n_concepts,
                COUNT(DISTINCT t.%s)::int AS n_persons,
                %s AS schema
         FROM   %s c
         LEFT JOIN %s t ON t.%s = c.%s
         WHERE  c.%s IS NULL
           AND  c.%s = 'S'
           AND  c.%s = %s
         GROUP  BY c.%s
         ORDER  BY n_persons DESC NULLS LAST",
        cvoc_col, cid_col, t_pid, pg_str(sch),
        fq(sch, "concept"),
        dom_table_fq, t_cid, cid_col,
        cinv_col, cstd_col, cdom_col, pg_str(dom_id_val),
        cvoc_col)
    } else {
      # No domain filter: just list vocabs by concept count (no person counts)
      sql <- sprintf(
        "SELECT c.%s AS vocabulary_id,
                COUNT(DISTINCT c.%s)::int AS n_concepts,
                0::int AS n_persons,
                %s AS schema
         FROM   %s c
         WHERE  c.%s IS NULL
           AND  c.%s = 'S'
         GROUP  BY c.%s
         ORDER  BY n_concepts DESC",
        cvoc_col, cid_col, pg_str(sch),
        fq(sch, "concept"), cinv_col, cstd_col, cvoc_col)
    }
    r <- tryCatch(db_query(sql), error = function(e) {
      message("[vocab-list] schema=", sch, " err=", conditionMessage(e)); NULL
    })
    if (is.null(r) || nrow(r) == 0) next
    names(r) <- tolower(names(r))
    r$n_concepts <- suppressWarnings(as.integer(as.character(r$n_concepts)))
    r$n_persons  <- suppressWarnings(as.integer(as.character(r$n_persons)))
    r$schema     <- as.character(r$schema)
    parts[[sch]] <- r
  }
  if (length(parts) == 0)
    return(data.frame(vocabulary_id=character(0), n_concepts=integer(0),
                      n_persons=integer(0), n_schemas_present=integer(0),
                      stringsAsFactors=FALSE))
  all_rows <- do.call(rbind, parts)
  vocabs <- unique(all_rows$vocabulary_id)
  out <- lapply(vocabs, function(v) {
    sub <- all_rows[all_rows$vocabulary_id == v, , drop = FALSE]
    np_named <- setNames(as.integer(sub$n_persons), sub$schema)
    present <- !is.na(np_named) & np_named > 0
    base <- data.frame(
      vocabulary_id     = v,
      n_concepts        = sum(as.integer(sub$n_concepts), na.rm = TRUE),
      n_persons         = sum(np_named, na.rm = TRUE),
      n_schemas_present = as.integer(sum(present)),
      stringsAsFactors = FALSE, row.names = NULL
    )
    attr(base, "per_schema") <- np_named
    base
  })
  combined <- do.call(rbind, lapply(out, function(x) { attr(x, "per_schema") <- NULL; x }))
  combined$per_schema <- I(lapply(out, attr, "per_schema"))
  combined <- combined[order(-combined$n_persons, -combined$n_concepts), , drop = FALSE]
  rownames(combined) <- NULL
  combined
}

# concept_ancestors_path_multi
# For a target concept, returns:
#   $ancestors  - df of standard same-domain ancestors with prevalence (per
#                 schema), ordered from root (highest level_of_sep) down to
#                 the direct parent of the target. May be empty.
#   $children   - df of direct children (min_levels_of_separation = 1) with
#                 prevalence (per schema) and n_children. May be empty.
#
# Both dfs use the same shape as the left-panel hierarchy aggregated output
# so the renderer can use .render_concept_row-style helpers.
#
# Strategy:
#   - One query per schema returns ancestor concept_ids with their
#     min_levels_of_separation to the target. The "path" is the chain of
#     ancestors with the smallest level at each step (so we pick the most
#     direct line back to the root rather than every possible branch).
#   - We then JOIN those concept_ids back to concept + the domain table
#     for prevalence counts.
#   - Children query reuses browse_hierarchy_children_multi.
concept_ancestors_path_multi <- function(schemas, col_maps, domain_key,
                                         concept_id) {
  if (length(schemas) == 0 || is.null(domain_key) ||
      !(domain_key %in% names(DOMAINS)) ||
      is.null(concept_id) || is.na(concept_id))
    return(list(ancestors = NULL, children = NULL))

  dom <- DOMAINS[[domain_key]]
  dom_id_val <- switch(domain_key,
    condition = "Condition", drug = "Drug", procedure = "Procedure",
    measurement = "Measurement", observation = "Observation",
    visit = "Visit", death = "Death", NULL)
  if (is.null(dom_id_val)) return(list(ancestors = NULL, children = NULL))

  # Per-schema ancestor queries: returns each ancestor + min_levels_of_sep
  # so we can build a longest-path chain. We also fetch the prevalence
  # counts here so we don't double-roundtrip.
  parts <- list()
  for (sch in schemas) {
    cm <- col_maps[[sch]]
    if (is.null(cm) || length(cm) == 0) next
    existing_tbls <- tryCatch(tolower(get_tables(sch)), error = function(e) character(0))
    if (!"concept" %in% existing_tbls) next
    if (!"concept_ancestor" %in% existing_tbls) next
    if (!tolower(dom$table) %in% existing_tbls) next

    cid_col   <- ac(cm, "concept", "concept_id")
    cname_col <- ac(cm, "concept", "concept_name")
    cdom_col  <- ac(cm, "concept", "domain_id")
    cvoc_col  <- ac(cm, "concept", "vocabulary_id")
    ccode_col <- ac(cm, "concept", "concept_code")
    cclass_col<- ac(cm, "concept", "concept_class_id")
    cstd_col  <- ac(cm, "concept", "standard_concept")
    cinv_col  <- ac(cm, "concept", "invalid_reason")
    anc_col   <- ac(cm, "concept_ancestor", "ancestor_concept_id")
    desc_col  <- ac(cm, "concept_ancestor", "descendant_concept_id")
    mls_col   <- ac(cm, "concept_ancestor", "min_levels_of_separation")
    t_pid     <- ac(cm, dom$table, dom$person_col)
    t_cid     <- ac(cm, dom$table, dom$concept_col)

    sql <- sprintf(
      "SELECT a.%s AS concept_id, a.%s AS concept_name,
              a.%s AS vocabulary_id, a.%s AS concept_code,
              a.%s AS concept_class_id, a.%s AS standard_concept,
              ca.%s AS levels_up,
              COUNT(DISTINCT t.%s)::int AS n_persons,
              COUNT(t.%s)::int AS n_records,
              %s AS schema
       FROM   %s ca
       JOIN   %s a ON a.%s = ca.%s
       LEFT JOIN %s t ON t.%s = a.%s
       WHERE  ca.%s = %d
         AND  ca.%s > 0
         AND  a.%s IS NULL
         AND  a.%s = 'S'
         AND  a.%s = %s
       GROUP  BY a.%s, a.%s, a.%s, a.%s, a.%s, a.%s, ca.%s
       ORDER  BY ca.%s DESC",
      cid_col, cname_col, cvoc_col, ccode_col, cclass_col, cstd_col,
      mls_col, t_pid, t_pid, pg_str(sch),
      fq(sch, "concept_ancestor"),
      fq(sch, "concept"), cid_col, anc_col,
      fq(sch, dom$table), t_cid, cid_col,
      desc_col, as.integer(concept_id),
      mls_col,
      cinv_col, cstd_col, cdom_col, pg_str(dom_id_val),
      cid_col, cname_col, cvoc_col, ccode_col, cclass_col, cstd_col, mls_col,
      mls_col)
    r <- tryCatch(db_query(sql), error = function(e) {
      message("[ancestors] schema=", sch, " err=", conditionMessage(e)); NULL
    })
    if (is.null(r) || nrow(r) == 0) next
    names(r) <- tolower(names(r))
    r$concept_id <- suppressWarnings(as.integer(as.character(r$concept_id)))
    r$levels_up  <- suppressWarnings(as.integer(as.character(r$levels_up)))
    r$n_persons  <- suppressWarnings(as.integer(as.character(r$n_persons)))
    r$n_records  <- suppressWarnings(as.integer(as.character(r$n_records)))
    r$schema     <- as.character(r$schema)
    parts[[sch]] <- r
  }

  ancestors_agg <- if (length(parts) == 0) {
    data.frame(concept_id=integer(0), concept_name=character(0),
               vocabulary_id=character(0), concept_code=character(0),
               concept_class_id=character(0), standard_concept=character(0),
               levels_up=integer(0),
               n_persons=integer(0), n_records=integer(0),
               n_schemas_present=integer(0),
               stringsAsFactors=FALSE)
  } else {
    all_rows <- do.call(rbind, parts)
    # Aggregate per concept_id, preserving levels_up (take min across schemas
    # - same ancestor will have same levels across schemas in well-formed
    # vocabularies, but be defensive).
    ids <- unique(all_rows$concept_id)
    out <- lapply(ids, function(cid) {
      sub <- all_rows[all_rows$concept_id == cid, , drop = FALSE]
      first_non_na <- function(v) {
        vv <- v[!is.na(v) & nzchar(as.character(v))]
        if (length(vv) == 0) NA else vv[1]
      }
      np_named <- setNames(as.integer(sub$n_persons), sub$schema)
      present <- !is.na(np_named) & np_named > 0
      base <- data.frame(
        concept_id        = cid,
        concept_name      = first_non_na(sub$concept_name),
        vocabulary_id     = first_non_na(sub$vocabulary_id),
        concept_code      = first_non_na(sub$concept_code),
        concept_class_id  = first_non_na(sub$concept_class_id),
        standard_concept  = first_non_na(sub$standard_concept),
        levels_up         = min(as.integer(sub$levels_up), na.rm = TRUE),
        n_persons         = sum(np_named, na.rm = TRUE),
        n_records         = sum(as.integer(sub$n_records), na.rm = TRUE),
        n_schemas_present = as.integer(sum(present)),
        stringsAsFactors  = FALSE, row.names = NULL
      )
      attr(base, "per_schema") <- np_named
      base
    })
    combined <- do.call(rbind, lapply(out, function(x) {
      attr(x, "per_schema") <- NULL; x
    }))
    combined$per_schema <- I(lapply(out, attr, "per_schema"))
    combined
  }

  # Build a single root-to-parent chain by picking, for each level, one
  # representative ancestor. We pick the one with the highest n_persons
  # (or alphabetical fall-back). This gives a clean linear path rather
  # than a full ancestor graph - appropriate for a "breadcrumb up" view.
  ancestors_path <- if (nrow(ancestors_agg) == 0) {
    ancestors_agg
  } else {
    levels_desc <- sort(unique(ancestors_agg$levels_up), decreasing = TRUE)
    picked <- do.call(rbind, lapply(levels_desc, function(lv) {
      lv_rows <- ancestors_agg[ancestors_agg$levels_up == lv, , drop = FALSE]
      lv_rows <- lv_rows[order(-lv_rows$n_persons, lv_rows$concept_name), , drop = FALSE]
      lv_rows[1, , drop = FALSE]
    }))
    rownames(picked) <- NULL
    picked
  }

  # Direct children: reuse the cached children query helper.
  children <- browse_hierarchy_children_multi(schemas, col_maps, domain_key,
                                              concept_id, limit = 100L)

  list(ancestors = ancestors_path, children = children)
}

# compute_schema_overlap_multi
# Returns the schema-overlap structure used to build the proportional Venn
# above the concept list. For each selected schema, fetches the distinct
# set of concept_ids that have at least one record in the schema's domain
# table (using standard, valid, in-domain concepts only). Then computes
# the 2^N - 1 region partitions in R and returns:
#   $schemas        character vector of schemas, in display order
#   $region_counts  named integer vector; names are bitmask strings like
#                   "100", "110", "111" (length = n_schemas, '1' = schema
#                   present in this region). Values are |distinct concept_ids|.
#   $region_ids     named list mirroring region_counts; each entry is the
#                   integer vector of concept_ids in that region (used by
#                   the region-click filter without re-querying).
#   $total          integer; total distinct concept_ids in the union.
#
# Edge cases:
#   - 0 schemas: returns NULL
#   - 1 schema: region_counts has one entry "1" = total count
#   - 2 or 3 schemas: full Venn partition
#   - >3 schemas: caller is expected to enforce the 3-schema cap; if not,
#     this function still works but downstream renderers will fail.
#
# This function is CHEAP relative to browse_concepts_multi_schema - one
# small query per schema returning a flat concept_id list, no joins to
# concept beyond domain filtering. Suitable for session-cached recompute
# on schema/domain change.
compute_schema_overlap_multi <- function(schemas, col_maps, domain_key) {
  if (length(schemas) == 0) return(NULL)
  if (is.null(domain_key) || !(domain_key %in% names(DOMAINS))) return(NULL)
  dom <- DOMAINS[[domain_key]]
  dom_id_val <- switch(domain_key,
    condition = "Condition", drug = "Drug", procedure = "Procedure",
    measurement = "Measurement", observation = "Observation",
    visit = "Visit", death = "Death", NULL)
  if (is.null(dom_id_val)) return(NULL)

  per_schema_sets <- list()
  for (sch in schemas) {
    cm <- col_maps[[sch]]
    if (is.null(cm) || length(cm) == 0) {
      per_schema_sets[[sch]] <- integer(0)
      next
    }
    existing_tbls <- tryCatch(tolower(get_tables(sch)),
                              error = function(e) character(0))
    if (!"concept" %in% existing_tbls || !tolower(dom$table) %in% existing_tbls) {
      per_schema_sets[[sch]] <- integer(0)
      next
    }
    cid_col  <- ac(cm, "concept", "concept_id")
    cdom_col <- ac(cm, "concept", "domain_id")
    cstd_col <- ac(cm, "concept", "standard_concept")
    cinv_col <- ac(cm, "concept", "invalid_reason")
    t_cid    <- ac(cm, dom$table, dom$concept_col)
    sql <- sprintf(
      "SELECT DISTINCT t.%s AS concept_id
       FROM   %s t
       JOIN   %s c ON c.%s = t.%s
       WHERE  c.%s IS NULL
         AND  c.%s = 'S'
         AND  c.%s = %s",
      t_cid,
      fq(sch, dom$table),
      fq(sch, "concept"), cid_col, t_cid,
      cinv_col, cstd_col, cdom_col, pg_str(dom_id_val))
    r <- tryCatch(db_query(sql), error = function(e) {
      message("[overlap] schema=", sch, " err=", conditionMessage(e)); NULL
    })
    if (is.null(r) || nrow(r) == 0) {
      per_schema_sets[[sch]] <- integer(0)
    } else {
      names(r) <- tolower(names(r))
      ids <- suppressWarnings(as.integer(as.character(r$concept_id)))
      per_schema_sets[[sch]] <- ids[!is.na(ids)]
    }
  }

  n <- length(schemas)
  # Compute every non-empty bitmask region. Each region is identified by an
  # n-character string of '1'/'0' indicating which schemas the concept lives
  # in. For 3 schemas this gives 7 regions: 100, 010, 001, 110, 101, 011, 111.
  all_ids <- unique(unlist(per_schema_sets))
  if (length(all_ids) == 0) {
    return(list(schemas = schemas,
                region_counts = integer(0),
                region_ids = list(),
                total = 0L))
  }
  # Build a membership matrix: rows=concept_ids, cols=schemas
  mem <- vapply(per_schema_sets, function(s) all_ids %in% s, logical(length(all_ids)))
  if (length(all_ids) == 1) mem <- matrix(mem, nrow = 1)
  # Bitmask string per concept_id
  bitmask <- apply(mem, 1, function(row) paste(as.integer(row), collapse = ""))
  # Drop the all-zero bitmask (shouldn't exist since all_ids is the union, but
  # be defensive)
  keep <- bitmask != strrep("0", n)
  bitmask <- bitmask[keep]
  ids_kept <- all_ids[keep]
  # Aggregate
  region_ids <- split(ids_kept, bitmask)
  region_counts <- vapply(region_ids, length, integer(1))
  # Sort regions: by population count ASC (single-schema first), then by
  # bitmask ASC for stable ordering of equal-population regions.
  pop <- vapply(names(region_counts), function(b) sum(strsplit(b, "")[[1]] == "1"), integer(1))
  ord <- order(pop, names(region_counts))
  region_counts <- region_counts[ord]
  region_ids    <- region_ids[ord]

  list(
    schemas       = schemas,
    region_counts = region_counts,
    region_ids    = region_ids,
    total         = length(all_ids)
  )
}

# ── 5b2. TEMPLATE SCORING ──────────────────────────────────────────────────────
# Queries top N concept IDs per domain to check which templates have data.
# Returns TEMPLATES list with extra fields:
#   $match_count   - how many concept_ids found in the data
#   $total_ids     - total concept_ids in the template (0 = domain-only match)
#   $match_pct     - match_count / max(1, total_ids)
#   $domain_hits   - named logical: which domains have any records
#   $evidence      - character vector of matched concept names / counts
#   $score         - overall relevance score (0-100)
score_templates <- function(schema, col_map, templates, top_n = 2000L) {
  tryCatch({
    existing_tbls <- tolower(get_tables(schema))

    # --- Step 1: For each domain with records, pull top concept_id frequencies ---
    domain_freq <- list()   # domain_key -> data.frame(concept_id, n)
    for (key in names(DOMAINS)) {
      dom <- DOMAINS[[key]]
      if (!tolower(dom$table) %in% existing_tbls) next
      cid_col <- ac(col_map, dom$table, dom$concept_col)
      if (is.null(cid_col) || nchar(cid_col) == 0) next
      r <- tryCatch(db_query(sprintf(
        "SELECT %s AS concept_id, COUNT(*)::int AS n
         FROM   %s
         WHERE  %s > 0
         GROUP  BY 1
         ORDER  BY 2 DESC
         LIMIT  %d",
        cid_col, fq(schema, dom$table), cid_col, top_n)),
        error = function(e) NULL)
      if (!is.null(r) && nrow(r) > 0)
        domain_freq[[key]] <- r
    }

    # --- Step 2: Look up concept names for matched IDs (single query) ----------
    all_template_ids <- unique(unlist(lapply(templates, function(t)
      unlist(lapply(t$criteria, function(c) as.integer(c$concept_ids %||% integer(0)))))))
    all_template_ids <- all_template_ids[!is.na(all_template_ids) & all_template_ids > 0L]

    concept_name_map <- list()
    if (length(all_template_ids) > 0 && "concept" %in% existing_tbls) {
      cid_col_c   <- ac(col_map, "concept", "concept_id")
      cname_col_c <- ac(col_map, "concept", "concept_name")
      if (!is.null(cid_col_c) && !is.null(cname_col_c)) {
        ids_sql <- paste(sprintf("%.0f", as.numeric(all_template_ids)), collapse = ",")
        nm_r <- tryCatch(db_query(sprintf(
          "SELECT %s AS concept_id, %s AS concept_name
           FROM   %s
           WHERE  %s IN (%s)",
          cid_col_c, cname_col_c, fq(schema, "concept"), cid_col_c, ids_sql)),
          error = function(e) NULL)
        if (!is.null(nm_r)) names(nm_r) <- tolower(names(nm_r))
        if (!is.null(nm_r) && nrow(nm_r) > 0)
          concept_name_map <- setNames(
            as.list(as.character(nm_r$concept_name)),
            sprintf("%.0f", as.numeric(nm_r$concept_id)))
      }
    }

    # --- Step 3: Score each template -----------------------------------------
    lapply(seq_along(templates), function(i) {
      tmpl <- templates[[i]]
      all_ids    <- unlist(lapply(tmpl$criteria, function(c) as.integer(c$concept_ids %||% integer(0))))
      all_ids    <- all_ids[!is.na(all_ids) & all_ids > 0L]
      all_domains <- unique(sapply(tmpl$criteria, function(c) c$domain))
      total_ids  <- length(all_ids)

      # Which domains in this template have data at all?
      domain_hits <- setNames(
        sapply(all_domains, function(dk) !is.null(domain_freq[[dk]])),
        all_domains)

      # Which specific concept_ids are in the data, and how common?
      matched_ids  <- integer(0)
      matched_n    <- integer(0)
      for (dk in all_domains) {
        df <- domain_freq[[dk]]
        if (is.null(df)) next
        hits <- all_ids[all_ids %in% df$concept_id]
        if (length(hits) > 0) {
          matched_ids <- c(matched_ids, hits)
          matched_n   <- c(matched_n,
            sapply(hits, function(id) {
              idx <- which(df$concept_id == id)
              if (length(idx) > 0) df$n[idx[[1]]] else 0L
            }))
        }
      }

      # Build evidence strings (top 3 matched concepts with patient counts)
      evidence <- character(0)
      if (length(matched_ids) > 0) {
        ord <- order(matched_n, decreasing = TRUE)[seq_len(min(3, length(matched_ids)))]
        evidence <- sapply(ord, function(j) {
          nm <- concept_name_map[[sprintf("%.0f", as.numeric(matched_ids[[j]]))]] %||%
                paste("Concept", matched_ids[[j]])
          sprintf("%s (%s patients)", nm, format(matched_n[[j]], big.mark = ","))
        })
      }

      # Domain-only hits (template uses domain broadly, no specific IDs)
      domain_only_hits <- sum(domain_hits) - sum(all_domains %in% names(domain_freq)[
        sapply(domain_freq, function(df) any(all_ids %in% df$concept_id))])
      domain_only_hits <- max(0L, domain_only_hits)

      # Score: weighted combination
      #   - Each exact concept match:  40 pts base, scaled by prevalence rank
      #   - Each domain-only match:    20 pts
      #   - All domains covered:       bonus 10 pts
      n_domains_hit   <- sum(domain_hits)
      n_domains_total <- length(all_domains)
      concept_score   <- if (total_ids > 0) (length(matched_ids) / total_ids) * 60 else 0
      domain_score    <- (n_domains_hit / n_domains_total) * 30
      coverage_bonus  <- if (n_domains_hit == n_domains_total) 10 else 0
      score           <- round(min(100, concept_score + domain_score + coverage_bonus))

      # Exclude templates with zero evidence
      feasible <- (score > 0) || (total_ids == 0 && n_domains_hit == n_domains_total)

      tmpl$match_count   <- length(matched_ids)
      tmpl$total_ids     <- total_ids
      tmpl$match_pct     <- if (total_ids > 0) length(matched_ids) / total_ids else
                            if (n_domains_hit > 0) 0.5 else 0
      tmpl$domain_hits   <- domain_hits
      tmpl$evidence      <- evidence
      tmpl$score         <- score
      tmpl$feasible      <- feasible
      tmpl$idx           <- i
      # n_top_records: highest single-concept record count across matched IDs.
      # Used by multi-schema breakdown to show a meaningful per-schema figure.
      tmpl$n_top_records <- if (length(matched_n) > 0) max(matched_n, na.rm = TRUE) else 0L
      tmpl
    })

  }, error = function(e) {
    # On any DB error return templates unscored
    lapply(seq_along(templates), function(i) {
      tmpl <- templates[[i]]
      tmpl$score <- 0; tmpl$match_count <- 0; tmpl$total_ids <- 0
      tmpl$domain_hits <- list(); tmpl$evidence <- character(0)
      tmpl$feasible <- TRUE; tmpl$idx <- i
      tmpl
    })
  })
}


# ── 5b2b. MULTI-SCHEMA TEMPLATE SCORING ───────────────────────────────────────
# Replaces the inline scoring block when >1 schema is selected.
# Key improvements over single-schema scoring:
#   1. Concept-level overlap: concepts found in ALL schemas are weighted higher
#   2. Cross-schema evidence: evidence strings highlight multi-schema matches
#   3. Overlap bonus: templates where all schemas have data score up to 20pts higher
#   4. Per-schema breakdown: shows record count and concept match% per schema
#
# Returns a list of scored templates with the same structure as score_templates()
# plus extra fields: $overlap_pct, $n_schemas_with_data.
score_templates_multi <- function(schemas, col_maps_list, summaries_list, templates) {
  if (length(schemas) == 0) return(list())
  if (length(schemas) == 1)
    return(score_templates(schemas[1], col_maps_list[[schemas[1]]], templates))

  # Score each schema independently
  per_schema <- setNames(lapply(schemas, function(s)
    score_templates(s, col_maps_list[[s]] %||% list(), templates)),
    schemas)

  # Person count per schema - used as size weight
  schema_sizes <- setNames(sapply(schemas, function(s) {
    sm <- summaries_list[[s]]
    if (!is.null(sm) && !is.na(sm$n_persons %||% NA)) max(1L, sm$n_persons)
    else 1L
  }), schemas)

  lapply(seq_along(templates), function(ti) {
    # Collect this template's result from every schema
    sr <- setNames(lapply(schemas, function(s) per_schema[[s]][[ti]]), schemas)

    # ── 1. Overlap: how many schemas have at least one matched concept? ────────
    n_with_data <- sum(sapply(sr, function(t_s)
      isTRUE(t_s$feasible) && (t_s$match_count %||% 0L) > 0))
    overlap_frac <- n_with_data / length(schemas)

    # ── 2. Weighted base score (size-weighted average) ─────────────────────────
    wt_sum <- sum(sapply(schemas, function(s)
      (sr[[s]]$score %||% 0L) * schema_sizes[[s]]))
    wt_cnt <- sum(schema_sizes)
    base_score <- if (wt_cnt > 0) round(wt_sum / wt_cnt) else 0L

    # ── 3. Overlap bonus: up to +20 pts, quadratic so partial overlap gets less
    #    Full overlap (all schemas match) = +20; half = +5; one schema = 0.
    overlap_bonus <- if (length(schemas) > 1)
      round(20 * overlap_frac^2)
    else 0L
    combined_score <- min(100L, base_score + overlap_bonus)

    # ── 4. Cross-schema evidence: collect all evidence, mark multi-schema hits ─
    # Build a named list keyed on concept name (stripped of count)
    ev_map <- list()
    for (s in schemas) {
      for (ev_str in (sr[[s]]$evidence %||% character(0))) {
        # ev_str format: "Concept Name (N patients)"
        cname <- trimws(sub("\\s*\\(.*$", "", ev_str))
        if (!nzchar(cname)) next
        if (is.null(ev_map[[cname]]))
          ev_map[[cname]] <- list(label=ev_str, schemas=character(0), max_n=0L)
        ev_map[[cname]]$schemas <- unique(c(ev_map[[cname]]$schemas, s))
        # Extract N
        m <- regmatches(ev_str, regexpr("[0-9,]+(?= patients)", ev_str, perl=TRUE))
        if (length(m) > 0) {
          n_val <- suppressWarnings(as.integer(gsub(",", "", m)))
          if (!is.na(n_val) && n_val > ev_map[[cname]]$max_n)
            ev_map[[cname]]$max_n <- n_val
        }
      }
    }
    # Sort: multi-schema hits first, then by record count
    # Guard: sapply on empty list returns list(), not numeric(0), breaking -
    combined_evidence <- if (length(ev_map) == 0) {
      character(0)
    } else {
      ev_order <- order(
        -as.numeric(sapply(ev_map, function(x) length(x$schemas))),
        -as.numeric(sapply(ev_map, function(x) x$max_n))
      )
      ev_sorted <- ev_map[ev_order]
      sapply(head(ev_sorted, 3L), function(ev_item) {
        n_schemas_for_concept <- length(ev_item$schemas)
        if (n_schemas_for_concept >= length(schemas) && length(schemas) > 1) {
          paste0(ev_item$label, " \u2713 all schemas")
        } else if (n_schemas_for_concept > 1) {
          paste0(ev_item$label, " [", n_schemas_for_concept, " schemas]")
        } else {
          ev_item$label
        }
      })
    }  # end if (length(ev_map) == 0) else

    # ── 5. Per-schema breakdown ────────────────────────────────────────────────
    breakdown <- sapply(schemas, function(s) {
      t_s <- sr[[s]]
      n_q <- t_s$n_top_records %||% 0L
      match_pct_s <- round(100 *
        (t_s$match_count %||% 0L) / max(1L, t_s$total_ids %||% 1L))
      if (isTRUE(t_s$feasible) && n_q > 0)
        sprintf("%s: %s records (%d%%)", s,
                format(n_q, big.mark = ","), match_pct_s)
      else
        sprintf("%s: not found", s)
    })

    # Build the return object from the highest-scoring schema's base
    # (carries idx, name, category, criteria, etc.)
    best_schema <- schemas[which.max(sapply(schemas, function(s)
      sr[[s]]$score %||% 0L))]
    base <- sr[[best_schema]]

    base$score              <- combined_score
    base$feasible           <- combined_score > 0
    base$evidence           <- combined_evidence
    base$breakdown          <- breakdown
    base$overlap_pct        <- overlap_frac
    base$n_schemas_with_data<- n_with_data
    base
  })
}


# ── 5b3. FULL COHORT EXTRACT ───────────────────────────────────────────────────
# For each OMOP table that contains a person_id column, selects all rows
# belonging to the cohort and writes a CSV.  Returns a list:
#   $files   - named vector: table_name -> local file path written
#   $counts  - named integer: table_name -> rows written
#   $errors  - named character: table_name -> error message (if any)
#
# Extra tables included beyond DOMAINS:
#   person, observation_period
#
# progress_fn(table_name, i, total) is called before each table query.
# ── 5b4. DICTIONARY XML GENERATION ────────────────────────────────────────────
# Produces a DatasetDefinition XML file matching the Aridhia FAIR metadata format.
# One XML per CSV: describes every column with type, label and description.
#
# Type mapping (R class → XML type):
#   integer / logical               → "integer"
#   numeric / double                → "decimal"
#   character / factor              → "text"
#   Date / POSIXct / POSIXlt       → "date"
#
# Known OMOP CDM column descriptions are pre-populated; unknown columns fall
# back to a generated label derived from snake_case.

