# Map R class to XML Type token
r_class_to_xml_type <- function(cls) {
  cls <- tolower(cls[[1]])
  if (cls %in% c("integer", "logical"))          return("integer")
  if (cls %in% c("numeric", "double", "float"))  return("decimal")
  if (cls %in% c("date", "posixct", "posixlt"))  return("date")
  "text"   # character, factor, everything else
}

# Snake_case → Title Case label
snake_to_label <- function(x) {
  gsub("(^|_)([[:alpha:]])", "\\U\\2", gsub("_", " ", x), perl = TRUE)
}

# Escape XML special characters in attribute values / text
xml_escape <- function(x) {
  x <- gsub("&",  "&amp;",  x, fixed = TRUE)
  x <- gsub("<",  "&lt;",   x, fixed = TRUE)
  x <- gsub(">",  "&gt;",   x, fixed = TRUE)
  x <- gsub("\"", "&quot;", x, fixed = TRUE)
  x <- gsub("'",  "&apos;", x, fixed = TRUE)
  x
}

# Generate DatasetDefinition XML for a data.frame
# table_name: used in TableName attribute (already schema-qualified by caller)
# description: human-readable table description
generate_dict_xml <- function(df, table_name, description = "") {
  lines <- character(0)
  lines <- c(lines, '<?xml version="1.0" encoding="UTF-8"?>')
  lines <- c(lines, sprintf('<DatasetDefinition Action="create" TableName="%s">',
                             xml_escape(table_name)))
  lines <- c(lines, sprintf("  <Title>%s</Title>", xml_escape(table_name)))
  lines <- c(lines, "  <Url></Url>")
  lines <- c(lines, sprintf("  <Description>%s</Description>",
                             xml_escape(description)))
  lines <- c(lines, "  <Columns>")

  col_names <- names(df)
  col_classes <- sapply(df, function(v) class(v)[[1]])

  for (i in seq_along(col_names)) {
    cn  <- col_names[[i]]
    typ <- r_class_to_xml_type(col_classes[[i]])
    meta <- OMOP_COL_META[[tolower(cn)]]
    lbl  <- if (!is.null(meta)) xml_escape(meta$l) else xml_escape(snake_to_label(cn))
    dsc  <- if (!is.null(meta)) xml_escape(meta$d) else xml_escape(snake_to_label(cn))
    lines <- c(lines, sprintf(
      '    <Column Name="%s" Description="%s" Label="%s" Type="%s"/>',
      xml_escape(cn), dsc, lbl, typ))
  }

  lines <- c(lines, "  </Columns>")
  lines <- c(lines,
    '  <Format Delimiter="," Encoding="UTF-8" Header="true" HeaderCase="lower"/>')
  lines <- c(lines, "</DatasetDefinition>")
  paste(lines, collapse = "\n")
}

# Per-table human-readable descriptions for OMOP tables
OMOP_TABLE_DESC <- list(
  person               = "One row per patient. Contains demographic attributes.",
  observation_period   = "Spans of time for which a patient has observable data.",
  condition_occurrence = "Records of conditions (diagnoses) present for a patient.",
  drug_exposure        = "Records of drugs dispensed or prescribed to a patient.",
  procedure_occurrence = "Records of clinical procedures performed on a patient.",
  measurement          = "Structured values from lab tests, vital signs and similar measurements.",
  observation          = "Clinical observations, scores and assessments not captured elsewhere.",
  visit_occurrence     = "Records of patient encounters with the healthcare system.",
  death                = "Death records including date and cause of death.",
  cohort_manifest      = "Cohort member list: one row per patient with their index date."
)

extract_cohort_tables <- function(schema, col_map, person_ids, out_dir,
                                   dict_schema = "",
                                   progress_fn = NULL) {

  if (!dir.exists(out_dir))
    dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)

  # All tables to extract: person + obs_period + all OMOP domain tables
  extra_tables <- list(
    person = list(
      table = "person", person_col = "person_id", extra_cols = list()
    ),
    observation_period = list(
      table = "observation_period", person_col = "person_id", extra_cols = list()
    )
  )
  all_tables <- c(extra_tables, lapply(DOMAINS, function(d)
    list(table = d$table, person_col = d$person_col, extra_cols = list())))

  existing_tbls <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))

  ids_sql  <- pid_sql(person_ids)

  files  <- character(0)
  counts <- integer(0)
  errors <- character(0)

  for (i in seq_along(all_tables)) {
    entry  <- all_tables[[i]]
    tbl    <- entry$table
    key    <- names(all_tables)[[i]]

    if (!is.null(progress_fn)) progress_fn(tbl, i, length(all_tables))

    if (!tbl %in% existing_tbls) {
      errors[[key]] <- "Table not present in schema"
      next
    }

    pid_col <- ac(col_map, tbl, entry$person_col)
    if (is.null(pid_col) || !nzchar(pid_col)) {
      errors[[key]] <- "person_id column could not be resolved"
      next
    }

    df <- tryCatch(
      db_query(sprintf(
        "SELECT * FROM %s WHERE %s IN (%s)",
        fq(schema, tbl), pid_col, ids_sql)),
      error = function(e) e)

    if (inherits(df, "error")) {
      errors[[key]] <- conditionMessage(df)
      next
    }

    if (is.null(df) || nrow(df) == 0) {
      counts[[key]] <- 0L
      next    # don't write empty files
    }

    # Normalise column names to lowercase for portability
    names(df) <- tolower(names(df))

    file_path <- file.path(out_dir, paste0(tbl, ".csv"))
    utils::write.csv(df, file_path, row.names = FALSE)
    files[[key]]  <- file_path
    counts[[key]] <- nrow(df)

    # Write matching dictionary XML
    xml_table_name <- if (nzchar(dict_schema %||% ""))
      paste0(dict_schema, ".", tbl) else tbl
    tbl_desc <- OMOP_TABLE_DESC[[tbl]] %||%
                paste("OMOP CDM table:", tbl)
    xml_content <- tryCatch(
      generate_dict_xml(df, xml_table_name, tbl_desc),
      error = function(e) NULL)
    if (!is.null(xml_content)) {
      xml_path <- file.path(out_dir, paste0(tbl, ".xml"))
      writeLines(xml_content, xml_path)
    }
  }

  # Write cohort manifest: person_id + index_date
  manifest_path <- file.path(out_dir, "cohort_manifest.csv")
  manifest_df <- data.frame(
    person_id = as_pid(person_ids),
    stringsAsFactors = FALSE)
  utils::write.csv(manifest_df, manifest_path, row.names = FALSE)
  files[["cohort_manifest"]]  <- manifest_path
  counts[["cohort_manifest"]] <- length(person_ids)

  # Dictionary XML for manifest
  manifest_xml_name <- if (nzchar(dict_schema %||% ""))
    paste0(dict_schema, ".cohort_manifest") else "cohort_manifest"
  manifest_xml <- tryCatch(
    generate_dict_xml(manifest_df, manifest_xml_name,
                      OMOP_TABLE_DESC[["cohort_manifest"]]),
    error = function(e) NULL)
  if (!is.null(manifest_xml))
    writeLines(manifest_xml, file.path(out_dir, "cohort_manifest.xml"))

  # Write README
  readme_path <- file.path(out_dir, "README.txt")
  csv_files_readme <- names(files)[names(files) != "cohort_manifest"]
  file_lines <- paste0(
    "  ", basename(files[csv_files_readme]), " / ",
    sub("[.]csv$", ".xml", basename(files[csv_files_readme])),
    "  - ", sapply(csv_files_readme, function(k) paste(counts[[k]] %||% 0L, "rows")))
  writeLines(c(
    "OMOP Cohort Extract",
    paste("Generated:", format(Sys.time(), "%Y-%m-%d %H:%M:%S")),
    paste("Source schema:", schema),
    if (nzchar(dict_schema %||% "")) paste("Dictionary schema:", dict_schema),
    paste("Cohort size:", length(person_ids), "persons"),
    "",
    "Files in this export:",
    "  cohort_manifest.csv / cohort_manifest.xml  - cohort member list",
    file_lines,
    "  README.txt",
    "",
    "Each .csv has a matching .xml DatasetDefinition dictionary file.",
    "Import the .xml files into the Aridhia FAIR Data Services catalogue",
    "to register the tables before uploading the CSV data.",
    "",
    "All tables are filtered to cohort members only.",
    "Column names are lowercased for portability.",
    "OMOP CDM v5.3/v5.4 schema."
  ), readme_path)

  list(files = files, counts = counts, errors = errors,
       out_dir = out_dir, n_persons = length(person_ids))
}

# Materialise a cohort as a complete, valid OMOP CDM in a new database schema,
# server-side (CREATE TABLE AS SELECT - data never leaves the database). Writes:
#   - clinical tables (person, observation_period, all DOMAINS tables present),
#     each filtered to cohort members, copied with source column casing;
#   - vocabulary tables copied whole (when include_vocab), so concept names
#     resolve and the CDM is self-contained;
#   - cdm_source metadata (copied if present);
#   - the OHDSI cohort triple in standard lowercase shape: cohort
#     (cohort_definition_id, subject_id, cohort_start_date = index_date,
#     cohort_end_date = observation_period end >= index, clamped), plus
#     cohort_set and cohort_attrition companions so CDMConnector attaches it and
#     the OHDSI tab discovers it.
# cohort_result must carry person_id and index_date. Refuses if target exists.
# Returns list(ok, schema, status) where status$created/$skipped/$errors report
# each table, so a partial write is fully accounted for.
materialise_cohort_to_schema <- function(source_schema, col_map, cohort_result,
                                          target_schema, cohort_name = "cohort",
                                          include_vocab = TRUE, definition_json = NULL,
                                          progress_fn = NULL) {
  status <- list(created = character(0), skipped = character(0), errors = list())
  add_ok   <- function(t) status$created <<- c(status$created, t)
  add_skip <- function(t, why) {
    status$skipped <<- c(status$skipped, t); status$errors[[t]] <<- why
  }
  ctas <- function(tbl, select_sql) {
    r <- tryCatch({ db_execute(sprintf('CREATE TABLE %s AS %s',
                                        fq(target_schema, tbl), select_sql)); TRUE },
                  error = function(e) { add_skip(tbl, conditionMessage(e)); FALSE })
    if (isTRUE(r)) add_ok(tbl)
    isTRUE(r)
  }

  ts <- tolower(gsub("[^A-Za-z0-9_]", "_", target_schema %||% ""))
  if (!nzchar(ts) || !grepl("^[a-z_]", ts))
    return(list(ok = FALSE, msg = "Invalid schema name. Use letters, digits and underscores, starting with a letter."))
  target_schema <- ts

  if (!conn_valid()) return(list(ok = FALSE, msg = "No database connection."))

  ex <- tryCatch(db_query(sprintf(
    "SELECT 1 FROM information_schema.schemata WHERE schema_name = %s",
    DBI::dbQuoteString(DRE_CONN, ts))), error = function(e) NULL)
  if (!is.null(ex) && nrow(ex) > 0)
    return(list(ok = FALSE,
      msg = sprintf("Schema '%s' already exists. Choose another name or drop it first.", ts)))

  created_schema <- tryCatch({ db_execute(sprintf('CREATE SCHEMA "%s"', ts)); TRUE },
                             error = function(e) { status$errors[["schema"]] <<- conditionMessage(e); FALSE })
  if (!isTRUE(created_schema))
    return(list(ok = FALSE, msg = paste("Could not create schema:", status$errors[["schema"]])))

  existing <- tryCatch(tolower(get_tables(source_schema)), error = function(e) character(0))
  ids_sql  <- pid_sql(unique(as_pid(cohort_result$person_id)))

  clin <- c(list(list(table = "person",             person_col = "person_id"),
                 list(table = "observation_period", person_col = "person_id")),
            unname(lapply(DOMAINS, function(d) list(table = d$table, person_col = d$person_col))))
  for (i in seq_along(clin)) {
    e <- clin[[i]]; tbl <- e$table
    if (!is.null(progress_fn)) progress_fn(tbl, i, length(clin) + 12L)
    if (!tbl %in% existing) { add_skip(tbl, "not in source schema"); next }
    pid_col <- ac(col_map, tbl, e$person_col)
    if (is.null(pid_col) || !nzchar(pid_col)) { add_skip(tbl, "person column unresolved"); next }
    ctas(tbl, sprintf('SELECT * FROM %s WHERE %s IN (%s)',
                      fq(source_schema, tbl), pid_col, ids_sql))
  }

  if (isTRUE(include_vocab)) {
    vocab <- c("concept", "vocabulary", "domain", "concept_class", "relationship",
               "concept_relationship", "concept_ancestor", "concept_synonym", "drug_strength")
    for (j in seq_along(vocab)) {
      tbl <- vocab[[j]]
      if (!is.null(progress_fn)) progress_fn(tbl, length(clin) + j, length(clin) + 12L)
      if (!tbl %in% existing) { add_skip(tbl, "not in source schema"); next }
      ctas(tbl, sprintf('SELECT * FROM %s', fq(source_schema, tbl)))
    }
  }

  if ("cdm_source" %in% existing)
    ctas("cdm_source", sprintf('SELECT * FROM %s', fq(source_schema, "cdm_source")))

  # ── cohort triple ───────────────────────────────────────────────────────────
  cr <- cohort_result[!is.na(cohort_result$index_date), c("person_id", "index_date"), drop = FALSE]
  cr <- cr[!duplicated(cr$person_id), , drop = FALSE]
  if (nrow(cr) == 0) {
    add_skip("cohort", "no cohort members carry an index_date")
  } else {
    if (!is.null(progress_fn)) progress_fn("cohort", length(clin) + 11L, length(clin) + 12L)
    vals <- paste(sprintf("(%s::bigint, %s::date)", as_pid(cr$person_id),
                          DBI::dbQuoteString(DRE_CONN, as.character(as.Date(cr$index_date)))),
                  collapse = ", ")
    op_pid <- ac(col_map, "observation_period", "person_id")
    op_end <- ac(col_map, "observation_period", "observation_period_end_date")
    end_expr <- if ("observation_period" %in% existing &&
                    !is.null(op_end) && nzchar(op_end) && !is.null(op_pid) && nzchar(op_pid))
      sprintf("COALESCE((SELECT MAX(op.%s::date) FROM %s op
                          WHERE op.%s = m.subject_id AND op.%s::date >= m.cohort_start_date),
                         m.cohort_start_date)",
              op_end, fq(source_schema, "observation_period"), op_pid, op_end)
      else "m.cohort_start_date"
    cohort_ok <- ctas("cohort", sprintf(
      'WITH m(subject_id, cohort_start_date) AS (VALUES %s)
       SELECT 1::int AS cohort_definition_id, m.subject_id,
              m.cohort_start_date, %s AS cohort_end_date
       FROM m', vals, end_expr))
    if (cohort_ok) {
      n <- nrow(cr)
      def_sql <- if (is.null(definition_json) || !nzchar(definition_json)) "NULL::text"
                 else paste0(DBI::dbQuoteString(DRE_CONN, definition_json), "::text")
      ctas("cohort_set", sprintf(
        'SELECT 1::int AS cohort_definition_id, %s::text AS cohort_name,
                %s AS cohort_definition_json',
        DBI::dbQuoteString(DRE_CONN, cohort_name), def_sql))
      ctas("cohort_attrition", sprintf(
        'SELECT 1::int AS cohort_definition_id, %d::int AS number_records,
                %d::int AS number_subjects, 1::int AS reason_id,
                %s::text AS reason, 0::int AS excluded_records, 0::int AS excluded_subjects',
        n, n, DBI::dbQuoteString(DRE_CONN, "Initial qualifying events")))
    }
  }

  list(ok = TRUE, schema = ts, status = status)
}

# ── 5b5. CHARACTERISATION QUERY HELPERS ───────────────────────────────────────

# Index event timeline: count of index events per quarter
# Comorbidity profile: top N conditions/drugs/measurements by prevalence in cohort
query_comorbidity_profile <- function(schema, col_map, person_ids,
                                      domain_key = "condition", top_n = 15L) {
  if (length(person_ids) == 0) return(NULL)
  dom <- DOMAINS[[domain_key]]
  if (is.null(dom)) return(NULL)

  existing <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  if (!tolower(dom$table) %in% existing) return(NULL)

  ids_sql  <- pid_sql(person_ids)
  pid_col  <- ac(col_map, dom$table, dom$person_col)
  cid_col  <- ac(col_map, dom$table, dom$concept_col)
  n_cohort <- length(unique(person_ids))

  # Concept frequencies
  freq_df <- tryCatch(db_query(sprintf(
    "SELECT %s AS concept_id,
            COUNT(DISTINCT %s) AS n_persons
     FROM   %s
     WHERE  %s IN (%s)
       AND  %s > 0
     GROUP  BY 1
     ORDER  BY 2 DESC
     LIMIT  %d",
    cid_col, pid_col, fq(schema, dom$table),
    pid_col, ids_sql, cid_col, top_n)),
    error = function(e) NULL)

  if (is.null(freq_df) || nrow(freq_df) == 0) return(NULL)

  # Look up concept names
  concept_tbl_exists <- "concept" %in% existing
  names_df <- NULL
  if (concept_tbl_exists) {
    cid_col_c   <- ac(col_map, "concept", "concept_id")
    cname_col_c <- ac(col_map, "concept", "concept_name")
    if (!is.null(cid_col_c) && !is.null(cname_col_c)) {
      ids_c <- cid_sql(freq_df$concept_id)
      names_df <- tryCatch(db_query(sprintf(
        "SELECT %s AS concept_id, %s AS concept_name
         FROM   %s WHERE %s IN (%s)",
        cid_col_c, cname_col_c, fq(schema, "concept"),
        cid_col_c, ids_c)),
        error = function(e) {
          message("[concept lookup] error: ", conditionMessage(e))
          NULL
        })
      if (!is.null(names_df)) names(names_df) <- tolower(names(names_df))
    }
  }

  # Merge names
  if (!is.null(names_df)) {
    # Normalise to character so integer/numeric type differences don't break merge
    freq_df$concept_id   <- as.character(freq_df$concept_id)
    names_df$concept_id  <- as.character(names_df$concept_id)
    freq_df <- merge(freq_df, names_df, by = "concept_id", all.x = TRUE)
    freq_df$label <- ifelse(is.na(freq_df$concept_name),
                            paste("Concept", freq_df$concept_id),
                            as.character(freq_df$concept_name))
  } else {
    freq_df$label <- paste("Concept", freq_df$concept_id)
  }

  freq_df$pct      <- 100 * freq_df$n_persons / n_cohort
  freq_df$n_cohort <- n_cohort
  freq_df[order(freq_df$n_persons, decreasing = TRUE), ]
}

# ── DRE ggplot theme (global - used by server plots and helper functions) ──────
theme_dre <- function() {
  ggplot2::theme_minimal(base_size = 13) +
  ggplot2::theme(
    plot.background    = ggplot2::element_rect(fill = "#0D2A4A", colour = NA),
    panel.background   = ggplot2::element_rect(fill = "#0B2341", colour = NA),
    panel.grid.major   = ggplot2::element_line(colour = "#FFFFFF10", linewidth = 0.4),
    panel.grid.minor   = ggplot2::element_blank(),
    axis.text          = ggplot2::element_text(colour = "#8BA3B5", size = 11),
    axis.title         = ggplot2::element_text(colour = "#8BA3B5", size = 12),
    plot.title         = ggplot2::element_text(colour = "#E8F4F8", size = 13, face = "bold"),
    plot.subtitle      = ggplot2::element_text(colour = "#8BA3B5", size = 11),
    plot.caption       = ggplot2::element_text(colour = "#FFB84D", size = 10, hjust = 0),
    legend.background  = ggplot2::element_rect(fill = "#0B2341", colour = NA),
    legend.text        = ggplot2::element_text(colour = "#8BA3B5", size = 11),
    strip.text         = ggplot2::element_text(colour = "#E8F4F8", size = 11),
    axis.ticks         = ggplot2::element_blank()
  )
}

# ── 5b5b. CHARACTERISATION HELPERS ────────────────────────────────────────────

# Follow-up time distribution: days from index to end of observation
query_followup_dist <- function(schema, col_map, cohort_result) {
  existing <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  if (!"observation_period" %in% existing) return(NULL)
  if (!"index_date" %in% names(cohort_result)) return(NULL)

  pid_col <- ac(col_map, "observation_period", "person_id")
  end_col <- ac(col_map, "observation_period", "observation_period_end_date")
  ids_sql  <- pid_sql(cohort_result$person_id)

  tmp_vals <- paste(
    sprintf("(%.0f, '%s'::date)",
            as_pid(cohort_result$person_id),
            as.character(as.Date(cohort_result$index_date))),
    collapse = ", ")

  tryCatch(db_query(sprintf(
    "WITH idx(person_id, index_date) AS (VALUES %s)
     SELECT (MAX(op.%s::date) - i.index_date)::int AS days
     FROM   %s op
     JOIN   idx i ON i.person_id = op.%s
     WHERE  op.%s IN (%s) AND op.%s::date >= i.index_date
     GROUP  BY i.person_id, i.index_date",
    tmp_vals, end_col,
    fq(schema, "observation_period"), pid_col,
    pid_col, ids_sql, end_col)),
    error = function(e) NULL)
}

# Measurement value distributions: for top N measurements, return value stats
query_measurement_dist <- function(schema, col_map, person_ids, top_n = 8L) {
  existing <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  if (!"measurement" %in% existing) {
    message("[meas_dist] measurement table not found in schema '", schema, "'")
    return(NULL)
  }

  ids_sql  <- pid_sql(person_ids)
  pid_col  <- ac(col_map, "measurement", "person_id")
  cid_col  <- ac(col_map, "measurement", "measurement_concept_id")
  val_col  <- ac(col_map, "measurement", "value_as_number")

  message(sprintf("[meas_dist] schema=%s  pid=%s  cid=%s  val=%s  n_ids=%d",
                  schema, pid_col, cid_col, val_col, length(person_ids)))

  # Verify value_as_number column actually exists in the table
  # ac() falls back to the logical name when not in col_map - check it exists
  meas_cols <- tryCatch(
    tolower(names(db_query(sprintf("SELECT * FROM %s LIMIT 0",
                                   fq(schema, "measurement"))))),
    error = function(e) character(0))
  message("[meas_dist] measurement columns: ", paste(meas_cols, collapse=", "))

  # Resolve the actual value column name (unquoted) from what's in the table
  val_bare <- gsub('"', '', val_col)   # strip surrounding quotes added by qq()
  if (!tolower(val_bare) %in% meas_cols) {
    # Try common alternatives
    alt <- intersect(c("value_as_number","valueasnumber","value_num","value"),
                     meas_cols)
    if (length(alt) == 0) {
      message("[meas_dist] value_as_number not found; available: ",
              paste(meas_cols, collapse=", "))
      return(NULL)
    }
    val_col <- qq(alt[[1]])
    message("[meas_dist] using fallback value column: ", val_col)
  }

  # Step 1: find top N concepts by total record count (used for both numeric
  # value-distribution selection and frequency-mode fallback). Also compute
  # the distinct patient count per concept - needed for the frequency-mode
  # display, since dividing record count by cohort N can easily produce
  # percentages > 100% when patients have many repeated measurements.
  # Bug 5 fix (v8.6).
  top_df <- tryCatch(db_query(sprintf(
    "SELECT %s AS concept_id,
            COUNT(*) AS n_records,
            COUNT(DISTINCT %s) AS n_persons
     FROM   %s
     WHERE  %s IN (%s)
       AND  %s > 0
     GROUP  BY 1
     ORDER  BY 2 DESC
     LIMIT  %d",
    cid_col, pid_col, fq(schema, "measurement"),
    pid_col, ids_sql,
    cid_col, top_n * 4L)),
    error = function(e) { message("[meas_dist] top_df error: ", e$message); NULL })

  message("[meas_dist] top_df rows: ", if (is.null(top_df)) "NULL" else nrow(top_df))
  if (is.null(top_df) || nrow(top_df) == 0) return(NULL)

  # Preserve old `n` field for code paths that read it (notably the
  # box-plot ranking that still wants total record count); add explicit
  # `n_persons` for the frequency display.
  if (!is.null(top_df) && nrow(top_df) > 0) {
    top_df$n <- top_df$n_records
  }

  ids_c <- cid_sql(top_df$concept_id)

  # Concept name lookup (needed for both numeric and frequency paths)
  ids_c_top <- cid_sql(head(top_df$concept_id, top_n))
  names_df <- NULL
  if ("concept" %in% existing) {
    cid_col_c   <- ac(col_map, "concept", "concept_id")
    cname_col_c <- ac(col_map, "concept", "concept_name")
    names_df <- tryCatch(db_query(sprintf(
      "SELECT %s AS concept_id, %s AS concept_name
       FROM   %s WHERE %s IN (%s)",
      cid_col_c, cname_col_c, fq(schema, "concept"),
      cid_col_c, ids_c_top)),
      error = function(e) { message("[meas_dist] names_df error: ", e$message); NULL })
      if (!is.null(names_df)) names(names_df) <- tolower(names(names_df))
  }

  add_labels <- function(df, id_col = "concept_id") {
    if (!is.null(names_df) && nrow(names_df) > 0) {
      # Normalise keys to character to avoid integer/numeric type mismatch
      df[[id_col]]        <- as.character(df[[id_col]])
      names_df$concept_id <- as.character(names_df$concept_id)
      df <- merge(df, names_df, by.x = id_col, by.y = "concept_id", all.x = TRUE)
      df$label <- ifelse(is.na(df$concept_name),
                         paste("Concept", df[[id_col]]),
                         as.character(df$concept_name))
    } else {
      df$label <- paste("Concept", df[[id_col]])
    }
    df$label <- ifelse(nchar(df$label) > 45,
                       paste0(substr(df$label, 1, 42), "..."),
                       df$label)
    df
  }

  # Step 2: try to fetch numeric values using the ac()-resolved column name
  # (already correctly quoted and cased from information_schema)
  message("[meas_dist] val_df query using val_col=", val_col)
  ids_c <- cid_sql(top_df$concept_id)

  val_df <- tryCatch(db_query(sprintf(
    "SELECT %s AS concept_id, %s::numeric AS value
     FROM   %s
     WHERE  %s IN (%s)
       AND  %s IN (%s)
       AND  %s IS NOT NULL
       AND  %s < 1e9
       AND  %s > -1e9",
    cid_col, val_col, fq(schema, "measurement"),
    pid_col, ids_sql,
    cid_col, ids_c,
    val_col, val_col, val_col)),
    error = function(e) { message("[meas_dist] val_df error: ", e$message); NULL })

  message("[meas_dist] val_df rows: ", if (is.null(val_df)) "NULL" else nrow(val_df))

  # ── Numeric values present → return for box plots ─────────────────────────
  if (!is.null(val_df) && nrow(val_df) > 0) {
    has_values <- unique(val_df$concept_id)
    top_num    <- top_df[top_df$concept_id %in% has_values, ]
    top_num    <- head(top_num, top_n)
    val_df     <- val_df[val_df$concept_id %in% top_num$concept_id, ]
    val_df     <- add_labels(val_df)
    val_df$value <- as.numeric(val_df$value)
    message("[meas_dist] returning ", length(unique(val_df$concept_id)),
            " concepts (numeric mode)")
    attr(val_df, "mode") <- "numeric"
    return(val_df)
  }

  # ── No numeric values → fall back to frequency bar chart ──────────────────
  message("[meas_dist] VALUE_AS_NUMBER unpopulated - falling back to frequency mode")
  freq_df <- head(top_df, top_n)
  freq_df <- add_labels(freq_df, "concept_id")
  attr(freq_df, "mode") <- "frequency"
  freq_df
}

# Charlson Comorbidity Index (Quan 2005 mapping to SNOMED/ICD concepts)
# Uses condition_occurrence; maps standard OMOP concepts to CCI categories.
# Returns data.frame: person_id, cci_score, cci_category
compute_cci <- function(schema, col_map, person_ids) {
  existing <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  if (!"condition_occurrence" %in% existing) return(NULL)

  ids_sql  <- pid_sql(person_ids)
  pid_col <- ac(col_map, "condition_occurrence", "person_id")
  cid_col <- ac(col_map, "condition_occurrence", "condition_concept_id")

  # Quan 2005 OMOP concept IDs for Charlson conditions (weight in list name)
  # These are standard OMOP/SNOMED concept IDs for each CCI category
  cci_map <- list(
    w1_mi          = list(w=1, ids=c(4329847L,314666L,312327L)),
    w1_chf         = list(w=1, ids=c(316139L,4229440L)),
    w1_pvd         = list(w=1, ids=c(321596L,4108564L)),
    w1_cva         = list(w=1, ids=c(372924L,375557L,443454L)),
    w1_dementia    = list(w=1, ids=c(4182210L,378419L,373192L)),
    w1_copd        = list(w=1, ids=c(255573L,4274024L)),
    w1_rheum       = list(w=1, ids=c(80809L,257628L,134442L)),
    w1_pud         = list(w=1, ids=c(4027663L,40481087L)),
    w1_mild_liver  = list(w=1, ids=c(4064161L,4212540L)),
    w1_diabetes_unc= list(w=1, ids=c(201820L,442793L)),
    w2_diabetes_c  = list(w=2, ids=c(201826L,4099651L)),
    w2_hemiplegia  = list(w=2, ids=c(4291005L,432284L)),
    w2_renal       = list(w=2, ids=c(46271022L,4030518L,443919L)),
    w2_cancer      = list(w=2, ids=c(443392L,4248385L,4112853L,4029524L,4212540L)),
    w3_mod_liver   = list(w=3, ids=c(4245975L,196454L,57345L)),
    w6_mets        = list(w=6, ids=c(432851L,4212448L)),
    w6_aids        = list(w=6, ids=c(439727L,4159981L))
  )

  all_ids <- unique(unlist(lapply(cci_map, `[[`, "ids")))
  ids_c   <- cid_sql(all_ids)

  # Fetch which cohort persons have which CCI concept IDs
  pts_df <- tryCatch(db_query(sprintf(
    "SELECT DISTINCT %s AS person_id, %s AS concept_id
     FROM   %s
     WHERE  %s IN (%s) AND %s IN (%s)",
    pid_col, cid_col, fq(schema, "condition_occurrence"),
    pid_col, ids_sql, cid_col, ids_c)),
    error = function(e) NULL)

  # Build score per person
  score_tbl <- data.frame(person_id = as_pid(person_ids),
                           cci_score = 0L, stringsAsFactors = FALSE)

  if (!is.null(pts_df) && nrow(pts_df) > 0) {
    for (cat_name in names(cci_map)) {
      cat_info <- cci_map[[cat_name]]
      hit_pids <- unique(pts_df$person_id[pts_df$concept_id %in% cat_info$ids])
      if (length(hit_pids) > 0) {
        idx <- score_tbl$person_id %in% hit_pids
        score_tbl$cci_score[idx] <- score_tbl$cci_score[idx] + cat_info$w
      }
    }
  }

  score_tbl$cci_category <- cut(
    score_tbl$cci_score,
    breaks = c(-Inf, 0, 1, 2, 3, Inf),
    labels = c("0 (None)", "1 (Low)", "2 (Moderate)", "3 (High)", "4+ (Very high)"),
    right  = TRUE)
  score_tbl
}

# Table 1: compute a standard baseline characteristics table from cohort data
build_table1 <- function(schema, col_map, person_ids, cohort_result) {
  if (length(person_ids) == 0) return(NULL)
  n_total   <- length(unique(person_ids))
  ids_sql  <- pid_sql(person_ids)
  existing  <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  rows      <- list()

  # ── N ────────────────────────────────────────────────────────────────────────
  rows[["n"]] <- data.frame(
    Characteristic = "N",
    Value          = format(n_total, big.mark = ","),
    stringsAsFactors = FALSE)

  # ── Age at index ─────────────────────────────────────────────────────────────
  if ("index_date" %in% names(cohort_result) && "person" %in% existing) {
    pid_col <- ac(col_map, "person", "person_id")
    yob_col <- ac(col_map, "person", "year_of_birth")
    tmp_vals <- paste(
      sprintf("(%.0f, '%s'::date)",
              as_pid(cohort_result$person_id),
              as.character(as.Date(cohort_result$index_date))),
      collapse = ", ")
    age_df <- tryCatch(db_query(sprintf(
      "WITH idx(person_id, index_date) AS (VALUES %s)
       SELECT EXTRACT(YEAR FROM i.index_date)::int - p.%s AS age
       FROM   %s p JOIN idx i ON i.person_id = p.%s
       WHERE  p.%s IS NOT NULL",
      tmp_vals, yob_col, fq(schema, "person"), pid_col, yob_col)),
      error = function(e) NULL)
    if (!is.null(age_df) && nrow(age_df) > 0) {
      ages <- as.numeric(age_df$age)
      ages <- ages[!is.na(ages) & ages >= 0 & ages <= 120]
      rows[["age_mean"]] <- data.frame(
        Characteristic = "Age at index, mean (SD)",
        Value = sprintf("%.1f (%.1f)", mean(ages), sd(ages)),
        stringsAsFactors = FALSE)
      rows[["age_med"]] <- data.frame(
        Characteristic = "Age at index, median [IQR]",
        Value = sprintf("%.0f [%.0f-%.0f]",
                        median(ages), quantile(ages, 0.25), quantile(ages, 0.75)),
        stringsAsFactors = FALSE)
      # Age bands
      bands <- c("0-17" = 18, "18-44" = 45, "45-64" = 65, "65-74" = 75, "75+" = Inf)
      breaks <- c(-Inf, 18, 45, 65, 75, Inf)
      labels <- c("0-17", "18-44", "45-64", "65-74", "75+")
      age_grp <- cut(ages, breaks = breaks, labels = labels, right = FALSE)
      for (lbl in labels) {
        n_g <- sum(age_grp == lbl, na.rm = TRUE)
        rows[[paste0("age_", lbl)]] <- data.frame(
          Characteristic = paste0("  ", lbl, " years"),
          Value = sprintf("%s (%.1f%%)", format(n_g, big.mark=","), 100*n_g/n_total),
          stringsAsFactors = FALSE)
      }
    }
  }

  # ── Sex ──────────────────────────────────────────────────────────────────────
  if ("person" %in% existing) {
    pid_col <- ac(col_map, "person", "person_id")
    gcol    <- ac(col_map, "person", "gender_concept_id")
    gd <- tryCatch(db_query(sprintf(
      "SELECT CASE %s WHEN 8507 THEN 'Male' WHEN 8532 THEN 'Female'
              ELSE 'Other/Unknown' END AS sex, COUNT(*) AS n
       FROM   %s WHERE %s IN (%s) GROUP BY 1 ORDER BY 2 DESC",
      gcol, fq(schema, "person"), pid_col, ids_sql)),
      error = function(e) NULL)
    if (!is.null(gd) && nrow(gd) > 0) {
      rows[["sex_hdr"]] <- data.frame(Characteristic = "Sex", Value = "", stringsAsFactors = FALSE)
      for (i in seq_len(nrow(gd))) {
        rows[[paste0("sex_", i)]] <- data.frame(
          Characteristic = paste0("  ", gd$sex[i]),
          Value = sprintf("%s (%.1f%%)", format(gd$n[i], big.mark=","), 100*gd$n[i]/n_total),
          stringsAsFactors = FALSE)
      }
    }
  }

  # ── Race ─────────────────────────────────────────────────────────────────────
  if ("person" %in% existing) {
    pid_col  <- ac(col_map, "person", "person_id")
    race_col <- ac(col_map, "person", "race_concept_id")
    race_df  <- tryCatch({
      # Join to concept table for labels if available
      if ("concept" %in% existing) {
        cid_col_c   <- ac(col_map, "concept", "concept_id")
        cname_col_c <- ac(col_map, "concept", "concept_name")
        db_query(sprintf(
          "SELECT COALESCE(c.%s, 'Unknown/Other') AS race, COUNT(*) AS n
           FROM   %s p
           LEFT JOIN %s c ON c.%s = p.%s AND p.%s != 0
           WHERE  p.%s IN (%s)
           GROUP  BY 1 ORDER BY 2 DESC LIMIT 10",
          cname_col_c, fq(schema, "person"),
          fq(schema, "concept"), cid_col_c, race_col, race_col,
          pid_col, ids_sql))
      } else {
        db_query(sprintf(
          "SELECT CASE %s WHEN 0 THEN 'Unknown/Other' ELSE CAST(%s AS text) END AS race,
                  COUNT(*) AS n
           FROM   %s WHERE %s IN (%s) GROUP BY 1 ORDER BY 2 DESC LIMIT 10",
          race_col, race_col, fq(schema, "person"), pid_col, ids_sql))
      }
    }, error = function(e) NULL)
    if (!is.null(race_df) && nrow(race_df) > 0 && sum(race_df$n) > 0) {
      rows[["race_hdr"]] <- data.frame(Characteristic = "Race", Value = "", stringsAsFactors = FALSE)
      for (i in seq_len(nrow(race_df))) {
        rows[[paste0("race_", i)]] <- data.frame(
          Characteristic = paste0("  ", race_df$race[i]),
          Value = sprintf("%s (%.1f%%)", format(race_df$n[i], big.mark=","), 100*race_df$n[i]/n_total),
          stringsAsFactors = FALSE)
      }
    }
  }

  # ── Ethnicity ─────────────────────────────────────────────────────────────
  if ("person" %in% existing) {
    pid_col  <- ac(col_map, "person", "person_id")
    eth_col  <- ac(col_map, "person", "ethnicity_concept_id")
    eth_df   <- tryCatch({
      if ("concept" %in% existing) {
        cid_col_c   <- ac(col_map, "concept", "concept_id")
        cname_col_c <- ac(col_map, "concept", "concept_name")
        db_query(sprintf(
          "SELECT COALESCE(c.%s, 'Unknown/Other') AS ethnicity, COUNT(*) AS n
           FROM   %s p
           LEFT JOIN %s c ON c.%s = p.%s AND p.%s != 0
           WHERE  p.%s IN (%s)
           GROUP  BY 1 ORDER BY 2 DESC LIMIT 6",
          cname_col_c, fq(schema, "person"),
          fq(schema, "concept"), cid_col_c, eth_col, eth_col,
          pid_col, ids_sql))
      } else NULL
    }, error = function(e) NULL)
    if (!is.null(eth_df) && nrow(eth_df) > 0 && sum(eth_df$n) > 0) {
      rows[["eth_hdr"]] <- data.frame(Characteristic = "Ethnicity", Value = "", stringsAsFactors = FALSE)
      for (i in seq_len(nrow(eth_df))) {
        rows[[paste0("eth_", i)]] <- data.frame(
          Characteristic = paste0("  ", eth_df$ethnicity[i]),
          Value = sprintf("%s (%.1f%%)", format(eth_df$n[i], big.mark=","), 100*eth_df$n[i]/n_total),
          stringsAsFactors = FALSE)
      }
    }
  }

  # ── Observation time ─────────────────────────────────────────────────────────
  if ("observation_period" %in% existing && "index_date" %in% names(cohort_result)) {
    pid_col   <- ac(col_map, "observation_period", "person_id")
    end_col   <- ac(col_map, "observation_period", "observation_period_end_date")
    tmp_vals  <- paste(
      sprintf("(%.0f, '%s'::date)",
              as_pid(cohort_result$person_id),
              as.character(as.Date(cohort_result$index_date))),
      collapse = ", ")
    obs_df <- tryCatch(db_query(sprintf(
      "WITH idx(person_id, index_date) AS (VALUES %s)
       SELECT (MAX(op.%s) - i.index_date) AS follow_up_days
       FROM   %s op
       JOIN   idx i ON i.person_id = op.%s
       WHERE  op.%s IN (%s)
       GROUP  BY i.index_date, i.person_id",
      tmp_vals, end_col, fq(schema, "observation_period"),
      pid_col, pid_col, ids_sql)),
      error = function(e) NULL)
    if (!is.null(obs_df) && nrow(obs_df) > 0) {
      fu <- as.numeric(obs_df$follow_up_days)
      fu <- fu[!is.na(fu) & fu >= 0]
      if (length(fu) > 0) {
        rows[["followup"]] <- data.frame(
          Characteristic = "Follow-up after index, median days [IQR]",
          Value = sprintf("%.0f [%.0f-%.0f]",
                          median(fu), quantile(fu, 0.25), quantile(fu, 0.75)),
          stringsAsFactors = FALSE)
      }
    }
  }

  # ── Top 5 conditions ─────────────────────────────────────────────────────────
  if ("condition_occurrence" %in% existing) {
    cond_df <- tryCatch(
      query_comorbidity_profile(schema, col_map, person_ids, "condition", 5L),
      error = function(e) NULL)
    if (!is.null(cond_df) && nrow(cond_df) > 0) {
      rows[["cond_hdr"]] <- data.frame(
        Characteristic = "Top 5 conditions (% of cohort)", Value = "", stringsAsFactors = FALSE)
      for (i in seq_len(nrow(cond_df))) {
        rows[[paste0("cond_", i)]] <- data.frame(
          Characteristic = paste0("  ", cond_df$label[i]),
          Value = sprintf("%s (%.1f%%)",
                          format(cond_df$n_persons[i], big.mark=","), cond_df$pct[i]),
          stringsAsFactors = FALSE)
      }
    }
  }

  # ── Top 5 medications ────────────────────────────────────────────────────────
  if ("drug_exposure" %in% existing) {
    drug_df <- tryCatch(
      query_comorbidity_profile(schema, col_map, person_ids, "drug", 5L),
      error = function(e) NULL)
    if (!is.null(drug_df) && nrow(drug_df) > 0) {
      rows[["drug_hdr"]] <- data.frame(
        Characteristic = "Top 5 medications (% of cohort)", Value = "", stringsAsFactors = FALSE)
      for (i in seq_len(nrow(drug_df))) {
        rows[[paste0("drug_", i)]] <- data.frame(
          Characteristic = paste0("  ", drug_df$label[i]),
          Value = sprintf("%s (%.1f%%)",
                          format(drug_df$n_persons[i], big.mark=","), drug_df$pct[i]),
          stringsAsFactors = FALSE)
      }
    }
  }

  if (length(rows) == 0) return(NULL)
  do.call(rbind, rows)
}

# Multi-schema Table 1 - gathers raw person-level rows across every selected
# schema, then computes pooled summary statistics (and a per-schema N row so
# the reader can see how the pool is composed). Returns the same
# (Characteristic, Value) two-column data.frame as build_table1 so every
# downstream renderer works unchanged. Falls back to single-schema
# build_table1 when only one schema is supplied.
build_table1_multi <- function(schemas, col_maps_list, cohort_result) {
  schemas <- schemas[!is.na(schemas) & nzchar(schemas)]
  if (length(schemas) == 0 || is.null(cohort_result) || nrow(cohort_result) == 0)
    return(NULL)

  # Derive per-schema cohort slices. If cohort_result lacks source_schema,
  # assume everything came from the first schema.
  if (!"source_schema" %in% names(cohort_result)) {
    cohort_result$source_schema <- schemas[[1]]
  }
  cohort_by_schema <- split(cohort_result, cohort_result$source_schema)
  cohort_by_schema <- cohort_by_schema[intersect(names(cohort_by_schema), schemas)]
  if (length(cohort_by_schema) == 0) return(NULL)

  if (length(cohort_by_schema) == 1) {
    sch     <- names(cohort_by_schema)[[1]]
    col_map <- col_maps_list[[sch]] %||% list()
    sub     <- cohort_by_schema[[sch]]
    return(build_table1(sch, col_map, as_pid(sub$person_id), sub))
  }

  n_total <- nrow(cohort_result)
  rows    <- list()

  rows[["n"]] <- data.frame(
    Characteristic = "N",
    Value          = format(n_total, big.mark = ","),
    stringsAsFactors = FALSE)

  # Per-schema N breakdown
  rows[["n_hdr"]] <- data.frame(
    Characteristic = "Per-schema N", Value = "",
    stringsAsFactors = FALSE)
  for (sch in names(cohort_by_schema)) {
    n_s <- nrow(cohort_by_schema[[sch]])
    rows[[paste0("n_", sch)]] <- data.frame(
      Characteristic = paste0("  ", sch),
      Value = sprintf("%s (%.1f%%)", format(n_s, big.mark = ","),
                      100 * n_s / n_total),
      stringsAsFactors = FALSE)
  }

  # ── Age at index (pooled) ──────────────────────────────────────────────
  age_all <- do.call(c, lapply(names(cohort_by_schema), function(sch) {
    cm  <- col_maps_list[[sch]] %||% list()
    sub <- cohort_by_schema[[sch]]
    if (!"index_date" %in% names(sub)) return(numeric(0))
    existing <- tryCatch(tolower(get_tables(sch)), error = function(e) character(0))
    if (!"person" %in% existing) return(numeric(0))
    pid_col <- ac(cm, "person", "person_id")
    yob_col <- ac(cm, "person", "year_of_birth")
    tmp_vals <- paste(
      sprintf("(%.0f, '%s'::date)",
              as_pid(sub$person_id),
              as.character(as.Date(sub$index_date))),
      collapse = ", ")
    df <- tryCatch(db_query(sprintf(
      "WITH idx(person_id, index_date) AS (VALUES %s)
       SELECT EXTRACT(YEAR FROM i.index_date)::int - p.%s AS age
       FROM   %s p JOIN idx i ON i.person_id = p.%s
       WHERE  p.%s IS NOT NULL",
      tmp_vals, yob_col, fq(sch, "person"), pid_col, yob_col)),
      error = function(e) NULL)
    if (is.null(df) || nrow(df) == 0) return(numeric(0))
    as.numeric(df$age)
  }))
  age_all <- age_all[!is.na(age_all) & age_all >= 0 & age_all <= 120]

  if (length(age_all) > 0) {
    rows[["age_hdr"]] <- data.frame(
      Characteristic = "Age at index (pooled)", Value = "",
      stringsAsFactors = FALSE)
    rows[["age_mean"]] <- data.frame(
      Characteristic = "  Mean (SD)",
      Value = sprintf("%.1f (%.1f)", mean(age_all), sd(age_all)),
      stringsAsFactors = FALSE)
    rows[["age_med"]] <- data.frame(
      Characteristic = "  Median [IQR]",
      Value = sprintf("%.0f [%.0f-%.0f]",
                      median(age_all),
                      quantile(age_all, 0.25),
                      quantile(age_all, 0.75)),
      stringsAsFactors = FALSE)
    # Bands
    breaks <- c(-Inf, 18, 45, 65, 75, Inf)
    labels <- c("0-17", "18-44", "45-64", "65-74", "75+")
    age_grp <- cut(age_all, breaks = breaks, labels = labels, right = FALSE)
    for (lbl in labels) {
      n_g <- sum(age_grp == lbl, na.rm = TRUE)
      rows[[paste0("age_", lbl)]] <- data.frame(
        Characteristic = paste0("  ", lbl, " years"),
        Value = sprintf("%s (%.1f%%)",
                        format(n_g, big.mark = ","),
                        100 * n_g / length(age_all)),
        stringsAsFactors = FALSE)
    }
  }

  # ── Sex (pooled) ──────────────────────────────────────────────────────
  sex_all <- do.call(rbind, Filter(Negate(is.null), lapply(
    names(cohort_by_schema), function(sch) {
      cm  <- col_maps_list[[sch]] %||% list()
      sub <- cohort_by_schema[[sch]]
      existing <- tryCatch(tolower(get_tables(sch)), error = function(e) character(0))
      if (!"person" %in% existing) return(NULL)
      pid_col <- ac(cm, "person", "person_id")
      gcol    <- ac(cm, "person", "gender_concept_id")
      ids_sql <- pid_sql(sub$person_id)
      tryCatch(db_query(sprintf(
        "SELECT CASE %s WHEN 8507 THEN 'Male' WHEN 8532 THEN 'Female'
                ELSE 'Other/Unknown' END AS sex, COUNT(*) AS n
         FROM   %s WHERE %s IN (%s) GROUP BY 1",
        gcol, fq(sch, "person"), pid_col, ids_sql)),
        error = function(e) NULL)
    })))
  if (!is.null(sex_all) && nrow(sex_all) > 0) {
    sex_sum <- aggregate(n ~ sex, data = sex_all, FUN = sum)
    sex_sum <- sex_sum[order(-sex_sum$n), ]
    sex_tot <- sum(sex_sum$n)
    rows[["sex_hdr"]] <- data.frame(
      Characteristic = "Sex", Value = "", stringsAsFactors = FALSE)
    for (i in seq_len(nrow(sex_sum))) {
      rows[[paste0("sex_", i)]] <- data.frame(
        Characteristic = paste0("  ", sex_sum$sex[i]),
        Value = sprintf("%s (%.1f%%)",
                        format(sex_sum$n[i], big.mark = ","),
                        100 * sex_sum$n[i] / sex_tot),
        stringsAsFactors = FALSE)
    }
  }

  # ── Follow-up (pooled) ────────────────────────────────────────────────
  fu_all <- do.call(c, lapply(names(cohort_by_schema), function(sch) {
    cm  <- col_maps_list[[sch]] %||% list()
    sub <- cohort_by_schema[[sch]]
    df <- tryCatch(query_followup_dist(sch, cm, sub),
                   error = function(e) NULL)
    if (is.null(df) || nrow(df) == 0) return(numeric(0))
    as.numeric(df$days)
  }))
  fu_all <- fu_all[!is.na(fu_all) & fu_all >= 0]
  if (length(fu_all) > 0) {
    rows[["fu_hdr"]] <- data.frame(
      Characteristic = "Follow-up days (pooled)", Value = "",
      stringsAsFactors = FALSE)
    rows[["fu_med"]] <- data.frame(
      Characteristic = "  Median [IQR]",
      Value = sprintf("%.0f [%.0f-%.0f]",
                      median(fu_all),
                      quantile(fu_all, 0.25),
                      quantile(fu_all, 0.75)),
      stringsAsFactors = FALSE)
    rows[["fu_pct_yr"]] <- data.frame(
      Characteristic = "  ≥1 year follow-up",
      Value = sprintf("%s (%.1f%%)",
                      format(sum(fu_all >= 365), big.mark = ","),
                      100 * mean(fu_all >= 365)),
      stringsAsFactors = FALSE)
  }

  # ── CCI (pooled) ──────────────────────────────────────────────────────
  cci_all <- do.call(rbind, Filter(Negate(is.null), lapply(
    names(cohort_by_schema), function(sch) {
      cm   <- col_maps_list[[sch]] %||% list()
      sub  <- cohort_by_schema[[sch]]
      pids <- unique(as_pid(sub$person_id))
      tryCatch(compute_cci(sch, cm, pids),
               error = function(e) NULL)
    })))
  if (!is.null(cci_all) && nrow(cci_all) > 0) {
    sc <- cci_all$cci_score
    rows[["cci_hdr"]] <- data.frame(
      Characteristic = "Charlson CCI (pooled)", Value = "",
      stringsAsFactors = FALSE)
    rows[["cci_med"]] <- data.frame(
      Characteristic = "  Median [IQR]",
      Value = sprintf("%.0f [%.0f-%.0f]",
                      median(sc),
                      quantile(sc, 0.25),
                      quantile(sc, 0.75)),
      stringsAsFactors = FALSE)
    rows[["cci_0"]] <- data.frame(
      Characteristic = "  CCI 0",
      Value = sprintf("%s (%.1f%%)",
                      format(sum(sc == 0), big.mark = ","),
                      100 * mean(sc == 0)),
      stringsAsFactors = FALSE)
    rows[["cci_12"]] <- data.frame(
      Characteristic = "  CCI 1-2",
      Value = sprintf("%s (%.1f%%)",
                      format(sum(sc >= 1 & sc <= 2), big.mark = ","),
                      100 * mean(sc >= 1 & sc <= 2)),
      stringsAsFactors = FALSE)
    rows[["cci_3"]] <- data.frame(
      Characteristic = "  CCI ≥3",
      Value = sprintf("%s (%.1f%%)",
                      format(sum(sc >= 3), big.mark = ","),
                      100 * mean(sc >= 3)),
      stringsAsFactors = FALSE)
  }

  if (length(rows) == 0) return(NULL)
  do.call(rbind, rows)
}

# ── 5c5. COHORT DEFINITION SERIALISATION ──────────────────────────────────────
# Serialise/deserialise the criteria list to/from JSON for save/load.
# Also captures cohort-level options (prior_obs_days, min_followup_days,
# index_strategy) so a full definition can be round-tripped from a .json file.

serialise_cohort_def <- function(criteria, cohort_name = "my_cohort",
                                  index_strategy    = "first_qualifying",
                                  prior_obs_days    = NA_integer_,
                                  min_followup_days = NA_integer_) {
  # Preserve array shape on fields that are conceptually lists even when
  # length-1, so a one-concept criterion serialises as "concept_ids": [1177480]
  # rather than "concept_ids": 1177480. Bug 16 fix (v8.1).
  criteria_arr_safe <- lapply(criteria, function(c) {
    if (!is.null(c$concept_ids)) c$concept_ids <- I(as.integer(c$concept_ids))
    if (!is.null(c$gender_ids))  c$gender_ids  <- I(as.integer(c$gender_ids))
    c
  })
  def <- list(
    version           = "cohortbuilder_v6",
    cohort_name       = cohort_name,
    index_strategy    = index_strategy,
    prior_obs_days    = prior_obs_days,
    min_followup_days = min_followup_days,
    criteria          = criteria_arr_safe
  )
  jsonlite::toJSON(def, auto_unbox = TRUE, na = "null", pretty = TRUE)
}

deserialise_cohort_def <- function(json_text) {
  tryCatch({
    def <- jsonlite::fromJSON(json_text, simplifyVector = FALSE)
    # Restore integer types that JSON flattens to numeric
    crits <- lapply(def$criteria %||% list(), function(c) {
      c$concept_ids  <- as.integer(c$concept_ids  %||% integer(0))
      c$gender_ids   <- as.integer(c$gender_ids   %||% integer(0))
      c$occur_min    <- as.integer(c$occur_min    %||% 1L)
      c$occur_max    <- if (is.null(c$occur_max))    NA_integer_ else as.integer(c$occur_max)
      c$window_start <- if (is.null(c$window_start)) NA_integer_ else as.integer(c$window_start)
      c$window_end   <- if (is.null(c$window_end))   NA_integer_ else as.integer(c$window_end)
      c$washout_days <- if (is.null(c$washout_days)) NA_integer_ else as.integer(c$washout_days)
      c$age_min      <- if (is.null(c$age_min))      NA_integer_ else as.integer(c$age_min)
      c$age_max      <- if (is.null(c$age_max))      NA_integer_ else as.integer(c$age_max)
      c$value_min    <- if (is.null(c$value_min))    NA_real_    else as.numeric(c$value_min)
      c$value_max    <- if (is.null(c$value_max))    NA_real_    else as.numeric(c$value_max)
      c$use_descendants <- isTRUE(c$use_descendants)
      c$logic        <- c$logic %||% "AND"
      c
    })
    list(
      ok                = TRUE,
      criteria          = crits,
      cohort_name       = as.character(def$cohort_name       %||% "my_cohort"),
      index_strategy    = as.character(def$index_strategy    %||% "first_qualifying"),
      prior_obs_days    = if (is.null(def$prior_obs_days))    NA_integer_ else as.integer(def$prior_obs_days),
      min_followup_days = if (is.null(def$min_followup_days)) NA_integer_ else as.integer(def$min_followup_days)
    )
  }, error = function(e) list(ok = FALSE, error = conditionMessage(e)))
}

# ── 5c3. KAPLAN-MEIER / TIME-TO-EVENT QUERY ───────────────────────────────────
# For a set of cohort members (with index_date), and an outcome domain + concept
# set, compute time from index to first outcome occurrence (or censoring at end
# of observation period).
#
# Returns a data.frame suitable for survival::survfit():
#   person_id, time (days), status (1=event, 0=censored)
#
query_survival_data <- function(schema, col_map, cohort_result,
                                 outcome_domain, outcome_concept_ids,
                                 use_descendants = FALSE,
                                 outcome_mode = "recurrence") {
  if (is.null(cohort_result) || nrow(cohort_result) == 0) return(NULL)
  if (!outcome_domain %in% names(DOMAINS)) return(NULL)

  existing_tbls <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  dom     <- DOMAINS[[outcome_domain]]
  if (!tolower(dom$table) %in% existing_tbls) return(NULL)
  if (!"observation_period" %in% existing_tbls) return(NULL)

  pids    <- as_pid(cohort_result$person_id)
  ids_sql <- paste(pids, collapse = ",")
  pid_col <- ac(col_map, dom$table, dom$person_col)
  dat_col <- ac(col_map, dom$table, dom$date_col)
  cid_col <- ac(col_map, dom$table, dom$concept_col)

  # Concept filter with optional descendant expansion
  concept_filter <- if (length(outcome_concept_ids) > 0) {
    ids_c <- paste(as.integer(outcome_concept_ids), collapse = ",")
    if (isTRUE(use_descendants) && "concept_ancestor" %in% existing_tbls) {
      desc_col <- ac(col_map, "concept_ancestor", "descendant_concept_id")
      anc_col  <- ac(col_map, "concept_ancestor", "ancestor_concept_id")
      sprintf("AND %s IN (SELECT %s FROM %s WHERE %s IN (%s))",
              cid_col, desc_col, fq(schema, "concept_ancestor"), anc_col, ids_c)
    } else {
      sprintf("AND %s IN (%s)", cid_col, ids_c)
    }
  } else ""

  # First-occurrence (incident) mode: exclude persons who already had the
  # outcome before index (prevalent cases), so the curve measures new onset
  # among those with no prior history. Recurrence mode (default) keeps everyone
  # and measures time to the first occurrence at/after index. This prior-history
  # exclusion is the only difference; the outcome window is identical.
  prior_cte <- if (identical(outcome_mode, "first")) {
    sprintf(
      ",
     prior AS (
       SELECT t.%s AS person_id
       FROM   %s t
       JOIN   idx ON idx.person_id = t.%s
       WHERE  t.%s IN (%s) AND t.%s::date < idx.index_date
         %s
       GROUP  BY 1
     )",
      pid_col, fq(schema, dom$table), pid_col,
      pid_col, ids_sql, dat_col, concept_filter)
  } else ""
  prior_filter <- if (identical(outcome_mode, "first"))
    "WHERE i.person_id NOT IN (SELECT person_id FROM prior)" else ""

  # Build VALUES CTE for index dates
  tmp_vals <- paste(
    sprintf("(%.0f, '%s'::date)", pids, as.character(as.Date(cohort_result$index_date))),
    collapse = ", ")

  op_pid <- ac(col_map, "observation_period", "person_id")
  op_end <- ac(col_map, "observation_period", "observation_period_end_date")

  sql <- sprintf(
    "WITH idx(person_id, index_date) AS (VALUES %s),
     outcomes AS (
       SELECT t.%s AS person_id,
              MIN(t.%s::date) AS event_date
       FROM   %s t
       JOIN   idx ON idx.person_id = t.%s
       WHERE  t.%s IN (%s)
         AND  t.%s::date >= idx.index_date
         %s
       GROUP  BY 1
     ),
     censoring AS (
       SELECT op.%s AS person_id,
              MAX(op.%s::date) AS censor_date
       FROM   %s op
       JOIN   idx ON idx.person_id = op.%s
       WHERE  op.%s IN (%s) AND op.%s::date >= idx.index_date
       GROUP  BY 1
     )%s
     SELECT i.person_id,
            COALESCE(o.event_date, c.censor_date, i.index_date) AS end_date,
            i.index_date,
            CASE WHEN o.person_id IS NOT NULL THEN 1 ELSE 0 END AS status
     FROM   idx i
     LEFT JOIN outcomes  o ON o.person_id = i.person_id
     LEFT JOIN censoring c ON c.person_id = i.person_id
     %s",
    tmp_vals,
    pid_col, dat_col, fq(schema, dom$table), pid_col,
    pid_col, ids_sql, dat_col, concept_filter,
    op_pid, op_end, fq(schema, "observation_period"), op_pid,
    op_pid, ids_sql, op_end,
    prior_cte, prior_filter)

  r <- tryCatch(db_query(sql), error = function(e) {
    message("[km] query error: ", e$message); NULL })
  if (is.null(r) || nrow(r) == 0) return(NULL)

  # RPostgreSQL may return column names in stored case - normalise defensively
  names(r) <- tolower(names(r))

  r$time   <- as.numeric(as.Date(r$end_date) - as.Date(r$index_date))
  r$time   <- pmax(r$time, 0)
  r$status <- as.integer(r$status)
  r[, c("person_id", "time", "status")]
}

# Person_ids (from cohort_result) with >=1 occurrence of the outcome strictly
# before their index date. Used to stratify KM curves into naive (no prior
# history -> first incidence) and experienced (prior history -> recurrence)
# arms. Same concept/descendant logic as query_survival_data's prior CTE.
query_prior_history_pids <- function(schema, col_map, cohort_result,
                                     outcome_domain, outcome_concept_ids,
                                     use_descendants = FALSE) {
  if (is.null(cohort_result) || nrow(cohort_result) == 0) return(character(0))
  if (!outcome_domain %in% names(DOMAINS)) return(character(0))
  existing_tbls <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  dom <- DOMAINS[[outcome_domain]]
  if (!tolower(dom$table) %in% existing_tbls) return(character(0))

  pids    <- as_pid(cohort_result$person_id)
  ids_sql <- paste(pids, collapse = ",")
  pid_col <- ac(col_map, dom$table, dom$person_col)
  dat_col <- ac(col_map, dom$table, dom$date_col)
  cid_col <- ac(col_map, dom$table, dom$concept_col)

  concept_filter <- if (length(outcome_concept_ids) > 0) {
    ids_c <- paste(as.integer(outcome_concept_ids), collapse = ",")
    if (isTRUE(use_descendants) && "concept_ancestor" %in% existing_tbls) {
      desc_col <- ac(col_map, "concept_ancestor", "descendant_concept_id")
      anc_col  <- ac(col_map, "concept_ancestor", "ancestor_concept_id")
      sprintf("AND %s IN (SELECT %s FROM %s WHERE %s IN (%s))",
              cid_col, desc_col, fq(schema, "concept_ancestor"), anc_col, ids_c)
    } else sprintf("AND %s IN (%s)", cid_col, ids_c)
  } else ""

  tmp_vals <- paste(
    sprintf("(%.0f, '%s'::date)", pids, as.character(as.Date(cohort_result$index_date))),
    collapse = ", ")

  sql <- sprintf(
    "WITH idx(person_id, index_date) AS (VALUES %s)
     SELECT DISTINCT t.%s AS person_id
     FROM   %s t
     JOIN   idx ON idx.person_id = t.%s
     WHERE  t.%s IN (%s) AND t.%s::date < idx.index_date
       %s",
    tmp_vals, pid_col, fq(schema, dom$table), pid_col,
    pid_col, ids_sql, dat_col, concept_filter)

  r <- tryCatch(db_query(sql), error = function(e) {
    message("[km prior] ", e$message); NULL })
  if (is.null(r) || nrow(r) == 0) return(character(0))
  names(r) <- tolower(names(r))
  as.character(as_pid(r$person_id))
}

# For every concept in the domain, how many cohort patients have >=1 occurrence
# at/after their index date (recurrence semantics). Powers the picker's "Cohort
# events" column so users can see which outcomes yield a usable curve BEFORE
# selecting. One GROUP BY query per schema. Returns data.frame(concept_id, n).
count_cohort_concept_events <- function(schema, col_map, cohort_result,
                                        outcome_domain) {
  if (is.null(cohort_result) || nrow(cohort_result) == 0) return(NULL)
  if (!outcome_domain %in% names(DOMAINS)) return(NULL)
  existing <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  dom <- DOMAINS[[outcome_domain]]
  if (!tolower(dom$table) %in% existing) return(NULL)

  pids    <- as_pid(cohort_result$person_id)
  ids_sql <- paste(pids, collapse = ",")
  pid_col <- ac(col_map, dom$table, dom$person_col)
  dat_col <- ac(col_map, dom$table, dom$date_col)
  cid_col <- ac(col_map, dom$table, dom$concept_col)
  tmp_vals <- paste(
    sprintf("(%.0f, '%s'::date)", pids, as.character(as.Date(cohort_result$index_date))),
    collapse = ", ")

  sql <- sprintf(
    "WITH idx(person_id, index_date) AS (VALUES %s)
     SELECT t.%s AS concept_id, COUNT(DISTINCT t.%s) AS n
     FROM   %s t
     JOIN   idx ON idx.person_id = t.%s
     WHERE  t.%s IN (%s) AND t.%s::date >= idx.index_date
     GROUP  BY t.%s",
    tmp_vals, cid_col, pid_col, fq(schema, dom$table), pid_col,
    pid_col, ids_sql, dat_col, cid_col)

  r <- tryCatch(db_query(sql), error = function(e) {
    message("[km picker events] ", e$message); NULL })
  if (is.null(r) || nrow(r) == 0) return(NULL)
  names(r) <- tolower(names(r))
  data.frame(concept_id = as.character(r$concept_id),
             n = as.integer(r$n), stringsAsFactors = FALSE)
}

# ── 5c3b. COMPETING RISKS - CUMULATIVE INCIDENCE FUNCTION ────────────────────
# Returns a data.frame: person_id, time, status
#   status 0 = censored, 1 = primary event, 2 = death (competing event)
# If death table is absent, falls back to standard KM censoring (status 0/1).
query_cif_data <- function(schema, col_map, cohort_result,
                            outcome_domain, outcome_concept_ids,
                            use_descendants = FALSE) {
  if (is.null(cohort_result) || nrow(cohort_result) == 0) return(NULL)
  surv <- query_survival_data(schema, col_map, cohort_result,
                               outcome_domain, outcome_concept_ids,
                               use_descendants)
  if (is.null(surv)) return(NULL)

  existing_tbls <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  if (!"death" %in% existing_tbls) {
    surv$status <- as.integer(surv$status)
    return(surv)   # no death table - treat as plain survival
  }

  pids    <- as_pid(cohort_result$person_id)
  ids_sql <- paste(pids, collapse = ",")
  tmp_vals <- paste(
    sprintf("(%.0f, '%s'::date)", pids,
            as.character(as.Date(cohort_result$index_date))),
    collapse = ", ")
  dp  <- ac(col_map, "death", "person_id")
  dd  <- ac(col_map, "death", "death_date")

  death_sql <- sprintf(
    "WITH idx(person_id, index_date) AS (VALUES %s)
     SELECT i.person_id,
            (d.%s::date - i.index_date)::int AS death_days
     FROM   idx i
     JOIN   %s d ON d.%s = i.person_id
     WHERE  d.%s IN (%s) AND d.%s::date > i.index_date",
    tmp_vals, dd, fq(schema, "death"), dp,
    dp, ids_sql, dd)
  death_r <- tryCatch(db_query(death_sql), error = function(e) NULL)
  if (is.null(death_r) || nrow(death_r) == 0) {
    surv$status <- as.integer(surv$status); return(surv)
  }
  names(death_r) <- tolower(names(death_r))
  death_map <- setNames(as.integer(death_r$death_days),
                        as_pid(death_r$person_id))

  surv$status <- as.integer(surv$status)
  for (i in seq_len(nrow(surv))) {
    pid <- surv$person_id[i]
    dt  <- death_map[as.character(pid)]
    if (!is.na(dt)) {
      if (surv$status[i] == 0L) {
        # No primary event - death is the competing event
        surv$time[i]   <- min(surv$time[i], dt)
        surv$status[i] <- if (dt <= surv$time[i]) 2L else 0L
      } else if (dt < surv$time[i]) {
        # Death before primary event - competing event wins
        surv$time[i]   <- dt
        surv$status[i] <- 2L
      }
    }
  }
  surv
}

# ── 5c4. INCIDENCE RATE ────────────────────────────────────────────────────────
# Computes crude incidence rate: events per 1000 person-years.
# Uses person-time at risk from observation_period after index date.
# If outcome concept IDs supplied, counts first event per person.
# Returns list: rate, n_events, person_years, ci_lower, ci_upper (Poisson 95% CI)

compute_incidence_rate <- function(schema, col_map, cohort_result,
                                    outcome_domain = NULL,
                                    outcome_concept_ids = integer(0),
                                    use_descendants = FALSE) {
  if (is.null(cohort_result) || nrow(cohort_result) == 0) return(NULL)
  existing_tbls <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  if (!"observation_period" %in% existing_tbls) return(NULL)

  pids    <- as_pid(cohort_result$person_id)
  ids_sql  <- paste(pids, collapse = ",")
  tmp_vals <- paste(
    sprintf("(%.0f, '%s'::date)", pids, as.character(as.Date(cohort_result$index_date))),
    collapse = ", ")

  op_pid <- ac(col_map, "observation_period", "person_id")
  op_end <- ac(col_map, "observation_period", "observation_period_end_date")

  # Person-time: days from index to end of last observation period.
  # PostgreSQL (date - date) returns integer days, not an interval, so
  # EXTRACT(EPOCH FROM ...) fails. Cast to numeric directly.
  pt_sql <- sprintf(
    "WITH idx(person_id, index_date) AS (VALUES %s)
     SELECT GREATEST(0, (MAX(op.%s::date) - i.index_date)::numeric) AS person_days
     FROM   %s op
     JOIN   idx i ON i.person_id = op.%s
     WHERE  op.%s IN (%s) AND op.%s::date >= i.index_date
     GROUP  BY i.person_id, i.index_date",
    tmp_vals, op_end, fq(schema, "observation_period"), op_pid,
    op_pid, ids_sql, op_end)

  pt_r <- tryCatch(db_query(pt_sql), error = function(e) NULL)
  if (is.null(pt_r) || nrow(pt_r) == 0) return(NULL)
  person_years <- sum(as.numeric(pt_r$person_days), na.rm = TRUE) / 365.25

  # Event count. Bug 10 fix (v8.2): outcome_domain and outcome_concept_ids
  # are now passed by the run_incidence_btn observer. When supplied, count
  # actual outcome events. Honour use_descendants the same way KM does, so
  # the rate matches the KM event count exactly.
  n_events <- length(pids)  # legacy fallback: cohort entry = event
  if (!is.null(outcome_domain) && outcome_domain %in% names(DOMAINS) &&
      length(outcome_concept_ids) > 0) {
    dom     <- DOMAINS[[outcome_domain]]
    if (tolower(dom$table) %in% existing_tbls) {
      pid_col <- ac(col_map, dom$table, dom$person_col)
      dat_col <- ac(col_map, dom$table, dom$date_col)
      cid_col <- ac(col_map, dom$table, dom$concept_col)
      ids_c   <- paste(as.integer(outcome_concept_ids), collapse = ",")
      concept_clause <- if (isTRUE(use_descendants)) {
        sprintf("t.%s IN (SELECT %s FROM %s WHERE %s IN (%s))",
                cid_col,
                ac(col_map, "concept_ancestor", "descendant_concept_id"),
                fq(schema, "concept_ancestor"),
                ac(col_map, "concept_ancestor", "ancestor_concept_id"),
                ids_c)
      } else {
        sprintf("t.%s IN (%s)", cid_col, ids_c)
      }
      ev_sql  <- sprintf(
        "WITH idx(person_id, index_date) AS (VALUES %s)
         SELECT COUNT(DISTINCT t.%s) AS n
         FROM   %s t JOIN idx ON idx.person_id = t.%s
         WHERE  t.%s IN (%s) AND %s AND t.%s::date > idx.index_date",
        tmp_vals, pid_col, fq(schema, dom$table), pid_col,
        pid_col, ids_sql, concept_clause, dat_col)
      ev_r <- tryCatch(db_query(ev_sql), error = function(e) NULL)
      if (!is.null(ev_r)) n_events <- as.integer(ev_r$n[1])
    }
  }

  # Poisson 95% CI: lambda = n/T, CI via chi-squared approximation
  rate <- if (person_years > 0) 1000 * n_events / person_years else NA_real_
  ci_lo <- if (n_events > 0 && person_years > 0)
    1000 * qchisq(0.025, 2 * n_events)    / (2 * person_years) else 0
  ci_hi <- if (person_years > 0)
    1000 * qchisq(0.975, 2 * (n_events + 1)) / (2 * person_years) else NA_real_

  list(rate = rate, n_events = n_events,
       person_years = person_years, ci_lower = ci_lo, ci_upper = ci_hi)
}



# ── compute_evalue ─────────────────────────────────────────────────────────────
# VanderWeele & Ding (2017) E-value for a hazard ratio.
# Returns list: evalue (point), evalue_ci (for lower CI bound closer to null).
compute_evalue <- function(hr, ci_lo, ci_hi) {
  ev_single <- function(h) {
    if (is.na(h) || h <= 0) return(NA_real_)
    if (h < 1) h <- 1 / h          # mirror for protective HRs
    h + sqrt(h * (h - 1))
  }
  # CI bound closer to null (1.0)
  ci_null <- if (hr >= 1) ci_lo else ci_hi
  list(
    evalue    = ev_single(hr),
    evalue_ci = ev_single(ci_null)
  )
}

# ── build_matched_table1 ───────────────────────────────────────────────────────
# Produces a display-ready data.frame for the matched cohorts comparison table.
# Columns: Characteristic, Cohort_A, Cohort_B, SMD
build_matched_table1 <- function(feat_mat, matched, smd_tbl,
                                  label_a = "Cohort A", label_b = "Cohort B") {
  if (is.null(matched) || is.null(smd_tbl)) return(NULL)

  ma <- matched[matched$cohort == 1L, ]
  mb <- matched[matched$cohort == 0L, ]

  fmt_mean_sd <- function(x) {
    x <- as.numeric(x[!is.na(x)])
    if (length(x) == 0) return("-")
    sprintf("%.1f (\u00b1%.1f)", mean(x), sd(x))
  }
  fmt_pct <- function(x, n) {
    x <- as.numeric(x[!is.na(x)])
    if (length(x) == 0 || n == 0) return("-")
    sprintf("%s (%.1f%%)", format(sum(x > 0), big.mark=","), 100*mean(x > 0))
  }

  rows <- list()

  # N
  rows[["n"]] <- data.frame(
    Characteristic = "N (matched)",
    Cohort_A = format(nrow(ma), big.mark=","),
    Cohort_B = format(nrow(mb), big.mark=","),
    SMD = "",
    stringsAsFactors = FALSE)

  # Demographics
  if ("age_at_index" %in% names(ma)) {
    rows[["age"]] <- data.frame(
      Characteristic = "Age at index, mean (\u00b1SD)",
      Cohort_A = fmt_mean_sd(ma$age_at_index),
      Cohort_B = fmt_mean_sd(mb$age_at_index),
      SMD = sprintf("%.3f", compute_smd(
              as.numeric(ma$age_at_index), as.numeric(mb$age_at_index))),
      stringsAsFactors = FALSE)
  }
  if ("is_female" %in% names(ma)) {
    rows[["female"]] <- data.frame(
      Characteristic = "Female, n (%)",
      Cohort_A = fmt_pct(ma$is_female, nrow(ma)),
      Cohort_B = fmt_pct(mb$is_female, nrow(mb)),
      SMD = sprintf("%.3f", compute_smd(
              as.numeric(ma$is_female), as.numeric(mb$is_female))),
      stringsAsFactors = FALSE)
  }

  # Clinical covariates from smd_tbl (top 30 by pre-match SMD)
  clin <- head(smd_tbl[order(abs(smd_tbl$smd_before), decreasing=TRUE), ], 30)
  if (nrow(clin) > 0) {
    rows[["clin_hdr"]] <- data.frame(
      Characteristic = "Pre-index clinical covariates (top 30)",
      Cohort_A = "", Cohort_B = "", SMD = "", stringsAsFactors=FALSE)
    for (i in seq_len(nrow(clin))) {
      cv  <- clin$covariate[i]
      lbl <- sub("^(cond|drug)_", "", cv)
      type_pfx <- if (grepl("^cond_", cv)) "Dx" else "Rx"
      if (cv %in% names(ma)) {
        rows[[paste0("clin_",i)]] <- data.frame(
          Characteristic = paste0("  [", type_pfx, "] ", lbl),
          Cohort_A = fmt_pct(ma[[cv]], nrow(ma)),
          Cohort_B = fmt_pct(mb[[cv]], nrow(mb)),
          SMD = sprintf("%.3f", clin$smd_after[i]),
          stringsAsFactors=FALSE)
      }
    }
  }

  t1 <- do.call(rbind, rows)
  names(t1)[2] <- label_a
  names(t1)[3] <- label_b
  t1
}

# ══════════════════════════════════════════════════════════════════════════════
#  COMPARATIVE ANALYSIS - PROPENSITY SCORE MATCHING
# ══════════════════════════════════════════════════════════════════════════════

# ── extract_covariates_long ────────────────────────────────────────────────────
# For a cohort result (person_id + index_date), extracts binary covariates from
# condition_occurrence and drug_exposure in the N days before index date.
# Returns a data.frame: person_id (int), covariate (chr), value (1L)
# Also returns demographics: person_id, age_at_index (int), is_female (0/1)
#
# All SQL uses col_map-resolved identifiers so column case is handled correctly.
extract_covariates_long <- function(schema, col_map, cohort_result,
                                    lookback_days = 365L,
                                    include_conditions = TRUE,
                                    include_drugs      = TRUE) {
  if (is.null(cohort_result) || nrow(cohort_result) == 0) return(list(long = NULL, demo = NULL))
  existing <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))

  pids    <- as_pid(cohort_result$person_id)
  ids_sql <- paste(pids, collapse = ",")
  lb      <- as.integer(lookback_days)

  # Values CTE - person_id + index_date
  tmp_vals <- paste(
    sprintf("(%.0f, '%s'::date)", pids, as.character(as.Date(cohort_result$index_date))),
    collapse = ", ")

  long_rows <- list()

  # ── Conditions ─────────────────────────────────────────────────────────────
  if (include_conditions && "condition_occurrence" %in% existing) {
    pid_c  <- ac(col_map, "condition_occurrence", "person_id")
    cid_c  <- ac(col_map, "condition_occurrence", "condition_concept_id")
    dat_c  <- ac(col_map, "condition_occurrence", "condition_start_date")
    sql <- sprintf(
      "WITH idx(person_id, index_date) AS (VALUES %s)
       SELECT t.%s AS person_id,
              'cond_' || t.%s::text AS covariate,
              1 AS value
       FROM   %s t
       JOIN   idx i ON i.person_id = t.%s
       WHERE  t.%s IN (%s)
         AND  t.%s != 0
         AND  t.%s::date >= i.index_date - %d
         AND  t.%s::date <  i.index_date",
      tmp_vals,
      pid_c, cid_c, fq(schema, "condition_occurrence"), pid_c,
      pid_c, ids_sql,
      cid_c,
      dat_c, lb, dat_c)
    r <- tryCatch(db_query(sql), error = function(e) { message("[compare] cond error: ", e$message); NULL })
    if (!is.null(r) && nrow(r) > 0) long_rows[["cond"]] <- r
  }

  # ── Drugs ──────────────────────────────────────────────────────────────────
  if (include_drugs && "drug_exposure" %in% existing) {
    pid_d  <- ac(col_map, "drug_exposure", "person_id")
    cid_d  <- ac(col_map, "drug_exposure", "drug_concept_id")
    dat_d  <- ac(col_map, "drug_exposure", "drug_exposure_start_date")
    sql <- sprintf(
      "WITH idx(person_id, index_date) AS (VALUES %s)
       SELECT t.%s AS person_id,
              'drug_' || t.%s::text AS covariate,
              1 AS value
       FROM   %s t
       JOIN   idx i ON i.person_id = t.%s
       WHERE  t.%s IN (%s)
         AND  t.%s != 0
         AND  t.%s::date >= i.index_date - %d
         AND  t.%s::date <  i.index_date",
      tmp_vals,
      pid_d, cid_d, fq(schema, "drug_exposure"), pid_d,
      pid_d, ids_sql,
      cid_d,
      dat_d, lb, dat_d)
    r <- tryCatch(db_query(sql), error = function(e) { message("[compare] drug error: ", e$message); NULL })
    if (!is.null(r) && nrow(r) > 0) long_rows[["drug"]] <- r
  }

  long_df <- if (length(long_rows) > 0)
    do.call(rbind, long_rows)
  else
    data.frame(person_id = integer(0), covariate = character(0), value = integer(0),
               stringsAsFactors = FALSE)

  # ── Demographics ───────────────────────────────────────────────────────────
  demo_df <- NULL
  if ("person" %in% existing) {
    pid_p   <- ac(col_map, "person", "person_id")
    yob_p   <- ac(col_map, "person", "year_of_birth")
    gen_p   <- ac(col_map, "person", "gender_concept_id")
    sql_dem <- sprintf(
      "WITH idx(person_id, index_date) AS (VALUES %s)
       SELECT p.%s AS person_id,
              EXTRACT(YEAR FROM i.index_date)::int - p.%s AS age_at_index,
              CASE WHEN p.%s = 8532 THEN 1 ELSE 0 END AS is_female
       FROM   %s p
       JOIN   idx i ON i.person_id = p.%s
       WHERE  p.%s IN (%s)",
      tmp_vals,
      pid_p, yob_p, gen_p,
      fq(schema, "person"), pid_p,
      pid_p, ids_sql)
    demo_df <- tryCatch(db_query(sql_dem), error = function(e) NULL)
    if (!is.null(demo_df) && nrow(demo_df) > 0) {
      # lower-case the returned column names defensively
      names(demo_df) <- tolower(names(demo_df))
    }
  }

  list(long = long_df, demo = demo_df)
}

# ── build_feature_matrix ───────────────────────────────────────────────────────
# Given long-format covariate data for two cohorts (plus demographics), pivots
# to a wide binary matrix limited to the top_n most prevalent concepts.
# Returns data.frame with columns: person_id, cohort (0/1), age_at_index,
#   is_female, then one column per concept (binary 0/1).
build_feature_matrix <- function(long_a, demo_a,
                                  long_b, demo_b,
                                  top_n = 50L) {
  top_n <- as.integer(top_n)

  # Combine and find top N most prevalent covariates across both cohorts
  long_all <- rbind(
    if (!is.null(long_a) && nrow(long_a) > 0) long_a else data.frame(person_id=integer(), covariate=character(), value=integer()),
    if (!is.null(long_b) && nrow(long_b) > 0) long_b else data.frame(person_id=integer(), covariate=character(), value=integer())
  )

  if (nrow(long_all) == 0) {
    # No clinical covariates - demographics only
    top_covs <- character(0)
  } else {
    cov_prev <- sort(table(long_all$covariate), decreasing = TRUE)
    top_covs <- names(cov_prev)[seq_len(min(top_n, length(cov_prev)))]
    long_all <- long_all[long_all$covariate %in% top_covs, ]
  }

  pivot_wide <- function(long_df, pids) {
    mat <- matrix(0L, nrow = length(pids), ncol = length(top_covs),
                  dimnames = list(NULL, top_covs))
    if (!is.null(long_df) && nrow(long_df) > 0) {
      long_df <- long_df[long_df$covariate %in% top_covs, ]
      pid_idx <- match(long_df$person_id, pids)
      cov_idx <- match(long_df$covariate, top_covs)
      ok <- !is.na(pid_idx) & !is.na(cov_idx)
      mat[cbind(pid_idx[ok], cov_idx[ok])] <- 1L
    }
    as.data.frame(mat, stringsAsFactors = FALSE)
  }

  make_cohort_df <- function(long_df, demo_df, cohort_label) {
    pids <- unique(if (!is.null(long_df) && nrow(long_df) > 0)
      as_pid(long_df$person_id)
    else if (!is.null(demo_df) && nrow(demo_df) > 0)
      as_pid(demo_df$person_id)
    else integer(0))
    if (!is.null(demo_df) && nrow(demo_df) > 0)
      pids <- union(pids, as_pid(demo_df$person_id))
    if (length(pids) == 0) return(NULL)

    wide <- pivot_wide(long_df, pids)
    df   <- data.frame(person_id = pids, cohort = cohort_label, stringsAsFactors = FALSE)

    if (!is.null(demo_df) && nrow(demo_df) > 0) {
      names(demo_df) <- tolower(names(demo_df))
      dm <- demo_df[match(pids, demo_df$person_id), c("age_at_index","is_female"), drop=FALSE]
    } else {
      dm <- data.frame(age_at_index = NA_real_, is_female = NA_real_,
                       row.names = NULL)[rep(1, length(pids)),]
    }
    cbind(df, dm, wide)
  }

  df_a <- make_cohort_df(long_a, demo_a, 1L)
  df_b <- make_cohort_df(long_b, demo_b, 0L)

  if (is.null(df_a) || is.null(df_b)) return(NULL)
  rbind(df_a, df_b)
}

# ── greedy_ps_match ────────────────────────────────────────────────────────────
# Greedy 1:1 nearest-neighbour PS matching without replacement.
# caliper_sd: max allowed PS distance in SD units of PS distribution.
# Returns a data.frame with matched_id column linking A to B records.
greedy_ps_match <- function(feat_mat, caliper_sd = 0.2) {
  idx <- feat_mat[feat_mat$cohort == 1L, ]
  cmp <- feat_mat[feat_mat$cohort == 0L, ]
  if (nrow(idx) == 0 || nrow(cmp) == 0) return(NULL)

  caliper <- caliper_sd * sd(feat_mat$ps, na.rm = TRUE)

  idx <- idx[order(idx$ps), ]  # process in PS order to reduce bias
  avail <- seq_len(nrow(cmp))
  match_idx  <- rep(NA_integer_, nrow(idx))
  match_cmp  <- rep(NA_integer_, nrow(idx))

  for (i in seq_len(nrow(idx))) {
    if (length(avail) == 0) break
    dists <- abs(idx$ps[i] - cmp$ps[avail])
    best  <- which.min(dists)
    if (dists[best] <= caliper) {
      match_idx[i] <- i
      match_cmp[i] <- avail[best]
      avail <- avail[-best]
    }
  }

  keep_i <- which(!is.na(match_idx))
  keep_c <- match_cmp[keep_i]

  matched <- rbind(idx[keep_i, ], cmp[keep_c, ])
  matched$match_group <- c(seq_along(keep_i), seq_along(keep_i))
  matched
}

# ── compute_smd ───────────────────────────────────────────────────────────────
# Standardised mean difference for a single covariate between two groups.
# Uses pooled SD for continuous; Cohen's h approximation for binary.
compute_smd <- function(x, y) {
  x <- x[!is.na(x)]; y <- y[!is.na(y)]
  if (length(x) < 2 || length(y) < 2) return(NA_real_)
  m1 <- mean(x); m2 <- mean(y)
  # Detect binary (all 0/1)
  is_bin <- all(x %in% c(0,1)) && all(y %in% c(0,1))
  if (is_bin) {
    p1 <- m1; p2 <- m2
    denom <- sqrt((p1*(1-p1) + p2*(1-p2)) / 2)
    if (denom < 1e-9) return(0)
    return((p1 - p2) / denom)
  }
  s1 <- var(x); s2 <- var(y)
  denom <- sqrt((s1 + s2) / 2)
  if (denom < 1e-9) return(0)
  (m1 - m2) / denom
}

# ── compute_smd_table ─────────────────────────────────────────────────────────
# Produces a data.frame with covariate, smd_before, smd_after, prev_a, prev_b
# for all non-id, non-cohort columns in the feature matrix.
compute_smd_table <- function(full_mat, matched_mat) {
  skip_cols <- c("person_id", "cohort", "ps", "match_group")
  covs <- setdiff(names(full_mat), skip_cols)
  if (length(covs) == 0) return(NULL)

  fa <- full_mat[full_mat$cohort == 1L, covs, drop=FALSE]
  fb <- full_mat[full_mat$cohort == 0L, covs, drop=FALSE]
  ma <- matched_mat[matched_mat$cohort == 1L, covs, drop=FALSE]
  mb <- matched_mat[matched_mat$cohort == 0L, covs, drop=FALSE]

  rows <- lapply(covs, function(cv) {
    data.frame(
      covariate  = cv,
      smd_before = compute_smd(fa[[cv]], fb[[cv]]),
      smd_after  = compute_smd(ma[[cv]], mb[[cv]]),
      prev_a     = mean(fa[[cv]], na.rm=TRUE),
      prev_b     = mean(fb[[cv]], na.rm=TRUE),
      stringsAsFactors = FALSE
    )
  })
  tbl <- do.call(rbind, rows)
  tbl[order(abs(tbl$smd_before), decreasing=TRUE), ]
}

# ── fit_ps_model ──────────────────────────────────────────────────────────────
# Fits logistic regression of cohort ~ covariates.
# Handles near-zero variance columns and perfect separation gracefully.
fit_ps_model <- function(feat_mat) {
  skip <- c("person_id", "ps", "match_group")
  pred_cols <- setdiff(names(feat_mat), c(skip, "cohort"))

  # Drop zero-variance columns
  nzv <- vapply(pred_cols, function(cv) {
    v <- feat_mat[[cv]]
    !all(is.na(v)) && var(v, na.rm=TRUE) > 0
  }, logical(1))
  pred_cols <- pred_cols[nzv]

  if (length(pred_cols) == 0) {
    # No usable predictors - random PS
    message("[compare] No variance in covariates - using random PS")
    feat_mat$ps <- runif(nrow(feat_mat))
    return(list(mat = feat_mat, model = NULL, n_covs = 0L))
  }

  formula_str <- paste("cohort ~", paste(sprintf("`%s`", pred_cols), collapse=" + "))
  fit <- tryCatch(
    glm(as.formula(formula_str), data=feat_mat, family=binomial()),
    warning = function(w) {
      suppressWarnings(glm(as.formula(formula_str), data=feat_mat, family=binomial()))
    },
    error = function(e) { message("[compare] glm error: ", e$message); NULL })

  if (is.null(fit)) {
    feat_mat$ps <- runif(nrow(feat_mat))
    return(list(mat=feat_mat, model=NULL, n_covs=length(pred_cols)))
  }

  feat_mat$ps <- as.numeric(predict(fit, type="response"))
  list(mat=feat_mat, model=fit, n_covs=length(pred_cols))
}

# ── query_survival_for_compare ────────────────────────────────────────────────
# Thin wrapper around query_survival_data for a named cohort subset.
# Returns long data.frame with time, status, cohort_label columns.
query_survival_for_compare <- function(schema, col_map, cohort_subset,
                                        outcome_domain, outcome_concept_ids,
                                        use_descendants = FALSE,
                                        cohort_label = "") {
  if (is.null(cohort_subset) || nrow(cohort_subset) == 0) return(NULL)
  surv <- tryCatch(
    query_survival_data(schema, col_map, cohort_subset,
                        outcome_domain, outcome_concept_ids, use_descendants),
    error = function(e) NULL)
  if (is.null(surv)) return(NULL)
  surv$cohort_label <- cohort_label
  surv
}

# ── 5d. PLAIN-ENGLISH DESCRIPTION ─────────────────────────────────────────────
plain_english <- function(criteria, concept_names = list()) {
  inc <- Filter(function(c) c$type == "inclusion", criteria)
  exc <- Filter(function(c) c$type == "exclusion", criteria)
  if (length(inc) == 0) return(NULL)

  fmt_concepts <- function(ids) {
    if (length(ids) == 0) return(NULL)
    nms <- vapply(ids, function(i) {
      concept_names[[as.character(i)]] %||% as.character(i)
    }, character(1))
    if (length(nms) == 1) nms
    else paste0(paste(nms[-length(nms)], collapse = ", "), " or ", nms[length(nms)])
  }

  parts <- character(0)

  for (i in seq_along(inc)) {
    cr  <- inc[[i]]
    dom <- DOMAINS[[cr$domain]]
    cstr <- fmt_concepts(cr$concept_ids)
    label <- if (!is.null(cstr)) cstr else dom$label

    # time window
    ws <- cr$window_start; we <- cr$window_end
    win <- if (!is.na(ws %||% NA) && !is.na(we %||% NA)) {
      if (ws < 0 && we == 0)       sprintf("in the %d days before index", abs(ws))
      else if (ws == 0 && we > 0)  sprintf("in the %d days after index", we)
      else                         sprintf("%d to %d days relative to index", ws, we)
    } else if (!is.na(ws %||% NA)) sprintf("from %d days relative to index", ws)
    else if (!is.na(we %||% NA))   sprintf("up to %d days relative to index", we)
    else NULL

    # occurrences
    occ <- if (!is.na(cr$occur_min %||% NA) && (cr$occur_min %||% 1L) > 1L)
      sprintf("at least %d times", cr$occur_min) else NULL

    # age
    am <- cr$age_min; ax <- cr$age_max
    age <- if (!is.na(am %||% NA) && !is.na(ax %||% NA)) sprintf("aged %d-%d", am, ax)
    else if (!is.na(am %||% NA))  sprintf("aged ≥%d", am)
    else if (!is.na(ax %||% NA))  sprintf("aged ≤%d", ax)
    else NULL

    qualifiers <- paste(Filter(Negate(is.null), list(occ, win, age)), collapse = ", ")

    if (i == 1) {
      parts <- c(parts, paste0("Persons with a recorded ", label,
                               if (nzchar(qualifiers)) paste0(" (", qualifiers, ")") else "",
                               " - this is the index event"))
    } else {
      parts <- c(parts, paste0("who also have ", label,
                               if (nzchar(qualifiers)) paste0(" (", qualifiers, ")") else ""))
    }
  }

  for (cr in exc) {
    dom  <- DOMAINS[[cr$domain]]
    cstr <- fmt_concepts(cr$concept_ids)
    label <- if (!is.null(cstr)) cstr else dom$label
    parts <- c(parts, paste0("excluding anyone with a recorded ", label))
  }

  paste(parts, collapse = ", ")
}

# ── 5e. TREATMENT PATHWAY QUERY ───────────────────────────────────────────────
# For each cohort member, finds all treatments (drug/procedure) occurring after
# index date within followup_days. Returns per-person first treatment event and
# aggregate counts per concept for the top-treatments chart.
query_trt_data <- function(schema, col_map, cohort_result,
                            domain_key     = "drug",
                            concept_ids    = integer(0),
                            followup_days  = 365L) {
  if (is.null(cohort_result) || nrow(cohort_result) == 0) return(NULL)
  dom <- DOMAINS[[domain_key]]
  if (is.null(dom)) return(NULL)
  existing <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  if (!tolower(dom$table) %in% existing) return(NULL)

  pids    <- as_pid(cohort_result$person_id)
  ids_sql  <- paste(pids, collapse = ",")
  tmp_vals <- paste(
    sprintf("(%.0f, '%s'::date)", pids, as.character(as.Date(cohort_result$index_date))),
    collapse = ", ")

  pid_col <- ac(col_map, dom$table, dom$person_col)
  dat_col <- ac(col_map, dom$table, dom$date_col)
  cid_col <- ac(col_map, dom$table, dom$concept_col)

  concept_filter <- if (length(concept_ids) > 0)
    sprintf("AND t.%s IN (%s)", cid_col, paste(as.integer(concept_ids), collapse = ","))
  else ""

  # First treatment per person
  sql_first <- sprintf(
    "WITH idx(person_id, index_date) AS (VALUES %s)
     SELECT DISTINCT ON (t.%s)
            t.%s AS person_id,
            t.%s::date AS trt_date,
            t.%s AS concept_id,
            (t.%s::date - i.index_date)::int AS days_to_trt
     FROM   %s t
     JOIN   idx i ON i.person_id = t.%s
     WHERE  t.%s IN (%s)
       AND  t.%s::date > i.index_date
       AND  t.%s::date <= i.index_date + INTERVAL '%d days'
       AND  t.%s != 0
       %s
     ORDER  BY t.%s, t.%s::date",
    tmp_vals,
    pid_col, pid_col, dat_col, cid_col, dat_col,
    fq(schema, dom$table), pid_col,
    pid_col, ids_sql,
    dat_col, dat_col, followup_days,
    cid_col, concept_filter,
    pid_col, dat_col)

  first_df <- tryCatch({
    r <- db_query(sql_first)
    names(r) <- tolower(names(r))
    r
  }, error = function(e) { message("[trt first] ", e$message); NULL })

  # Concept prevalence: all treatments per concept
  sql_prev <- sprintf(
    "WITH idx(person_id, index_date) AS (VALUES %s)
     SELECT t.%s AS concept_id,
            COUNT(DISTINCT t.%s)::int AS n_persons
     FROM   %s t
     JOIN   idx i ON i.person_id = t.%s
     WHERE  t.%s IN (%s)
       AND  t.%s::date > i.index_date
       AND  t.%s::date <= i.index_date + INTERVAL '%d days'
       AND  t.%s != 0
       %s
     GROUP  BY t.%s
     ORDER  BY n_persons DESC",
    tmp_vals,
    cid_col, pid_col,
    fq(schema, dom$table), pid_col,
    pid_col, ids_sql,
    dat_col, dat_col, followup_days,
    cid_col, concept_filter,
    cid_col)

  prev_df <- tryCatch({
    r <- db_query(sql_prev)
    names(r) <- tolower(names(r))
    r
  }, error = function(e) NULL)

  # Resolve concept names from concept table if available
  concept_name_map <- list()
  if (!is.null(prev_df) && nrow(prev_df) > 0 && "concept" %in% existing) {
    cids_to_look <- as.numeric(prev_df$concept_id[!is.na(prev_df$concept_id) & suppressWarnings(as.numeric(prev_df$concept_id) != 0)])
    if (length(cids_to_look) > 0) {
      cid_c  <- ac(col_map, "concept", "concept_id")
      cname_c <- ac(col_map, "concept", "concept_name")
      sql_nm <- sprintf(
        "SELECT %s AS concept_id, %s AS concept_name FROM %s WHERE %s IN (%s)",
        cid_c, cname_c, fq(schema, "concept"), cid_c,
        paste(cids_to_look, collapse = ","))
      nm_df <- tryCatch({
        r <- db_query(sql_nm); names(r) <- tolower(names(r)); r
      }, error = function(e) NULL)
      if (!is.null(nm_df) && nrow(nm_df) > 0)
        concept_name_map <- setNames(as.list(nm_df$concept_name),
                                     sprintf("%.0f", as.numeric(nm_df$concept_id)))
    }
  }

  list(first_df = first_df, prev_df = prev_df,
       concept_name_map = concept_name_map,
       n_cohort = length(pids), followup_days = followup_days,
       domain_label = dom$label)
}

