# Date window presets - converts to (window_start, window_end) integer pair
DATE_WINDOW_PRESETS <- list(
  "any_before"   = list(label = "Any time before index",         ws = NA_integer_, we = -1L),
  "yr1_before"   = list(label = "Within 1 year before index",    ws = -365L,       we = 0L),
  "mo6_before"   = list(label = "Within 6 months before index",  ws = -183L,       we = 0L),
  "mo3_before"   = list(label = "Within 3 months before index",  ws = -91L,        we = 0L),
