                        sapply(DATE_WINDOW_PRESETS, `[[`, "label"))


# ── 7. SQL GENERATION ─────────────────────────────────────────────────────────
# Generates a cohort SQL from a list of criterion objects.
#
# Each criterion: list(
#   id             = unique string,
#   type           = "inclusion" | "exclusion",
#   domain         = one of names(DOMAINS),
#   concept_ids    = integer vector (empty = any),
#   use_descendants= logical - if TRUE, expand via concept_ancestor (default FALSE),
#   occur_min      = integer min occurrences (default 1),
#   occur_max      = integer or NA (no max),
#   window_start   = integer days before index (NA = no limit), negative = before
#   window_end     = integer days after  index (NA = no limit)
#   washout_days   = integer or NA - if set, person must have NO occurrence of this
#                    concept in the N days before index (incident cohort requirement)
#   value_min      = numeric (measurement only, NA = ignore)
#   value_max      = numeric (measurement only, NA = ignore)
#   age_min        = integer (demographics, NA = ignore)
#   age_max        = integer (demographics, NA = ignore)
#   gender_ids     = integer vector (8507=Male, 8532=Female, empty=any)
#   logic          = "AND" | "OR" - OR groups this criterion with the previous one
#                    via UNION; AND (default) requires both independently
# )
#
# Cohort-level observation period options (passed as separate args to build_cohort_sql):
#   prior_obs_days   = integer or NA - require N days of observation before index
#   min_followup_days= integer or NA - require N days of observation after index
#
# Index date strategy: earliest date from the FIRST inclusion criterion
# (the "qualifying event").  All subsequent criteria windows are relative to it.

build_cohort_sql <- function(schema, criteria, cohort_name = "my_cohort",
                              index_strategy    = "first_qualifying",
                              prior_obs_days    = NA_integer_,
                              min_followup_days = NA_integer_,
                              col_map           = list()) {

  ac2 <- function(tbl, col) ac(col_map, tbl, col)

  # Build a concept filter, optionally expanding descendants via concept_ancestor
  make_concept_filter <- function(tbl, concept_col, concept_ids, use_desc, existing_tbls) {
    if (length(concept_ids) == 0) return("")
    ids_sql <- paste(sprintf("%.0f", as.numeric(concept_ids)), collapse = ", ")
    if (isTRUE(use_desc) && "concept_ancestor" %in% existing_tbls) {
      desc_col <- ac2("concept_ancestor", "descendant_concept_id")
      anc_col  <- ac2("concept_ancestor", "ancestor_concept_id")
      sprintf("\n       AND %s IN (SELECT %s FROM %s WHERE %s IN (%s))",
              ac2(tbl, concept_col), desc_col,
              fq(schema, "concept_ancestor"), anc_col, ids_sql)
    } else {
      sprintf("\n       AND %s IN (%s)", ac2(tbl, concept_col), ids_sql)
    }
  }

  inc <- Filter(function(c) c$type == "inclusion", criteria)
  exc <- Filter(function(c) c$type == "exclusion", criteria)
  if (length(inc) == 0) return(NULL)

  existing_tbls <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))

  lines <- c(
    "-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550",
    paste0("-- Cohort: ", cohort_name),
    paste0("-- Schema: ", schema),
    paste0("-- Generated: ", format(Sys.time(), "%Y-%m-%d %H:%M:%S")),
    if (!is.na(prior_obs_days    %||% NA_integer_)) paste0("-- Prior observation required: ", prior_obs_days, " days"),
    if (!is.na(min_followup_days %||% NA_integer_)) paste0("-- Minimum follow-up required: ", min_followup_days, " days"),
    "-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550",
    ""
  )

  # ── Step 1: Index population ──────────────────────────────────────────────
  idx_c   <- inc[[1]]
  idx_dom <- DOMAINS[[idx_c$domain]]
  idx_agg <- if (identical(index_strategy, "last_qualifying")) "MAX" else "MIN"
  conc_f  <- make_concept_filter(idx_dom$table, idx_dom$concept_col,
                                  idx_c$concept_ids %||% integer(0),
                                  idx_c$use_descendants %||% FALSE, existing_tbls)

  lines <- c(lines,
    "WITH index_population AS (",
    "  -- Qualifying event per person (defines index date)",
    sprintf("  SELECT %s AS person_id,", ac2(idx_dom$table, idx_dom$person_col)),
    sprintf("         %s(%s::date) AS index_date", idx_agg, ac2(idx_dom$table, idx_dom$date_col)),
    sprintf("  FROM   %s", fq(schema, idx_dom$table)),
    sprintf("  WHERE  1=1 %s", conc_f),
    "  GROUP BY 1",
    "),", "")

  # ── Step 2: Inclusion CTEs (respecting OR logic via UNION) ────────────────
  inc_cte_names <- c()
  i <- 1L
  grp <- 0L
  while (i <= length(inc)) {
    # Collect all criteria sharing an OR group (criterion i plus any following
    # criteria that have logic = "OR")
    grp_crits <- list(inc[[i]])
    j <- i + 1L
    while (j <= length(inc) && identical(inc[[j]]$logic %||% "AND", "OR")) {
      grp_crits <- c(grp_crits, list(inc[[j]]))
      j <- j + 1L
    }
    grp <- grp + 1L
    cname <- sprintf("inc_%02d", grp)
    inc_cte_names <- c(inc_cte_names, cname)

    member_blocks <- lapply(seq_along(grp_crits), function(gi) {
      gc   <- grp_crits[[gi]]
      gdom <- DOMAINS[[gc$domain]]
      cf   <- make_concept_filter(gdom$table, gdom$concept_col,
                                   gc$concept_ids %||% integer(0),
                                   gc$use_descendants %||% FALSE, existing_tbls)
      val_f <- ""
      if (!is.na(gc$value_min %||% NA_real_))
        val_f <- paste0(val_f, sprintf("\n       AND %s >= %s",
                                       ac2(gdom$table, "value_as_number"), gc$value_min))
      if (!is.na(gc$value_max %||% NA_real_))
        val_f <- paste0(val_f, sprintf("\n       AND %s <= %s",
                                       ac2(gdom$table, "value_as_number"), gc$value_max))
      occ_min <- gc$occur_min %||% 1L
      occ_max <- gc$occur_max
      having  <- if (!is.na(occ_max %||% NA_integer_))
        sprintf("  HAVING COUNT(*) BETWEEN %d AND %d", occ_min, occ_max)
      else if (occ_min > 1L) sprintf("  HAVING COUNT(*) >= %d", occ_min)
      else ""

      # Date window (skip for first criterion of first group - it IS the index)
      win_join <- win_where <- ""
      if (!(grp == 1L && gi == 1L)) {
        ws <- gc$window_start %||% NA_integer_
        we <- gc$window_end   %||% NA_integer_
        win_join <- sprintf("\n  JOIN index_population ip ON t.%s = ip.person_id",
                            ac2(gdom$table, gdom$person_col))
        if (!is.na(ws) && !is.na(we))
          win_where <- sprintf(
            "\n       AND t.%s::date BETWEEN ip.index_date::date + INTERVAL '%d days' AND ip.index_date::date + INTERVAL '%d days'",
            ac2(gdom$table, gdom$date_col), ws, we)
        else if (!is.na(ws))
          win_where <- sprintf("\n       AND t.%s::date >= ip.index_date::date + INTERVAL '%d days'",
                               ac2(gdom$table, gdom$date_col), ws)
        else if (!is.na(we))
          win_where <- sprintf("\n       AND t.%s::date <= ip.index_date::date + INTERVAL '%d days'",
                               ac2(gdom$table, gdom$date_col), we)
      }
      c(sprintf("  SELECT t.%s AS person_id", ac2(gdom$table, gdom$person_col)),
        sprintf("  FROM   %s t%s", fq(schema, gdom$table), win_join),
        sprintf("  WHERE  1=1%s%s%s", cf, val_f, win_where),
        "  GROUP BY 1", having)
    })

    # Interleave UNION between OR members
    body <- member_blocks[[1]]
    for (mi in seq_along(member_blocks)[-1])
      body <- c(body, "  UNION", member_blocks[[mi]])

    dom_labels <- paste(sapply(grp_crits, function(gc) DOMAINS[[gc$domain]]$label), collapse = " OR ")
    lines <- c(lines,
      sprintf("%s AS (", cname),
      sprintf("  -- Inclusion %d: %s", grp,
              if (length(grp_crits) > 1) paste0("(", dom_labels, ")") else dom_labels),
      body, "),", "")
    i <- j
  }

  # ── Step 3: Exclusion CTEs ────────────────────────────────────────────────
  exc_cte_names <- c()
  for (ei in seq_along(exc)) {
    crit  <- exc[[ei]]
    dom   <- DOMAINS[[crit$domain]]
    cname <- sprintf("exc_%02d", ei)
    exc_cte_names <- c(exc_cte_names, cname)
    cf   <- make_concept_filter(dom$table, dom$concept_col,
                                 crit$concept_ids %||% integer(0),
                                 crit$use_descendants %||% FALSE, existing_tbls)
    ws <- crit$window_start %||% NA_integer_
    we <- crit$window_end   %||% NA_integer_
    win_join  <- sprintf("\n  JOIN index_population ip ON t.%s = ip.person_id",
                         ac2(dom$table, dom$person_col))
    win_where <- ""
    if (!is.na(ws) && !is.na(we))
      win_where <- sprintf(
        "\n       AND t.%s::date BETWEEN ip.index_date::date + INTERVAL '%d days' AND ip.index_date::date + INTERVAL '%d days'",
        ac2(dom$table, dom$date_col), ws, we)
    lines <- c(lines,
      sprintf("%s AS (", cname),
      sprintf("  -- Exclusion %d: %s", ei, dom$label),
      sprintf("  SELECT DISTINCT t.%s AS person_id", ac2(dom$table, dom$person_col)),
      sprintf("  FROM   %s t%s", fq(schema, dom$table), win_join),
      sprintf("  WHERE  1=1%s%s", cf, win_where),
      "),", "")
  }

  # ── Step 4: Washout CTEs ─────────────────────────────────────────────────
  # For each inclusion criterion with washout_days set, produce a CTE that
  # identifies persons with a PRIOR occurrence - then exclude them.
  washout_cte_names <- c()
  for (wi in seq_along(inc)) {
    crit <- inc[[wi]]
    wd   <- crit$washout_days %||% NA_integer_
    if (is.na(wd) || wd <= 0L) next
    dom   <- DOMAINS[[crit$domain]]
    cname <- sprintf("washout_%02d", wi)
    washout_cte_names <- c(washout_cte_names, cname)
    cf    <- make_concept_filter(dom$table, dom$concept_col,
                                  crit$concept_ids %||% integer(0),
                                  crit$use_descendants %||% FALSE, existing_tbls)
    lines <- c(lines,
      sprintf("%s AS (", cname),
      sprintf("  -- Washout %d: persons with %s in %d days before index (to be excluded)",
              wi, dom$label, wd),
      sprintf("  SELECT DISTINCT t.%s AS person_id", ac2(dom$table, dom$person_col)),
      sprintf("  FROM   %s t", fq(schema, dom$table)),
      sprintf("  JOIN   index_population ip ON t.%s = ip.person_id",
              ac2(dom$table, dom$person_col)),
      sprintf("  WHERE  1=1%s", cf),
      sprintf("    AND  t.%s::date <  ip.index_date::date", ac2(dom$table, dom$date_col)),
      sprintf("    AND  t.%s::date >= ip.index_date::date - INTERVAL '%d days'",
              ac2(dom$table, dom$date_col), wd),
      "),", "")
  }

  # ── Step 5: Demographics CTE ─────────────────────────────────────────────
  demo_criteria <- Filter(function(c) c$type == "inclusion" &&
    (!is.na(c$age_min %||% NA) || !is.na(c$age_max %||% NA) ||
     length(c$gender_ids %||% c()) > 0), criteria)
  has_demo <- length(demo_criteria) > 0
  if (has_demo) {
    demo_parts <- c()
    for (dc in demo_criteria) {
      if (!is.na(dc$age_min %||% NA_integer_))
        demo_parts <- c(demo_parts, sprintf("  AND (EXTRACT(YEAR FROM ip.index_date) - p.%s) >= %d",
                                             ac2("person", "year_of_birth"), dc$age_min))
      if (!is.na(dc$age_max %||% NA_integer_))
        demo_parts <- c(demo_parts, sprintf("  AND (EXTRACT(YEAR FROM ip.index_date) - p.%s) <= %d",
                                             ac2("person", "year_of_birth"), dc$age_max))
      if (length(dc$gender_ids %||% c()) > 0)
        demo_parts <- c(demo_parts, sprintf("  AND p.%s IN (%s)",
                                             ac2("person", "gender_concept_id"),
                                             paste(dc$gender_ids, collapse = ", ")))
    }
    lines <- c(lines,
      "demo_filter AS (", "  -- Demographics filter",
      sprintf("  SELECT p.%s AS person_id FROM %s p", ac2("person", "person_id"), fq(schema, "person")),
      sprintf("  JOIN index_population ip ON p.%s = ip.person_id", ac2("person", "person_id")),
      "  WHERE 1=1", demo_parts, "),", "")
  }

  # ── Step 6: Observation period CTE (with prior obs + follow-up options) ───
  prior_clause <- if (!is.na(prior_obs_days %||% NA_integer_) && prior_obs_days > 0L)
    sprintf("    AND op.%s::date <= ip.index_date::date - INTERVAL '%d days'",
            ac2("observation_period", "observation_period_start_date"), prior_obs_days)
  else
    sprintf("    AND op.%s::date <= ip.index_date::date",
            ac2("observation_period", "observation_period_start_date"))

  followup_clause <- if (!is.na(min_followup_days %||% NA_integer_) && min_followup_days > 0L)
    sprintf("    AND op.%s::date >= ip.index_date::date + INTERVAL '%d days'",
            ac2("observation_period", "observation_period_end_date"), min_followup_days)
  else
    sprintf("    AND op.%s::date >= ip.index_date::date",
            ac2("observation_period", "observation_period_end_date"))

  lines <- c(lines,
    "obs_period AS (",
    "  -- Persons with observation period covering index date",
    if (!is.na(prior_obs_days    %||% NA_integer_) && prior_obs_days    > 0L)
      sprintf("  --   Requires %d days prior observation", prior_obs_days),
    if (!is.na(min_followup_days %||% NA_integer_) && min_followup_days > 0L)
      sprintf("  --   Requires %d days follow-up after index", min_followup_days),
    sprintf("  SELECT DISTINCT op.%s AS person_id FROM %s op",
            ac2("observation_period", "person_id"), fq(schema, "observation_period")),
    sprintf("  JOIN index_population ip ON op.%s = ip.person_id",
            ac2("observation_period", "person_id")),
    prior_clause, followup_clause,
    "),", "")

  # ── Step 7: Final assembly ────────────────────────────────────────────────
  all_joins <- c()
  for (cn in inc_cte_names)
    all_joins <- c(all_joins, sprintf("  JOIN %-22s ON %s.person_id = ip.person_id", cn, cn))
  all_joins <- c(all_joins,
    sprintf("  JOIN %-22s ON obs_period.person_id = ip.person_id", "obs_period"))
  if (has_demo)
    all_joins <- c(all_joins,
      sprintf("  JOIN %-22s ON demo_filter.person_id = ip.person_id", "demo_filter"))
  for (cn in exc_cte_names)
    all_joins <- c(all_joins,
      sprintf("  LEFT JOIN %-20s ON %s.person_id = ip.person_id", cn, cn))
  for (cn in washout_cte_names)
    all_joins <- c(all_joins,
      sprintf("  LEFT JOIN %-20s ON %s.person_id = ip.person_id", cn, cn))

  where_parts <- c()
  for (cn in exc_cte_names)
    where_parts <- c(where_parts, sprintf("    AND %s.person_id IS NULL", cn))
  for (cn in washout_cte_names)
    where_parts <- c(where_parts, sprintf("    AND %s.person_id IS NULL", cn))
  where_clause <- if (length(where_parts) > 0)
    c("WHERE 1=1", where_parts) else character(0)

  lines <- c(lines,
    "cohort AS (",
    "  -- Final cohort: all inclusion criteria met, all exclusions removed",
    "  SELECT ip.person_id,",
    "         ip.index_date",
    "  FROM   index_population ip",
    all_joins,
    where_clause,
    ")", "",
    "-- \u2500\u2500 RESULT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500",
    "SELECT person_id,",
    "       index_date,",
    "       ROW_NUMBER() OVER (ORDER BY person_id) AS cohort_rank",
    "FROM   cohort",
    "ORDER  BY person_id;", "")

  paste(lines, collapse = "\n")
}


# ── 8. ATTRITION SQL ──────────────────────────────────────────────────────────
# Builds a series of queries to count how many persons pass each filter,
# generating a waterfall/attrition table.

build_attrition_sql <- function(schema, criteria, col_map = list()) {
  inc <- Filter(function(c) c$type == "inclusion", criteria)
  exc <- Filter(function(c) c$type == "exclusion", criteria)

  if (length(inc) == 0) return(NULL)

  steps <- list()
  # local resolver
  ac2 <- function(tbl, col) ac(col_map, tbl, col)

  # Concept-membership clause that honours use_descendants. Same pattern as
  # the main cohort SQL builder. Bug 1 fix (v8.2): previously this function
  # ignored use_descendants entirely, producing 0-person counts for any
  # criterion built against an ingredient or parent concept.
  concept_clause <- function(cr, dom) {
    if (length(cr$concept_ids) == 0) return("")
    col <- ac2(dom$table, dom$concept_col)
    ids <- paste(cr$concept_ids, collapse = ", ")
    if (isTRUE(cr$use_descendants)) {
      sprintf(" AND %s IN (SELECT %s FROM %s WHERE %s IN (%s))",
              col,
              ac2("concept_ancestor", "descendant_concept_id"),
              fq(schema, "concept_ancestor"),
              ac2("concept_ancestor", "ancestor_concept_id"),
              ids)
    } else {
      sprintf(" AND %s IN (%s)", col, ids)
    }
  }

  # Step 0: all persons in schema
  steps[[1]] <- list(
    label = "All persons in schema",
    sql   = sprintf("SELECT COUNT(DISTINCT %s) AS n FROM %s",
                    ac2("person", "person_id"), fq(schema, "person"))
  )

  # Step 1: observation period
  steps[[2]] <- list(
    label = "Persons with observation period",
    sql   = sprintf("SELECT COUNT(DISTINCT %s) AS n FROM %s",
                    ac2("observation_period", "person_id"), fq(schema, "observation_period"))
  )

  # Step 2: qualifying event (index criterion)
  idx_c   <- inc[[1]]
  idx_dom <- DOMAINS[[idx_c$domain]]
  conc_f  <- concept_clause(idx_c, idx_dom)

  steps[[3]] <- list(
    label = sprintf("Index event: %s", idx_dom$label),
    sql   = sprintf("SELECT COUNT(DISTINCT %s) AS n FROM %s WHERE 1=1%s",
                    ac2(idx_dom$table, idx_dom$person_col), fq(schema, idx_dom$table), conc_f)
  )

  # Additional inclusion criteria (approx counts - actual intersection requires full CTE)
  for (i in seq_along(inc)[-1]) {
    crit  <- inc[[i]]
    dom   <- DOMAINS[[crit$domain]]
    conc_f2 <- concept_clause(crit, dom)
    steps[[length(steps)+1]] <- list(
      label = sprintf("Inclusion %d: %s", i, dom$label),
      sql   = sprintf("SELECT COUNT(DISTINCT %s) AS n FROM %s WHERE 1=1%s",
                      ac2(dom$table, dom$person_col), fq(schema, dom$table), conc_f2)
    )
  }

  # Exclusion criteria
  for (i in seq_along(exc)) {
    crit  <- exc[[i]]
    dom   <- DOMAINS[[crit$domain]]
    conc_f3 <- concept_clause(crit, dom)
    steps[[length(steps)+1]] <- list(
      label = sprintf("Exclusion %d: %s (removed)", i, dom$label),
      sql   = sprintf("SELECT COUNT(DISTINCT %s) AS n FROM %s WHERE 1=1%s",
                      ac2(dom$table, dom$person_col), fq(schema, dom$table), conc_f3)
    )
  }

  steps
}


# ── STANDARDS CODE CHECK - CODELIST FROM DEFINITION (v11) ────────────────────
# Build an omopgenerics codelist from the cohort definition so the OHDSI tidy
# stack (CodelistGenerator) can validate it against the database. The concept
# set is expanded to descendants exactly as the cohort SQL does (via
# concept_ancestor when present), so the standards view counts the same codes
# the cohort actually matches.

# Expand a concept-id set to its descendants via concept_ancestor in the schema,
# matching the cohort query when use_descendants is TRUE. Returns an integer
# vector; falls back to the input ids when concept_ancestor is absent
# (source-vocabulary-only schemas) or use_descendants is FALSE.
expand_concept_ids <- function(schema, col_map, concept_ids, use_descendants) {
  ids <- unique(as.integer(concept_ids[!is.na(concept_ids)]))
  if (length(ids) == 0 || !isTRUE(use_descendants)) return(ids)
  existing <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  if (!"concept_ancestor" %in% existing) return(ids)
  desc_col <- ac(col_map, "concept_ancestor", "descendant_concept_id")
  anc_col  <- ac(col_map, "concept_ancestor", "ancestor_concept_id")
  sql <- sprintf("SELECT DISTINCT %s AS descendant FROM %s WHERE %s IN (%s)",
                 desc_col, fq(schema, "concept_ancestor"), anc_col,
                 paste(ids, collapse = ","))
  res <- tryCatch(db_query(sql), error = function(e) NULL)
  if (is.null(res) || nrow(res) == 0) return(ids)
  out <- unique(as.integer(res$descendant))
  out <- out[!is.na(out)]
  if (length(out) == 0) ids else sort(unique(c(ids, out)))
}

# Build an omopgenerics codelist (named list of integer concept_ids) from the
# cohort criteria: one entry per criterion that references concepts, descendants
# expanded to match the cohort. Names are unique and readable (type + domain).
# Returns a newCodelist, the plain named list if newCodelist is unavailable, or
# NULL when no criterion names any concepts.
build_definition_codelist <- function(schema, col_map, criteria) {
  if (length(criteria) == 0) return(NULL)
  entries <- list()
  for (i in seq_along(criteria)) {
    cr   <- criteria[[i]]
    cids <- cr$concept_ids
    if (is.null(cids) || length(cids) == 0) next
    full <- expand_concept_ids(schema, col_map, cids, isTRUE(cr$use_descendants))
    if (length(full) == 0) next
    base_nm <- sprintf("%s_%s", cr$type %||% "criterion", cr$domain %||% "concept")
    nm <- base_nm; k <- 2L
    while (nm %in% names(entries)) { nm <- sprintf("%s_%d", base_nm, k); k <- k + 1L }
    entries[[nm]] <- as.integer(full)
  }
  if (length(entries) == 0) return(NULL)
  tryCatch(omopgenerics::newCodelist(entries), error = function(e) entries)
}


# ── 8a3. STANDARDS SURVIVAL ENGINE (CohortSurvival, v11) ──────────────────────
# Kaplan-Meier survival for a materialised target cohort, as an independent
# cross-check of the native survfit path. Builds a cdm with the target cohort
# attached (get_cohort_cdm), generates an outcome cohort from the chosen concept
# set (descendants expanded to match the native path), then runs
# CohortSurvival::estimateSingleEventSurvival.
#
# Outcome generation writes a cohort table (cb_surv_outcome) into the cohort's
# own schema via generateConceptCohortSet, so that schema must be writable. A
# materialised scratch schema qualifies; a read-only mounted schema does not.
# overwrite = TRUE, so re-runs replace the prior outcome table.

# Generate a concept-based outcome cohort, returning the cdm with it attached.
# Prefers CDMConnector::generateConceptCohortSet (current as of 2026); falls
# back to CohortConstructor::conceptCohort on namespace drift.
ohdsi_generate_outcome_cohort <- function(cdm, ids, name = "cb_surv_outcome",
                                          end = "observation_period_end_date") {
  ids <- as.integer(ids[!is.na(ids)])
  if (length(ids) == 0) return(NULL)
  cset <- stats::setNames(list(ids), name)
  if (requireNamespace("CDMConnector", quietly = TRUE) &&
      "generateConceptCohortSet" %in% getNamespaceExports("CDMConnector")) {
    # limit = "all": keep every occurrence, not just the first-ever. The survival
    # estimate measures time to the first outcome at/after index, so a person
    # whose first-ever event predates index must still expose their post-index
    # occurrences or they are wrongly censored at time zero. This matches the
    # native path, which counts any post-index occurrence.
    # end controls era length: "observation_period_end_date" (survival, where end
    # is irrelevant) vs "event_end_date" (incidence, where spanning to obs end
    # would make every prior-outcome person permanently not-at-risk).
    return(CDMConnector::generateConceptCohortSet(
      cdm, conceptSet = cset, name = name, limit = "all",
      end = end, overwrite = TRUE))
  }
  if (requireNamespace("CohortConstructor", quietly = TRUE) &&
      "conceptCohort" %in% getNamespaceExports("CohortConstructor")) {
    cdm[[name]] <- CohortConstructor::conceptCohort(
      cdm, conceptSet = cset, name = name)
    return(cdm)
  }
  stop("No concept-cohort generator available (CDMConnector / CohortConstructor).")
}

# Detect the cohort_definition_id to use as the survival target. A materialised
# cohort table may carry an id other than 1; pick the most populated id so the
# target matches the loaded members rather than assuming 1.
ohdsi_target_cohort_id <- function(schema, cohort_table) {
  cols <- tryCatch(db_query(sprintf(
    "SELECT column_name FROM information_schema.columns
     WHERE table_schema = %s AND table_name = %s",
    pg_str(schema), pg_str(cohort_table)))$column_name, error = function(e) character(0))
  idcol <- cols[tolower(cols) == "cohort_definition_id"]
  if (length(idcol) == 0) return(1L)
  ids <- tryCatch(db_query(sprintf(
    "SELECT %s AS id, COUNT(*) AS n FROM %s GROUP BY %s ORDER BY n DESC",
    qq(idcol[1]), fq(schema, cohort_table), qq(idcol[1]))),
    error = function(e) NULL)
  if (is.null(ids) || nrow(ids) == 0) return(1L)
  tid <- suppressWarnings(as.integer(ids$id[1]))
  if (is.na(tid)) 1L else tid
}

# cdm must be built by the caller: get_cohort_cdm lives in server scope, so this
# global helper cannot reach it (R is lexically scoped). Returns
# list(result, n_outcome, error); error is a human-readable string when the run
# could not complete.
run_standards_survival <- function(cdm, cohort_table, outcome_concept_ids,
                                   use_descendants = FALSE, schema = NULL,
                                   col_map = NULL, target_cohort_id = 1L,
                                   event_gap = 7L) {
  out <- list(result = NULL, n_outcome = NA_integer_, error = NULL)
  if (!ohdsi_pkgs_available()) {
    out$error <- "OHDSI packages are not installed in this workspace."; return(out) }
  if (!requireNamespace("CohortSurvival", quietly = TRUE)) {
    out$error <- "CohortSurvival is not installed in this workspace."; return(out) }
  if (is.null(cdm)) {
    out$error <- "Could not attach the cohort table to a cdm reference."; return(out) }

  ids <- tryCatch(expand_concept_ids(schema, col_map, outcome_concept_ids,
                                     use_descendants),
                  error = function(e) as.integer(outcome_concept_ids))
  ids <- as.integer(ids[!is.na(ids)])
  if (length(ids) == 0) {
    out$error <- "Select at least one outcome concept for the standards run."
    return(out) }

  res <- tryCatch({
    cdm <- ohdsi_generate_outcome_cohort(cdm, ids, name = "cb_surv_outcome")
    if (is.null(cdm) || is.null(cdm[["cb_surv_outcome"]]))
      stop("Outcome cohort generation returned nothing.")

    n_out <- tryCatch(
      as.integer(dplyr::pull(dplyr::tally(cdm[["cb_surv_outcome"]]), 1)),
      error = function(e) NA_integer_)
    if (!is.na(n_out) && n_out == 0)
      stop("No outcome events found for the chosen concepts in this cohort's data.")

    sr <- CohortSurvival::estimateSingleEventSurvival(
      cdm,
      targetCohortTable  = cohort_table,
      targetCohortId     = as.integer(target_cohort_id),
      outcomeCohortTable = "cb_surv_outcome",
      outcomeCohortId    = 1,
      eventGap           = as.integer(event_gap))
    list(sr = sr, n_outcome = n_out, error = NULL)
  }, error = function(e) list(sr = NULL, n_outcome = NA_integer_,
                              error = conditionMessage(e)))

  if (!is.null(res$error)) { out$error <- res$error; return(out) }
  out$result   <- res$sr
  out$n_outcome <- res$n_outcome
  out
}


# ── 8a4. STANDARDS INCIDENCE & PREVALENCE (IncidencePrevalence, v11) ──────────
# Incidence rates and period prevalence of the outcome WITHIN the materialised
# cohort, over calendar time. Builds the outcome cohort (generateConceptCohortSet)
# and a target denominator restricted to the cohort
# (generateTargetDenominatorCohortSet), then runs estimateIncidence and
# estimatePeriodPrevalence. cdm is built by the caller (server scope).
# Returns list(incidence, prevalence, error).
run_incidence_prevalence <- function(cdm, cohort_table, outcome_concept_ids,
                                     use_descendants = FALSE, schema = NULL,
                                     col_map = NULL, target_cohort_id = 1L,
                                     interval = "years") {
  out <- list(incidence = NULL, prevalence = NULL, error = NULL)
  if (!ohdsi_pkgs_available()) {
    out$error <- "OHDSI packages are not installed in this workspace."; return(out) }
  if (!requireNamespace("IncidencePrevalence", quietly = TRUE)) {
    out$error <- "IncidencePrevalence is not installed in this workspace."; return(out) }
  if (is.null(cdm)) {
    out$error <- "Could not attach the cohort table to a cdm reference."; return(out) }

  ids <- tryCatch(expand_concept_ids(schema, col_map, outcome_concept_ids,
                                     use_descendants),
                  error = function(e) as.integer(outcome_concept_ids))
  ids <- as.integer(ids[!is.na(ids)])
  if (length(ids) == 0) {
    out$error <- "Select at least one outcome concept for the standards run."
    return(out) }

  res <- tryCatch({
    cdm <- ohdsi_generate_outcome_cohort(cdm, ids, name = "cb_ip_outcome",
                                         end = "event_end_date")
    if (is.null(cdm) || is.null(cdm[["cb_ip_outcome"]]))
      stop("Outcome cohort generation returned nothing.")

    cdm <- IncidencePrevalence::generateTargetDenominatorCohortSet(
      cdm = cdm, name = "cb_ip_denom",
      targetCohortTable = cohort_table,
      targetCohortId    = as.integer(target_cohort_id),
      requirementsAtEntry = FALSE)
    if (is.null(cdm[["cb_ip_denom"]]))
      stop("Denominator generation returned nothing.")

    inc <- tryCatch(
      IncidencePrevalence::estimateIncidence(
        cdm = cdm, denominatorTable = "cb_ip_denom", outcomeTable = "cb_ip_outcome",
        interval = interval, repeatedEvents = TRUE, outcomeWashout = 0,
        completeDatabaseIntervals = FALSE),
      error = function(e) { message("[ip inc] ", conditionMessage(e)); NULL })

    prev <- if (identical(interval, "overall")) NULL else tryCatch(
      IncidencePrevalence::estimatePeriodPrevalence(
        cdm = cdm, denominatorTable = "cb_ip_denom", outcomeTable = "cb_ip_outcome",
        interval = interval, completeDatabaseIntervals = FALSE,
        fullContribution = FALSE),
      error = function(e) { message("[ip prev] ", conditionMessage(e)); NULL })

    list(inc = inc, prev = prev, error = NULL)
  }, error = function(e) list(inc = NULL, prev = NULL, error = conditionMessage(e)))

  if (!is.null(res$error)) { out$error <- res$error; return(out) }
  out$incidence  <- res$inc
  out$prevalence <- res$prev
  if (identical(interval, "overall"))
    out$prev_note <- "Period prevalence is not estimated in Overall mode (it needs a calendar interval). Switch to Years/Quarters/Months for prevalence."
  if (is.null(res$inc) && is.null(res$prev))
    out$error <- "Neither incidence nor prevalence could be estimated (see server log)."
  out
}


# ── 8b. PHENOTYPE DIAGNOSTICS - ORPHAN CONCEPTS (v10.15) ──────────────────────
# Orphan-concept recommender for a concept set, native SQL over the OMOP
# vocabulary tables. Answers: "which concepts have records in this schema that
# are hierarchically related to my chosen concepts but are NOT captured by my
# definition?" This is the only phenotype diagnostic that *changes* the cohort
# rather than merely describing it - it produces an actionable add/exclude list.
#
# Candidate sources (tagged in the `relationship` column):
#   - 'descendant' : concepts BELOW a chosen concept in concept_ancestor that
#                    are not already captured. The classic "picked the parent
#                    but not its children" gap. When use_descendants = TRUE
#                    these are already covered, so none appear - correct.
#   - 'ancestor'   : the IMMEDIATE parent(s) of a chosen concept (separation 1)
#                    that themselves carry records - a broader code you may have
#                    meant to include. Only emitted when concept_ancestor
#                    exposes min_levels_of_separation; otherwise omitted, so a
#                    general root ("Clinical finding") never swamps the list.
#
# Returns a data.frame ordered by person count desc:
#   concept_id, concept_name, vocabulary_id, concept_code, standard_concept,
#   relationship, n_records, n_persons
# NULL if the concept set is empty, or the domain/concept/concept_ancestor
# tables are absent (e.g. a source-vocabulary-only schema). The caller checks
# the same preconditions to show the right message.
query_orphan_concepts <- function(schema, col_map, concept_ids,
                                   domain_key, use_descendants = FALSE,
                                   top_n = 25L, min_records = 1L) {
  concept_ids <- as.integer(concept_ids[!is.na(concept_ids)])
  if (length(concept_ids) == 0) return(NULL)
  dom <- DOMAINS[[domain_key]]
  if (is.null(dom)) return(NULL)

  tbls <- tryCatch(tolower(get_tables(schema)), error = function(e) character(0))
  if (!tolower(dom$table) %in% tbls) return(NULL)
  if (!"concept"          %in% tbls) return(NULL)
  if (!"concept_ancestor" %in% tbls) return(NULL)

  ids_arr <- sprintf("ARRAY[%s]::bigint[]", cid_sql(concept_ids))

  ca_anc  <- ac(col_map, "concept_ancestor", "ancestor_concept_id")
  ca_des  <- ac(col_map, "concept_ancestor", "descendant_concept_id")
  t_cid   <- ac(col_map, dom$table, dom$concept_col)
  t_pid   <- ac(col_map, dom$table, dom$person_col)
  co_cid  <- ac(col_map, "concept", "concept_id")
  co_name <- ac(col_map, "concept", "concept_name")
  co_voc  <- ac(col_map, "concept", "vocabulary_id")
  co_code <- ac(col_map, "concept", "concept_code")
  co_std  <- ac(col_map, "concept", "standard_concept")

  # Immediate-parent ancestors only - and only when the separation column is
  # present - so general roots never dominate the recommendation.
  has_sep <- !is.null(col_map[["concept_ancestor"]][["min_levels_of_separation"]])
  anc_block <- if (has_sep) {
    ca_sep <- ac(col_map, "concept_ancestor", "min_levels_of_separation")
    sprintf(
"    UNION
    SELECT ca.%s AS concept_id, 'ancestor' AS rel
    FROM   %s ca
    JOIN   sel s ON ca.%s = s.concept_id
    WHERE  ca.%s <> ca.%s AND ca.%s = 1",
      ca_anc, fq(schema, "concept_ancestor"), ca_des, ca_anc, ca_des, ca_sep)
  } else ""

  # In descendants mode the cohort SQL already captures every descendant, so
  # fold them into the covered set (they are not orphans).
  covered_desc <- if (isTRUE(use_descendants)) {
    sprintf(
"    UNION
    SELECT ca.%s FROM %s ca JOIN sel s ON ca.%s = s.concept_id",
      ca_des, fq(schema, "concept_ancestor"), ca_anc)
  } else ""

  sql <- sprintf(
"WITH sel AS (
    SELECT unnest(%s) AS concept_id
),
covered AS (
    SELECT concept_id FROM sel
%s
),
cand AS (
    SELECT ca.%s AS concept_id, 'descendant' AS rel
    FROM   %s ca
    JOIN   sel s ON ca.%s = s.concept_id
    WHERE  ca.%s <> ca.%s
%s
),
cand_f AS (
    SELECT concept_id, string_agg(DISTINCT rel, '+' ORDER BY rel) AS relationship
    FROM   cand
    WHERE  concept_id NOT IN (SELECT concept_id FROM covered)
    GROUP  BY concept_id
),
cnt AS (
    SELECT t.%s AS concept_id,
           COUNT(*)::int             AS n_records,
           COUNT(DISTINCT t.%s)::int AS n_persons
    FROM   %s t
    WHERE  t.%s IN (SELECT concept_id FROM cand_f)
    GROUP  BY t.%s
)
SELECT cf.concept_id   AS concept_id,
       co.%s           AS concept_name,
       co.%s           AS vocabulary_id,
       co.%s           AS concept_code,
       co.%s           AS standard_concept,
       cf.relationship AS relationship,
       cnt.n_records   AS n_records,
       cnt.n_persons   AS n_persons
FROM   cand_f cf
JOIN   cnt ON cnt.concept_id = cf.concept_id
LEFT   JOIN %s co ON co.%s = cf.concept_id
WHERE  cnt.n_records >= %d
ORDER  BY cnt.n_persons DESC, cnt.n_records DESC
LIMIT  %d",
    ids_arr,
    covered_desc,
    ca_des, fq(schema, "concept_ancestor"), ca_anc, ca_des, ca_anc, anc_block,
    t_cid, t_pid, fq(schema, dom$table), t_cid, t_cid,
    co_name, co_voc, co_code, co_std,
    fq(schema, "concept"), co_cid,
    as.integer(min_records),
    as.integer(top_n))

  res <- tryCatch(db_query(sql), error = function(e) {
    message("[orphan] query failed: ", conditionMessage(e)); NULL
  })
  if (is.null(res) || nrow(res) == 0) return(NULL)
  names(res) <- tolower(names(res))
  res$concept_id <- as.integer(res$concept_id)
  res$n_records  <- as.integer(res$n_records)
  res$n_persons  <- as.integer(res$n_persons)
  res
}


# v11: lightweight cohort overview for the Validate tab. Works on ANY cohort -
# definition-run or loaded from a materialised schema - because it reads only
# person_id (+ index_date for age, + cohort_end_date for follow-up if present).
# Person/sex/year-of-birth come from one IN-clause query per schema (the proven
# demographics pattern); age, sex and follow-up are reduced in R. Returns a
# small summary list, or NULL.
query_cohort_overview <- function(res, schemas, col_maps, multi = FALSE) {
  if (is.null(res) || nrow(res) == 0 || !"person_id" %in% names(res)) return(NULL)
  by_schema <- if (isTRUE(multi) && "source_schema" %in% names(res))
    split(res, res$source_schema)
  else setNames(list(res), schemas[[1]] %||% "")

  demo <- lapply(names(by_schema), function(sch) {
    if (!nzchar(sch %||% "")) return(NULL)
    cm  <- col_maps[[sch]] %||% list()
    sub <- by_schema[[sch]]
    pid  <- ac(cm, "person", "person_id")
    gcol <- ac(cm, "person", "gender_concept_id")
    yob  <- ac(cm, "person", "year_of_birth")
    sql <- sprintf(
      "SELECT %s AS person_id, %s AS gender_concept_id, %s AS year_of_birth
       FROM %s WHERE %s IN (%s)",
      pid, gcol, yob, fq(sch, "person"), pid, pid_sql(sub$person_id))
    d <- tryCatch(db_query(sql), error = function(e) {
      message("[overview] ", conditionMessage(e)); NULL })
    if (is.null(d) || nrow(d) == 0) return(NULL)
    names(d) <- tolower(names(d)); d
  })
  pdf <- do.call(rbind, Filter(Negate(is.null), demo))
  if (is.null(pdf) || nrow(pdf) == 0) return(NULL)
  pdf$person_id <- as.character(pdf$person_id)

  idx_year <- suppressWarnings(as.integer(format(
    as.Date(as.character(res$index_date)), "%Y")))
  res2 <- data.frame(person_id = as.character(res$person_id),
                     idx_year = idx_year, stringsAsFactors = FALSE)
  m   <- merge(pdf, res2, by = "person_id", all.x = TRUE)
  age <- m$idx_year - suppressWarnings(as.integer(m$year_of_birth))
  age[!is.finite(age) | age < 0 | age > 120] <- NA

  # Follow-up: days from index to end of observation period, per schema slice -
  # the same helper the Characterisation tab uses, so the two figures agree.
  # (Definition cohorts carry no cohort_end_date, which is why this read n/a.)
  fu_days <- unlist(lapply(names(by_schema), function(sch) {
    if (!nzchar(sch %||% "")) return(numeric(0))
    cm <- col_maps[[sch]] %||% list()
    d  <- tryCatch(query_followup_dist(sch, cm, by_schema[[sch]]), error = function(e) NULL)
    if (is.null(d) || nrow(d) == 0) return(numeric(0))
    names(d) <- tolower(names(d))
    suppressWarnings(as.numeric(d$days))
  }))
  fu_days <- fu_days[is.finite(fu_days) & fu_days >= 0]
  fu_y <- if (length(fu_days)) round(stats::median(fu_days) / 365.25, 1) else NA_real_
  if (is.na(fu_y) && "cohort_end_date" %in% names(res)) {   # fallback for imported cohorts
    d <- as.numeric(as.Date(as.character(res$cohort_end_date)) -
                    as.Date(as.character(res$index_date)))
    d <- d[is.finite(d) & d >= 0]
    if (length(d)) fu_y <- round(stats::median(d) / 365.25, 1)
  }

  list(
    n           = nrow(res),
    pct_female  = if (any(!is.na(m$gender_concept_id)))
                    round(100 * mean(m$gender_concept_id == 8532, na.rm = TRUE)) else NA,
    median_age  = if (any(!is.na(age))) round(stats::median(age, na.rm = TRUE)) else NA,
    median_fu_y = fu_y
  )
}


# v11: sequential (intersection) attrition for the Validate tab. Unlike the
# marginal build_attrition_sql (each rule counted independently), this builds
# the cohort with successively more criteria and counts survivors at each step -
# the real waterfall. Primary schema only; definition cohorts only (a
# materialised cohort has no rules to walk). Returns a data.frame of
# label, n, removed - or NULL.
query_sequential_attrition <- function(schema, criteria, col_map,
                                       cohort_name = "cohort",
                                       index_strategy = "first_qualifying",
                                       prior_obs_days = NA_integer_,
                                       min_followup_days = NA_integer_) {
  inc <- Filter(function(c) identical(c$type, "inclusion"), criteria)
  exc <- Filter(function(c) identical(c$type, "exclusion"), criteria)
  if (length(inc) == 0) return(NULL)

  crit_label <- function(cr) {
    nm <- (DOMAINS[[cr$domain]]$label) %||% cr$domain
    k  <- length(as.integer(cr$concept_ids %||% integer(0)))
    if (k == 0) nm else sprintf("%s (%d concept%s)", nm, k, if (k == 1) "" else "s")
  }
  count_for <- function(subset) {
    sql <- tryCatch(build_cohort_sql(schema, subset, cohort_name = cohort_name,
             index_strategy = index_strategy, prior_obs_days = prior_obs_days,
             min_followup_days = min_followup_days, col_map = col_map),
             error = function(e) NULL)
    if (is.null(sql) || !is.character(sql) || !nzchar(sql)) return(NA_integer_)
    sql <- sub("[;[:space:]]+$", "", sql)   # a trailing ';' is illegal inside a subquery
    r <- tryCatch(db_query(sprintf(
      "SELECT COUNT(DISTINCT person_id)::int AS n FROM (%s) _q", sql)),
      error = function(e) NULL)
    if (is.null(r) || nrow(r) == 0) NA_integer_ else as.integer(r$n[1])
  }

  labels <- character(0); ns <- integer(0)
  alln <- tryCatch(as.integer(db_query(sprintf(
    "SELECT COUNT(*)::int AS n FROM %s", fq(schema, "person")))$n[1]),
    error = function(e) NA_integer_)
  labels <- c(labels, "All persons in dataset"); ns <- c(ns, alln)

  cur <- list()
  for (i in seq_along(inc)) {
    cur <- c(cur, inc[i])
    lbl <- if (i == 1) sprintf("Index event - %s", crit_label(inc[[1]]))
           else sprintf("+ require %s", crit_label(inc[[i]]))
    labels <- c(labels, lbl); ns <- c(ns, count_for(cur))
  }
  for (j in seq_along(exc)) {
    cur <- c(cur, exc[j])
    labels <- c(labels, sprintf("- exclude %s", crit_label(exc[[j]])))
    ns <- c(ns, count_for(cur))
  }

  df <- data.frame(label = labels, n = ns, stringsAsFactors = FALSE)
  df$removed <- c(NA_integer_, as.integer(-diff(df$n)))
  df
}


# v11: index-event breakdown for the Validate tab. Data-driven, so it works on
# ANY cohort - it looks at what concepts are recorded on each person's index
# date. For a definition cohort, pass the index domain + concept set to see
# which of those concepts actually drive entry. For a materialised cohort
# (no domain/set), it scans the main clinical domains and shows the most common
# concepts on the index date, reconstructing the likely entry event. Returns a
# data.frame of concept_id, concept_name, domain, n_persons, pct - or NULL.
query_index_breakdown <- function(schema, col_map, res, domain_key = NULL,
                                  concept_ids = integer(0), use_descendants = FALSE,
                                  top_n = 15L) {
  if (is.null(res) || nrow(res) == 0) return(NULL)
  if (!all(c("person_id", "index_date") %in% names(res))) return(NULL)
  sub <- res[!is.na(res$person_id) & !is.na(res$index_date), c("person_id", "index_date")]
  if (nrow(sub) == 0) return(NULL)
  idv <- if (inherits(sub$person_id, "integer64")) as.character(sub$person_id)
         else sprintf("%.0f", suppressWarnings(as.numeric(as.character(sub$person_id))))
  dtv  <- sprintf("'%s'::date", as.character(sub$index_date))
  vals <- paste(sprintf("(%s,%s)", idv, dtv), collapse = ",")

  run_domain <- function(dk, filter_ids) {
    dom <- DOMAINS[[dk]]; if (is.null(dom)) return(NULL)
    tcid <- ac(col_map, dom$table, dom$concept_col)
    tpid <- ac(col_map, dom$table, dom$person_col)
    tdat <- ac(col_map, dom$table, dom$date_col)
    where <- ""
    if (length(filter_ids) > 0) {
      where <- if (isTRUE(use_descendants))
        sprintf("WHERE t.%s IN (SELECT %s FROM %s WHERE %s IN (%s))",
                tcid, ac(col_map, "concept_ancestor", "descendant_concept_id"),
                fq(schema, "concept_ancestor"),
                ac(col_map, "concept_ancestor", "ancestor_concept_id"), cid_sql(filter_ids))
      else sprintf("WHERE t.%s IN (%s)", tcid, cid_sql(filter_ids))
    }
    sql <- sprintf(
"WITH idx(person_id, index_date) AS (VALUES %s)
SELECT t.%s AS concept_id, COUNT(DISTINCT t.%s) AS n_persons
FROM %s t JOIN idx i ON i.person_id = t.%s AND t.%s::date = i.index_date
%s
GROUP BY t.%s ORDER BY n_persons DESC LIMIT %d",
      vals, tcid, tpid, fq(schema, dom$table), tpid, tdat, where, tcid, as.integer(top_n))
    r <- tryCatch(db_query(sql), error = function(e) NULL)
    if (is.null(r) || nrow(r) == 0) return(NULL)
    names(r) <- tolower(names(r)); r$domain <- dk; r
  }

  if (!is.null(domain_key)) {
    out <- run_domain(domain_key, as.integer(concept_ids))
  } else {
    doms  <- intersect(c("condition", "drug", "measurement", "procedure", "observation"),
                       names(DOMAINS))
    parts <- Filter(Negate(is.null), lapply(doms, function(d) run_domain(d, integer(0))))
    out   <- if (length(parts)) do.call(rbind, parts) else NULL
  }
  if (is.null(out) || nrow(out) == 0) return(NULL)
  out <- head(out[order(-out$n_persons), , drop = FALSE], top_n)

  ids <- unique(out$concept_id)
  nm  <- tryCatch(db_query(sprintf(
    "SELECT %s AS concept_id, %s AS concept_name FROM %s WHERE %s IN (%s)",
    ac(col_map, "concept", "concept_id"), ac(col_map, "concept", "concept_name"),
    fq(schema, "concept"), ac(col_map, "concept", "concept_id"), cid_sql(ids))),
    error = function(e) NULL)
  if (!is.null(nm) && nrow(nm) > 0) {
    names(nm) <- tolower(names(nm))
    out <- merge(out, nm, by = "concept_id", all.x = TRUE)
    out <- out[order(-out$n_persons), , drop = FALSE]
  } else out$concept_name <- NA_character_
  out$pct <- round(100 * out$n_persons / nrow(res))
  out
}


# ── 9. OVERLAP-AWARE BANNER HELPERS ───────────────────────────────────────────
# overlap_banner_ui(): render an in-tab banner that escalates by overlap status.
#   - "full": returns NULL (no banner - analyses are valid by default)
#   - "partial": amber warning, no gate
#   - "none": red gate - requires explicit user acknowledgement before the
#     downstream analysis observer will proceed
# ack_input_id is the actionButton inputId; the per-tab proceed reactiveVal is
# set TRUE in server() by an observeEvent watching that input.
overlap_banner_ui <- function(ov, ack_input_id = NULL, acknowledged = FALSE,
                              tab_name = "this analysis") {
  if (is.null(ov) || identical(ov$overlap, "full")) return(NULL)

  if (identical(ov$overlap, "partial")) {
    return(div(
      class = "overlap-panel overlap-partial",
      style = "margin-bottom:14px;",
      tags$span(
        icon("triangle-exclamation"),
        tags$strong("  Partial observation-period overlap.")),
      tags$p(
        style = "font-size:0.86rem;margin:4px 0 0;color:inherit;opacity:0.9;",
        sprintf(paste(
          "Selected schemas share only %d days (%s \u2192 %s).",
          "Curves on a shared days-from-index axis pool data from",
          "non-contemporaneous populations; interpret cross-schema",
          "comparisons with care."),
          ov$overlap_days,
          format(ov$overlap_start), format(ov$overlap_end)))
    ))
  }

  # overlap == "none"
  ranges_summary <- paste(sapply(names(ov$ranges), function(s) {
    r <- ov$ranges[[s]]
    if (is.na(r$min)) sprintf("%s: (no observation_period)", s)
    else sprintf("%s: %s\u2013%s", s, format(r$min, "%Y"), format(r$max, "%Y"))
  }), collapse = "  \u2502  ")

  if (isTRUE(acknowledged)) {
    return(div(
      class = "overlap-panel overlap-partial",
      style = "margin-bottom:14px;",
      tags$span(
        icon("circle-info"),
        tags$strong("  Acknowledged: no observation-period overlap.")),
      tags$p(
        style = "font-size:0.84rem;margin:4px 0 0;color:inherit;opacity:0.85;",
        sprintf("Proceeding at user request. %s.", ranges_summary))
    ))
  }

  div(
    class = "overlap-panel overlap-none",
    style = "margin-bottom:14px;",
    tags$span(
      icon("circle-xmark"),
      tags$strong("  No observation-period overlap between selected schemas.")),
    tags$p(
      style = "font-size:0.86rem;margin:4px 0 0;color:inherit;opacity:0.92;",
      sprintf(paste(
        "Schemas do not share any calendar window.",
        "Pooled %s curves on a days-from-index axis combine",
        "populations alive in different eras, which is misleading.",
        "Either: deselect schemas to analyse one at a time, or",
        "acknowledge the limitation and proceed."), tab_name)),
    tags$p(
      style = "font-size:0.78rem;margin:6px 0 8px;color:inherit;opacity:0.75;",
      ranges_summary),
    if (!is.null(ack_input_id)) actionButton(
      ack_input_id,
      tagList(icon("check"), " I understand \u2014 proceed anyway"),
      class = "btn-warning btn-sm",
      style = "margin-top:6px;")
  )
}

# overlap_gate_blocks(): TRUE when the analysis should refuse to run.
# Used by guarded observers. Single source of truth.
overlap_gate_blocks <- function(ov, acknowledged = FALSE) {
  !is.null(ov) && identical(ov$overlap, "none") && !isTRUE(acknowledged)
}


# ── Chart export toolbar helper (v10.13) ──────────────────────────────────────
# Defined at file scope so it can be called from the UI definition. The
# function only emits markup; the corresponding server-side observers wire
# up Save / Code behaviour via input IDs "save_<id>_btn" / "code_<id>_btn"
# and the chart_registry_rv reactive (see chart_register() in server()).
chart_toolbar <- function(chart_id) {
  tags$span(class = "chart-toolbar",
    actionButton(paste0("code_", chart_id, "_btn"),
      label = NULL, icon = icon("code"),
      class = "btn-dre-sec btn-sm chart-tool-btn",
      title = "View R code"),
    actionButton(paste0("save_", chart_id, "_btn"),
      label = NULL, icon = icon("download"),
      class = "btn-dre-sec btn-sm chart-tool-btn",
      title = "Save as PNG to Downloads")
  )
}


