      menuItem("Survival",           tabName = "tab_survival",  icon = icon("chart-line")),
      menuItem("Cumulative Incidence", tabName = "tab_attrition", icon = icon("filter")),
      menuItem("Cox Regression",     tabName = "tab_cox",       icon = icon("chart-line")),
      menuItem("Treatment Pathways", tabName = "tab_trt",       icon = icon("route")),
      menuItem("Compare Cohorts",    tabName = "tab_compare",   icon = icon("code-compare")),
      # ── 5 · Export ───────────────────────────────────────────────────────────
      tags$li(class = "sidebar-group-label", "Export"),
      menuItem("Export",           tabName = "tab_export",   icon = icon("file-export")),
      menuItem("OHDSI Tools",      tabName = "tab_ohdsi",    icon = icon("share-nodes"))
    ),
    tags$hr(style = "border-color:var(--dre-border);margin:8px 0;"),
    uiOutput("compare_ab_status_ui")
