  dashboardBody(

    # ── CSS ─────────────────────────────────────────────────────────────────
    tags$head(tags$style(HTML("
/* ═══════════════════════════════════════════════════
   OMOP Cohort Builder - DRE Navy theme
   Matches SQL Workbench colour scheme & font sizes
═══════════════════════════════════════════════════ */
:root {
  --dre-dark:    #0B2341;
  --dre-surface: #0D2A4A;
  --dre-mid:     #133660;
  --dre-teal:    #00C5B5;
  --dre-teal-lt: #00E5D2;
  --dre-teal-dim:rgba(0,197,181,.12);
  --dre-text:    #E8F4F8;
  --dre-muted:   #8BA3B5;
  --dre-border:  rgba(255,255,255,0.10);
  --dre-error:   #E05C6E;
  --dre-gold:    #FFB84D;
  --dre-success: #3DD68C;
  --dre-warn:    #FFB84D;
  --dre-inc:     rgba(61,214,140,.12);
  --dre-exc:     rgba(224,92,110,.12);
}
html { font-size:15px; }
/* Reactable (OHDSI tab) - theme to the app's dark palette. Reactable renders
   into the normal DOM, so global CSS applies; this covers both the
   visOmopResults/CohortCharacteristics reactables and the fallback reactable.
   Without it the cells inherit light text on reactable's white background. */
.reactable { background: var(--dre-surface) !important; color: var(--dre-text) !important;
  border:1px solid var(--dre-border); border-radius:6px; }
.reactable .rt-table { background: var(--dre-surface) !important; }
.reactable .rt-thead .rt-th, .reactable .rt-thead .rt-td {
  background: var(--dre-mid) !important; color: var(--dre-text) !important;
  border-color: var(--dre-border) !important; font-weight:600; }
.reactable .rt-tbody .rt-td {
  background: var(--dre-surface) !important; color: var(--dre-text) !important;
  border-color: var(--dre-border) !important; }
.reactable .rt-tbody .rt-tr.rt-tr-striped .rt-td,
.reactable .rt-tbody .rt-tr:nth-child(even) .rt-td { background: var(--dre-mid) !important; }
.reactable .rt-tbody .rt-tr:hover .rt-td { background: var(--dre-teal-dim) !important; }
.reactable .rt-search, .reactable .rt-filter {
  background: var(--dre-dark) !important; color: var(--dre-text) !important;
  border:1px solid var(--dre-border) !important; border-radius:4px; }
.reactable .rt-search::placeholder, .reactable .rt-filter::placeholder { color: var(--dre-muted) !important; }
.reactable .rt-page-button, .reactable .rt-page-info, .reactable .rt-page-size-select {
  background: var(--dre-dark) !important; color: var(--dre-text) !important;
  border-color: var(--dre-border) !important; }
.reactable .rt-page-button:not([disabled]):hover { background: var(--dre-teal-dim) !important; }
.reactable a { color: var(--dre-teal-lt) !important; }
body, .content-wrapper, .main-sidebar, .sidebar {
  background: var(--dre-dark) !important;
  color: var(--dre-text) !important;
  font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif;
  font-size: 1rem;
  line-height: 1.6;
}
/* ── Header / Sidebar ── */
.skin-black .main-header .logo,
.skin-black .main-header .navbar { background:var(--dre-dark) !important; border-bottom:1px solid var(--dre-border) !important; }
.skin-black .main-header .logo   { color:var(--dre-teal) !important; font-weight:700; font-size:1.15rem; }
/* Hamburger toggle - make visible against dark navbar (v10.13) */
.skin-black .main-header .sidebar-toggle {
  color: var(--dre-text) !important;
  background: transparent !important;
  border: none !important;
}
.skin-black .main-header .sidebar-toggle:hover,
.skin-black .main-header .sidebar-toggle:focus {
  color: var(--dre-teal) !important;
  background: var(--dre-teal-dim) !important;
}
.skin-black .main-header .sidebar-toggle::before {
  /* Some shinydashboard skins hide the icon via a transparent pseudo -
     force it visible. */
  color: inherit !important;
}
.skin-black .main-sidebar         { background:var(--dre-surface) !important; border-right:1px solid var(--dre-border) !important; }
.skin-black .sidebar-menu > li.active > a,
.skin-black .sidebar-menu > li > a:hover { background:var(--dre-teal-dim) !important; color:var(--dre-teal) !important; }
.skin-black .sidebar-menu > li > a { color:var(--dre-muted) !important; font-size:0.97rem !important; }
/* ── Inputs ── */
.form-control, select.form-control {
  background:var(--dre-mid) !important;
  border:1px solid var(--dre-border) !important;
  color:var(--dre-text) !important;
  border-radius:6px !important;
  font-size:0.97rem !important;
}
.form-control:focus { border-color:var(--dre-teal) !important; box-shadow:0 0 0 3px rgba(0,197,181,.2) !important; outline:none !important; }
label { color:var(--dre-muted) !important; font-size:0.87rem !important; }
/* ── Tabs ── */
.tab-content { background:transparent !important; }
.nav-tabs { border-bottom:1px solid var(--dre-border) !important; }
.nav-tabs > li > a { color:var(--dre-muted) !important; background:transparent !important; border:none !important; font-size:0.97rem !important; }
.nav-tabs > li.active > a, .nav-tabs > li.active > a:hover {
  color:var(--dre-teal) !important; background:transparent !important;
  border-bottom:2px solid var(--dre-teal) !important; }
/* ── Buttons ── */
.btn-dre-pri   { background:var(--dre-teal) !important; color:var(--dre-dark) !important; border:none !important; border-radius:8px !important; font-weight:700 !important; font-size:1rem !important; }
.btn-dre-pri:hover { background:var(--dre-teal-lt) !important; }
.btn-dre-sec   { background:var(--dre-mid) !important; color:var(--dre-text) !important; border:1px solid var(--dre-border) !important; border-radius:8px !important; font-size:0.97rem !important; }
.btn-dre-sec:hover { border-color:var(--dre-teal) !important; color:var(--dre-teal) !important; }
.btn-dre-danger { background:rgba(224,92,110,.15) !important; color:var(--dre-error) !important; border:1px solid rgba(224,92,110,.3) !important; border-radius:8px !important; font-size:0.97rem !important; }
.btn-dre-danger:hover { background:rgba(224,92,110,.25) !important; }
.btn-sm { padding:4px 11px !important; font-size:0.87rem !important; }
/* ── Cards ── */
.cb-card {
  background:var(--dre-surface); border:1px solid var(--dre-border);
  border-radius:10px; padding:18px 20px; margin-bottom:14px;
}
.cb-card-title {
  font-size:0.84rem; font-weight:700; color:var(--dre-teal);
  text-transform:uppercase; letter-spacing:.6px; margin-bottom:14px;
}
/* AIRA concept summary panel (R-AIRA-16): readable typography inside the
   detail panel. The markdown renderer produces h4/p/ul; we constrain them
   so they fit the panel without overwhelming surrounding chrome. */
.aira-concept-summary { font-size:0.86rem; line-height:1.55; color:var(--dre-text); }
.aira-concept-summary h4 {
  color:var(--dre-teal); font-size:0.82rem; text-transform:uppercase;
  letter-spacing:.4px; margin:16px 0 6px; font-weight:700;
}
.aira-concept-summary h4:first-child { margin-top:0; }
.aira-concept-summary p { margin:0 0 10px; }
.aira-concept-summary ul,
.aira-concept-summary ol { margin:6px 0 12px; padding-left:22px; }
.aira-concept-summary li { margin-bottom:4px; }
.aira-concept-summary strong { color:var(--dre-text); }
/* Chart toolbar (Save / Code buttons) - top-right of chart card titles. */
.chart-toolbar {
  float: right;
  display: inline-flex; gap: 4px;
  margin-top: -4px;
}
.chart-tool-btn {
  padding: 3px 8px !important;
  font-size: 0.78rem !important;
  min-width: 32px;
}
.chart-tool-btn .fa,
.chart-tool-btn i {
  font-size: 0.85rem;
}
/* Code modal pre block: monospace, scrollable, contrast-friendly. */
.chart-code-block {
  background: #061320 !important;
  color: #C9E5EA !important;
  border: 1px solid var(--dre-border) !important;
  border-radius: 6px !important;
  padding: 14px 16px !important;
  font-family: 'SF Mono', Monaco, 'Courier New', monospace !important;
  font-size: 0.83rem !important;
  line-height: 1.5 !important;
  max-height: 60vh; overflow: auto;
  white-space: pre;
}
/* ── Section headers ── */
.sb-label { font-size:0.84rem; color:var(--dre-muted); text-transform:uppercase;
  letter-spacing:.6px; font-weight:700; margin-bottom:8px; }
/* ── Criterion rows ── */
.criterion-row {
  background:var(--dre-mid); border:1px solid var(--dre-border);
  border-radius:8px; padding:14px 16px; margin-bottom:10px;
  position:relative;
}
.criterion-row.inc { border-left:3px solid var(--dre-success); }
.criterion-row.exc { border-left:3px solid var(--dre-error); }
.criterion-label {
  font-size:0.80rem; font-weight:700; letter-spacing:.8px;
  text-transform:uppercase; margin-bottom:8px;
}
.criterion-label.inc { color:var(--dre-success); }
.criterion-label.exc { color:var(--dre-error); }
.criterion-domain-badge {
  display:inline-block; background:var(--dre-teal-dim); color:var(--dre-teal);
  border-radius:4px; font-size:0.80rem; padding:2px 9px; margin-right:6px; font-weight:700;
}
/* ── Concept chips ── */
.concept-chip {
  display:inline-flex; align-items:center; gap:5px;
  background:var(--dre-surface); border:1px solid var(--dre-border);
  border-radius:16px; padding:4px 11px; font-size:0.87rem; margin:2px;
  color:var(--dre-text);
}
.concept-chip .rm-chip { cursor:pointer; color:var(--dre-muted); font-size:0.97rem; line-height:1; }
.concept-chip .rm-chip:hover { color:var(--dre-error); }
/* ── Connection dot ── */
.conn-dot { display:inline-block; width:9px; height:9px; border-radius:50%; margin-right:6px; }
.conn-dot.ok  { background:var(--dre-success); box-shadow:0 0 6px var(--dre-success); }
.conn-dot.err { background:var(--dre-error);   box-shadow:0 0 6px var(--dre-error); }
/* ── OMOP badge ── */
.omop-badge {
  background:var(--dre-teal-dim); border:1px solid rgba(0,197,181,.3);
  border-radius:8px; padding:8px 13px; margin-top:8px; font-size:0.87rem;
}
.omop-badge-title { color:var(--dre-teal); font-weight:700; font-size:0.87rem; }
/* ── SQL panel ── */
.sql-panel {
  background:#060F1A; border:1px solid var(--dre-border); border-radius:8px;
  padding:16px; font-family:JetBrains Mono,Consolas,monospace;
  font-size:0.87rem; color:#A8D8EA; white-space:pre-wrap; overflow:auto; max-height:520px;
  line-height:1.75;
}
/* ── Attrition table ── */
.attrition-step { display:flex; align-items:center; gap:12px; margin-bottom:8px; }
.attrition-bar-bg { flex:1; background:var(--dre-mid); border-radius:4px; height:24px; overflow:hidden; }
.attrition-bar-fill {
  height:100%; background:var(--dre-teal); border-radius:4px;
  display:flex; align-items:center; padding-left:10px;
  font-size:0.80rem; font-weight:700; color:var(--dre-dark);
  transition: width .4s ease;
}
.attrition-label { width:220px; font-size:0.90rem; color:var(--dre-text); }
.attrition-count { width:80px; text-align:right; font-size:0.90rem; color:var(--dre-teal); font-weight:700; }
.attrition-pct   { width:54px; text-align:right; font-size:0.84rem; color:var(--dre-muted); }
.attrition-exc   { color:var(--dre-error) !important; }
/* ── Metric boxes ── */
.metric-box {
  background:var(--dre-surface); border:1px solid var(--dre-border);
  border-radius:10px; padding:20px; text-align:center;
}
.metric-val { font-size:2rem; font-weight:700; color:var(--dre-teal); line-height:1.1; }
.metric-lab { font-size:0.84rem; color:var(--dre-muted); margin-top:4px; }
/* ── Empty state ── */
.empty-state { text-align:center; padding:60px 20px; color:var(--dre-muted); }
.empty-state .es-icon  { font-size:3rem; margin-bottom:16px; color:var(--dre-border); }
.empty-state .es-title { font-size:1.1rem; font-weight:600; color:var(--dre-text); margin-bottom:8px; }
/* ── Concept search modal ── */
.cs-row { padding:9px 13px; border-bottom:1px solid var(--dre-border); cursor:pointer; font-size:0.93rem; }
.cs-row:hover { background:var(--dre-teal-dim); }
.cs-domain-pill { display:inline-block; background:var(--dre-teal-dim); color:var(--dre-teal); border-radius:4px; padding:1px 7px; font-size:0.80rem; margin-left:6px; }
.modal-content { background:var(--dre-surface) !important; border:1px solid var(--dre-border) !important; }
.modal-header, .modal-footer { border-color:var(--dre-border) !important; }
.modal-title { color:var(--dre-text) !important; font-size:1.05rem !important; }
/* ── DT table ── */
.dataTables_wrapper, table.dataTable { background:transparent !important; color:var(--dre-text) !important; font-size:0.93rem !important; }
.dataTables_wrapper .dataTables_paginate .paginate_button { color:var(--dre-muted) !important; }
.dataTables_wrapper .dataTables_info { color:var(--dre-muted) !important; }
table.dataTable thead th { background:var(--dre-mid) !important; color:var(--dre-teal) !important; border-bottom:1px solid var(--dre-border) !important; font-size:0.84rem !important; }
table.dataTable tbody tr { background:var(--dre-surface) !important; }
table.dataTable tbody tr:hover { background:var(--dre-mid) !important; }
table.dataTable tbody td { border-top:1px solid var(--dre-border) !important; color:var(--dre-text) !important; }
/* ── Schema overview badges ── */
.domain-grid { display:grid; grid-template-columns:repeat(3,1fr); gap:7px; margin-top:10px; }
.domain-badge {
  background:var(--dre-mid); border:1px solid var(--dre-border);
  border-radius:6px; padding:5px 10px; font-size:0.84rem; color:var(--dre-text);
  display:flex; flex-direction:column; align-items:center;
  transition: border-color .15s, background .15s, transform .1s;
}
.domain-badge.has-data {
  border-color:rgba(0,197,181,.35); cursor:pointer;
}
.domain-badge.has-data:hover {
  background:rgba(0,197,181,.12); border-color:rgba(0,197,181,.7);
  transform:translateY(-2px);
}
.domain-badge.has-data:active { transform:translateY(0); }
.domain-badge.no-data  { opacity:.45; cursor:default; }
.domain-badge .db-label { font-size:0.77rem; color:var(--dre-muted); margin-top:2px; }
.domain-badge.has-data .db-icon { color:var(--dre-teal); }
.domain-badge-hint {
  font-size:0.72rem; color:rgba(0,197,181,.6); margin-top:3px; letter-spacing:.3px;
}
.schema-metrics { display:flex; gap:10px; flex-wrap:wrap; margin-bottom:10px; }
.schema-metric  {
  background:var(--dre-mid); border:1px solid var(--dre-border);
  border-radius:8px; padding:10px 16px; flex:1; min-width:120px;
}
.schema-metric .sm-val { font-size:1.4rem; font-weight:700; color:var(--dre-teal); line-height:1.1; }
.schema-metric .sm-lbl { font-size:0.80rem; color:var(--dre-muted); margin-top:3px; }
/* ── Criterion count badges ── */
.crit-count-badge {
  display:inline-flex; align-items:center; gap:5px;
  background:var(--dre-teal-dim); border:1px solid rgba(0,197,181,.25);
  border-radius:20px; padding:3px 10px; font-size:0.84rem;
  color:var(--dre-teal); margin-top:6px;
}
.crit-count-badge.zero    { background:rgba(224,92,110,.1);  border-color:rgba(224,92,110,.3);  color:var(--dre-error); }
.crit-count-badge.loading { background:rgba(139,163,181,.08); border-color:var(--dre-border); color:var(--dre-muted); }
/* ── Plain-English description box ── */
.plain-english-box {
  background:var(--dre-teal-dim); border:1px solid rgba(0,197,181,.3);
  border-radius:8px; padding:10px 15px; margin-bottom:14px;
  font-size:0.97rem; color:var(--dre-text); line-height:1.6;
}
/* ── Copy buttons in concept search ── */
.cp-btn {
  display:inline-block; font-size:0.75rem; padding:1px 7px;
  border:1px solid var(--dre-border); border-radius:4px;
  background:var(--dre-mid); color:var(--dre-muted);
  cursor:pointer; margin-left:5px; user-select:none;
  transition:background 0.15s, color 0.15s;
}
.cp-btn:hover { background:var(--dre-teal-dim); color:var(--dre-teal); }
.cp-btn.copied { background:rgba(0,197,181,.25); color:var(--dre-teal); }
.cs-cid { font-size:0.84rem; color:var(--dre-muted); margin-left:5px; }
/* ── KM outcome concept pills ── */
.km-concept-pill {
  display:inline-flex; align-items:center; gap:5px;
  background:var(--dre-teal-dim); border:1px solid rgba(0,197,181,.3);
  border-radius:20px; padding:3px 10px; font-size:0.87rem; color:var(--dre-teal);
  margin:3px 4px 3px 0;
}
.km-concept-pill .rm-x {
  cursor:pointer; font-size:0.95rem; color:var(--dre-muted); margin-left:2px;
}
.km-concept-pill .rm-x:hover { color:var(--dre-error); }
/* KM picker (v10.13 - browser-like rich picker) */
/* KM picker collapse (v10.13) */
.km-picker-header {
  display: flex; align-items: center; gap: 8px;
  cursor: pointer; user-select: none;
  padding: 4px 0 6px;
  transition: color .12s;
}
.km-picker-header:hover { color: var(--dre-teal); }
.km-picker-chevron {
  color: var(--dre-muted); font-size: 0.85rem;
  min-width: 14px; display: inline-block;
}
.km-picker-header:hover .km-picker-chevron { color: var(--dre-teal); }
.km-picker-title { margin: 0; cursor: pointer; }
.km-picker-body.collapsed { display: none; }

.km-picker-filter { margin-bottom:8px; }
.km-picker-list-body { background:rgba(0,0,0,.06); }
.km-picker-row {
  display:flex; align-items:center; gap:8px;
  padding:6px 10px; border-bottom:1px solid var(--dre-border);
  cursor:pointer; transition:background .12s;
}
.km-picker-row:last-child { border-bottom:none; }
.km-picker-row:hover {
  background:rgba(0,197,181,.06);
}
.km-picker-row-added { background:rgba(0,197,181,.05); }
.km-picker-row-added:hover { background:rgba(0,197,181,.05); }
.km-picker-add-mark {
  font-size:1.1rem; font-weight:700; color:var(--dre-teal);
  width:24px; text-align:center; opacity:0.6;
}
.km-picker-row:hover .km-picker-add-mark { opacity:1; }
.km-picker-added-mark {
  color:var(--dre-teal); width:24px; text-align:center;
}
/* ── Frequency pill (concept search) ── */
.freq-pill {
  display:inline-block; background:rgba(0,197,181,.12); color:var(--dre-teal);
  border-radius:4px; padding:1px 7px; font-size:0.80rem; margin-left:6px;
}
.freq-pill.has-data { background:rgba(0,197,181,.18); }
/* ── Missingness bars ── */
.miss-bar-bg  { background:var(--dre-border);border-radius:3px;height:6px; }
.miss-bar-fill{ height:6px;border-radius:3px;transition:width .4s; }
/* ── Comparative analysis ── */
.cohort-ab-badge {
  display:inline-flex; align-items:center; gap:8px;
  border-radius:8px; padding:8px 14px; font-size:0.93rem; font-weight:600;
  margin-bottom:4px;
}
.cohort-ab-badge.cohort-a { background:rgba(0,197,181,.15); border:1px solid rgba(0,197,181,.35); color:var(--dre-teal); }
.cohort-ab-badge.cohort-b { background:rgba(255,184,77,.10); border:1px solid rgba(255,184,77,.30); color:var(--dre-gold); }
.cohort-ab-badge.unset    { background:var(--dre-mid); border:1px solid var(--dre-border); color:var(--dre-muted); }
.love-plot-wrap { background:var(--dre-surface); border-radius:8px; padding:6px 0; }
.compare-hr-box {
  background:var(--dre-mid); border:1px solid var(--dre-border); border-radius:10px;
  padding:18px 24px; text-align:center;
}
.compare-hr-val { font-size:2.2rem; font-weight:700; color:var(--dre-teal); }
.compare-hr-ci  { font-size:0.93rem; color:var(--dre-muted); margin-top:4px; }
.compare-hr-p   { font-size:0.87rem; color:var(--dre-muted); margin-top:2px; }
.compare-step-badge {
  display:inline-flex; align-items:center; justify-content:center;
  width:24px; height:24px; border-radius:50%;
  background:var(--dre-teal); color:var(--dre-dark);
  font-size:0.80rem; font-weight:700; margin-right:8px; flex-shrink:0;
}
.btn-set-a { background:rgba(0,197,181,.2) !important; color:var(--dre-teal) !important; border:1px solid rgba(0,197,181,.4) !important; border-radius:8px !important; font-size:0.87rem !important; }
.btn-set-a:hover { background:rgba(0,197,181,.35) !important; }
.btn-set-b { background:rgba(255,184,77,.15) !important; color:var(--dre-gold) !important; border:1px solid rgba(255,184,77,.35) !important; border-radius:8px !important; font-size:0.87rem !important; }
.btn-set-b:hover { background:rgba(255,184,77,.28) !important; }
/* ── PS overlap / E-value / matched table ── */
.ps-overlap-wrap { background:var(--dre-surface); border-radius:8px; padding:6px 0; }
.evalue-box {
  background:var(--dre-mid); border:1px solid var(--dre-border);
  border-radius:10px; padding:16px 20px;
}
.evalue-val { font-size:2rem; font-weight:700; color:var(--dre-gold); line-height:1.1; }
.evalue-ci  { font-size:0.90rem; color:var(--dre-muted); margin-top:3px; }
.evalue-interp { font-size:0.84rem; color:var(--dre-text); margin-top:10px; line-height:1.5; }
.balance-good { color:var(--dre-success); font-weight:600; }
.balance-warn { color:var(--dre-gold);    font-weight:600; }
.balance-poor { color:var(--dre-error);   font-weight:600; }
.export-results-bar {
  display:flex; gap:10px; align-items:center; flex-wrap:wrap;
  padding:12px 0 4px;
}
/* ── Sidebar compare AB indicator ── */
.ab-sidebar-panel {
  padding:8px 14px 10px;
}
.ab-sidebar-label {
  font-size:0.75rem; font-weight:700; color:var(--dre-muted);
  text-transform:uppercase; letter-spacing:.6px; margin-bottom:6px;
}
.ab-indicator {
  display:flex; align-items:center; gap:7px;
  font-size:0.84rem; padding:4px 0;
}
.ab-dot {
  width:9px; height:9px; border-radius:50%; flex-shrink:0;
}
.ab-dot.set   { background:var(--dre-teal); box-shadow:0 0 5px rgba(0,197,181,.5); }
.ab-dot.set-b { background:var(--dre-gold); box-shadow:0 0 5px rgba(255,184,77,.5); }
.ab-dot.unset { background:var(--dre-border); }
.ab-label-set   { color:var(--dre-teal); font-weight:600; }
.ab-label-set-b { color:var(--dre-gold); font-weight:600; }
.ab-label-unset { color:var(--dre-muted); font-style:italic; }
/* ── File browser modal ── */
.fb-modal-breadcrumb { padding:6px 0 12px; font-size:0.87rem; color:var(--dre-muted); }
.fb-crumb-link { color:var(--dre-teal) !important; cursor:pointer; }
.fb-crumb-sep  { color:var(--dre-muted); }
.fb-modal-row  { display:flex; align-items:center; gap:10px; padding:9px 12px;
  border-radius:6px; cursor:pointer; font-size:0.97rem; color:var(--dre-text); }
.fb-modal-row:hover { background:var(--dre-teal-dim); }
.fb-modal-dir  { color:var(--dre-teal); }
.fb-modal-file { }
.fb-modal-name { flex:1; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
.fb-modal-size { font-size:0.84rem; color:var(--dre-muted); }
.fb-modal-empty { color:var(--dre-muted); font-style:italic; padding:16px 0; }
/* ── Cohort run error panel ───────────────────────────────────────────────── */
.cohort-error-panel {
  background:rgba(224,92,110,0.1); border:1px solid rgba(224,92,110,0.4);
  border-left:4px solid var(--dre-danger); border-radius:8px;
  padding:14px 18px; margin-bottom:14px;
}
.cohort-error-title { color:var(--dre-danger); font-weight:700; font-size:0.97rem; margin-bottom:8px; }
.cohort-error-msg {
  margin:0; color:var(--dre-text); background:transparent; border:none;
  font-family:'Cascadia Code','JetBrains Mono',Consolas,monospace;
  font-size:0.84rem; white-space:pre-wrap; word-break:break-all; max-height:200px; overflow:auto;
}

/* ── Global search bar ──────────────────────────────────────────────────────── */
.global-search-bar {
  background:var(--dre-surface); border:1px solid rgba(0,197,181,.3);
  border-radius:10px; padding:16px 20px; margin-bottom:16px;
}
.gsb-label { font-size:0.93rem; font-weight:700; color:var(--dre-teal); margin-bottom:10px; }
.gsb-input-wrap { position:relative; }
.gsb-input-wrap .gsb-spinner {
  position:absolute; right:12px; top:50%; transform:translateY(-50%);
  color:var(--dre-teal); font-size:0.9rem; display:none;
}
.gsb-input-wrap.searching .gsb-spinner { display:block; }
.gsb-hint { font-size:0.80rem; color:var(--dre-muted); margin-top:4px; }
.gsb-results { margin-top:8px; border:1px solid var(--dre-border); border-radius:8px; overflow:hidden; }

/* ── Criterion row sub-sections ──────────────────────────────────────────────── */
.crit-row-header { display:flex; align-items:center; justify-content:space-between; margin-bottom:14px; }
.crit-sub-row { margin-bottom:12px; padding-bottom:12px; border-bottom:1px solid rgba(255,255,255,0.05); }
.crit-sub-row:last-child { border-bottom:none; margin-bottom:0; padding-bottom:0; }
.crit-sublabel { display:block; font-size:0.84rem !important; color:var(--dre-teal) !important; font-weight:700 !important; margin-bottom:6px !important; }
.crit-hint { font-size:0.84rem; color:var(--dre-muted); margin:3px 0 8px; }
.crit-hint-chip { font-size:0.84rem; color:var(--dre-muted); font-style:italic; }

/* ── Concept chips container ─────────────────────────────────────────────────── */
.concept-chips-container { display:flex; flex-wrap:wrap; align-items:center; gap:6px; min-height:34px; }
.concept-find-btn { flex-shrink:0; }

/* ── Template cards ──────────────────────────────────────────────────────────── */
.tmpl-card {
  background:var(--dre-mid); border:1px solid var(--dre-border);
  border-radius:8px; padding:12px 16px; margin-bottom:6px; cursor:pointer;
  transition: border-color .15s, background .15s;
}
.tmpl-card:hover { border-color:rgba(0,197,181,.5); background:rgba(0,197,181,.07); }
.tmpl-card-name { color:var(--dre-teal); font-weight:700; font-size:0.97rem; margin-bottom:3px; }
.tmpl-card-desc { color:var(--dre-text); font-size:0.87rem; margin-bottom:4px; }
.tmpl-card-meta { font-size:0.78rem; color:var(--dre-muted); }

/* ── First-run banner ────────────────────────────────────────────────────────── */
.first-run-banner {
  background:linear-gradient(135deg, rgba(0,197,181,.12) 0%, rgba(0,197,181,.05) 100%);
  border:1px solid rgba(0,197,181,.3); border-radius:10px;
  padding:18px 20px; margin-bottom:16px;
}
.frb-content {}
.frb-steps { display:flex; gap:18px; flex-wrap:wrap; margin-bottom:4px; }
.frb-step { display:flex; align-items:flex-start; gap:12px; flex:1; min-width:180px; }
.frb-step-num {
  background:var(--dre-teal); color:var(--dre-dark); font-weight:700; font-size:0.93rem;
  width:26px; height:26px; border-radius:50%; display:flex; align-items:center;
  justify-content:center; flex-shrink:0;
}
.frb-step-text b { color:var(--dre-text); font-size:0.93rem; }
.frb-step-text span { color:var(--dre-muted); font-size:0.84rem; }

/* ── Next steps panel (Results tab) ──────────────────────────────────────────── */
.next-steps-panel {
  background:rgba(61,214,140,.08); border:1px solid rgba(61,214,140,.3);
  border-left:4px solid var(--dre-success); border-radius:8px;
  padding:16px 20px; margin-bottom:16px;
}
.nsp-title { color:var(--dre-success); font-weight:700; font-size:1rem; margin-bottom:6px; }
.nsp-actions { display:flex; gap:12px; flex-wrap:wrap; }
.nsp-action {
  background:var(--dre-surface); border:1px solid var(--dre-border);
  border-radius:8px; padding:12px 14px; flex:1; min-width:180px;
}
.nsp-action b { color:var(--dre-teal); font-size:0.93rem; }
.nsp-action p { color:var(--dre-muted); font-size:0.84rem; margin:4px 0 0; }

/* ── Suggestion cards (first-run banner) ─────────────────────────────────────── */
.frb-title { font-size:1rem; font-weight:700; color:var(--dre-teal); margin-bottom:6px; }
.frb-subtitle { font-size:0.87rem; color:var(--dre-muted); margin-bottom:14px; }
.frb-footer { margin-top:14px; display:flex; align-items:center; }

.suggestion-grid {
  display:grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap:10px;
}
.suggestion-card {
  background:var(--dre-mid); border:1px solid var(--dre-border);
  border-radius:8px; padding:13px 14px; cursor:pointer;
  transition: border-color .15s, box-shadow .15s;
}
.suggestion-card:hover {
  border-color:rgba(0,197,181,.5);
  box-shadow: 0 0 0 2px rgba(0,197,181,.12);
}
.sc-top { display:flex; align-items:flex-start; justify-content:space-between; gap:8px; margin-bottom:4px; }
.sc-name { font-weight:700; font-size:0.93rem; color:var(--dre-text); line-height:1.3; }
.sc-score {
  font-size:0.75rem; font-weight:700; padding:2px 7px; border-radius:12px;
  white-space:nowrap; flex-shrink:0; margin-top:1px;
}
.score-high { background:rgba(61,214,140,.18); color:#3dd68c; }
.score-mid  { background:rgba(255,184,77,.18); color:#FFB84D; }
.score-low  { background:rgba(224,92,110,.18); color:var(--dre-error); }
.score-none { background:rgba(139,163,181,.12); color:var(--dre-muted); }

.sc-category { font-size:0.75rem; color:var(--dre-muted); margin-bottom:6px; }
.sc-evidence { margin-bottom:4px; }
.sc-ev-row { font-size:0.81rem; color:var(--dre-teal); display:flex; align-items:center; gap:4px; line-height:1.5; }
.sc-partial { font-size:0.77rem; color:var(--dre-muted); border-top:1px solid var(--dre-border); padding-top:5px; margin-top:5px; }

/* ── Template cards (modal) ──────────────────────────────────────────────────── */
.tmpl-card-top { display:flex; align-items:flex-start; justify-content:space-between; gap:8px; margin-bottom:3px; }
.tmpl-card-live { border-color:rgba(0,197,181,.15); }
.tmpl-card-live:hover { border-color:rgba(0,197,181,.5); }
.tmpl-card-dim { opacity:0.55; cursor:default; }
.tmpl-card-dim:hover { border-color:var(--dre-border) !important; }
.tmpl-card-evidence { margin:5px 0 2px; }
.tmpl-card-unavail { font-size:0.79rem; color:var(--dre-muted); margin-top:6px; }

/* ── Extract status box ─────────────────────────────────────────────────────── */
.extract-status-box {
  background:var(--dre-surface); border:1px solid var(--dre-border);
  border-left:4px solid var(--dre-success); border-radius:8px;
  padding:14px 16px; margin-top:14px;
}
.extract-status-box table { font-size:0.84rem; }
.extract-status-box tr:nth-child(even) td { background:rgba(255,255,255,0.03); }

/* ── Results tab plots ───────────────────────────────────────────────────────── */
.shiny-plot-output {
  border-radius: 6px;
  overflow: hidden;
}

/* ── Table 1 ─────────────────────────────────────────────────────────────────── */
#table1_dt table { font-size: 0.87rem !important; }
#table1_dt td:first-child { padding-left: 8px !important; }
#table1_dt td:last-child  { text-align: right !important; font-variant-numeric: tabular-nums; }

/* ── Characterisation tab ────────────────────────────────────────────────────── */
.char-stat-row {
  display: flex; gap: 16px; flex-wrap: wrap; margin-bottom: 12px;
}
.char-stat {
  background: var(--dre-mid); border: 1px solid var(--dre-border);
  border-radius: 8px; padding: 10px 14px; flex: 1; min-width: 100px; text-align: center;
}
.char-stat-val {
  font-size: 1.3rem; font-weight: 700; color: var(--dre-teal); line-height: 1.2;
}
.char-stat-lab {
  font-size: 0.78rem; color: var(--dre-muted); margin-top: 2px;
}

/* ── Misc ── */
.rs-card { background:var(--dre-surface); border:1px solid var(--dre-border); border-radius:8px; padding:14px 18px; }
.rs-num  { font-size:1.75rem; font-weight:700; color:var(--dre-teal); line-height:1.1; }
.rs-lbl  { font-size:0.84rem; color:var(--dre-muted); margin-top:3px; }
.shiny-notification { background:var(--dre-surface) !important; border-left:3px solid var(--dre-teal) !important; color:var(--dre-text) !important; }
.shiny-notification-error { border-left-color:var(--dre-error) !important; }
.shiny-progress-container { background:var(--dre-surface) !important; }
.progress-bar { background:var(--dre-teal) !important; }
hr  { border-color:var(--dre-border) !important; }
.well { background:var(--dre-surface) !important; border-color:var(--dre-border) !important; }
/* ── Multi-schema styles (v6) ── */
.schema-check-item { display:flex; align-items:center; gap:6px;
  font-size:0.85rem; color:var(--dre-text); padding:4px 0; }
input[type=checkbox].schema-cb { accent-color:var(--dre-teal); width:14px; height:14px; }
.vocab-panel { padding:10px 12px; border-radius:6px; margin:8px 0;
  font-size:0.85rem; border:1px solid; }
.vocab-green { background:rgba(61,214,140,.1); border-color:rgba(61,214,140,.3); color:#3DD68C; }
.vocab-amber { background:rgba(255,184,77,.1);  border-color:rgba(255,184,77,.3);  color:#FFB84D; }
.vocab-red   { background:rgba(224,92,110,.1);  border-color:rgba(224,92,110,.3);  color:#E05C6E; }
.vocab-issue { font-size:0.80rem; color:var(--dre-muted); margin:2px 0 0 18px; }
.overlap-panel { padding:10px 12px; border-radius:6px; margin:8px 0;
  font-size:0.85rem; border:1px solid; }
.overlap-full    { background:rgba(61,214,140,.1);  border-color:rgba(61,214,140,.3);  color:#3DD68C; }
.overlap-partial { background:rgba(255,184,77,.1);  border-color:rgba(255,184,77,.3);  color:#FFB84D; }
.overlap-none    { background:rgba(224,92,110,.1);  border-color:rgba(224,92,110,.3);  color:#E05C6E; }
.schema-source-badge { display:inline-block; font-size:0.75rem; font-weight:700;
  padding:1px 7px; border-radius:10px; margin-right:4px;
  background:var(--dre-teal-dim); color:var(--dre-teal); }
.multi-cohort-banner { padding:10px 14px; background:var(--dre-mid);
  border:1px solid var(--dre-teal); border-radius:8px; margin-bottom:12px;
  font-size:0.87rem; color:var(--dre-teal); }
.save-cohort-panel { padding:14px 16px; background:var(--dre-surface);
  border:1px solid var(--dre-border); border-radius:8px; margin-bottom:12px; }
.sc-schema-breakdown { font-size:0.79rem; color:var(--dre-muted); margin-top:4px; }

/* ── Concept Browser (v10.12) ────────────────────────────────────────────────── */
.cb-browser-filters {
  background:var(--dre-surface); border:1px solid var(--dre-border);
  border-radius:10px; padding:12px 16px; margin-bottom:14px;
}
.cb-browser-list-card  {
  padding:0 !important; overflow:hidden;
  /* v10.13: Fixed component height. Inside, flex column means the list
     body flexes to fill whatever space isn't used by the Venn diagram.
     When Venn is present, fewer rows visible; when absent, more rows.
     Total component height stays the same. */
  height: calc(100vh - 220px);
  display: flex;
  flex-direction: column;
}
/* The uiOutput wrappers Shiny inserts need explicit flex behaviour.
   The list_ui wrapper grows; others (overlap_ui, filter_chrome_ui) take
   only the space they need. */
.cb-browser-list-card > #browser_list_ui {
  flex: 1 1 auto;
  min-height: 0;       /* required for flex children to scroll */
  overflow: hidden;    /* its child .browser-list-body handles overflow */
  display: flex;
  flex-direction: column;
}
.cb-browser-detail-card {
  display:flex; flex-direction:column;
  min-height:0;
  /* v10.13: cap to viewport - leave room for the sticky drawer below */
  max-height: calc(100vh - 220px);
  padding:0 !important; overflow:hidden;
}

/* Mode tabs */
.browser-mode-tabs {
  display:flex; border-bottom:1px solid var(--dre-border);
  background:var(--dre-mid); border-radius:10px 10px 0 0;
}
.browser-mode-tab {
  flex:1; text-align:center; padding:10px 4px; font-size:0.84rem;
  color:var(--dre-muted); cursor:pointer; border-bottom:2px solid transparent;
  transition:color .15s, border-color .15s;
}
.browser-mode-tab.active {
  color:var(--dre-teal); border-bottom-color:var(--dre-teal);
}
.browser-mode-tab.disabled {
  opacity:.4; cursor:not-allowed; pointer-events:none;
}
.browser-mode-tab:not(.disabled):not(.active):hover { color:var(--dre-text); }

/* List body - flexes to fill the renderUI wrapper which itself flexes to
   fill the list card. The body's content (rows + count line + sort header
   render order matters: sort header and count line are fixed-height, list
   rows take the rest). */
.browser-list-body {
  flex: 1 1 auto;
  min-height: 0;
  overflow-y: auto;
}
.browser-list-row {
  display:flex; align-items:center; gap:10px;
  padding:9px 14px; border-bottom:1px solid var(--dre-border);
  cursor:pointer; transition:background .1s;
}
.browser-list-row:hover { background:var(--dre-teal-dim); }
.browser-list-row.selected { background:rgba(0,197,181,.15); border-left:3px solid var(--dre-teal); }
.browser-list-row:last-child { border-bottom:none; }
.blr-main { flex:1; min-width:0; }
.blr-name { font-size:0.93rem; color:var(--dre-text); white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }
.blr-meta { font-size:0.77rem; color:var(--dre-muted); margin-top:1px; }
.blr-pill {
  font-size:0.75rem; font-weight:700; border-radius:10px;
  padding:2px 8px; white-space:nowrap; flex-shrink:0;
}
.blr-pill.has-data { background:var(--dre-teal-dim); color:var(--dre-teal); }
.blr-pill.no-data  { background:var(--dre-mid);      color:var(--dre-muted); }
.blr-std { font-size:0.72rem; color:var(--dre-teal); flex-shrink:0; }

/* Multi-schema pills (v10.13) */
.blr-pills { display:flex; gap:4px; flex-shrink:0; align-items:center; flex-wrap:wrap; justify-content:flex-end; max-width:55%; }
.blr-pill-sch {
  font-size:0.72rem; font-weight:700; border-radius:8px;
  padding:2px 7px; white-space:nowrap; line-height:1.3;
  border:1px solid transparent;
}
/* Stable position-based colour key - sch-1..sch-4 match cohort schema slots */
.blr-pill-sch.sch-1 { background:rgba(0,197,181,.16);  color:#5ee5d2; border-color:rgba(0,197,181,.4); }
.blr-pill-sch.sch-2 { background:rgba(126,160,255,.16);color:#a8c0ff; border-color:rgba(126,160,255,.4); }
.blr-pill-sch.sch-3 { background:rgba(255,176,102,.16);color:#ffc88c; border-color:rgba(255,176,102,.4); }
.blr-pill-sch.sch-4 { background:rgba(213,143,255,.16);color:#dba5ff; border-color:rgba(213,143,255,.4); }
.blr-pill-sch.sch-empty { opacity:.35; font-weight:500; }
.blr-pill-summary {
  font-size:0.7rem; font-weight:700; border-radius:8px;
  padding:2px 7px; white-space:nowrap; line-height:1.3;
}
.blr-pill-summary.all-present { background:rgba(0,197,181,.22); color:var(--dre-teal); border:1px solid var(--dre-teal); }
.blr-pill-summary.partial     { background:var(--dre-mid);      color:var(--dre-text);  border:1px solid var(--dre-border); }
.blr-pill-summary.none        { background:var(--dre-mid);      color:var(--dre-muted); border:1px solid var(--dre-border); }
/* Row highlight when concept is in every selected schema */
.browser-list-row.in-all-schemas {
  background:linear-gradient(90deg, rgba(0,197,181,.07), transparent 60%);
  box-shadow:inset 3px 0 0 var(--dre-teal);
}
.browser-list-row.in-all-schemas.selected {
  background:linear-gradient(90deg, rgba(0,197,181,.18), rgba(0,197,181,.06) 60%);
}

/* Hierarchy + Vocabulary mode chrome (v10.13) */
.browser-crumb {
  display:flex; flex-wrap:wrap; align-items:center; gap:6px;
  padding:8px 14px; border-bottom:1px solid var(--dre-border);
  font-size:0.85rem; color:var(--dre-muted);
  background:rgba(0,0,0,.1);
}
.browser-crumb-link {
  cursor:pointer; color:var(--dre-teal);
  padding:2px 6px; border-radius:4px;
}
.browser-crumb-link:hover { background:var(--dre-teal-dim); }
.browser-crumb-link.current {
  color:var(--dre-text); font-weight:600; cursor:default;
}
.browser-crumb-link.current:hover { background:transparent; }
.browser-crumb-sep { color:var(--dre-muted); opacity:.6; }
.browser-crumb-spacer { flex:1; }
.browser-crumb-refresh {
  cursor:pointer; color:var(--dre-muted);
  padding:2px 8px; border-radius:4px;
  font-size:0.85rem;
}
.browser-crumb-refresh:hover { color:var(--dre-teal); background:var(--dre-teal-dim); }

/* Schema overlap Venn (v10.13) */
.browser-overlap-card {
  border-bottom:1px solid var(--dre-border);
  background:rgba(0,0,0,.08);
  padding:10px 14px 12px;
}
.browser-overlap-header {
  display:flex; align-items:center; gap:10px;
  margin-bottom:8px;
}
.browser-overlap-title {
  font-size:0.78rem; text-transform:uppercase; letter-spacing:.6px;
  color:var(--dre-muted); font-weight:700;
}
.browser-overlap-spacer { flex:1; }
.browser-overlap-refresh {
  cursor:pointer; color:var(--dre-muted);
  padding:2px 8px; border-radius:4px; font-size:0.85rem;
}
.browser-overlap-refresh:hover { color:var(--dre-teal); background:var(--dre-teal-dim); }
.browser-overlap-filter-pill {
  cursor:pointer; font-size:0.72rem;
  background:var(--dre-teal-dim); color:var(--dre-teal);
  padding:2px 8px; border-radius:10px;
  border:1px solid var(--dre-teal);
}
.browser-overlap-filter-pill:hover { background:rgba(0,197,181,.3); }
.browser-overlap-body {
  display:grid; grid-template-columns: 1fr 1fr; gap:12px;
  align-items:center;
}
.browser-overlap-svg-wrap { min-width:0; }
.browser-overlap-svg { display:block; max-width:100%; }
.browser-overlap-legend-wrap { font-size:0.78rem; }
.browser-overlap-legend-total {
  font-size:0.76rem; color:var(--dre-muted); margin-bottom:6px;
}
.browser-overlap-legend-table {
  width:100%; border-collapse:collapse;
}
.browser-overlap-legend-row {
  cursor:pointer; transition:background .1s;
}
.browser-overlap-legend-row:hover {
  background:var(--dre-teal-dim);
}
.browser-overlap-legend-row.active {
  background:rgba(0,197,181,.18);
  outline:1px solid var(--dre-teal);
}
.browser-overlap-legend-row td {
  padding:4px 6px; border-bottom:1px solid var(--dre-border);
}
.browser-overlap-legend-row:last-child td { border-bottom:none; }
.bol-pill-row { display:flex; gap:3px; }
.bol-sch {
  font-size:0.66rem; font-weight:700;
  border-radius:4px; padding:1px 4px; line-height:1.4;
  border:1px solid transparent; white-space:nowrap;
}
.bol-sch.sch-1 { background:rgba(0,197,181,.18); color:#5ee5d2; border-color:rgba(0,197,181,.5); }
.bol-sch.sch-2 { background:rgba(126,160,255,.18); color:#a8c0ff; border-color:rgba(126,160,255,.5); }
.bol-sch.sch-3 { background:rgba(255,176,102,.18); color:#ffc88c; border-color:rgba(255,176,102,.5); }
.bol-sch.sch-empty { opacity:.25; font-weight:500; }
.bol-count {
  text-align:right; font-variant-numeric:tabular-nums;
  color:var(--dre-text); font-weight:600;
}
.browser-overlap-skip {
  font-size:0.82rem; color:var(--dre-muted);
  padding:8px 0;
}

/* Selected concepts drawer (v10.13) - sits as a separate card below the
   detail panel in the right column. Width matches the column. */
.browser-selected-drawer {
  background:var(--dre-surface);
  border:1px solid var(--dre-border);
  border-radius:10px;
  margin-top:10px;
  overflow:hidden;
}
.browser-selected-drawer.empty .browser-selected-header {
  cursor:default; color:var(--dre-muted); font-style:italic;
  padding:8px 14px;
}
.browser-selected-header {
  display:flex; align-items:center; gap:10px;
  padding:10px 14px; cursor:pointer;
  user-select:none; font-size:0.85rem; font-weight:600;
  color:var(--dre-text);
  transition:background .12s;
}
.browser-selected-header:hover {
  background:rgba(0,197,181,.06);
}
.browser-selected-title { display:flex; align-items:center; gap:8px; }
.browser-selected-spacer { flex:1; }
.browser-selected-toggle-hint {
  font-size:0.72rem; color:var(--dre-muted); font-weight:400;
}
.browser-selected-body {
  padding:0 14px 8px; max-height:240px; overflow-y:auto;
}
.bsd-section { margin-top:10px; }
.bsd-section-label {
  font-size:0.72rem; text-transform:uppercase; letter-spacing:.5px;
  color:var(--dre-muted); margin-bottom:4px;
}
.bsd-section.inc .bsd-section-label { color:#5ee5d2; }
.bsd-section.exc .bsd-section-label { color:#ff8b8b; }
.bsd-item {
  display:flex; align-items:center; gap:8px;
  padding:5px 8px; margin-bottom:3px;
  border-radius:5px;
  background:rgba(255,255,255,.03);
  border-left:3px solid transparent;
  font-size:0.83rem;
}
.bsd-item.bsd-inc { border-left-color:#00C5B5; }
.bsd-item.bsd-exc { border-left-color:#ff6b6b; }
.bsd-item:hover { background:rgba(255,255,255,.06); }
.bsd-item-name { flex:1; display:flex; align-items:center; gap:6px; min-width:0; }
.bsd-item-concept-name {
  overflow:hidden; text-overflow:ellipsis; white-space:nowrap;
}
.bsd-item-cid {
  font-size:0.72rem; color:var(--dre-muted); font-variant-numeric:tabular-nums;
}
.bsd-desc {
  color:var(--dre-teal); font-size:0.78rem;
  padding:1px 5px; border-radius:3px;
  background:var(--dre-teal-dim);
}
.bsd-remove {
  cursor:pointer; color:var(--dre-muted);
  padding:2px 6px; border-radius:3px;
  transition:color .12s, background .12s;
}
.bsd-remove:hover {
  color:#ff8b8b; background:rgba(255,107,107,.1);
}
.browser-selected-actions {
  display:flex; gap:8px; align-items:center;
  padding:10px 14px;
  border-top:1px solid var(--dre-border);
}
.browser-selected-actions-mini {
  display:flex; gap:6px; align-items:center;
  padding:0 14px 10px;
}
.browser-selected-actions .btn-sm,
.browser-selected-actions-mini .btn-sm {
  font-size:0.83rem;
}

/* Sidebar nav state badges (v10.13) */
.cb-nav-has-state > a::after {
  content:' '; display:inline-block;
  width:8px; height:8px; border-radius:50%;
  background:var(--dre-teal);
  margin-left:8px; vertical-align:middle;
  box-shadow:0 0 6px rgba(0,197,181,.6);
}

/* Quick filter input + sort header (v10.13) */
.browser-list-filter {
  padding:8px 12px 6px;
  border-bottom:1px solid var(--dre-border);
}
.browser-list-filter-input {
  width:100%; box-sizing:border-box;
  background:var(--dre-mid); color:var(--dre-text);
  border:1px solid var(--dre-border); border-radius:6px;
  padding:6px 10px; font-size:0.85rem;
  outline:none; transition:border-color .15s;
}
.browser-list-filter-input:focus { border-color:var(--dre-teal); }
.browser-list-filter-input::placeholder { color:var(--dre-muted); }
.browser-list-sort-header {
  display:flex; gap:6px; align-items:center;
  padding:6px 12px; border-bottom:1px solid var(--dre-border);
  background:rgba(0,0,0,.12); font-size:0.72rem;
  text-transform:uppercase; letter-spacing:.5px;
  color:var(--dre-muted); user-select:none; flex-wrap:wrap;
}
.bls-col {
  cursor:pointer; padding:2px 8px; border-radius:4px;
  white-space:nowrap; transition:color .1s, background .1s;
}
.bls-col:hover { color:var(--dre-text); background:rgba(0,197,181,.1); }
.bls-col.active { color:var(--dre-teal); font-weight:700; background:var(--dre-teal-dim); }
/* Right-align numeric columns visually - flex order trick: numeric cols
   sit on the right side of the header by pushing left-side cols to the
   left and adding a spacer. Simpler: give numeric cols margin-left:auto
   on the first one and let the rest sit after it. */
.bls-col.col-persons,
.bls-col.col-records,
.bls-col.col-n_concepts,
.bls-col.col-n_schemas_present { margin-left:0; }
.bls-col.col-persons:first-of-type,
.bls-col.col-records:first-of-type,
.bls-col.col-n_concepts:first-of-type,
.bls-col.col-n_schemas_present:first-of-type { margin-left:auto; }
.hier-drill {
  font-size:0.72rem; color:var(--dre-muted); margin-left:6px;
  flex-shrink:0;
}
.hier-drill.leaf { font-style:italic; opacity:.5; }
.browser-list-row.hier-row { cursor:pointer; }
.browser-list-row.vocab-row { cursor:pointer; }
.browser-list-row.vocab-row .blr-name {
  font-weight:600; color:var(--dre-teal);
}

/* Detail-panel Hierarchy sub-tab (v10.13) */
.hier-detail-section-header {
  font-size:0.72rem; color:var(--dre-muted);
  text-transform:uppercase; letter-spacing:.6px; font-weight:700;
  padding:8px 6px 4px; margin-top:6px;
}
.hier-detail-section-header.empty {
  color:var(--dre-muted); opacity:.55; font-style:italic;
  text-transform:none; letter-spacing:normal; font-weight:500;
}
.hier-detail-row {
  display:flex; align-items:center; gap:8px;
  padding:7px 8px; border-bottom:1px solid var(--dre-border);
  cursor:pointer; transition:background .1s;
  border-radius:4px;
}
.hier-detail-row:hover { background:var(--dre-teal-dim); }
.hier-detail-row:last-child { border-bottom:none; }
.hier-detail-main { flex:1; min-width:0; display:flex; align-items:center; gap:6px; flex-wrap:wrap; }
.hier-detail-name { font-size:0.9rem; color:var(--dre-text); }
.hier-detail-meta {
  font-size:0.74rem; color:var(--dre-muted);
  margin-left:8px; white-space:nowrap;
  overflow:hidden; text-overflow:ellipsis;
}
.hier-detail-marker {
  font-size:0.72rem; color:var(--dre-muted);
  margin-right:4px;
}
.hier-detail-marker.current { color:var(--dre-teal); font-size:0.9rem; }
.hier-detail-row.hier-detail-current {
  background:rgba(0,197,181,.10);
  border-left:3px solid var(--dre-teal);
  cursor:default;
}
.hier-detail-row.hier-detail-current:hover {
  background:rgba(0,197,181,.10);
}
.hier-detail-row.hier-detail-current .hier-detail-name {
  font-weight:700; color:var(--dre-teal);
}

/* Detail panel */
.browser-detail-header {
  padding:14px 16px 10px; border-bottom:1px solid var(--dre-border);
  background:var(--dre-mid); border-radius:10px 10px 0 0;
}
.browser-detail-empty {
  display:flex; align-items:center; justify-content:center;
  flex:1; color:var(--dre-muted); font-size:0.93rem; padding:40px 20px;
  text-align:center;
}
.browser-detail-tabs {
  display:flex; border-bottom:1px solid var(--dre-border);
  background:var(--dre-surface); padding:0 16px;
}
.browser-detail-tab {
  padding:8px 14px; font-size:0.84rem; color:var(--dre-muted);
  cursor:pointer; border-bottom:2px solid transparent;
}
.browser-detail-tab.active  { color:var(--dre-teal); border-bottom-color:var(--dre-teal); }
.browser-detail-tab.disabled { opacity:.4; cursor:not-allowed; pointer-events:none; }
.browser-detail-body { flex:1; padding:14px 16px; overflow-y:auto; max-height:340px; }
.browser-detail-stat { display:flex; gap:12px; flex-wrap:wrap; margin-bottom:14px; }
.browser-detail-stat-box {
  background:var(--dre-mid); border:1px solid var(--dre-border);
  border-radius:8px; padding:8px 14px; flex:1; min-width:90px; text-align:center;
}
.bds-val { font-size:1.2rem; font-weight:700; color:var(--dre-teal); line-height:1.2; }
.bds-lbl { font-size:0.77rem; color:var(--dre-muted); margin-top:2px; }

/* Per-schema breakdown row inside KPI cards (v10.13) */
.bds-sch-row {
  display:flex; gap:4px; flex-wrap:wrap; justify-content:center;
  margin-top:6px; padding-top:6px; border-top:1px solid var(--dre-border);
}
.bds-sch {
  font-size:0.68rem; font-weight:600;
  border-radius:6px; padding:1px 6px; line-height:1.4;
  border:1px solid transparent; white-space:nowrap;
}
.bds-sch.sch-1 { background:rgba(0,197,181,.16);  color:#5ee5d2; border-color:rgba(0,197,181,.4); }
.bds-sch.sch-2 { background:rgba(126,160,255,.16);color:#a8c0ff; border-color:rgba(126,160,255,.4); }
.bds-sch.sch-3 { background:rgba(255,176,102,.16);color:#ffc88c; border-color:rgba(255,176,102,.4); }
.bds-sch.sch-4 { background:rgba(213,143,255,.16);color:#dba5ff; border-color:rgba(213,143,255,.4); }
.bds-sch.sch-empty { opacity:.35; font-weight:500; }

/* Action footer */
.browser-action-footer {
  border-top:1px solid var(--dre-border); padding:10px 16px;
  display:flex; gap:8px; align-items:center; flex-wrap:wrap;
  background:var(--dre-surface); border-radius:0 0 10px 10px;
}
.browser-search-wrap input { padding-right:30px; }

/* ── Schema Profile collapsible card (v10.12) ────────────────────────────────── */
.cb-card details > summary { outline: none; }
.cb-card details > summary::-webkit-details-marker { display: none; }
.cb-card details[open] > summary .details-arrow { transform: rotate(180deg); }

/* ── Sidebar accordion sections (v10.13) ──────────────────────────────────── */
.sidebar-section { margin-bottom: 2px; }
.sidebar-section-header {
  display: flex; align-items: center; gap: 8px;
  padding: 10px 16px; cursor: pointer;
  user-select: none;
  transition: background .12s;
}
.sidebar-section-header:hover { background: rgba(0,197,181,.06); }
.sidebar-section-chevron {
  color: var(--dre-muted); font-size: 0.75rem; width: 12px;
}
.sidebar-section-title {
  color: var(--dre-teal); font-size: 0.78rem;
  text-transform: uppercase; letter-spacing: .7px; font-weight: 700;
}
.sidebar-section-spacer { flex: 1; }
.sidebar-section-body { padding: 0 16px 8px; }
.sidebar-section.collapsed .sidebar-section-body { display: none; }

/* ── Sidebar group labels (v10.12) ──────────────────────────────────────────── */
.sidebar-menu .sidebar-group-label {
  color: var(--dre-teal) !important;
  font-size: 0.72rem !important;
  text-transform: uppercase;
  letter-spacing: 0.7px;
  font-weight: 700;
  padding: 14px 16px 6px;
  pointer-events: none;
  border-top: 1px solid var(--dre-border);
  margin-top: 6px;
}
.sidebar-menu li.sidebar-group-label:first-child {
  border-top: none;
  margin-top: 0;
}

