    tags$head(tags$script(HTML("
Shiny.addCustomMessageHandler('cb_set_subtab_active', function(tab) {
  var ids = {overview: 'bdt_overview', hier: 'bdt_hier', cooccur: 'bdt_cooccur', samples: 'bdt_samples', aira: 'bdt_aira'};
  for (var k in ids) {
    var el = document.getElementById(ids[k]);
    if (!el) continue;
    if (k === tab) el.classList.add('active'); else el.classList.remove('active');
  }
});
Shiny.addCustomMessageHandler('cb_set_mode_active', function(mode) {
  var ids = {prevalence: 'bmt_prevalence', hierarchy: 'bmt_hierarchy', vocabulary: 'bmt_vocabulary'};
  for (var k in ids) {
    var el = document.getElementById(ids[k]);
    if (!el) continue;
    if (k === mode) el.classList.add('active'); else el.classList.remove('active');
  }
});
Shiny.addCustomMessageHandler('cb_clear_filter_inputs', function(_) {
  // Clear both DOM value and Shiny input value for the per-tab filters.
  ['browser_hier_filter_input', 'browser_vocab_filter_input'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.value = '';
  });
  Shiny.setInputValue('browser_hier_filter', '', {priority: 'event'});
  Shiny.setInputValue('browser_vocab_filter', '', {priority: 'event'});
});
// v10.13: toggle sidebar nav badges based on cohort state
Shiny.addCustomMessageHandler('cb_set_nav_state', function(state) {
  // state.has_criteria = true|false; state.has_result = true|false
  ['tab_build'].forEach(function(tabName) {
    var link = document.querySelector('a[data-value=\"' + tabName + '\"]');
    if (!link) return;
    var parent = link.closest('li');
    if (!parent) return;
    if (state && state.has_criteria) parent.classList.add('cb-nav-has-state');
    else parent.classList.remove('cb-nav-has-state');
  });
  // Validate tab gets a badge when there's an actual result (Results folded in, v11)
  var resLink = document.querySelector('a[data-value=\"tab_validate\"]');
  if (resLink) {
    var resParent = resLink.closest('li');
    if (resParent) {
      if (state && state.has_result) resParent.classList.add('cb-nav-has-state');
      else resParent.classList.remove('cb-nav-has-state');
    }
  }
});
// v10.13: Sidebar accordion class toggle. Keeps inputs in the DOM across
// expand/collapse cycles (avoids destroying input bindings).
Shiny.addCustomMessageHandler('cb_open_sql', function(x) {
  var d = document.getElementById('sql_details');
  if (d) { d.open = true; setTimeout(function(){ d.scrollIntoView({behavior:'smooth', block:'start'}); }, 60); }
});
Shiny.addCustomMessageHandler('cb_set_accordion', function(state) {
  var el = document.getElementById(state.id);
  if (!el) return;
  if (state.open) el.classList.remove('collapsed');
  else el.classList.add('collapsed');
});

// v10.13: Chart-code modal copy-to-clipboard. Registers a click handler on
// the modal's Copy button that reads the code from the <pre> element and
// writes to clipboard. Uses the modern Clipboard API; falls back to a
// textarea + execCommand on older browsers.
Shiny.addCustomMessageHandler('cb_register_copy_btn', function(spec) {
  // Delay to let modal DOM settle
  setTimeout(function() {
    var btn = document.getElementById(spec.btn_id);
    var pre = document.getElementById(spec.pre_id);
    if (!btn || !pre) return;
    btn.onclick = function(ev) {
      ev.preventDefault();
      var text = pre.textContent || pre.innerText || '';
      var done = function() {
        var orig = btn.innerHTML;
        btn.innerHTML = '<i class=\"fa fa-check\"></i> Copied';
        setTimeout(function() { btn.innerHTML = orig; }, 1600);
      };
      if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).then(done, function() {});
      } else {
        var ta = document.createElement('textarea');
        ta.value = text;
        document.body.appendChild(ta);
        ta.select();
        try { document.execCommand('copy'); done(); } catch(e) {}
        document.body.removeChild(ta);
      }
    };
  }, 50);
});
