            "Number of patients entering the cohort per quarter. Spikes or sudden drops can indicate data quality issues."),
          plotOutput("entry_timeseries_plot", height = "260px")
        ),

        # ── Missingness report ────────────────────────────────────────────────
        div(class = "cb-card",
          div(class = "cb-card-title", icon("circle-exclamation"), " Data Completeness Report",
