              actionButton("run_missingness_btn", tagList(icon("play"), " Run"),
                           class = "btn-dre-pri btn-sm"))
          ),
          tags$p(style = "font-size:0.84rem;color:var(--dre-muted);margin-bottom:8px;",
            "Percentage of cohort members with data present for key clinical variables. ",
            "Required for journal submission and regulatory review."),
          uiOutput("missingness_ui")
        ),

        # ── Lab value distributions ───────────────────────────────────────────
        div(class = "cb-card",
