              actionButton("run_attrition_btn", "▶  Run Attrition", class = "btn-dre-pri btn-sm"))
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:16px;",
            "Each row shows the count of distinct persons meeting that criterion independently. ",
