        # ── Materialise cohort to a database schema (v10.14) ──────────────────
        div(class = "cb-card",
          div(class = "cb-card-title", icon("database"),
            " Write cohort to a database schema"),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:10px;",
            "Materialise this cohort as a complete, valid OMOP CDM in a new database ",
            "schema: the cohort-scoped clinical tables, the vocabulary, and a standard ",
            "OHDSI cohort table (cohort, cohort_set, cohort_attrition). Written ",
            "server-side; the new schema is then ready for the OHDSI Tools tab and any ",
            "OHDSI package."),
          div(style = "display:flex;gap:12px;align-items:flex-end;flex-wrap:wrap;",
            textInput("ohdsi_write_schema", "New schema name", value = "",
                      placeholder = "e.g. my_cohort_cdm", width = "260px"),
            checkboxInput("ohdsi_write_vocab",
                          "Include vocabulary tables (larger, self-contained)", value = TRUE),
            actionButton("ohdsi_write_db_btn",
                         tagList(icon("database"), " Write to database"),
                         class = "btn-dre-pri btn-sm")),
          uiOutput("ohdsi_write_status_ui")
        ),


        # ── RMarkdown Report ─────────────────────────────────────────────────
        div(class = "cb-card",
