            tags$span(style = "float:right;",
              actionButton("export_rmd_btn", tagList(icon("file-word"), " Save .Rmd to Downloads"),
                             class = "btn-dre-pri btn-sm"))
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:10px;",
            "Downloads a pre-configured RMarkdown file containing all analyses from this session. ",
            "Open it in the workspace RStudio, set the parameters at the top, and knit to produce a ",
            "publication-ready Word document (.docx) that reconnects to the database and regenerates all figures."
          ),
          fluidRow(
            column(4,
              tags$p(style="font-size:0.84rem;color:var(--dre-muted);margin:0 0 4px;font-weight:600;",
                     "Report will include:"),
              tags$ul(style="font-size:0.83rem;color:var(--dre-muted);margin:0;padding-left:18px;",
                tags$li("Cohort definition and criteria"),
                tags$li("Table 1 - baseline characteristics"),
                tags$li("Cohort entry over time"),
                tags$li("Kaplan-Meier survival curve"),
                tags$li("Multivariate Cox model + forest plot"),
                tags$li("Treatment pathways"),
                tags$li("Data completeness report"),
                tags$li("Methods and audit log")
              )
            ),
            column(8,
              tags$p(style="font-size:0.84rem;color:var(--dre-muted);margin:0 0 6px;font-weight:600;",
                     "How to use in RStudio:"),
              tags$ol(style="font-size:0.83rem;color:var(--dre-muted);margin:0;padding-left:18px;",
                tags$li("Download the .Rmd file and save it to your workspace files"),
                tags$li("Open it in RStudio (available from the workspace Apps menu)"),
                tags$li("Edit the ", tags$code("params:"), " section at the top with your schema and settings"),
                tags$li("Click ", tags$strong("Knit → Knit to Word"), " - the report connects to the same database and generates the .docx")
              ),
              div(style="margin-top:8px;padding:8px 10px;background:rgba(0,197,181,.08);border-radius:6px;font-size:0.82rem;color:var(--dre-teal);",
                icon("info-circle"), " ",
                "The report uses ", tags$code("xaputils::xap.conn"), " - the same database connection as this app. ",
                "It will only work when knitted inside a DRE workspace RStudio session."
              )
            )
          )
        ),

        # ── Table 1 ──────────────────────────────────────────────────────────
        div(class = "cb-card",
          div(class = "cb-card-title", icon("table-list"), " Table 1 - Baseline Characteristics"),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:14px;",
            "Standardised baseline characteristics table as used in clinical publications. ",
            "Includes N, age (mean, median, IQR, age bands), sex, follow-up time, ",
            "top 5 conditions and top 5 medications. Run the cohort query first."
          ),
