              "Recommended"
            )
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:14px;",
            "Exports every OMOP table filtered to your cohort members. ",
            "Each table produces a ", tags$b(".csv"), " and a matching ",
            tags$b(".xml"), " dictionary file describing column names, types and descriptions - ",
            "ready to import into the Aridhia FAIR Data Services catalogue. ",
            "All files are bundled into one zip."
          ),
          fluidRow(
            column(6,
              textInput("extract_cohort_name", "Cohort name (used for file naming)",
