      # ══ TAB: SURVIVAL ════════════════════════════════════════════════════
      tabItem(tabName = "tab_survival",

        # ── KM configuration ─────────────────────────────────────────────────
        uiOutput("km_overlap_banner"),
        div(class = "cb-card",
          div(class = "cb-card-title", icon("chart-line"), " Kaplan-Meier Survival Curve",
            chart_toolbar("km_curve"),
            tags$span(style = "float:right;margin-right:6px;",
              actionButton("run_km_btn", tagList(icon("play"), " Run KM Analysis"),
                           class = "btn-dre-pri btn-sm"))
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:14px;",
            "Time from each person's ", tags$b("index date"), " (cohort entry) to the outcome. ",
            "Patients without the outcome are censored at the end of their observation period. ",
            "Use the ", tags$b("Outcome occurrence"), " setting below to choose whether prior history counts."
          ),
          # Outcome domain + concept picker (v10.13 - browser-like rich picker)
          fluidRow(
            column(4,
              uiOutput("km_outcome_domain_ui"),
              checkboxInput("km_use_desc", "Include descendants", value = FALSE)
            ),
            column(8,
              # Outcome concepts header - chevron toggles the picker body
              # below. Chips remain visible above when collapsed.
              tags$div(class = "km-picker-header",
                onclick = "Shiny.setInputValue('km_picker_toggle', Date.now(), {priority:'event'})",
                tags$span(class = "km-picker-chevron",
                  uiOutput("km_picker_chevron_ui", inline = TRUE)),
                tags$span(class = "control-label km-picker-title",
                          "Outcome concepts")
              ),
              # Selected concepts chips - always visible regardless of state
              uiOutput("km_selected_concepts_ui"),
              # Collapsible picker body - search box + concept list + hint.
              # Mounted statically so inputs aren't destroyed on collapse;
              # visibility driven by the .collapsed class on the wrapper.
              tags$div(id = "km_picker_body", class = "km-picker-body collapsed",
                tags$div(class = "km-picker-filter",
                  tags$input(type = "text", id = "km_picker_search_input",
                    class = "browser-list-filter-input",
                    placeholder = "Filter concept names\u2026",
                    autocomplete = "off",
                    oninput = paste0(
                      "clearTimeout(window._cbKmFltT); ",
                      "window._cbKmFltT = setTimeout(function(v){",
                      "  Shiny.setInputValue('km_picker_search', v, {priority:'event'});",
                      "}, 300, this.value);"
                    )
                  )
                ),
                uiOutput("km_picker_list_ui"),
                tags$p(class = "crit-hint", style = "margin-top:6px;",
                  "Click a concept to use it as an outcome. Leave empty to use all events in the domain.")
              )
            )
          ),
          fluidRow(
            column(4,
              radioButtons("km_outcome_mode", "Outcome occurrence",
                choices = c("Recurrence (any after index)" = "recurrence",
                            "First occurrence (incident)"   = "first"),
                selected = "recurrence")
            ),
            column(4,
              numericInput("km_time_horizon", "Time horizon (days, optional)",
                           value = NA, min = 1, width = "100%")
            ),
            column(4,
              selectInput("km_stratum", "Stratify by",
                choices = c("None" = "none", "Sex" = "sex", "Age group" = "age_group",
                            "Prior history (incidence vs recurrence)" = "prior_history"),
                selected = "none", width = "100%")
            )
          ),
          tags$p(style = "font-size:0.82rem;color:var(--dre-muted);margin:-6px 0 6px;",
            tags$b("Recurrence"), " keeps all cohort members and times the first occurrence at or after index. ",
            tags$b("First occurrence (incident)"), " drops members who already had the outcome before index, so it measures new onset and the at-risk count falls accordingly. ",
            "Both are valid; they answer different questions."
          ),
          uiOutput("km_preflight_ui"),
          uiOutput("km_status_ui"),
          plotOutput("km_plot", height = "480px")
        ),

        # ── Standards cross-check (CohortSurvival) ───────────────────────────
        div(class = "cb-card",
          div(class = "cb-card-title", icon("vial-circle-check"),
            " Standards Survival (CohortSurvival)",
            tags$span(style = "float:right;margin-right:6px;",
              actionButton("run_cs_surv_btn", tagList(icon("play"), " Run Standards KM"),
                           class = "btn-dre-sec btn-sm"))
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:12px;",
            "Independent Kaplan-Meier estimate via the OHDSI CohortSurvival package, ",
            "using the same outcome concepts as the curve above. Requires a ",
            "materialised cohort: it generates an outcome cohort in the cohort's ",
            "schema, then estimates single-event survival. CohortSurvival measures ",
            tags$b("new onset"), " (it excludes prior history), so it lines up with the native ",
            "curve when ", tags$b("Outcome occurrence"), " above is set to ",
            tags$b("First occurrence"), ", not Recurrence."
          ),
          uiOutput("cs_surv_status"),
          plotOutput("cs_surv_plot", height = "420px"),
          div(style = "margin-top:14px;", ohdsi_tbl_out("cs_surv_tbl"))
        ),

        # ── Competing Risks ───────────────────────────────────────────────────
        uiOutput("cif_overlap_banner"),
        div(class = "cb-card",
          div(class = "cb-card-title", icon("chart-area"), " Competing Risks (Cumulative Incidence)",
            chart_toolbar("cif_curve"),
            tags$span(style = "float:right;margin-right:6px;",
              actionButton("run_cif_btn", tagList(icon("play"), " Run CIF"),
                           class = "btn-dre-pri btn-sm"))
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:12px;",
            "Cumulative incidence accounting for death as a competing event. ",
            "Kaplan-Meier overestimates risk when death is common - this is the correct estimate. ",
            "Uses the same outcome configuration as the KM analysis above."
          ),
          uiOutput("cif_status_ui"),
          plotOutput("cif_plot", height = "400px")
        ),

        # ── Incidence rate card (moved below KM in v10.13) ────────────────────
        div(class = "cb-card",
          div(class = "cb-card-title", icon("calculator"), " Incidence Rate",
            tags$span(style = "float:right;",
              actionButton("run_incidence_btn", tagList(icon("play"), " Calculate"),
                           class = "btn-dre-pri btn-sm"))
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:12px;",
            "Crude incidence rate per 1,000 person-years of follow-up, with 95% Poisson confidence interval. ",
            "Person-time is computed from observation_period after index date. Run the cohort query first."
          ),
          uiOutput("incidence_ui")
        ),

        # ── Standards incidence & prevalence (IncidencePrevalence) ───────────
        div(class = "cb-card",
          div(class = "cb-card-title", icon("chart-column"),
            " Standards Incidence & Prevalence (IncidencePrevalence)",
            tags$span(style = "float:right;margin-right:6px;",
              actionButton("run_ip_btn", tagList(icon("play"), " Run Incidence & Prevalence"),
                           class = "btn-dre-sec btn-sm"))
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:10px;",
            "Incidence rates and period prevalence of the outcome within the materialised cohort, ",
            "over calendar time, via the OHDSI IncidencePrevalence package. The denominator is ",
            "restricted to cohort members, and it uses the same outcome concepts as the curves above. ",
            "Requires a materialised cohort."
          ),
          fluidRow(
            column(4,
              selectInput("ip_interval", "Interval",
                choices = c("Overall (pooled)" = "overall", "Years" = "years",
                            "Quarters" = "quarters", "Months" = "months"),
                selected = "overall", width = "100%"))
          ),
          uiOutput("ip_status"),
          tags$div(style = "margin-top:12px;",
            tags$div(class = "cb-card-title", style = "font-size:0.95rem;margin-bottom:6px;",
              "Incidence rate"),
            plotOutput("ip_inc_plot", height = "360px"),
            div(style = "margin-top:10px;", ohdsi_tbl_out("ip_inc_tbl"))
          ),
          tags$div(style = "margin-top:18px;",
            tags$div(class = "cb-card-title", style = "font-size:0.95rem;margin-bottom:6px;",
              "Period prevalence"),
            plotOutput("ip_prev_plot", height = "360px"),
            div(style = "margin-top:10px;", ohdsi_tbl_out("ip_prev_tbl"))
          )
        )
      ),


      # ══ TAB: COMPARE ══════════════════════════════════════════════════════
      tabItem(tabName = "tab_compare",

        uiOutput("compare_overlap_banner"),

        # ── Step 1: Cohort selection status ────────────────────────────────
        div(class = "cb-card",
          div(class = "cb-card-title",
            tags$span(class="compare-step-badge","1"), "Select Cohorts"),
          tags$p(style="font-size:0.87rem;color:var(--dre-muted);margin-bottom:14px;",
            "Build and run a cohort in the Build/SQL tabs, then use the ",
            tags$b("Set as Cohort A"), " / ", tags$b("Set as Cohort B"),
            " buttons in the Results tab to register each cohort for comparison."),
          fluidRow(
            column(6, uiOutput("cohort_a_badge_ui")),
            column(6, uiOutput("cohort_b_badge_ui"))
          )
        ),

        # ── Step 2: Outcome ────────────────────────────────────────────────
        div(class = "cb-card",
          div(class = "cb-card-title",
            tags$span(class="compare-step-badge","2"), "Define Outcome Event"),
          tags$p(style="font-size:0.87rem;color:var(--dre-muted);margin-bottom:14px;",
            "Select the outcome domain and search for concept(s). Leave the concept list empty to use all events in the domain."),
          fluidRow(
            column(4,
              selectInput("cmp_outcome_domain", "Outcome domain",
