                actionButton("cmp_concept_search_btn","Search",
                             class="btn-dre-sec btn-sm",
                             style="white-space:nowrap;align-self:flex-start;margin-top:1px;")
              ),
              uiOutput("cmp_concept_search_results_ui"),
              uiOutput("cmp_selected_concepts_ui")
            )
          )
        ),

        # ── Step 3: Analysis settings ──────────────────────────────────────
        div(class = "cb-card",
          div(class = "cb-card-title",
            tags$span(class="compare-step-badge","3"), "Analysis Settings"),
          fluidRow(
            column(4,
              numericInput("cmp_lookback", "Covariate lookback window (days)",
                           value = 365, min = 30, max = 1825, width = "100%"),
              tags$p(class="crit-hint",
                     "Medical history in this window before index date is used to build covariates.")
            ),
            column(4,
              numericInput("cmp_top_n", "Max covariates (top N by prevalence)",
                           value = 50, min = 5, max = 200, width = "100%"),
              tags$p(class="crit-hint",
                     "The N most prevalent conditions and drugs across both cohorts are used as PS model inputs.")
            ),
            column(4,
              numericInput("cmp_caliper", "PS caliper (SD units)",
                           value = 0.2, min = 0.05, max = 1.0, step = 0.05, width = "100%"),
              numericInput("cmp_time_horizon", "KM time horizon (days, optional)",
                           value = NA, min = 1, width = "100%")
            )
          ),
          div(style="text-align:right;",
            actionButton("run_compare_btn",
              tagList(icon("play"), " Run Comparative Analysis"),
              class="btn-dre-pri")
          )
        ),

        # ── Results ───────────────────────────────────────────────────────
        uiOutput("compare_results_ui")
      ),

      # ══ TAB: COX REGRESSION ══════════════════════════════════════════════
      tabItem(tabName = "tab_cox",

        uiOutput("cox_overlap_banner"),

        div(class = "cb-card",
          div(class = "cb-card-title", icon("chart-line"), " Multivariate Cox Proportional Hazards",
            tags$span(style = "float:right;",
              actionButton("run_cox_btn", tagList(icon("play"), " Run Cox Model"),
                           class = "btn-dre-pri btn-sm"))
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:14px;",
            "Fit a Cox proportional hazards model for the outcome defined in the Survival tab. ",
            "Covariates: age at index, sex, Charlson Comorbidity Index, and top pre-index conditions and drugs. ",
            "Run the cohort query and configure an outcome in the Survival tab first."
          ),
          fluidRow(
            column(4,
              numericInput("cox_lookback_days", "Covariate lookback window (days)",
                           value = 365L, min = 30, max = 3650, width = "100%"),
              tags$p(class = "crit-hint", "Conditions and drugs recorded in this window before index date are included as covariates."),
              numericInput("cox_top_n_covs", "Max binary covariates",
                           value = 20L, min = 5, max = 100, width = "100%"),
              tags$p(class = "crit-hint", "Top N most prevalent conditions/drugs by cohort frequency."),
              numericInput("cox_time_horizon", "Time horizon (days, optional)",
                           value = NA, min = 1, width = "100%")
            ),
            column(8,
              uiOutput("cox_status_ui")
            )
          )
        ),

        # Prominent banner - only renders when diagnostics flag a problem
        uiOutput("cox_diagnostics_alert_ui"),

        # Forest plot gets the full width - it's the headline visualisation
        # and the previous 7/12 column made the labels unreadable. The table
        # and summary now sit below the plot rather than beside it.
        div(class = "cb-card",
          div(class = "cb-card-title", icon("chart-bar"), " Hazard Ratio Forest Plot",
            chart_toolbar("cox_forest")),
          tags$p(style = "font-size:0.84rem;color:var(--dre-muted);margin-bottom:8px;",
            "Adjusted hazard ratios with 95% confidence intervals. Red dashed line at HR = 1."),
          plotOutput("cox_forest_plot", height = "640px")
        ),

        fluidRow(
          column(8,
            div(class = "cb-card",
              div(class = "cb-card-title", icon("table"), " Model Coefficients"),
              tags$p(style = "font-size:0.84rem;color:var(--dre-muted);margin-bottom:8px;",
                "HR, 95% CI, and p-value for each covariate. Significant covariates (p < 0.05) highlighted."),
              DT::dataTableOutput("cox_coef_table")
            )
          ),
          column(4,
            div(class = "cb-card",
              div(class = "cb-card-title", icon("info-circle"), " Model Summary"),
              uiOutput("cox_summary_ui")
            )
          )
        ),

        # ── Model diagnostics card (PH assumption, EPV, VIF, influential obs) ──
        # v8.1: structured set of output bindings rather than a single uiOutput.
        # Each sub-panel is independent and the DT/plot bindings are served
        # by their natural output types (dataTableOutput, plotOutput).
        div(class = "cb-card",
          div(class = "cb-card-title", icon("stethoscope"), " Model Diagnostics"),
          tags$p(style = "font-size:0.84rem;color:var(--dre-muted);margin-bottom:8px;",
            "Standard checks for Cox model validity. ",
            "Test results that fall outside accepted thresholds are highlighted."),

          uiOutput("cox_diag_epv_ui"),
          uiOutput("cox_diag_prune_ui"),
          uiOutput("cox_diag_ph_summary_ui"),

          tags$h5(style = "color:var(--dre-teal);font-size:12px;margin-top:14px;margin-bottom:6px;",
                  "Schoenfeld residual test by covariate"),
          DT::dataTableOutput("cox_diag_zph_table"),

          tags$h5(style = "color:var(--dre-teal);font-size:12px;margin-top:14px;margin-bottom:6px;",
                  "Schoenfeld residual plots (loess smoothers should be flat under PH)",
                  chart_toolbar("cox_diag")),
          plotOutput("cox_diag_zph_plot", height = "520px"),

          tags$h5(style = "color:var(--dre-teal);font-size:12px;margin-top:14px;margin-bottom:6px;",
                  "Variance Inflation Factors"),
          tags$p(style = "color:var(--dre-muted);font-size:0.82rem;margin-bottom:6px;",
            "VIF > 5 indicates problematic collinearity; > 10 is severe."),
          DT::dataTableOutput("cox_diag_vif_table"),
          uiOutput("cox_diag_vif_notice_ui"),

          uiOutput("cox_diag_infl_ui")
        )
      ),

      # ══ TAB: TREATMENT PATHWAYS ════════════════════════════════════════════
      tabItem(tabName = "tab_trt",

        div(class = "cb-card",
          div(class = "cb-card-title", icon("route"), " Treatment Pathway Configuration",
            tags$span(style = "float:right;",
              actionButton("run_trt_btn", tagList(icon("play"), " Run Analysis"),
                           class = "btn-dre-pri btn-sm"))
          ),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:14px;",
            "Analyses time from index date to first treatment, and which drugs patients receive. ",
            "Run the cohort query first. Leave concept search empty to include all drug exposures."
          ),
          fluidRow(
            column(4,
              selectInput("trt_outcome_domain", "Treatment domain",
                choices = c("Medications & Prescriptions" = "drug",
                            "Procedures" = "procedure"),
                selected = "drug", width = "100%"),
              numericInput("trt_followup_days", "Follow-up window (days)",
                           value = 365L, min = 1, width = "100%"),
              tags$p(class = "crit-hint", "Only treatments occurring within this window after index date are included."),
              numericInput("trt_top_n", "Top N treatments to display",
                           value = 15L, min = 5, max = 50, width = "100%")
            ),
            column(8,
              tags$label(class = "control-label", "Filter to specific concepts (optional)"),
              div(style = "display:flex;gap:6px;margin-bottom:6px;",
                textInput("trt_concept_q", NULL, placeholder = "Search drug name...",
                          width = "100%"),
                actionButton("trt_concept_search_btn", "Search",
                             class = "btn-dre-sec btn-sm",
                             style = "white-space:nowrap;align-self:flex-start;margin-top:1px;")
              ),
              uiOutput("trt_concept_results_ui"),
              uiOutput("trt_selected_concepts_ui"),
              tags$p(class = "crit-hint",
                "Leave empty to analyse all treatments. Add concepts to restrict to a drug class.")
            )
          ),
          uiOutput("trt_status_ui")
        ),

        fluidRow(
          column(6,
            div(class = "cb-card",
              div(class = "cb-card-title", icon("chart-line"), " Time to First Treatment"),
              tags$p(style = "font-size:0.84rem;color:var(--dre-muted);margin-bottom:8px;",
                "Kaplan-Meier estimate of the probability of remaining treatment-naive over time. ",
                "Median time to first treatment shown as dashed line."),
              uiOutput("trt_km_stats_ui"),
              plotOutput("trt_km_plot", height = "360px")
            )
          ),
          column(6,
            div(class = "cb-card",
              div(class = "cb-card-title", icon("chart-bar"), " Top Treatments Received"),
              tags$p(style = "font-size:0.84rem;color:var(--dre-muted);margin-bottom:8px;",
                "Percentage of cohort members receiving each treatment within the follow-up window."),
              plotOutput("trt_top_plot", height = "360px")
            )
          )
        ),

        div(class = "cb-card",
          div(class = "cb-card-title", icon("table"), " Treatment Details"),
          tags$p(style = "font-size:0.84rem;color:var(--dre-muted);margin-bottom:8px;",
            "Per-treatment counts, median days to first use, and percentage of cohort."),
          DT::dataTableOutput("trt_detail_table")
        )
      ),

      # ── OHDSI Tools (v10.14) ──────────────────────────────────────────────
      tabItem(tabName = "tab_ohdsi",

        div(class = "cb-card",
          div(class = "cb-card-title", icon("share-nodes"), " OHDSI Standard Tooling"),
          tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:6px;",
            "Every other tab in cohortbuilder runs its own SQL directly against ",
            "the workspace database. This tab reads the same data through the ",
            "OHDSI community-standard R ecosystem, ", tags$code("CDMConnector"),
            " and ", tags$code("OmopSketch"),
            ", to show the app interoperates with the standard stack rather than ",
            "depending on a bespoke approach."),
          tags$p(style = "font-size:0.84rem;color:var(--dre-muted);margin-bottom:0;",
            "It opens a separate standards-compliant connection to the same ",
            "database and builds a ", tags$code("cdm_reference"),
            " for the first selected schema. Schema profiling lands here next.")
        ),

        div(class = "cb-card",
          div(class = "cb-card-title", icon("circle-nodes"), " Connection & CDM Reference"),
          uiOutput("ohdsi_panel_ui")
        )
      )

    ) # end tabItems
  ) # end dashboardBody
) # end dashboardPage


# ── 11. SERVER ────────────────────────────────────────────────────────────────

server <- function(input, output, session) {

  # ── Reactive state ─────────────────────────────────────────────────────────
  schemas_rv      <- reactiveVal(data.frame(schema_name = character(0),
                                             table_count  = integer(0),
                                             stringsAsFactors = FALSE))
  omop_rv         <- reactiveVal(NULL)
  omop_col_map_rv   <- reactiveVal(list())
  schema_summary_rv <- reactiveVal(NULL)
  schema_profile_rv  <- reactiveVal(list())  # named list: schema -> schema_profile result (v10.12)
  # ── Concept Browser state ────────────────────────────────────────────────────
  browser_list_rv       <- reactiveVal(NULL)         # data.frame of current list
  browser_dom_labels_rv <- reactiveVal(character(0)) # cache of domain dropdown labels (for diff-checking)
  browser_selected_rv   <- reactiveVal(NA_integer_)  # selected concept_id (NA = none)
  browser_detail_rv     <- reactiveVal(list(         # detail panel content + load flags
    overview      = NULL,
    overview_loaded = FALSE
  ))
  # v10.13: detail sub-tab state + lazy-loaded data for the non-default tabs.
  browser_subtab_rv     <- reactiveVal("overview")   # "overview" | "hier" | "cooccur" | "samples" | "aira"
  browser_samples_rv    <- reactiveVal(list(data = NULL, loaded = FALSE, for_cid = NA_integer_))
  browser_cooccur_rv    <- reactiveVal(list(data = NULL, loaded = FALSE, for_cid = NA_integer_))
  # Hierarchy mini-view in the detail panel: ancestors path + immediate
  # children for the selected concept.
  browser_hier_detail_rv <- reactiveVal(list(data = NULL, loaded = FALSE, for_cid = NA_integer_))
  # R-AIRA-16: per-session cache of AIRA concept summaries, keyed by
  # concept_id. Each entry: list(status, content, generated_at,
  # prompt_version). Cleared when AIRA config changes.
  aira_concept_cache_rv <- reactiveVal(list())
  # Which concept_id is currently being summarised (NA when idle). Used to
  # show the spinner state in the AIRA tab without blocking other UI.
  aira_concept_busy_for_rv <- reactiveVal(NA_integer_)

  # v10.13: left-panel browse mode + per-mode state.
  browser_mode_rv       <- reactiveVal("prevalence") # "prevalence" | "hierarchy" | "vocabulary"
  # Sort state: "<column>:<dir>". Columns: persons, records, name, vocab, code,
  # n_schemas_present. Direction: asc | desc. Applies to prevalence list and
  # vocab-drilled-in concept list (which is also a prevalence query). Hierarchy
  # sort is handled separately (client-side, per current level).
  browser_sort_rv       <- reactiveVal("persons:desc")
  # Hierarchy: path is a list of list(concept_id, concept_name) from root to
  # current parent. Empty = at the root view. browser_hier_rv is the children
  # of the current path's last element (or roots if path is empty).
  browser_hier_path_rv  <- reactiveVal(list())
  browser_hier_rv       <- reactiveVal(NULL)
  # Hierarchy result cache: named list keyed by paste(schemas|dom|parent),
  # cleared when col_maps_rv changes or the user clicks the refresh button.
  browser_hier_cache_rv <- reactiveVal(list())
  # v10.13: Schema overlap state for the Venn diagram chrome.
  # browser_overlap_rv      $schemas, $region_counts, $region_ids, $total
  # browser_overlap_cache_rv  per-(schemas,domain) cache
  # browser_overlap_region_rv currently active region bitmask filter (NULL = all)
  browser_overlap_rv        <- reactiveVal(NULL)
  browser_overlap_cache_rv  <- reactiveVal(list())
  browser_overlap_region_rv <- reactiveVal(NULL)
  # v10.13: Selected-concepts drawer expand/collapse state. Auto-expands when
  # a criterion is added; user can collapse manually via the header.
  browser_drawer_open_rv    <- reactiveVal(FALSE)

  # v10.13: Sidebar nav badge observer - toggles a CSS class on the Build
  # Cohort and Cohort SQL nav items when the cohort has criteria. Results
  # gets the badge when there's a result loaded.
  observe({
    has_crit <- length(criteria_rv()) > 0
    has_res  <- !is.null(cohort_result_rv()) &&
                tryCatch(nrow(cohort_result_rv()) > 0, error = function(e) FALSE)
    session$sendCustomMessage("cb_set_nav_state", list(
      has_criteria = has_crit,
      has_result   = has_res
    ))
  })
  # Vocabulary: NULL = at the vocab-list view. Non-NULL = drilled into a vocab.
  browser_vocab_sel_rv  <- reactiveVal(NULL)
  browser_vocab_list_rv <- reactiveVal(NULL)         # df of vocabs (top view)
  browser_vocab_concepts_rv <- reactiveVal(NULL)     # df of concepts in drilled vocab
  concept_names_rv  <- reactiveVal(list())
  crit_counts_rv    <- reactiveVal(list())
  criteria_rv     <- reactiveVal(list())
  # v10.13: Sidebar accordion state. DATABASE expanded by default since
  # users need to see the schema list on first load; user can collapse
  # when satisfied. COHORT collapsed by default.
  sidebar_db_open_rv     <- reactiveVal(TRUE)
  sidebar_cohort_open_rv <- reactiveVal(FALSE)

  observeEvent(input$sidebar_db_toggle, {
    sidebar_db_open_rv(!isTRUE(isolate(sidebar_db_open_rv())))
  }, ignoreNULL = TRUE)
  observeEvent(input$sidebar_cohort_toggle, {
    sidebar_cohort_open_rv(!isTRUE(isolate(sidebar_cohort_open_rv())))
  }, ignoreNULL = TRUE)

  # v10.13: Sidebar accordion - header renderers only. The section bodies
  # are mounted statically in UI so input bindings (schema_select, cohort_name)
  # are not destroyed on collapse. The accordion state drives a custom message
  # that toggles a CSS class on the section wrapper to show/hide the body.
  output$sidebar_db_header_ui <- renderUI({
    open <- isTRUE(sidebar_db_open_rv())
    tags$div(class = "sidebar-section-header",
      onclick = "Shiny.setInputValue('sidebar_db_toggle', Date.now(), {priority:'event'})",
      tags$span(class = "sidebar-section-chevron",
        icon(if (open) "chevron-down" else "chevron-right")),
      tags$span(class = "sidebar-section-title", "Database"),
      tags$span(class = "sidebar-section-spacer")
    )
  })

  output$sidebar_cohort_header_ui <- renderUI({
    open <- isTRUE(sidebar_cohort_open_rv())
    tags$div(class = "sidebar-section-header",
      onclick = "Shiny.setInputValue('sidebar_cohort_toggle', Date.now(), {priority:'event'})",
      tags$span(class = "sidebar-section-chevron",
        icon(if (open) "chevron-down" else "chevron-right")),
      tags$span(class = "sidebar-section-title", "Cohort"),
      tags$span(class = "sidebar-section-spacer")
    )
  })

  # Push collapsed state to the DOM as a class toggle (keeps inputs mounted).
  observe({
    open <- isTRUE(sidebar_db_open_rv())
    session$sendCustomMessage("cb_set_accordion",
      list(id = "sidebar_db_section", open = open))
  })
  observe({
    open <- isTRUE(sidebar_cohort_open_rv())
    session$sendCustomMessage("cb_set_accordion",
      list(id = "sidebar_cohort_section", open = open))
  })
  next_id_rv      <- reactiveVal(1L)
  cohort_result_rv<- reactiveVal(NULL)
  validate_orphan_rv <- reactiveVal(NULL)         # v11: orphan-concept scan result (Validate tab)
  validate_orphan_status_rv <- reactiveVal(NULL)  # v11: status / empty-state message for the scan
  run_status_rv    <- reactiveVal("empty")  # v11: "empty" | "running" | "fresh" | "stale"
  run_signature_rv <- reactiveVal("")       # v11: definition signature that produced the current result
  validate_attrition_rv <- reactiveVal(NULL)         # v11: sequential attrition waterfall
  validate_attrition_status_rv <- reactiveVal(NULL)  # v11: attrition status / empty-state message
  validate_index_rv <- reactiveVal(NULL)             # v11: index-event breakdown result
  validate_index_status_rv <- reactiveVal(NULL)      # v11: index-breakdown status message
  validate_aira_rv <- reactiveVal(NULL)              # v11: AIRA phenotype review markdown
  validate_aira_status_rv <- reactiveVal(NULL)       # v11: AIRA review status message
  validate_codeuse_rv <- reactiveVal(NULL)           # v11: CodelistGenerator code-use summarised_result
  validate_codeuse_status_rv <- reactiveVal(NULL)    # v11: code-use status / empty-state message
  cohort_error_rv     <- reactiveVal(NULL)
  extract_status_rv    <- reactiveVal(NULL)
  comorbidity_rv       <- reactiveVal(NULL)
  char_rv              <- reactiveVal(NULL)
  table1_rv            <- reactiveVal(NULL)
  concept_search_rv    <- reactiveVal(NULL)
  global_search_rv     <- reactiveVal(NULL)
  smart_templates_rv   <- reactiveVal(NULL)
  # New v3 state
  prior_obs_days_rv    <- reactiveVal(NA_integer_)
  min_followup_days_rv <- reactiveVal(NA_integer_)
  survival_rv          <- reactiveVal(NULL)   # KM result list
  cif_rv               <- reactiveVal(NULL)   # CIF result list
  missingness_rv       <- reactiveVal(NULL)   # missingness report
  incidence_rv         <- reactiveVal(NULL)   # incidence rate result
  km_concepts_rv       <- reactiveVal(list())  # KM outcome: list(cid=integer, name=character)
  cs_surv_result_rv    <- reactiveVal(NULL)    # v11: CohortSurvival summarised_result
  cs_surv_status_rv    <- reactiveVal(NULL)    # v11: list(state, msg, n_outcome)
  ip_inc_rv            <- reactiveVal(NULL)    # v11: IncidencePrevalence incidence sr
  ip_prev_rv           <- reactiveVal(NULL)    # v11: IncidencePrevalence prevalence sr
  ip_status_rv         <- reactiveVal(NULL)    # v11: list(state, msg, target)
  # v10.13: KM outcome picker state - separate from main browser picker.
  km_picker_data_rv    <- reactiveVal(NULL)    # data.frame from browse_concepts_multi_schema
  km_picker_cache_rv   <- reactiveVal(list())  # cache keyed by (schemas, domain)
  km_picker_sort_rv    <- reactiveVal("cohortevents:desc")
  km_picker_domain_counts_rv <- reactiveVal(NULL)  # named integer: domain -> n_concepts
  # v10.13: picker body expand/collapse. Starts collapsed; user expands
  # via chevron to pick. Auto-expand never fires.
  km_picker_open_rv          <- reactiveVal(FALSE)

  observeEvent(input$km_picker_toggle, {
    km_picker_open_rv(!isTRUE(isolate(km_picker_open_rv())))
  }, ignoreNULL = TRUE)

  # Chevron icon reflects current state
  output$km_picker_chevron_ui <- renderUI({
    if (isTRUE(km_picker_open_rv())) icon("chevron-down") else icon("chevron-right")
  })

  # Push state to DOM as a class toggle (keeps inputs mounted across collapse)
  observe({
    open <- isTRUE(km_picker_open_rv())
    session$sendCustomMessage("cb_set_accordion",
      list(id = "km_picker_body", open = open))
  })
  # Comparative analysis state
  cohort_a_rv      <- reactiveVal(NULL)   # list(result, schema, col_map, label)
  cohort_b_rv      <- reactiveVal(NULL)
  cmp_concepts_rv  <- reactiveVal(list()) # outcome concepts for compare
  compare_rv       <- reactiveVal(NULL)   # full analysis result
  cox_rv           <- reactiveVal(NULL)   # Cox model result
  modal_search_rv  <- reactiveVal(NULL)   # current modal concept search state
  trt_rv           <- reactiveVal(NULL)   # Treatment pathway result
  trt_concepts_rv  <- reactiveVal(list()) # Treatment concept filter
  # ── Multi-schema state (v6) ───────────────────────────────────────────────
  first_run_dismissed_rv <- reactiveVal(FALSE)  # moved here so schema observer can reset it
  col_maps_rv      <- reactiveVal(list())  # named list: schema -> col_map
  summaries_rv     <- reactiveVal(list())  # named list: schema -> schema_summary
  vocab_check_rv   <- reactiveVal(NULL)    # result of check_vocab_consistency()
  overlap_rv       <- reactiveVal(NULL)    # result of check_obs_overlap()
  multi_mode_rv    <- reactiveVal(FALSE)   # TRUE when >1 schema selected
  scratch_ok_rv    <- reactiveVal(FALSE)   # TRUE after ensure_scratch_schema()

  # ── OHDSI Tools state (v10.14) ────────────────────────────────────────────
  # ohdsi_con_rv : the parallel RPostgres connection (PqConnection) or NULL,
  #                opened lazily on first OHDSI tab use, one per session.
  # ohdsi_cdm_rv : cached cdm_reference for the primary selected schema, the
  #                schema it was built for (rebuild only on change), and any
  #                build error message for the four-state panel.
  ohdsi_con_rv <- reactiveVal(NULL)
  ohdsi_cdm_rv <- reactiveVal(list(cdm = NULL, schema = NA_character_, error = NULL))
  # ohdsi_profile_rv : cached OmopSketch output for the primary schema, keyed by
  # schema name. Each summarise call carries its own error so one failing (e.g.
  # the snapshot on a text-date schema) does not blank the other.
  ohdsi_profile_rv <- reactiveVal(list(schema = NA_character_,
                                       snapshot = NULL, snapshot_err = NULL,
                                       counts = NULL,   counts_err = NULL))
  # Cohort characterisation state (v10.14): tables discovered in the schema, and
  # the result of the last characterisation run (kept until schema changes).
  ohdsi_cohort_tables_rv <- reactiveVal(character(0))
  ohdsi_cohort_result_rv <- reactiveVal(list())
  pr_result_rv <- reactiveVal(NULL)   # v11: PhenotypeR cohortDiagnostics summarised_result
  pr_status_rv <- reactiveVal(NULL)   # v11: PhenotypeR status / empty-state message
  # Result of the last "write cohort CDM to a database schema" run.
  ohdsi_write_result_rv  <- reactiveVal(NULL)

  # Per-tab acknowledgement when overlap=="none". Cleared whenever overlap
  # changes (new cohort build or schema selection change), so the user must
  # explicitly acknowledge each time the gate would block.
  proceed_km_rv      <- reactiveVal(FALSE)
  proceed_cif_rv     <- reactiveVal(FALSE)
  proceed_cox_rv     <- reactiveVal(FALSE)
  proceed_compare_rv <- reactiveVal(FALSE)

  # ── AIRA cohort drafting state (v10) ──────────────────────────────────────
  # aira_draft_rv holds the most recent draft response (the 6-field shape).
  # While a request is in flight, aira_busy_rv is TRUE - used to disable the
  # submit button. aira_resolved_rv holds the per-criterion concept lookups
  # produced by resolving search_terms against the in-app concept search.
  aira_draft_rv     <- reactiveVal(NULL)
  aira_busy_rv      <- reactiveVal(FALSE)
  aira_resolved_rv  <- reactiveVal(NULL)
  aira_cfg <- aira_resolve_cfg()
  # v10.1 instrumentation: log what the server captured. If this shows
  # enabled=FALSE here but you ran options(aira_cfg=list(enabled=TRUE,...)),
  # the options() call happened AFTER the app started - restart with the
  # cfg set first. In DRE deployment, use the AIRA_ENABLED env var instead.
  message(sprintf("[AIRA] server() captured aira_cfg: enabled=%s base_url=%s model=%s timeout=%ss thinking_off=%s",
                   isTRUE(aira_cfg$enabled),
                   aira_cfg$base_url %||% "<unset>",
                   aira_cfg$model %||% "<unset>",
                   aira_cfg$timeout_s_drafting %||% NA,
                   isTRUE(aira_cfg$disable_thinking)))



  # ──────────────────────────────────────────────────────────────────────────
  # CHART EXPORT INFRASTRUCTURE (v10.13)
  # ──────────────────────────────────────────────────────────────────────────
  # Each chart that supports save+code has:
  #   - A "Save" button (id "save_<chart_id>_btn") that writes a PNG to
  #     /home/workspace/files/Downloads/ named
  #     <cohort_name>_<chart_id>_<YYYYMMDD_HHMMSS>.png
  #   - A "Code" button (id "code_<chart_id>_btn") that opens a modal with
  #     the standalone R code that would reproduce the chart in a fresh
  #     R session in the same workspace.
  #
  # Charts register by name with chart_register(). The registry holds, per
  # chart id, the reactive ggplot getter and the code generator. Save and
  # Code observers iterate the registry to wire up button handlers.
  #
  # Code snippets are self-contained: they connect via xaputils::xap.conn,
  # run real SQL (no app helpers like ac()/fq()/qq()), and produce the
  # ggplot. The user can paste the snippet into RStudio in their workspace
  # and run it end-to-end.

  chart_registry_rv <- reactiveVal(list())

  chart_register <- function(id, label,
                             plot_fn,           # reactive/function returning ggplot
                             code_fn,           # function() -> character code string
                             width  = 12, height = 8, dpi = 120) {
    reg <- isolate(chart_registry_rv())
    reg[[id]] <- list(
      id     = id, label = label,
      plot_fn = plot_fn, code_fn = code_fn,
      width  = width, height = height, dpi = dpi
    )
    chart_registry_rv(reg)
  }

  # Build a safe filename from cohort name. Disallowed: anything not
  # alphanumeric/underscore/hyphen. Spaces become underscores; everything
  # else dropped. Empty → "cohort".
  .safe_cohort_slug <- function(name) {
    nm <- as.character(name %||% "")
    nm <- gsub("\\s+", "_", trimws(nm))
    nm <- gsub("[^A-Za-z0-9_-]", "", nm)
    if (!nzchar(nm)) "cohort" else nm
  }

  # Ensure Downloads dir exists; return TRUE if writable
  .ensure_downloads <- function() {
    if (!dir.exists(DOWNLOADS_DIR)) {
      ok <- tryCatch({
        dir.create(DOWNLOADS_DIR, recursive = TRUE, showWarnings = FALSE)
        TRUE
      }, error = function(e) FALSE)
      if (!ok) return(FALSE)
    }
    file.access(DOWNLOADS_DIR, mode = 2) == 0L
  }

  # Save a chart's plot to /home/workspace/files/Downloads/
  .save_chart <- function(chart_id) {
    reg <- chart_registry_rv()
    spec <- reg[[chart_id]]
    if (is.null(spec)) {
      showNotification(sprintf("Chart '%s' not registered", chart_id),
                       type = "error"); return()
    }
    plot_obj <- tryCatch(spec$plot_fn(), error = function(e) NULL)
    if (is.null(plot_obj)) {
      showNotification("No chart available to save (run the analysis first).",
                       type = "warning"); return()
    }
    if (!.ensure_downloads()) {
      showNotification(sprintf("Cannot write to %s", DOWNLOADS_DIR),
                       type = "error"); return()
    }
    cohort_slug <- .safe_cohort_slug(input$cohort_name)
    ts <- format(Sys.time(), "%Y%m%d_%H%M%S")
    fname <- sprintf("%s_%s_%s.png", cohort_slug, chart_id, ts)
    fpath <- file.path(DOWNLOADS_DIR, fname)
    ok <- tryCatch({
      ggplot2::ggsave(filename = fpath, plot = plot_obj,
                      width = spec$width, height = spec$height,
                      dpi = spec$dpi, bg = "#0B2341")
      TRUE
    }, error = function(e) {
      message("[chart_save] ", chart_id, ": ", conditionMessage(e)); FALSE
    })
    if (ok)
      showNotification(sprintf("Saved: %s", fname),
                       type = "message", duration = 5)
    else
      showNotification("Failed to save chart (see logs).", type = "error")
  }

  # ── Cohort SQL block (shared across chart code generators) ─────────────────
  # Produces the cohort-building portion of a chart's standalone R snippet.
  # Handles single- vs multi-schema. Returns a string ready to inline into
  # a larger snippet. Returns NULL if no cohort SQL is available (no
  # criteria, no connection, or SQL generation failed) - callers should
  # handle this by returning a "build cohort first" placeholder.
  .cohort_sql_block <- function() {
    sql_obj <- tryCatch(generated_sql(), error = function(e) NULL)
    if (is.null(sql_obj)) return(NULL)
    schemas <- input$schema_select %||% character(0)
    if (length(schemas) == 0) return(NULL)

    cohort_nm <- input$cohort_name %||% "my_cohort"

    if (is.character(sql_obj)) {
      # Single schema
      sprintf('
# ── 1. Connect to workspace database ─────────────────────────────────────
# xap.conn is an active binding from xaputils - accessing it returns a
# fresh connection handle. We deliberately do NOT capture it to a local
# variable, because the underlying pointer can become invalid if the
# connection is recycled between R evaluations ("external pointer is
# not valid"). Reference xap.conn inline at every DB call instead.
library(DBI)
library(xaputils)

# ── 2. Build the cohort ──────────────────────────────────────────────────
# This SQL was generated by cohortbuilder for cohort "%s" against schema
# "%s". It runs on the workspace PostgreSQL (uses PG-specific syntax such
# as EXTRACT, ::date casts). The R raw-string syntax r"---(...)---"
# avoids quote-escaping the embedded SQL.
cohort_sql <- r"---(
%s
)---"

cohort_result <- DBI::dbGetQuery(xap.conn, cohort_sql)
cat(sprintf("Cohort: %%d persons\\n", nrow(cohort_result)))
',
        cohort_nm, schemas[1], sql_obj)
    } else {
      # Multi schema - sql_obj is a named list keyed by schema
      # Emit per-schema chunks with the SQL inlined, then union.
      schemas_have_sql <- intersect(schemas, names(sql_obj))
      schemas_have_sql <- schemas_have_sql[
        !vapply(sql_obj[schemas_have_sql], is.null, logical(1))]
      if (length(schemas_have_sql) == 0) return(NULL)

      # Build the per-schema SQL literals as raw strings to avoid escaping.
      sql_lines <- vapply(schemas_have_sql, function(sch) {
        sprintf('  %s = r"---(\n%s\n)---"', deparse(sch), sql_obj[[sch]])
      }, character(1))
      sql_list_str <- paste(sql_lines, collapse = ",\n")

      sprintf('
# ── 1. Connect to workspace database ─────────────────────────────────────
# xap.conn is an active binding - reference it inline at every DB call
# rather than capturing to a local variable (the captured pointer can
# go stale with "external pointer is not valid").
library(DBI)
library(xaputils)

# ── 2. Build the cohort (multi-schema) ───────────────────────────────────
# This cohort was built across schemas: %s.
# Each schema has its own SQL; results are tagged with source_schema and
# row-bound into a single cohort_result. SQL is workspace PostgreSQL.
# Raw-string syntax r"---(...)---" lets the SQL contain quotes freely.
cohort_sqls <- list(
%s
)

cohort_result <- do.call(rbind, lapply(names(cohort_sqls), function(sch) {
  r <- DBI::dbGetQuery(xap.conn, cohort_sqls[[sch]])
  if (is.null(r) || nrow(r) == 0) return(NULL)
  r$source_schema <- sch
  r
}))
cohort_result$cohort_rank <- seq_len(nrow(cohort_result))
cat(sprintf("Cohort: %%d persons across %%d schemas\\n",
            nrow(cohort_result),
            length(unique(cohort_result$source_schema))))
',
        paste(schemas_have_sql, collapse = ", "),
        sql_list_str)
    }
  }

  # Helper: pick a primary schema and its col_map for chart-specific queries
  # that don't iterate per-schema. For single-schema cohorts returns that
  # schema; for multi-schema returns the first selected.
  .primary_schema_info <- function() {
    schemas <- input$schema_select %||% character(0)
    if (length(schemas) == 0) return(NULL)
    list(schema   = schemas[1],
         schemas  = schemas,
         multi    = length(schemas) > 1,
         col_map  = col_maps_rv()[[schemas[1]]] %||% omop_col_map_rv())
  }

  # ── Cox model code block (shared by forest plot + Schoenfeld diagnostics) ─
  # Produces the cohort + survival + covariate + coxph fit portion of the
  # standalone snippet. Both Cox chart code generators call this and then
  # add their own plot section. Returns NULL if the model isn't fitted yet.
  .cox_model_block <- function() {
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done") || is.null(cv$coef_df))
      return(NULL)
    cohort_block <- .cohort_sql_block()
    if (is.null(cohort_block)) return(NULL)

    schemas    <- input$schema_select %||% character(0)
    sch        <- schemas[1]  # Cox runs on the primary schema
    cm         <- col_maps_rv()[[sch]] %||% omop_col_map_rv()
    lookback   <- as.integer(input$cox_lookback_days %||% 365L)
    horizon    <- input$cox_time_horizon

    outcome_domain <- input$km_outcome_domain %||% "condition"
    outcome_ids    <- vapply(km_concepts_rv(), function(x) as.integer(x$cid), integer(1))
    use_desc       <- isTRUE(input$km_use_desc)
    dom            <- DOMAINS[[outcome_domain]]
    if (is.null(dom)) return(NULL)

    # Final covariate list - what the app actually fit on after pruning.
    # We hard-code these into the snippet so the user reproduces the same
    # model without needing the app's EPV/collinearity pruning logic.
    covariates <- cv$coef_df$covariate
    formula_rhs <- paste(sprintf("`%s`", covariates), collapse = " + ")

    # ── Survival data query (same shape as KM) ─────────────────────────────
    pid_col <- ac(cm, dom$table, dom$person_col)
    dat_col <- ac(cm, dom$table, dom$date_col)
    cid_col <- ac(cm, dom$table, dom$concept_col)
    op_pid  <- ac(cm, "observation_period", "person_id")
    op_end  <- ac(cm, "observation_period", "observation_period_end_date")
    ids_c   <- paste(outcome_ids, collapse = ", ")
    if (use_desc) {
      anc_col  <- ac(cm, "concept_ancestor", "ancestor_concept_id")
      desc_col <- ac(cm, "concept_ancestor", "descendant_concept_id")
      concept_filter <- sprintf(
        "AND t.%s IN (SELECT %s FROM \"%s\".\"concept_ancestor\" WHERE %s IN (%s))",
        cid_col, desc_col, sch, anc_col, ids_c)
    } else {
      concept_filter <- sprintf("AND t.%s IN (%s)", cid_col, ids_c)
    }
    surv_sql <- sprintf(
'WITH idx(person_id, index_date) AS (VALUES %%s),
     outcomes AS (
       SELECT t.%s AS person_id, MIN(t.%s::date) AS event_date
       FROM   "%s"."%s" t
       JOIN   idx ON idx.person_id = t.%s
       WHERE  t.%s::date >= idx.index_date %s
       GROUP  BY 1
     ),
     censoring AS (
       SELECT op.%s AS person_id, MAX(op.%s::date) AS censor_date
       FROM   "%s"."observation_period" op
       JOIN   idx ON idx.person_id = op.%s
       WHERE  op.%s::date >= idx.index_date
       GROUP  BY 1
     )
SELECT i.person_id, i.index_date,
       COALESCE(o.event_date, c.censor_date, i.index_date) AS end_date,
       CASE WHEN o.person_id IS NOT NULL THEN 1 ELSE 0 END AS status
FROM   idx i
LEFT JOIN outcomes  o ON o.person_id = i.person_id
LEFT JOIN censoring c ON c.person_id = i.person_id',
      pid_col, dat_col, sch, dom$table, pid_col, dat_col, concept_filter,
      op_pid, op_end, sch, op_pid, op_end)

    # ── Per-domain covariate query templates ────────────────────────────────
    cond_pid <- ac(cm, "condition_occurrence", "person_id")
    cond_cid <- ac(cm, "condition_occurrence", "condition_concept_id")
    cond_dat <- ac(cm, "condition_occurrence", "condition_start_date")
    drug_pid <- ac(cm, "drug_exposure", "person_id")
    drug_cid <- ac(cm, "drug_exposure", "drug_concept_id")
    drug_dat <- ac(cm, "drug_exposure", "drug_exposure_start_date")
    p_pid    <- ac(cm, "person", "person_id")
    p_yob    <- ac(cm, "person", "year_of_birth")
    p_gen    <- ac(cm, "person", "gender_concept_id")

    cond_sql <- sprintf(
'WITH idx(person_id, index_date) AS (VALUES %%s)
SELECT t.%s AS person_id,
       \'cond_\' || t.%s::text AS covariate,
       1 AS value
FROM   "%s"."condition_occurrence" t
JOIN   idx i ON i.person_id = t.%s
WHERE  t.%s != 0
  AND  t.%s::date >= i.index_date - %d
  AND  t.%s::date <  i.index_date',
      cond_pid, cond_cid, sch, cond_pid, cond_cid, cond_dat, lookback, cond_dat)

    drug_sql <- sprintf(
'WITH idx(person_id, index_date) AS (VALUES %%s)
SELECT t.%s AS person_id,
       \'drug_\' || t.%s::text AS covariate,
       1 AS value
FROM   "%s"."drug_exposure" t
JOIN   idx i ON i.person_id = t.%s
WHERE  t.%s != 0
  AND  t.%s::date >= i.index_date - %d
  AND  t.%s::date <  i.index_date',
      drug_pid, drug_cid, sch, drug_pid, drug_cid, drug_dat, lookback, drug_dat)

    demo_sql <- sprintf(
'WITH idx(person_id, index_date) AS (VALUES %%s)
SELECT p.%s AS person_id,
       EXTRACT(YEAR FROM i.index_date)::int - p.%s AS age_at_index,
       CASE WHEN p.%s = 8532 THEN 1 ELSE 0 END AS is_female
FROM   "%s"."person" p
JOIN   idx i ON i.person_id = p.%s',
      p_pid, p_yob, p_gen, sch, p_pid)

    # CCI: re-use the cci_map inline. Keep it compact since this snippet is
    # already long; only the concept_ids matter for scoring.
    cci_cond_pid <- ac(cm, "condition_occurrence", "person_id")
    cci_cond_cid <- ac(cm, "condition_occurrence", "condition_concept_id")
    cci_sql <- sprintf(
'SELECT DISTINCT %s AS person_id, %s AS concept_id
FROM   "%s"."condition_occurrence"
WHERE  %s IN (%%s)',
      cci_cond_pid, cci_cond_cid, sch, cci_cond_cid)

    horizon_block <- if (!is.null(horizon) && !is.na(suppressWarnings(as.integer(horizon)))) {
      sprintf('
# Apply time horizon
surv_data$time <- pmin(surv_data$time, %dL)
', as.integer(horizon))
    } else ""

    # Quote the final covariate list as an R character vector
    cov_quoted <- paste(sprintf('"%s"', covariates), collapse = ", ")

    sprintf('
# ── 3. Query survival data for the primary schema ────────────────────────
library(DBI)
library(survival)
library(ggplot2)

surv_query <- r"---(%s)---"
vals <- paste(
  sprintf("(%%.0f, \'%%s\'::date)",
          as.numeric(cohort_result$person_id),
          as.character(as.Date(cohort_result$index_date))),
  collapse = ", ")
surv_data <- DBI::dbGetQuery(xap.conn, sprintf(surv_query, vals))
names(surv_data) <- tolower(names(surv_data))
surv_data$time <- as.integer(as.Date(surv_data$end_date) -
                              as.Date(surv_data$index_date))
surv_data$time[surv_data$time < 0] <- 0
%s

# ── 4. Query condition + drug exposures in the lookback window ───────────
# Lookback: %d days before index_date.
cond_query <- r"---(%s)---"
drug_query <- r"---(%s)---"
demo_query <- r"---(%s)---"

cond_long <- DBI::dbGetQuery(xap.conn, sprintf(cond_query, vals))
drug_long <- DBI::dbGetQuery(xap.conn, sprintf(drug_query, vals))
demo      <- DBI::dbGetQuery(xap.conn, sprintf(demo_query, vals))
names(cond_long) <- tolower(names(cond_long))
names(drug_long) <- tolower(names(drug_long))
names(demo)      <- tolower(names(demo))
long_df <- rbind(cond_long, drug_long)

# ── 5. CCI score (uses condition_occurrence in any time window) ──────────
cci_query <- r"---(%s)---"
all_pids_sql <- paste(sprintf("%%.0f", as.numeric(cohort_result$person_id)),
                       collapse = ", ")
cci_pts <- DBI::dbGetQuery(xap.conn, sprintf(cci_query, all_pids_sql))
names(cci_pts) <- tolower(names(cci_pts))
cci_map <- list(
  list(w = 1, ids = c(4329847, 314666, 312327)),       # MI
  list(w = 1, ids = c(316139, 4229440)),                # CHF
  list(w = 1, ids = c(321596, 4108564)),                # PVD
  list(w = 1, ids = c(372924, 375557, 443454)),         # CVA
  list(w = 1, ids = c(4182210, 378419, 373192)),        # Dementia
  list(w = 1, ids = c(255573, 4274024)),                # COPD
  list(w = 1, ids = c(80809, 257628, 134442)),          # Rheumatic
  list(w = 1, ids = c(4027663, 40481087)),              # PUD
  list(w = 1, ids = c(4064161, 4212540)),               # Mild liver
  list(w = 1, ids = c(201820, 442793)),                 # Diabetes uncomp.
  list(w = 2, ids = c(201826, 4099651)),                # Diabetes comp.
  list(w = 2, ids = c(4291005, 432284)),                # Hemiplegia
  list(w = 2, ids = c(46271022, 4030518, 443919)),      # Renal
  list(w = 2, ids = c(443392, 4248385, 4112853, 4029524, 4212540)),  # Cancer
  list(w = 3, ids = c(4245975, 196454, 57345)),         # Mod./severe liver
  list(w = 6, ids = c(432851, 4212448)),                # Metastatic
  list(w = 6, ids = c(439727, 4159981))                 # AIDS/HIV
)
cci_score_one <- function(person_ids, pts) {
  out <- data.frame(person_id = unique(person_ids), cci_score = 0L)
  for (cat in cci_map) {
    hit <- unique(pts$person_id[pts$concept_id %%in%% cat$ids])
    if (length(hit) > 0) {
      i <- out$person_id %%in%% hit
      out$cci_score[i] <- out$cci_score[i] + cat$w
    }
  }
  out
}
cci_df <- cci_score_one(cohort_result$person_id, cci_pts)

# ── 6. Build the wide model matrix ───────────────────────────────────────
# Pivot the long-format covariate data to wide. Each unique covariate
# becomes a column; values are 1 if the person had that covariate in the
# lookback window, 0 otherwise.
mat <- surv_data[, c("person_id", "time", "status")]
mat <- merge(mat, demo[, c("person_id", "age_at_index", "is_female")],
             by = "person_id", all.x = TRUE)
mat <- merge(mat, cci_df, by = "person_id", all.x = TRUE)

# Pivot the long covariate data to wide
if (nrow(long_df) > 0) {
  wide <- reshape(unique(long_df), idvar = "person_id",
                   timevar = "covariate", direction = "wide",
                   v.names = "value")
  names(wide) <- sub("^value\\\\.", "", names(wide))
  for (c in names(wide)[names(wide) != "person_id"]) wide[[c]][is.na(wide[[c]])] <- 0
  mat <- merge(mat, wide, by = "person_id", all.x = TRUE)
  # Fill NAs introduced by the merge with 0
  for (c in names(mat)[!(names(mat) %%in%% c("person_id","time","status","age_at_index","is_female","cci_score"))]) {
    mat[[c]][is.na(mat[[c]])] <- 0
  }
}

# ── 7. Fit Cox model on the final covariate list ─────────────────────────
# These are the covariates the app retained after EPV-based and
# collinearity-based pruning. Hard-coded here so this snippet produces an
# identical model without re-running the pruning logic.
final_covariates <- c(%s)

# Defensive: keep only covariates that actually appear in the data
final_covariates <- intersect(final_covariates, names(mat))

mat <- mat[complete.cases(mat[, c("time", "status", final_covariates)]), ]

f <- as.formula(paste("Surv(time, status) ~",
                       paste(sprintf("`%%s`", final_covariates), collapse = " + ")))
fit_cox <- coxph(f, data = mat)
',
      surv_sql, horizon_block, lookback,
      cond_sql, drug_sql, demo_sql,
      cci_sql,
      cov_quoted)
  }

  # Show the R code that reproduces a chart in a modal
  .show_chart_code <- function(chart_id) {
    reg <- chart_registry_rv()
    spec <- reg[[chart_id]]
    if (is.null(spec)) return()
    code <- tryCatch(spec$code_fn(), error = function(e) {
      message("[chart_code] ", chart_id, ": ", conditionMessage(e))
      paste0("# Error generating code snippet: ", conditionMessage(e))
    })
    showModal(modalDialog(
      title = tagList(icon("code"), " R code: ", spec$label),
      tagList(
        tags$p(style = "color:var(--dre-muted);font-size:0.87rem;",
          "Copy and paste this into RStudio in your workspace. ",
          "It connects via xaputils, runs the SQL, and produces the chart. ",
          "No app-internal helpers required."),
        tags$pre(id = paste0("chart_code_pre_", chart_id),
          class = "chart-code-block",
          code)
      ),
      footer = tagList(
        actionButton(paste0("copy_code_", chart_id),
          tagList(icon("copy"), " Copy to clipboard"),
          class = "btn-dre-sec btn-sm",
          onclick = sprintf(
            "var el = document.getElementById('chart_code_pre_%s'); ",
            chart_id
          ) %||% ""),
        modalButton("Close")
      ),
      easyClose = TRUE,
      size = "l"
    ))
    # Trigger the JS copy handler when the button is clicked.
    # Using a custom message keeps the clipboard call decoupled from
    # whatever the modal's renderUI cycle does.
    session$sendCustomMessage("cb_register_copy_btn",
      list(btn_id = paste0("copy_code_", chart_id),
           pre_id = paste0("chart_code_pre_", chart_id)))
  }

  # Wire Save / Code observers for every registered chart. Done once when
  # the registry is first populated; subsequent additions also pick up.
  chart_observers_wired_rv <- reactiveVal(character(0))
  observe({
    reg <- chart_registry_rv()
    wired <- isolate(chart_observers_wired_rv())
    new_ids <- setdiff(names(reg), wired)
    for (cid in new_ids) {
      local({
        chart_id <- cid
        observeEvent(input[[paste0("save_", chart_id, "_btn")]], {
          .save_chart(chart_id)
        }, ignoreInit = TRUE)
        observeEvent(input[[paste0("code_", chart_id, "_btn")]], {
          .show_chart_code(chart_id)
        }, ignoreInit = TRUE)
      })
    }
    if (length(new_ids) > 0)
      chart_observers_wired_rv(c(wired, new_ids))
  })

  # Helper chart_toolbar() is defined at file scope so it can be called
  # from the UI; see the definition above the `ui <- ...` block.


  # ── Global concept search (cross-domain, creates new inclusion criterion) ──
  # Live-as-you-type concept search - debounced 350 ms so it doesn't fire
  # on every keystroke.  Clears results when the box is emptied.
  global_concept_q_d <- debounce(reactive(input$global_concept_q %||% ""), 350)

  observe({
    q <- trimws(global_concept_q_d())
    if (!nzchar(q) || nchar(q) < 2) {
      global_search_rv(NULL)
      return()
    }
    req(conn_valid(), length(input$schema_select %||% character(0)) > 0)
    res <- tryCatch(
      do_concept_search(q, domain_key = NULL),
      error = function(e) NULL)
    global_search_rv(res)
  })

  output$global_search_results_ui <- renderUI({
    res <- global_search_rv()
    q   <- trimws(input$global_concept_q %||% "")
    if (is.null(res)) {
      if (nchar(q) >= 1 && nchar(q) < 2)
        return(tags$p(style="font-size:0.84rem;color:var(--dre-muted);padding:6px 0;",
                      icon("keyboard"), " Type at least 2 characters to search..."))
      return(NULL)
    }
    if (nrow(res) == 0)
      return(tags$p(style = "font-size:0.87rem;color:var(--dre-muted);padding:8px 0;",
                    sprintf("No concepts matching \"%s\" found in the concept table.", q)))
    sm    <- schema_summary_rv()
    total <- if (!is.null(sm)) sm$n_persons else NA_integer_
    div(class = "gsb-results",
      tags$p(style = "font-size:0.84rem;color:var(--dre-muted);margin-bottom:6px;",
             sprintf("%d results - click to add as a new inclusion criterion", nrow(res))),
      tags$div(style = "max-height:260px;overflow-y:auto;",
        lapply(seq_len(min(nrow(res), 30L)), function(i) {
          r       <- res[i,]
          cid_val <- as.integer(r[["concept_id"]])
          nm      <- as.character(r[["concept_name"]])
          np      <- tryCatch(as.integer(r[["n_persons"]]), error = function(e) NA_integer_)
          dom_raw <- tolower(as.character(r[["domain_id"]] %||% ""))
          # v10.6: explicit mapping from OMOP's domain_id values to our
          # DOMAINS keys. The previous heuristic (grep against the table
          # name) failed for any domain where the table name doesn't
          # contain the domain_id string - e.g. "drug" vs "drug_exposure".
          # That made every drug result fall through to "condition" and
          # show the wrong chip.
          domain_key <- switch(dom_raw,
            "drug"        = "drug",
            "condition"   = "condition",
            "procedure"   = "procedure",
            "measurement" = "measurement",
            "observation" = "observation",
            "visit"       = "visit",
            "device"      = "drug",        # devices live in drug_exposure
            "condition")                    # safe default for unknown
          freq_str <- if (!is.na(np) && !is.na(total) && total > 0)
            sprintf(" · %s persons (%.1f%%)", format(np, big.mark=","), 100*np/total)
          else if (!is.na(np)) sprintf(" · %s persons", format(np, big.mark=",")) else ""
          voc <- as.character(r[["vocabulary_id"]] %||% "")
          std <- identical(as.character(r[["standard_concept"]] %||% ""), "S")
          div(class = "cs-row",
            onclick = sprintf(
              "Shiny.setInputValue('global_add_concept',{cid:%d,name:'%s',domain:'%s'},{priority:'event'})",
              cid_val, gsub("'", "\\\'", nm), domain_key),
            tags$span(style = "font-weight:600;color:var(--dre-text);", nm),
            if (std) tags$span(style = "font-size:0.78rem;color:var(--dre-success);margin-left:4px;", "✓ Standard"),
            tags$span(class = "cs-domain-pill", DOMAINS[[domain_key]]$label %||% dom_raw),
            if (nzchar(voc)) tags$span(style = "font-size:0.78rem;color:var(--dre-muted);margin-left:6px;", voc),
            tags$span(style = "font-size:0.84rem;color:var(--dre-teal);", freq_str)
          )
        })
      )
    )
  })

  observeEvent(input$global_add_concept, {
    payload   <- input$global_add_concept
    cid_val   <- as.integer(payload$cid)
    nm        <- as.character(payload$name %||% paste("Code", payload$cid))
    domain_key <- as.character(payload$domain %||% "condition")
    crits      <- criteria_rv()
    id_counter <- next_id_rv()
    new_id     <- paste0("crit_", id_counter)
    next_id_rv(id_counter + 1L)
    new_crit <- list(
      id = new_id, type = "inclusion", domain = domain_key,
      concept_ids = cid_val, occur_min = 1L, occur_max = NA_integer_,
      window_start = NA_integer_, window_end = NA_integer_,
      age_min = NA_integer_, age_max = NA_integer_,
      gender_ids = integer(0), value_min = NA_real_, value_max = NA_real_
    )
    cn <- concept_names_rv()
    cn[[as.character(cid_val)]] <- nm
    concept_names_rv(cn)
    criteria_rv(c(crits, list(new_crit)))
    global_search_rv(NULL)
    updateTextInput(session, "global_concept_q", value = "")
    showNotification(sprintf("Added: %s", nm), type = "message", duration = 3)
  })
  attrition_rv    <- reactiveVal(NULL)
  active_crit_rv  <- reactiveVal(NULL)         # criterion id receiving concept picks

  # ── Schema load ─────────────────────────────────────────────────────────────
  # Triggered on startup and whenever the user clicks ↺ Refresh.
  # get_schemas() uses xaputils::xap.conn directly for freshest state.

  load_schemas <- function() {
    df <- get_schemas()
    # Filter to schemas that look like OMOP CDM (>= 5 core tables present)
    omop_df <- if (!is.null(df$omop_hits))
      df[df$omop_hits >= 5L, , drop = FALSE]
    else
      df
    schemas_rv(omop_df)
    choices <- if (nrow(omop_df) > 0)
      setNames(omop_df$schema_name, omop_df$schema_name)
    else
      character(0)
    updateSelectInput(session, "export_schema", choices = choices)
    omop_df
  }

  observe({ load_schemas() })

  observeEvent(input$refresh_schemas_btn, {
    showNotification("Refreshing schema list...", type = "message", duration = 2)
    load_schemas()
  })

  # Render the schema selector with per-schema table counts
  output$schema_select_ui <- renderUI({
    df <- schemas_rv()
    if (!is.data.frame(df) || nrow(df) == 0) {
      if (!conn_valid())
        return(tags$p(style = "color:var(--dre-muted);font-size:0.84rem;margin:6px 0;",
                      "No database connection."))
      return(tags$p(style = "color:var(--dre-muted);font-size:0.84rem;margin:6px 0;",
                    "No OMOP schemas found. Click \u21ba to refresh."))
    }
    hits   <- if (!is.null(df$omop_hits)) df$omop_hits else rep(NA_integer_, nrow(df))
    n_core <- length(OMOP_CORE_TABLES)
    labels <- ifelse(
      !is.na(hits),
      sprintf("%s  (%d/%d OMOP tables)", df$schema_name, hits, n_core),
      sprintf("%s  (%d tables)",          df$schema_name, df$table_count)
    )
    # Badge schemas that contain a cohort table (the cohort triple) so a
    # materialised cohort is visually distinct from a plain dataset.
    cohort_set <- ohdsi_cohort_schema_set(df$schema_name)
    choiceNames <- lapply(seq_len(nrow(df)), function(i) {
      is_cohort <- df$schema_name[i] %in% cohort_set
      tags$span(labels[i],
        if (is_cohort) tags$span(
          style = "margin-left:6px;padding:1px 7px;border-radius:10px;font-size:0.7rem;background:var(--dre-teal);color:#04212a;font-weight:600;vertical-align:middle;",
          "cohort"))
    })
    choiceValues <- as.list(df$schema_name)
    tagList(
      # checkboxGroupInput allows multi-select; single selection = existing behaviour
      checkboxGroupInput("schema_select", label = NULL,
                         choiceNames = choiceNames, choiceValues = choiceValues,
                         width = "100%"),
      tags$p(style = "color:var(--dre-muted);font-size:0.80rem;margin:2px 0 0;",
             sprintf("%d OMOP schema%s found",
                     nrow(df), if (nrow(df) == 1) "" else "s")),
      uiOutput("vocab_check_ui"),
      uiOutput("overlap_ui")
    )
  })

  # ── Connection status ───────────────────────────────────────────────────────
  output$connection_status_ui <- renderUI({
    if (conn_valid())
      tags$div(tags$span(class = "conn-dot ok"), "Connected")
    else
      tags$div(tags$span(class = "conn-dot err"), "No connection")
  })

  # ── OMOP detection + column map + schema data summary ───────────────────────
  observeEvent(input$schema_select, {
    schemas <- input$schema_select %||% character(0)
    if (length(schemas) == 0) return()
    req(conn_valid())
    multi_mode_rv(length(schemas) > 1)

    # Clear previous state - also reset suggestion banner so it
    # refreshes fully whenever the schema selection changes.
    schema_summary_rv(NULL)
    schema_profile_rv(list())  # v10.12
    omop_col_map_rv(list())
    vocab_check_rv(NULL)
    overlap_rv(NULL)
    crit_counts_rv(list())
    smart_templates_rv(NULL)   # force spinner while re-scoring
    first_run_dismissed_rv(FALSE)  # re-show banner with fresh scores

    withProgress(message = "Loading schema data\u2026", value = 0, {
      # ── Load col_map and summary for each selected schema ──────────────
      new_col_maps  <- list()
      new_summaries <- list()
      for (k in seq_along(schemas)) {
        sch <- schemas[k]
        setProgress(k / (length(schemas) + 2),
                    detail = sprintf("Resolving %s\u2026", sch))
        cm  <- get_omop_col_map(sch)
        sm  <- get_schema_summary(sch, cm)
        new_col_maps[[sch]]  <- cm
        new_summaries[[sch]] <- sm
      }
      col_maps_rv(new_col_maps)
      summaries_rv(new_summaries)

      # For single-schema backwards compat: expose first schema's col_map
      omop_col_map_rv(new_col_maps[[schemas[1]]] %||% list())
      omop_rv(detect_omop(schemas[1]))
      schema_summary_rv(new_summaries[[schemas[1]]])

      # ── Multi-schema checks (only when >1 schema) ──────────────────────
      if (length(schemas) > 1) {
        setProgress(0.75, detail = "Checking vocabulary consistency\u2026")
        vocab_check_rv(check_vocab_consistency(schemas, new_col_maps))
        setProgress(0.85, detail = "Checking observation periods\u2026")
        overlap_rv(check_obs_overlap(schemas, new_col_maps))
      }

      # ── Score templates across all schemas ─────────────────────────────
      setProgress(0.92, detail = "Scoring cohort suggestions\u2026")
      smart_templates_rv(NULL)
      # score_templates_multi handles both single and multi-schema cases.
      # For multi-schema it applies cross-schema overlap bonuses and builds
      # combined evidence that highlights concepts found across all schemas.
      scored <- score_templates_multi(schemas, new_col_maps, new_summaries, TEMPLATES)
      smart_templates_rv(scored)

      # ── Schema Profile (v10.12) ────────────────────────────────────────────
      # Run schema_profile for each selected schema and cache by name.
      setProgress(0.97, detail = "Building schema profile...")
      new_profiles <- list()
      for (sch in schemas) {
        cm <- new_col_maps[[sch]] %||% list()
        new_profiles[[sch]] <- schema_profile(sch, cm)
      }
      schema_profile_rv(new_profiles)
    })
  })

  # ── Vocabulary check UI ─────────────────────────────────────────────────────
  output$vocab_check_ui <- renderUI({
    vc <- vocab_check_rv()
    if (is.null(vc)) return(NULL)
    icon_map <- c(green="circle-check", amber="triangle-exclamation", red="circle-xmark")
    label_map <- c(green="Vocabularies consistent", amber="Minor vocabulary differences",
                   red="Vocabulary incompatibility detected")
    div(class = paste("vocab-panel", paste0("vocab-", vc$status)),
      tags$span(icon(icon_map[vc$status]), " ", label_map[vc$status]),
      if (length(vc$detail) > 0)
        tagList(lapply(vc$detail, function(d)
          tags$p(class = "vocab-issue", d)))
    )
  })

  # ── Observation period overlap UI ────────────────────────────────────────────
  output$overlap_ui <- renderUI({
    ov <- overlap_rv()
    if (is.null(ov)) return(NULL)
    icon_map  <- c(full="circle-check", partial="triangle-exclamation", none="circle-xmark")
    label_map <- c(
      full    = "Observation periods overlap \u2014 combined analysis valid",
      partial = "Partial overlap \u2014 cross-schema curves may mix eras",
      none    = "No overlap \u2014 cross-schema analyses gated, deselect or acknowledge"
    )
    detail <- if (ov$overlap == "full") {
      sprintf("Shared window: %s \u2192 %s (%d days)",
              ov$overlap_start, ov$overlap_end, ov$overlap_days)
    } else if (ov$overlap == "partial") {
      sprintf("Overlap window: %s \u2192 %s (%d days)",
              ov$overlap_start, ov$overlap_end, ov$overlap_days)
    } else {
      ranges <- ov$ranges
      paste(sapply(names(ranges), function(s) {
        r <- ranges[[s]]
        sprintf("%s: %s \u2192 %s", s,
                format(r$min, "%Y"), format(r$max, "%Y"))
      }), collapse = " | ")
    }
    div(class = paste("overlap-panel", paste0("overlap-", ov$overlap)),
      tags$span(icon(icon_map[ov$overlap]), " ", label_map[ov$overlap]),
      tags$p(style="font-size:0.80rem;margin:4px 0 0;color:inherit;opacity:0.85;", detail)
    )
  })

  # ── Reset per-tab acknowledgements when overlap status changes ──────────────
  # Triggers when the user changes schemas, rebuilds the cohort, or reconnects.
  # The intent is: each new overlap context requires a fresh acknowledgement.
  observeEvent(overlap_rv(), {
    proceed_km_rv(FALSE)
    proceed_cif_rv(FALSE)
    proceed_cox_rv(FALSE)
    proceed_compare_rv(FALSE)
  }, ignoreNULL = FALSE, ignoreInit = TRUE)

  # Per-tab acknowledgement buttons (rendered by overlap_banner_ui)
  observeEvent(input$ack_overlap_km,      proceed_km_rv(TRUE))
  observeEvent(input$ack_overlap_cif,     proceed_cif_rv(TRUE))
  observeEvent(input$ack_overlap_cox,     proceed_cox_rv(TRUE))
  observeEvent(input$ack_overlap_compare, proceed_compare_rv(TRUE))

  # Banners rendered in each gated tab
  output$km_overlap_banner <- renderUI({
    overlap_banner_ui(overlap_rv(),
                      ack_input_id = "ack_overlap_km",
                      acknowledged = isTRUE(proceed_km_rv()),
                      tab_name     = "Kaplan-Meier")
  })
  output$cif_overlap_banner <- renderUI({
    overlap_banner_ui(overlap_rv(),
                      ack_input_id = "ack_overlap_cif",
                      acknowledged = isTRUE(proceed_cif_rv()),
                      tab_name     = "Competing Risks")
  })
  output$cox_overlap_banner <- renderUI({
    overlap_banner_ui(overlap_rv(),
                      ack_input_id = "ack_overlap_cox",
                      acknowledged = isTRUE(proceed_cox_rv()),
                      tab_name     = "Cox regression")
  })
  output$compare_overlap_banner <- renderUI({
    overlap_banner_ui(overlap_rv(),
                      ack_input_id = "ack_overlap_compare",
                      acknowledged = isTRUE(proceed_compare_rv()),
                      tab_name     = "cohort comparison")
  })


  # ── Schema Profile extended card (v10.12) ─────────────────────────────────────
  # Aggregates across ALL selected schemas, not just the primary.
  output$schema_profile_ui <- renderUI({
    schemas  <- input$schema_select %||% character(0)
    profiles <- schema_profile_rv()
    sums     <- summaries_rv()
    if (length(schemas) == 0 || length(profiles) == 0) return(NULL)

    # Collect per-schema profile objects; drop any that failed to load.
    sp_list <- Filter(Negate(is.null), lapply(schemas, function(s) profiles[[s]]))
    if (length(sp_list) == 0) return(NULL)

    # ── Aggregate: persons (sum across schemas) + date range (union) ──────────
    sm_list <- Filter(Negate(is.null), lapply(schemas, function(s) sums[[s]]))
    total_persons <- sum(sapply(sm_list, function(sm) sm$n_persons %||% 0L), na.rm = TRUE)
    all_min <- Filter(Negate(is.na), sapply(sm_list, function(sm) sm$min_date %||% NA_character_))
    all_max <- Filter(Negate(is.na), sapply(sm_list, function(sm) sm$max_date %||% NA_character_))
    yr_min  <- if (length(all_min) > 0) substr(min(all_min), 1, 4) else "?"
    yr_max  <- if (length(all_max) > 0) substr(max(all_max), 1, 4) else "?"
    n_str   <- if (total_persons > 0) format(total_persons, big.mark = ",") else "-"

    top_metrics <- div(class = "schema-metrics",
      div(class = "schema-metric",
        div(class = "sm-val", n_str),
        div(class = "sm-lbl", if (length(schemas) > 1) "Persons (sum)" else "Persons")
      ),
      div(class = "schema-metric",
        div(class = "sm-val", paste(yr_min, "-", yr_max)),
        div(class = "sm-lbl", "Date range")
      )
    )

    # ── CDM version: unique versions across schemas ───────────────────────────
    cdm_versions <- unique(sapply(sp_list, `[[`, "cdm_version"))
    cdm_label    <- paste(cdm_versions, collapse = " / ")
    known        <- !all(cdm_versions == "unknown")
    cdm_badge <- div(
      style = "display:flex;align-items:center;gap:8px;margin-bottom:10px;",
      tags$span(style = "font-size:0.80rem;color:var(--dre-muted);text-transform:uppercase;letter-spacing:.5px;",
                "CDM version"),
      tags$span(
        style = paste0(
          "background:", if (!known) "var(--dre-mid)" else "var(--dre-teal-dim)",
          ";color:",     if (!known) "var(--dre-muted)" else "var(--dre-teal)",
          ";border-radius:6px;padding:2px 10px;font-size:0.84rem;font-weight:700;"),
        cdm_label)
    )

    # ── Ancestor status: worst-case across schemas (red beats amber beats green)
    status_rank  <- c(green = 1L, amber = 2L, red = 3L)
    anc_statuses <- sapply(sp_list, `[[`, "ancestor_status")
    worst_status <- names(which.max(status_rank[anc_statuses]))
    total_anc_rows <- sum(sapply(sp_list, function(sp) sp$ancestor_rows %||% 0L), na.rm = TRUE)
    anc_col  <- c(green = "var(--dre-success)", amber = "var(--dre-gold)", red = "var(--dre-error)")[[worst_status]]
    anc_icon <- c(green = "circle-check", amber = "triangle-exclamation", red = "circle-xmark")[[worst_status]]
    anc_note <- c(
      green = "Hierarchy navigation fully available.",
      amber = "concept_ancestor present but sparse in at least one schema; hierarchy may be incomplete.",
      red   = "concept_ancestor absent or empty in at least one schema; hierarchy navigation unavailable."
    )[[worst_status]]
    anc_badge <- div(
      style = "margin-bottom:10px;",
      tags$span(style = paste0("color:", anc_col, ";font-size:0.87rem;"),
        icon(anc_icon), " ", anc_note),
      if (worst_status == "green")
        tags$span(style = "font-size:0.80rem;color:var(--dre-muted);",
          sprintf(" (%s rows total)", format(total_anc_rows, big.mark=",")))
    )

    # ── Vocabulary mix: sum records across schemas, re-rank top 5 ─────────────
    vocab_combined <- do.call(rbind, lapply(sp_list, `[[`, "vocab_mix_df"))
    vocab_bar <- if (!is.null(vocab_combined) && nrow(vocab_combined) > 0) {
      vocab_agg <- aggregate(n_records ~ vocabulary_id, data = vocab_combined, FUN = sum)
      vocab_agg <- vocab_agg[order(-vocab_agg$n_records), , drop = FALSE]
      vocab_agg <- head(vocab_agg, 5)
      total_shown <- sum(vocab_agg$n_records)
      colours <- c("#00C5B5","#00A89A","#008B7D","#006F63","#005249")
      segments <- lapply(seq_len(nrow(vocab_agg)), function(i) {
        pct <- 100 * vocab_agg$n_records[i] / max(1, total_shown)
        col <- colours[min(i, length(colours))]
        tags$div(
          style = sprintf("width:%.1f%%;background:%s;height:100%%;display:inline-block;", pct, col),
          title = sprintf("%s: %s records (%.1f%%)",
                          vocab_agg$vocabulary_id[i],
                          format(vocab_agg$n_records[i], big.mark=","), pct))
      })
      tagList(
        tags$p(style = "font-size:0.80rem;color:var(--dre-muted);text-transform:uppercase;letter-spacing:.5px;margin:0 0 4px;",
               "Top vocabularies (by record count)"),
        div(style = "height:14px;border-radius:4px;overflow:hidden;background:var(--dre-mid);display:flex;margin-bottom:4px;",
            do.call(tagList, segments)),
        div(style = "display:flex;flex-wrap:wrap;gap:6px;",
          lapply(seq_len(nrow(vocab_agg)), function(i) {
            col <- colours[min(i, length(colours))]
            tags$span(style = "font-size:0.77rem;color:var(--dre-text);display:flex;align-items:center;gap:3px;",
              tags$span(style = sprintf("width:9px;height:9px;border-radius:2px;background:%s;display:inline-block;", col)),
              vocab_agg$vocabulary_id[i])
          })
        )
      )
    } else NULL

    # ── Domain tiles: sum n_persons + n_records across schemas,
    #    union date range (earliest min, latest max) ───────────────────────────
    domain_icons <- c(
      condition = "heartbeat", drug = "pills", procedure = "cut",
      measurement = "ruler", observation = "eye", visit = "hospital", death = "skull"
    )
    domain_tiles <- tagList(
      tags$p(style = "font-size:0.80rem;color:var(--dre-muted);text-transform:uppercase;letter-spacing:.5px;margin:10px 0 4px;",
             "Populated domains"),
      div(class = "domain-grid",
        lapply(names(DOMAINS), function(key) {
          dom <- DOMAINS[[key]]
          # Collect this domain's row from every schema profile
          rows <- lapply(sp_list, function(sp) {
            df <- sp$domain_stats_df
            if (is.null(df)) return(NULL)
            df[df$key == key, , drop = FALSE]
          })
          rows <- Filter(function(r) !is.null(r) && nrow(r) > 0, rows)
          np   <- sum(sapply(rows, function(r) r$n_persons[1] %||% 0L), na.rm = TRUE)
          nr   <- sum(sapply(rows, function(r) r$n_records[1] %||% 0L), na.rm = TRUE)
          mins <- Filter(Negate(is.na), sapply(rows, function(r) r$min_date[1]))
          maxs <- Filter(Negate(is.na), sapply(rows, function(r) r$max_date[1]))
          mn   <- if (length(mins) > 0) substr(min(mins), 1, 4) else NA_character_
          mx   <- if (length(maxs) > 0) substr(max(maxs), 1, 4) else NA_character_
          has  <- np > 0
          np_str   <- if (has) format(np, big.mark=",") else "-"
          nr_str   <- if (nr > 0) format(nr, big.mark=",") else ""
          date_str <- if (!is.na(mn) && !is.na(mx)) paste0(mn, "-", mx) else ""
          badge_class <- paste("domain-badge", if (has) "has-data" else "no-data")
          if (has) {
            tags$div(class = badge_class,
              onClick = sprintf("Shiny.setInputValue('domain_tile_click','%s',{priority:'event'})", key),
              div(class = "db-icon", icon(domain_icons[[key]] %||% "circle")),
              div(class = "db-count", np_str),
              div(class = "db-label", dom$label),
              if (nzchar(nr_str))   tags$span(class = "domain-badge-hint", nr_str, " records"),
              if (nzchar(date_str)) tags$span(class = "domain-badge-hint", date_str)
            )
          } else {
            tags$div(class = badge_class,
              div(class = "db-icon", icon(domain_icons[[key]] %||% "circle")),
              div(class = "db-count", "-"),
              div(class = "db-label", dom$label)
            )
          }
        })
      )
    )

    tagList(
      top_metrics,
      tags$hr(style = "border-color:var(--dre-border);margin:8px 0;"),
      cdm_badge,
      anc_badge,
      if (!is.null(vocab_bar)) tagList(vocab_bar, tags$br()),
      domain_tiles
    )
  })


  # ══════════════════════════════════════════════════════════════════════════
  #  CONCEPT BROWSER
  # ══════════════════════════════════════════════════════════════════════════

  # ── Annotate domain dropdown labels with person counts ────────────────────
  # v10.13 fix: previously this observer unconditionally re-emitted choices +
  # selected on every schema_profile_rv change, which caused Shiny to echo
  # input$browser_domain back to the server even when the value was unchanged.
  # The echo set browser_domain_rv to the same value (a no-op in reactiveVal),
  # so the downstream query observer never re-fired on user clicks.
  # Fix: diff the labels and only push if they actually changed; let
  # input$browser_domain be the direct trigger for downstream observers.
  #
  # CRITICAL: updateSelectInput expects choices = c(label = value), i.e. the
  # *names* of the vector are the displayed labels and the *values* are what
  # gets sent to input$browser_domain. Building it the other way round causes
  # bare keys to display AND input$browser_domain to receive the formatted
  # label string instead of the domain key, breaking everything downstream.
  observe({
    schemas  <- input$schema_select %||% character(0)
    profiles <- schema_profile_rv()
    if (length(profiles) == 0) return()
    # When the user deselects all schemas the observer still fires (profiles
    # may be cached). sapply over an empty character vector returns list(),
    # and sum(list()) errors with "invalid 'type' (list) of argument" -
    # guard explicitly.
    if (length(schemas) == 0) {
      browser_dom_labels_rv(setNames(names(DOMAINS),
        sprintf("%s - no schema selected",
                vapply(DOMAINS, `[[`, character(1), "label"))))
      return()
    }
    # Build a named character vector where names = displayed labels,
    # values = domain keys (what input$browser_domain receives).
    dom_labels <- character(length(DOMAINS))
    dom_keys   <- names(DOMAINS)
    for (i in seq_along(dom_keys)) {
      key      <- dom_keys[i]
      dom_def  <- DOMAINS[[key]]
      # vapply with integer(1) template - same semantics as sapply when it
      # simplifies, but errors loudly rather than returning a list if a
      # branch returns something other than length-1 integer.
      np_total <- sum(vapply(schemas, function(s) {
        sp  <- profiles[[s]]
        if (is.null(sp) || is.null(sp$domain_stats_df)) return(0L)
        row <- sp$domain_stats_df[sp$domain_stats_df$key == key, , drop = FALSE]
        if (nrow(row) == 0 || is.na(row$n_persons[1])) return(0L)
        as.integer(row$n_persons[1])
      }, integer(1)), na.rm = TRUE)
      dom_labels[i] <- if (np_total > 0)
        sprintf("%s - %s persons", dom_def$label, format(np_total, big.mark = ","))
      else
        sprintf("%s - no data", dom_def$label)
    }
    dom_choices <- setNames(dom_keys, dom_labels)
    prev <- isolate(browser_dom_labels_rv())
    if (!identical(prev, dom_choices)) {
      browser_dom_labels_rv(dom_choices)
      cur_sel <- isolate(input$browser_domain) %||% "condition"
      # Defend against the case where input$browser_domain currently holds a
      # stale formatted label string (from a pre-v10.13 broken state).
      if (!cur_sel %in% dom_keys) cur_sel <- "condition"
      updateSelectInput(session, "browser_domain",
                        choices  = dom_choices,
                        selected = cur_sel)
    }
  })

  # ── Shared browser query execution ────────────────────────────────────────
  browser_search_debounced <- reactive({ input$browser_search }) |> debounce(600)

  .do_browser_load <- function(domain_key, search_text) {
    if (!conn_valid()) return()
    schemas <- isolate(input$schema_select) %||% character(0)
    if (length(schemas) == 0) return()
    col_maps <- isolate(col_maps_rv())
    if (length(col_maps) == 0) return()
    browser_list_rv(NULL)
    browser_selected_rv(NA_integer_)
    browser_detail_rv(list(overview = NULL, overview_loaded = FALSE))
    dom_key <- if (!is.null(domain_key) && nzchar(domain_key)) domain_key else NULL
    message(sprintf("[browse-load] schemas=[%s] dom=%s search='%s'",
                    paste(schemas, collapse=","), dom_key %||% "NULL",
                    search_text %||% ""))
    result <- withProgress(
      message = "Loading concepts by prevalence",
      detail  = sprintf("Across %d schema%s",
                       length(schemas),
                       if (length(schemas) == 1) "" else "s"),
      value   = NULL,
      {
        browse_concepts_multi_schema(
          schemas       = schemas,
          col_maps      = col_maps,
          domain_key    = dom_key,
          vocab_id      = NULL,
          standard_only = TRUE,
          has_data_only = FALSE,  # v10.13: LEFT JOIN so ingredients/abstract nodes appear
          search_text   = search_text %||% "",
          limit         = 200L,
          order_by      = isolate(browser_sort_rv())
        )
      })
    browser_list_rv(result)
  }

  # ── Domain change (prevalence mode): read input$browser_domain directly ───
  # Only fires for prevalence mode; the observe() block below handles
  # hierarchy and vocabulary refresh on domain change.
  observeEvent(input$browser_domain, {
    if (browser_mode_rv() != "prevalence") return()
    .do_browser_load(input$browser_domain, isolate(browser_search_debounced()))
  }, ignoreNULL = TRUE)

  # ── Search: debounced 600ms ────────────────────────────────────────────────
  observeEvent(browser_search_debounced(), {
    if (browser_mode_rv() != "prevalence") return()
    .do_browser_load(isolate(input$browser_domain), browser_search_debounced())
  }, ignoreInit = TRUE)

  # ── Schema load: fires when col_maps_rv becomes ready (multi-schema aware)
  observeEvent(col_maps_rv(), {
    if (length(col_maps_rv()) == 0) return()
    # Schema selection changed; clear caches for both hierarchy and overlap.
    browser_hier_cache_rv(list())
    browser_overlap_cache_rv(list())
    browser_overlap_region_rv(NULL)  # clear any active Venn filter
    # Reload the overlap unconditionally - it's used by all modes via the
    # chrome above the list, independent of which list mode is active.
    .do_overlap_load()
    # Refresh whichever list mode is currently active
    mode <- isolate(browser_mode_rv())
    if (mode == "prevalence")
      .do_browser_load(isolate(input$browser_domain), isolate(browser_search_debounced()))
    else if (mode == "hierarchy")
      .do_hierarchy_load()
    else if (mode == "vocabulary")
      .do_vocab_load()
  }, ignoreInit = TRUE)

  # ── Hierarchy loader ──────────────────────────────────────────────────────
  # Loads either the roots of the current domain (when path is empty) or the
  # direct children of the last element in the path. Uses
  # ── Schema overlap loader ─────────────────────────────────────────────────
  # Computes the Venn region partition for the currently selected schemas
  # and domain. Session-cached per (schemas, domain). Cleared when schemas
  # change (col_maps_rv reactive); not re-fetched on sort/filter/row-click.
  .do_overlap_load <- function() {
    if (!conn_valid()) return()
    schemas  <- isolate(input$schema_select) %||% character(0)
    col_maps <- isolate(col_maps_rv())
    dom_key  <- isolate(input$browser_domain)
    if (length(schemas) == 0 || length(col_maps) == 0) {
      browser_overlap_rv(NULL); return()
    }
    if (is.null(dom_key) || !nzchar(dom_key)) {
      browser_overlap_rv(NULL); return()
    }
    if (length(schemas) > 3) {
      # Per the 3-schema cap. Surface a non-fatal message; the renderer will
      # display a "too many schemas" note rather than a Venn.
      message("[overlap] >3 schemas selected (", length(schemas),
              "); Venn not rendered")
      browser_overlap_rv(list(too_many = TRUE, n = length(schemas)))
      return()
    }
    cache_key <- paste(c(paste(sort(schemas), collapse=","), dom_key),
                       collapse = "|")
    cache <- isolate(browser_overlap_cache_rv())
    if (!is.null(cache[[cache_key]])) {
      message("[overlap-load] cache HIT key=", cache_key)
      browser_overlap_rv(cache[[cache_key]])
      return()
    }
    message("[overlap-load] cache MISS key=", cache_key)
    browser_overlap_rv(NULL)
    data <- withProgress(
      message = "Computing schema overlap",
      detail  = sprintf("Across %d schema%s",
                       length(schemas),
                       if (length(schemas) == 1) "" else "s"),
      value   = NULL,
      compute_schema_overlap_multi(schemas, col_maps, dom_key)
    )
    cache[[cache_key]] <- data
    browser_overlap_cache_rv(cache)
    browser_overlap_rv(data)
  }

  # ── Hierarchy loader ──────────────────────────────────────────────────────
  # Loads either the roots of the current domain (when path is empty) or the
  # direct children of the last element in the path. Uses
  # browser_hier_cache_rv keyed by (schemas, domain, parent_cid) so the same
  # path is never queried twice in a session. The cache is cleared whenever
  # col_maps_rv changes (schema selection changed) or the user clicks the
  # refresh button on the breadcrumb.
  .do_hierarchy_load <- function() {
    if (!conn_valid()) return()
    schemas  <- isolate(input$schema_select) %||% character(0)
    col_maps <- isolate(col_maps_rv())
    dom_key  <- isolate(input$browser_domain)
    if (length(schemas) == 0 || length(col_maps) == 0) return()
    if (is.null(dom_key) || !nzchar(dom_key)) return()
    path <- isolate(browser_hier_path_rv())
    parent_cid <- if (length(path) == 0) NA_integer_ else path[[length(path)]]$concept_id
    # Cache key: schemas sorted (so order doesn't matter), domain, parent.
    cache_key <- paste(c(paste(sort(schemas), collapse=","),
                         dom_key,
                         as.character(parent_cid %||% "ROOT")),
                       collapse = "|")
    cache <- isolate(browser_hier_cache_rv())
    if (!is.null(cache[[cache_key]])) {
      message("[hier-load] cache HIT key=", cache_key)
      browser_hier_rv(cache[[cache_key]])
      return()
    }
    message("[hier-load] cache MISS key=", cache_key)
    browser_hier_rv(NULL)
    is_root <- length(path) == 0
    data <- withProgress(
      message = if (is_root) "Loading hierarchy roots"
                else        sprintf("Loading children of %s",
                                    path[[length(path)]]$concept_name),
      detail  = "Computing descendant rollup\u2026",
      value   = NULL,
      {
        if (is_root) {
          browse_hierarchy_roots_multi(schemas, col_maps, dom_key, limit = 50L)
        } else {
          browse_hierarchy_children_multi(schemas, col_maps, dom_key,
                                          parent_cid, limit = 200L)
        }
      })
    # Store in cache (even if NULL/empty - avoid re-querying empty branches)
    cache[[cache_key]] <- data
    browser_hier_cache_rv(cache)
    browser_hier_rv(data)
  }

  # ── Vocabulary loader ─────────────────────────────────────────────────────
  # If a vocab is selected, loads concepts in that vocab (with current domain
  # filter applied if any). Otherwise loads the vocab list.
  .do_vocab_load <- function() {
    if (!conn_valid()) return()
    schemas  <- isolate(input$schema_select) %||% character(0)
    col_maps <- isolate(col_maps_rv())
    if (length(schemas) == 0 || length(col_maps) == 0) return()
    sel_vocab <- isolate(browser_vocab_sel_rv())
    dom_key   <- isolate(input$browser_domain)
    if (is.null(sel_vocab)) {
      browser_vocab_list_rv(NULL)
      message("[vocab-load] list dom=", dom_key %||% "NULL")
      data <- withProgress(
        message = "Loading vocabularies",
        detail  = sprintf("Across %d schema%s",
                         length(schemas),
                         if (length(schemas) == 1) "" else "s"),
        value   = NULL,
        list_vocabularies_with_prevalence_multi(schemas, col_maps, dom_key)
      )
      browser_vocab_list_rv(data)
    } else {
      browser_vocab_concepts_rv(NULL)
      message("[vocab-load] concepts vocab=", sel_vocab, " dom=", dom_key %||% "NULL")
      data <- withProgress(
        message = sprintf("Loading %s concepts", sel_vocab),
        detail  = "Computing prevalence\u2026",
        value   = NULL,
        browse_concepts_multi_schema(
          schemas       = schemas,
          col_maps      = col_maps,
          domain_key    = dom_key,
          vocab_id      = sel_vocab,
          standard_only = TRUE,
          has_data_only = FALSE,  # v10.13: show ingredients/abstract nodes
          search_text   = "",
          limit         = 200L,
          order_by      = isolate(browser_sort_rv()))
      )
      browser_vocab_concepts_rv(data)
    }
  }

  # ── Mode click: switch the active browse mode ─────────────────────────────
  observeEvent(input$browser_mode_click, {
    mode <- input$browser_mode_click
    if (!mode %in% c("prevalence", "hierarchy", "vocabulary")) return()
    if (identical(mode, isolate(browser_mode_rv()))) return()
    browser_mode_rv(mode)
    session$sendCustomMessage("cb_set_mode_active", mode)
    # Clear concept selection so the detail panel doesn't show stale info
    # for a concept that isn't in the new mode's list.
    browser_selected_rv(NA_integer_)
    browser_detail_rv(list(overview = NULL, overview_loaded = FALSE))
    # Clear per-tab filter inputs on mode switch (users expect a fresh start).
    # Note: sendInputMessage doesn't work for raw <input> elements driven by
    # Shiny.setInputValue, so we use a custom message that the client-side
    # handler resets both the DOM value and the Shiny input value.
    session$sendCustomMessage("cb_clear_filter_inputs", list())
    # Reset per-mode state when entering a mode
    if (mode == "hierarchy") {
      browser_hier_path_rv(list())
      .do_hierarchy_load()
    } else if (mode == "vocabulary") {
      browser_vocab_sel_rv(NULL)
      .do_vocab_load()
    } else {
      .do_browser_load(isolate(input$browser_domain),
                       isolate(browser_search_debounced()))
    }
  }, ignoreNULL = TRUE)

  # ── Domain change: re-trigger the active mode ─────────────────────────────
  # (Note: this replaces the simpler observer above. Domain change should
  # refresh whichever mode is currently shown, not always prevalence.)
  observe({
    dom <- input$browser_domain
    if (is.null(dom) || !nzchar(dom)) return()
    # Domain change always invalidates the active Venn region filter.
    isolate({
      browser_overlap_region_rv(NULL)
      .do_overlap_load()
    })
    mode <- isolate(browser_mode_rv())
    if (mode == "hierarchy") {
      # Domain change resets hierarchy path to root
      browser_hier_path_rv(list())
      .do_hierarchy_load()
    } else if (mode == "vocabulary") {
      # Domain change resets to vocab list
      browser_vocab_sel_rv(NULL)
      .do_vocab_load()
    }
    # For prevalence mode the existing observeEvent(input$browser_domain)
    # below handles the reload, so we don't double-fire here.
  })

  # ── Hierarchy: click a node to drill in ───────────────────────────────────
  observeEvent(input$browser_hier_drill, {
    payload <- input$browser_hier_drill
    if (is.null(payload)) return()
    # Payload arrives as a JSON object with concept_id + concept_name
    cid <- suppressWarnings(as.integer(payload$concept_id))
    cnm <- as.character(payload$concept_name %||% "")
    if (is.na(cid)) return()
    path <- isolate(browser_hier_path_rv())
    browser_hier_path_rv(c(path, list(list(concept_id = cid, concept_name = cnm))))
    .do_hierarchy_load()
  }, ignoreNULL = TRUE)

  # ── Hierarchy: breadcrumb click to jump to ancestor (or root) ─────────────
  observeEvent(input$browser_hier_breadcrumb, {
    target <- input$browser_hier_breadcrumb  # 0 = root; 1..n = depth in path
    target <- suppressWarnings(as.integer(target))
    if (is.na(target) || target < 0) return()
    path <- isolate(browser_hier_path_rv())
    if (target == 0) {
      browser_hier_path_rv(list())
    } else if (target <= length(path)) {
      browser_hier_path_rv(path[seq_len(target)])
    }
    .do_hierarchy_load()
  }, ignoreNULL = TRUE)

  # ── Hierarchy: refresh button (clear cache and reload current view) ───────
  observeEvent(input$browser_hier_refresh, {
    message("[hier-refresh] clearing cache, reloading current view")
    browser_hier_cache_rv(list())
    .do_hierarchy_load()
  }, ignoreNULL = TRUE)

  # ── Vocabulary: click a vocab to drill in ─────────────────────────────────
  observeEvent(input$browser_vocab_drill, {
    v <- as.character(input$browser_vocab_drill %||% "")
    if (!nzchar(v)) return()
    browser_vocab_sel_rv(v)
    .do_vocab_load()
  }, ignoreNULL = TRUE)

  # ── Vocabulary: back to the vocab list ────────────────────────────────────
  observeEvent(input$browser_vocab_back, {
    browser_vocab_sel_rv(NULL)
    browser_vocab_concepts_rv(NULL)
    .do_vocab_load()
  }, ignoreNULL = TRUE)

  # ── Overlap region click ──────────────────────────────────────────────────
  # User clicked a Venn region (or a legend row). Payload is the bitmask
  # string (e.g. "100", "111"). NULL/empty/"all" clears the filter.
  observeEvent(input$browser_overlap_region_click, {
    bm <- input$browser_overlap_region_click
    cur <- isolate(browser_overlap_region_rv())
    if (is.null(bm) || !nzchar(bm) || identical(as.character(bm), "all")) {
      if (!is.null(cur)) {
        browser_overlap_region_rv(NULL)
        message("[overlap-region] cleared")
      }
      return()
    }
    bm <- as.character(bm)
    # Toggle: clicking the active region clears the filter
    if (identical(bm, cur)) {
      browser_overlap_region_rv(NULL)
      message("[overlap-region] toggled OFF (", bm, ")")
    } else {
      browser_overlap_region_rv(bm)
      message("[overlap-region] set to ", bm)
    }
  }, ignoreNULL = TRUE)

  # ── Overlap refresh: clear cache + reload ─────────────────────────────────
  observeEvent(input$browser_overlap_refresh, {
    message("[overlap-refresh] clearing cache, reloading")
    browser_overlap_cache_rv(list())
    browser_overlap_region_rv(NULL)
    .do_overlap_load()
  }, ignoreNULL = TRUE)

  # ── Sort header click ─────────────────────────────────────────────────────
  # Payload is "<col>:<dir>". If user clicks the same column that's already
  # active, flip direction. Otherwise switch to the new column with its
  # default direction (numeric -> desc; text -> asc).
  observeEvent(input$browser_sort_click, {
    new_col <- input$browser_sort_click
    if (is.null(new_col) || !nzchar(new_col)) return()
    new_col <- as.character(new_col)
    cur <- isolate(browser_sort_rv())
    parts <- strsplit(cur, ":", fixed = TRUE)[[1]]
    cur_col <- if (length(parts) >= 1) parts[1] else "persons"
    cur_dir <- if (length(parts) >= 2) parts[2] else "desc"
    next_dir <- if (identical(new_col, cur_col)) {
      if (identical(cur_dir, "desc")) "asc" else "desc"
    } else {
      # Default direction per column type
      if (new_col %in% c("persons","records","n_schemas_present")) "desc" else "asc"
    }
    new_sort <- paste0(new_col, ":", next_dir)
    if (identical(new_sort, cur)) return()
    browser_sort_rv(new_sort)
    message("[browser-sort] ", new_sort)
    # Re-fire whichever mode is currently active so the new sort applies.
    mode <- isolate(browser_mode_rv())
    if (mode == "prevalence") {
      .do_browser_load(isolate(input$browser_domain),
                       isolate(browser_search_debounced()))
    } else if (mode == "vocabulary" && !is.null(isolate(browser_vocab_sel_rv()))) {
      .do_vocab_load()
    }
    # Hierarchy doesn't re-query on sort - it's client-side. The renderer
    # reads browser_sort_rv() reactively so the list re-renders automatically.
  }, ignoreNULL = TRUE)

  # ── Sort header renderer ──────────────────────────────────────────────────
  # Renders a clickable header row above concept lists. col_keys is a vector
  # of column codes; col_labels their display strings. The currently active
  # sort gets an arrow indicator.
  .render_sort_header <- function(col_keys, col_labels) {
    cur <- browser_sort_rv()
    parts <- strsplit(cur, ":", fixed = TRUE)[[1]]
    cur_col <- if (length(parts) >= 1) parts[1] else "persons"
    cur_dir <- if (length(parts) >= 2) parts[2] else "desc"
    cells <- lapply(seq_along(col_keys), function(i) {
      k <- col_keys[i]; lbl <- col_labels[i]
      active <- identical(k, cur_col)
      arrow <- if (active) {
        if (cur_dir == "desc") " \u25BE" else " \u25B4"  # ▾ / ▴
      } else ""
      tags$span(
        class = paste("bls-col", paste0("col-", k),
                      if (active) "active"),
        onclick = sprintf("Shiny.setInputValue('browser_sort_click',%s,{priority:'event'})",
                          jsonlite::toJSON(k, auto_unbox = TRUE)),
        paste0(lbl, arrow)
      )
    })
    do.call(div, c(list(class = "browser-list-sort-header"), cells))
  }

  # ── Shared pill renderer (used by all three modes) ────────────────────────
  # Takes the per-schema info from a row and emits the multi-schema pill
  # block. row_data must have: n_persons, per_schema (list of named int
  # vector OR NULL), n_schemas_present.
  .render_pill_block <- function(row_data, all_schemas) {
    n_sel <- length(all_schemas)
    np    <- row_data$n_persons
    has_per_schema <- !is.null(row_data$per_schema) &&
                      length(row_data$per_schema) > 0
    if (n_sel <= 1 || !has_per_schema) {
      has <- !is.na(np) && np > 0
      cls <- if (has) "blr-pill has-data" else "blr-pill no-data"
      txt <- if (has) format(np, big.mark = ",") else "no data"
      return(tags$span(class = cls, txt))
    }
    ps <- row_data$per_schema
    per_pills <- lapply(seq_along(all_schemas), function(j) {
      sch <- all_schemas[j]
      n   <- if (!is.null(ps) && sch %in% names(ps)) ps[[sch]] else NA_integer_
      has <- !is.na(n) && n > 0
      cls <- paste0("blr-pill-sch sch-", j, if (!has) " sch-empty")
      txt <- if (has) sprintf("%s %s", schema_short(sch), format(n, big.mark = ","))
             else     sprintf("%s \u2013", schema_short(sch))
      tags$span(class = cls, title = sch, txt)
    })
    n_present <- row_data$n_schemas_present %||% 0L
    summary_pill <- tags$span(
      class = paste0("blr-pill-summary",
                     if (n_present == n_sel) " all-present"
                     else if (n_present > 0) " partial"
                     else " none"),
      sprintf("%d/%d", n_present, n_sel)
    )
    do.call(tagList, c(list(summary_pill), per_pills))
  }

  # ── Shared concept-row renderer (used by prevalence + vocab modes) ────────
  # row: one row of a df with concept columns + per_schema. on_click_js sets
  # how the row click is handled (defaults to browser_row_click for detail).
  .render_concept_row <- function(row, sel, all_schemas,
                                  on_click_js = NULL) {
    cid  <- row$concept_id
    is_sel <- !is.na(sel) && !is.na(cid) &&
              identical(as.integer(sel), as.integer(cid))
    std_flag <- if (identical(as.character(row$standard_concept), "S"))
      tags$span(class = "blr-std", "\u2605") else NULL
    # Build a single-row "data" object for the pill helper. row$per_schema is
    # an AsIs list-column; row$per_schema[[1]] is the named int vector.
    row_data <- list(
      n_persons = row$n_persons,
      per_schema = if ("per_schema" %in% names(row)) row$per_schema[[1]] else NULL,
      n_schemas_present = row$n_schemas_present %||% 0L
    )
    pill_block <- .render_pill_block(row_data, all_schemas)
    n_sel <- length(all_schemas)
    n_present <- row_data$n_schemas_present
    in_all <- n_sel > 1 && n_present == n_sel
    row_cls <- paste("browser-list-row",
                     if (is_sel) "selected",
                     if (in_all) "in-all-schemas")
    click_js <- on_click_js %||%
      sprintf("Shiny.setInputValue('browser_row_click',%d,{priority:'event'})",
              as.integer(cid))
    tags$div(class = row_cls, onclick = click_js,
      div(class = "blr-main",
        div(class = "blr-name", row$concept_name),
        div(class = "blr-meta",
            paste0(row$vocabulary_id, ":", row$concept_code,
                   if (nzchar(row$concept_class_id %||% ""))
                     paste0(" \u00b7 ", row$concept_class_id) else ""))
      ),
      div(class = "blr-pills", pill_block),
      std_flag
    )
  }

  # ── Selected concepts drawer (v10.13) ──────────────────────────────────────
  # Renders below the list. Collapsible. Shows running tally of inclusion +
  # exclusion criteria, with × to remove and Run / Edit detail buttons.
  output$browser_selected_drawer_ui <- renderUI({
    crits <- criteria_rv()
    is_open <- isTRUE(browser_drawer_open_rv())

    if (length(crits) == 0) {
      # Empty state: passive header, no toggle
      return(div(class = "browser-selected-drawer empty",
        div(class = "browser-selected-header",
          tags$span(class = "browser-selected-title",
            icon("circle-info"),
            " Click Include or Exclude on any concept to start a cohort."))
      ))
    }

    # Split include vs exclude, count concept_ids across criteria
    inc_crits <- Filter(function(c) identical(c$type, "inclusion"), crits)
    exc_crits <- Filter(function(c) identical(c$type, "exclusion"), crits)
    n_inc <- sum(vapply(inc_crits,
                        function(c) length(c$concept_ids %||% integer(0)),
                        integer(1)))
    n_exc <- sum(vapply(exc_crits,
                        function(c) length(c$concept_ids %||% integer(0)),
                        integer(1)))

    # Header - always visible, clickable to toggle
    header <- div(class = "browser-selected-header",
      onclick = "Shiny.setInputValue('browser_drawer_toggle', Date.now(), {priority:'event'})",
      tags$span(class = "browser-selected-title",
        icon(if (is_open) "chevron-down" else "chevron-up"),
        sprintf(" Selected concepts: %d included, %d excluded",
                as.integer(n_inc), as.integer(n_exc))),
      tags$span(class = "browser-selected-spacer"),
      tags$span(class = "browser-selected-toggle-hint",
                if (is_open) "click to collapse" else "click to expand")
    )

    if (!is_open) {
      # Collapsed: header only, with mini action buttons inline
      return(div(class = "browser-selected-drawer",
        header,
        div(class = "browser-selected-actions-mini",
          actionButton("browser_drawer_run", "\u25B6  Run",
                       class = "btn-dre-pri btn-sm"),
          actionButton("browser_drawer_edit", "Edit detail",
                       class = "btn-dre-sec btn-sm",
                       icon = icon("arrow-up-right-from-square")),
          actionButton("browser_drawer_clear", "Clear all",
                       class = "btn-link btn-sm",
                       style = "color: var(--dre-muted); padding: 4px 8px;")
        )
      ))
    }

    # Expanded: render item rows for each (criterion, concept_id) pair.
    # Cap visible items to keep panel sane; show "+ N more" if exceeded.
    .render_item_row <- function(crit, cid, kind_class) {
      cn <- concept_names_rv()
      name <- cn[[as.character(cid)]] %||%
              sprintf("Concept %s", format(as.integer(cid), big.mark = ","))
      desc_marker <- if (isTRUE(crit$use_descendants))
        tags$span(class = "bsd-desc", title = "Includes descendants",
                  icon("sitemap")) else NULL
      remove_js <- sprintf(
        "Shiny.setInputValue('browser_drawer_remove', {crit_id:%s, concept_id:%d, _ts:Date.now()}, {priority:'event'})",
        jsonlite::toJSON(crit$id, auto_unbox = TRUE),
        as.integer(cid))
      div(class = paste("bsd-item", kind_class),
        div(class = "bsd-item-name",
          tags$span(class = "bsd-item-concept-name", name),
          tags$span(class = "bsd-item-cid",
                    sprintf("(%s)", format(as.integer(cid), big.mark = ","))),
          desc_marker
        ),
        tags$span(class = "bsd-remove",
          title = "Remove from cohort",
          onclick = remove_js,
          icon("xmark"))
      )
    }

    inc_rows <- list()
    for (cr in inc_crits) {
      for (cid in (cr$concept_ids %||% integer(0)))
        inc_rows[[length(inc_rows) + 1]] <- .render_item_row(cr, cid, "bsd-inc")
    }
    exc_rows <- list()
    for (cr in exc_crits) {
      for (cid in (cr$concept_ids %||% integer(0)))
        exc_rows[[length(exc_rows) + 1]] <- .render_item_row(cr, cid, "bsd-exc")
    }

    .render_section <- function(label, rows, kind_class) {
      if (length(rows) == 0) return(NULL)
      div(class = paste("bsd-section", kind_class),
        div(class = "bsd-section-label", label),
        do.call(div, c(list(class = "bsd-section-body"), rows))
      )
    }

    div(class = "browser-selected-drawer",
      header,
      div(class = "browser-selected-body",
        .render_section(sprintf("Included (%d)", as.integer(n_inc)),
                        inc_rows, "inc"),
        .render_section(sprintf("Excluded (%d)", as.integer(n_exc)),
                        exc_rows, "exc")
      ),
      div(class = "browser-selected-actions",
        actionButton("browser_drawer_run",
                     label = HTML("\u25B6  Run cohort"),
                     class = "btn-dre-pri btn-sm"),
        actionButton("browser_drawer_edit",
                     label = "Edit detail",
                     class = "btn-dre-sec btn-sm",
                     icon = icon("arrow-up-right-from-square")),
        tags$span(class = "browser-selected-spacer"),
        actionButton("browser_drawer_clear",
                     label = "Clear all",
                     class = "btn-link btn-sm",
                     style = "color: var(--dre-muted);")
      )
    )
  })

  # Drawer toggle observer
  observeEvent(input$browser_drawer_toggle, {
    browser_drawer_open_rv(!isTRUE(isolate(browser_drawer_open_rv())))
  }, ignoreNULL = TRUE)

  # Drawer Run button - in-place, no tab switch
  observeEvent(input$browser_drawer_run, {
    # v10.13: Run from the browser navigates to Results - running is when
    # the user wants the answer, and the answer lives on the Results tab.
    run_cohort_core(navigate_to_results = TRUE)
  })

  # Drawer Edit detail - navigate to Build Cohort
  observeEvent(input$browser_drawer_edit, {
    updateTabItems(session, "main_tabs", "tab_build")
  })

  # Drawer Clear all - remove all criteria
  observeEvent(input$browser_drawer_clear, {
    showModal(modalDialog(
      title = "Clear cohort?",
      "This removes all included and excluded concepts. The cohort definition will be empty.",
      footer = tagList(
        modalButton("Cancel"),
        actionButton("browser_drawer_clear_confirm",
                     "Clear all", class = "btn-dre-pri")
      ),
      easyClose = TRUE
    ))
  })

  observeEvent(input$browser_drawer_clear_confirm, {
    criteria_rv(list())
    cohort_result_rv(NULL)
    browser_drawer_open_rv(FALSE)
    removeModal()
    showNotification("Cohort cleared.", type = "message", duration = 2)
  })

  # Drawer remove-item - drops the concept_id from a criterion; if the
  # criterion becomes empty, drops the whole criterion.
  observeEvent(input$browser_drawer_remove, {
    payload <- input$browser_drawer_remove
    crit_id <- payload$crit_id %||% ""
    cid     <- as.integer(payload$concept_id %||% NA_integer_)
    if (!nzchar(crit_id) || is.na(cid)) return()
    crits <- criteria_rv()
    new_crits <- lapply(crits, function(c) {
      if (!identical(c$id, crit_id)) return(c)
      c$concept_ids <- setdiff(c$concept_ids %||% integer(0), cid)
      if (length(c$concept_ids) == 0) return(NULL)
      c
    })
    new_crits <- Filter(Negate(is.null), new_crits)
    criteria_rv(new_crits)
    showNotification("Concept removed.", type = "message", duration = 2)
  }, ignoreNULL = TRUE)

  # ── Schema overlap Venn chrome ────────────────────────────────────────────
  # Renders a proportional Venn diagram (via eulerr) above the concept list,
  # with clickable regions and a legend table. Soft-fallback to a legend-only
  # view when eulerr isn't installed.
  output$browser_overlap_ui <- renderUI({
    ov <- browser_overlap_rv()
    if (is.null(ov)) return(NULL)
    if (isTRUE(ov$too_many))
      return(div(class = "browser-overlap-skip",
                 icon("circle-info"),
                 sprintf(" Venn diagram is shown for up to 3 schemas (you have %d selected).",
                         as.integer(ov$n))))
    schemas <- ov$schemas %||% character(0)
    if (length(schemas) < 2) return(NULL)  # single schema: no overlap to show
    region_counts <- ov$region_counts %||% integer(0)
    if (length(region_counts) == 0)
      return(div(class = "browser-overlap-skip",
                 icon("circle-info"), " No concepts with records in this domain."))

    active_region <- browser_overlap_region_rv()

    # Build inputs for eulerr. eulerr expects either a vector of size N
    # (with names like "A&B", "A&B&C") OR a list of named id sets. We use
    # the vector form because we already computed region_counts.
    has_eulerr <- requireNamespace("eulerr", quietly = TRUE)
    venn_svg <- if (has_eulerr) {
      .render_overlap_svg(schemas, region_counts, active_region)
    } else {
      div(class = "browser-overlap-skip",
          icon("triangle-exclamation"),
          " 'eulerr' package not installed; showing counts only.")
    }
    legend <- .render_overlap_legend(schemas, region_counts, active_region, ov$total)

    refresh_btn <- tags$span(class = "browser-overlap-refresh",
      onclick = "Shiny.setInputValue('browser_overlap_refresh', Date.now(), {priority:'event'})",
      title = "Refresh overlap (clears cache)",
      icon("arrows-rotate"))

    div(class = "browser-overlap-card",
      div(class = "browser-overlap-header",
        tags$span(class = "browser-overlap-title",
          "Concept coverage across schemas"),
        if (!is.null(active_region))
          tags$span(class = "browser-overlap-filter-pill",
            onclick = "Shiny.setInputValue('browser_overlap_region_click','all',{priority:'event'})",
            icon("xmark"),
            sprintf(" %s filter active \u2014 click to clear",
                    .bitmask_label(active_region, schemas))),
        tags$span(class = "browser-overlap-spacer"),
        refresh_btn
      ),
      div(class = "browser-overlap-body",
        div(class = "browser-overlap-svg-wrap", venn_svg),
        div(class = "browser-overlap-legend-wrap", legend)
      )
    )
  })

  # ── Overlap SVG renderer (eulerr backend) ─────────────────────────────────
  # Fits a proportional Euler diagram to the region counts and emits SVG.
  # If eulerr's fit is degenerate (some non-empty region was collapsed to
  # zero area), we still emit the SVG; the legend table is the source of
  # truth for clickability.
  .render_overlap_svg <- function(schemas, region_counts, active_region) {
    # Convert bitmask names ("100", "110", "111") into eulerr's expected
    # ampersand format ("A", "A&B", "A&B&C") where A/B/C are schema names.
    eulerr_names <- vapply(names(region_counts), function(bm) {
      bits <- strsplit(bm, "")[[1]]
      idx <- which(bits == "1")
      paste(schemas[idx], collapse = "&")
    }, character(1))
    counts_for_eulerr <- as.integer(region_counts)
    names(counts_for_eulerr) <- eulerr_names

    fit <- tryCatch(eulerr::euler(counts_for_eulerr),
                    error = function(e) {
                      message("[overlap-svg] eulerr error: ", conditionMessage(e))
                      NULL
                    })
    if (is.null(fit)) {
      return(div(class = "browser-overlap-skip",
                 icon("triangle-exclamation"),
                 " Could not compute Venn layout for these counts."))
    }
    # eulerr returns ellipses (h, k, a, b, phi) for each schema. We need
    # the circle/ellipse centres + radii to draw SVG manually with clickable
    # region polygons. Simpler approach: use eulerr's own coordinates for
    # the ellipses and draw N overlapping ellipses; the "region" hit areas
    # become tags$path elements derived from the boolean intersections.
    # For v1 we draw the ellipses themselves as clickable shapes and let
    # users click the legend for fine-grained region selection - this avoids
    # the complex SVG path arithmetic for true region polygons.
    e <- fit$ellipses
    if (is.null(e) || nrow(e) == 0) {
      return(div(class = "browser-overlap-skip",
                 icon("triangle-exclamation"),
                 " Venn layout returned no shapes."))
    }
    # Compute viewport from ellipse extents with margin
    xs_min <- min(e$h - e$a) - 2
    xs_max <- max(e$h + e$a) + 2
    ys_min <- min(e$k - e$b) - 2
    ys_max <- max(e$k + e$b) + 2
    vb <- sprintf("%f %f %f %f", xs_min, ys_min,
                  xs_max - xs_min, ys_max - ys_min)

    # SVG ellipses, one per schema. Colour-keyed to match the .sch-N pill
    # palette used elsewhere. Ellipses are display-only - the legend table
    # below is the sole click target. This avoids confusing users when they
    # click on a visual overlap area (which would otherwise just select the
    # single-schema region they happened to click).
    palette_fill <- c("rgba(0,197,181,.32)", "rgba(126,160,255,.32)", "rgba(255,176,102,.32)")
    palette_stroke <- c("#00C5B5", "#7EA0FF", "#FFB066")
    ellipses <- lapply(seq_len(nrow(e)), function(i) {
      tags$g(
        # rotate uses degrees in SVG; eulerr returns radians as 'phi'
        transform = sprintf("rotate(%f %f %f)", e$phi[i] * 180/pi, e$h[i], e$k[i]),
        tags$ellipse(
          cx = e$h[i], cy = e$k[i], rx = e$a[i], ry = e$b[i],
          fill = palette_fill[i %% length(palette_fill) + 1],
          stroke = palette_stroke[i %% length(palette_stroke) + 1],
          `stroke-width` = 0.5,
          style = "pointer-events:none;"  # display-only
        )
      )
    })

    # Schema name labels - placed near each ellipse centre but offset
    labels <- lapply(seq_len(nrow(e)), function(i) {
      sch <- rownames(e)[i]
      n_persons_in_schema <- sum(region_counts[grepl(
        sprintf("(^|[^0])%s", strrep("0", match(sch, schemas) - 1)),
        names(region_counts)
      )])
      # simpler: sum any region where this schema's bit is '1'
      sch_idx <- match(sch, schemas)
      bits_in_region <- vapply(names(region_counts), function(bm) {
        strsplit(bm, "")[[1]][sch_idx] == "1"
      }, logical(1))
      sch_total <- sum(region_counts[bits_in_region])
      # Label position: shift outward from centre of the diagram
      ctr_x <- (xs_min + xs_max) / 2
      ctr_y <- (ys_min + ys_max) / 2
      dx <- e$h[i] - ctr_x
      dy <- e$k[i] - ctr_y
      mag <- sqrt(dx^2 + dy^2)
      if (mag < 0.01) { dx <- 0; dy <- -1; mag <- 1 }
      offset <- 1.5
      lx <- e$h[i] + (dx / mag) * (max(e$a[i], e$b[i]) + offset)
      ly <- e$k[i] + (dy / mag) * (max(e$a[i], e$b[i]) + offset)
      tags$text(
        x = lx, y = ly,
        `text-anchor` = "middle", `dominant-baseline` = "middle",
        `font-size` = "1.4px", fill = palette_stroke[i %% length(palette_stroke) + 1],
        `font-weight` = "700",
        sch
      )
    })

    HTML(as.character(tags$svg(
      xmlns = "http://www.w3.org/2000/svg",
      viewBox = vb,
      `preserveAspectRatio` = "xMidYMid meet",
      class = "browser-overlap-svg",
      style = sprintf("width:100%%;height:%dpx;",
                      if (length(schemas) <= 2) 140 else 180),
      do.call(tagList, ellipses),
      do.call(tagList, labels)
    )))
  }

  # ── Overlap legend renderer ───────────────────────────────────────────────
  # Compact table: one row per non-empty region. Rows show the membership
  # combination as schema short-codes and the concept count. Active region
  # is highlighted. "All concepts" row at the top.
  .render_overlap_legend <- function(schemas, region_counts, active_region, total) {
    schema_codes <- vapply(schemas, function(s) schema_short(s), character(1))
    # Sort region_counts so highest counts appear first (more useful than
    # bitmask-sorted)
    ord <- order(-as.integer(region_counts))
    region_counts <- region_counts[ord]

    rows <- lapply(seq_along(region_counts), function(i) {
      bm <- names(region_counts)[i]
      cnt <- region_counts[i]
      is_active <- !is.null(active_region) && identical(bm, active_region)
      bits <- strsplit(bm, "")[[1]]
      # Render schema pills (active and inactive)
      pill_codes <- lapply(seq_along(schema_codes), function(j) {
        on <- bits[j] == "1"
        cls <- paste0("bol-sch sch-", j, if (!on) " sch-empty")
        tags$span(class = cls, schema_codes[j])
      })
      tags$tr(
        class = paste("browser-overlap-legend-row",
                      if (is_active) "active"),
        onclick = sprintf(
          "Shiny.setInputValue('browser_overlap_region_click',%s,{priority:'event'})",
          jsonlite::toJSON(bm, auto_unbox = TRUE)),
        tags$td(class = "bol-pills", do.call(tags$div,
          c(list(class = "bol-pill-row"), pill_codes))),
        tags$td(class = "bol-count",
                format(as.integer(cnt), big.mark = ","))
      )
    })

    tags$div(class = "browser-overlap-legend",
      tags$div(class = "browser-overlap-legend-total",
               sprintf("%s distinct concepts across %d schemas \u00b7 click a row to filter",
                       format(as.integer(total), big.mark = ","),
                       length(schemas))),
      tags$table(class = "browser-overlap-legend-table",
        tags$tbody(do.call(tagList, rows))
      )
    )
  }

  # ── Bitmask helper for header pill text ────────────────────────────────────
  .bitmask_label <- function(bm, schemas) {
    if (is.null(bm) || !nzchar(bm)) return("")
    bits <- strsplit(bm, "")[[1]]
    on <- which(bits == "1")
    if (length(on) == 0) return("")
    paste(vapply(schemas[on], schema_short, character(1)), collapse = " \u2229 ")
  }

  # ── Filter chrome renderer ────────────────────────────────────────────────
  # Renders the per-tab quick filter input. Only re-runs when the mode (or
  # vocab drill state) changes - so typing into the box doesn't destroy and
  # recreate the <input> element. Uses a tiny client-side debounce on the
  # `Shiny.setInputValue` calls so the list renderer fires at most every
  # 300ms while the user is typing.
  output$browser_filter_chrome_ui <- renderUI({
    mode <- browser_mode_rv()
    if (mode == "hierarchy") {
      tags$div(class = "browser-list-filter",
        tags$input(type = "text", id = "browser_hier_filter_input",
          class = "browser-list-filter-input",
          placeholder = "Filter this level\u2026",
          autocomplete = "off",
          oninput = paste0(
            "clearTimeout(window._cbHierFltT); ",
            "window._cbHierFltT = setTimeout(function(v){",
            "  Shiny.setInputValue('browser_hier_filter', v, {priority:'event'});",
            "}, 300, this.value);"
          )
        )
      )
    } else if (mode == "vocabulary" && is.null(browser_vocab_sel_rv())) {
      tags$div(class = "browser-list-filter",
        tags$input(type = "text", id = "browser_vocab_filter_input",
          class = "browser-list-filter-input",
          placeholder = "Filter vocabularies\u2026",
          autocomplete = "off",
          oninput = paste0(
            "clearTimeout(window._cbVocabFltT); ",
            "window._cbVocabFltT = setTimeout(function(v){",
            "  Shiny.setInputValue('browser_vocab_filter', v, {priority:'event'});",
            "}, 300, this.value);"
          )
        )
      )
    } else {
      NULL  # no filter chrome for prevalence mode or vocab-drilled-in
    }
  })

  # ── Render concept list (dispatches on browser_mode_rv) ───────────────────
  output$browser_list_ui <- renderUI({
    mode <- browser_mode_rv()
    if (mode == "hierarchy")  return(.render_hierarchy_list())
    if (mode == "vocabulary") return(.render_vocabulary_list())
    .render_prevalence_list()  # default
  })

  # ── Prevalence mode renderer ──────────────────────────────────────────────
  .render_prevalence_list <- function() {
    lst <- browser_list_rv()
    sel <- browser_selected_rv()
    all_schemas <- input$schema_select %||% character(0)
    show_schemas_col <- length(all_schemas) > 1

    header <- if (show_schemas_col)
      .render_sort_header(
        c("name","vocab","code","persons","records","n_schemas_present"),
        c("Concept","Vocab","Code","Persons","Records","Schemas")
      )
    else
      .render_sort_header(
        c("name","vocab","code","persons","records"),
        c("Concept","Vocab","Code","Persons","Records")
      )

    if (is.null(lst)) {
      schema <- primary_schema(input$schema_select %||% character(0))
      if (is.null(schema))
        return(div(class = "browser-detail-empty",
                   "Select a schema to browse concepts."))
      return(tagList(header,
        div(class = "browser-detail-empty",
                 icon("spinner"), " Loading\u2026")))
    }
    if (nrow(lst) == 0)
      return(tagList(header,
        div(class = "browser-detail-empty",
                 "No concepts match the current filters.")))

    # Apply Venn region filter if active. The overlap state holds region_ids
    # (a named list mapping bitmask -> integer vector of concept_ids in that
    # region). When a region is active, filter the list to those IDs.
    lst_view <- lst
    active_region <- browser_overlap_region_rv()
    if (!is.null(active_region)) {
      ov <- browser_overlap_rv()
      if (!is.null(ov) && !is.null(ov$region_ids) &&
          active_region %in% names(ov$region_ids)) {
        keep_ids <- as.integer(ov$region_ids[[active_region]])
        lst_view <- lst_view[lst_view$concept_id %in% keep_ids, , drop = FALSE]
      }
    }
    if (nrow(lst_view) == 0)
      return(tagList(header,
        div(class = "browser-detail-empty",
            "No concepts in the active Venn region match the current sort/filter.")))

    rows <- lapply(seq_len(nrow(lst_view)), function(i) {
      .render_concept_row(lst_view[i, , drop = FALSE], sel, all_schemas)
    })
    tagList(
      header,
      div(style = "padding:6px 14px 4px;font-size:0.80rem;color:var(--dre-muted);",
          if (is.null(active_region))
            sprintf("%d concept%s", nrow(lst_view),
                    if (nrow(lst_view) == 1) "" else "s")
          else
            sprintf("%d concept%s in active region (of %d shown)",
                    nrow(lst_view), if (nrow(lst_view) == 1) "" else "s",
                    nrow(lst))),
      div(class = "browser-list-body", do.call(tagList, rows))
    )
  }

  # ── Hierarchy mode renderer ───────────────────────────────────────────────
  .render_hierarchy_list <- function() {
    lst <- browser_hier_rv()
    sel <- browser_selected_rv()
    path <- browser_hier_path_rv()
    all_schemas <- input$schema_select %||% character(0)

    # Breadcrumb (always rendered, even at root)
    crumb_items <- list(
      tags$span(class = "browser-crumb-link",
        onclick = "Shiny.setInputValue('browser_hier_breadcrumb',0,{priority:'event'})",
        icon("home"), " Roots")
    )
    if (length(path) > 0) {
      for (i in seq_along(path)) {
        crumb_items <- c(crumb_items, list(
          tags$span(class = "browser-crumb-sep", "\u203a"),
          tags$span(class = paste("browser-crumb-link",
                                  if (i == length(path)) "current" else ""),
            onclick = sprintf("Shiny.setInputValue('browser_hier_breadcrumb',%d,{priority:'event'})", i),
            path[[i]]$concept_name)
        ))
      }
    }
    # Refresh button - right-aligned via flexbox spacer
    refresh_btn <- tags$span(class = "browser-crumb-refresh",
      onclick = "Shiny.setInputValue('browser_hier_refresh',Date.now(),{priority:'event'})",
      title = "Refresh hierarchy (clears cache)",
      icon("arrows-rotate"))
    breadcrumb <- div(class = "browser-crumb",
                     do.call(tagList, crumb_items),
                     tags$span(class = "browser-crumb-spacer"),
                     refresh_btn)

    # Quick filter input is now rendered by output$browser_filter_chrome_ui
    # (mounted once per mode change, not on every list update) so typing
    # doesn't lose focus.

    # Sort header - uses browser_sort_rv just like prevalence mode. Sort is
    # applied client-side here (we have the rows already; no re-query).
    show_schemas_col <- length(all_schemas) > 1
    sort_header <- if (show_schemas_col)
      .render_sort_header(
        c("name","vocab","code","persons","records","n_schemas_present"),
        c("Concept","Vocab","Code","Persons","Records","Schemas")
      )
    else
      .render_sort_header(
        c("name","vocab","code","persons","records"),
        c("Concept","Vocab","Code","Persons","Records")
      )

    body <- if (is.null(lst)) {
      div(class = "browser-detail-empty",
          icon("spinner"), " Loading\u2026")
    } else if (nrow(lst) == 0) {
      div(class = "browser-detail-empty",
          if (length(path) == 0)
            "No root concepts found for this domain."
          else
            "No further children in this domain.")
    } else {
      # Apply client-side filter
      flt <- input$browser_hier_filter
      lst_view <- lst
      if (!is.null(flt) && nzchar(trimws(flt))) {
        needle <- tolower(trimws(flt))
        keep <- grepl(needle, tolower(lst_view$concept_name %||% ""), fixed = TRUE) |
                grepl(needle, tolower(lst_view$concept_code %||% ""), fixed = TRUE)
        keep[is.na(keep)] <- FALSE
        lst_view <- lst_view[keep, , drop = FALSE]
      }
      # Apply client-side sort
      {
        cur <- browser_sort_rv()
        parts <- strsplit(cur, ":", fixed = TRUE)[[1]]
        col_k <- if (length(parts) >= 1) parts[1] else "persons"
        dir_k <- if (length(parts) >= 2) parts[2] else "desc"
        is_desc <- !identical(dir_k, "asc")
        key_vec <- switch(col_k,
          persons          = lst_view$n_persons,
          records          = lst_view$n_records,
          name             = lst_view$concept_name,
          vocab            = lst_view$vocabulary_id,
          code             = lst_view$concept_code,
          n_schemas_present = lst_view$n_schemas_present,
          lst_view$n_persons)
        if (nrow(lst_view) > 0) {
          if (is.numeric(key_vec)) {
            ord <- if (is_desc) order(-key_vec, lst_view$concept_name)
                   else         order(key_vec,  lst_view$concept_name)
          } else {
            ord <- if (is_desc) order(key_vec, decreasing = TRUE)
                   else         order(key_vec)
          }
          lst_view <- lst_view[ord, , drop = FALSE]
        }
      }
      if (nrow(lst_view) == 0) {
        div(class = "browser-detail-empty",
            "No concepts at this level match the filter.")
      } else {
      rows <- lapply(seq_len(nrow(lst_view)), function(i) {
        row <- lst_view[i, , drop = FALSE]
        cid <- row$concept_id
        nch <- row$n_children %||% 0L
        # Two click targets per row: drill into children (left) vs. select
        # concept for detail (right pill area). Whole row drills; an inner
        # click on the name-area also triggers select-for-detail via stopProp.
        drill_js <- sprintf(
          "(function(e){ if (e && e.stopPropagation) e.stopPropagation(); Shiny.setInputValue('browser_hier_drill', {concept_id:%d, concept_name:%s, _ts:Date.now()}, {priority:'event'}); })(event)",
          as.integer(cid), jsonlite::toJSON(row$concept_name, auto_unbox = TRUE))
        select_js <- sprintf(
          "(function(e){ if (e && e.stopPropagation) e.stopPropagation(); Shiny.setInputValue('browser_row_click',%d,{priority:'event'}); })(event)",
          as.integer(cid))

        is_sel <- !is.na(sel) && !is.na(cid) &&
                  identical(as.integer(sel), as.integer(cid))
        std_flag <- if (identical(as.character(row$standard_concept), "S"))
          tags$span(class = "blr-std", "\u2605") else NULL
        row_data <- list(
          n_persons = row$n_persons,
          per_schema = if ("per_schema" %in% names(row)) row$per_schema[[1]] else NULL,
          n_schemas_present = row$n_schemas_present %||% 0L
        )
        pill_block <- .render_pill_block(row_data, all_schemas)
        n_sel <- length(all_schemas)
        n_present <- row_data$n_schemas_present
        in_all <- n_sel > 1 && n_present == n_sel
        row_cls <- paste("browser-list-row hier-row",
                         if (is_sel) "selected",
                         if (in_all) "in-all-schemas")
        drill_marker <- if (nch > 0)
          tags$span(class = "hier-drill", title = sprintf("%d child concept%s",
                                                          nch, if (nch == 1) "" else "s"),
                    sprintf("%d \u203a", nch))
        else
          tags$span(class = "hier-drill leaf", "leaf")

        tags$div(class = row_cls,
          # Click on the row drills in (when it has children); otherwise
          # selects for detail.
          onclick = if (nch > 0) drill_js else select_js,
          div(class = "blr-main",
            div(class = "blr-name", row$concept_name),
            div(class = "blr-meta",
                paste0(row$vocabulary_id, ":", row$concept_code,
                       if (nzchar(row$concept_class_id %||% ""))
                         paste0(" \u00b7 ", row$concept_class_id) else ""))
          ),
          # Pills click selects-for-detail (separate from drill)
          tags$div(class = "blr-pills", onclick = select_js, pill_block),
          drill_marker, std_flag
        )
      })
      tagList(
        div(style = "padding:6px 14px 4px;font-size:0.80rem;color:var(--dre-muted);",
            sprintf("%d concept%s \u00b7 click row to drill, pills to view detail",
                    nrow(lst_view), if (nrow(lst_view) == 1) "" else "s")),
        div(class = "browser-list-body", do.call(tagList, rows))
      )
      }
    }

    tagList(breadcrumb, sort_header, body)
  }

  # ── Vocabulary mode renderer ──────────────────────────────────────────────
  .render_vocabulary_list <- function() {
    sel_vocab <- browser_vocab_sel_rv()
    sel       <- browser_selected_rv()
    all_schemas <- input$schema_select %||% character(0)

    if (is.null(sel_vocab)) {
      # Vocab list view
      vlst <- browser_vocab_list_rv()

      # Filter input is rendered by output$browser_filter_chrome_ui to avoid
      # focus loss on typing. Sort header is fine inline (atomic clicks only).
      show_schemas_col <- length(all_schemas) > 1
      sort_header <- if (show_schemas_col)
        .render_sort_header(
          c("vocab","n_concepts","persons","n_schemas_present"),
          c("Vocabulary","Concepts","Persons","Schemas")
        )
      else
        .render_sort_header(
          c("vocab","n_concepts","persons"),
          c("Vocabulary","Concepts","Persons")
        )

      if (is.null(vlst))
        return(tagList(sort_header,
          div(class = "browser-detail-empty",
              icon("spinner"), " Loading vocabularies\u2026")))
      if (nrow(vlst) == 0)
        return(tagList(sort_header,
          div(class = "browser-detail-empty",
              "No vocabularies found in selected schemas.")))

      # Client-side filter
      vlst_view <- vlst
      flt <- input$browser_vocab_filter
      if (!is.null(flt) && nzchar(trimws(flt))) {
        needle <- tolower(trimws(flt))
        keep <- grepl(needle, tolower(vlst_view$vocabulary_id %||% ""), fixed = TRUE)
        keep[is.na(keep)] <- FALSE
        vlst_view <- vlst_view[keep, , drop = FALSE]
      }
      # Client-side sort
      {
        cur <- browser_sort_rv()
        parts <- strsplit(cur, ":", fixed = TRUE)[[1]]
        col_k <- if (length(parts) >= 1) parts[1] else "persons"
        dir_k <- if (length(parts) >= 2) parts[2] else "desc"
        is_desc <- !identical(dir_k, "asc")
        key_vec <- switch(col_k,
          vocab             = vlst_view$vocabulary_id,
          n_concepts        = vlst_view$n_concepts,
          persons           = vlst_view$n_persons,
          n_schemas_present = vlst_view$n_schemas_present,
          vlst_view$n_persons)
        if (nrow(vlst_view) > 0) {
          if (is.numeric(key_vec)) {
            ord <- if (is_desc) order(-key_vec, vlst_view$vocabulary_id)
                   else         order(key_vec,  vlst_view$vocabulary_id)
          } else {
            ord <- if (is_desc) order(key_vec, decreasing = TRUE)
                   else         order(key_vec)
          }
          vlst_view <- vlst_view[ord, , drop = FALSE]
        }
      }

      if (nrow(vlst_view) == 0)
        return(tagList(sort_header,
          div(class = "browser-detail-empty",
              "No vocabularies match the filter.")))

      rows <- lapply(seq_len(nrow(vlst_view)), function(i) {
        row <- vlst_view[i, , drop = FALSE]
        v   <- row$vocabulary_id
        row_data <- list(
          n_persons = row$n_persons,
          per_schema = if ("per_schema" %in% names(row)) row$per_schema[[1]] else NULL,
          n_schemas_present = row$n_schemas_present %||% 0L
        )
        pill_block <- .render_pill_block(row_data, all_schemas)
        n_present <- row_data$n_schemas_present
        n_sel <- length(all_schemas)
        in_all <- n_sel > 1 && n_present == n_sel
        row_cls <- paste("browser-list-row vocab-row",
                         if (in_all) "in-all-schemas")
        drill_js <- sprintf(
          "Shiny.setInputValue('browser_vocab_drill', %s, {priority:'event'})",
          jsonlite::toJSON(v, auto_unbox = TRUE))
        tags$div(class = row_cls, onclick = drill_js,
          div(class = "blr-main",
            div(class = "blr-name", v),
            div(class = "blr-meta",
                sprintf("%s concept%s",
                        format(as.integer(row$n_concepts), big.mark=","),
                        if (row$n_concepts == 1) "" else "s"))
          ),
          div(class = "blr-pills", pill_block),
          tags$span(class = "hier-drill", "\u203a")
        )
      })
      return(tagList(
        sort_header,
        div(style = "padding:6px 14px 4px;font-size:0.80rem;color:var(--dre-muted);",
            sprintf("%d vocabular%s \u00b7 click to drill in",
                    nrow(vlst_view), if (nrow(vlst_view) == 1) "y" else "ies")),
        div(class = "browser-list-body", do.call(tagList, rows))
      ))
    }

    # Drilled-in: concepts within the selected vocab
    lst <- browser_vocab_concepts_rv()
    breadcrumb <- div(class = "browser-crumb",
      tags$span(class = "browser-crumb-link",
        onclick = "Shiny.setInputValue('browser_vocab_back',Date.now(),{priority:'event'})",
        icon("home"), " Vocabularies"),
      tags$span(class = "browser-crumb-sep", "\u203a"),
      tags$span(class = "browser-crumb-link current", sel_vocab)
    )
    show_schemas_col <- length(all_schemas) > 1
    header <- if (show_schemas_col)
      .render_sort_header(
        c("name","code","persons","records","n_schemas_present"),
        c("Concept","Code","Persons","Records","Schemas")
      )
    else
      .render_sort_header(
        c("name","code","persons","records"),
        c("Concept","Code","Persons","Records")
      )
    body <- if (is.null(lst)) {
      tagList(header, div(class = "browser-detail-empty",
          icon("spinner"), " Loading concepts\u2026"))
    } else if (nrow(lst) == 0) {
      tagList(header, div(class = "browser-detail-empty",
          "No concepts in this vocabulary match the current domain filter."))
    } else {
      # Apply Venn region filter if active
      lst_view <- lst
      active_region <- browser_overlap_region_rv()
      if (!is.null(active_region)) {
        ov <- browser_overlap_rv()
        if (!is.null(ov) && !is.null(ov$region_ids) &&
            active_region %in% names(ov$region_ids)) {
          keep_ids <- as.integer(ov$region_ids[[active_region]])
          lst_view <- lst_view[lst_view$concept_id %in% keep_ids, , drop = FALSE]
        }
      }
      if (nrow(lst_view) == 0) {
        tagList(header, div(class = "browser-detail-empty",
            "No concepts in the active Venn region match this vocabulary."))
      } else {
      rows <- lapply(seq_len(nrow(lst_view)), function(i) {
        .render_concept_row(lst_view[i, , drop = FALSE], sel, all_schemas)
      })
      tagList(
        header,
        div(style = "padding:6px 14px 4px;font-size:0.80rem;color:var(--dre-muted);",
            if (is.null(active_region))
              sprintf("%d concept%s in %s", nrow(lst_view),
                      if (nrow(lst_view) == 1) "" else "s", sel_vocab)
            else
              sprintf("%d concept%s in active region (of %d in %s)",
                      nrow(lst_view), if (nrow(lst_view) == 1) "" else "s",
                      nrow(lst), sel_vocab)),
        div(class = "browser-list-body", do.call(tagList, rows))
      )
      }
    }
    tagList(breadcrumb, body)
  }


  # ── Row click: select concept + load detail ───────────────────────────────
  observeEvent(input$browser_row_click, {
    cid <- as.integer(input$browser_row_click)
    browser_selected_rv(cid)
    browser_detail_rv(list(overview = NULL, overview_loaded = FALSE))
    # Reset sub-tab caches: new concept = stale data
    browser_samples_rv(list(data = NULL, loaded = FALSE, for_cid = NA_integer_))
    browser_cooccur_rv(list(data = NULL, loaded = FALSE, for_cid = NA_integer_))
    browser_hier_detail_rv(list(data = NULL, loaded = FALSE, for_cid = NA_integer_))
    browser_subtab_rv("overview")  # always start on Overview
    # The R-side reactive resets to "overview" but the tab-pill CSS is
    # JS-controlled - sync the UI explicitly. Without this, the AIRA pill
    # (or whichever was last clicked) stays visually active even though
    # the body renders Overview, which is confusing.
    session$sendCustomMessage("cb_set_subtab_active", "overview")

    # Determine domain_key from the current list
    lst <- isolate(browser_list_rv())
    domain_key <- NULL
    if (!is.null(lst) && nrow(lst) > 0) {
      row <- lst[lst$concept_id == cid, , drop = FALSE]
      if (nrow(row) > 0) {
        # Map domain_id string back to DOMAINS key
        did <- tolower(trimws(row$domain_id[1] %||% ""))
        domain_key <- names(Filter(function(d) {
          tolower(trimws(d$label)) == did ||
          grepl(gsub("_occurrence|_exposure", "", tolower(d$table)), did, fixed = TRUE)
        }, DOMAINS))
        if (length(domain_key) == 0) {
          # fallback: match by current filter domain
          filt_dom <- isolate(input$browser_domain) %||% NULL
          domain_key <- if (!is.null(filt_dom) && nzchar(filt_dom)) filt_dom else NULL
        } else {
          domain_key <- domain_key[1]
        }
      }
    }

    schemas  <- isolate(input$schema_select) %||% character(0)
    col_maps <- isolate(col_maps_rv())
    if (length(schemas) == 0 || length(col_maps) == 0) return()

    detail <- concept_detail_overview_multi(schemas, domain_key, cid, col_maps)
    browser_detail_rv(list(overview = detail, overview_loaded = TRUE,
                           domain_key = domain_key, concept_id = cid,
                           schemas = schemas))
  })

  # ── Detail header ──────────────────────────────────────────────────────────
  output$browser_detail_header_ui <- renderUI({
    sel <- browser_selected_rv()
    det <- browser_detail_rv()
    if (is.na(sel) || !isTRUE(det$overview_loaded) || is.null(det$overview)) {
      return(div(class = "browser-detail-header",
        div(style = "color:var(--dre-muted);font-size:0.93rem;",
            "Select a concept from the list to see details.")))
    }
    meta <- det$overview$concept_meta
    if (is.null(meta) || nrow(meta) == 0)
      return(div(class = "browser-detail-header",
        div(style = "color:var(--dre-muted);", "Concept metadata unavailable.")))

    std_label <- switch(as.character(meta$standard_concept[1] %||% ""),
      S = tags$span(style = "background:var(--dre-teal-dim);color:var(--dre-teal);border-radius:4px;padding:1px 7px;font-size:0.80rem;font-weight:700;", "Standard"),
      C = tags$span(style = "background:rgba(255,184,77,.15);color:var(--dre-gold);border-radius:4px;padding:1px 7px;font-size:0.80rem;font-weight:700;", "Classification"),
        tags$span(style = "background:var(--dre-mid);color:var(--dre-muted);border-radius:4px;padding:1px 7px;font-size:0.80rem;", "Non-standard")
    )
    div(class = "browser-detail-header",
      div(style = "font-size:1.05rem;font-weight:700;color:var(--dre-text);margin-bottom:6px;",
          meta$concept_name[1]),
      div(style = "display:flex;flex-wrap:wrap;gap:6px;align-items:center;",
        std_label,
        tags$span(style = "font-size:0.80rem;color:var(--dre-muted);",
          meta$vocabulary_id[1], ":", meta$concept_code[1]),
        if (!is.null(meta$concept_class_id) && nzchar(meta$concept_class_id[1] %||% ""))
          tags$span(style = "font-size:0.80rem;color:var(--dre-muted);",
            "\u00b7", meta$concept_class_id[1]),
        tags$span(style = "font-size:0.80rem;color:var(--dre-muted);",
          "\u00b7 ID:", format(as.integer(meta$concept_id[1]), big.mark = ","))
      )
    )
  })

  # ── Detail body (dispatches on active sub-tab) ────────────────────────────
  output$browser_detail_body_ui <- renderUI({
    sel <- browser_selected_rv()
    det <- browser_detail_rv()
    tab <- browser_subtab_rv() %||% "overview"

    if (is.na(sel))
      return(div(class = "browser-detail-body browser-detail-empty",
                 icon("arrow-left"), " Pick a concept on the left."))
    if (!isTRUE(det$overview_loaded))
      return(div(class = "browser-detail-body browser-detail-empty",
                 icon("spinner"), " Loading\u2026"))
    if (is.null(det$overview))
      return(div(class = "browser-detail-body browser-detail-empty",
                 "Could not load concept details."))

    if (tab == "overview") {
      .render_overview_subtab(det)
    } else if (tab == "hier") {
      .render_hier_subtab(det)
    } else if (tab == "cooccur") {
      .render_cooccur_subtab()
    } else if (tab == "samples") {
      .render_samples_subtab()
    } else if (tab == "aira") {
      .render_aira_subtab(det)
    } else {
      .render_overview_subtab(det)
    }
  })

  # ── Overview sub-tab renderer ─────────────────────────────────────────────
  # Combined KPI cards with per-schema breakdown shown as a small split below
  # each number (when more than one schema is selected and has data).
  .render_overview_subtab <- function(det) {
    ov <- det$overview
    schemas <- det$schemas %||% character(0)
    n_sel   <- length(schemas)
    combined <- ov$stats_combined
    per_sch  <- ov$per_schema %||% list()

    # Per-KPI helpers ─────────────────────────────────────────────────────
    fmt_num <- function(x) if (!is.null(x) && !is.na(x))
      format(as.integer(x), big.mark = ",") else "\u2014"
    fmt_date <- function(x) if (!is.null(x) && !is.na(x) && nzchar(as.character(x)))
      substr(as.character(x), 1, 10) else "\u2014"

    if (is.null(combined) || nrow(combined) == 0) {
      stat_boxes <- div(style = "color:var(--dre-muted);font-size:0.87rem;margin-bottom:12px;",
                        "No records found in any selected schema for this concept.")
    } else {
      # Build per-KPI per-schema mini-row (only when multi-schema)
      per_kpi_row <- function(kpi) {
        if (n_sel <= 1) return(NULL)
        items <- lapply(seq_along(schemas), function(j) {
          sch <- schemas[j]
          ps  <- per_sch[[sch]]
          val <- if (kpi == "persons") ps$stats$n_persons[1]
                 else if (kpi == "records") ps$stats$n_records[1]
                 else if (kpi == "first") ps$stats$min_date[1]
                 else if (kpi == "last")  ps$stats$max_date[1]
                 else NA
          str <- if (kpi %in% c("persons", "records")) fmt_num(val) else fmt_date(val)
          empty_cls <- if (identical(str, "\u2014")) " sch-empty" else ""
          tags$span(class = paste0("bds-sch sch-", j, empty_cls),
                    title = sch,
                    sprintf("%s %s", schema_short(sch), str))
        })
        do.call(div, c(list(class = "bds-sch-row"), items))
      }

      stat_boxes <- div(class = "browser-detail-stat",
        div(class = "browser-detail-stat-box",
            div(class = "bds-val", fmt_num(combined$n_persons[1])),
            div(class = "bds-lbl", "Persons"),
            per_kpi_row("persons")),
        div(class = "browser-detail-stat-box",
            div(class = "bds-val", fmt_num(combined$n_records[1])),
            div(class = "bds-lbl", "Records"),
            per_kpi_row("records")),
        div(class = "browser-detail-stat-box",
            div(class = "bds-val", fmt_date(combined$min_date[1])),
            div(class = "bds-lbl", "First event"),
            per_kpi_row("first")),
        div(class = "browser-detail-stat-box",
            div(class = "bds-val", fmt_date(combined$max_date[1])),
            div(class = "bds-lbl", "Last event"),
            per_kpi_row("last"))
      )
    }

    # Gender bar - uses combined values
    gdf <- ov$gender_combined
    gender_ui <- if (!is.null(gdf) && nrow(gdf) > 0) {
      total_g <- sum(gdf$n, na.rm = TRUE)
      gender_concept_labels <- c("8507" = "Male", "8532" = "Female")
      tagList(
        tags$p(style="font-size:0.80rem;color:var(--dre-muted);text-transform:uppercase;letter-spacing:.5px;margin:0 0 4px;",
               "Gender split"),
        div(style="display:flex;gap:6px;margin-bottom:10px;",
          lapply(seq_len(nrow(gdf)), function(i) {
            gid  <- as.character(gdf$gender_concept_id[i])
            pct  <- if (total_g > 0) round(100 * gdf$n[i] / total_g) else 0
            lbl  <- gender_concept_labels[[gid]] %||% paste("Concept", gid)
            col  <- if (gid == "8507") "#00C5B5" else "#FFB84D"
            tags$span(style=sprintf("background:rgba(0,0,0,.15);border-left:3px solid %s;padding:4px 10px;border-radius:4px;font-size:0.84rem;color:var(--dre-text);", col),
              sprintf("%s: %d%%", lbl, pct))
          })
        )
      )
    } else NULL

    div(class = "browser-detail-body",
      stat_boxes,
      gender_ui
    )
  }

  # ── Hierarchy sub-tab renderer ────────────────────────────────────────────
  # Shows the ancestors path (root \u2192 parent of selected concept) above and
  # immediate children below, all clickable for navigation. The currently
  # selected concept appears in the middle as the "you are here" marker.
  .render_hier_subtab <- function(det) {
    state <- browser_hier_detail_rv()
    if (!isTRUE(state$loaded))
      return(div(class = "browser-detail-body browser-detail-empty",
                 icon("spinner"), " Loading hierarchy\u2026"))
    data <- state$data
    if (is.null(data))
      return(div(class = "browser-detail-body browser-detail-empty",
                 "Hierarchy data unavailable for this concept."))

    ancestors <- data$ancestors
    children  <- data$children
    all_schemas <- input$schema_select %||% character(0)
    sel_cid <- isolate(browser_selected_rv())
    cur_meta <- det$overview$concept_meta
    cur_name <- if (!is.null(cur_meta) && nrow(cur_meta) > 0)
      cur_meta$concept_name[1] else paste("Concept", sel_cid)

    # A small row renderer for ancestor/child entries inside the sub-tab.
    # Click sends the concept_id to browser_row_click so the existing
    # row-click observer handles selection + detail reload uniformly.
    render_hier_row <- function(row, indent_level = 0L, marker_text = NULL) {
      cid <- row$concept_id
      row_data <- list(
        n_persons = row$n_persons,
        per_schema = if ("per_schema" %in% names(row)) row$per_schema[[1]] else NULL,
        n_schemas_present = row$n_schemas_present %||% 0L
      )
      pill_block <- .render_pill_block(row_data, all_schemas)
      indent_style <- sprintf("padding-left:%dpx;", 6L + indent_level * 18L)
      click_js <- sprintf(
        "Shiny.setInputValue('browser_row_click',%d,{priority:'event'})",
        as.integer(cid))
      tags$div(class = "hier-detail-row", onclick = click_js,
        div(class = "hier-detail-main", style = indent_style,
          if (!is.null(marker_text))
            tags$span(class = "hier-detail-marker", marker_text),
          div(class = "hier-detail-name", row$concept_name),
          div(class = "hier-detail-meta",
              paste0(row$vocabulary_id, ":", row$concept_code,
                     if (!is.null(row$concept_class_id) &&
                         nzchar(row$concept_class_id %||% ""))
                       paste0(" \u00b7 ", row$concept_class_id) else ""))
        ),
        div(class = "blr-pills", pill_block)
      )
    }

    # Build the layout: ancestors top-down, then the current concept as
    # a non-clickable "you are here" row, then children indented one level.
    ancestor_rows <- if (!is.null(ancestors) && nrow(ancestors) > 0) {
      lapply(seq_len(nrow(ancestors)), function(i) {
        render_hier_row(ancestors[i, , drop = FALSE],
                        indent_level = i - 1L,
                        marker_text = NULL)
      })
    } else list()

    # "You are here" row (non-clickable)
    current_indent_level <- length(ancestor_rows)
    current_row <- tags$div(class = "hier-detail-row hier-detail-current",
      div(class = "hier-detail-main",
          style = sprintf("padding-left:%dpx;", 6L + current_indent_level * 18L),
        tags$span(class = "hier-detail-marker current", "\u25CF"),
        div(class = "hier-detail-name", cur_name),
        div(class = "hier-detail-meta",
            "Selected concept")
      )
    )

    child_rows <- if (!is.null(children) && nrow(children) > 0) {
      lapply(seq_len(nrow(children)), function(i) {
        render_hier_row(children[i, , drop = FALSE],
                        indent_level = current_indent_level + 1L,
                        marker_text = NULL)
      })
    } else list()

    header_anc <- if (length(ancestor_rows) > 0)
      div(class = "hier-detail-section-header",
          sprintf("Ancestors (%d level%s up)",
                  length(ancestor_rows),
                  if (length(ancestor_rows) == 1) "" else "s"))
    else
      div(class = "hier-detail-section-header empty",
          "No standard same-domain ancestors")
    header_child <- if (length(child_rows) > 0)
      div(class = "hier-detail-section-header",
          sprintf("Direct children (%d)", length(child_rows)))
    else
      div(class = "hier-detail-section-header empty",
          "No direct children in this domain")

    div(class = "browser-detail-body",
      div(style = "font-size:0.80rem;color:var(--dre-muted);margin-bottom:8px;",
          "Click any concept above or below to navigate to it."),
      header_anc,
      if (length(ancestor_rows) > 0) do.call(tagList, ancestor_rows) else NULL,
      current_row,
      header_child,
      if (length(child_rows) > 0) do.call(tagList, child_rows) else NULL
    )
  }

  # ── Co-occurring sub-tab renderer ─────────────────────────────────────────
  .render_cooccur_subtab <- function() {
    state <- browser_cooccur_rv()
    if (!isTRUE(state$loaded))
      return(div(class = "browser-detail-body browser-detail-empty",
                 icon("spinner"), " Loading co-occurring concepts\u2026"))
