      div(style = "font-size:0.80rem;color:var(--dre-muted);margin-bottom:8px;",
          sprintf("Top %d concepts that appear in the same patient + same domain table. Counts summed across selected schemas.", nrow(df))),
      DT::DTOutput("browser_cooccur_table")
    )
  }

  # ── Sample records sub-tab renderer ───────────────────────────────────────
  .render_samples_subtab <- function() {
    state <- browser_samples_rv()
    if (!isTRUE(state$loaded))
      return(div(class = "browser-detail-body browser-detail-empty",
                 icon("spinner"), " Loading sample records\u2026"))
    df <- state$data
    if (is.null(df) || nrow(df) == 0)
