  # ── AIRA sub-tab renderer (R-AIRA-16) ─────────────────────────────────────
  # Three visual states:
  #   1. AIRA disabled - short explanatory message
  #   2. No summary yet for this concept - "Generate" button
  #   3. Summary cached - render the Markdown content with metadata footer
  #
  # The renderer is purely a UI; the actual LLM call is triggered by the
  # button click observer (input$aira_concept_btn) so users opt-in.
  .render_aira_subtab <- function(det) {
    # AIRA availability gate
    cfg <- tryCatch(aira_resolve_cfg(), error = function(e) NULL)
    if (is.null(cfg) || !aira_is_enabled(cfg)) {
      return(div(class = "browser-detail-body browser-detail-empty",
        icon("circle-info"), " AIRA is not enabled in this workspace. ",
        "Concept summaries are unavailable."))
    }

    sel <- isolate(browser_selected_rv())
    if (is.na(sel))
      return(div(class = "browser-detail-body browser-detail-empty",
                 "Pick a concept to see its AIRA summary."))

    cache <- aira_concept_cache_rv()
    busy_for <- aira_concept_busy_for_rv()
    cid_key  <- as.character(as.integer(sel))
    entry    <- cache[[cid_key]]

    # Busy state
    if (!is.na(busy_for) && identical(as.integer(busy_for), as.integer(sel))) {
      return(div(class = "browser-detail-body",
        div(style = "display:flex;align-items:center;gap:10px;color:var(--dre-teal);margin-bottom:10px;",
          icon("spinner", class = "fa-spin"),
          tags$span(style = "font-weight:600;", "AIRA is summarising this concept\u2026")),
        div(style = "color:var(--dre-muted);font-size:0.80rem;",
          "Local inference typically takes 10\u201340 seconds. ",
          "You can continue browsing the app; this panel will update when ready.")))
    }

    # Empty state - first visit for this concept
    if (is.null(entry)) {
      # det$overview is the multi-schema overview list; the concept's
      # metadata lives in $concept_meta (single-row data.frame).
      cm_df <- det$overview$concept_meta
      concept_name <- if (!is.null(cm_df) && nrow(cm_df) > 0)
        as.character(cm_df$concept_name[1]) else "this concept"
      return(div(class = "browser-detail-body",
        div(style = "font-size:0.86rem;color:var(--dre-muted);margin-bottom:12px;line-height:1.5;",
          "Ask AIRA for a plain-language clinical context summary of ",
          tags$b(concept_name), ". ",
          "Useful when deciding whether the concept fits your cohort."),
        actionButton("aira_concept_btn",
          tagList(icon("wand-magic-sparkles"), " Generate summary"),
          class = "btn-dre-pri btn-sm"),
        div(style = "color:var(--dre-muted);font-size:0.75rem;margin-top:10px;",
          tags$i("AI-generated content. Treat as a second opinion; verify clinically important claims against source vocabulary."))))
    }

    # Error / disabled / malformed state
    if (!identical(entry$status, "ok")) {
      reason_msg <- switch(entry$status,
        "timeout"     = "AIRA timed out before producing a response. The model may be under load \u2014 try again.",
        "malformed"   = "AIRA returned a response that didn't match the expected format.",
        "disabled"    = "AIRA is not enabled in this workspace.",
        "unavailable" = "AIRA is unavailable right now.",
        sprintf("Unknown error: %s", entry$status))
      return(div(class = "browser-detail-body",
        div(style = "color:var(--dre-error);margin-bottom:10px;",
          icon("triangle-exclamation"), " ", reason_msg),
        if (!is.null(entry$reason))
          div(style = "color:var(--dre-muted);font-size:0.78rem;margin-bottom:10px;",
            tags$code(entry$reason)),
        actionButton("aira_concept_btn",
          tagList(icon("rotate-right"), " Try again"),
          class = "btn-dre-sec btn-sm")))
    }

    # Success - render the Markdown content
    md_html <- tryCatch(
      HTML(markdown::markdownToHTML(text = entry$content,
                                     fragment.only = TRUE)),
      error = function(e) {
        # Fallback: render as preformatted text if markdown package missing
        tags$pre(style = "white-space:pre-wrap;font-family:inherit;font-size:0.86rem;",
                 entry$content)
      })

    div(class = "browser-detail-body",
      div(class = "aira-concept-summary", md_html),
      div(class = "aira-concept-footer",
        style = "margin-top:14px;padding-top:10px;border-top:1px solid var(--dre-border);font-size:0.74rem;color:var(--dre-muted);",
        tagList(
          icon("wand-magic-sparkles"),
          sprintf(" AI-generated %s",
                  format(entry$generated_at, "%Y-%m-%d %H:%M")),
          if (!is.null(entry$prompt_version))
            sprintf(" \u00b7 prompt %s", entry$prompt_version),
          if (!is.null(entry$duration_ms))
            sprintf(" \u00b7 %.1fs",
                    as.numeric(entry$duration_ms) / 1000),
          " \u00b7 ",
          actionLink("aira_concept_refresh",
            tagList(icon("rotate-right"), " Regenerate"),
            style = "color:var(--dre-teal);")
        )))
  }

  # Build the concept_info list that aira_concept_summary() consumes. Pulls
  # name, vocab, domain from the loaded overview's concept_meta data frame;
  # parents and children from the hierarchy detail if available. Returns
  # NULL when essential fields are missing.
  .build_aira_concept_info <- function() {
    sel <- isolate(browser_selected_rv())
    det <- isolate(browser_detail_rv())
    if (is.na(sel) || !isTRUE(det$overview_loaded)) return(NULL)
    ov <- det$overview
    if (is.null(ov)) return(NULL)

    # Concept metadata lives in $concept_meta (data.frame, one row).
    cm_df <- ov$concept_meta
    if (is.null(cm_df) || nrow(cm_df) == 0) return(NULL)
    concept_name <- as.character(cm_df$concept_name[1] %||% "")
    if (!nzchar(concept_name)) return(NULL)

    domain_key <- det$domain_key %||% (isolate(input$browser_domain) %||% "condition")
    domain_lbl <- DOMAINS[[domain_key]]$label %||% domain_key

    # Pull hierarchy if it's been lazily loaded (don't trigger a load).
    # Both $ancestors and $children are data.frames (one row per concept,
    # with concept_name column). Not list-of-lists.
    h <- isolate(browser_hier_detail_rv())
    parents  <- character(0); children <- character(0)
    if (isTRUE(h$loaded) && identical(h$for_cid, as.integer(sel))) {
      d <- h$data
      if (!is.null(d)) {
        anc_df <- d$ancestors
        if (is.data.frame(anc_df) && nrow(anc_df) > 0 &&
            "concept_name" %in% names(anc_df))
          parents <- as.character(anc_df$concept_name)
        chi_df <- d$children
        if (is.data.frame(chi_df) && nrow(chi_df) > 0 &&
            "concept_name" %in% names(chi_df))
          children <- as.character(head(chi_df$concept_name, 12))
      }
    }
    list(
      name             = concept_name,
      concept_id       = as.integer(sel),
      vocabulary       = as.character(cm_df$vocabulary_id[1] %||% "(unknown)"),
      concept_class    = as.character(cm_df$concept_class_id[1] %||% "(unknown)"),
      domain           = domain_lbl,
      standard_concept = as.character(cm_df$standard_concept[1] %||% "(unknown)"),
      parents          = parents[nzchar(parents)],
      children         = children[nzchar(children)]
    )
  }

  # Trigger the AIRA call when the user clicks Generate / Try again /
  # Regenerate. Async via promises; updates cache on completion.
  observeEvent(input$aira_concept_btn, {
    info <- .build_aira_concept_info()
    if (is.null(info)) {
      showNotification("Cannot summarise: concept details not loaded yet.",
                       type = "warning"); return()
    }
    aira_concept_busy_for_rv(as.integer(info$concept_id))
    cfg_local <- aira_resolve_cfg()
    input_chars <- nchar(paste(info$name, info$vocabulary, info$domain,
                                paste(info$parents, collapse=","),
                                paste(info$children, collapse=",")))
    prom <- aira_concept_summary_async(info, cfg_local)
    promises::then(prom,
      onFulfilled = function(resp) {
        aira_log_event("aira_concept_summary", resp, input_chars = input_chars)
        cache <- isolate(aira_concept_cache_rv())
        cache[[as.character(info$concept_id)]] <- list(
          status         = resp$status %||% "unavailable",
          content        = resp$content %||% "",
          reason         = resp$reason,
          prompt_version = resp$prompt_version,
          duration_ms    = resp$duration_ms,
          generated_at   = Sys.time()
        )
        aira_concept_cache_rv(cache)
        aira_concept_busy_for_rv(NA_integer_)
      },
      onRejected = function(e) {
        aira_log_event("aira_concept_summary",
                       aira_empty_response("unavailable",
                                            reason = conditionMessage(e)),
                       input_chars = input_chars)
        cache <- isolate(aira_concept_cache_rv())
        cache[[as.character(info$concept_id)]] <- list(
          status = "unavailable",
          reason = conditionMessage(e),
          generated_at = Sys.time()
        )
        aira_concept_cache_rv(cache)
        aira_concept_busy_for_rv(NA_integer_)
      })
  }, ignoreInit = TRUE)

  # Regenerate link - clear the cache entry, then re-run.
  observeEvent(input$aira_concept_refresh, {
    sel <- isolate(browser_selected_rv())
    if (is.na(sel)) return()
    cache <- isolate(aira_concept_cache_rv())
    cache[[as.character(as.integer(sel))]] <- NULL
    aira_concept_cache_rv(cache)
    # Trigger as if the button was clicked
    info <- .build_aira_concept_info()
    if (is.null(info)) return()
    aira_concept_busy_for_rv(as.integer(info$concept_id))
    cfg_local <- aira_resolve_cfg()
    prom <- aira_concept_summary_async(info, cfg_local)
    promises::then(prom,
      onFulfilled = function(resp) {
        aira_log_event("aira_concept_summary", resp)
        cache <- isolate(aira_concept_cache_rv())
        cache[[as.character(info$concept_id)]] <- list(
          status         = resp$status %||% "unavailable",
          content        = resp$content %||% "",
          reason         = resp$reason,
          prompt_version = resp$prompt_version,
          duration_ms    = resp$duration_ms,
          generated_at   = Sys.time()
        )
        aira_concept_cache_rv(cache)
        aira_concept_busy_for_rv(NA_integer_)
      },
      onRejected = function(e) {
        cache <- isolate(aira_concept_cache_rv())
        cache[[as.character(info$concept_id)]] <- list(
          status = "unavailable",
          reason = conditionMessage(e),
          generated_at = Sys.time()
        )
        aira_concept_cache_rv(cache)
        aira_concept_busy_for_rv(NA_integer_)
      })
  }, ignoreInit = TRUE)

  # ── Co-occurring table output ─────────────────────────────────────────────
  output$browser_cooccur_table <- DT::renderDT({
    state <- browser_cooccur_rv()
    df <- state$data
    if (is.null(df) || nrow(df) == 0)
      return(DT::datatable(data.frame(), filter = "none", rownames = FALSE,
                           options = list(dom = "t")))
    show_df <- df[, c("concept_name", "vocabulary_id", "concept_code",
                      "n_persons", "n_records", "n_schemas_present"), drop = FALSE]
    colnames(show_df) <- c("Concept", "Vocab", "Code",
                           "Persons", "Records", "Schemas")
    DT::datatable(show_df,
      rownames = FALSE, filter = "none", selection = "none",
      options = list(pageLength = 10, dom = "tip",
                     columnDefs = list(
                       list(targets = c(3, 4, 5), className = "dt-right"))))
  }, server = TRUE)

  # ── Sample records table output ───────────────────────────────────────────
  output$browser_samples_table <- DT::renderDT({
    state <- browser_samples_rv()
    df <- state$data
    if (is.null(df) || nrow(df) == 0)
      return(DT::datatable(data.frame(), filter = "none", rownames = FALSE,
                           options = list(dom = "t")))
    show_df <- df[, c("schema", "person_id", "event_date", "concept_id"), drop = FALSE]
    colnames(show_df) <- c("Schema", "Person ID", "Event date", "Concept ID")
    DT::datatable(show_df,
      rownames = FALSE, filter = "none", selection = "none",
      options = list(pageLength = 15, dom = "tip", order = list(list(2, "desc"))))
  }, server = TRUE)

  # ── Action footer ─────────────────────────────────────────────────────────
  output$browser_action_footer_ui <- renderUI({
    sel <- browser_selected_rv()
    det <- browser_detail_rv()
    if (is.na(sel) || !isTRUE(det$overview_loaded)) return(NULL)

    div(class = "browser-action-footer",
      checkboxInput("browser_use_descendants",
                    tagList(icon("sitemap"), " Include descendants"),
                    value = FALSE),
      actionButton("browser_add_inclusion",
        tagList(icon("circle-plus"), " Add as inclusion"),
        class = "btn-dre-pri btn-sm"),
      actionButton("browser_add_exclusion",
        tagList(icon("circle-minus"), " Add as exclusion"),
        class = "btn-dre-danger btn-sm")
    )
  })

  # ── Sub-tab switching ─────────────────────────────────────────────────────
  # Updates the active-class on the tab spans via session$sendCustomMessage
  # equivalent (here, plain shinyjs-like JS injection), and lazy-loads the
  # data for cooccur/samples the first time their tab is opened for the
  # current concept.
  observeEvent(input$browser_detail_subtab, {
    tab <- input$browser_detail_subtab
    if (!tab %in% c("overview", "hier", "cooccur", "samples", "aira")) return()
    browser_subtab_rv(tab)
    # Toggle active class on the spans
    session$sendCustomMessage("cb_set_subtab_active", tab)

    # Lazy-load on first open for the current concept
    sel <- isolate(browser_selected_rv())
    det <- isolate(browser_detail_rv())
    if (is.na(sel) || !isTRUE(det$overview_loaded)) return()

    domain_key <- det$domain_key
    schemas    <- det$schemas %||% (isolate(input$schema_select) %||% character(0))
    col_maps   <- isolate(col_maps_rv())
    if (length(schemas) == 0 || length(col_maps) == 0) return()

    if (tab == "cooccur") {
      cur <- isolate(browser_cooccur_rv())
      if (!isTRUE(cur$loaded) || !identical(cur$for_cid, as.integer(sel))) {
        data <- concept_cooccurring_multi(schemas, domain_key,
                                          as.integer(sel), col_maps, limit = 50L)
        browser_cooccur_rv(list(data = data, loaded = TRUE, for_cid = as.integer(sel)))
      }
    } else if (tab == "samples") {
      cur <- isolate(browser_samples_rv())
      if (!isTRUE(cur$loaded) || !identical(cur$for_cid, as.integer(sel))) {
        data <- concept_sample_records_multi(schemas, domain_key,
                                             as.integer(sel), col_maps,
                                             per_schema_limit = 20L)
        browser_samples_rv(list(data = data, loaded = TRUE, for_cid = as.integer(sel)))
      }
    } else if (tab == "hier") {
      cur <- isolate(browser_hier_detail_rv())
      if (!isTRUE(cur$loaded) || !identical(cur$for_cid, as.integer(sel))) {
        data <- concept_ancestors_path_multi(schemas, col_maps, domain_key,
                                             as.integer(sel))
        browser_hier_detail_rv(list(data = data, loaded = TRUE,
                                    for_cid = as.integer(sel)))
      }
    }
  }, ignoreNULL = TRUE)

  # ── Add as inclusion ──────────────────────────────────────────────────────
  observeEvent(input$browser_add_inclusion, {
    .browser_add_criterion("inclusion")
  })

  # ── Add as exclusion ──────────────────────────────────────────────────────
  observeEvent(input$browser_add_exclusion, {
    .browser_add_criterion("exclusion")
  })

  # ── Shared criterion-append logic ─────────────────────────────────────────
  .browser_add_criterion <- function(crit_type) {
    sel <- browser_selected_rv()
    det <- browser_detail_rv()
    if (is.na(sel) || !isTRUE(det$overview_loaded)) return()

    domain_key <- det$domain_key %||% "condition"
    use_desc   <- isTRUE(input$browser_use_descendants)

    id  <- next_id_rv()
    next_id_rv(id + 1L)
    new_crit <- list(
      id              = paste0("crit_", id),
      type            = crit_type,
      domain          = domain_key,
      concept_ids     = as.integer(sel),
      use_descendants = use_desc,
      occur_min       = 1L,
      occur_max       = NA_integer_,
      window_start    = NA_integer_,
      window_end      = NA_integer_,
      washout_days    = NA_integer_,
      value_min       = NA_real_,
      value_max       = NA_real_,
      age_min         = NA_integer_,
      age_max         = NA_integer_,
      gender_ids      = integer(0),
      logic           = "AND"
    )
    crits <- criteria_rv()
    criteria_rv(c(crits, list(new_crit)))

    # Cache concept name
    if (!is.null(det$overview$concept_meta) && nrow(det$overview$concept_meta) > 0) {
      cn <- concept_names_rv()
      cn[[as.character(sel)]] <- det$overview$concept_meta$concept_name[1]
      concept_names_rv(cn)
    }

    # v10.13: no longer auto-switches to Build Cohort. The selected concepts
    # panel below the list shows what's been added; the user navigates
    # explicitly via the Run / Edit detail buttons or the sidebar nav.
    browser_drawer_open_rv(TRUE)
    showNotification(
      sprintf("Concept added as %s criterion.", crit_type),
      type = "message", duration = 2)
  }

  # ── Plain-English cohort description ─────────────────────────────────────────
  output$plain_english_ui <- renderUI({
    crits <- criteria_rv()
    if (length(crits) == 0) return(NULL)
    cn    <- concept_names_rv()
    desc  <- plain_english(crits, concept_names = cn)
    if (is.null(desc) || !nzchar(desc)) return(NULL)
    div(class = "plain-english-box",
      div(class = "pe-label", icon("pen-to-square"), " Cohort definition"),
      tags$span(desc)
    )
  })

  # ── Per-criterion live counts ─────────────────────────────────────────────────
  observe({
    crits   <- criteria_rv()
    schema  <- primary_schema(input$schema_select %||% character(0))
    col_map <- omop_col_map_rv()
    if (!conn_valid() || is.null(schema)) return()
    if (length(crits) == 0) { crit_counts_rv(list()); return() }

    counts <- crit_counts_rv()
    for (cr in crits) {
      dom    <- DOMAINS[[cr$domain]]
      p_col  <- ac(col_map, dom$table, dom$person_col)
      c_col  <- ac(col_map, dom$table, dom$concept_col)
      # Bug 1 fix (v8.2): honour use_descendants here too. Without this, the
      # "X persons match" badge in the criterion card shows 0 for any
      # criterion built against an ingredient/parent concept.
      conc_f <- if (length(cr$concept_ids) > 0) {
        ids <- paste(cr$concept_ids, collapse = ",")
        if (isTRUE(cr$use_descendants)) {
          sprintf(" AND %s IN (SELECT %s FROM %s WHERE %s IN (%s))",
                  c_col,
                  ac(col_map, "concept_ancestor", "descendant_concept_id"),
                  fq(schema, "concept_ancestor"),
                  ac(col_map, "concept_ancestor", "ancestor_concept_id"),
                  ids)
        } else {
          sprintf(" AND %s IN (%s)", c_col, ids)
        }
      } else ""
      sql <- sprintf("SELECT COUNT(DISTINCT %s)::int AS n FROM %s WHERE 1=1%s",
                     p_col, fq(schema, dom$table), conc_f)
      n <- tryCatch({
        r <- db_query(sql)
        v <- r$n[1]
        if (length(v) == 0L) NA_integer_ else as.integer(v)
      }, error = function(e) NA_integer_)
      counts[[cr$id]] <- n
    }
    crit_counts_rv(counts)
  }) |> bindEvent(criteria_rv(), input$schema_select)

  # Render a count badge for each criterion
  observe({
    crits <- criteria_rv()
    for (cr in crits) {
      local({
        cid <- cr$id
        output[[paste0("crit_count_", cid)]] <- renderUI({
          counts <- crit_counts_rv()
          n <- counts[[cid]]
          if (is.null(n) || length(n) == 0L) return(NULL)
          sm    <- schema_summary_rv()
          total <- if (!is.null(sm) && length(sm$n_persons) == 1L) sm$n_persons else NA_integer_
          pct_str <- if (isTRUE(!is.na(n) && !is.na(total) && total > 0L))
            sprintf(" · %.1f%% of persons", 100 * n / total) else ""
          if (isTRUE(is.na(n)))
            div(class = "crit-count-badge loading", icon("spinner"), " counting...")
          else if (isTRUE(n == 0L))
            div(class = "crit-count-badge zero", icon("triangle-exclamation"),
                " 0 persons match - check concept IDs or domain")
          else
            div(class = "crit-count-badge",
                icon("users"), " ", format(n, big.mark = ","), " persons", pct_str)
        })
      })
    }
  })

  # ── Concept name cache: update when concepts are added ───────────────────────
  observe({
    crits <- criteria_rv()
    schema <- primary_schema(input$schema_select %||% character(0))
    if (!conn_valid() || is.null(schema)) return()
    all_ids <- unique(unlist(lapply(crits, `[[`, "concept_ids")))
    if (length(all_ids) == 0) return()
    existing <- names(concept_names_rv())
    new_ids  <- setdiff(as.character(all_ids), existing)
    if (length(new_ids) == 0) return()
    tbls <- tolower(get_tables(schema))
    if (!"concept" %in% tbls) return()
    col_map  <- omop_col_map_rv()
    cid_col  <- ac(col_map, "concept", "concept_id")
    cname_col <- ac(col_map, "concept", "concept_name")
    sql <- sprintf("SELECT %s AS concept_id, %s AS concept_name FROM %s WHERE %s IN (%s)",
                   cid_col, cname_col,
                   fq(schema, "concept"),
                   cid_col, paste(new_ids, collapse = ","))
    r <- tryCatch(db_query(sql), error = function(e) NULL)
    if (!is.null(r) && nrow(r) > 0) {
      cn <- concept_names_rv()
      for (i in seq_len(nrow(r)))
        cn[[as.character(r$concept_id[i])]] <- r$concept_name[i]
      concept_names_rv(cn)
    }
  }) |> bindEvent(criteria_rv())

