  # Shared templates modal body - sorted by relevance score if available
  output$templates_modal_body <- renderUI({
    scored <- smart_templates_rv()

    # Build display list: if scored, merge score info; otherwise raw templates
    display_list <- if (!is.null(scored)) {
      scored[order(sapply(scored, `[[`, "score"), decreasing = TRUE)]
    } else {
      lapply(seq_along(TEMPLATES), function(i) {
        t <- TEMPLATES[[i]]; t$idx <- i; t$score <- NA; t$feasible <- TRUE
        t$evidence <- character(0); t$match_count <- 0; t$total_ids <- 0
        t
      })
    }

    has_scores <- !is.null(scored)

    # Group by category, keeping score order within each group
    cats <- unique(sapply(display_list, `[[`, "category"))
    # Re-order cats by best score in category
    cat_best <- sapply(cats, function(cat) {
      sc <- sapply(Filter(function(t) t$category == cat, display_list), function(t) t$score %||% 0)
      if (length(sc) > 0) max(sc, na.rm = TRUE) else 0
    })
    cats <- cats[order(cat_best, decreasing = TRUE)]

    if (has_scores)
      tagList(
        tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:12px;",
               "Sorted by relevance to your dataset. Match % reflects how many defining concepts were found."),
        lapply(cats, function(cat) {
          cat_tmpls <- Filter(function(t) t$category == cat, display_list)
          tagList(
            tags$p(style = "font-size:0.78rem;font-weight:700;text-transform:uppercase;letter-spacing:.7px;color:var(--dre-muted);margin:14px 0 6px;", cat),
            lapply(cat_tmpls, function(tmpl) {
              i <- tmpl$idx
              badge_cls <- if (!is.na(tmpl$score) && tmpl$score >= 70) "score-high"
                           else if (!is.na(tmpl$score) && tmpl$score >= 40) "score-mid"
                           else if (!is.na(tmpl$score) && tmpl$score > 0) "score-low"
                           else "score-none"
              ev <- head(tmpl$evidence, 2L)
              div(class = if (tmpl$feasible && tmpl$score > 0) "tmpl-card tmpl-card-live" else "tmpl-card tmpl-card-dim",
                onclick = sprintf("Shiny.setInputValue('load_template',%d,{priority:'event'})", i),
                div(class = "tmpl-card-top",
                  div(class = "tmpl-card-name", tmpl$name),
                  if (!is.na(tmpl$score))
                    div(class = paste("sc-score", badge_cls),
                        if (tmpl$score == 0) "Not found" else sprintf("%d%% match", tmpl$score))
                ),
                div(class = "tmpl-card-desc", tmpl$desc),
                if (length(ev) > 0)
                  div(class = "tmpl-card-evidence",
                    lapply(ev, function(e) div(class = "sc-ev-row", icon("check"), " ", e))
                  ),
                if (is.na(tmpl$score) || tmpl$score == 0)
                  div(class = "tmpl-card-unavail",
                      icon("triangle-exclamation"), " Defining concepts not found in this dataset")
              )
            })
          )
        })
      )
    else
      tagList(
        tags$p(style = "font-size:0.87rem;color:var(--dre-muted);margin-bottom:12px;",
               "Connect to a schema to see which cohorts match your data."),
        lapply(cats, function(cat) {
          cat_tmpls <- Filter(function(t) t$category == cat, display_list)
          cat_idxs  <- sapply(cat_tmpls, `[[`, "idx")
          tagList(
            tags$p(style = "font-size:0.78rem;font-weight:700;text-transform:uppercase;letter-spacing:.7px;color:var(--dre-muted);margin:12px 0 6px;", cat),
            lapply(seq_along(cat_tmpls), function(j) {
              tmpl <- cat_tmpls[[j]]; i <- cat_idxs[[j]]
              div(class = "tmpl-card",
                onclick = sprintf("Shiny.setInputValue('load_template',%d,{priority:'event'})", i),
                div(class = "tmpl-card-name", tmpl$name),
                div(class = "tmpl-card-desc", tmpl$desc)
              )
            })
          )
        })
      )
  })

