  observeEvent(input$load_template, {
    idx  <- as.integer(input$load_template)
    if (idx < 1 || idx > length(TEMPLATES)) return()
    tmpl <- TEMPLATES[[idx]]
    id_counter <- next_id_rv()
    new_crits <- lapply(seq_along(tmpl$criteria), function(j) {
      cr <- tmpl$criteria[[j]]
      cr$id <- paste0("crit_", id_counter + j - 1L)
      cr
    })
    next_id_rv(id_counter + length(tmpl$criteria))
    criteria_rv(new_crits)
    removeModal()
    removeModal()
    showNotification(sprintf("Template '%s' loaded - adjust criteria as needed.", tmpl$name),
                     type = "message", duration = 4)
  })


