  # ──────────────────────────────────────────────────────────────────────────
  # CRITERION MANAGEMENT
  # ──────────────────────────────────────────────────────────────────────────

  new_criterion <- function(type) {
    id <- next_id_rv()
    next_id_rv(id + 1L)
    list(
      id             = paste0("crit_", id),
      type           = type,
      domain         = "condition",
      concept_ids    = integer(0),
      use_descendants= FALSE,
      occur_min      = 1L,
      occur_max      = NA_integer_,
      window_start   = NA_integer_,
      window_end     = NA_integer_,
      washout_days   = NA_integer_,
      value_min      = NA_real_,
      value_max      = NA_real_,
      age_min        = NA_integer_,
      age_max        = NA_integer_,
      gender_ids     = integer(0),
      logic          = "AND"
    )
  }

  observeEvent(input$add_inc_btn, {
    crits <- criteria_rv()
    crits[[length(crits) + 1]] <- new_criterion("inclusion")
    criteria_rv(crits)
  })

  observeEvent(input$add_exc_btn, {
    crits <- criteria_rv()
    crits[[length(crits) + 1]] <- new_criterion("exclusion")
    criteria_rv(crits)
  })

  # ── Domain tile click: add inclusion criterion pre-set to that domain ────────
  observeEvent(input$domain_tile_click, {
    domain_key <- input$domain_tile_click
    if (!domain_key %in% names(DOMAINS)) return()
    dom   <- DOMAINS[[domain_key]]
    id    <- next_id_rv()
    next_id_rv(id + 1L)
    new_crit <- list(
      id             = paste0("crit_", id),
      type           = "inclusion",
      domain         = domain_key,
      concept_ids    = integer(0),
      use_descendants= FALSE,
      occur_min      = 1L,
      occur_max      = NA_integer_,
      window_start   = NA_integer_,
      window_end     = NA_integer_,
      washout_days   = NA_integer_,
      value_min      = NA_real_,
      value_max      = NA_real_,
      age_min        = NA_integer_,
      age_max        = NA_integer_,
      gender_ids     = integer(0),
      logic          = "AND"
    )
    crits <- criteria_rv()
    criteria_rv(c(crits, list(new_crit)))
    # v10.13: no longer auto-switches to Build Cohort.
    showNotification(
      sprintf("%s criterion added.", dom$label),
      type = "message", duration = 2)
  })

  # Remove criterion
  observe({
    crits <- criteria_rv()
    for (cr in crits) {
      local({
        cid <- cr$id
        observeEvent(input[[paste0("rm_", cid)]], {
          current <- criteria_rv()
          criteria_rv(Filter(function(c) c$id != cid, current))
        }, ignoreInit = TRUE, once = TRUE)
      })
    }
  })

  # Sync inputs back to criteria_rv when user edits
  observe({
    crits <- criteria_rv()
    for (i in seq_along(crits)) {
      local({
        ci    <- i
        crit  <- crits[[ci]]
        cid   <- crit$id

        # Domain change
        observeEvent(input[[paste0("domain_", cid)]], {
          current <- criteria_rv()
          idx     <- which(sapply(current, `[[`, "id") == cid)
          if (length(idx) == 1) {
            current[[idx]]$domain <- input[[paste0("domain_", cid)]]
            criteria_rv(current)
          }
        }, ignoreInit = TRUE, ignoreNULL = TRUE)

        # Numeric inputs
        for (fld in c("occur_min", "occur_max", "window_start", "window_end",
                      "value_min", "value_max", "age_min", "age_max", "washout_days")) {
          local({
            f <- fld
            observeEvent(input[[paste0(f, "_", cid)]], {
              val <- suppressWarnings(as.numeric(input[[paste0(f, "_", cid)]]))
              current <- criteria_rv()
              idx <- which(sapply(current, `[[`, "id") == cid)
              if (length(idx) == 1) {
                current[[idx]][[f]] <- if (is.na(val)) NA_integer_ else as.integer(val)
                criteria_rv(current)
              }
            }, ignoreInit = TRUE, ignoreNULL = FALSE)
          })
        }

        # Descendant expansion toggle
        observeEvent(input[[paste0("use_desc_", cid)]], {
          current <- criteria_rv()
          idx <- which(sapply(current, `[[`, "id") == cid)
          if (length(idx) == 1) {
            current[[idx]]$use_descendants <- isTRUE(input[[paste0("use_desc_", cid)]])
            criteria_rv(current)
          }
        }, ignoreInit = TRUE, ignoreNULL = FALSE)

        # OR logic toggle
        observeEvent(input[[paste0("or_logic_", cid)]], {
          current <- criteria_rv()
          idx <- which(sapply(current, `[[`, "id") == cid)
          if (length(idx) == 1) {
            current[[idx]]$logic <- if (isTRUE(input[[paste0("or_logic_", cid)]])) "OR" else "AND"
            criteria_rv(current)
          }
        }, ignoreInit = TRUE, ignoreNULL = FALSE)

        # Gender checkboxes
        observeEvent(input[[paste0("gender_", cid)]], {
          gmap <- c(Male = 8507L, Female = 8532L, Other = 8521L)
          sel  <- input[[paste0("gender_", cid)]] %||% character(0)
          ids  <- as.integer(gmap[sel[sel %in% names(gmap)]])
          current <- criteria_rv()
          idx <- which(sapply(current, `[[`, "id") == cid)
          if (length(idx) == 1) {
            current[[idx]]$gender_ids <- ids
            criteria_rv(current)
          }
        }, ignoreInit = TRUE, ignoreNULL = FALSE)

        # Date window preset
        observeEvent(input[[paste0("dw_preset_", cid)]], {
          preset <- input[[paste0("dw_preset_", cid)]] %||% "anytime"
          if (preset == "custom") return()  # let custom numeric inputs handle it
          p <- DATE_WINDOW_PRESETS[[preset]]
          if (is.null(p)) return()
          current <- criteria_rv()
          idx <- which(sapply(current, `[[`, "id") == cid)
          if (length(idx) == 1) {
            current[[idx]]$window_start <- p$ws
            current[[idx]]$window_end   <- p$we
            criteria_rv(current)
          }
        }, ignoreInit = TRUE, ignoreNULL = TRUE)

        # Domain change: update hint
        observeEvent(input[[paste0("domain_", cid)]], {
          current <- criteria_rv()
          idx <- which(sapply(current, `[[`, "id") == cid)
          if (length(idx) == 1) {
            current[[idx]]$domain <- input[[paste0("domain_", cid)]]
            criteria_rv(current)
          }
        }, ignoreInit = TRUE, ignoreNULL = TRUE)

      }) # end local
    }
  })

  # ── Concept chips (name-based, no IDs shown) ───────────────────────────────
  observe({
    crits <- criteria_rv()
    for (cr in crits) {
      local({
        cid  <- cr$id
        output[[paste0("concept_chips_", cid)]] <- renderUI({
          current <- criteria_rv()
          idx <- which(sapply(current, `[[`, "id") == cid)
          if (length(idx) == 0) return(NULL)
          ids <- current[[idx]]$concept_ids %||% integer(0)
          if (length(ids) == 0)
            return(tags$span(class = "crit-hint-chip", "All (no filter)"))
          cn <- concept_names_rv()
          tagList(lapply(ids, function(id) {
            nm <- cn[[as.character(id)]] %||% paste("Code", id)
            tags$span(class = "concept-chip",
              tags$span(nm),
              tags$span(class = "rm-chip",
                onclick = sprintf(
                  "Shiny.setInputValue('rm_concept',{crit:'%s',cid:%d},{priority:'event'})",
                  cid, id),
                "×")
            )
          }))
        })
      })
    }
  })

  # Remove concept chip
  observeEvent(input$rm_concept, {
    payload <- input$rm_concept
    crit_id <- payload$crit
    rm_id   <- as.integer(payload$cid)
    current <- criteria_rv()
    idx <- which(sapply(current, `[[`, "id") == crit_id)
    if (length(idx) == 1) {
      current[[idx]]$concept_ids <- setdiff(current[[idx]]$concept_ids %||% integer(0), rm_id)
      criteria_rv(current)
    }
  })

  # ── First-run banner ───────────────────────────────────────────────────────
  # v10.11: persistent schema requirement banner. Visible whenever no
  # schema is selected. Auto-disappears the moment a schema is ticked.
  # Sits above the first-run banner so it's the first thing the user sees.
  output$schema_required_banner_ui <- renderUI({
    sel <- input$schema_select %||% character(0)
    if (length(sel) > 0 && nzchar(sel[[1]])) return(NULL)
    if (!conn_valid()) return(NULL)  # different banner handles no-conn case
    div(class = "first-run-banner",
      style = paste(
        "border:1px solid var(--dre-warning);",
        "background:rgba(255,184,77,.08);"),
      div(class = "frb-title",
        style = "color:var(--dre-warning);",
        icon("triangle-exclamation"),
        " Select a workspace schema to begin"),
      tags$p(style = "color:var(--dre-text);font-size:0.93rem;margin:8px 0 0;",
        "Cohort building, characterisation, and all analyses operate on an ",
        "OMOP schema. Tick a schema from the dropdown in the sidebar to ",
        "enable the rest of the app."))
  })

  output$first_run_banner_ui <- renderUI({
    crits   <- criteria_rv()
    if (length(crits) > 0 || first_run_dismissed_rv()) return(NULL)

    scored  <- smart_templates_rv()
    schema  <- primary_schema(input$schema_select %||% character(0)) %||% ""
    has_db  <- conn_valid() && nzchar(schema)

    # ── State A: no connection yet ───────────────────────────────────────────
    if (!has_db) {
      return(div(class = "first-run-banner",
        div(class = "frb-title", icon("circle-info"), " Getting started"),
        tags$p(style = "color:var(--dre-muted);font-size:0.93rem;",
          "Connect to a database and select an OMOP schema - the builder will scan your data ",
          "and suggest the most relevant cohort definitions automatically."),
        div(style = "margin-top:10px;",
          actionButton("dismiss_banner_btn", "Build from scratch",
                       class = "btn-dre-sec btn-sm", icon = icon("pencil")))
      ))
    }

    # ── State B: connected, scoring in progress ──────────────────────────────
    if (is.null(scored)) {
      return(div(class = "first-run-banner",
        div(class = "frb-title", icon("spinner"), " Analysing your dataset..."),
        tags$p(style = "color:var(--dre-muted);font-size:0.93rem;",
          "Scanning concept frequencies to find the most relevant cohorts for this data.")
      ))
    }

    # ── State C: suggestions ready ───────────────────────────────────────────
    schemas_sel <- input$schema_select %||% character(0)
    multi       <- length(schemas_sel) > 1
    n_schemas   <- length(schemas_sel)

    feasible <- Filter(function(t) t$feasible && t$score > 0, scored)

    if (multi) {
      # Primary sort key: number of schemas with matching data (desc)
      # Secondary sort key: combined score (desc)
      # This guarantees all-schema matches always appear before
      # partial or single-schema matches regardless of raw score.
      n_with <- sapply(feasible, function(t)
        t$n_schemas_with_data %||% 0L)
      scores  <- sapply(feasible, function(t) t$score %||% 0L)
      ord <- order(-n_with, -scores)
      top <- head(feasible[ord], 6L)   # show 6 in multi-schema mode
    } else {
      top <- head(
        feasible[order(sapply(feasible, `[[`, "score"), decreasing = TRUE)],
        5L)
    }
    title_txt <- if (multi)
      paste("Suggested cohorts across", length(schemas_sel), "schemas")
    else "Suggested cohorts for this dataset"
    subtitle_txt <- if (multi)
      paste0("Ranked by concept overlap across all selected schemas. ",
             "Cards showing ✓ all schemas indicate cohort criteria ",
             "present in every dataset. Click any card to load it.")
    else
      "Based on what conditions, medications and lab tests are actually in your data. Click any card to load it."

    div(class = "first-run-banner",
      div(class = "frb-title",
        icon("wand-magic-sparkles"), " ", title_txt
      ),
      tags$p(class = "frb-subtitle", subtitle_txt),
      div(class = "suggestion-grid",
        lapply(top, function(t) {
          # Score badge colour
          badge_cls <- if (t$score >= 70) "score-high" else if (t$score >= 40) "score-mid" else "score-low"
          # Evidence list (first 2 items)
          ev <- head(t$evidence, 2L)
          div(class = "suggestion-card",
            onclick = sprintf(
              "Shiny.setInputValue('load_template',%d,{priority:'event'})",
              t$idx),
            div(class = "sc-top",
              div(class = "sc-name", t$name),
              div(style = "display:flex;align-items:center;gap:6px;",
                if (multi && !is.null(t$n_schemas_with_data) &&
                    t$n_schemas_with_data >= length(schemas_sel))
                  tags$span(style = paste0(
                    "font-size:0.72rem;font-weight:700;padding:2px 7px;",
                    "border-radius:10px;background:rgba(61,214,140,.15);",
                    "color:#3DD68C;white-space:nowrap;"),
                    "✓ all schemas")
                else if (multi && !is.null(t$n_schemas_with_data) &&
                         t$n_schemas_with_data > 0)
                  tags$span(style = paste0(
                    "font-size:0.72rem;font-weight:700;padding:2px 7px;",
                    "border-radius:10px;background:rgba(255,184,77,.12);",
                    "color:#FFB84D;white-space:nowrap;"),
                    sprintf("%d/%d schemas", t$n_schemas_with_data, length(schemas_sel))),
                div(class = paste("sc-score", badge_cls),
                    sprintf("%d%%", t$score))
              )
            ),
            div(class = "sc-category", t$category),
            div(class = "sc-evidence",
              lapply(ev, function(e)
                div(class = "sc-ev-row", icon("check"), " ", e)
              )
            ),
            if (!is.null(t$breakdown) && length(t$breakdown) > 0)
              div(class = "sc-schema-breakdown",
                  paste(t$breakdown, collapse = " \u00b7 ")),
            if (t$match_count < t$total_ids && t$total_ids > 0)
              div(class = "sc-partial",
                  sprintf("%d / %d concepts found in data",
                          t$match_count, t$total_ids))
          )
        })
      ),
      div(class = "frb-footer",
        actionButton("templates_btn_inner", "Browse all cohorts",
                     class = "btn-dre-sec btn-sm", icon = icon("list")),
        actionButton("dismiss_banner_btn", "Start from scratch",
                     class = "btn-dre-sec btn-sm", icon = icon("pencil"),
                     style = "margin-left:8px;")
      )
    )
  })

  observeEvent(input$dismiss_banner_btn, first_run_dismissed_rv(TRUE))

  observeEvent(input$templates_btn_inner, {
    showModal(modalDialog(
      title = tagList(icon("book-open"), " All Cohorts"),
      uiOutput("templates_modal_body"),
      size = "m", easyClose = TRUE, footer = modalButton("Cancel")
    ))
  })



