  output$empty_criteria_ui <- renderUI({
    crits <- criteria_rv()
    if (length(crits) == 0)
      div(class = "empty-state",
        div(class = "es-icon", icon("layer-group")),
        div(class = "es-title", "No criteria defined"),
        tags$p("Click ＋ Inclusion to add your first criterion.",
               tags$br(), "The first inclusion criterion defines the index event.")
      )
    else NULL
  })

  output$criteria_list_ui <- renderUI({
    crits <- criteria_rv()
    if (length(crits) == 0) return(NULL)

    inc_count <- 0L; exc_count <- 0L
    tagList(lapply(seq_along(crits), function(i) {
      cr  <- crits[[i]]
      cid <- cr$id
      is_inc <- cr$type == "inclusion"
      if (is_inc) { inc_count <<- inc_count + 1L; idx_num <- inc_count }
      else         { exc_count <<- exc_count + 1L; idx_num <- exc_count }

      is_first <- i == 1 && is_inc
      dom_def  <- DOMAINS[[cr$domain %||% "condition"]]

      # Determine current date-window preset
      ws_val <- cr$window_start %||% NA_integer_
      we_val <- cr$window_end   %||% NA_integer_
      cur_dw_preset <- "anytime"
      if (!is.na(ws_val) || !is.na(we_val)) {
        matched <- Filter(function(k) {
          p <- DATE_WINDOW_PRESETS[[k]]
          identical(p$ws, ws_val) && identical(p$we, we_val)
        }, setdiff(names(DATE_WINDOW_PRESETS), "custom"))
        cur_dw_preset <- if (length(matched) > 0) matched[[1]] else "custom"
      }
      show_custom <- cur_dw_preset == "custom"

      # Value range inputs (measurement only)
      val_ui <- if ((cr$domain %||% "") == "measurement")
        div(class = "crit-sub-row",
          tags$label(class = "crit-sublabel", icon("ruler"), " Lab result range (optional)"),
          fluidRow(
            column(3, numericInput(paste0("value_min_", cid), "Minimum value", value = cr$value_min, width = "100%")),
            column(3, numericInput(paste0("value_max_", cid), "Maximum value", value = cr$value_max, width = "100%"))
          )
        )
      else NULL

      # Descendant expansion toggle (only useful when concept IDs specified)
      desc_ui <- if (length(cr$concept_ids %||% integer(0)) > 0)
        div(class = "crit-sub-row",
          checkboxInput(paste0("use_desc_", cid),
            tagList(icon("sitemap"), " Include descendant concepts (via concept_ancestor)"),
            value = isTRUE(cr$use_descendants)),
          tags$p(class = "crit-hint",
            "Also matches all more-specific concepts in the OMOP hierarchy below your selected concepts.")
        )
      else NULL

      # OR logic toggle (not shown for first criterion - it is always the index)
      or_ui <- if (!is_first && i > 1)
        div(class = "crit-sub-row",
          checkboxInput(paste0("or_logic_", cid),
            tagList(icon("code-branch"), " OR - combine with previous criterion (UNION)"),
            value = identical(cr$logic %||% "AND", "OR")),
          tags$p(class = "crit-hint",
            "When checked, patients matching EITHER this criterion OR the one above it are included.")
        )
      else NULL

      # Washout period (inclusion criteria only; not meaningful for first criterion)
      washout_ui <- if (is_inc && !is_first)
        div(class = "crit-sub-row",
          tags$label(class = "crit-sublabel", icon("ban"), " Washout period (incident cohort, optional)"),
          tags$p(class = "crit-hint",
            "Exclude patients who already had this condition/drug N days before index. Leave blank to skip."),
          numericInput(paste0("washout_", cid), "Prior occurrence washout (days)",
                       value = if (is.na(cr$washout_days %||% NA_integer_)) NA else cr$washout_days,
                       min = 1, width = "220px")
        )
      else NULL

      div(class = paste("criterion-row", if (is_inc) "inc" else "exc"),

        # ── Header ──────────────────────────────────────────────────────────
        div(class = "crit-row-header",
          tags$span(class = paste("criterion-label", if (is_inc) "inc" else "exc"),
            if (is_inc)
              if (is_first) tagList(icon("star"), " Index condition - patients must have...")
              else          tagList(icon("circle-plus"), paste(" Also require (criterion", idx_num, ")"))
            else
              tagList(icon("circle-minus"), paste(" Exclude patients who have (criterion", idx_num, ")"))
          ),
          actionButton(paste0("rm_", cid), "Remove",
                       class = "btn-dre-danger btn-sm",
                       icon = icon("trash"))
        ),

        # ── Clinical type ───────────────────────────────────────────────────
        div(class = "crit-sub-row",
          tags$label(class = "crit-sublabel", icon("tag"), " Clinical category"),
          selectInput(paste0("domain_", cid), NULL,
                      choices = DOMAIN_CHOICES, selected = cr$domain %||% "condition", width = "100%"),
          tags$p(class = "crit-hint", dom_def$sublabel)
        ),

        # ── Concept finder ──────────────────────────────────────────────────
        div(class = "crit-sub-row",
          tags$label(class = "crit-sublabel", icon("magnifying-glass"),
                     " Specific diagnoses / medications / tests"),
          tags$p(class = "crit-hint", "Leave empty to match all. Click Find to search."),
          div(class = "concept-chips-container",
            uiOutput(paste0("concept_chips_", cid)),
            actionButton(paste0("search_concepts_", cid), "Find...",
                         class = "btn-dre-sec btn-sm concept-find-btn",
                         icon = icon("magnifying-glass"))
          )
        ),

        # ── Occurrence ──────────────────────────────────────────────────────
        div(class = "crit-sub-row",
          tags$label(class = "crit-sublabel", icon("hashtag"), " Number of times recorded"),
          fluidRow(
            column(3, numericInput(paste0("occur_min_", cid), "At least", value = cr$occur_min %||% 1, min = 1, width = "100%")),
            column(3, numericInput(paste0("occur_max_", cid), "At most (optional)", value = cr$occur_max, width = "100%"))
          )
        ),

        # ── Time window ──────────────────────────────────────────────────────
        if (!is_first) div(class = "crit-sub-row",
          tags$label(class = "crit-sublabel", icon("clock"), " Timing relative to index event"),
          selectInput(paste0("dw_preset_", cid), NULL,
                      choices = DW_CHOICES, selected = cur_dw_preset, width = "100%"),
          if (show_custom) fluidRow(
            column(3, numericInput(paste0("window_start_", cid), "Start day (negative = before)", value = ws_val, width = "100%")),
            column(3, numericInput(paste0("window_end_",   cid), "End day",                        value = we_val, width = "100%"))
          )
        ) else NULL,

        # ── Demographics ─────────────────────────────────────────────────────
        if (is_inc) div(class = "crit-sub-row",
          tags$label(class = "crit-sublabel", icon("user"), " Patient demographics (optional)"),
          fluidRow(
            column(3, numericInput(paste0("age_min_", cid), "Minimum age", value = cr$age_min, min = 0, max = 120, width = "100%")),
            column(3, numericInput(paste0("age_max_", cid), "Maximum age", value = cr$age_max, min = 0, max = 120, width = "100%")),
            column(6,
              tags$label(class = "control-label", "Biological sex"),
              checkboxGroupInput(paste0("gender_", cid), NULL,
                                 choices = c("Male" = "Male", "Female" = "Female", "Other / Unknown" = "Other"),
                                 selected = c(
                                   if (8507L %in% (cr$gender_ids %||% integer(0))) "Male",
                                   if (8532L %in% (cr$gender_ids %||% integer(0))) "Female",
                                   if (any(c(8521L, 8570L) %in% (cr$gender_ids %||% integer(0)))) "Other"
                                 ),
                                 inline = TRUE)
            )
          )
        ) else NULL,

        val_ui,
        desc_ui,
        or_ui,
        washout_ui,
        uiOutput(paste0("crit_count_", cid))
      )
    }))
  })
  # ── Open concept search modal from criterion row ───────────────────────────
  observe({
    crits <- criteria_rv()
    for (cr in crits) {
      local({
        cid <- cr$id
        observeEvent(input[[paste0("search_concepts_", cid)]], {
          active_crit_rv(cid)
          # Pre-populate with top concepts for this criterion's domain
          crits_now  <- criteria_rv()
          idx_now    <- which(vapply(crits_now, function(c) identical(c$id, cid), logical(1)))
          dom_key    <- if (length(idx_now)==1) crits_now[[idx_now]]$domain else NULL
          modal_search_rv(list(term="", domain_key=dom_key, res=NULL, loading=TRUE))
          showModal(modalDialog(
            title = tagList(icon("magnifying-glass"), " Concept Search"),
            div(style="margin-bottom:10px;",
              textInput("modal_concept_q", NULL,
                placeholder = "Type to filter - showing top concepts by prevalence...",
                width = "100%")
            ),
            uiOutput("modal_concept_results_ui"),
            size = "l",
            easyClose = TRUE,
            footer = tagList(modalButton("Close"))
          ))
          # Load top concepts after modal is shown
          top_res <- tryCatch(top_concepts_for_domain(dom_key), error=function(e) NULL)
          modal_search_rv(list(term="", domain_key=dom_key, res=top_res, loading=FALSE))
        }, ignoreInit = TRUE, once = FALSE)
      })
    }
  })

  # ──────────────────────────────────────────────────────────────────────────
  # CONCEPT SEARCH (sidebar + modal)
  # ──────────────────────────────────────────────────────────────────────────

  # Returns top concepts for the domain - used to populate modal on open.
  top_concepts_for_domain <- function(domain_key = NULL) {
    req(conn_valid(), length(input$schema_select %||% character(0)) > 0)
    schema  <- primary_schema(input$schema_select %||% character(0))
    tbls    <- tolower(get_tables(schema))
    col_map <- omop_col_map_rv()
    if (!is.null(domain_key) && domain_key %in% names(DOMAINS)) {
      dom <- DOMAINS[[domain_key]]
      if (!tolower(dom$table) %in% tbls) return(NULL)
      pid_col <- ac(col_map, dom$table, dom$person_col)
      cid_col <- ac(col_map, dom$table, dom$concept_col)
      if (!"concept" %in% tbls) {
        # No concept table - return raw IDs
        sql <- sprintf(
          "SELECT %s::int AS concept_id, COUNT(DISTINCT %s)::int AS n_persons
           FROM   %s WHERE %s != 0
           GROUP  BY %s ORDER BY n_persons DESC LIMIT 50",
          cid_col, pid_col, fq(schema, dom$table), cid_col, cid_col)
        r <- tryCatch({
          r2 <- db_query(sql); names(r2) <- tolower(names(r2)); r2
        }, error = function(e) NULL)
        if (is.null(r)) return(NULL)
        r$concept_name   <- paste("Concept", r$concept_id)
        r$domain_id      <- dom$label
        r$vocabulary_id  <- ""
        r$standard_concept <- NA_character_
        return(r)
      }
      cid_c   <- ac(col_map, "concept", "concept_id")
      cname_c <- ac(col_map, "concept", "concept_name")
      cdom_c  <- ac(col_map, "concept", "domain_id")
      cvoc_c  <- ac(col_map, "concept", "vocabulary_id")
      cstd_c  <- ac(col_map, "concept", "standard_concept")
      cinv_c  <- ac(col_map, "concept", "invalid_reason")
      t_cid   <- ac(col_map, dom$table, dom$concept_col)
      sql <- sprintf(
        "SELECT c.%s AS concept_id, c.%s AS concept_name,
                c.%s AS domain_id, c.%s AS vocabulary_id,
                c.%s AS standard_concept,
                COUNT(DISTINCT t.%s)::int AS n_persons
         FROM   %s t
         JOIN   %s c ON t.%s = c.%s
         WHERE  t.%s != 0 AND c.%s IS NULL
         GROUP  BY c.%s, c.%s, c.%s, c.%s, c.%s
         ORDER  BY n_persons DESC, c.%s DESC NULLS LAST
         LIMIT  50",
        cid_c, cname_c, cdom_c, cvoc_c, cstd_c, pid_col,
        fq(schema, dom$table), fq(schema, "concept"),
        t_cid, cid_c,
        t_cid, cinv_c,
        cid_c, cname_c, cdom_c, cvoc_c, cstd_c, cstd_c)
      tryCatch({
        r <- db_query(sql); names(r) <- tolower(names(r)); r
      }, error = function(e) NULL)
    } else NULL
  }

  do_concept_search <- function(term, domain_key = NULL) {
    req(conn_valid(), length(input$schema_select %||% character(0)) > 0, nzchar(trimws(term)))
    schema  <- primary_schema(input$schema_select %||% character(0))
    tbls    <- tolower(get_tables(schema))
    col_map <- omop_col_map_rv()
    if (!"concept" %in% tbls) {
      showNotification("concept table not found in this schema", type = "warning")
      return(NULL)
    }
    # Resolved concept column names
    cid_col   <- ac(col_map, "concept", "concept_id")
    cname_col <- ac(col_map, "concept", "concept_name")
    cdom_col  <- ac(col_map, "concept", "domain_id")
    cvoc_col  <- ac(col_map, "concept", "vocabulary_id")
    cstd_col  <- ac(col_map, "concept", "standard_concept")
    cinv_col  <- ac(col_map, "concept", "invalid_reason")

    # v8.7: presence-check for concept_class_id. The column is standard in
    # OMOP CDM 5.x but we don't assume; if absent the chip is just omitted.
    concept_cols_lc <- tryCatch(
      tolower(names(db_query(sprintf("SELECT * FROM %s LIMIT 0",
                                      fq(schema, "concept"))))),
      error = function(e) character(0))
    has_class <- "concept_class_id" %in% concept_cols_lc
    class_sel <- if (has_class)
      sprintf(", c.%s AS concept_class_id",
              ac(col_map, "concept", "concept_class_id"))
    else ""
    class_grp <- if (has_class)
      sprintf(", c.%s", ac(col_map, "concept", "concept_class_id"))
    else ""

    # If we know the domain, JOIN its table for in-schema person frequency
    freq_join <- ""
    freq_col  <- "NULL::int AS n_persons"
    if (!is.null(domain_key) && domain_key %in% names(DOMAINS)) {
      dom <- DOMAINS[[domain_key]]
      if (tolower(dom$table) %in% tbls) {
        t_concept_col <- ac(col_map, dom$table, dom$concept_col)
        t_person_col  <- ac(col_map, dom$table, dom$person_col)
        freq_join <- sprintf("LEFT JOIN %s t ON t.%s = c.%s",
                             fq(schema, dom$table),
                             t_concept_col, cid_col)
        freq_col  <- sprintf("COUNT(DISTINCT t.%s)::int AS n_persons", t_person_col)
      }
    }
    sql <- sprintf(
      "SELECT c.%s AS concept_id, c.%s AS concept_name,
              c.%s AS domain_id,  c.%s AS vocabulary_id,
              c.%s AS standard_concept%s, %s
       FROM   %s c %s
       WHERE  lower(c.%s::text) LIKE lower(%s)
         AND  c.%s IS NULL
       GROUP  BY c.%s, c.%s, c.%s, c.%s, c.%s%s
       ORDER  BY c.%s DESC NULLS LAST,
                 n_persons DESC NULLS LAST, c.%s
       LIMIT  50",
      cid_col, cname_col, cdom_col, cvoc_col, cstd_col, class_sel, freq_col,
      fq(schema, "concept"), freq_join,
      cname_col, pg_str(paste0("%", trimws(term), "%")),
      cinv_col,
      cid_col, cname_col, cdom_col, cvoc_col, cstd_col, class_grp,
      cstd_col, cname_col)
    res <- tryCatch({
      r <- db_query(sql); if (!is.null(r)) names(r) <- tolower(names(r)); r
    }, error = function(e) {
      showNotification(paste("Concept search failed:", e$message), type = "error")
      NULL
    })

    # v8.7: descendant-aware prevalence - for each result row, count
    # distinct persons in the domain table whose record references *any*
    # descendant of the candidate concept. Only meaningful when we have
    # both a domain to count in AND a concept_ancestor table to expand
    # through. Merged onto the result by concept_id. Graceful omission:
    # missing concept_ancestor → no descendant column appears on the result.
    if (!is.null(res) && nrow(res) > 0 && nzchar(freq_join) &&
        "concept_ancestor" %in% tbls) {
      ids_sql <- paste(as.integer(res$concept_id), collapse = ",")
      ca_anc  <- ac(col_map, "concept_ancestor", "ancestor_concept_id")
      ca_des  <- ac(col_map, "concept_ancestor", "descendant_concept_id")
      dom     <- DOMAINS[[domain_key]]
      t_cid   <- ac(col_map, dom$table, dom$concept_col)
      t_pid   <- ac(col_map, dom$table, dom$person_col)
      desc_sql <- sprintf(
        "SELECT ca.%s AS concept_id,
                COUNT(DISTINCT t.%s)::int AS n_persons_desc
         FROM   %s ca
         JOIN   %s t ON t.%s = ca.%s
         WHERE  ca.%s IN (%s)
         GROUP  BY ca.%s",
        ca_anc, t_pid,
        fq(schema, "concept_ancestor"),
        fq(schema, dom$table), t_cid, ca_des,
        ca_anc, ids_sql,
        ca_anc)
      desc_df <- tryCatch(db_query(desc_sql), error = function(e) NULL)
      if (!is.null(desc_df) && nrow(desc_df) > 0) {
        names(desc_df) <- tolower(names(desc_df))
        res$concept_id    <- as.integer(res$concept_id)
        desc_df$concept_id <- as.integer(desc_df$concept_id)
        # Preserve the original SQL ranking - merge() reorders by the
        # join column by default.
        res$.orig <- seq_len(nrow(res))
        res <- merge(res, desc_df, by = "concept_id", all.x = TRUE)
        res <- res[order(res$.orig), , drop = FALSE]
        res$.orig <- NULL
        rownames(res) <- NULL
      }
    }

    res
  }

  # Sidebar concept search (no domain context, no frequency join)
  # Modal concept search - debounced live search; also triggered by Search button
  modal_concept_q_d <- debounce(reactive(input$modal_concept_q %||% ""), 350)

  observe({
    q   <- trimws(modal_concept_q_d())
    st  <- modal_search_rv()
    if (is.null(st)) return()          # modal not open
    dom_key <- st$domain_key
    if (nchar(q) == 0) {
      # Empty box - keep showing top concepts (already loaded on open)
      return()
    }
    if (nchar(q) < 2) return()         # too short - wait for more input
    res <- tryCatch(
      do_concept_search(q, domain_key = dom_key),
      error = function(e) NULL)
    modal_search_rv(list(term=q, domain_key=dom_key, res=res, loading=FALSE))
  })

  output$modal_concept_results_ui <- renderUI({
    st <- modal_search_rv()
    if (is.null(st)) return(NULL)
    if (isTRUE(st$loading))
      return(div(style="color:var(--dre-muted);font-size:0.87rem;padding:12px 0;",
                 icon("spinner"), " Loading top concepts..."))
    res <- st$res
    q   <- trimws(input$modal_concept_q %||% "")
    if (is.null(res)) {
      if (nchar(q) >= 1 && nchar(q) < 2)
        return(tags$p(style="color:var(--dre-muted);font-size:0.84rem;padding:8px 0;",
                      "Type at least 2 characters to search..."))
      return(tags$p(style="color:var(--dre-muted);font-size:0.87rem;padding:8px 0;",
                    "No concepts found."))
    }
    if (nrow(res) == 0)
      return(tags$p(style="color:var(--dre-muted);font-size:0.87rem;padding:8px 0;",
                    sprintf('No concepts matching "%s" found.', q)))

    active_cid    <- active_crit_rv()
    has_freq      <- "n_persons" %in% names(res) && any(!is.na(res$n_persons))
    has_desc      <- "n_persons_desc" %in% names(res) && any(!is.na(res$n_persons_desc))
    has_class     <- "concept_class_id" %in% names(res) &&
                     any(nzchar(as.character(res$concept_class_id %||% "")))
    total_persons <- if (has_freq) { sm <- schema_summary_rv(); if (!is.null(sm)) sm$n_persons else NA_integer_ } else NA_integer_
    header_msg    <- if (nchar(q) == 0)
      sprintf("Top %d concepts by prevalence - type to filter", nrow(res))
    else
      sprintf("%d result%s - click to add", nrow(res), if (nrow(res)==1) "" else "s")

    tagList(
      tags$p(style="color:var(--dre-muted);font-size:0.84rem;margin:6px 0 4px;", header_msg),
      tags$div(style="max-height:360px;overflow-y:auto;margin-top:4px;",
          lapply(seq_len(nrow(res)), function(i) {
            r       <- res[i,]
            cid_val <- as.integer(r[["concept_id"]])
            np      <- if (has_freq && !is.na(r[["n_persons"]])) as.integer(r[["n_persons"]]) else NA_integer_
            np_desc <- if (has_desc && !is.na(r[["n_persons_desc"]])) as.integer(r[["n_persons_desc"]]) else NA_integer_

            # Exact-match prevalence pill (existing behaviour)
            freq_ui <- if (!is.na(np)) {
              pct_str <- if (!is.na(total_persons) && total_persons > 0)
                sprintf(" \u00b7 %.1f%%", 100 * np / total_persons) else ""
              tags$span(class = if (np > 0) "freq-pill has-data" else "freq-pill",
                        format(np, big.mark = ","), " persons", pct_str)
            } else NULL

            # v8.7: descendant-aware prevalence pill. Only show when it adds
            # information beyond the exact pill - i.e. when descendant count
            # is strictly greater (which means the concept has descendants
            # with records). Suppresses the chip on leaf concepts where
            # exact == descendant. Distinct visual style: amber tint to
            # signal "with descendants" without competing with the primary
            # exact-match pill.
            desc_ui <- if (!is.na(np_desc) && !is.na(np) && np_desc > np) {
              pct_str <- if (!is.na(total_persons) && total_persons > 0)
                sprintf(" \u00b7 %.1f%%", 100 * np_desc / total_persons) else ""
              tags$span(
                class = "freq-pill desc-pill",
                style = "background:rgba(255,184,77,.18);color:#FFB84D;border-color:rgba(255,184,77,.35);",
                "+ desc: ", format(np_desc, big.mark = ","), " persons", pct_str)
            } else NULL

            # v8.7: concept-class chip. Renders only when concept_class_id
            # is populated. Distinct from the existing vocabulary pill so
            # the user can see Ingredient / Clinical Drug / Branded Drug
            # at a glance.
            class_str <- as.character(r[["concept_class_id"]] %||% "")
            class_ui  <- if (has_class && nzchar(class_str))
              tags$span(class = "cs-class-pill",
                        style = paste(
                          "display:inline-block;font-size:0.74rem;",
                          "padding:2px 8px;border-radius:10px;margin-left:4px;",
                          "background:rgba(0,197,181,.10);",
                          "color:var(--dre-teal);",
                          "border:1px solid rgba(0,197,181,.30);"),
                        class_str)
            else NULL

            std_mark <- if (identical(as.character(r[["standard_concept"]] %||% ""), "S"))
              tags$span(style = "font-size:0.80rem;color:var(--dre-success);margin-left:4px;", "S") else NULL
            div(class = "cs-row",
              onclick = sprintf(
                "Shiny.setInputValue('add_concept_to_crit',{crit:'%s',cid:%d,name:'%s'},{priority:'event'})",
                active_cid %||% "", cid_val,
                gsub("'", "\\\\'", as.character(r[["concept_name"]] %||% ""))),
              tags$span(style = "font-weight:600;color:var(--dre-text);",
                        as.character(r[["concept_name"]] %||% "")), std_mark,
              tags$span(class = "cs-domain-pill",
                        as.character(r[["vocabulary_id"]] %||% r[["domain_id"]] %||% "")),
              class_ui,
              freq_ui,
              desc_ui
            )
          })
        )
    )
  })

  # Add selected concept to criterion
  observeEvent(input$add_concept_to_crit, {
    payload <- input$add_concept_to_crit
    crit_id <- payload$crit
    cid_val <- as.integer(payload$cid)
    # cache the display name if available from search result
    nm <- as.character(payload$name %||% "")
    if (nzchar(nm)) {
      cn <- concept_names_rv()
      cn[[as.character(cid_val)]] <- nm
      concept_names_rv(cn)
    }
    current <- criteria_rv()
    idx     <- which(sapply(current, `[[`, "id") == crit_id)
    if (length(idx) == 1) {
      existing <- current[[idx]]$concept_ids %||% integer(0)
      if (!cid_val %in% existing) {
        current[[idx]]$concept_ids <- c(existing, cid_val)
        criteria_rv(current)
        # Update the text input too
        updateTextInput(session, paste0("concepts_text_", crit_id),
                        value = paste(current[[idx]]$concept_ids, collapse = ", "))
        showNotification(sprintf("Added concept %d", cid_val), type = "message", duration = 2)
      }
    }
  })

  # ──────────────────────────────────────────────────────────────────────────
  # SQL GENERATION
  # ──────────────────────────────────────────────────────────────────────────

  # generated_sql now returns:
  #   single schema → character (SQL string, backwards-compatible)
  #   multi schema  → named list(schema = sql_string)
  generated_sql <- reactive({
    crits   <- criteria_rv()
    schemas <- input$schema_select %||% character(0)
    req(length(crits) > 0, length(schemas) > 0)
    col_maps <- col_maps_rv()
    if (length(schemas) == 1) {
      sch <- schemas[1]
      cm  <- col_maps[[sch]] %||% omop_col_map_rv()
      build_cohort_sql(sch, crits,
                       cohort_name       = input$cohort_name %||% "my_cohort",
                       index_strategy    = input$index_strategy %||% "first_qualifying",
                       prior_obs_days    = prior_obs_days_rv(),
                       min_followup_days = min_followup_days_rv(),
                       col_map           = cm)
    } else {
      sqls <- setNames(lapply(schemas, function(sch) {
        cm <- col_maps[[sch]] %||% list()
        tryCatch(
          build_cohort_sql(sch, crits,
                           cohort_name       = input$cohort_name %||% "my_cohort",
                           index_strategy    = input$index_strategy %||% "first_qualifying",
                           prior_obs_days    = prior_obs_days_rv(),
                           min_followup_days = min_followup_days_rv(),
                           col_map           = cm),
          error = function(e) NULL)
      }), schemas)
      sqls
    }
  })

  output$cohort_error_ui <- renderUI({
    err <- cohort_error_rv()
    if (is.null(err)) return(NULL)
    div(class = "cohort-error-panel",
      div(class = "cohort-error-title",
        icon("circle-exclamation"), " Query Error"
      ),
      tags$pre(class = "cohort-error-msg", err)
    )
  })

  output$sql_panel_ui <- renderUI({
    sql <- tryCatch(generated_sql(), error = function(e) NULL)
    if (is.null(sql))
      return(div(class = "empty-state",
        div(class = "es-icon", icon("code")),
        div(class = "es-title", "No SQL generated"),
        tags$p("Add at least one inclusion criterion in the Build tab.")))
    if (is.character(sql))
      return(div(class = "sql-panel", sql))
    # Multi-schema: show each schema's SQL in a labelled panel
    tagList(lapply(names(sql), function(s) {
      div(style = "margin-bottom:16px;",
        div(style = "font-size:0.80rem;color:var(--dre-teal);margin-bottom:4px;font-weight:700;",
            icon("database"), " ", s),
        div(class = "sql-panel",
            if (!is.null(sql[[s]])) sql[[s]] else "-- No SQL generated for this schema")
      )
    }))
  })

  # ──────────────────────────────────────────────────────────────────────────
  # RUN COHORT QUERY - shared core (v10.12)
  # Both the SQL-tab Run button and the Build-tab Run button call this.
  # ──────────────────────────────────────────────────────────────────────────

  # v11: signature of the patient-determining definition (criteria + options +
  # schemas). Used to cache-skip an auto-run and to detect a stale result.
  # cohort_name is held constant so a rename does not invalidate the result.
  cohort_signature <- function() {
    paste0(
      serialise_cohort_def(
        criteria          = criteria_rv(),
        cohort_name       = "sig",
        index_strategy    = input$index_strategy %||% "first_qualifying",
        prior_obs_days    = prior_obs_days_rv(),
        min_followup_days = min_followup_days_rv()),
      "|schemas=",
      paste(sort(input$schema_select %||% character(0)), collapse = ","))
  }

  run_cohort_core <- function(navigate_to_results = TRUE) {
    req(conn_valid())
    schemas <- input$schema_select %||% character(0)
    req(length(schemas) > 0)
    cohort_error_rv(NULL)

    sql_obj <- tryCatch(generated_sql(), error = function(e) {
      cohort_error_rv(paste("SQL generation failed:", conditionMessage(e))); NULL
    })
    if (is.null(sql_obj)) {
      if (is.null(cohort_error_rv()))
        cohort_error_rv("No SQL to run \u2014 add at least one inclusion criterion.")
      return()
    }

    run_status_rv("running")
    withProgress(message = "Running cohort query\u2026", value = 0, {
      if (is.character(sql_obj)) {
        # ── Single schema ──────────────────────────────────────────────
        setProgress(0.3)
        result <- tryCatch(db_query(sql_obj), error = function(e) {
          cohort_error_rv(conditionMessage(e))
          showNotification(paste("Query error:", conditionMessage(e)),
                           type = "error", duration = 8)
          NULL
        })
        setProgress(1)
        cohort_result_rv(result)
      } else {
        # ── Multi schema - run each, tag with source_schema, bind ──────
        all_results <- list()
        errors      <- character(0)
        for (si in seq_along(schemas)) {
          sch <- schemas[si]
          setProgress(si / length(schemas),
                      detail = sprintf("Querying %s\u2026", sch))
          sql_i <- sql_obj[[sch]]
          if (is.null(sql_i)) { errors <- c(errors, sprintf("%s: no SQL", sch)); next }
          r <- tryCatch(db_query(sql_i), error = function(e) {
            errors <<- c(errors, sprintf("%s: %s", sch, conditionMessage(e))); NULL
          })
          if (!is.null(r) && nrow(r) > 0) {
            r$source_schema <- sch
            all_results[[sch]] <- r
          }
        }
        if (length(errors) > 0)
          showNotification(paste("Errors:", paste(errors, collapse="; ")),
                           type = "warning", duration = 10)
        if (length(all_results) == 0) {
          cohort_result_rv(NULL)
          cohort_error_rv(if (length(errors)>0) paste(errors, collapse="\n")
                          else "No persons found in any selected schema.")
        } else {
          # Bind all schemas; re-rank globally
          combined <- do.call(rbind, all_results)
          combined$cohort_rank <- seq_len(nrow(combined))
          cohort_result_rv(combined)
        }
      }
    })

    res <- cohort_result_rv()
    if (!is.null(res) && nrow(res) > 0) {
      n_schemas <- if ("source_schema" %in% names(res))
        length(unique(res$source_schema)) else 1L
      msg <- if (n_schemas > 1)
        sprintf("Cohort: %d persons across %d schemas",
                nrow(res), n_schemas)
      else sprintf("Cohort: %d persons", nrow(res))
      showNotification(msg, type = "message", duration = 4)
      if (navigate_to_results)
        updateTabItems(session, "main_tabs", "tab_validate")
    } else if (!is.null(res)) {
      showNotification("Query returned 0 persons.", type = "warning")
    }

    if (!is.null(cohort_result_rv())) {
      run_signature_rv(cohort_signature())
      run_status_rv("fresh")
    } else {
      run_status_rv("empty")
    }
  }

  # v11: run the cohort if a result is needed but missing or stale. The cache
  # guard skips when a fresh result already matches the current definition.
  # Manual Run buttons still call run_cohort_core directly; this is the auto path.
  # v11: load the members of a materialised cohort (a schema that contains a
  # standard cohort table) into cohort_result_rv. The cohort table already holds
  # subject_id + cohort_start_date, which is the shape the analysis tabs need.
  # Column casing is resolved from information_schema to be robust.
  load_materialised_cohort <- function(schema) {
    tbls <- ohdsi_discover_cohort_tables(schema)
    if (length(tbls) == 0) return(NULL)
    ct <- if (any(tolower(tbls) == "cohort")) tbls[tolower(tbls) == "cohort"][1] else tbls[1]
    cols <- tryCatch(db_query(sprintf(
      "SELECT column_name FROM information_schema.columns
       WHERE table_schema = %s AND table_name = %s",
      pg_str(schema), pg_str(ct)))$column_name, error = function(e) character(0))
    pick <- function(want) { m <- cols[tolower(cols) == want]; if (length(m)) m[1] else want }
    sid <- qq(pick("subject_id"))
    sd  <- qq(pick("cohort_start_date"))
    ed  <- qq(pick("cohort_end_date"))
    sql <- sprintf(
      "SELECT %s AS person_id,
              %s::date AS index_date,
              %s::date AS cohort_end_date,
              ROW_NUMBER() OVER (ORDER BY %s) AS cohort_rank
       FROM %s",
      sid, sd, ed, sid, fq(schema, ct))
    res <- tryCatch(db_query(sql), error = function(e) {
      message("[load cohort] ", conditionMessage(e)); NULL })
    if (is.null(res) || nrow(res) == 0) return(NULL)
    names(res) <- tolower(names(res))
    res
  }

  # v11: read the persisted cohort definition from a materialised schema's
  # cohort_set (written by materialise_cohort_to_schema since v11). Returns the
  # deserialised definition, or NULL for older exports that stored no definition.
  read_cohort_definition <- function(schema) {
    meta <- tryCatch(db_query(sprintf(
      "SELECT table_name, column_name FROM information_schema.columns
       WHERE table_schema = %s AND lower(table_name) = 'cohort_set'",
      pg_str(schema))), error = function(e) NULL)
    if (is.null(meta) || nrow(meta) == 0) return(NULL)
    names(meta) <- tolower(names(meta))
    jrow <- meta[tolower(meta$column_name) == "cohort_definition_json", , drop = FALSE]
    if (nrow(jrow) == 0) return(NULL)
    tn <- jrow$table_name[1]; jc <- jrow$column_name[1]
    j <- tryCatch(db_query(sprintf(
      "SELECT %s AS j FROM %s WHERE %s IS NOT NULL LIMIT 1",
      qq(jc), fq(schema, tn), qq(jc)))$j, error = function(e) NULL)
    if (is.null(j) || length(j) == 0 || is.na(j[1]) || !nzchar(as.character(j[1]))) return(NULL)
    def <- deserialise_cohort_def(as.character(j[1]))
    if (!isTRUE(def$ok) || length(def$criteria) == 0) return(NULL)
    def
  }

  # v11: materialise the cohort if a result is needed but missing or stale. Two
  # sources: (A) an interactive definition (criteria_rv) -> run build_cohort_sql;
  # (B) no definition, but a selected schema holds a materialised cohort table
  # -> load its members directly. The cache guard skips redundant work.
  ensure_cohort_run <- function() {
    if (!conn_valid()) return(invisible(FALSE))
    schemas <- input$schema_select %||% character(0)
    inc <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())

    if (length(inc) > 0) {
      if (length(schemas) == 0) return(invisible(FALSE))
      if (!is.null(cohort_result_rv()) &&
          identical(run_status_rv(), "fresh") &&
          identical(run_signature_rv(), cohort_signature()))
        return(invisible(TRUE))
      run_cohort_core(navigate_to_results = FALSE)
      return(invisible(TRUE))
    }

    cohort_schema <- NULL
    for (s in schemas)
      if (length(ohdsi_discover_cohort_tables(s)) > 0) { cohort_schema <- s; break }
    if (is.null(cohort_schema)) {
      # clear a previously auto-loaded materialised cohort if its schema is gone
      if (startsWith(run_signature_rv(), "materialised|")) {
        cohort_result_rv(NULL); run_signature_rv(""); run_status_rv("empty")
      }
      return(invisible(FALSE))
    }
    sig <- paste0("materialised|", cohort_schema)
    if (!is.null(cohort_result_rv()) &&
        identical(run_status_rv(), "fresh") &&
        identical(run_signature_rv(), sig))
      return(invisible(TRUE))
    res <- load_materialised_cohort(cohort_schema)
    if (is.null(res)) return(invisible(FALSE))
    cohort_result_rv(res)
    def <- read_cohort_definition(cohort_schema)
    if (!is.null(def) && isTRUE(def$ok) && length(def$criteria) > 0) {
      # The export persisted the definition: restore it so the orphan, attrition
      # and index diagnostics work. Keep the loaded members and set the signature
      # from the restored definition so the next pass cache-hits as a definition
      # cohort instead of needlessly re-running build_cohort_sql.
      criteria_rv(def$criteria)
      prior_obs_days_rv(def$prior_obs_days)
      min_followup_days_rv(def$min_followup_days)
      updateSelectInput(session, "index_strategy", selected = def$index_strategy)
      if (!is.null(def$cohort_name))
        updateTextInput(session, "cohort_name", value = def$cohort_name)
      def_sig <- paste0(
        serialise_cohort_def(criteria = def$criteria, cohort_name = "sig",
          index_strategy    = def$index_strategy %||% "first_qualifying",
          prior_obs_days    = def$prior_obs_days,
          min_followup_days = def$min_followup_days),
        "|schemas=", paste(sort(schemas), collapse = ","))
      run_signature_rv(def_sig)
      run_status_rv("fresh")
      showNotification(sprintf("Loaded cohort and its definition from %s: %s persons.",
                               cohort_schema, format(nrow(res), big.mark = ",")),
                       type = "message", duration = 5)
      return(invisible(TRUE))
    }
    run_signature_rv(sig)
    run_status_rv("fresh")
    showNotification(sprintf("Loaded cohort from %s: %s persons.",
                             cohort_schema, format(nrow(res), big.mark = ",")),
                     type = "message", duration = 4)
    invisible(TRUE)
  }

  # v11: mark a definition-backed result stale when its definition changes.
  # Materialised cohorts (no inclusion criteria) are never flagged stale here.
  observe({
    sig <- cohort_signature()
    isolate({
      inc <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())
      if (length(inc) > 0 &&
          !is.null(cohort_result_rv()) &&
          !identical(run_status_rv(), "running") &&
          !identical(sig, run_signature_rv()))
        run_status_rv("stale")
    })
  })

  # v11: when entering a result-dependent tab, materialise the cohort if needed.
  observeEvent(input$main_tabs, {
    if (input$main_tabs %in% c("tab_validate", "tab_char",
                               "tab_survival", "tab_attrition", "tab_cox",
                               "tab_trt"))
      ensure_cohort_run()
  }, ignoreInit = TRUE)

  # SQL-tab Run button (unchanged UX)
  observeEvent(input$run_cohort_btn, {
    run_cohort_core()
  })

  # Build-tab "Preview SQL" button - reveal the inline SQL panel (v11: SQL folded in)
  observeEvent(input$build_preview_sql_btn, {
    session$sendCustomMessage("cb_open_sql", list())
  })
  # SQL panel lives in a collapsed <details>; keep it rendered so it is ready when opened.
  outputOptions(output, "sql_panel_ui", suspendWhenHidden = FALSE)

  # Build-tab "Run cohort" button - run then navigate to Results
  observeEvent(input$build_run_cohort_btn, {
    run_cohort_core()
  })

  # ── v11: PERSISTENT CONTEXT BAR ───────────────────────────────────────────
  # Surfaces the cohort context (dataset + CDM version + vocab status, cohort
  # name, N, run-status, plain-English definition) on every tab, plus a global
  # Run/Re-run control. Reads only existing reactives; additive, no nav change.
  output$context_bar <- renderUI({
    schemas <- input$schema_select %||% character(0)
    chip <- function(txt, col, bg)
      tags$span(style = sprintf(
        "background:%s;color:%s;border-radius:6px;padding:2px 9px;font-size:0.78rem;font-weight:600;white-space:nowrap;",
        bg, col), txt)

    if (length(schemas) == 0)
      return(div(class = "ctx-bar",
        div(class = "ctx-seg", icon("database"),
            tags$span(style = "color:var(--dre-muted);",
                      "No dataset selected - choose one in the sidebar to begin"))))

    # Dataset: name(s), CDM version, vocab status (worst-case across schemas)
    profiles <- schema_profile_rv()
    sp_list  <- Filter(Negate(is.null), lapply(schemas, function(s) profiles[[s]]))
    if (length(sp_list) > 0) {
      cvs <- unique(vapply(sp_list, function(p) p$cdm_version %||% "unknown", character(1)))
      cvs <- cvs[cvs != "unknown" & !is.na(cvs)]
      cdm_label <- if (length(cvs)) paste("CDM", paste(cvs, collapse = " / ")) else "CDM version unknown"
      rank  <- c(green = 1L, amber = 2L, red = 3L)
      anc   <- vapply(sp_list, function(p) p$ancestor_status %||% "red", character(1))
      worst <- names(which.max(rank[anc])); if (length(worst) == 0) worst <- "red"
      voc_col <- c(green = "var(--dre-success)", amber = "var(--dre-gold)", red = "var(--dre-error)")[[worst]]
      voc_lbl <- c(green = "vocab ok", amber = "vocab sparse", red = "no vocab")[[worst]]
      voc_chip <- tags$span(
        style = sprintf("color:%s;font-size:0.8rem;display:inline-flex;align-items:center;gap:5px;", voc_col),
        tags$span(style = sprintf("width:7px;height:7px;border-radius:50%%;background:%s;display:inline-block;", voc_col)),
        voc_lbl)
    } else {
      cdm_label <- "checking dataset\u2026"; voc_chip <- NULL
    }
    ds_name <- if (length(schemas) == 1) schemas[1] else sprintf("%d datasets", length(schemas))
    dataset_seg <- div(class = "ctx-seg", icon("database"),
      tags$span(style = "font-weight:600;", ds_name),
      tags$span(style = "color:var(--dre-muted);font-size:0.82rem;", cdm_label),
      voc_chip)

    # Cohort: name, N, run-status
    res  <- cohort_result_rv()
    st   <- run_status_rv()
    materialised <- startsWith(run_signature_rv(), "materialised|")
    inc  <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())
    nm   <- trimws(input$cohort_name %||% "")
    if (materialised && !nzchar(nm)) nm <- sub("^materialised\\|", "", run_signature_rv())
    if (!nzchar(nm)) nm <- if (length(inc) > 0) "Untitled cohort" else "No cohort"
    has_res <- !is.null(res) && nrow(res) > 0
    status_chip <-
      if (identical(st, "running")) chip("running\u2026", "var(--dre-gold)", "var(--dre-mid)")
      else if (identical(st, "stale")) chip("stale", "var(--dre-gold)", "var(--dre-mid)")
      else if (materialised && has_res) chip("imported", "var(--dre-teal)", "var(--dre-teal-dim)")
      else if (has_res) chip("ready", "var(--dre-success)", "var(--dre-mid)")
      else NULL
    cohort_seg <- div(class = "ctx-seg", icon("users"),
      tags$span(style = "font-weight:600;max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;", nm),
      if (has_res) tags$span(style = "font-weight:700;color:var(--dre-teal);", format(nrow(res), big.mark = ",")),
      if (has_res) tags$span(style = "color:var(--dre-muted);font-size:0.8rem;", "persons"),
      status_chip)

    # Definition summary
    desc <- if (length(inc) > 0)
      tryCatch(plain_english(criteria_rv(), concept_names = concept_names_rv()),
               error = function(e) NULL)
    else if (materialised) "Imported cohort - members only, no stored definition."
    else NULL
    def_seg <- if (!is.null(desc) && nzchar(desc))
      div(class = "ctx-seg ctx-def", icon("pen-to-square"),
          tags$span(style = "color:var(--dre-muted);", desc)) else NULL

    # Global run control (definition cohorts that are unrun or stale)
    run_btn <- if (length(inc) > 0 && st %in% c("empty", "stale"))
      actionButton("ctx_run_cohort",
        tagList(icon(if (identical(st, "stale")) "rotate" else "play"),
                if (identical(st, "stale")) " Re-run" else " Run cohort"),
        class = "btn-sm ctx-run") else NULL

    div(class = "ctx-bar",
      dataset_seg,
      div(class = "ctx-divider"),
      cohort_seg,
      if (!is.null(def_seg)) div(class = "ctx-divider"),
      def_seg,
      div(style = "flex:1 1 auto;min-width:8px;"),
      run_btn)
  })

  observeEvent(input$ctx_run_cohort, {
    run_cohort_core(navigate_to_results = FALSE)
  })

  # ──────────────────────────────────────────────────────────────────────────
  # RESULTS TAB
  # ──────────────────────────────────────────────────────────────────────────

  output$results_next_steps_ui <- renderUI({
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) return(NULL)
    n <- nrow(res)
    div(class = "next-steps-panel",
      div(class = "nsp-title", icon("circle-check"), " Cohort ready - ", format(n, big.mark=","), " patients"),
      tags$p(style = "font-size:0.93rem;color:var(--dre-text);margin:8px 0 12px;",
        "Your cohort has been built. Here is what you can do next:"),
      div(class = "nsp-actions",
        div(class = "nsp-action",
          icon("chart-bar"), tags$b(" Review demographics"),
          tags$p("See the age and sex breakdown below.")
        ),
        div(class = "nsp-action",
          icon("filter"), tags$b(" Check attrition"),
          tags$p("Use the Attrition tab to see how many patients each criterion removes.")
        ),
        div(class = "nsp-action",
          icon("download"), tags$b(" Export cohort"),
          tags$p("Save to the database or download as CSV from the Export tab.")
        ),
        div(class = "nsp-action",
          icon("code"), tags$b(" Analyse in R / Python"),
          tags$p("Open RStudio or JupyterLab in this workspace and load your cohort by name.")
        )
      )
    )
  })

  # ════════════════════════════════════════════════════════════════════════
  #  CHARACTERISATION TAB
  # ════════════════════════════════════════════════════════════════════════

  observeEvent(input$run_char_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first (SQL tab).", type = "warning")
      return()
    }
    req(conn_valid())

    # Multi-schema aware: iterate over every selected schema, query each with
    # its own col_map and the slice of persons that came from that schema,
    # then bind results tagged with source_schema. For single-schema or when
    # cohort_result has no source_schema column, this collapses to a single
    # iteration and the downstream renderers behave as before.
    schemas    <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi      <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res)

    cohort_by_schema <- if (multi) {
      split(res, res$source_schema)
    } else {
      setNames(list(res), schemas[[1]] %||% "")
    }

    char_rv(list(state = "running"))

    withProgress(message = "Running characterisation...", value = 0, {

      # Runs one domain across all schemas, binds results, pools counts by
      # concept so the pct column always reflects cohort-wide prevalence.
      run_domain <- function(domain_key, top_n, progress, label) {
        setProgress(progress, detail = label)
        per_schema <- lapply(names(cohort_by_schema), function(sch) {
          cm   <- col_maps_l[[sch]] %||% omop_col_map_rv()
          pids <- unique(as_pid(cohort_by_schema[[sch]]$person_id))
          df   <- tryCatch(
            query_comorbidity_profile(sch, cm, pids, domain_key, top_n),
            error = function(e) NULL)
          if (!is.null(df) && nrow(df) > 0) df$source_schema <- sch
          df
        })
        bound <- do.call(rbind, Filter(Negate(is.null), per_schema))
        if (is.null(bound) || nrow(bound) == 0) return(NULL)
        if (!multi) return(bound)

        # Pool: aggregate on concept_id across schemas, recompute pct against
        # full cohort N. concept_name / label pulled from the first schema
        # that resolved a name for that concept (post-vocab-check this is
        # expected to be consistent).
        bound$concept_id <- as.character(bound$concept_id)
        n_cohort         <- nrow(res)
        agg <- aggregate(n_persons ~ concept_id, data = bound, FUN = sum)
        # Preserve the first label and concept_name per concept_id
        first_label <- tapply(as.character(bound$label),
                              bound$concept_id, function(x) x[[1]])
        agg$label        <- first_label[as.character(agg$concept_id)]
        agg$pct          <- 100 * agg$n_persons / n_cohort
        agg$n_cohort     <- n_cohort
        agg$concept_name <- agg$label
        agg <- agg[order(-agg$n_persons), ]
        head(agg, top_n)
      }

      cond_df  <- run_domain("condition",   20L, 0.05, "Conditions...")
      drug_df  <- run_domain("drug",        20L, 0.20, "Medications...")
      proc_df  <- run_domain("procedure",   15L, 0.35, "Procedures...")
      visit_df <- run_domain("visit",       10L, 0.50, "Visits...")

      # Measurement distribution: facet-friendly - keep source_schema.
      # Per-schema query_measurement_dist returns either numeric-mode
      # (with `value` column) or frequency-mode (without). Mixing the two
      # would break rbind, so coerce to a single mode across schemas: if
      # any schema has numeric, use only those; otherwise fall back to
      # frequency. The mode attribute is preserved on the final df for
      # the renderer.
      setProgress(0.65, detail = "Lab values...")
      meas_err <- NULL
      meas_per_schema <- Filter(Negate(is.null), lapply(
        names(cohort_by_schema), function(sch) {
          cm   <- col_maps_l[[sch]] %||% omop_col_map_rv()
          pids <- unique(as_pid(cohort_by_schema[[sch]]$person_id))
          df <- tryCatch(
            query_measurement_dist(sch, cm, pids, 8L),
            error = function(e) { meas_err <<- e$message; NULL })
          if (!is.null(df) && nrow(df) > 0) df$source_schema <- sch
          df
        }))
      meas_per_schema <- Filter(function(d) !is.null(d) && nrow(d) > 0, meas_per_schema)
      meas_df <- if (length(meas_per_schema) == 0) NULL else {
        modes <- vapply(meas_per_schema,
                        function(d) attr(d, "mode") %||% "frequency",
                        character(1))
        # Prefer numeric; if any schema has numeric, keep only those.
        chosen <- if ("numeric" %in% modes) {
          meas_per_schema[modes == "numeric"]
        } else {
          meas_per_schema
        }
        # Re-check column alignment defensively - if two dfs at the same
        # mode somehow differ in columns, intersect column names so rbind
        # succeeds. Set the mode attribute on the final df.
        if (length(chosen) > 1) {
          common_cols <- Reduce(intersect, lapply(chosen, names))
          chosen <- lapply(chosen, function(d) d[, common_cols, drop = FALSE])
        }
        out <- do.call(rbind, chosen)
        attr(out, "mode") <- if ("numeric" %in% modes) "numeric" else "frequency"
        message("[meas_dist] combined ", length(chosen), " schema(s) in '",
                attr(out, "mode"), "' mode")
        out
      }

      setProgress(0.80, detail = "Follow-up time...")
      fu_df <- do.call(rbind, Filter(Negate(is.null), lapply(
        names(cohort_by_schema), function(sch) {
          cm <- col_maps_l[[sch]] %||% omop_col_map_rv()
          df <- tryCatch(
            query_followup_dist(sch, cm, cohort_by_schema[[sch]]),
            error = function(e) NULL)
          if (!is.null(df) && nrow(df) > 0) df$source_schema <- sch
          df
        })))

      setProgress(0.90, detail = "Charlson CCI...")
      cci_df <- do.call(rbind, Filter(Negate(is.null), lapply(
        names(cohort_by_schema), function(sch) {
          cm   <- col_maps_l[[sch]] %||% omop_col_map_rv()
          pids <- unique(as_pid(cohort_by_schema[[sch]]$person_id))
          df <- tryCatch(
            compute_cci(sch, cm, pids),
            error = function(e) NULL)
          if (!is.null(df) && nrow(df) > 0) df$source_schema <- sch
          df
        })))

      setProgress(1.0, detail = "Done")
      char_rv(list(
        state       = "done",
        condition   = cond_df,
        drug        = drug_df,
        procedure   = proc_df,
        visit       = visit_df,
        meas        = meas_df,
        meas_err    = meas_err,
        followup    = fu_df,
        cci         = cci_df,
        n_persons   = nrow(res),
        n_by_schema = if (multi) as.list(table(res$source_schema)) else NULL,
        multi       = multi,
        schemas     = schemas
      ))
    })
  })

  output$char_status_ui <- renderUI({
    cr <- char_rv()
    if (is.null(cr)) return(NULL)
    if (identical(cr$state, "running"))
      return(div(style = "color:var(--dre-muted);font-size:0.87rem;margin-top:8px;",
                 icon("spinner"), " Running..."))
    if (identical(cr$state, "done")) {
      non_null <- sum(sapply(cr[c("condition","drug","procedure","visit","meas","followup","cci")],
                             Negate(is.null)))
      meas_note <- if (is.null(cr$meas)) {
        reason <- if (!is.null(cr$meas_err)) cr$meas_err
                  else "No numeric values found in measurement table (value_as_number may be NULL for all rows, or the column may not exist). Check server logs for [meas_dist] diagnostics."
        div(style="color:#FFB84D;font-size:0.82rem;margin-top:4px;",
            icon("triangle-exclamation"), " Lab distributions: ", reason)
      } else NULL
      tagList(
        div(style = "color:var(--dre-success);font-size:0.87rem;margin-top:8px;",
          icon("circle-check"),
          sprintf(" Characterisation complete - %s persons, %d data sources populated.",
                  format(cr$n_persons, big.mark=","), non_null)
        ),
        meas_note
      )
    }
    NULL
  })

  # ── Helper: standard comorbidity bar chart ──────────────────────────────────
  make_comorbidity_plot <- function(df, n_cohort, schemas = NULL) {
    if (is.null(df) || nrow(df) == 0)
      return(ggplot2::ggplot() +
        ggplot2::annotate("text", x=0.5, y=0.5,
          label="No data - run characterisation", colour="#8BA3B5", size=4) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA)))

    df$label_short <- ifelse(nchar(df$label) > 42,
                             paste0(substr(df$label,1,39),"..."), df$label)
    df$label_short <- factor(df$label_short, levels=df$label_short[order(df$n_persons)])

    # Subtitle calls out multi-schema pooling so the reader knows the
    # percentages are combined across schemas.
    subtitle <- if (is.character(schemas) && length(schemas) > 1) {
      paste0("Pooled across ", length(schemas), " schemas: ",
             paste(schemas, collapse = ", "))
    } else NULL

    ggplot2::ggplot(df, ggplot2::aes(x=label_short, y=pct)) +
      ggplot2::geom_col(fill="#00C5B5", width=0.72) +
      ggplot2::geom_text(ggplot2::aes(
        label=sprintf("%s  %.1f%%", format(n_persons,big.mark=","), pct)),
        hjust=-0.06, colour="#E8F4F8", size=3.8) +
      ggplot2::scale_y_continuous(
        labels=function(x) paste0(x,"%"),
        limits=c(0, max(df$pct, na.rm=TRUE)*1.28)) +
      ggplot2::coord_flip() +
      ggplot2::labs(x=NULL,
                    y=paste0("% of cohort (N=",format(n_cohort,big.mark=","),")"),
                    subtitle = subtitle) +
      theme_dre()
  }

  # ── Condition plot ──────────────────────────────────────────────────────────
  output$char_condition_plot <- renderPlot({
    cr <- char_rv()
    make_comorbidity_plot(cr$condition %||% NULL, cr$n_persons %||% 0L,
                          if (isTRUE(cr$multi)) cr$schemas else NULL)
  }, res = PLOT_RES, bg="#0B2341")

  # ── Drug plot ───────────────────────────────────────────────────────────────
  output$char_drug_plot <- renderPlot({
    cr <- char_rv()
    make_comorbidity_plot(cr$drug %||% NULL, cr$n_persons %||% 0L,
                          if (isTRUE(cr$multi)) cr$schemas else NULL)
  }, res = PLOT_RES, bg="#0B2341")

  # ── Procedure plot ──────────────────────────────────────────────────────────
  output$char_procedure_plot <- renderPlot({
    cr <- char_rv()
    make_comorbidity_plot(cr$procedure %||% NULL, cr$n_persons %||% 0L,
                          if (isTRUE(cr$multi)) cr$schemas else NULL)
  }, res = PLOT_RES, bg="#0B2341")

  # ── Visit plot ──────────────────────────────────────────────────────────────
  output$char_visit_plot <- renderPlot({
    cr <- char_rv()
    make_comorbidity_plot(cr$visit %||% NULL, cr$n_persons %||% 0L,
                          if (isTRUE(cr$multi)) cr$schemas else NULL)
  }, res = PLOT_RES, bg="#0B2341")

  # ── Follow-up distribution plot + stats ────────────────────────────────────
  output$followup_stats_ui <- renderUI({
    cr <- char_rv()
    fu_df <- cr$followup
    if (is.null(fu_df) || nrow(fu_df) == 0) return(NULL)
    fu <- as.numeric(fu_df$days)
    fu <- fu[!is.na(fu) & fu >= 0]
    if (length(fu) == 0) return(NULL)
    div(class = "char-stat-row",
      div(class = "char-stat",
        div(class = "char-stat-val", sprintf("%.0f", median(fu))),
        div(class = "char-stat-lab", "Median days")),
      div(class = "char-stat",
        div(class = "char-stat-val",
            sprintf("%.0f-%.0f", quantile(fu,0.25), quantile(fu,0.75))),
        div(class = "char-stat-lab", "IQR")),
      div(class = "char-stat",
        div(class = "char-stat-val", sprintf("%.0f", mean(fu))),
        div(class = "char-stat-lab", "Mean days")),
      div(class = "char-stat",
        div(class = "char-stat-val",
            paste0(round(100*mean(fu >= 365)), "%")),
        div(class = "char-stat-lab", "≥1 year follow-up"))
    )
  })

  followup_plot_obj <- reactive({
    cr <- char_rv()
    fu_df <- cr$followup
    if (is.null(fu_df) || nrow(fu_df) == 0)
      return(ggplot2::ggplot() +
        ggplot2::annotate("text",x=0.5,y=0.5,label="No follow-up data",
          colour="#8BA3B5",size=4) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA)))

    fu <- as.numeric(fu_df$days)
    fu <- fu[!is.na(fu) & fu >= 0]
    df <- data.frame(days = fu)

    # Bin width: ~30 bins across range
    bw <- max(1, round(diff(range(fu)) / 30))

    ggplot2::ggplot(df, ggplot2::aes(x=days)) +
      ggplot2::geom_histogram(binwidth=bw, fill="#00C5B5", colour="#0B2341", linewidth=0.2) +
      ggplot2::geom_vline(xintercept=median(fu), colour="#FFB84D",
                          linewidth=0.8, linetype="dashed") +
      ggplot2::annotate("text", x=median(fu), y=Inf,
                        label=sprintf(" median
 %d d", as.integer(median(fu))),
                        colour="#FFB84D", hjust=0, vjust=1.3, size=3.8) +
      ggplot2::scale_x_continuous(labels=function(x) format(x,big.mark=",")) +
      ggplot2::scale_y_continuous(labels=function(x) format(x,big.mark=",")) +
      ggplot2::labs(x="Days of follow-up", y="Persons") +
      theme_dre()
  })
  output$followup_plot <- renderPlot(followup_plot_obj(),
                                      res = PLOT_RES, bg="#0B2341")

  .followup_code <- function() {
    cr <- char_rv()
    if (is.null(cr) || is.null(cr$followup) || nrow(cr$followup) == 0)
      return("# Run characterisation first to generate a follow-up code snippet.")
    cohort_block <- .cohort_sql_block()
    if (is.null(cohort_block))
      return("# Cohort SQL not available - build at least one inclusion criterion first.")

    cohort_nm <- input$cohort_name %||% "my_cohort"
    schemas   <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi     <- length(schemas) > 1

    # Per-schema followup query template (concrete column names baked in)
    .schema_query <- function(sch) {
      cm <- col_maps_l[[sch]] %||% omop_col_map_rv()
      pid_col <- ac(cm, "observation_period", "person_id")
      end_col <- ac(cm, "observation_period", "observation_period_end_date")
      sprintf(
'-- Per-person follow-up time = days from index_date to last observation
WITH idx(person_id, index_date) AS (VALUES %%s)
SELECT (MAX(op.%s::date) - i.index_date)::int AS days
FROM   "%s"."observation_period" op
JOIN   idx i ON i.person_id = op.%s
WHERE  op.%s::date >= i.index_date
GROUP  BY i.person_id, i.index_date',
        end_col, sch, pid_col, end_col)
    }

    header <- sprintf(paste0(
      "# ──────────────────────────────────────────────────────────────────────\n",
      "# Follow-up time distribution\n",
      "# Cohort:    %s\n",
      "# Schemas:   %s\n",
      "# Generated: %s\n",
      "#\n",
      "# Self-contained: builds the cohort, computes per-person follow-up\n",
      "# days from observation_period, and plots the histogram.\n",
      "# ──────────────────────────────────────────────────────────────────────\n"),
      cohort_nm,
      paste(schemas, collapse = ", "),
      format(Sys.time(), "%Y-%m-%d %H:%M:%S"))

    if (multi) {
      query_lines <- vapply(schemas, function(sch) {
        sprintf('  %s = r"---(%s)---"', deparse(sch), .schema_query(sch))
      }, character(1))
      chart_body <- sprintf('
# ── 3. Compute follow-up days per person, per schema ─────────────────────
library(ggplot2)

queries <- list(
%s
)

per_schema_fu <- lapply(names(queries), function(sch) {
  sub <- cohort_result[cohort_result$source_schema == sch, , drop = FALSE]
  if (nrow(sub) == 0) return(NULL)
  vals <- paste(
    sprintf("(%%.0f, \'%%s\'::date)",
            as.numeric(sub$person_id),
            as.character(as.Date(sub$index_date))),
    collapse = ", ")
  sql <- sprintf(queries[[sch]], vals)
  r <- DBI::dbGetQuery(xap.conn, sql)
  if (is.null(r) || nrow(r) == 0) return(NULL)
  names(r) <- tolower(names(r))
  r$source_schema <- sch
  r
})
followup_df <- do.call(rbind, per_schema_fu)
',
        paste(query_lines, collapse = ",\n"))
    } else {
      chart_body <- sprintf('
