  chart_register("followup", "Follow-up time distribution",
                 plot_fn = followup_plot_obj,
                 code_fn = .followup_code,
                 width = 10, height = 6)

  # ── CCI plot ────────────────────────────────────────────────────────────────
  cci_plot_obj <- reactive({
    cr  <- char_rv()
    cci <- cr$cci
    if (is.null(cci) || nrow(cci) == 0)
      return(ggplot2::ggplot() +
        ggplot2::annotate("text",x=0.5,y=0.5,label="No CCI data - run characterisation",
          colour="#8BA3B5",size=4) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA)))

    # Colour scale: green → amber → red by severity
    pal <- c("0 (None)"="#3DD68C",
             "1 (Low)"="#00C5B5",
             "2 (Moderate)"="#FFB84D",
             "3 (High)"="#E07050",
             "4+ (Very high)"="#E05C6E")

    multi <- isTRUE(cr$multi) && "source_schema" %in% names(cci) &&
             length(unique(cci$source_schema)) > 1

    if (multi) {
      # Per-schema breakdown: grouped bars so population differences are visible
      # rather than hidden in a pooled percentage.
      cci_df <- as.data.frame(
        table(category = cci$cci_category, source_schema = cci$source_schema))
      # Percentage within each schema (denominator = that schema's N)
      tot_by_sch <- tapply(cci_df$Freq, cci_df$source_schema, sum)
      cci_df$pct <- 100 * cci_df$Freq / tot_by_sch[as.character(cci_df$source_schema)]
      # Per-facet max for label placement decision: bars above 70% of facet
      # max get labels INSIDE the bar (otherwise they clip off the top).
      facet_max <- tapply(cci_df$pct, cci_df$source_schema, max, na.rm = TRUE)
      cci_df$label_inside <- cci_df$pct > 0.7 *
        facet_max[as.character(cci_df$source_schema)]
      cci_df$label_y <- ifelse(cci_df$label_inside,
                                cci_df$pct * 0.5,   # mid-bar
                                cci_df$pct + 2)     # just above bar
      cci_df$label_colour <- ifelse(cci_df$label_inside,
                                     "#0B2341",     # dark on bright bar
                                     "#E8F4F8")     # light on background
      cci_df$label_vjust <- ifelse(cci_df$label_inside, 0.5, 0)

      ggplot2::ggplot(cci_df,
        ggplot2::aes(x=category, y=pct, fill=category)) +
        ggplot2::geom_col(width=0.7, show.legend=FALSE,
                          position=ggplot2::position_dodge2(preserve="single")) +
        ggplot2::facet_wrap(~ source_schema, ncol = 1, scales = "free_y") +
        ggplot2::geom_text(ggplot2::aes(
          y = label_y,
          vjust = label_vjust,
          colour = label_colour,
          label = sprintf("%s\n%.1f%%", format(Freq, big.mark=","), pct)),
          size = 3.2, show.legend = FALSE) +
        ggplot2::scale_fill_manual(values = pal) +
        ggplot2::scale_colour_identity() +
        ggplot2::scale_y_continuous(
          labels = function(x) paste0(x, "%"),
          expand = ggplot2::expansion(mult = c(0, 0.15))) +
        ggplot2::labs(x = "CCI Score", y = "% within schema",
                      subtitle = "Per-schema CCI distribution (denominators are schema N)") +
        theme_dre() +
        ggplot2::theme(axis.text.x = ggplot2::element_text(size = 11),
                       strip.text  = ggplot2::element_text(size = 12, face = "bold"))
    } else {
      n_total <- nrow(cci)
      cat_df  <- as.data.frame(table(category = cci$cci_category))
      cat_df$pct  <- 100 * cat_df$Freq / n_total
      cat_df$fill <- pal[as.character(cat_df$category)]
      cat_df$fill[is.na(cat_df$fill)] <- "#8BA3B5"

      ggplot2::ggplot(cat_df, ggplot2::aes(x=category, y=pct, fill=category)) +
        ggplot2::geom_col(width=0.7, show.legend=FALSE) +
        ggplot2::geom_text(ggplot2::aes(
          label=sprintf("%s\n%.1f%%", format(Freq,big.mark=","), pct)),
          vjust=-0.3, colour="#E8F4F8", size=3.8) +
        ggplot2::scale_fill_manual(values=pal) +
        ggplot2::scale_y_continuous(labels=function(x) paste0(x,"%"),
                                     limits=c(0, max(cat_df$pct, na.rm=TRUE)*1.25)) +
        ggplot2::labs(x="CCI Score", y="% of cohort") +
        theme_dre() +
        ggplot2::theme(axis.text.x=ggplot2::element_text(size=11))
    }
  })
  output$cci_plot <- renderPlot(cci_plot_obj(), res = PLOT_RES, bg = "#0B2341")

  .cci_code <- function() {
    cr <- char_rv()
    if (is.null(cr) || is.null(cr$cci) || nrow(cr$cci) == 0)
      return("# Run characterisation first to generate a CCI code snippet.")
    cohort_block <- .cohort_sql_block()
    if (is.null(cohort_block))
      return("# Cohort SQL not available - build at least one inclusion criterion first.")

    schemas <- input$schema_select %||% character(0)
    cohort_nm <- input$cohort_name %||% "my_cohort"
    col_maps_l <- col_maps_rv()
    multi <- length(schemas) > 1

    # Per-schema condition_occurrence query template
    .schema_query <- function(sch) {
      cm <- col_maps_l[[sch]] %||% omop_col_map_rv()
      pid_col <- ac(cm, "condition_occurrence", "person_id")
      cid_col <- ac(cm, "condition_occurrence", "condition_concept_id")
      sprintf(
'SELECT DISTINCT %s AS person_id, %s AS concept_id
 FROM   "%s"."condition_occurrence"
 WHERE  %s IN (%%s)         -- cohort person_ids placeholder
   AND  %s IN (%%s)',
        pid_col, cid_col, sch, pid_col, cid_col)
    }

    header <- sprintf(paste0(
      "# ──────────────────────────────────────────────────────────────────────\n",
      "# Charlson Comorbidity Index (Quan 2005 implementation)\n",
      "# Cohort:    %s\n",
      "# Schemas:   %s\n",
      "# Generated: %s\n",
      "#\n",
      "# Self-contained: builds the cohort, computes per-person CCI scores\n",
      "# from condition_occurrence using Quan-OMOP concept IDs, and plots\n",
      "# the per-schema score distribution.\n",
      "# ──────────────────────────────────────────────────────────────────────\n"),
      cohort_nm,
      paste(schemas, collapse = ", "),
      format(Sys.time(), "%Y-%m-%d %H:%M:%S"))

    if (multi) {
      query_lines <- vapply(schemas, function(sch) {
        sprintf('  %s = r"---(%s)---"', deparse(sch), .schema_query(sch))
      }, character(1))
      query_block <- sprintf("queries <- list(\n%s\n)",
                              paste(query_lines, collapse = ",\n"))
      per_schema_loop <- '
per_schema_cci <- lapply(names(queries), function(sch) {
  sub_pids <- unique(cohort_result$person_id[
    cohort_result$source_schema == sch])
  if (length(sub_pids) == 0) return(NULL)
  ids_sql <- paste(sprintf("%.0f", as.numeric(sub_pids)), collapse = ", ")
  sql <- sprintf(queries[[sch]], ids_sql, cci_ids_sql)
  pts <- DBI::dbGetQuery(xap.conn, sql)
  if (nrow(pts) == 0) {
    return(data.frame(person_id = sub_pids, cci_score = 0L,
                      source_schema = sch))
  }
  names(pts) <- tolower(names(pts))
  score_one_schema(pts, sub_pids, sch)
})
cci <- do.call(rbind, per_schema_cci)
'
    } else {
      query_block <- sprintf('single_query <- r"---(%s)---"', .schema_query(schemas[1]))
      per_schema_loop <- sprintf('
ids_sql <- paste(sprintf("%%.0f", as.numeric(cohort_result$person_id)),
                 collapse = ", ")
sql <- sprintf(single_query, ids_sql, cci_ids_sql)
pts <- DBI::dbGetQuery(xap.conn, sql)
names(pts) <- tolower(names(pts))
cci <- score_one_schema(pts, cohort_result$person_id, "%s")
', schemas[1])
    }

    chart_body <- sprintf('
# ── 3. CCI definition (Quan 2005, OMOP/SNOMED concept IDs) ───────────────
library(ggplot2)

cci_map <- list(
  list(name = "MI",                  w = 1, ids = c(4329847, 314666, 312327)),
  list(name = "Congestive heart failure", w = 1, ids = c(316139, 4229440)),
  list(name = "Peripheral vascular disease", w = 1, ids = c(321596, 4108564)),
  list(name = "CVA",                 w = 1, ids = c(372924, 375557, 443454)),
  list(name = "Dementia",            w = 1, ids = c(4182210, 378419, 373192)),
  list(name = "COPD",                w = 1, ids = c(255573, 4274024)),
  list(name = "Rheumatic disease",   w = 1, ids = c(80809, 257628, 134442)),
  list(name = "Peptic ulcer",        w = 1, ids = c(4027663, 40481087)),
  list(name = "Mild liver disease",  w = 1, ids = c(4064161, 4212540)),
  list(name = "Diabetes (uncomplicated)", w = 1, ids = c(201820, 442793)),
  list(name = "Diabetes (complicated)",   w = 2, ids = c(201826, 4099651)),
  list(name = "Hemiplegia",          w = 2, ids = c(4291005, 432284)),
  list(name = "Renal disease",       w = 2, ids = c(46271022, 4030518, 443919)),
  list(name = "Cancer",              w = 2, ids = c(443392, 4248385, 4112853, 4029524, 4212540)),
  list(name = "Moderate/severe liver disease", w = 3, ids = c(4245975, 196454, 57345)),
  list(name = "Metastatic cancer",   w = 6, ids = c(432851, 4212448)),
  list(name = "AIDS/HIV",            w = 6, ids = c(439727, 4159981))
)
all_cci_ids <- unique(unlist(lapply(cci_map, `[[`, "ids")))
cci_ids_sql <- paste(sprintf("%%.0f", all_cci_ids), collapse = ", ")

# Helper: take a (person_id, concept_id) result set, return per-person score
score_one_schema <- function(pts, person_ids, schema_name) {
  score_tbl <- data.frame(person_id = unique(person_ids),
                          cci_score = 0L,
                          source_schema = schema_name,
                          stringsAsFactors = FALSE)
  for (cat in cci_map) {
    hit <- unique(pts$person_id[pts$concept_id %%in%% cat$ids])
    if (length(hit) > 0) {
      idx <- score_tbl$person_id %%in%% hit
      score_tbl$cci_score[idx] <- score_tbl$cci_score[idx] + cat$w
    }
  }
  score_tbl$cci_category <- cut(
    score_tbl$cci_score,
    breaks = c(-Inf, 0, 1, 2, 3, Inf),
    labels = c("0 (None)", "1 (Low)", "2 (Moderate)",
               "3 (High)", "4+ (Very high)"),
    right = TRUE)
  score_tbl
}

# ── 4. Query condition_occurrence per schema, score, combine ─────────────
%s

%s
', query_block, per_schema_loop)

    plot_body <- '
