cci_df$label_vjust  <- ifelse(cci_df$label_inside, 0.5, 0)

ggplot(cci_df, aes(x = category, y = pct, fill = category)) +
  geom_col(width = 0.7, show.legend = FALSE) +
  facet_wrap(~ source_schema, ncol = 1, scales = "free_y") +
