                 width = 10, height = 8)

  # ── Measurement distribution (boxplots) ────────────────────────────────────
  output$char_meas_plot <- renderPlot({
    cr      <- char_rv()
    meas_df <- cr$meas
    if (is.null(meas_df) || nrow(meas_df) == 0)
      return(ggplot2::ggplot() +
        ggplot2::annotate("text", x=0.5, y=0.5,
          label="No measurement data found", colour="#8BA3B5", size=4) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA)))

    mode <- attr(meas_df, "mode") %||% "numeric"
    multi <- isTRUE(cr$multi) && "source_schema" %in% names(meas_df) &&
             length(unique(meas_df$source_schema)) > 1

    if (mode == "frequency") {
      # ── Frequency bar chart (VALUE_AS_NUMBER unpopulated in this dataset) ──
      # Bug 5 fix (v8.6): use distinct-patient count (n_persons) for the
      # percentage, not record count (n). One patient with 200 measurements
      # contributes 1 to n_persons but 200 to n; the latter trivially exceeds
      # 100% of the cohort. Fall back to n if n_persons missing (older results
      # may not have it).
      n_field <- if ("n_persons" %in% names(meas_df)) "n_persons" else "n"
      if (multi) {
        # Sum counts by concept across schemas, pct against total cohort N
        agg <- aggregate(meas_df[[n_field]] ~ label, data = meas_df, FUN = sum)
        names(agg)[2] <- "n"
        n_cohort <- cr$n_persons %||% 1L
        agg$pct <- pmin(100, 100 * agg$n / n_cohort)
        agg$label_ord <- factor(agg$label, levels = agg$label[order(agg$n)])
        ggplot2::ggplot(agg, ggplot2::aes(x = label_ord, y = pct)) +
          ggplot2::geom_col(fill = "#00C5B5", width = 0.72) +
          ggplot2::geom_text(ggplot2::aes(
            label = sprintf("%s  %.1f%%", format(n, big.mark = ","), pct)),
            hjust = -0.06, colour = "#E8F4F8", size = 3.8) +
          ggplot2::scale_y_continuous(
            labels = function(x) paste0(x, "%"),
            limits = c(0, max(agg$pct, na.rm = TRUE) * 1.28)) +
          ggplot2::coord_flip() +
          ggplot2::labs(
            x = NULL,
            y = paste0("% of cohort with at least one record (N=",
                       format(n_cohort, big.mark = ","), ")"),
            subtitle = paste0("Pooled across ", length(unique(meas_df$source_schema)), " schemas"),
            caption = "Note: numeric values not recorded - showing measurement frequency") +
          theme_dre()
      } else {
        n_cohort <- cr$n_persons %||% 1L
        meas_df$pct_n     <- meas_df[[n_field]]
        meas_df$pct       <- pmin(100, 100 * meas_df$pct_n / n_cohort)
        meas_df$label_ord <- factor(meas_df$label,
                                     levels = meas_df$label[order(meas_df$pct_n)])
        ggplot2::ggplot(meas_df, ggplot2::aes(x = label_ord, y = pct)) +
          ggplot2::geom_col(fill = "#00C5B5", width = 0.72) +
          ggplot2::geom_text(ggplot2::aes(
            label = sprintf("%s  %.1f%%", format(pct_n, big.mark = ","), pct)),
            hjust = -0.06, colour = "#E8F4F8", size = 3.8) +
          ggplot2::scale_y_continuous(
            labels = function(x) paste0(x, "%"),
            limits = c(0, max(meas_df$pct, na.rm = TRUE) * 1.28)) +
          ggplot2::coord_flip() +
          ggplot2::labs(
            x = NULL,
            y = paste0("% of cohort with at least one record (N=",
                       format(n_cohort, big.mark = ","), ")"),
            caption = "Note: numeric values not recorded for this dataset - showing measurement frequency") +
          theme_dre()
      }

    } else {
      # ── Box plots (numeric values present) ─────────────────────────────────
      # When multi-schema, colour boxes by source_schema so unit/range
      # differences between datasets are immediately visible.
      meas_clip <- do.call(rbind, lapply(
        split(meas_df, meas_df$label), function(d) {
          q <- quantile(d$value, c(0.01, 0.99), na.rm=TRUE)
          d$value_clipped <- pmax(pmin(d$value, q[2]), q[1])
          d
        }))
      med_order <- tapply(meas_clip$value_clipped, meas_clip$label, median, na.rm=TRUE)
      meas_clip$label <- factor(meas_clip$label,
                                 levels=names(sort(med_order, decreasing=TRUE)))

      if (multi) {
        ggplot2::ggplot(meas_clip,
          ggplot2::aes(x = label, y = value_clipped, fill = source_schema)) +
          ggplot2::geom_boxplot(
            colour = "#00C5B5", outlier.colour = "#8BA3B5",
            outlier.size = 0.6, linewidth = 0.5,
            position = ggplot2::position_dodge(preserve = "single")) +
          ggplot2::coord_flip() +
          ggplot2::facet_wrap(~ label, scales = "free", ncol = 2) +
          ggplot2::labs(x = NULL, y = "Value (1st-99th percentile)",
                        fill = "Schema",
                        subtitle = "Values shown per schema to expose unit/range differences") +
          theme_dre() +
          ggplot2::theme(
            strip.text  = ggplot2::element_text(colour="#E8F4F8", size=11),
            axis.text.y = ggplot2::element_blank(),
            panel.spacing = ggplot2::unit(0.6, "lines"))
      } else {
        ggplot2::ggplot(meas_clip, ggplot2::aes(x=label, y=value_clipped)) +
          ggplot2::geom_boxplot(
            fill="#133660", colour="#00C5B5", outlier.colour="#8BA3B5",
            outlier.size=0.6, linewidth=0.5) +
          ggplot2::coord_flip() +
          ggplot2::facet_wrap(~label, scales="free", ncol=2) +
          ggplot2::labs(x=NULL, y="Value (1st-99th percentile)") +
          theme_dre() +
          ggplot2::theme(
            strip.text  = ggplot2::element_text(colour="#E8F4F8", size=11),
            axis.text.y = ggplot2::element_blank(),
            panel.spacing = ggplot2::unit(0.6, "lines"))
      }
    }
  }, res = PLOT_RES, bg="#0B2341")

