  # ── VALIDATE TAB (v11): orphan-concept scan ───────────────────────────────
  # Reads the index event concept set from the current definition and lists
  # related concepts that have records here but are not captured. Manual run
  # (button) to avoid surprise queries, matching the count-preview model.
  # v11: cohort run-state line on the Validate tab.
  output$validate_cohort_state <- renderUI({
    state_line <- function(col, ic, txt)
      tags$div(style = sprintf("font-size:0.9rem;color:%s;margin:2px 0 0;", col),
               ic, " ", txt)
    st  <- run_status_rv()
    res <- cohort_result_rv()
    inc <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())
    materialised <- startsWith(run_signature_rv(), "materialised|")
    src <- if (materialised)
      sprintf(" (loaded from %s)", sub("^materialised\\|", "", run_signature_rv())) else ""

    if (identical(st, "running"))
      return(state_line("var(--dre-muted)", icon("spinner"), "Materialising the cohort\u2026"))
    if (identical(st, "stale"))
      return(state_line("var(--dre-warning, #e0a800)", icon("triangle-exclamation"),
        "Definition changed since the last run. Re-run the cohort to refresh the result."))
    if (!is.null(res) && nrow(res) > 0)
      return(state_line("var(--dre-success, #2ea043)", icon("circle-check"),
        sprintf("Cohort ready: %s persons.%s", format(nrow(res), big.mark = ","), src)))
    if (length(inc) == 0)
      return(state_line("var(--dre-muted)", icon("circle-info"),
        "No cohort yet. Build a definition in Build Cohort, or select a schema that contains a cohort table."))
    if (!is.null(res))
      return(state_line("var(--dre-muted)", icon("circle"),
        "Cohort ran: 0 persons match this definition."))
    state_line("var(--dre-muted)", icon("circle-info"),
      "Cohort not run yet. It materialises when you open this tab.")
  })

  # v11: cohort overview metric cards (works for any loaded cohort).
  output$validate_overview_ui <- renderUI({
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) return(NULL)
    ov <- query_cohort_overview(res, input$schema_select %||% character(0),
                                col_maps_rv(), multi = isTRUE(multi_mode_rv()))
    if (is.null(ov)) return(NULL)
    box <- function(val, lab) div(class = "metric-box",
      div(class = "metric-val", val), div(class = "metric-lab", lab))
    div(style = "margin-top:12px;",
      fluidRow(
        column(3, box(format(ov$n, big.mark = ","), "Persons")),
        column(3, box(if (is.na(ov$pct_female)) "n/a" else paste0(ov$pct_female, "%"),
                      "Female")),
        column(3, box(if (is.na(ov$median_age)) "n/a" else ov$median_age,
                      "Median age at index")),
        column(3, box(if (is.na(ov$median_fu_y)) "n/a" else paste0(ov$median_fu_y, " yr"),
                      "Median follow-up"))
      ))
  })

  # v11: sequential attrition (manual run; multiple cohort builds, so behind a button).
  output$validate_attrition_status <- renderUI({ validate_attrition_status_rv() })

  observeEvent(input$validate_run_attrition, {
    validate_attrition_rv(NULL); validate_attrition_status_rv(NULL)
    mk <- function(...) tags$div(style = "font-size:0.87rem;color:var(--dre-muted);padding:6px 0;", ...)
    schema <- primary_schema(input$schema_select %||% character(0))
    if (is.null(schema) || !nzchar(schema)) {
      validate_attrition_status_rv(mk(icon("triangle-exclamation"), " Select a dataset first."))
      return(invisible(NULL))
    }
    inc <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())
    if (length(inc) == 0) {
      validate_attrition_status_rv(mk(icon("circle-info"),
        if (startsWith(run_signature_rv(), "materialised|"))
          " Attrition detail was not stored with this imported cohort; only the final count is available (shown above). Build a definition to see the full waterfall."
        else " Add criteria in Build Cohort first."))
      return(invisible(NULL))
    }
    col_map <- col_maps_rv()[[schema]] %||% omop_col_map_rv()
    df <- tryCatch(query_sequential_attrition(schema, criteria_rv(), col_map,
            cohort_name       = input$cohort_name %||% "cohort",
            index_strategy    = input$index_strategy %||% "first_qualifying",
            prior_obs_days    = prior_obs_days_rv(),
            min_followup_days = min_followup_days_rv()),
            error = function(e) { message("[attrition] ", conditionMessage(e)); NULL })
    if (is.null(df) || nrow(df) == 0) {
      validate_attrition_status_rv(mk(icon("circle-info"), " Could not compute attrition."))
      return(invisible(NULL))
    }
    if (length(input$schema_select %||% character(0)) > 1)
      validate_attrition_status_rv(mk(icon("circle-info"),
        sprintf(" Shown for the primary schema (%s).", schema)))
    validate_attrition_rv(df)
  })

  output$validate_attrition_ui <- renderUI({
    df <- validate_attrition_rv()
    if (is.null(df) || nrow(df) == 0)
      return(tags$div(style = "font-size:0.85rem;color:var(--dre-muted);padding:4px 0;",
        "Click Compute attrition to see how each criterion narrows the cohort."))
    maxn <- suppressWarnings(max(df$n, na.rm = TRUE))
    if (!is.finite(maxn) || maxn <= 0) maxn <- 1
    rows <- lapply(seq_len(nrow(df)), function(i) {
      n <- df$n[i]; w <- if (is.na(n)) 0L else as.integer(round(100 * n / maxn))
      final <- i == nrow(df); rem <- df$removed[i]
      div(style = "display:flex;align-items:center;gap:10px;margin-bottom:6px;font-size:0.86rem;",
        div(style = "width:240px;flex-shrink:0;color:var(--dre-text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;",
            df$label[i]),
        div(style = "flex:1;background:var(--dre-mid);border-radius:4px;height:18px;min-width:40px;",
          div(style = sprintf("width:%d%%;height:100%%;border-radius:4px;background:%s;",
              w, if (final) "var(--dre-teal)" else "var(--dre-teal-dim)"))),
        div(style = sprintf("width:62px;text-align:right;flex-shrink:0;%s",
            if (final) "font-weight:700;color:var(--dre-teal);" else "color:var(--dre-text);"),
          if (is.na(n)) "n/a" else format(n, big.mark = ",")),
        div(style = "width:64px;text-align:right;flex-shrink:0;font-size:0.78rem;color:var(--dre-error);",
          if (!is.na(rem) && rem > 0) sprintf("-%s", format(rem, big.mark = ",")) else ""))
    })
    div(style = "margin-top:4px;", rows)
  })

  # v11: index-event breakdown (manual run; VALUES-join query, behind a button).
  output$validate_index_status <- renderUI({ validate_index_status_rv() })

  observeEvent(input$validate_run_index, {
    validate_index_rv(NULL); validate_index_status_rv(NULL)
    mk <- function(...) tags$div(style = "font-size:0.87rem;color:var(--dre-muted);padding:6px 0;", ...)
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      validate_index_status_rv(mk(icon("circle-info"),
        " No cohort loaded. Open a result tab or run a cohort first."))
      return(invisible(NULL))
    }
    schema <- primary_schema(input$schema_select %||% character(0))
    if (is.null(schema) || !nzchar(schema)) {
      validate_index_status_rv(mk(icon("triangle-exclamation"), " Select a dataset first."))
      return(invisible(NULL))
    }
    col_map <- col_maps_rv()[[schema]] %||% omop_col_map_rv()
    inc <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())
    dk <- NULL; cids <- integer(0); ud <- FALSE
    if (length(inc) > 0) {
      dk   <- inc[[1]]$domain
      cids <- as.integer(inc[[1]]$concept_ids %||% integer(0))
      ud   <- isTRUE(inc[[1]]$use_descendants)
    }
    df <- tryCatch(query_index_breakdown(schema, col_map, res, domain_key = dk,
            concept_ids = cids, use_descendants = ud, top_n = 15L),
            error = function(e) { message("[index] ", conditionMessage(e)); NULL })
    if (is.null(df) || nrow(df) == 0) {
      validate_index_status_rv(mk(icon("circle-info"), " No concepts found on the index dates."))
      return(invisible(NULL))
    }
    if (is.null(dk))
      validate_index_status_rv(mk(icon("circle-info"),
        " Reconstructed from the data (no stored index concept set). A person can have several concepts on the index date, so shares may exceed 100%."))
    validate_index_rv(df)
  })

  output$validate_index_ui <- renderUI({
    df <- validate_index_rv()
    if (is.null(df) || nrow(df) == 0)
      return(tags$div(style = "font-size:0.85rem;color:var(--dre-muted);padding:4px 0;",
        "Click Show breakdown to see what concepts triggered entry."))
    show_dom <- "domain" %in% names(df) && length(unique(df$domain)) > 1
    rows <- lapply(seq_len(nrow(df)), function(i) {
      pct <- df$pct[i]; w <- if (is.na(pct)) 0L else as.integer(min(100, max(0, pct)))
      nm  <- df$concept_name[i]; if (is.na(nm) || !nzchar(nm)) nm <- paste("concept", df$concept_id[i])
      label <- if (show_dom) sprintf("%s  \u00b7  %s", nm, df$domain[i]) else nm
      div(style = "margin-bottom:7px;font-size:0.86rem;",
        div(style = "display:flex;justify-content:space-between;gap:10px;margin-bottom:3px;",
          tags$span(style = "overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:var(--dre-text);", label),
          tags$span(style = "color:var(--dre-muted);flex-shrink:0;",
                    sprintf("%s%% (%s)", pct, format(df$n_persons[i], big.mark = ",")))),
        div(style = "height:6px;background:var(--dre-mid);border-radius:3px;",
          div(style = sprintf("width:%d%%;height:100%%;background:var(--dre-teal-dim);border-radius:3px;", w))))
    })
    div(rows)
  })

  # v11: AIRA phenotype review (synchronous; gathers diagnostics, calls the model).
  output$validate_aira_status <- renderUI({ validate_aira_status_rv() })

  observeEvent(input$validate_run_aira, {
    validate_aira_rv(NULL); validate_aira_status_rv(NULL)
    mk <- function(...) tags$div(style = "font-size:0.87rem;color:var(--dre-muted);padding:6px 0;", ...)
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      validate_aira_status_rv(mk(icon("circle-info"), " No cohort loaded yet."))
      return(invisible(NULL))
    }
    schema  <- primary_schema(input$schema_select %||% character(0))
    col_map <- col_maps_rv()[[schema]] %||% omop_col_map_rv()
    materialised <- startsWith(run_signature_rv(), "materialised|")
    inc  <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())
    defn <- if (length(inc) > 0)
      tryCatch(plain_english(criteria_rv(), concept_names = concept_names_rv()),
               error = function(e) NULL) else NULL
    ov <- tryCatch(query_cohort_overview(res, input$schema_select %||% character(0),
            col_maps_rv(), multi = isTRUE(multi_mode_rv())), error = function(e) NULL)
    diag <- list(
      cohort_name     = trimws(input$cohort_name %||% ""),
      is_imported     = materialised,
      definition      = defn %||% (if (materialised)
                          "Imported cohort (members only, no stored definition)" else "(none)"),
      n_persons       = nrow(res),
      pct_female      = if (is.null(ov)) NA else ov$pct_female,
      median_age      = if (is.null(ov)) NA else ov$median_age,
      median_fu_y     = if (is.null(ov)) NA else ov$median_fu_y,
      attrition       = validate_attrition_rv(),
      index_breakdown = validate_index_rv(),
      orphans         = validate_orphan_rv()
    )
    result <- withProgress(message = "AIRA is reviewing the cohort\u2026", value = 0.5, {
      aira_phenotype_review(diag)
    })
    if (is.null(result) || !identical(result$status, "ok")) {
      reason <- (result$reason %||% result$status) %||% "unavailable"
      validate_aira_status_rv(mk(icon("triangle-exclamation"),
        sprintf(" Review unavailable (%s). Check that AIRA is enabled for this workspace.", reason)))
      return(invisible(NULL))
    }
    validate_aira_rv(result$content)
  })

  output$validate_aira_ui <- renderUI({
    txt <- validate_aira_rv()
    if (is.null(txt) || !nzchar(txt))
      return(tags$div(style = "font-size:0.85rem;color:var(--dre-muted);padding:4px 0;",
        "Run review to get an AI critique of this cohort, grounded in the diagnostics above."))
    body <- tryCatch(shiny::markdown(txt),
                     error = function(e) tags$pre(style = "white-space:pre-wrap;", txt))
    div(class = "plain-english-box",
      div(style = "font-size:0.8rem;color:var(--dre-muted);margin-bottom:8px;",
        icon("robot"),
        " Generated by AIRA. Only aggregate counts were sent; verify cited concept IDs before acting."),
      body)
  })

  # Standards code check (CodelistGenerator). Validates the definition's concept
  # set against the database directly (no Achilles needed), via the get_cdm
  # adapter. Works on a definition cohort; imported cohorts have no concept set.
  output$validate_codeuse_status <- renderUI({ validate_codeuse_status_rv() })

  observeEvent(input$validate_run_codeuse, {
    validate_codeuse_rv(NULL); validate_codeuse_status_rv(NULL)
    mk <- function(...) tags$div(style = "font-size:0.87rem;color:var(--dre-muted);padding:6px 0;", ...)
    if (!ohdsi_pkgs_available() || !requireNamespace("CodelistGenerator", quietly = TRUE)) {
      validate_codeuse_status_rv(mk(icon("triangle-exclamation"),
        " The OHDSI standards packages are not available in this workspace."))
      return(invisible(NULL))
    }
    crit <- criteria_rv()
    has_concepts <- any(vapply(crit,
      function(c) length(c$concept_ids %||% integer(0)) > 0, logical(1)))
    if (!has_concepts) {
      validate_codeuse_status_rv(mk(icon("circle-info"),
        " This cohort references no concept sets to check. Imported cohorts store members only, not a definition."))
      return(invisible(NULL))
    }
    schema  <- primary_schema(input$schema_select %||% character(0))
    col_map <- col_maps_rv()[[schema]] %||% omop_col_map_rv()
    codelist <- tryCatch(build_definition_codelist(schema, col_map, crit),
                         error = function(e) NULL)
    if (is.null(codelist) || length(codelist) == 0) {
      validate_codeuse_status_rv(mk(icon("circle-info"),
        " No concepts resolved from the definition."))
      return(invisible(NULL))
    }
    res <- withProgress(message = "Checking concept-set code use against the database\u2026",
                        value = 0.4, {
      cdm <- get_cdm(schema)
      if (is.null(cdm)) NULL
      else tryCatch(
        CodelistGenerator::summariseCodeUse(codelist, cdm = cdm,
                                            countBy = c("record", "person")),
        error = function(e) {
          message("[codeuse] summariseCodeUse failed: ", conditionMessage(e)); NULL })
    })
    if (is.null(res)) {
      validate_codeuse_status_rv(mk(icon("triangle-exclamation"),
        " Could not build a CDMConnector reference or summarise code use for this schema. See the app log."))
      return(invisible(NULL))
    }
    nrows <- tryCatch(nrow(res), error = function(e) 0L)
    if (is.null(nrows) || nrows == 0) {
      validate_codeuse_status_rv(mk(icon("circle-info"),
        " None of the definition's concepts have records in this database."))
      return(invisible(NULL))
    }
    validate_codeuse_rv(res)
  })

  output$validate_codeuse_tbl <- ohdsi_table_render(validate_codeuse_rv, "code_use")

  output$validate_orphan_context <- renderUI({
    inc <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())
    if (length(inc) == 0) {
      if (startsWith(run_signature_rv(), "materialised|"))
        return(tags$div(style = "font-size:0.85rem;color:var(--dre-muted);margin-bottom:6px;",
          icon("circle-info"),
          " This cohort was imported from a schema, which stores its members but not its concept set, so the orphan scan does not apply. Orphan detection runs on cohorts built from a definition."))
      return(tags$div(style = "font-size:0.85rem;color:var(--dre-muted);margin-bottom:6px;",
        icon("circle-info"), " Define an index event in Build Cohort first, then run the scan."))
    }
    idx <- inc[[1]]
    dom <- DOMAINS[[idx$domain]]
    n   <- length(as.integer(idx$concept_ids %||% integer(0)))
    tags$div(style = "font-size:0.85rem;color:var(--dre-muted);margin-bottom:6px;",
      sprintf("Scans the index event: %s, %d concept%s%s.",
              dom$label %||% idx$domain, n, if (n == 1) "" else "s",
              if (isTRUE(idx$use_descendants)) ", descendants on" else ""))
  })

  output$validate_orphan_status <- renderUI({ validate_orphan_status_rv() })

  observeEvent(input$validate_run_orphans, {
    validate_orphan_rv(NULL)
    validate_orphan_status_rv(NULL)
    mk <- function(...) tags$div(style = "font-size:0.87rem;color:var(--dre-muted);padding:6px 0;", ...)

    schema <- primary_schema(input$schema_select %||% character(0))
    if (is.null(schema) || !nzchar(schema)) {
      validate_orphan_status_rv(mk(icon("triangle-exclamation"), " Select a dataset first."))
      return(invisible(NULL))
    }
    inc <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())
    if (length(inc) == 0) {
      validate_orphan_status_rv(mk(icon("circle-info"),
        if (startsWith(run_signature_rv(), "materialised|"))
          " Not available for imported cohorts: the concept set was not stored with the cohort. Build a definition to scan for orphans."
        else " Add an index event in Build Cohort first."))
      return(invisible(NULL))
    }
    idx  <- inc[[1]]
    cids <- as.integer(idx$concept_ids %||% integer(0))
    if (length(cids) == 0) {
      validate_orphan_status_rv(mk(icon("circle-info"),
        " Your index event matches any concept, so there is no concept set to scan. Add specific concepts to it first."))
      return(invisible(NULL))
    }

    col_map <- col_maps_rv()[[schema]] %||% omop_col_map_rv()
    res <- tryCatch(
      query_orphan_concepts(schema, col_map, cids, idx$domain,
                            use_descendants = isTRUE(idx$use_descendants),
                            top_n = 50L),
      error = function(e) {
        message("[validate] orphan scan failed: ", conditionMessage(e)); NULL
      })

    if (is.null(res) || nrow(res) == 0) {
      has_ca <- "concept_ancestor" %in% tryCatch(tolower(get_tables(schema)),
                                                 error = function(e) character(0))
      validate_orphan_status_rv(mk(
        if (!has_ca)
          tagList(icon("circle-info"),
            " This dataset has no concept_ancestor table, so orphan detection is unavailable. This is expected on source-vocabulary-only schemas (e.g. MIMIC).")
        else
          tagList(icon("circle-check"),
            " No orphan concepts found. Your definition already captures the related codes that have records here.")))
      return(invisible(NULL))
    }

    validate_orphan_status_rv(mk(
      sprintf("%d candidate concept%s with records, ranked by persons. ",
              nrow(res), if (nrow(res) == 1) "" else "s"),
      "A descendant is usually a code to add; an ancestor is broader, so add it only deliberately."))
    validate_orphan_rv(res)
  })

  output$validate_orphan_dt <- DT::renderDataTable({
    res <- validate_orphan_rv()
    if (is.null(res) || nrow(res) == 0)
      return(DT::datatable(
        data.frame(Message = "Run the orphan scan to see candidate concepts your definition does not capture."),
        filter = "none", options = list(dom = "t"), rownames = FALSE))
    disp <- data.frame(
      Concept      = res$concept_name,
      `Concept ID` = res$concept_id,
      Vocabulary   = res$vocabulary_id,
      Code         = res$concept_code,
      Standard     = res$standard_concept,
      Relationship = res$relationship,
      Persons      = res$n_persons,
      Records      = res$n_records,
      check.names  = FALSE, stringsAsFactors = FALSE)
    DT::datatable(disp,
      filter    = "none",
      rownames  = FALSE,
      selection = "multiple",
      class     = "cell-border stripe",
      options   = list(
        pageLength = 25,
        scrollX    = TRUE,
        order      = list(list(6, "desc")),
        dom        = "lfrtip"))
  })

  # v11: add selected orphan concepts to the index event concept set.
  observeEvent(input$validate_add_orphans, {
    sel <- input$validate_orphan_dt_rows_selected
    res <- validate_orphan_rv()
    if (is.null(res) || length(sel) == 0) {
      showNotification("Select one or more orphan rows first.", type = "message", duration = 3)
      return()
    }
    add_ids   <- as.integer(res$concept_id[sel])
    add_names <- as.character(res$concept_name[sel])
    crits   <- criteria_rv()
    inc_idx <- which(vapply(crits, function(c) identical(c$type, "inclusion"), logical(1)))
    if (length(inc_idx) == 0) {
      showNotification("No index event to add to. Build one in Build Cohort first.", type = "warning")
      return()
    }
    i      <- inc_idx[1]
    before <- as.integer(crits[[i]]$concept_ids %||% integer(0))
    crits[[i]]$concept_ids <- sort(unique(c(before, add_ids)))
    criteria_rv(crits)
    cn <- concept_names_rv()
    for (k in seq_along(add_ids)) cn[[as.character(add_ids[k])]] <- add_names[k]
    concept_names_rv(cn)
    n_new <- length(setdiff(add_ids, before))
    showNotification(sprintf("Added %d concept%s to the index event. Re-run to refresh the cohort.",
                             n_new, if (n_new == 1) "" else "s"), type = "message", duration = 4)
  })

  # Demographics breakdown
  output$demo_gender_ui <- renderUI({
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0 || !conn_valid())
      return(tags$p(style = "color:#8b949e;", "Run query to see demographics."))

    schemas    <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi      <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res)

    cohort_by_schema <- if (multi) split(res, res$source_schema)
                       else setNames(list(res), schemas[[1]] %||% "")

    # Query each schema's person table with its own col_map and pid slice,
    # then aggregate gender counts across schemas.
    gd_list <- lapply(names(cohort_by_schema), function(sch) {
      cm      <- col_maps_l[[sch]] %||% omop_col_map_rv()
      sub     <- cohort_by_schema[[sch]]
      pid_col <- ac(cm, "person", "person_id")
      gcol    <- ac(cm, "person", "gender_concept_id")
      ids_sql <- pid_sql(sub$person_id)
      sql <- sprintf(
        "SELECT CASE %s WHEN 8507 THEN 'Male' WHEN 8532 THEN 'Female' ELSE 'Other/Unknown' END AS gender,
                COUNT(*) AS n
         FROM   %s WHERE %s IN (%s) GROUP BY 1 ORDER BY n DESC",
        gcol, fq(sch, "person"), pid_col, ids_sql)
      tryCatch(db_query(sql), error = function(e) NULL)
    })
    gd_all <- do.call(rbind, Filter(Negate(is.null), gd_list))
    if (is.null(gd_all) || nrow(gd_all) == 0)
      return(tags$p(style = "color:#8b949e;", "Could not load gender breakdown."))

    gd    <- aggregate(n ~ gender, data = gd_all, FUN = sum)
    gd    <- gd[order(-gd$n), ]
    total <- sum(gd$n)
    div(
      tags$h5(style = "color:var(--dre-teal);font-size:12px;margin-bottom:10px;",
              if (multi) paste0("Gender (", length(cohort_by_schema), " schemas pooled)")
              else "Gender"),
      lapply(seq_len(nrow(gd)), function(i) {
        pct <- round(100 * gd$n[i] / total)
        div(class = "attrition-step",
          div(class = "attrition-label", gd$gender[i]),
          div(class = "attrition-bar-bg",
            div(class = "attrition-bar-fill",
                style = sprintf("width:%d%%;", pct),
                if (pct > 8) paste0(pct, "%") else "")),
          div(class = "attrition-count", format(gd$n[i], big.mark = ","))
        )
      })
    )
  })

  output$demo_age_ui <- renderUI({
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0 || !conn_valid())
      return(NULL)

    # Need index_date to compute age
    if (!"index_date" %in% names(res))
      return(tags$p(style = "color:#8b949e;", "No index_date in results."))

    schemas    <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi      <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res)

    cohort_by_schema <- if (multi) split(res, res$source_schema)
                       else setNames(list(res), schemas[[1]] %||% "")

    # Run one (schema, col_map, index-dates) query per schema, then bind.
    ad_list <- lapply(names(cohort_by_schema), function(sch) {
      cm      <- col_maps_l[[sch]] %||% omop_col_map_rv()
      sub     <- cohort_by_schema[[sch]]
      pid_col <- ac(cm, "person",  "person_id")
      yob_col <- ac(cm, "person",  "year_of_birth")
      tmp_values <- paste(
        sprintf("(%.0f, '%s'::date)", as_pid(sub$person_id),
                as.character(as.Date(sub$index_date))),
        collapse = ", ")
      sql <- sprintf(
        "WITH idx(person_id, index_date) AS (VALUES %s)
         SELECT CASE
           WHEN age < 18  THEN '0-17'
           WHEN age < 30  THEN '18-29'
           WHEN age < 45  THEN '30-44'
           WHEN age < 60  THEN '45-59'
           WHEN age < 75  THEN '60-74'
           ELSE                '75+' END AS age_group,
           COUNT(*) AS n,
           MIN(age)  AS min_age
         FROM (
           SELECT EXTRACT(YEAR FROM i.index_date) - p.%s AS age
           FROM   %s p JOIN idx i ON i.person_id = p.%s
         ) t
         GROUP BY 1",
        tmp_values, yob_col, fq(sch, "person"), pid_col)
      tryCatch(db_query(sql), error = function(e) NULL)
    })
    ad_all <- do.call(rbind, Filter(Negate(is.null), ad_list))
    if (is.null(ad_all) || nrow(ad_all) == 0)
      return(tags$p(style = "color:#8b949e;", "Could not load age breakdown."))

    # Pool counts by band, preserve band ordering via min_age
    ad_n  <- aggregate(n       ~ age_group, data = ad_all, FUN = sum)
    ad_mi <- aggregate(min_age ~ age_group, data = ad_all, FUN = min)
    ad    <- merge(ad_n, ad_mi, by = "age_group")
    ad    <- ad[order(ad$min_age), ]
    total <- sum(ad$n)
    div(
      tags$h5(style = "color:var(--dre-teal);font-size:12px;margin-bottom:10px;",
              if (multi) paste0("Age at Index Date (", length(cohort_by_schema), " schemas pooled)")
              else "Age at Index Date"),
      lapply(seq_len(nrow(ad)), function(i) {
        pct <- round(100 * ad$n[i] / total)
        div(class = "attrition-step",
          div(class = "attrition-label", ad$age_group[i]),
          div(class = "attrition-bar-bg",
            div(class = "attrition-bar-fill",
                style = sprintf("width:%d%%;", pct),
                if (pct > 8) paste0(pct, "%") else "")),
          div(class = "attrition-count", format(ad$n[i], big.mark = ","))
        )
      })
    )
  })

  # ── Index event timeline ────────────────────────────────────────────────────
  # The plot object is built in a reactive so it can be reused both by the
  # renderPlot output and by the chart-export registry (Save/Code buttons).
  timeline_plot_obj <- reactive({
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0 || !"index_date" %in% names(res))
      return(ggplot2::ggplot() +
               ggplot2::annotate("text", x=0.5, y=0.5,
                 label="Run the cohort query to see the timeline",
                 colour="#8BA3B5", size=4) +
               ggplot2::theme_void() +
               ggplot2::theme(plot.background = ggplot2::element_rect(fill="#0B2341", colour=NA)))

    gran <- input$timeline_granularity %||% "quarter"
    res2 <- res[!is.na(res$index_date), , drop = FALSE]
    if (nrow(res2) == 0) return(NULL)
    dates <- as.Date(res2$index_date)

    # Truncate dates to chosen granularity
    period <- switch(gran,
      year    = as.Date(format(dates, "%Y-01-01")),
      quarter = {
        yr <- as.integer(format(dates, "%Y"))
        qn <- ceiling(as.integer(format(dates, "%m")) / 3)
        as.Date(paste0(yr, "-", sprintf("%02d", (qn - 1) * 3 + 1), "-01"))
      },
      month   = as.Date(format(dates, "%Y-%m-01"))
    )

    multi <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res2) &&
             length(unique(res2$source_schema)) > 1

    gran_label <- switch(gran, year = "Year", quarter = "Quarter", month = "Month")
    col_width  <- switch(gran, year = 250, quarter = 60, month = 20)

    if (multi) {
      # Stacked bars by schema so entry volume per schema is visible over time.
      # Loess smooth drawn once across the pooled total, in teal.
      df  <- as.data.frame(table(period = period, schema = res2$source_schema))
      df$period <- as.Date(as.character(df$period))
      df$Freq   <- as.integer(df$Freq)
      names(df)[names(df) == "schema"] <- "source_schema"

      tot_df <- aggregate(Freq ~ period, data = df, FUN = sum)

      smooth_layer <- if (nrow(tot_df) >= 6)
        ggplot2::geom_smooth(data = tot_df,
          ggplot2::aes(x = period, y = Freq),
          colour = "#FFB84D", se = FALSE, linewidth = 0.8,
          method = "loess", formula = y ~ x, inherit.aes = FALSE,
          span = max(0.6, 4 / nrow(tot_df)))
      else NULL

      ggplot2::ggplot(df,
        ggplot2::aes(x = period, y = Freq, fill = source_schema)) +
        ggplot2::geom_col(width = col_width) +
        smooth_layer +
        ggplot2::scale_y_continuous(labels = function(x) format(x, big.mark = ",")) +
        ggplot2::labs(x = gran_label, y = "Index events", fill = "Schema",
                      subtitle = "Stacked by source schema") +
        theme_dre()
    } else {
      df <- as.data.frame(table(period = period))
      df$period <- as.Date(as.character(df$period))
      df$Freq   <- as.integer(df$Freq)

      smooth_layer <- if (nrow(df) >= 6)
        ggplot2::geom_smooth(colour = "#FFB84D", se = FALSE, linewidth = 0.8,
                             method = "loess", formula = y ~ x,
                             span = max(0.6, 4 / nrow(df)))
      else NULL

      ggplot2::ggplot(df, ggplot2::aes(x = period, y = Freq)) +
        ggplot2::geom_col(fill = "#00C5B5", width = col_width) +
        smooth_layer +
        ggplot2::scale_y_continuous(labels = function(x) format(x, big.mark=",")) +
        ggplot2::labs(x = gran_label, y = "Index events") +
        theme_dre()
    }
  })
  output$timeline_plot <- renderPlot(timeline_plot_obj(),
                                      res = PLOT_RES, bg = "#0B2341")

  # Chart code generator: standalone R snippet that connects to the workspace
  # and reproduces this chart in a fresh R session.
  .timeline_code <- function() {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0)
      return("# Run the cohort query first to generate a code snippet for the index timeline.")
    cohort_block <- .cohort_sql_block()
    if (is.null(cohort_block))
      return("# Cohort SQL not available - build at least one inclusion criterion first.")
    schemas <- input$schema_select %||% character(0)
    multi <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res) &&
             length(unique(res$source_schema)) > 1
    gran <- input$timeline_granularity %||% "quarter"
    cohort_nm <- input$cohort_name %||% "my_cohort"
    header <- sprintf(paste0(
      "# ──────────────────────────────────────────────────────────────────────\n",
      "# Index event timeline\n",
      "# Cohort:    %s\n",
      "# Schemas:   %s\n",
      "# Mode:      %s\n",
      "# Generated: %s\n",
      "#\n",
      "# This script is self-contained: it connects to the workspace, runs\n",
      "# the cohort SQL, then produces the chart. Paste into RStudio in your\n",
      "# workspace and run end-to-end. Requires DBI, xaputils, ggplot2.\n",
      "# SQL dialect: workspace PostgreSQL.\n",
      "# ──────────────────────────────────────────────────────────────────────\n"),
      cohort_nm,
      paste(schemas, collapse = ", "),
      if (multi) "multi-schema (stacked by source_schema)" else "single-schema",
      format(Sys.time(), "%Y-%m-%d %H:%M:%S"))
    chart_body <- sprintf('
# ── 3. Build the timeline plot ───────────────────────────────────────────
library(ggplot2)

dates <- as.Date(cohort_result$index_date)
gran  <- "%s"   # "year" | "quarter" | "month"

period <- switch(gran,
  year    = as.Date(format(dates, "%%Y-01-01")),
  quarter = {
    yr <- as.integer(format(dates, "%%Y"))
    qn <- ceiling(as.integer(format(dates, "%%m")) / 3)
    as.Date(paste0(yr, "-", sprintf("%%02d", (qn - 1) * 3 + 1), "-01"))
  },
  month   = as.Date(format(dates, "%%Y-%%m-01"))
)
col_width <- switch(gran, year = 250, quarter = 60, month = 20)
gran_lbl  <- switch(gran, year = "Year", quarter = "Quarter", month = "Month")
', gran)
    chart_body <- if (multi)
      paste0(chart_body, '
# Multi-schema: stacked bars by source_schema
df <- as.data.frame(table(period = period, schema = cohort_result$source_schema))
df$period <- as.Date(as.character(df$period))
df$Freq   <- as.integer(df$Freq)
names(df)[names(df) == "schema"] <- "source_schema"

ggplot(df, aes(x = period, y = Freq, fill = source_schema)) +
  geom_col(width = col_width) +
  labs(x = gran_lbl, y = "Index events", fill = "Schema",
       subtitle = "Stacked by source schema") +
  theme_minimal()
')
    else
      paste0(chart_body, '
# Single-schema
df <- as.data.frame(table(period = period))
df$period <- as.Date(as.character(df$period))
df$Freq   <- as.integer(df$Freq)

ggplot(df, aes(x = period, y = Freq)) +
  geom_col(fill = "#00C5B5", width = col_width) +
  labs(x = gran_lbl, y = "Index events") +
  theme_minimal()
')
    paste0(header, cohort_block, chart_body)
  }

  chart_register("index_timeline", "Index event timeline",
                 plot_fn = timeline_plot_obj,
                 code_fn = .timeline_code,
                 width = 12, height = 6)

  # ── Comorbidity profile ─────────────────────────────────────────────────────
  # Recompute when domain selector changes OR new cohort result
  observe({
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0 || !conn_valid()) {
      comorbidity_rv(NULL); return()
    }
    domain_key <- input$comorbidity_domain %||% "condition"

    schemas    <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi      <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res)

    cohort_by_schema <- if (multi) split(res, res$source_schema)
                       else setNames(list(res), schemas[[1]] %||% "")

    per_schema <- lapply(names(cohort_by_schema), function(sch) {
      cm   <- col_maps_l[[sch]] %||% omop_col_map_rv()
      pids <- unique(as_pid(cohort_by_schema[[sch]]$person_id))
      df   <- tryCatch(
        query_comorbidity_profile(sch, cm, pids, domain_key, 15L),
        error = function(e) NULL)
      if (!is.null(df) && nrow(df) > 0) df$source_schema <- sch
      df
    })
    bound <- do.call(rbind, Filter(Negate(is.null), per_schema))

    if (is.null(bound) || nrow(bound) == 0) {
      comorbidity_rv(NULL); return()
    }

    if (multi) {
      bound$concept_id <- as.character(bound$concept_id)
      n_cohort <- nrow(res)
      agg <- aggregate(n_persons ~ concept_id, data = bound, FUN = sum)
      first_label <- tapply(as.character(bound$label),
                            bound$concept_id, function(x) x[[1]])
      agg$label        <- first_label[as.character(agg$concept_id)]
      agg$concept_name <- agg$label
      agg$pct          <- 100 * agg$n_persons / n_cohort
      agg$n_cohort     <- n_cohort
      agg <- agg[order(-agg$n_persons), ]
      comorbidity_rv(head(agg, 15L))
    } else {
      comorbidity_rv(bound)
    }
  }) |> bindEvent(cohort_result_rv(), input$comorbidity_domain, ignoreNULL = FALSE)

  comorbidity_plot_obj <- reactive({
    df <- comorbidity_rv()
    if (is.null(df) || nrow(df) == 0) {
      msg <- if (is.null(cohort_result_rv()) || nrow(cohort_result_rv() %||% data.frame()) == 0)
        "Run the cohort query to see the comorbidity profile"
      else "No data found for this domain"
      return(ggplot2::ggplot() +
               ggplot2::annotate("text", x=0.5, y=0.5, label=msg,
                 colour="#8BA3B5", size=4) +
               ggplot2::theme_void() +
               ggplot2::theme(plot.background = ggplot2::element_rect(fill="#0B2341", colour=NA)))
    }

    # Truncate long concept names
    df$label_short <- ifelse(nchar(df$label) > 45,
                             paste0(substr(df$label, 1, 42), "..."),
                             df$label)
    # Order by frequency
    df$label_short <- factor(df$label_short,
                              levels = df$label_short[order(df$n_persons)])

    n_cohort <- df$n_cohort[[1]]

    ggplot2::ggplot(df, ggplot2::aes(x = label_short, y = pct)) +
      ggplot2::geom_col(fill = "#00C5B5", width = 0.7) +
      ggplot2::geom_text(ggplot2::aes(
        label = sprintf("%s  %.1f%%", format(n_persons, big.mark=","), pct)),
        hjust = -0.08, colour = "#E8F4F8", size = 3) +
      ggplot2::scale_y_continuous(
        labels = function(x) paste0(x, "%"),
        limits = c(0, max(df$pct, na.rm=TRUE) * 1.25)) +
      ggplot2::coord_flip() +
      ggplot2::labs(x = NULL,
        y = paste0("% of cohort (N=", format(n_cohort, big.mark=","), ")")) +
      theme_dre()
  })
  output$comorbidity_plot <- renderPlot(comorbidity_plot_obj(),
                                         res = PLOT_RES, bg = "#0B2341")

  .comorbidity_code <- function() {
    df <- comorbidity_rv()
    if (is.null(df) || nrow(df) == 0)
      return("# Run the cohort query and view the comorbidity profile first.")
    cohort_block <- .cohort_sql_block()
    if (is.null(cohort_block))
      return("# Cohort SQL not available - build at least one inclusion criterion first.")

    domain_key <- input$comorbidity_domain %||% "condition"
    schemas    <- input$schema_select %||% character(0)
    cohort_nm  <- input$cohort_name %||% "my_cohort"
    dom        <- DOMAINS[[domain_key]]
    if (is.null(dom))
      return("# Invalid domain selection.")

    col_maps_l <- col_maps_rv()
    multi      <- length(schemas) > 1

    # Resolve table/column names per schema. Output a per-schema query
    # template ready for sprintf with the concrete column names baked in.
    .schema_query <- function(sch) {
      cm <- col_maps_l[[sch]] %||% omop_col_map_rv()
      pid_col <- ac(cm, dom$table, dom$person_col)
      cid_col <- ac(cm, dom$table, dom$concept_col)
      c_id    <- ac(cm, "concept", "concept_id")
      c_name  <- ac(cm, "concept", "concept_name")
      sprintf(
'SELECT t.%s::int AS concept_id,
        c.%s AS concept_name,
        COUNT(DISTINCT t.%s) AS n_persons
 FROM   "%s"."%s" t
 JOIN   "%s"."concept" c ON c.%s = t.%s
 WHERE  t.%s IN (%%s)        -- person_ids placeholder
   AND  t.%s > 0
 GROUP  BY 1, 2
 ORDER  BY 3 DESC
 LIMIT  15',
        cid_col, c_name, pid_col,
        sch, dom$table, sch, c_id, cid_col,
        pid_col, cid_col)
    }

    header <- sprintf(paste0(
      "# ──────────────────────────────────────────────────────────────────────\n",
      "# Comorbidity profile - top 15 concepts in cohort\n",
      "# Cohort:    %s\n",
      "# Schemas:   %s\n",
      "# Domain:    %s\n",
      "# Generated: %s\n",
      "#\n",
      "# Self-contained: builds the cohort, queries top concepts per schema,\n",
      "# combines, computes percent-of-cohort, and plots.\n",
      "# ──────────────────────────────────────────────────────────────────────\n"),
      cohort_nm,
      paste(schemas, collapse = ", "),
      dom$label %||% domain_key,
      format(Sys.time(), "%Y-%m-%d %H:%M:%S"))

    if (multi) {
      # Multi-schema: one query template per schema
      query_lines <- vapply(schemas, function(sch) {
        sprintf('  %s = r"---(%s)---"', deparse(sch), .schema_query(sch))
      }, character(1))
      chart_body <- sprintf('
# ── 3. Query top concepts per schema ─────────────────────────────────────
library(ggplot2)

# Per-schema query templates (concrete column names baked in)
queries <- list(
%s
)

# Run each per-schema query, scoped to that schema\'s cohort persons,
# then merge and compute percentages.
per_schema_dfs <- lapply(names(queries), function(sch) {
  sub_pids <- unique(cohort_result$person_id[
    cohort_result$source_schema == sch])
  if (length(sub_pids) == 0) return(NULL)
  ids_sql <- paste(sprintf("%%.0f", as.numeric(sub_pids)), collapse = ", ")
  sql <- sprintf(queries[[sch]], ids_sql)
  r <- DBI::dbGetQuery(xap.conn, sql)
  if (is.null(r) || nrow(r) == 0) return(NULL)
  names(r) <- tolower(names(r))
  r$source_schema <- sch
  r$n_cohort_sch <- length(sub_pids)
  r
})
freq_df <- do.call(rbind, per_schema_dfs)

# Aggregate across schemas: sum n_persons by concept; pct over whole cohort
comorbidity_df <- aggregate(n_persons ~ concept_id + concept_name,
                             data = freq_df, FUN = sum)
n_cohort <- nrow(cohort_result)
comorbidity_df$pct <- 100 * comorbidity_df$n_persons / n_cohort
comorbidity_df <- comorbidity_df[order(-comorbidity_df$pct), ]
comorbidity_df <- head(comorbidity_df, 15)
',
        paste(query_lines, collapse = ",\n"))
    } else {
      # Single schema
      chart_body <- sprintf('
# ── 3. Query top concepts ────────────────────────────────────────────────
library(ggplot2)

single_query <- r"---(%s)---"

ids_sql <- paste(sprintf("%%.0f", as.numeric(cohort_result$person_id)),
                 collapse = ", ")
sql <- sprintf(single_query, ids_sql)
freq_df <- DBI::dbGetQuery(xap.conn, sql)
names(freq_df) <- tolower(names(freq_df))

comorbidity_df <- freq_df
n_cohort <- nrow(cohort_result)
comorbidity_df$pct <- 100 * comorbidity_df$n_persons / n_cohort
comorbidity_df <- comorbidity_df[order(-comorbidity_df$pct), ]
',
        .schema_query(schemas[1]))
    }

    plot_body <- '
# ── 4. Plot ──────────────────────────────────────────────────────────────
comorbidity_df$concept_name <- factor(comorbidity_df$concept_name,
                                       levels = rev(comorbidity_df$concept_name))

ggplot(comorbidity_df, aes(x = concept_name, y = pct)) +
  geom_col(fill = "#00C5B5", width = 0.7) +
  geom_text(aes(label = sprintf("%s  %.1f%%",
                                 format(n_persons, big.mark = ","), pct)),
            hjust = -0.1, size = 3.4, colour = "#1A2530") +
  scale_y_continuous(labels = function(x) paste0(x, "%"),
                     limits = c(0, max(comorbidity_df$pct) * 1.25)) +
  coord_flip() +
  labs(x = NULL,
       y = paste0("% of cohort (N=", format(n_cohort, big.mark = ","), ")")) +
  theme_minimal()
'

    paste0(header, cohort_block, chart_body, plot_body)
  }

  chart_register("comorbidity", "Comorbidity profile (top concepts)",
                 plot_fn = comorbidity_plot_obj,
                 code_fn = .comorbidity_code,
                 width = 12, height = 8)

  # ── Table 1 ─────────────────────────────────────────────────────────────────
  observeEvent(input$build_table1_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type = "warning"); return()
    }
    schemas <- input$schema_select %||% character(0)
    cmaps   <- col_maps_rv()
    # If col_maps_rv hasn't been populated (edge case on fresh session), fall
    # back to wrapping the primary schema's col_map so the single-schema path
    # still finds a map.
    if (length(cmaps) == 0 && length(schemas) >= 1)
      cmaps <- setNames(list(omop_col_map_rv()), schemas[[1]])
    table1_rv(NULL)
    withProgress(message = "Building Table 1...", value = 0.3, {
      t1 <- tryCatch(
        build_table1_multi(schemas, cmaps, res),
        error = function(e) {
          showNotification(paste("Table 1 error:", e$message), type = "error"); NULL
        })
      table1_rv(t1)
    })
  })

  output$table1_status_ui <- renderUI({
    t1 <- table1_rv()
    if (is.null(t1)) return(NULL)
    if (nrow(t1) == 0)
      return(div(style = "color:var(--dre-muted);font-size:0.87rem;", "No data available."))
    NULL  # table itself shown via DT below
  })

  output$table1_dt <- DT::renderDataTable({
    t1 <- table1_rv()
    if (is.null(t1) || nrow(t1) == 0) return(NULL)
    DT::datatable(t1,
      filter   = "none",
      options  = list(dom = "t", pageLength = 100, scrollX = FALSE),
      rownames = FALSE,
      class    = "cell-border",
      colnames = c("Characteristic", "Value")
    ) |> DT::formatStyle(
      "Characteristic",
      fontWeight = DT::styleEqual(
        t1$Characteristic[!grepl("^  ", t1$Characteristic)], "bold"),
      color = DT::styleEqual(
        t1$Characteristic[!grepl("^  ", t1$Characteristic)], "#00C5B5")
    )
  })

  output$table1_dl_ui <- renderUI({
    t1 <- table1_rv()
    if (is.null(t1) || nrow(t1) == 0) return(NULL)
    downloadButton("table1_csv_btn", "Download Table 1 (.csv)",
                   class = "btn-dre-sec btn-sm")
  })

  output$table1_csv_btn <- downloadHandler(
    filename = function() {
      nm <- trimws(input$cohort_name %||% "cohort")
      if (!nzchar(nm)) nm <- "cohort"
      paste0(nm, "_table1_", format(Sys.Date(), "%Y%m%d"), ".csv")
    },
    content = function(file) {
      t1 <- table1_rv()
      if (is.null(t1)) t1 <- data.frame(Characteristic = "No data", Value = "")
      utils::write.csv(t1, file, row.names = FALSE)
      dl_dir <- DOWNLOADS_DIR
      if (!dir.exists(dl_dir)) dir.create(dl_dir, recursive=TRUE, showWarnings=FALSE)
      tryCatch(file.copy(file, file.path(dl_dir, basename(file))), error=function(e) NULL)
    }
  )

  # ──────────────────────────────────────────────────────────────────────────
  # COHORT DEFINITION SAVE / LOAD
  # ──────────────────────────────────────────────────────────────────────────

  output$save_def_btn <- downloadHandler(
    filename = function() {
      nm <- trimws(input$cohort_name %||% "cohort")
      if (!nzchar(nm)) nm <- "cohort"
      paste0(nm, "_definition_", format(Sys.Date(), "%Y%m%d"), ".json")
    },
    content = function(file) {
      json <- serialise_cohort_def(
        criteria          = criteria_rv(),
        cohort_name       = input$cohort_name       %||% "my_cohort",
        index_strategy    = input$index_strategy    %||% "first_qualifying",
        prior_obs_days    = prior_obs_days_rv(),
        min_followup_days = min_followup_days_rv()
      )
      writeLines(json, file)
      dl_dir <- DOWNLOADS_DIR
      if (!dir.exists(dl_dir)) dir.create(dl_dir, recursive = TRUE, showWarnings = FALSE)
      tryCatch(file.copy(file, file.path(dl_dir, basename(file))), error = function(e) NULL)
    }
  )

  observeEvent(input$load_def_content, {
    json_text <- input$load_def_content
    if (is.null(json_text) || !nzchar(json_text)) return()
    result <- deserialise_cohort_def(json_text)
    if (!isTRUE(result$ok)) {
      showNotification(paste("Failed to load definition:", result$error), type = "error")
      return()
    }
    # Assign unique IDs to loaded criteria so they don't clash with any existing ones
    start_id <- next_id_rv()
    loaded <- lapply(seq_along(result$criteria), function(i) {
      cr <- result$criteria[[i]]
      cr$id <- paste0("crit_", start_id + i - 1L)
      cr
    })
    next_id_rv(start_id + length(loaded))
    criteria_rv(loaded)
    updateTextInput(session, "cohort_name",    value = result$cohort_name)
    updateSelectInput(session, "index_strategy", selected = result$index_strategy)
    if (!is.na(result$prior_obs_days))
      updateNumericInput(session, "prior_obs_days",    value = result$prior_obs_days)
    if (!is.na(result$min_followup_days))
      updateNumericInput(session, "min_followup_days", value = result$min_followup_days)
    prior_obs_days_rv(result$prior_obs_days)
    min_followup_days_rv(result$min_followup_days)
    showNotification(sprintf("Loaded definition: %s (%d criteria)",
                             result$cohort_name, length(loaded)), type = "message", duration = 5)
  })

  output$load_def_status_ui <- renderUI({
    fname <- input$load_def_upload
    if (is.null(fname)) return(NULL)
    tags$p(style = "font-size:0.84rem;color:var(--dre-success);margin-top:6px;",
           icon("circle-check"), " Loaded: ", fname)
  })

  # Sync prior_obs_days and min_followup_days inputs → reactiveVals
  observeEvent(input$prior_obs_days, {
    v <- suppressWarnings(as.integer(input$prior_obs_days))
    prior_obs_days_rv(if (is.na(v) || v <= 0L) NA_integer_ else v)
  }, ignoreNULL = FALSE)

  observeEvent(input$min_followup_days, {
    v <- suppressWarnings(as.integer(input$min_followup_days))
    min_followup_days_rv(if (is.na(v) || v <= 0L) NA_integer_ else v)
  }, ignoreNULL = FALSE)

  # ──────────────────────────────────────────────────────────────────────────
  # SURVIVAL TAB - INCIDENCE RATE
  # ──────────────────────────────────────────────────────────────────────────

  observeEvent(input$run_incidence_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type = "warning"); return()
    }
    req(conn_valid())

    # Bug 10 fix (v8.2): read the outcome configuration from the Survival tab
    # and pass it through to compute_incidence_rate. Without this the function
    # falls back to "events = cohort N" which gives nonsensical rates.
    outcome_domain <- input$km_outcome_domain %||% "condition"
    outcome_cids   <- vapply(km_concepts_rv(), `[[`, integer(1), "cid")
    use_desc       <- isTRUE(input$km_use_desc)

    if (length(outcome_cids) == 0) {
      showNotification(
        paste("Select at least one outcome concept on the Survival tab",
              "before calculating an incidence rate."),
        type = "warning", duration = 8)
      return()
    }

    schemas    <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi      <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res)

    cohort_by_schema <- if (multi) split(res, res$source_schema)
                       else setNames(list(res), schemas[[1]] %||% "")

    incidence_rv(list(state = "running"))
    withProgress(message = "Computing incidence rate...", value = 0.5, {
      per_schema <- lapply(names(cohort_by_schema), function(sch) {
        cm   <- col_maps_l[[sch]] %||% omop_col_map_rv()
        sub  <- cohort_by_schema[[sch]]
        r    <- tryCatch(
          compute_incidence_rate(sch, cm, sub,
                                  outcome_domain      = outcome_domain,
                                  outcome_concept_ids = outcome_cids,
                                  use_descendants     = use_desc),
          error = function(e) NULL)
        if (!is.null(r)) r$schema <- sch
        r
      })
      per_schema <- Filter(Negate(is.null), per_schema)

      result <- if (length(per_schema) == 0) {
        showNotification("Incidence computation failed for every selected schema.",
                         type = "error")
        NULL
      } else if (length(per_schema) == 1) {
        per_schema[[1]]
      } else {
        # Pooled Poisson rate: sum events and person-years, recompute CI.
        n_events     <- sum(vapply(per_schema, function(x) x$n_events,     integer(1)))
        person_years <- sum(vapply(per_schema, function(x) x$person_years, numeric(1)))
        rate  <- if (person_years > 0) 1000 * n_events / person_years else NA_real_
        ci_lo <- if (n_events > 0 && person_years > 0)
          1000 * qchisq(0.025, 2 * n_events)        / (2 * person_years) else 0
        ci_hi <- if (person_years > 0)
          1000 * qchisq(0.975, 2 * (n_events + 1))  / (2 * person_years) else NA_real_
        list(rate = rate, n_events = n_events,
             person_years = person_years,
             ci_lower = ci_lo, ci_upper = ci_hi,
             per_schema = per_schema, multi = TRUE)
      }
    })
    incidence_rv(result)
  })

  output$incidence_ui <- renderUI({
    ir <- incidence_rv()
    if (is.null(ir)) {
      return(tags$p(style = "color:var(--dre-muted);font-size:0.87rem;",
                    "Click Calculate to compute incidence rate from follow-up time."))
    }
    if (identical(ir$state, "running"))
      return(div(style = "color:var(--dre-muted);", icon("spinner"), " Computing..."))

    rate <- ir$rate; lo <- ir$ci_lower; hi <- ir$ci_upper
    py   <- ir$person_years; ne <- ir$n_events
    if (is.null(rate) || is.na(rate))
      return(tags$p(style = "color:var(--dre-muted);", "Could not compute - observation_period data may be missing."))

    per_schema_block <- if (isTRUE(ir$multi) && !is.null(ir$per_schema)) {
      rows <- lapply(ir$per_schema, function(s) {
        s_rate <- if (!is.null(s$rate) && !is.na(s$rate)) sprintf("%.1f", s$rate) else "-"
        s_ci   <- if (!is.null(s$ci_lower) && !is.null(s$ci_upper) &&
                      !is.na(s$ci_lower) && !is.na(s$ci_upper))
                    sprintf("%.1f - %.1f", s$ci_lower, s$ci_upper) else "-"
        tags$tr(
          tags$td(s$schema %||% ""),
          tags$td(style = "text-align:right;", format(s$n_events, big.mark = ",")),
          tags$td(style = "text-align:right;", sprintf("%.0f", s$person_years)),
          tags$td(style = "text-align:right;", s_rate),
          tags$td(style = "text-align:right;", s_ci)
        )
      })
      div(style = "margin-top:14px;",
        tags$h5(style = "color:var(--dre-teal);font-size:12px;margin-bottom:8px;",
                "Per-schema breakdown"),
        tags$table(class = "dre-table", style = "width:100%;font-size:0.86rem;",
          tags$thead(tags$tr(
            tags$th("Schema"),
            tags$th(style = "text-align:right;", "Events"),
            tags$th(style = "text-align:right;", "Person-years"),
            tags$th(style = "text-align:right;", "Rate / 1,000"),
            tags$th(style = "text-align:right;", "95% CI"))),
          tags$tbody(rows)
        )
      )
    } else NULL

    div(
      fluidRow(
        column(3, div(class = "metric-box",
          div(class = "metric-val", sprintf("%.1f", rate)),
          div(class = "metric-lab", "Events / 1,000 person-years"))),
        column(3, div(class = "metric-box",
          div(class = "metric-val", sprintf("%.1f - %.1f", lo, hi)),
          div(class = "metric-lab", "95% Poisson CI"))),
        column(3, div(class = "metric-box",
          div(class = "metric-val", format(ne, big.mark=",")),
          div(class = "metric-lab", "Events"))),
        column(3, div(class = "metric-box",
          div(class = "metric-val", sprintf("%.0f", py)),
          div(class = "metric-lab", "Person-years at risk")))
      ),
      per_schema_block
    )
  })

  # ──────────────────────────────────────────────────────────────────────────
  # SURVIVAL TAB - KAPLAN-MEIER
  # ──────────────────────────────────────────────────────────────────────────


  # ── Set Cohort A / B ──────────────────────────────────────────────────────
  observeEvent(input$set_cohort_a_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type="warning"); return()
    }
    cohort_a_rv(list(
      result  = res,
      schema  = primary_schema(input$schema_select %||% character(0)),
      col_map = omop_col_map_rv(),
      label   = sprintf("Cohort A (%s persons)", format(nrow(res), big.mark=","))
    ))
    compare_rv(NULL)
    showNotification(sprintf("Cohort A set - %s persons.", format(nrow(res), big.mark=",")),
                     type="message", duration=3)
  })

  observeEvent(input$set_cohort_b_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type="warning"); return()
    }
    cohort_b_rv(list(
      result  = res,
      schema  = primary_schema(input$schema_select %||% character(0)),
      col_map = omop_col_map_rv(),
      label   = sprintf("Cohort B (%s persons)", format(nrow(res), big.mark=","))
    ))
    compare_rv(NULL)
    showNotification(sprintf("Cohort B set - %s persons.", format(nrow(res), big.mark=",")),
                     type="message", duration=3)
  })

  output$compare_ab_status_ui <- renderUI({
    ca <- cohort_a_rv()
    cb <- cohort_b_rv()
    div(class = "ab-sidebar-panel",
      div(class = "ab-sidebar-label", "Compare"),
      div(class = "ab-indicator",
        div(class = if (!is.null(ca)) "ab-dot set" else "ab-dot unset"),
        if (!is.null(ca))
          tags$span(class = "ab-label-set",
            "A: ", tags$b(format(nrow(ca$result), big.mark = ","), " persons"))
        else
          tags$span(class = "ab-label-unset", "Cohort A - not set")
      ),
      div(class = "ab-indicator",
        div(class = if (!is.null(cb)) "ab-dot set-b" else "ab-dot unset"),
        if (!is.null(cb))
          tags$span(class = "ab-label-set-b",
            "B: ", tags$b(format(nrow(cb$result), big.mark = ","), " persons"))
        else
          tags$span(class = "ab-label-unset", "Cohort B - not set")
      )
    )
  })

  output$cohort_a_badge_ui <- renderUI({
    ca <- cohort_a_rv()
    if (is.null(ca))
      div(class="cohort-ab-badge unset", icon("circle-xmark"), " Cohort A - not set. Run a cohort and click Set as Cohort A.")
    else
      div(class="cohort-ab-badge cohort-a", icon("a"), ca$label)
  })

  output$cohort_b_badge_ui <- renderUI({
    cb <- cohort_b_rv()
    if (is.null(cb))
      div(class="cohort-ab-badge unset", icon("circle-xmark"), " Cohort B - not set. Run a cohort and click Set as Cohort B.")
    else
      div(class="cohort-ab-badge cohort-b", icon("b"), cb$label)
  })

  # ── Compare - outcome concept search ──────────────────────────────────────
  observeEvent(input$cmp_concept_search_btn, {
    req(conn_valid(), nzchar(trimws(input$cmp_concept_q %||% "")))
    domain_key <- input$cmp_outcome_domain %||% "condition"
    res <- tryCatch(do_concept_search(input$cmp_concept_q, domain_key=domain_key),
                    error = function(e) NULL)
    output$cmp_concept_search_results_ui <- renderUI({
      if (is.null(res) || nrow(res) == 0)
        return(tags$p(style="color:var(--dre-muted);font-size:0.87rem;margin:4px 0;", "No concepts found."))
      already <- vapply(cmp_concepts_rv(), `[[`, integer(1), "cid")
      tags$div(style="max-height:180px;overflow-y:auto;border:1px solid var(--dre-border);border-radius:6px;margin-bottom:4px;",
        lapply(seq_len(nrow(res)), function(i) {
          r       <- res[i,]
          cid_val <- as.integer(r[["concept_id"]])
          cname   <- as.character(r[["concept_name"]])
          added   <- cid_val %in% already
          div(class="cs-row",
            style=if(added)"opacity:0.5;cursor:default;" else "cursor:pointer;",
            onclick=if(!added) sprintf(
              "Shiny.setInputValue('cmp_add_concept',{cid:%d,name:'%s'},{priority:'event'})",
              cid_val, gsub("'","\\'",cname)) else "",
            tags$b(cname),
            tags$span(class="cs-cid", paste0(" ",cid_val)),
            tags$span(class="cs-domain-pill", r[["vocabulary_id"]] %||% r[["domain_id"]]),
            if(added) tags$span(style="color:var(--dre-teal);font-size:0.84rem;margin-left:6px;","✓") else NULL
          )
        })
      )
    })
  })

  observeEvent(input$cmp_add_concept, {
    payload <- input$cmp_add_concept
    cid_val <- as.integer(payload$cid)
    cname   <- as.character(payload$name %||% as.character(cid_val))
    current <- cmp_concepts_rv()
    if (!any(vapply(current, function(x) x$cid==cid_val, logical(1))))
      cmp_concepts_rv(c(current, list(list(cid=cid_val, name=cname))))
  })

  observeEvent(input$cmp_remove_concept, {
    cid_val <- as.integer(input$cmp_remove_concept)
    cmp_concepts_rv(Filter(function(x) x$cid!=cid_val, cmp_concepts_rv()))
  })

  output$cmp_selected_concepts_ui <- renderUI({
    concepts <- cmp_concepts_rv()
    if (length(concepts)==0)
      return(tags$p(style="color:var(--dre-muted);font-size:0.84rem;margin:4px 0;",
                    "No outcomes selected - all domain events will be used."))
    tagList(
      tags$p(style="font-size:0.84rem;color:var(--dre-muted);margin:6px 0 4px;",
             sprintf("%d outcome concept%s:", length(concepts), if(length(concepts)==1)"" else "s")),
      div(style="display:flex;flex-wrap:wrap;gap:4px;",
        lapply(concepts, function(co)
          div(class="km-concept-pill",
            tags$span(co$name),
            tags$span(class="cs-cid", paste0(" ",co$cid)),
            tags$span(class="rm-x",
              onclick=sprintf("Shiny.setInputValue('cmp_remove_concept',%d,{priority:'event'})",co$cid),
              "\u00d7"))))
    )
  })

  # ── Run comparative analysis ───────────────────────────────────────────────
  observeEvent(input$run_compare_btn, {
    ca <- cohort_a_rv(); cb <- cohort_b_rv()
    if (is.null(ca) || is.null(cb)) {
      showNotification("Set both Cohort A and Cohort B first.", type="warning"); return()
    }

    if (overlap_gate_blocks(overlap_rv(), proceed_compare_rv())) {
      showNotification(
        "Acknowledge the no-overlap banner above to run comparison across these schemas.",
        type = "warning", duration = 6)
      return()
    }

    outcome_cids <- vapply(cmp_concepts_rv(), `[[`, integer(1), "cid")
    outcome_dom  <- input$cmp_outcome_domain %||% "condition"

    # Bug 17 fix (v8.1): same outcome-concept guard as the Cox tab. The
    # Compare tab also routes through query_survival_data, which drops its
    # concept filter when given an empty IDs list - and would silently
    # produce nonsense effect estimates.
    if (length(outcome_cids) == 0) {
      showNotification(
        paste("Select at least one outcome concept for the comparison.",
              "Without a specific outcome the analysis would treat any",
              "event in the domain as the outcome."),
        type = "warning", duration = 8)
      compare_rv(list(state = "error",
                      msg = "No outcome concept configured for cohort comparison."))
      return()
    }

    lookback     <- as.integer(input$cmp_lookback %||% 365)
    top_n        <- as.integer(input$cmp_top_n %||% 50)
    caliper_sd   <- as.numeric(input$cmp_caliper %||% 0.2)
    horizon      <- suppressWarnings(as.integer(input$cmp_time_horizon))
    use_desc     <- isTRUE(input$cmp_use_desc)

    compare_rv(list(state="running"))

    withProgress(message="Comparative analysis...", value=0, {

      setProgress(0.05, detail="Extracting covariates - Cohort A")
      cov_a <- tryCatch(
        extract_covariates_long(ca$schema, ca$col_map, ca$result, lookback),
        error=function(e){ message("[compare] cov_a error: ",e$message); list(long=NULL,demo=NULL) })

      setProgress(0.15, detail="Extracting covariates - Cohort B")
      cov_b <- tryCatch(
        extract_covariates_long(cb$schema, cb$col_map, cb$result, lookback),
        error=function(e){ message("[compare] cov_b error: ",e$message); list(long=NULL,demo=NULL) })

      setProgress(0.25, detail="Building feature matrix")
      feat_mat <- tryCatch(
        build_feature_matrix(cov_a$long, cov_a$demo, cov_b$long, cov_b$demo, top_n),
        error=function(e){ message("[compare] matrix error: ",e$message); NULL })

      if (is.null(feat_mat) || nrow(feat_mat)==0) {
        compare_rv(list(state="error", msg="Could not build feature matrix - check that both cohorts share the same schema and OMOP tables are present."))
        return()
      }

      setProgress(0.40, detail="Fitting propensity score model")
      ps_result <- tryCatch(
        fit_ps_model(feat_mat),
        error=function(e){ message("[compare] PS error: ",e$message); NULL })

      if (is.null(ps_result)) {
        compare_rv(list(state="error", msg="Propensity score model failed."))
        return()
      }
      feat_mat <- ps_result$mat

      setProgress(0.55, detail="Matching cohorts")
      matched <- tryCatch(
        greedy_ps_match(feat_mat, caliper_sd=caliper_sd),
        error=function(e){ message("[compare] match error: ",e$message); NULL })

      if (is.null(matched) || nrow(matched)==0) {
        compare_rv(list(state="error", msg="No matches found within caliper - try increasing caliper width or check that cohorts overlap in PS."))
        return()
      }

      setProgress(0.65, detail="Computing standardised mean differences")
      smd_tbl <- tryCatch(
        compute_smd_table(feat_mat, matched),
        error=function(e) NULL)

      setProgress(0.75, detail="Running KM analysis on matched cohorts")
      # Build cohort_result-like frames for matched subsets
      make_matched_cohort <- function(base_result, matched_subset) {
        pids    <- as_pid(matched_subset$person_id)
        base_result[base_result$person_id %in% pids, ]
      }

      matched_a_result <- make_matched_cohort(ca$result, matched[matched$cohort==1L,])
      matched_b_result <- make_matched_cohort(cb$result, matched[matched$cohort==0L,])

      surv_a <- tryCatch(
        query_survival_for_compare(ca$schema, ca$col_map, matched_a_result,
                                    outcome_dom, outcome_cids, use_desc, ca$label),
        error=function(e) NULL)
      surv_b <- tryCatch(
        query_survival_for_compare(cb$schema, cb$col_map, matched_b_result,
                                    outcome_dom, outcome_cids, use_desc, cb$label),
        error=function(e) NULL)

      setProgress(0.88, detail="Fitting Cox model")
      cox_result <- NULL
      if (!is.null(surv_a) && !is.null(surv_b)) {
        surv_combined <- rbind(surv_a, surv_b)
        if (!is.na(horizon) && horizon > 0)
          surv_combined$time <- pmin(surv_combined$time, horizon)
        surv_combined$cohort_label <- factor(surv_combined$cohort_label,
                                              levels=c(cb$label, ca$label))
        cox_result <- tryCatch({
          fit_cox <- survival::coxph(survival::Surv(time, status) ~ cohort_label,
                                     data=surv_combined)
          s   <- summary(fit_cox)
          hr  <- s$conf.int[1, "exp(coef)"]
          lo  <- s$conf.int[1, "lower .95"]
          hi  <- s$conf.int[1, "upper .95"]
          pv  <- s$sctest["pvalue"]
          list(hr=hr, ci_lo=lo, ci_hi=hi, p=pv, n_a=nrow(surv_a), n_b=nrow(surv_b),
               n_events_a=sum(surv_a$status==1L), n_events_b=sum(surv_b$status==1L),
               surv_combined=surv_combined, label_a=ca$label, label_b=cb$label)
        }, error=function(e){ message("[compare] cox error: ",e$message); NULL })
      }

      # E-value
      evalue_result <- if (!is.null(cox_result))
        compute_evalue(cox_result$hr, cox_result$ci_lo, cox_result$ci_hi)
      else NULL

      # Matched Table 1
      matched_t1 <- tryCatch(
        build_matched_table1(feat_mat, matched, smd_tbl, ca$label, cb$label),
        error = function(e) NULL)

      setProgress(1.0, detail="Done")
      compare_rv(list(
        state         = "done",
        feat_mat      = feat_mat,
        matched       = matched,
        smd_tbl       = smd_tbl,
        cox_result    = cox_result,
        evalue_result = evalue_result,
        matched_t1    = matched_t1,
        n_a_before    = nrow(ca$result),
        n_b_before    = nrow(cb$result),
        n_a_after     = if(!is.null(matched)) sum(matched$cohort==1L) else 0L,
        n_b_after     = if(!is.null(matched)) sum(matched$cohort==0L) else 0L,
        n_covs        = ps_result$n_covs,
        label_a       = ca$label,
        label_b       = cb$label,
        settings      = list(lookback=lookback, top_n=top_n,
                             caliper_sd=caliper_sd, horizon=horizon,
                             outcome_dom=outcome_dom,
                             outcome_cids=outcome_cids,
                             timestamp=format(Sys.time(), "%Y-%m-%d %H:%M:%S"))
      ))
    }) # end withProgress
  })

  # ── Compare results rendering ─────────────────────────────────────────────
  output$compare_results_ui <- renderUI({
    cr <- compare_rv()
    if (is.null(cr)) return(NULL)

    if (identical(cr$state, "running"))
      return(div(class="cb-card",style="text-align:center;padding:40px;",
                 icon("spinner",class="fa-spin",style="font-size:2rem;color:var(--dre-teal);"),
                 tags$p(style="margin-top:12px;color:var(--dre-muted);","Running analysis...")))

    if (identical(cr$state, "error"))
      return(div(class="cb-card cohort-error-panel",
                 div(class="cohort-error-title", icon("triangle-exclamation"), " Analysis Error"),
                 tags$pre(class="cohort-error-msg", cr$msg)))

    # Balance summary flag
    n_imbalanced <- if (!is.null(cr$smd_tbl))
      sum(abs(cr$smd_tbl$smd_after) > 0.1, na.rm=TRUE) else NA_integer_
    balance_class <- if (is.na(n_imbalanced)) "balance-warn"
      else if (n_imbalanced == 0) "balance-good"
      else if (n_imbalanced <= 3) "balance-warn"
      else "balance-poor"
    balance_txt <- if (is.na(n_imbalanced)) "Balance unknown"
      else if (n_imbalanced == 0) "Good balance achieved (all SMD < 0.10)"
      else sprintf("%d covariate%s with SMD \u2265 0.10 after matching",
                   n_imbalanced, if(n_imbalanced==1)"" else "s")

    tagList(
      # ── Match summary metrics ──
      div(class="cb-card",
        div(class="cb-card-title", icon("check-circle"), " Matching Summary"),
        fluidRow(
          column(3, div(class="metric-box",
            div(class="metric-val", cr$n_covs),
            div(class="metric-lab","PS covariates"))),
          column(3, div(class="metric-box",
            div(class="metric-val",
              sprintf("%s \u2192 %s", format(cr$n_a_before,big.mark=","), format(cr$n_a_after,big.mark=","))),
            div(class="metric-lab","Cohort A (before \u2192 after match)"))),
          column(3, div(class="metric-box",
            div(class="metric-val",
              sprintf("%s \u2192 %s", format(cr$n_b_before,big.mark=","), format(cr$n_b_after,big.mark=","))),
            div(class="metric-lab","Cohort B (before \u2192 after match)"))),
          column(3, div(class="metric-box",
            div(class="metric-val",
              tags$span(class=balance_class, if(n_imbalanced==0) "\u2713" else "\u26a0")),
            div(class="metric-lab", tags$span(class=balance_class, balance_txt))))
        )
      ),

      # ── PS overlap plot ──
      if (!is.null(cr$feat_mat))
        div(class="cb-card",
          div(class="cb-card-title", icon("layer-group"), " Propensity Score Overlap",
            tags$span(style="float:right;font-size:0.84rem;color:var(--dre-muted);font-weight:400;font-style:italic;",
                      "Substantial overlap required for valid comparison")),
          tags$p(style="font-size:0.87rem;color:var(--dre-muted);margin-bottom:10px;",
            "Density of estimated propensity scores for each cohort before matching. ",
            "Regions with little overlap indicate limited common support - ",
            "matched estimates in those regions carry greater uncertainty."),
          div(class="ps-overlap-wrap", plotOutput("ps_overlap_plot", height="280px"))
        )
      else NULL,

      # ── Love plot ──
      if (!is.null(cr$smd_tbl) && nrow(cr$smd_tbl) > 0)
        div(class="cb-card",
          div(class="cb-card-title", icon("heart"), " Covariate Balance - Love Plot",
            tags$span(style="float:right;font-size:0.84rem;color:var(--dre-muted);font-weight:400;font-style:italic;",
                      "SMD < 0.10 indicates good balance")),
          div(class="love-plot-wrap",
            plotOutput("love_plot", height=paste0(max(280, min(nrow(cr$smd_tbl)*18+80, 700)),"px")))
        )
      else NULL,

      # ── KM comparison + Cox + E-value ──
      if (!is.null(cr$cox_result)) {
        ev <- cr$evalue_result
        ev_interp <- if (!is.null(ev) && !is.na(ev$evalue))
          sprintf(
            "An unmeasured confounder associated with both treatment and outcome by a factor of %.2f or more could explain away the observed effect. For the confidence interval bound, this factor is %.2f.",
            ev$evalue, ev$evalue_ci)
        else "E-value not available."

        div(class="cb-card",
          div(class="cb-card-title", icon("chart-line"), " Outcome Comparison - Matched Cohorts"),
          fluidRow(
            column(8, plotOutput("compare_km_plot", height="400px")),
            column(4,
              div(class="compare-hr-box", style="margin-bottom:10px;",
                tags$p(style="font-size:0.78rem;color:var(--dre-muted);margin-bottom:6px;text-transform:uppercase;letter-spacing:.6px;",
                       "Hazard Ratio (Cox PH)"),
                tags$p(style="font-size:0.80rem;color:var(--dre-muted);margin-bottom:4px;",
                       paste(cr$cox_result$label_a, "vs", cr$cox_result$label_b)),
                div(class="compare-hr-val", sprintf("%.2f", cr$cox_result$hr)),
                div(class="compare-hr-ci",
                    sprintf("95%% CI: %.2f \u2013 %.2f", cr$cox_result$ci_lo, cr$cox_result$ci_hi)),
                div(class="compare-hr-p",
                    sprintf("Log-rank p %s",
                            if(cr$cox_result$p < 0.001) "< 0.001"
                            else sprintf("= %.3f", cr$cox_result$p))),
                tags$hr(style="border-color:var(--dre-border);margin:10px 0;"),
                tags$p(style="font-size:0.84rem;color:var(--dre-muted);",
                  sprintf("A: %s events / %s",
                    format(cr$cox_result$n_events_a,big.mark=","),
                    format(cr$cox_result$n_a,big.mark=","))),
                tags$p(style="font-size:0.84rem;color:var(--dre-muted);",
                  sprintf("B: %s events / %s",
                    format(cr$cox_result$n_events_b,big.mark=","),
                    format(cr$cox_result$n_b,big.mark=",")))
              ),
              if (!is.null(ev) && !is.na(ev$evalue))
                div(class="evalue-box",
                  tags$p(style="font-size:0.78rem;color:var(--dre-muted);margin-bottom:6px;text-transform:uppercase;letter-spacing:.6px;",
                         "E-Value (unmeasured confounding)"),
                  div(class="evalue-val", sprintf("%.2f", ev$evalue)),
                  div(class="evalue-ci",  sprintf("For CI bound: %.2f", ev$evalue_ci)),
                  div(class="evalue-interp", ev_interp)
                )
              else NULL
            )
          )
        )
      } else if (!is.null(cr$smd_tbl))
        div(class="cb-card",
          div(class="cb-card-title", icon("chart-line"), " Outcome Comparison"),
          tags$p(style="color:var(--dre-muted);font-size:0.87rem;",
                 "Select an outcome domain and run the analysis to see KM curves and hazard ratio."))
      else NULL,

      # ── Matched Table 1 ──
      if (!is.null(cr$matched_t1) && nrow(cr$matched_t1) > 0)
        div(class="cb-card",
          div(class="cb-card-title", icon("table"), " Matched Table 1 - Covariate Balance After Matching",
            tags$span(style="float:right;",
              downloadButton("download_matched_t1_btn", "Download CSV",
                             class="btn-dre-sec btn-sm"))),
          tags$p(style="font-size:0.87rem;color:var(--dre-muted);margin-bottom:10px;",
            "Standardised mean differences shown are post-matching. ",
            tags$b("SMD < 0.10"), " is conventionally considered balanced. ",
            "[Dx] = diagnosis / condition;  [Rx] = drug / medication."),
          DT::dataTableOutput("matched_t1_dt")
        )
      else NULL,

      # ── Export results package ──
      div(class="cb-card",
        div(class="cb-card-title", icon("file-export"), " Export Results Package"),
        tags$p(style="font-size:0.87rem;color:var(--dre-muted);margin-bottom:12px;",
          "Download all analysis outputs as a ZIP for audit, submission, or statistical review. ",
          "Files are also written to your workspace Downloads folder."),
        div(class="export-results-bar",
          downloadButton("download_compare_zip_btn",
            tagList(icon("file-zipper"), " Download Full Results Package"),
            class="btn-dre-pri"),
          downloadButton("download_matched_ids_btn",
            tagList(icon("id-card"), " Matched Person IDs"),
            class="btn-dre-sec"),
          downloadButton("download_ps_model_btn",
            tagList(icon("brain"), " PS Model Covariates"),
            class="btn-dre-sec")
        )
      )
    )
  })

  output$love_plot <- renderPlot({
    cr <- compare_rv()
    if (is.null(cr) || !identical(cr$state,"done") || is.null(cr$smd_tbl)) return(NULL)
    tbl <- cr$smd_tbl
    # Show top 30 by absolute pre-match SMD
    tbl <- head(tbl[order(abs(tbl$smd_before), decreasing=TRUE),], 30)
    tbl$covariate <- factor(tbl$covariate, levels=rev(tbl$covariate))

    # Friendly labels: strip cond_/drug_ prefix, truncate
    tbl$label <- sub("^(cond|drug)_","",tbl$covariate)
    tbl$type  <- ifelse(grepl("^cond_",as.character(tbl$covariate)),"Condition","Drug/Other")
    tbl$label <- factor(tbl$label, levels=rev(tbl$label))

    p <- ggplot2::ggplot(tbl) +
      ggplot2::geom_vline(xintercept=0,  colour="#4A6080", linewidth=0.5) +
      ggplot2::geom_vline(xintercept= 0.1, colour=grDevices::rgb(1,.72,.3,.35), linewidth=0.8, linetype="dashed") +
      ggplot2::geom_vline(xintercept=-0.1, colour=grDevices::rgb(1,.72,.3,.35), linewidth=0.8, linetype="dashed") +
      ggplot2::geom_segment(ggplot2::aes(x=smd_after, xend=smd_before, y=label, yend=label),
                            colour="#4A6080", linewidth=0.5) +
      ggplot2::geom_point(ggplot2::aes(x=smd_before, y=label),
                          colour="#E05C6E", size=3, alpha=0.85) +
      ggplot2::geom_point(ggplot2::aes(x=smd_after, y=label),
                          colour="#00C5B5", size=3, alpha=0.95) +
      ggplot2::annotate("text", x=max(abs(tbl$smd_before),na.rm=TRUE)*0.85,
                        y=nrow(tbl)+0.5, label="Before match", colour="#E05C6E",
                        size=3.2, hjust=0.5) +
      ggplot2::annotate("text", x=max(abs(tbl$smd_before),na.rm=TRUE)*0.3,
                        y=nrow(tbl)+0.5, label="After match", colour="#00C5B5",
                        size=3.2, hjust=0.5) +
      ggplot2::scale_x_continuous(labels=function(x) sprintf("%.2f",x)) +
      ggplot2::labs(x="Standardised Mean Difference", y=NULL,
                    title="Covariate Balance",
                    subtitle=sprintf("%d covariates shown  |  Dashed lines at SMD = \u00b10.10", nrow(tbl))) +
      theme_dre() +
      ggplot2::theme(axis.text.y=ggplot2::element_text(size=10),
                     panel.grid.major.y=ggplot2::element_line(colour="#1A3A60",linewidth=0.3))
    p
  }, res = PLOT_RES, bg="#0B2341")

  output$compare_km_plot <- renderPlot({
    cr <- compare_rv()
    if (is.null(cr) || !identical(cr$state,"done") || is.null(cr$cox_result)) return(NULL)
    sc <- cr$cox_result$surv_combined

    lvls  <- levels(sc$cohort_label)
    cols  <- c("#00C5B5","#FFB84D")  # teal for reference, gold for index
    names(cols) <- lvls

    fits <- lapply(lvls, function(lv) {
      d <- sc[sc$cohort_label==lv,]
      survival::survfit(survival::Surv(time,status)~1, data=d)
    })
    names(fits) <- lvls

    km_rows <- do.call(rbind, lapply(lvls, function(lv) {
      f <- fits[[lv]]
      data.frame(time=c(0,f$time), surv=c(1,f$surv),
                 upper=c(1,f$upper), lower=c(1,f$lower),
                 group=lv, stringsAsFactors=FALSE)
    }))
    km_rows <- km_rows[!is.na(km_rows$surv),]
    km_rows$group <- factor(km_rows$group, levels=lvls)

    p <- ggplot2::ggplot(km_rows, ggplot2::aes(x=time, y=surv, colour=group, fill=group)) +
      ggplot2::geom_ribbon(ggplot2::aes(ymin=lower,ymax=upper), alpha=0.15, colour=NA) +
      ggplot2::geom_step(linewidth=1.1) +
      ggplot2::scale_colour_manual(values=cols, name=NULL) +
      ggplot2::scale_fill_manual(values=cols, name=NULL) +
      ggplot2::scale_y_continuous(labels=scales::percent_format(accuracy=1),
                                   limits=c(0,1), expand=c(0.01,0)) +
      ggplot2::scale_x_continuous(labels=function(x) format(x,big.mark=","), expand=c(0.01,0)) +
      ggplot2::labs(x="Days from index", y="Event-free survival probability",
                    title="Kaplan-Meier - matched cohort comparison",
                    subtitle=sprintf("HR = %.2f (95%% CI %.2f-%.2f)  |  Log-rank p %s",
                      cr$cox_result$hr, cr$cox_result$ci_lo, cr$cox_result$ci_hi,
                      if(cr$cox_result$p < 0.001) "< 0.001" else sprintf("= %.3f",cr$cox_result$p)),
                    caption="Shaded areas: 95% confidence intervals  |  Propensity score matched") +
      theme_dre() +
      ggplot2::theme(legend.position="bottom",
                     legend.background=ggplot2::element_rect(fill="transparent",colour=NA),
                     legend.text=ggplot2::element_text(colour="#E8F4F8",size=10))
    p
  }, res = PLOT_RES, bg="#0B2341")


  # ── PS overlap plot ──────────────────────────────────────────────────────────
  output$ps_overlap_plot <- renderPlot({
    cr <- compare_rv()
    if (is.null(cr) || !identical(cr$state,"done") || is.null(cr$feat_mat)) return(NULL)
    fm <- cr$feat_mat
    if (!"ps" %in% names(fm)) return(NULL)

    fa <- fm[fm$cohort == 1L, ]
    fb <- fm[fm$cohort == 0L, ]

    # Density for each group
    da <- tryCatch(density(fa$ps, from=0, to=1, n=512), error=function(e) NULL)
    db <- tryCatch(density(fb$ps, from=0, to=1, n=512), error=function(e) NULL)
    if (is.null(da) || is.null(db)) return(NULL)

    df_dens <- rbind(
      data.frame(ps=da$x, density=da$y, group=cr$label_a, stringsAsFactors=FALSE),
      data.frame(ps=db$x, density=db$y, group=cr$label_b, stringsAsFactors=FALSE)
    )
    df_dens$group <- factor(df_dens$group, levels=c(cr$label_a, cr$label_b))

    cols  <- c("#00C5B5","#FFB84D")
    names(cols) <- levels(df_dens$group)

    # Overlap region shading - minimum density at each x
    x_seq  <- da$x
    ov_y   <- pmin(da$y, approx(db$x, db$y, xout=x_seq)$y)
    df_ov  <- data.frame(ps=x_seq, density=ov_y)

    # Caliper strip (PS range of matched cohort A)
    if (!is.null(cr$matched) && "ps" %in% names(cr$matched)) {
      ps_matched <- cr$matched$ps
      ps_lo <- min(ps_matched, na.rm=TRUE)
      ps_hi <- max(ps_matched, na.rm=TRUE)
    } else { ps_lo <- 0; ps_hi <- 1 }

    ggplot2::ggplot(df_dens, ggplot2::aes(x=ps, y=density, colour=group, fill=group)) +
      ggplot2::geom_area(data=df_ov, ggplot2::aes(x=ps, y=density),
                         inherit.aes=FALSE,
                         fill=grDevices::rgb(0,197/255,181/255,.18), colour=NA) +
      ggplot2::geom_line(linewidth=1.1, alpha=0.9) +
      ggplot2::scale_colour_manual(values=cols, name=NULL) +
      ggplot2::scale_fill_manual(values=cols, name=NULL) +
      ggplot2::scale_x_continuous(limits=c(0,1), expand=c(0.01,0),
                                   labels=function(x) sprintf("%.2f",x)) +
      ggplot2::scale_y_continuous(expand=c(0.02,0)) +
      ggplot2::annotate("text", x=0.5, y=max(df_ov$density,na.rm=TRUE)*0.6,
                        label="Overlap region", colour=grDevices::rgb(0,197/255,181/255,.7),
                        size=3.2, fontface="italic") +
      ggplot2::labs(x="Propensity Score", y="Density",
                    title="PS Distributions Before Matching",
                    subtitle="Shaded area = common support region used for matching") +
      theme_dre() +
      ggplot2::theme(legend.position="bottom",
                     legend.background=ggplot2::element_rect(fill="transparent",colour=NA),
                     legend.text=ggplot2::element_text(colour="#E8F4F8",size=10))
  }, res = PLOT_RES, bg="#0B2341")

  # ── Matched Table 1 DT ───────────────────────────────────────────────────────
  output$matched_t1_dt <- DT::renderDataTable({
    cr <- compare_rv()
    if (is.null(cr) || is.null(cr$matched_t1)) return(NULL)
    t1 <- cr$matched_t1
    is_hdr <- !grepl("^  ", t1$Characteristic) & t1$Characteristic != "N (matched)"

    DT::datatable(t1,
      filter  = "none",
      options = list(dom="t", pageLength=200, scrollX=FALSE),
      rownames= FALSE
    ) |>
      DT::formatStyle("Characteristic",
        fontWeight = DT::styleEqual(
          t1$Characteristic[is_hdr], rep("700", sum(is_hdr))),
        color = DT::styleEqual(
          t1$Characteristic[is_hdr], rep("#00C5B5", sum(is_hdr)))
      ) |>
      DT::formatStyle("SMD",
        color = DT::styleInterval(c(-0.1, 0.1), c("#E05C6E","#3DD68C","#E05C6E")))
  })

  # ── Download: Matched Table 1 CSV ─────────────────────────────────────────────
  output$download_matched_t1_btn <- downloadHandler(
    filename = function() sprintf("matched_table1_%s.csv", format(Sys.time(),"%Y%m%d_%H%M")),
    content  = function(file) {
      cr <- compare_rv()
      if (is.null(cr) || is.null(cr$matched_t1)) return()
      write.csv(cr$matched_t1, file, row.names=FALSE)
      tryCatch({
        dir.create(DOWNLOADS_DIR, recursive=TRUE, showWarnings=FALSE)
        write.csv(cr$matched_t1,
          file.path(DOWNLOADS_DIR, sprintf("matched_table1_%s.csv", format(Sys.time(),"%Y%m%d_%H%M"))),
          row.names=FALSE)
      }, error=function(e) NULL)
    }
  )

  # ── Download: Matched person IDs ──────────────────────────────────────────────
  output$download_matched_ids_btn <- downloadHandler(
    filename = function() sprintf("matched_person_ids_%s.csv", format(Sys.time(),"%Y%m%d_%H%M")),
    content  = function(file) {
      cr <- compare_rv()
      if (is.null(cr) || is.null(cr$matched)) return()
      m <- cr$matched
      out <- data.frame(
        person_id    = as_pid(m$person_id),
        cohort       = ifelse(m$cohort == 1L, "A", "B"),
        match_group  = as.integer(m$match_group),
        ps           = round(m$ps, 6),
        stringsAsFactors = FALSE)
      out <- out[order(out$match_group, out$cohort), ]
      write.csv(out, file, row.names=FALSE)
      tryCatch({
        dir.create(DOWNLOADS_DIR, recursive=TRUE, showWarnings=FALSE)
        write.csv(out,
          file.path(DOWNLOADS_DIR, sprintf("matched_person_ids_%s.csv", format(Sys.time(),"%Y%m%d_%H%M"))),
          row.names=FALSE)
      }, error=function(e) NULL)
    }
  )

  # ── Download: PS model covariate table ────────────────────────────────────────
  output$download_ps_model_btn <- downloadHandler(
    filename = function() sprintf("ps_model_covariates_%s.csv", format(Sys.time(),"%Y%m%d_%H%M")),
    content  = function(file) {
      cr <- compare_rv()
      if (is.null(cr) || is.null(cr$smd_tbl)) return()
      out <- cr$smd_tbl
      out$type <- ifelse(grepl("^cond_", out$covariate), "Condition", "Drug/Other")
      out$concept_id <- as.integer(sub("^(cond|drug)_","",out$covariate))
      out <- out[, c("covariate","type","concept_id","prev_a","prev_b","smd_before","smd_after")]
      names(out) <- c("covariate","type","concept_id",
                       paste0("prevalence_",cr$label_a), paste0("prevalence_",cr$label_b),
                       "smd_before_match","smd_after_match")
      write.csv(out, file, row.names=FALSE)
      tryCatch({
        dir.create(DOWNLOADS_DIR, recursive=TRUE, showWarnings=FALSE)
        write.csv(out,
          file.path(DOWNLOADS_DIR, sprintf("ps_model_covariates_%s.csv", format(Sys.time(),"%Y%m%d_%H%M"))),
          row.names=FALSE)
      }, error=function(e) NULL)
    }
  )

  # ── Download: Full results ZIP ────────────────────────────────────────────────
  output$download_compare_zip_btn <- downloadHandler(
    filename = function() sprintf("compare_results_%s.zip", format(Sys.time(),"%Y%m%d_%H%M")),
    content  = function(file) {
      cr <- compare_rv()
      if (is.null(cr) || !identical(cr$state,"done")) return()

      tmp <- file.path(tempdir(), paste0("compare_", format(Sys.time(),"%Y%m%d_%H%M%S")))
      dir.create(tmp, recursive=TRUE, showWarnings=FALSE)

      # 1. Matched Table 1
      if (!is.null(cr$matched_t1))
        write.csv(cr$matched_t1, file.path(tmp,"matched_table1.csv"), row.names=FALSE)

      # 2. Matched person IDs
      if (!is.null(cr$matched)) {
        m   <- cr$matched
        ids <- data.frame(person_id=as_pid(m$person_id),
                          cohort=ifelse(m$cohort==1L,"A","B"),
                          match_group=as.integer(m$match_group),
                          ps=round(m$ps,6), stringsAsFactors=FALSE)
        ids <- ids[order(ids$match_group,ids$cohort),]
        write.csv(ids, file.path(tmp,"matched_person_ids.csv"), row.names=FALSE)
      }

      # 3. PS model covariates
      if (!is.null(cr$smd_tbl)) {
        out <- cr$smd_tbl
        out$type <- ifelse(grepl("^cond_",out$covariate),"Condition","Drug/Other")
        out$concept_id <- as.integer(sub("^(cond|drug)_","",out$covariate))
        out <- out[,c("covariate","type","concept_id","prev_a","prev_b","smd_before","smd_after")]
        names(out) <- c("covariate","type","concept_id",
                         paste0("prevalence_",cr$label_a),paste0("prevalence_",cr$label_b),
                         "smd_before_match","smd_after_match")
        write.csv(out, file.path(tmp,"ps_model_covariates.csv"), row.names=FALSE)
      }

      # 4. Analysis summary text
      s <- cr$settings %||% list()
      ev <- cr$evalue_result
      cox <- cr$cox_result
      summary_lines <- c(
        "OMOP Cohort Builder - Comparative Analysis Summary",
        paste(rep("=",60),collapse=""),
        sprintf("Generated:    %s", s$timestamp %||% format(Sys.time(),"%Y-%m-%d %H:%M:%S")),
        "",
        "COHORTS",
        sprintf("  Cohort A:   %s  (before match: %d, after: %d)",
                cr$label_a, cr$n_a_before, cr$n_a_after),
        sprintf("  Cohort B:   %s  (before match: %d, after: %d)",
                cr$label_b, cr$n_b_before, cr$n_b_after),
        "",
        "PS MODEL",
        sprintf("  Covariates:       %d", cr$n_covs),
        sprintf("  Lookback window:  %d days", s$lookback %||% NA),
        sprintf("  Max covariates:   %d", s$top_n %||% NA),
        sprintf("  Caliper (SD):     %.2f", s$caliper_sd %||% NA),
        "",
        "BALANCE",
        if (!is.null(cr$smd_tbl)) {
          n_imbal <- sum(abs(cr$smd_tbl$smd_after) > 0.1, na.rm=TRUE)
          sprintf("  Covariates with SMD >= 0.10 after matching: %d / %d",
                  n_imbal, nrow(cr$smd_tbl))
        } else "  Balance data not available",
        "",
        if (!is.null(cox)) c(
          "OUTCOME",
          sprintf("  Domain:           %s", s$outcome_dom %||% "-"),
          sprintf("  Concept IDs:      %s",
                  if(length(s$outcome_cids %||% integer(0))>0)
                    paste(s$outcome_cids, collapse=", ") else "(all domain events)"),
          sprintf("  Cohort A events:  %d / %d", cox$n_events_a, cox$n_a),
          sprintf("  Cohort B events:  %d / %d", cox$n_events_b, cox$n_b),
          "",
          "RESULTS",
          sprintf("  Hazard Ratio:     %.4f", cox$hr),
          sprintf("  95%% CI:           %.4f \u2013 %.4f", cox$ci_lo, cox$ci_hi),
          sprintf("  Log-rank p-value: %s",
                  if(cox$p < 0.001) "< 0.001" else sprintf("%.4f", cox$p))
        ) else character(0),
        "",
        if (!is.null(ev) && !is.na(ev$evalue)) c(
          "E-VALUE (VanderWeele & Ding, 2017)",
          sprintf("  E-value (point estimate): %.4f", ev$evalue),
          sprintf("  E-value (CI bound):       %.4f", ev$evalue_ci),
          paste0("  Interpretation: An unmeasured confounder would need to be associated\n",
                 "  with both exposure and outcome by a factor of at least ",
                 sprintf("%.2f",ev$evalue),
                 " to fully explain away\n  the observed effect.")
        ) else character(0),
        "",
        paste(rep("=",60),collapse=""),
        "Files in this package:",
        "  matched_table1.csv        - covariate balance table (post-match)",
        "  matched_person_ids.csv    - person IDs and match groups for audit",
        "  ps_model_covariates.csv   - all PS model inputs with SMD before/after",
        "  analysis_summary.txt      - this file"
      )
      writeLines(unlist(summary_lines), file.path(tmp,"analysis_summary.txt"))

      # ZIP everything
      old_wd <- getwd()
      setwd(tmp)
      zip_file <- file
      tryCatch({
        utils::zip(zip_file, list.files(tmp), flags="-j")
      }, error=function(e) {
        # Fallback: write the summary as the download if zip fails
        file.copy(file.path(tmp,"analysis_summary.txt"), zip_file)
      })
      setwd(old_wd)

      # Mirror to workspace Downloads
      tryCatch({
        dir.create(DOWNLOADS_DIR, recursive=TRUE, showWarnings=FALSE)
        ts <- format(Sys.time(),"%Y%m%d_%H%M")
        for (f in list.files(tmp)) {
          file.copy(file.path(tmp,f), file.path(DOWNLOADS_DIR, f), overwrite=TRUE)
        }
      }, error=function(e) NULL)
    }
  )

  # ── KM outcome picker (v10.13) ─────────────────────────────────────────────
  # Replaces the old search-by-name flow with a browser-style picker:
  #   - Domain dropdown with counts
  #   - Concept list (top 200 by prevalence) with schema pills and sort
  #   - Search filters the loaded list client-side
  #   - Click row -> add to outcomes; chips above show selections.
  # Reuses browse_concepts_multi_schema and compute_schema_overlap_multi
  # already used by the main browser.

  # Render the domain dropdown with per-domain concept counts. Counts come
  # from a lightweight query: one COUNT(DISTINCT concept_id) per domain over
  # the schema's domain table. Computed on demand when schemas change.
  output$km_outcome_domain_ui <- renderUI({
    counts <- km_picker_domain_counts_rv()
    sel <- input$km_outcome_domain %||% "condition"
    choices_vec <- names(DOMAINS)
    labels_vec <- vapply(DOMAINS, `[[`, character(1), "label")
    if (!is.null(counts)) {
      labels_vec <- vapply(choices_vec, function(k) {
        n <- counts[[k]] %||% NA_integer_
        if (is.null(n) || is.na(n))
          DOMAINS[[k]]$label
        else
          sprintf("%s (%s)", DOMAINS[[k]]$label,
                  format(as.integer(n), big.mark = ","))
      }, character(1))
    }
    selectInput("km_outcome_domain", "Outcome domain",
      choices  = setNames(choices_vec, labels_vec),
      selected = sel, width = "100%")
  })

  # Compute per-domain concept counts when schemas change. Runs one cheap
  # query per (schema, domain) pair counting distinct concept_ids that have
  # records.
  observe({
    if (!conn_valid()) return()
    schemas <- input$schema_select %||% character(0)
    col_maps <- col_maps_rv()
    if (length(schemas) == 0 || length(col_maps) == 0) {
      km_picker_domain_counts_rv(NULL); return()
    }
    isolate({
      counts <- list()
      for (dk in names(DOMAINS)) {
        dom <- DOMAINS[[dk]]
        # Aggregate distinct concept_ids across schemas
        ids <- integer(0)
        for (sch in schemas) {
          cm <- col_maps[[sch]]
          if (is.null(cm)) next
          existing <- tryCatch(tolower(get_tables(sch)),
                               error = function(e) character(0))
          if (!tolower(dom$table) %in% existing) next
          t_cid <- ac(cm, dom$table, dom$concept_col)
          sql <- sprintf(
            "SELECT DISTINCT t.%s::int AS cid FROM %s t WHERE t.%s IS NOT NULL",
            t_cid, fq(sch, dom$table), t_cid)
          r <- tryCatch(db_query(sql), error = function(e) NULL)
          if (!is.null(r) && nrow(r) > 0) {
            names(r) <- tolower(names(r))
            ids <- union(ids, as.integer(r$cid))
          }
        }
        counts[[dk]] <- length(ids)
      }
      km_picker_domain_counts_rv(counts)
    })
  })

  # Load the concept list when schemas/domain change. Cached per (schemas,
  # domain). Wrapped in withProgress for visible feedback.
  .km_picker_load <- function() {
    if (!conn_valid()) return()
    schemas <- isolate(input$schema_select) %||% character(0)
    col_maps <- isolate(col_maps_rv())
    dom_key  <- isolate(input$km_outcome_domain) %||% "condition"
    if (length(schemas) == 0 || length(col_maps) == 0) {
      km_picker_data_rv(NULL); return()
    }
    cache_key <- paste(c(paste(sort(schemas), collapse=","), dom_key,
                         isolate(km_picker_sort_rv())), collapse="|")
    cache <- isolate(km_picker_cache_rv())
    if (!is.null(cache[[cache_key]])) {
      km_picker_data_rv(cache[[cache_key]]); return()
    }
    km_picker_data_rv(NULL)
    result <- withProgress(
      message = "Loading outcome concepts",
      detail  = sprintf("Domain: %s", DOMAINS[[dom_key]]$label %||% dom_key),
      value   = NULL,
      browse_concepts_multi_schema(
        schemas       = schemas,
        col_maps      = col_maps,
        domain_key    = dom_key,
        vocab_id      = NULL,
        standard_only = TRUE,
        has_data_only = TRUE,    # picker only shows concepts with records
        search_text   = "",      # client-side filter applies below
        limit         = 200L,
        order_by      = { bs <- isolate(km_picker_sort_rv())
                          if (startsWith(bs, "cohortevents")) "persons:desc" else bs }
      )
    )
    cache[[cache_key]] <- result
    km_picker_cache_rv(cache)
    km_picker_data_rv(result)
  }

  # Trigger picker reload on schema or domain change
  observeEvent({
    col_maps_rv()
    input$km_outcome_domain
  }, {
    if (length(col_maps_rv()) == 0) return()
    .km_picker_load()
  }, ignoreInit = FALSE, ignoreNULL = TRUE)

  # Sort header click for the KM picker (uses same column-key convention as
  # the main browser sort header)
  observeEvent(input$km_picker_sort_click, {
    new_col <- input$km_picker_sort_click
    if (is.null(new_col) || !nzchar(new_col)) return()
    cur <- isolate(km_picker_sort_rv())
    parts <- strsplit(cur, ":", fixed = TRUE)[[1]]
    cur_col <- if (length(parts) >= 1) parts[1] else "persons"
    cur_dir <- if (length(parts) >= 2) parts[2] else "desc"
    new_col <- as.character(new_col)
    next_dir <- if (identical(new_col, cur_col)) {
      if (identical(cur_dir, "desc")) "asc" else "desc"
    } else {
      if (new_col %in% c("persons","records","n_schemas_present")) "desc" else "asc"
    }
    new_sort <- paste0(new_col, ":", next_dir)
    if (identical(new_sort, cur)) return()
    km_picker_sort_rv(new_sort)
    .km_picker_load()
  }, ignoreNULL = TRUE)

  # Per-concept cohort post-index event counts (concept_id -> n), recomputed
  # when the cohort, domain, or schemas change. Merged into the picker rows so
  # users see which outcomes yield events before selecting.
  km_picker_events <- reactive({
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) return(setNames(integer(0), character(0)))
    domain  <- input$km_outcome_domain %||% "condition"
    schemas <- input$schema_select %||% character(0)
    if (length(schemas) == 0) schemas <- ""
    if (!"source_schema" %in% names(res)) res$source_schema <- schemas[[1]]
    acc <- list()
    for (sch in schemas) {
      sub <- res[res$source_schema == sch, , drop = FALSE]
      if (nrow(sub) == 0) next
      cm <- col_maps_rv()[[sch]] %||% omop_col_map_rv()
      cc <- tryCatch(count_cohort_concept_events(sch, cm, sub, domain),
                     error = function(e) NULL)
      if (!is.null(cc) && nrow(cc) > 0)
        for (k in seq_len(nrow(cc))) {
          id <- cc$concept_id[k]
          acc[[id]] <- (acc[[id]] %||% 0L) + cc$n[k]
        }
    }
    if (length(acc) == 0) return(setNames(integer(0), character(0)))
    out <- as.integer(unlist(acc)); names(out) <- names(acc); out
  })

  # Render the concept list. Applies client-side search filter on
  # input$km_picker_search to the loaded data.
  output$km_picker_list_ui <- renderUI({
    lst <- km_picker_data_rv()
    all_schemas <- input$schema_select %||% character(0)
    show_schemas_col <- length(all_schemas) > 1
    sort_header <- if (show_schemas_col)
      .render_km_sort_header(
        c("name","cohortevents","vocab","code","persons","records","n_schemas_present"),
        c("Concept","Cohort","Vocab","Code","Persons","Records","Schemas")
      )
    else
      .render_km_sort_header(
        c("name","cohortevents","vocab","code","persons","records"),
        c("Concept","Cohort","Vocab","Code","Persons","Records")
      )

    if (is.null(lst)) {
      return(tagList(sort_header,
        div(class = "browser-detail-empty",
            icon("spinner"), " Loading\u2026")))
    }
    if (nrow(lst) == 0)
      return(tagList(sort_header,
        div(class = "browser-detail-empty",
            "No concepts with records in this domain.")))

    # Client-side text filter
    lst_view <- lst
    flt <- input$km_picker_search
    if (!is.null(flt) && nzchar(trimws(flt))) {
      needle <- tolower(trimws(flt))
      keep <- grepl(needle, tolower(lst_view$concept_name %||% ""), fixed = TRUE) |
              grepl(needle, tolower(lst_view$concept_code %||% ""), fixed = TRUE)
      keep[is.na(keep)] <- FALSE
      lst_view <- lst_view[keep, , drop = FALSE]
    }
    if (nrow(lst_view) == 0)
      return(tagList(sort_header,
        div(class = "browser-detail-empty",
            "No concepts match the filter.")))

    # Merge per-concept cohort post-index event counts; sort by them if chosen.
    ev <- km_picker_events()
    lst_view$cohort_events <- as.integer(ev[as.character(lst_view$concept_id)])
    lst_view$cohort_events[is.na(lst_view$cohort_events)] <- 0L
    sort_parts <- strsplit(km_picker_sort_rv(), ":", fixed = TRUE)[[1]]
    if (length(sort_parts) >= 1 && identical(sort_parts[1], "cohortevents")) {
      dec <- !(length(sort_parts) >= 2 && identical(sort_parts[2], "asc"))
      lst_view <- lst_view[order(lst_view$cohort_events, decreasing = dec), ,
                           drop = FALSE]
    }

    # Render rows; click row -> add to outcomes
    already <- vapply(km_concepts_rv(), `[[`, integer(1), "cid")
    rows <- lapply(seq_len(nrow(lst_view)), function(i) {
      row <- lst_view[i, , drop = FALSE]
      cid <- as.integer(row$concept_id)
      added <- cid %in% already
      add_js <- if (!added) sprintf(
        "Shiny.setInputValue('km_picker_add', {cid:%d, name:%s, _ts:Date.now()}, {priority:'event'})",
        cid, jsonlite::toJSON(row$concept_name, auto_unbox = TRUE)
      ) else ""
      row_data <- list(
        n_persons = row$n_persons,
        per_schema = if ("per_schema" %in% names(row)) row$per_schema[[1]] else NULL,
        n_schemas_present = row$n_schemas_present %||% 0L
      )
      pill_block <- .render_pill_block(row_data, all_schemas)
      ce <- as.integer(row$cohort_events %||% 0L); if (is.na(ce)) ce <- 0L
      ce_col <- if (ce == 0) "#FF6B6B" else if (ce < 25) "#FFD166" else "#00C5B5"
      ce_badge <- tags$span(
        title = "Cohort patients with at least one occurrence after index",
        style = sprintf("display:inline-block;min-width:30px;text-align:center;padding:1px 7px;margin-right:8px;border-radius:10px;font-size:0.74rem;font-weight:600;color:%s;border:1px solid %s;background:rgba(255,255,255,0.03);flex:none;", ce_col, ce_col),
        format(ce, big.mark = ","))
      tags$div(
        class = paste("browser-list-row km-picker-row",
                      if (added) "km-picker-row-added"),
        onclick = add_js,
        style = if (added) "opacity:0.55;cursor:default;" else NULL,
        div(class = "blr-main",
          div(class = "blr-name", row$concept_name),
          div(class = "blr-meta",
              paste0(row$vocabulary_id, ":", row$concept_code,
                     if (nzchar(row$concept_class_id %||% ""))
                       paste0(" \u00b7 ", row$concept_class_id) else ""))
        ),
        ce_badge,
        tags$div(class = "blr-pills", pill_block),
        if (added)
          tags$span(class = "km-picker-added-mark",
                    title = "Already added as outcome",
                    icon("check"))
          else
          tags$span(class = "km-picker-add-mark",
                    title = "Use as outcome", "+")
      )
    })
    tagList(
      sort_header,
      div(style = "padding:6px 2px 0;font-size:0.76rem;color:var(--dre-muted);line-height:1.55;",
        tags$span(
          tags$b(style = "color:var(--dre-text);", "Cohort"),
          " = your patients with this event after index (drives the curve). ",
          tags$b(style = "color:var(--dre-text);", "Persons / Records"),
          " = how common across the whole database."
        ),
        tags$span(style = "display:block;margin-top:1px;",
          tags$span(style = "color:#00C5B5;", "\u25CF"), " 25+ sufficient  \u00b7  ",
          tags$span(style = "color:#FFD166;", "\u25CF"), " under 25 sparse  \u00b7  ",
          tags$span(style = "color:#FF6B6B;", "\u25CF"), " 0 no curve")
      ),
      div(style = "padding:6px 0 4px;font-size:0.78rem;color:var(--dre-muted);",
          sprintf("%d concept%s \u00b7 click to use as outcome",
                  nrow(lst_view), if (nrow(lst_view) == 1) "" else "s")),
      div(class = "km-picker-list-body",
          style = "max-height:280px;overflow-y:auto;border:1px solid var(--dre-border);border-radius:6px;",
          do.call(tagList, rows))
    )
  })

  # KM-specific sort header helper (separate from main browser's because it
  # writes to km_picker_sort_click, not browser_sort_click).
  .render_km_sort_header <- function(col_keys, col_labels) {
    cur <- km_picker_sort_rv()
    parts <- strsplit(cur, ":", fixed = TRUE)[[1]]
    cur_col <- if (length(parts) >= 1) parts[1] else "persons"
    cur_dir <- if (length(parts) >= 2) parts[2] else "desc"
    cells <- lapply(seq_along(col_keys), function(i) {
      k <- col_keys[i]; lbl <- col_labels[i]
      active <- identical(k, cur_col)
      arrow <- if (active) {
        if (cur_dir == "desc") " \u25BE" else " \u25B4"
      } else ""
      tags$span(
        class = paste("bls-col", paste0("col-", k),
                      if (active) "active"),
        onclick = sprintf("Shiny.setInputValue('km_picker_sort_click',%s,{priority:'event'})",
                          jsonlite::toJSON(k, auto_unbox = TRUE)),
        paste0(lbl, arrow)
      )
    })
    do.call(div, c(list(class = "browser-list-sort-header"), cells))
  }

  # Add outcome from picker
  observeEvent(input$km_picker_add, {
    payload <- input$km_picker_add
    cid <- as.integer(payload$cid %||% NA_integer_)
    name <- as.character(payload$name %||% as.character(cid))
    if (is.na(cid)) return()
    current <- km_concepts_rv()
    if (!any(vapply(current, function(x) x$cid == cid, logical(1)))) {
      km_concepts_rv(c(current, list(list(cid = cid, name = name))))
      showNotification(sprintf("Outcome added: %s", name),
                       type = "message", duration = 2)
    }
  }, ignoreNULL = TRUE)

  observeEvent(input$km_remove_concept, {
    cid_val <- as.integer(input$km_remove_concept)
    km_concepts_rv(Filter(function(x) x$cid != cid_val, km_concepts_rv()))
  })

  output$km_selected_concepts_ui <- renderUI({
    concepts <- km_concepts_rv()
    if (length(concepts) == 0)
      return(tags$p(style="color:var(--dre-muted);font-size:0.84rem;margin:4px 0;",
                    "No outcomes selected - all domain events will be used."))
    tagList(
      tags$p(style="font-size:0.84rem;color:var(--dre-muted);margin:6px 0 4px;",
             sprintf("%d outcome concept%s selected:", length(concepts), if(length(concepts)==1) "" else "s")),
      div(style="display:flex;flex-wrap:wrap;gap:4px;",
        lapply(concepts, function(co) {
          div(class="km-concept-pill",
            tags$span(co$name),
            tags$span(class="cs-cid", paste0(" ", co$cid)),
            tags$span(class="rm-x",
              onclick=sprintf("Shiny.setInputValue('km_remove_concept',%d,{priority:'event'})", co$cid),
              "×")
          )
        })
      )
    )
  })

  # ── Standards survival (CohortSurvival) - cross-check beside native KM ──────
  # Reuses the KM outcome configuration (km_concepts_rv + km_use_desc). Requires
  # the current cohort to be materialised so the cdm can attach a target cohort
  # table; the schema is recovered from the "materialised|<schema>" signature.
  cs_surv_schema <- reactive({
    sig <- run_signature_rv()
    if (startsWith(sig, "materialised|")) {
      s <- sub("^materialised\\|", "", sig)
      if (length(ohdsi_discover_cohort_tables(s)) > 0) return(s)
    }
    # Fall back to any selected schema that physically holds a cohort table.
    # v11 materialised exports persist a definition, so a materialised cohort
    # can carry a definition-style signature (run_signature is then NOT
    # "materialised|..."); the reliable test is whether a cohort table exists.
    for (s in (input$schema_select %||% character(0)))
      if (length(ohdsi_discover_cohort_tables(s)) > 0) return(s)
    NULL
  })

  observeEvent(input$run_cs_surv_btn, {
    req(conn_valid())
    schema <- cs_surv_schema()
    if (is.null(schema)) {
      cs_surv_result_rv(NULL)
      cs_surv_status_rv(list(state = "gate",
        msg = "No materialised cohort table found in the selected schemas. Materialise the cohort (Export tab), or select the schema that holds it."))
      return()
    }
    tbls <- ohdsi_discover_cohort_tables(schema)
    if (length(tbls) == 0) {
      cs_surv_result_rv(NULL)
      cs_surv_status_rv(list(state = "gate",
        msg = paste0("No cohort table found in schema ", schema, ".")))
      return()
    }
    cohort_table <- if (any(tolower(tbls) == "cohort"))
      tbls[tolower(tbls) == "cohort"][1] else tbls[1]
    n_target <- tryCatch(as.integer(db_query(sprintf(
      "SELECT COUNT(*) AS n FROM %s", fq(schema, cohort_table)))$n[1]),
      error = function(e) NA_integer_)
    outcome_ids <- vapply(km_concepts_rv(), `[[`, integer(1), "cid")
    cm <- col_maps_rv()[[schema]] %||% omop_col_map_rv()

    cs_surv_result_rv(NULL)
    cs_surv_status_rv(list(state = "running"))
    run <- NULL
    withProgress(message = "Running standards survival (CohortSurvival)...",
                 value = 0.4, {
      cdm <- get_cohort_cdm(schema, cohort_table)
      tid <- ohdsi_target_cohort_id(schema, cohort_table)
      run <- run_standards_survival(
        cdm = cdm, cohort_table = cohort_table,
        outcome_concept_ids = outcome_ids,
        use_descendants = isTRUE(input$km_use_desc),
        schema = schema, col_map = cm, target_cohort_id = tid)
    })
    if (!is.null(run$error)) {
      cs_surv_status_rv(list(state = "error", msg = run$error)); return() }
    if (is.null(run$result)) {
      cs_surv_status_rv(list(state = "error",
        msg = "No survival result was produced.")); return() }
    cs_surv_result_rv(run$result)
    cs_surv_status_rv(list(state = "ok", n_outcome = run$n_outcome,
      target = sprintf("%s.%s", schema, cohort_table), n_target = n_target))
  })

  output$cs_surv_status <- renderUI({
    st <- cs_surv_status_rv()
    if (is.null(st))
      return(tags$p(style = "color:var(--dre-muted);font-size:0.87rem;margin:0;",
        "Configure the outcome in the KM card above, materialise the cohort, then run the standards check to compare against the native curve."))
    if (identical(st$state, "running"))
      return(tags$p(style = "color:var(--dre-teal);margin:0;",
        icon("spinner", class = "fa-spin"),
        " Generating outcome cohort and estimating survival..."))
    if (identical(st$state, "gate"))
      return(tags$div(style = "color:var(--dre-muted);font-size:0.9rem;margin:0;",
        icon("circle-info"), " ", st$msg))
    if (identical(st$state, "error"))
      return(tags$div(style = "color:#FFB4A2;font-size:0.9rem;margin:0;",
        icon("triangle-exclamation"), " ", st$msg))
    if (identical(st$state, "ok")) {
      n   <- st$n_outcome
      tgt <- if (!is.null(st$target)) {
        nt <- if (!is.null(st$n_target) && !is.na(st$n_target))
          sprintf(" (%s rows)", format(st$n_target, big.mark = ",")) else ""
        sprintf(" Target: %s%s.", st$target, nt)
      } else ""
      sub <- if (!is.null(n) && !is.na(n))
        sprintf(" %s outcome record(s) identified.", format(n, big.mark = ",")) else ""
      return(tags$p(style = "color:var(--dre-muted);font-size:0.87rem;margin:0;",
        icon("check", style = "color:var(--dre-teal);"),
        " CohortSurvival Kaplan-Meier estimate.", tgt, sub))
    }
    NULL
  })

  output$cs_surv_plot <- renderPlot({
    r <- cs_surv_result_rv(); req(!is.null(r))
    p <- tryCatch(CohortSurvival::plotSurvival(r), error = function(e) NULL)
    if (is.null(p)) {
      plot.new()
      text(0.5, 0.5, "Plot unavailable for this result.", col = "#8BA3B5")
    } else p
  }, height = 420)

  output$cs_surv_tbl <- ohdsi_table_render(function() cs_surv_result_rv(), "survival")

  # ── Standards incidence & prevalence (IncidencePrevalence) ─────────────────
  # Reuses the materialised-cohort gate (cs_surv_schema) and the KM outcome
  # concepts. Denominator is restricted to the cohort, so these are within-cohort
  # rates over calendar time.
  observeEvent(input$run_ip_btn, {
    req(conn_valid())
    schema <- cs_surv_schema()
    if (is.null(schema)) {
      ip_inc_rv(NULL); ip_prev_rv(NULL)
      ip_status_rv(list(state = "gate",
        msg = "No materialised cohort table found in the selected schemas. Materialise the cohort (Export tab), or select the schema that holds it."))
      return()
    }
    tbls <- ohdsi_discover_cohort_tables(schema)
    if (length(tbls) == 0) {
      ip_inc_rv(NULL); ip_prev_rv(NULL)
      ip_status_rv(list(state = "gate",
        msg = paste0("No cohort table found in schema ", schema, ".")))
      return()
    }
    cohort_table <- if (any(tolower(tbls) == "cohort"))
      tbls[tolower(tbls) == "cohort"][1] else tbls[1]
    outcome_ids <- vapply(km_concepts_rv(), `[[`, integer(1), "cid")
    cm   <- col_maps_rv()[[schema]] %||% omop_col_map_rv()
    intv <- input$ip_interval %||% "years"

    ip_inc_rv(NULL); ip_prev_rv(NULL)
    ip_status_rv(list(state = "running"))
    run <- NULL
    withProgress(message = "Estimating incidence and prevalence (IncidencePrevalence)...",
                 value = 0.4, {
      cdm <- get_cohort_cdm(schema, cohort_table)
      tid <- ohdsi_target_cohort_id(schema, cohort_table)
      run <- run_incidence_prevalence(
        cdm = cdm, cohort_table = cohort_table,
        outcome_concept_ids = outcome_ids,
        use_descendants = isTRUE(input$km_use_desc),
        schema = schema, col_map = cm, target_cohort_id = tid,
        interval = intv)
    })
    if (!is.null(run$error)) {
      ip_status_rv(list(state = "error", msg = run$error)); return() }
    ip_inc_rv(run$incidence)
    ip_prev_rv(run$prevalence)
    ip_status_rv(list(state = "ok",
      target    = sprintf("%s.%s", schema, cohort_table),
      has_inc   = !is.null(run$incidence),
      has_prev  = !is.null(run$prevalence),
      prev_note = run$prev_note))
  })

  output$ip_status <- renderUI({
    st <- ip_status_rv()
    if (is.null(st))
      return(tags$p(style = "color:var(--dre-muted);font-size:0.87rem;margin:0;",
        "Uses the same outcome and materialised cohort as the curves above. Estimates incidence rates and period prevalence of the outcome within the cohort over calendar time."))
    if (identical(st$state, "running"))
      return(tags$p(style = "color:var(--dre-teal);margin:0;",
        icon("spinner", class = "fa-spin"),
        " Generating denominator and outcome cohorts, then estimating..."))
    if (identical(st$state, "gate"))
      return(tags$div(style = "color:var(--dre-muted);font-size:0.9rem;margin:0;",
        icon("circle-info"), " ", st$msg))
    if (identical(st$state, "error"))
      return(tags$div(style = "color:#FFB4A2;font-size:0.9rem;margin:0;",
        icon("triangle-exclamation"), " ", st$msg))
    if (identical(st$state, "ok")) {
      miss <- character(0)
      if (!isTRUE(st$has_inc))  miss <- c(miss, "incidence")
      if (!isTRUE(st$has_prev) && is.null(st$prev_note)) miss <- c(miss, "prevalence")
      warn <- if (length(miss) > 0)
        sprintf(" (%s unavailable for this cohort, see server log)",
                paste(miss, collapse = " and ")) else ""
      note <- if (!is.null(st$prev_note))
        tags$div(style = "color:var(--dre-muted);font-size:0.82rem;margin-top:4px;",
                 icon("circle-info"), " ", st$prev_note) else NULL
      return(tagList(
        tags$p(style = "color:var(--dre-muted);font-size:0.87rem;margin:0;",
          icon("check", style = "color:var(--dre-teal);"),
          sprintf(" Estimated within %s.", st$target %||% "the cohort"), warn),
        note))
    }
    NULL
  })

  output$ip_inc_plot <- renderPlot({
    r <- ip_inc_rv(); req(!is.null(r))
    p <- tryCatch(IncidencePrevalence::plotIncidence(r), error = function(e) NULL)
    if (is.null(p)) {
      plot.new(); text(0.5, 0.5, "Incidence plot unavailable.", col = "#8BA3B5")
    } else p
  }, height = 360)

  output$ip_inc_tbl  <- ohdsi_table_render(function() ip_inc_rv(),  "incidence")

  output$ip_prev_plot <- renderPlot({
    r <- ip_prev_rv(); req(!is.null(r))
    p <- tryCatch(IncidencePrevalence::plotPrevalence(r), error = function(e) NULL)
    if (is.null(p)) {
      plot.new(); text(0.5, 0.5, "Prevalence plot unavailable.", col = "#8BA3B5")
    } else p
  }, height = 360)

  output$ip_prev_tbl <- ohdsi_table_render(function() ip_prev_rv(), "prevalence")

  # ── KM pre-flight: live event-count preview for the configured outcome ──────
  # Reuses query_survival_data so the preview count exactly matches the eventual
  # run (no drift). Debounced to coalesce rapid concept/mode/descendant changes.
  km_preflight <- debounce(reactive({
    res      <- cohort_result_rv()
    concepts <- km_concepts_rv()
    if (is.null(res) || nrow(res) == 0) return(list(state = "no_cohort"))
    if (length(concepts) == 0)          return(list(state = "no_concept"))

    domain <- input$km_outcome_domain
    if (is.null(domain) || !nzchar(domain)) return(list(state = "no_concept"))
    cids <- vapply(concepts, function(x) as.integer(x$cid), integer(1))
    mode <- input$km_outcome_mode %||% "recurrence"
    desc <- isTRUE(input$km_use_desc)

    schemas <- isolate(input$schema_select) %||% character(0)
    if (length(schemas) == 0) schemas <- ""
    if (!"source_schema" %in% names(res)) res$source_schema <- schemas[[1]]

    n_events <- 0L; n_at_risk <- 0L; any_ok <- FALSE
    for (sch in schemas) {
      sub <- res[res$source_schema == sch, , drop = FALSE]
      if (nrow(sub) == 0) next
      cm <- col_maps_rv()[[sch]] %||% omop_col_map_rv()
      sd <- tryCatch(query_survival_data(sch, cm, sub, domain, cids, desc, mode),
                     error = function(e) NULL)
      if (!is.null(sd) && nrow(sd) > 0) {
        any_ok    <- TRUE
        n_events  <- n_events  + sum(sd$status == 1L)
        n_at_risk <- n_at_risk + nrow(sd)
      }
    }
    if (!any_ok) return(list(state = "unavailable"))
    list(state = "ready", n_events = n_events, n_at_risk = n_at_risk, mode = mode)
  }), millis = 600)

  output$km_preflight_ui <- renderUI({
    pf  <- km_preflight()
    box <- function(border, body)
      tags$div(style = sprintf("border-left:3px solid %s;background:rgba(255,255,255,0.03);padding:8px 12px;margin:4px 0 12px;border-radius:4px;font-size:0.87rem;", border), body)
    if (identical(pf$state, "no_cohort"))
      return(box("var(--dre-border)", tags$span(style = "color:var(--dre-muted);",
        icon("circle-info"), " Run a cohort first to preview how many events your outcome will yield.")))
    if (identical(pf$state, "no_concept"))
      return(box("var(--dre-border)", tags$span(style = "color:var(--dre-muted);",
        icon("circle-info"), " Add an outcome concept to preview its event count before running.")))
    if (identical(pf$state, "unavailable"))
      return(box("var(--dre-border)", tags$span(style = "color:var(--dre-muted);",
        icon("circle-info"), " Event preview unavailable for this outcome (domain table not found).")))
    if (identical(pf$state, "ready")) {
      n   <- pf$n_events; atr <- pf$n_at_risk
      pct <- if (atr > 0) round(100 * n / atr) else 0
      v <- if (n == 0)      list(c = "#FF6B6B", t = "No events. This outcome produces no curve in this mode. Pick a different concept, or switch to Recurrence.")
           else if (n < 10) list(c = "#FF9E80", t = "Very few events. The curve will be highly unstable. Consider a more common outcome.")
           else if (n < 25) list(c = "#FFD166", t = "Sparse. The curve will be steppy with wide confidence intervals, especially at the tail.")
           else             list(c = "#00C5B5", t = "Sufficient for a stable estimate.")
      mode_note <- if (identical(pf$mode, "first"))
        " Incident mode: patients with prior history are excluded from the at-risk count." else ""
      box(v$c, tagList(
        tags$span(style = "color:var(--dre-text);font-weight:600;",
          sprintf("%s event%s across %s at-risk patient%s (%s%%).",
                  format(n, big.mark = ","), if (n == 1) "" else "s",
                  format(atr, big.mark = ","), if (atr == 1) "" else "s", pct)),
        tags$span(style = sprintf("color:%s;", v$c), paste0(" ", v$t)),
        if (nzchar(mode_note)) tags$span(style = "color:var(--dre-muted);", mode_note)
      ))
    }
  })

  observeEvent(input$run_km_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type = "warning"); return()
    }
    req(conn_valid())

    # Overlap gate: when schemas have no observation-period overlap, refuse
    # to plot a pooled days-from-index curve unless the user has explicitly
    # acknowledged the limitation via the banner above.
    if (overlap_gate_blocks(overlap_rv(), proceed_km_rv())) {
      showNotification(
        "Acknowledge the no-overlap banner above to run KM across these schemas.",
        type = "warning", duration = 6)
      return()
    }

    schemas    <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi      <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res)

    cohort_by_schema <- if (multi) split(res, res$source_schema)
                       else setNames(list(res), schemas[[1]] %||% "")

    # Concept IDs from km_concepts_rv picker
    concept_ids <- vapply(km_concepts_rv(), `[[`, integer(1), "cid")

    # When stratifying by prior history we need both arms (naive + experienced)
    # present, so force recurrence-mode data regardless of the outcome toggle;
    # the stratification itself provides the incidence-vs-recurrence split.
    strat0   <- input$km_stratum %||% "none"
    eff_mode <- if (identical(strat0, "prior_history")) "recurrence"
                else (input$km_outcome_mode %||% "recurrence")

    survival_rv(list(state = "running"))
    withProgress(message = "Running Kaplan-Meier...", value = 0.4, {
      surv_per_schema <- lapply(names(cohort_by_schema), function(sch) {
        cm  <- col_maps_l[[sch]] %||% omop_col_map_rv()
        sub <- cohort_by_schema[[sch]]
        sd  <- tryCatch(
          query_survival_data(sch, cm, sub,
                              outcome_domain       = input$km_outcome_domain,
                              outcome_concept_ids  = concept_ids,
                              use_descendants      = isTRUE(input$km_use_desc),
                              outcome_mode         = eff_mode),
          error = function(e) {
            showNotification(paste("KM query error (", sch, "): ", e$message),
                             type = "warning"); NULL })
        if (!is.null(sd) && nrow(sd) > 0) sd$source_schema <- sch
        sd
      })
    })
    surv_data <- do.call(rbind, Filter(Negate(is.null), surv_per_schema))
    if (is.null(surv_data) || nrow(surv_data) == 0) {
      showNotification("No survival data returned from any schema.", type = "error")
      survival_rv(NULL); return()
    }

    # Compute KM fit - optional stratification.
    # If user selected "none" and we're in multi-mode, stratify by source_schema
    # so the curves are visibly separate per schema. Otherwise honour the
    # user's choice and pool across schemas for that stratification.
    km_fit <- tryCatch({
      horizon <- suppressWarnings(as.integer(input$km_time_horizon))
      if (!is.na(horizon) && horizon > 0)
        surv_data$time <- pmin(surv_data$time, horizon)

      stratum_choice <- input$km_stratum %||% "none"

      if (stratum_choice == "none" && multi) {
        surv_data$stratum <- surv_data$source_schema
        stratum <- "source_schema"
      } else if (stratum_choice == "sex") {
        # Look up sex from every selected schema's person table
        sex_rows <- do.call(rbind, Filter(Negate(is.null), lapply(
          names(cohort_by_schema), function(sch) {
            cm <- col_maps_l[[sch]] %||% omop_col_map_rv()
            if (!"person" %in% tolower(get_tables(sch))) return(NULL)
            pids <- if (multi) surv_data$person_id[surv_data$source_schema == sch]
                    else surv_data$person_id
            if (length(pids) == 0) return(NULL)
            pid_col <- ac(cm, "person", "person_id")
            sex_col <- ac(cm, "person", "gender_concept_id")
            r <- tryCatch(db_query(sprintf(
              "SELECT %s AS person_id, %s AS gender_concept_id FROM %s WHERE %s IN (%s)",
              pid_col, sex_col, fq(sch, "person"), pid_col, pid_sql(pids))),
              error = function(e) NULL)
            if (!is.null(r)) {
              names(r) <- tolower(names(r))
              r$source_schema <- sch
            }
            r
          })))
        if (!is.null(sex_rows) && nrow(sex_rows) > 0) {
          lab <- ifelse(sex_rows$gender_concept_id == 8507L, "Male",
                 ifelse(sex_rows$gender_concept_id == 8532L, "Female", "Unknown"))
          sex_key <- paste(as.character(as_pid(sex_rows$person_id)),
                           sex_rows$source_schema, sep = "|")
          sex_map <- setNames(lab, sex_key)
          surv_key <- if (multi)
            paste(as.character(as_pid(surv_data$person_id)),
                  surv_data$source_schema, sep = "|")
          else
            paste(as.character(as_pid(surv_data$person_id)),
                  surv_data$source_schema %||% "", sep = "|")
          surv_data$stratum <- sex_map[surv_key]
          surv_data$stratum[is.na(surv_data$stratum)] <- "Unknown"
          stratum <- "sex"
        } else stratum <- "none"
      } else if (stratum_choice == "age_group") {
        res_all <- cohort_result_rv()
        yob_rows <- do.call(rbind, Filter(Negate(is.null), lapply(
          names(cohort_by_schema), function(sch) {
            cm <- col_maps_l[[sch]] %||% omop_col_map_rv()
            if (!"person" %in% tolower(get_tables(sch))) return(NULL)
            pids <- if (multi) surv_data$person_id[surv_data$source_schema == sch]
                    else surv_data$person_id
            if (length(pids) == 0) return(NULL)
            pid_col <- ac(cm, "person", "person_id")
            yob_col <- ac(cm, "person", "year_of_birth")
            r <- tryCatch(db_query(sprintf(
              "SELECT %s AS person_id, %s AS year_of_birth FROM %s WHERE %s IN (%s)",
              pid_col, yob_col, fq(sch, "person"), pid_col, pid_sql(pids))),
              error = function(e) NULL)
            if (!is.null(r)) {
              names(r) <- tolower(names(r))
              r$source_schema <- sch
            }
            r
          })))
        if (!is.null(yob_rows) && nrow(yob_rows) > 0) {
          idx_yr <- as.integer(format(as.Date(
            res_all$index_date[
              match(paste(as.character(as_pid(surv_data$person_id)),
                          surv_data$source_schema %||% "", sep = "|"),
                    paste(as.character(as_pid(res_all$person_id)),
                          res_all$source_schema %||% "", sep = "|"))]), "%Y"))
          yob_key <- paste(as.character(as_pid(yob_rows$person_id)),
                           yob_rows$source_schema, sep = "|")
          yob_map <- setNames(as.integer(yob_rows$year_of_birth), yob_key)
          surv_key <- paste(as.character(as_pid(surv_data$person_id)),
                            surv_data$source_schema %||% "", sep = "|")
          ages <- idx_yr - yob_map[surv_key]
          surv_data$stratum <- ifelse(is.na(ages), "Unknown",
                               ifelse(ages < 40, "<40",
                               ifelse(ages < 65, "40-64", "65+")))
          stratum <- "age_group"
        } else stratum <- "none"
      } else if (stratum_choice == "prior_history") {
        prior_rows <- do.call(rbind, Filter(Negate(is.null), lapply(
          names(cohort_by_schema), function(sch) {
            cm  <- col_maps_l[[sch]] %||% omop_col_map_rv()
            sub <- cohort_by_schema[[sch]]
            ph  <- query_prior_history_pids(sch, cm, sub,
                     outcome_domain      = input$km_outcome_domain,
                     outcome_concept_ids = concept_ids,
                     use_descendants     = isTRUE(input$km_use_desc))
            data.frame(
              person_id     = as.character(as_pid(sub$person_id)),
              source_schema = sch,
              prior         = as.character(as_pid(sub$person_id)) %in% ph,
              stringsAsFactors = FALSE)
          })))
        if (!is.null(prior_rows) && nrow(prior_rows) > 0) {
          prior_key <- paste(prior_rows$person_id, prior_rows$source_schema, sep = "|")
          prior_map <- setNames(prior_rows$prior, prior_key)
          surv_key  <- paste(as.character(as_pid(surv_data$person_id)),
                             surv_data$source_schema %||% "", sep = "|")
          has_prior <- prior_map[surv_key]
          has_prior[is.na(has_prior)] <- FALSE
          surv_data$stratum <- ifelse(has_prior,
            "Recurrence (prior history)", "First incidence (no prior history)")
          stratum <- "prior_history"
        } else stratum <- "none"
      } else {
        stratum <- "none"
      }

      if (stratum != "none" && "stratum" %in% names(surv_data)) {
        survfit(Surv(time, status) ~ stratum, data = surv_data)
      } else {
        survfit(Surv(time, status) ~ 1, data = surv_data)
      }
    }, error = function(e) {
      showNotification(paste("KM fit error:", e$message), type = "error"); NULL })

    survival_rv(list(
      state         = "done",
      fit           = km_fit,
      data          = surv_data,
      n_total       = nrow(surv_data),
      n_events      = sum(surv_data$status == 1L),
      domain        = input$km_outcome_domain,
      concept_names = vapply(km_concepts_rv(),
                              function(x) as.character(x$name %||% x$cid),
                              character(1)),
      stratum       = if (exists("stratum", inherits = FALSE)) stratum else "none",
      multi         = multi,
      mode          = eff_mode,
      schemas       = schemas
    ))
  })

  output$km_status_ui <- renderUI({
    sv <- survival_rv()
    if (is.null(sv)) return(NULL)
    if (identical(sv$state, "running"))
      return(div(style = "color:var(--dre-muted);font-size:0.87rem;margin:8px 0;",
                 icon("spinner"), " Computing..."))
    if (identical(sv$state, "done"))
      return(div(style = "color:var(--dre-success);font-size:0.87rem;margin:8px 0;",
        icon("circle-check"),
        sprintf(" KM complete - %s persons, %s events (%s%%)",
                format(sv$n_total,  big.mark=","),
                format(sv$n_events, big.mark=","),
                round(100 * sv$n_events / max(sv$n_total, 1)))))
    NULL
  })

  km_plot_obj <- reactive({
    sv <- survival_rv()
    empty_plot <- function(msg) {
      ggplot2::ggplot() +
        ggplot2::annotate("text", x=0.5, y=0.5, label=msg, colour="#8BA3B5", size=4) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341", colour=NA))
    }
    if (is.null(sv) || !identical(sv$state, "done"))
      return(empty_plot("Configure the outcome above and click Run KM Analysis"))
    if (is.null(sv$fit))
      return(empty_plot("KM fit failed - check server log"))

    fit       <- sv$fit
    dom_label <- DOMAINS[[sv$domain]]$label %||% sv$domain
    # Bug 9 fix (v8.6): plot titles previously used the domain category
    # ("Diagnoses & Conditions") instead of the specific outcome concept(s).
    # Build a concept-aware label: one concept → use its name; two →
    # "A & B"; more → "first plus N others"; none → fall back to domain.
    outcome_label <- local({
      nm <- sv$concept_names %||% character(0)
      nm <- nm[nzchar(nm)]
      if (length(nm) == 0) dom_label
      else if (length(nm) == 1) nm
      else if (length(nm) == 2) paste(nm, collapse = " & ")
      else sprintf("%s plus %d others", nm[1], length(nm) - 1)
    })
    stratified <- isTRUE(sv$stratum != "none") && length(fit$strata) > 0
    STRATUM_COLS <- c("#00C5B5","#FFB84D","#E05C6E","#A78BFA","#34D399")

    # Human-readable stratum name for titles and legend
    stratum_label <- switch(sv$stratum %||% "",
      source_schema = "schema",
      age_group     = "age group",
      sex           = "sex",
      prior_history = "prior history",
      sv$stratum %||% "")

    mode_lbl <- if (identical(sv$mode %||% "recurrence", "first"))
      "First occurrence (incident, prior history excluded)"
    else
      "Recurrence (first occurrence at/after index)"

    if (stratified) {
      strata_names <- names(fit$strata)
      n_strata     <- length(strata_names)
      km_list <- lapply(seq_len(n_strata), function(si) {
        idx <- seq(
          if (si == 1) 1 else sum(fit$strata[seq_len(si-1)]) + 1,
          sum(fit$strata[seq_len(si)]))
        lbl <- sub("^stratum=", "", strata_names[si])
        data.frame(time=c(0, fit$time[idx]), surv=c(1, fit$surv[idx]),
                   upper=c(1, fit$upper[idx]), lower=c(1, fit$lower[idx]),
                   stratum=lbl, stringsAsFactors=FALSE)
      })
      km_df <- do.call(rbind, km_list)
      km_df <- km_df[!is.na(km_df$surv), ]
      cols  <- setNames(STRATUM_COLS[seq_len(n_strata)],
                        unique(km_df$stratum))
      p <- ggplot2::ggplot(km_df, ggplot2::aes(x=time, y=surv,
                                                colour=stratum, fill=stratum)) +
        ggplot2::geom_ribbon(ggplot2::aes(ymin=lower, ymax=upper),
                             alpha=0.12, colour=NA) +
        ggplot2::geom_step(linewidth=1) +
        ggplot2::scale_colour_manual(values=cols, name=stratum_label) +
        ggplot2::scale_fill_manual(  values=cols, name=stratum_label) +
        ggplot2::scale_y_continuous(labels=scales::percent_format(accuracy=1),
                                     limits=c(0,1), expand=c(0.01,0)) +
        ggplot2::scale_x_continuous(labels=function(x) format(x, big.mark=","),
                                     expand=c(0.01,0)) +
        ggplot2::labs(x="Days from index", y="Event-free survival",
                      title=paste0("Kaplan-Meier - time to first ", outcome_label,
                                   " by ", stratum_label),
                      subtitle=sprintf("N=%s  |  Events=%s",
                        format(sv$n_total, big.mark=","),
                        format(sv$n_events, big.mark=",")),
                      caption=paste0("Shaded bands: 95% CI  |  Censoring at end of observation period  |  ", mode_lbl)) +
        theme_dre() +
        ggplot2::theme(legend.position="right")
    } else {
      km_df <- data.frame(time=c(0,fit$time), surv=c(1,fit$surv),
                           upper=c(1,fit$upper), lower=c(1,fit$lower))
      km_df <- km_df[!is.na(km_df$surv), ]
      median_t <- tryCatch(summary(fit)$table["median"], error=function(e) NA_real_)
      # Bug 8 fix (v8.6): when the survival curve never crosses 0.5 within
      # the follow-up window, summary(fit)$table["median"] returns NA.
      # Previously the subtitle substituted 0, displaying "Median=0 days"
      # - clinically misleading (suggests every patient had an immediate
      # event). Show "Not reached" instead.
      median_lbl <- if (is.na(median_t) || !is.finite(median_t))
                      "Not reached"
                    else
                      sprintf("%s days", format(round(median_t), big.mark = ","))
      p <- ggplot2::ggplot(km_df, ggplot2::aes(x=time, y=surv)) +
        ggplot2::geom_ribbon(ggplot2::aes(ymin=lower, ymax=upper),
                             fill="#00C5B540", colour=NA) +
        ggplot2::geom_step(colour="#00C5B5", linewidth=1) +
        ggplot2::scale_y_continuous(labels=scales::percent_format(accuracy=1),
                                     limits=c(0,1), expand=c(0.01,0)) +
        ggplot2::scale_x_continuous(labels=function(x) format(x, big.mark=","),
                                     expand=c(0.01,0)) +
        ggplot2::labs(x="Days from index", y="Event-free survival probability",
                      title=paste0("Kaplan-Meier - time to first ", outcome_label),
                      subtitle=sprintf("N=%s  |  Events=%s  |  Median=%s",
                        format(sv$n_total, big.mark=","),
                        format(sv$n_events, big.mark=","),
                        median_lbl),
                      caption=paste0("Shaded area: 95% CI  |  Censoring at end of observation period  |  ", mode_lbl)) +
        theme_dre()
      if (!is.na(median_t) && is.finite(median_t) && median_t > 0)
        p <- p +
          ggplot2::geom_vline(xintercept=median_t, colour="#FFB84D",
                              linewidth=0.7, linetype="dashed") +
          ggplot2::annotate("text", x=median_t, y=0.1,
                            label=sprintf("Median\n%.0f d", median_t),
                            colour="#FFB84D", hjust=-0.1, size=3.8)
    }
    p
  })
  output$km_plot <- renderPlot(km_plot_obj(), res = PLOT_RES, bg = "#0B2341")

  .km_code <- function() {
    sv <- survival_rv()
    if (is.null(sv) || !identical(sv$state, "done") ||
        is.null(sv$data) || nrow(sv$data) == 0)
      return("# Run KM analysis first to generate a code snippet.")
    cohort_block <- .cohort_sql_block()
    if (is.null(cohort_block))
      return("# Cohort SQL not available - build at least one inclusion criterion first.")

    schemas    <- input$schema_select %||% character(0)
    cohort_nm  <- input$cohort_name %||% "my_cohort"
    outcomes   <- vapply(km_concepts_rv(), function(x) x$name, character(1))
    outcome_ids <- vapply(km_concepts_rv(), function(x) as.integer(x$cid), integer(1))
    outcome_domain <- input$km_outcome_domain %||% "condition"
    use_desc   <- isTRUE(input$km_use_desc)
    horizon    <- input$km_time_horizon
    col_maps_l <- col_maps_rv()
    multi      <- length(schemas) > 1
    dom        <- DOMAINS[[outcome_domain]]
    if (is.null(dom))
      return("# Outcome domain not recognised.")

    # Render per-schema query template
    .schema_query <- function(sch) {
      cm <- col_maps_l[[sch]] %||% omop_col_map_rv()
      pid_col <- ac(cm, dom$table, dom$person_col)
      dat_col <- ac(cm, dom$table, dom$date_col)
      cid_col <- ac(cm, dom$table, dom$concept_col)
      op_pid  <- ac(cm, "observation_period", "person_id")
      op_end  <- ac(cm, "observation_period", "observation_period_end_date")

      # Concept filter SQL - descendants or direct
      if (length(outcome_ids) > 0) {
        ids_c <- paste(outcome_ids, collapse = ", ")
        if (use_desc) {
          anc_col  <- ac(cm, "concept_ancestor", "ancestor_concept_id")
          desc_col <- ac(cm, "concept_ancestor", "descendant_concept_id")
          concept_filter <- sprintf(
            "AND t.%s IN (SELECT %s FROM \"%s\".\"concept_ancestor\" WHERE %s IN (%s))",
            cid_col, desc_col, sch, anc_col, ids_c)
        } else {
          concept_filter <- sprintf("AND t.%s IN (%s)", cid_col, ids_c)
        }
      } else {
        concept_filter <- ""
      }

      sprintf(
'WITH idx(person_id, index_date) AS (VALUES %%s),
     outcomes AS (
       SELECT t.%s AS person_id,
              MIN(t.%s::date) AS event_date
       FROM   "%s"."%s" t
       JOIN   idx ON idx.person_id = t.%s
       WHERE  t.%s::date >= idx.index_date
         %s
       GROUP  BY 1
     ),
     censoring AS (
       SELECT op.%s AS person_id,
              MAX(op.%s::date) AS censor_date
       FROM   "%s"."observation_period" op
       JOIN   idx ON idx.person_id = op.%s
       WHERE  op.%s::date >= idx.index_date
       GROUP  BY 1
     )
SELECT i.person_id,
       i.index_date,
       COALESCE(o.event_date, c.censor_date, i.index_date) AS end_date,
       CASE WHEN o.person_id IS NOT NULL THEN 1 ELSE 0 END AS status
FROM   idx i
LEFT JOIN outcomes  o ON o.person_id = i.person_id
LEFT JOIN censoring c ON c.person_id = i.person_id',
        pid_col, dat_col, sch, dom$table, pid_col, dat_col, concept_filter,
        op_pid, op_end, sch, op_pid, op_end)
    }

    header <- sprintf(paste0(
      "# ──────────────────────────────────────────────────────────────────────\n",
      "# Kaplan-Meier survival curve\n",
      "# Cohort:    %s\n",
      "# Schemas:   %s\n",
      "# Domain:    %s%s\n",
      "# Outcomes:  %s\n",
      "# Time horizon (days): %s\n",
      "# Generated: %s\n",
      "#\n",
      "# Self-contained: builds the cohort, queries the outcome event per\n",
      "# schema with observation_period for censoring, computes time-to-event,\n",
      "# fits Kaplan-Meier, plots the curve.\n",
      "# ──────────────────────────────────────────────────────────────────────\n"),
      cohort_nm,
      paste(schemas, collapse = ", "),
      dom$label %||% outcome_domain,
      if (use_desc) " (with descendants)" else "",
      if (length(outcomes) == 0) "(all events in domain)" else paste(outcomes, collapse = ", "),
      if (is.null(horizon) || is.na(horizon) || horizon == "") "(all)" else as.character(horizon),
      format(Sys.time(), "%Y-%m-%d %H:%M:%S"))

    if (multi) {
      query_lines <- vapply(schemas, function(sch) {
        sprintf('  %s = r"---(%s)---"', deparse(sch), .schema_query(sch))
      }, character(1))
      query_block <- sprintf("queries <- list(\n%s\n)",
                              paste(query_lines, collapse = ",\n"))
      per_schema_loop <- '
per_schema_km <- lapply(names(queries), function(sch) {
  sub <- cohort_result[cohort_result$source_schema == sch, , drop = FALSE]
  if (nrow(sub) == 0) return(NULL)
  vals <- paste(
    sprintf("(%.0f, \'%s\'::date)",
            as.numeric(sub$person_id),
            as.character(as.Date(sub$index_date))),
    collapse = ", ")
  sql <- sprintf(queries[[sch]], vals)
  r <- DBI::dbGetQuery(xap.conn, sql)
  if (is.null(r) || nrow(r) == 0) return(NULL)
  names(r) <- tolower(names(r))
  r$source_schema <- sch
  r
})
surv_data <- do.call(rbind, per_schema_km)
'
    } else {
      query_block <- sprintf('single_query <- r"---(%s)---"', .schema_query(schemas[1]))
      per_schema_loop <- '
vals <- paste(
  sprintf("(%.0f, \'%s\'::date)",
          as.numeric(cohort_result$person_id),
          as.character(as.Date(cohort_result$index_date))),
  collapse = ", ")
sql <- sprintf(single_query, vals)
surv_data <- DBI::dbGetQuery(xap.conn, sql)
names(surv_data) <- tolower(names(surv_data))
'
    }

    horizon_block <- if (!is.null(horizon) && !is.na(suppressWarnings(as.integer(horizon)))) {
      sprintf('
# Apply time horizon (clamp time-at-risk)
horizon <- %dL
surv_data$time <- pmin(surv_data$time, horizon)
', as.integer(horizon))
    } else ""

    chart_body <- sprintf('
# ── 3. Query the outcome event + observation_period per schema ───────────
library(DBI)
library(survival)
library(ggplot2)

%s

%s

# Compute time-to-event (days). status: 1 = event, 0 = censored.
surv_data$time <- as.integer(as.Date(surv_data$end_date) -
                              as.Date(surv_data$index_date))
surv_data$time[surv_data$time < 0] <- 0
surv_data <- surv_data[, c("person_id", "time", "status",
                            if ("source_schema" %%in%% names(surv_data)) "source_schema")]
%s
', query_block, per_schema_loop, horizon_block)

    plot_body <- if (multi) '
# ── 4. Fit KM by schema and plot ─────────────────────────────────────────
# Even though the cohort was defined as multi-schema, one or more schemas
# may have returned no rows (concept IDs may not exist in every schema).
# Detect runtime collapse to a single stratum and switch to a non-strat
# fit, otherwise survfit returns fit$strata=NULL and the data.frame call
# below crashes with "arguments imply differing number of rows".
schemas_present <- unique(surv_data$source_schema)
if (length(schemas_present) >= 2) {
  surv_data$stratum <- surv_data$source_schema
  fit <- survfit(Surv(time, status) ~ stratum, data = surv_data)
  strata_names <- rep(names(fit$strata), fit$strata)
  plot_df <- data.frame(
    time = fit$time, surv = fit$surv,
    lower = fit$lower, upper = fit$upper,
    stratum = sub("^stratum=", "", strata_names))

  ggplot(plot_df, aes(x = time, y = surv, colour = stratum, fill = stratum)) +
    geom_step(linewidth = 0.9) +
    geom_ribbon(aes(ymin = lower, ymax = upper), alpha = 0.15, linetype = 0) +
    scale_y_continuous(limits = c(0, 1),
                       labels = scales::percent_format(accuracy = 1)) +
    labs(x = "Days from index", y = "Survival probability",
         colour = "Schema", fill = "Schema") +
    theme_minimal()
} else {
  message(sprintf("Note: only one schema returned data (%s) - plotting as single curve.",
                   schemas_present[1]))
  fit <- survfit(Surv(time, status) ~ 1, data = surv_data)
  plot_df <- data.frame(time = fit$time, surv = fit$surv,
                        lower = fit$lower, upper = fit$upper)
  ggplot(plot_df, aes(x = time, y = surv)) +
    geom_step(colour = "#00C5B5", linewidth = 0.9) +
    geom_ribbon(aes(ymin = lower, ymax = upper),
                fill = "#00C5B5", alpha = 0.15, linetype = 0) +
    scale_y_continuous(limits = c(0, 1),
                       labels = scales::percent_format(accuracy = 1)) +
    labs(x = "Days from index", y = "Survival probability",
         subtitle = sprintf("Schema: %s only", schemas_present[1])) +
    theme_minimal()
}
' else '
# ── 4. Fit KM and plot ───────────────────────────────────────────────────
fit <- survfit(Surv(time, status) ~ 1, data = surv_data)
plot_df <- data.frame(time = fit$time, surv = fit$surv,
                      lower = fit$lower, upper = fit$upper)

ggplot(plot_df, aes(x = time, y = surv)) +
  geom_step(colour = "#00C5B5", linewidth = 0.9) +
  geom_ribbon(aes(ymin = lower, ymax = upper),
              fill = "#00C5B5", alpha = 0.15, linetype = 0) +
  scale_y_continuous(limits = c(0, 1),
                     labels = scales::percent_format(accuracy = 1)) +
  labs(x = "Days from index", y = "Survival probability") +
  theme_minimal()
'

    paste0(header, cohort_block, chart_body, plot_body)
  }

  chart_register("km_curve", "Kaplan-Meier survival curve",
                 plot_fn = km_plot_obj,
                 code_fn = .km_code,
                 width = 12, height = 7)

  # ── CIF observer ─────────────────────────────────────────────────────────────
  observeEvent(input$run_cif_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type = "warning"); return()
    }
    req(conn_valid())

    if (overlap_gate_blocks(overlap_rv(), proceed_cif_rv())) {
      showNotification(
        "Acknowledge the no-overlap banner above to run CIF across these schemas.",
        type = "warning", duration = 6)
      return()
    }

    schemas    <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi      <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res)

    cohort_by_schema <- if (multi) split(res, res$source_schema)
                       else setNames(list(res), schemas[[1]] %||% "")

    concept_ids <- vapply(km_concepts_rv(), `[[`, integer(1), "cid")

    cif_rv(list(state = "running"))
    withProgress(message = "Running competing risks analysis...", value = 0.4, {
      per_schema <- lapply(names(cohort_by_schema), function(sch) {
        cm  <- col_maps_l[[sch]] %||% omop_col_map_rv()
        sub <- cohort_by_schema[[sch]]
        d <- tryCatch(
          query_cif_data(sch, cm, sub,
                         outcome_domain      = input$km_outcome_domain,
                         outcome_concept_ids = concept_ids,
                         use_descendants     = isTRUE(input$km_use_desc)),
          error = function(e) {
            showNotification(paste("CIF error (", sch, "): ", e$message),
                             type = "warning"); NULL })
        if (!is.null(d) && nrow(d) > 0) d$source_schema <- sch
        d
      })
    })
    cif_data <- do.call(rbind, Filter(Negate(is.null), per_schema))
    if (is.null(cif_data) || nrow(cif_data) == 0) {
      cif_rv(NULL)
      showNotification("No CIF data available from any schema.", type = "warning")
      return()
    }

    has_competing <- any(cif_data$status == 2L)
    cif_result <- tryCatch({
      horizon <- suppressWarnings(as.integer(input$km_time_horizon))
      if (!is.na(horizon) && horizon > 0)
        cif_data$time <- pmin(cif_data$time, horizon)

      # Multi-schema: compute CIF per schema and return a list of fits so
      # the renderer can overlay them. Single-schema: keep legacy shape.
      if (multi && has_competing && requireNamespace("cmprsk", quietly = TRUE)) {
        per_schema_fits <- lapply(split(cif_data, cif_data$source_schema), function(d) {
          if (nrow(d) == 0) return(NULL)
          list(fit     = cmprsk::cuminc(ftime = d$time, fstatus = d$status),
               data    = d,
               n_total = nrow(d),
               n_event = sum(d$status == 1L),
               n_death = sum(d$status == 2L))
        })
        per_schema_fits <- Filter(Negate(is.null), per_schema_fits)
        list(type = "cif", per_schema = per_schema_fits, multi = TRUE,
             data = cif_data, n_total = nrow(cif_data),
             n_event = sum(cif_data$status == 1L),
             n_death = sum(cif_data$status == 2L))
      } else if (has_competing && requireNamespace("cmprsk", quietly = TRUE)) {
        list(
          type    = "cif",
          fit     = cmprsk::cuminc(ftime = cif_data$time, fstatus = cif_data$status),
          data    = cif_data,
          n_total = nrow(cif_data),
          n_event = sum(cif_data$status == 1L),
          n_death = sum(cif_data$status == 2L),
          multi   = FALSE
        )
      } else if (multi) {
        # No competing events: KM per schema overlaid
        per_schema_fits <- lapply(split(cif_data, cif_data$source_schema), function(d) {
          if (nrow(d) == 0) return(NULL)
          list(fit = survival::survfit(survival::Surv(time, status) ~ 1, data = d),
               data = d, n_total = nrow(d),
               n_event = sum(d$status == 1L), n_death = 0L)
        })
        per_schema_fits <- Filter(Negate(is.null), per_schema_fits)
        list(type = "km", per_schema = per_schema_fits, multi = TRUE,
             data = cif_data, n_total = nrow(cif_data),
             n_event = sum(cif_data$status == 1L), n_death = 0L)
      } else {
        fit <- survival::survfit(survival::Surv(time, status) ~ 1, data = cif_data)
        list(type = "km", fit = fit, data = cif_data,
             n_total = nrow(cif_data), n_event = sum(cif_data$status == 1L),
             n_death = 0L, multi = FALSE)
      }
    }, error = function(e) {
      showNotification(paste("CIF fit error:", e$message), type="error"); NULL })

    if (is.null(cif_result)) { cif_rv(NULL); return() }
    cif_rv(c(list(state = "done", domain = input$km_outcome_domain,
                  concept_names = vapply(km_concepts_rv(),
                                          function(x) as.character(x$name %||% x$cid),
                                          character(1)),
                  schemas = schemas), cif_result))
  })

  output$cif_status_ui <- renderUI({
    cv <- cif_rv()
    if (is.null(cv)) return(NULL)
    if (identical(cv$state, "running"))
      return(div(style="color:var(--dre-muted);font-size:0.87rem;margin:8px 0;",
                 icon("spinner"), " Computing..."))
    if (identical(cv$state, "done"))
      return(div(style="color:var(--dre-success);font-size:0.87rem;margin:8px 0;",
        icon("circle-check"),
        sprintf(" %s | Primary events: %s | Deaths (competing): %s",
                if(cv$type=="cif") "Competing risks CIF" else "KM (no death table)",
                format(cv$n_event, big.mark=","),
                format(cv$n_death, big.mark=","))))
    NULL
  })

  cif_plot_obj <- reactive({
    cv <- cif_rv()
    empty_cif <- function(msg)
      ggplot2::ggplot() +
        ggplot2::annotate("text",x=0.5,y=0.5,label=msg,colour="#8BA3B5",size=4) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA))

    if (is.null(cv) || !identical(cv$state,"done"))
      return(empty_cif("Configure the outcome above and click Run CIF"))

    dom_label <- DOMAINS[[cv$domain]]$label %||% cv$domain
    # Bug 9 fix (v8.6): use concept names rather than the domain category.
    outcome_label <- local({
      nm <- cv$concept_names %||% character(0)
      nm <- nm[nzchar(nm)]
      if (length(nm) == 0) dom_label
      else if (length(nm) == 1) nm
      else if (length(nm) == 2) paste(nm, collapse = " & ")
      else sprintf("%s plus %d others", nm[1], length(nm) - 1)
    })
    SCH_COLS <- c("#00C5B5","#FFB84D","#E05C6E","#A78BFA","#34D399")

    # Helper for extracting per-event data frames from a single cuminc fit
    cif_to_df <- function(fit, extra = NULL) {
      grp_names <- names(fit)
      g1 <- grp_names[grepl(" 1$", grp_names)][1]
      g2 <- grp_names[grepl(" 2$", grp_names)][1]
      make_df <- function(grp, label) {
        if (is.null(grp) || is.na(grp)) return(NULL)
        d <- fit[[grp]]
        out <- data.frame(time=c(0, d$time), cif=c(0, d$est),
                          upper=c(0, d$upper), lower=c(0, d$lower),
                          event=label, stringsAsFactors=FALSE)
        if (!is.null(extra)) for (k in names(extra)) out[[k]] <- extra[[k]]
        out
      }
      rbind(make_df(g1, paste("Primary:", outcome_label)),
            make_df(g2, "Death (competing)"))
    }

    if (isTRUE(cv$multi) && cv$type == "cif" && !is.null(cv$per_schema)) {
      # Overlay per-schema CIFs with facet by event so both the primary event
      # and the competing death curve are comparable across schemas.
      dfs <- do.call(rbind, Filter(Negate(is.null), lapply(
        names(cv$per_schema), function(sch)
          cif_to_df(cv$per_schema[[sch]]$fit, extra = list(source_schema = sch)))))
      if (is.null(dfs) || nrow(dfs) == 0)
        return(empty_cif("CIF computation returned no data"))
      ggplot2::ggplot(dfs, ggplot2::aes(x=time, y=cif,
                                          colour=source_schema, fill=source_schema)) +
        ggplot2::geom_ribbon(ggplot2::aes(ymin=lower, ymax=upper), alpha=0.12, colour=NA) +
        ggplot2::geom_step(linewidth=1) +
        ggplot2::scale_colour_manual(values=SCH_COLS[seq_along(unique(dfs$source_schema))],
                                      name="Schema") +
        ggplot2::scale_fill_manual(  values=SCH_COLS[seq_along(unique(dfs$source_schema))],
                                      name="Schema") +
        ggplot2::scale_y_continuous(labels=scales::percent_format(accuracy=1),
                                     limits=c(0,NA), expand=c(0.01,0)) +
        ggplot2::scale_x_continuous(labels=function(x) format(x, big.mark=","),
                                     expand=c(0.01,0)) +
        ggplot2::facet_wrap(~ event, ncol = 1) +
        ggplot2::labs(x="Days from index", y="Cumulative incidence",
                      title=paste0("Competing Risks - ", outcome_label, " (per schema)"),
                      subtitle=sprintf("N=%s | Primary events=%s | Deaths=%s",
                        format(cv$n_total, big.mark=","),
                        format(cv$n_event, big.mark=","),
                        format(cv$n_death, big.mark=",")),
                      caption="Fine-Gray cumulative incidence function  |  Shaded bands: 95% CI") +
        theme_dre() + ggplot2::theme(legend.position="right")

    } else if (isTRUE(cv$multi) && cv$type == "km" && !is.null(cv$per_schema)) {
      # No competing events; overlay per-schema 1 - KM curves
      dfs <- do.call(rbind, Filter(Negate(is.null), lapply(
        names(cv$per_schema), function(sch) {
          fit <- cv$per_schema[[sch]]$fit
          kd  <- data.frame(time=c(0,fit$time), cif=c(0, 1-fit$surv),
                            upper=c(0, 1-fit$lower), lower=c(0, 1-fit$upper),
                            source_schema = sch)
          kd[!is.na(kd$cif), ]
        })))
      ggplot2::ggplot(dfs, ggplot2::aes(x=time, y=cif,
                                          colour=source_schema, fill=source_schema)) +
        ggplot2::geom_ribbon(ggplot2::aes(ymin=lower, ymax=upper), alpha=0.12, colour=NA) +
        ggplot2::geom_step(linewidth=1) +
        ggplot2::scale_colour_manual(values=SCH_COLS[seq_along(unique(dfs$source_schema))],
                                      name="Schema") +
        ggplot2::scale_fill_manual(  values=SCH_COLS[seq_along(unique(dfs$source_schema))],
                                      name="Schema") +
        ggplot2::scale_y_continuous(labels=scales::percent_format(accuracy=1),
                                     limits=c(0,NA), expand=c(0.01,0)) +
        ggplot2::scale_x_continuous(labels=function(x) format(x, big.mark=","),
                                     expand=c(0.01,0)) +
        ggplot2::labs(x="Days from index", y="Cumulative incidence (1 - KM)",
                      title=paste0("Cumulative Incidence - ", outcome_label, " (per schema)"),
                      caption="Death table not found - showing 1 - KM estimate per schema") +
        theme_dre() + ggplot2::theme(legend.position="right")

    } else if (cv$type == "cif") {
      cif_df <- cif_to_df(cv$fit)
      if (is.null(cif_df) || nrow(cif_df) == 0)
        return(empty_cif("CIF computation returned no data"))

      ggplot2::ggplot(cif_df, ggplot2::aes(x=time, y=cif, colour=event, fill=event)) +
        ggplot2::geom_ribbon(ggplot2::aes(ymin=lower, ymax=upper), alpha=0.12, colour=NA) +
        ggplot2::geom_step(linewidth=1) +
        ggplot2::scale_colour_manual(values=c("#00C5B5","#E05C6E"), name="Event") +
        ggplot2::scale_fill_manual(  values=c("#00C5B5","#E05C6E"), name="Event") +
        ggplot2::scale_y_continuous(labels=scales::percent_format(accuracy=1),
                                     limits=c(0,NA), expand=c(0.01,0)) +
        ggplot2::scale_x_continuous(labels=function(x) format(x, big.mark=","),
                                     expand=c(0.01,0)) +
        ggplot2::labs(x="Days from index", y="Cumulative incidence",
                      title=paste0("Competing Risks - ", outcome_label),
                      subtitle=sprintf("N=%s | Primary events=%s | Deaths=%s",
                        format(cv$n_total, big.mark=","),
                        format(cv$n_event, big.mark=","),
                        format(cv$n_death, big.mark=",")),
                      caption="Fine-Gray cumulative incidence function  |  Shaded bands: 95% CI") +
        theme_dre() +
        ggplot2::theme(legend.position="right")
    } else {
      # Single-schema fallback: plain 1 - KM
      fit <- cv$fit
      kd <- data.frame(time=c(0,fit$time), surv=c(1,fit$surv),
                        upper=c(1,fit$upper), lower=c(1,fit$lower))
      kd <- kd[!is.na(kd$surv),]
      ggplot2::ggplot(kd, ggplot2::aes(x=time,y=1-surv)) +
        ggplot2::geom_ribbon(ggplot2::aes(ymin=1-upper,ymax=1-lower),
                             fill="#00C5B540",colour=NA) +
        ggplot2::geom_step(colour="#00C5B5", linewidth=1) +
        ggplot2::scale_y_continuous(labels=scales::percent_format(accuracy=1),
                                     limits=c(0,NA), expand=c(0.01,0)) +
        ggplot2::scale_x_continuous(labels=function(x) format(x, big.mark=","),
                                     expand=c(0.01,0)) +
        ggplot2::labs(x="Days from index", y="Cumulative incidence (1 - KM)",
                      title=paste0("Cumulative Incidence - ", outcome_label, " (no death table)"),
                      caption="Death table not found - showing 1-KM estimate") +
        theme_dre()
    }
  })
  output$cif_plot <- renderPlot(cif_plot_obj(), res = PLOT_RES, bg = "#0B2341")

  .cif_code <- function() {
    cv <- cif_rv()
    if (is.null(cv) || !identical(cv$state, "done"))
      return("# Run CIF analysis first to generate a code snippet.")
    cohort_block <- .cohort_sql_block()
    if (is.null(cohort_block))
      return("# Cohort SQL not available - build at least one inclusion criterion first.")

    cohort_nm <- input$cohort_name %||% "my_cohort"
    schemas   <- input$schema_select %||% character(0)
    outcomes  <- vapply(km_concepts_rv(), function(x) x$name, character(1))
    outcome_ids <- vapply(km_concepts_rv(), function(x) as.integer(x$cid), integer(1))
    outcome_domain <- input$km_outcome_domain %||% "condition"
    use_desc  <- isTRUE(input$km_use_desc)
    horizon   <- input$km_time_horizon
    col_maps_l <- col_maps_rv()
    multi      <- length(schemas) > 1
    dom        <- DOMAINS[[outcome_domain]]
    if (is.null(dom))
      return("# Outcome domain not recognised.")

    # Survival + death query per schema. Survival is the KM-style query
    # (same as in .km_code). Death is a separate query to the death table.
    .schema_surv_query <- function(sch) {
      cm <- col_maps_l[[sch]] %||% omop_col_map_rv()
      pid_col <- ac(cm, dom$table, dom$person_col)
      dat_col <- ac(cm, dom$table, dom$date_col)
      cid_col <- ac(cm, dom$table, dom$concept_col)
      op_pid  <- ac(cm, "observation_period", "person_id")
      op_end  <- ac(cm, "observation_period", "observation_period_end_date")
      if (length(outcome_ids) > 0) {
        ids_c <- paste(outcome_ids, collapse = ", ")
        if (use_desc) {
          anc_col  <- ac(cm, "concept_ancestor", "ancestor_concept_id")
          desc_col <- ac(cm, "concept_ancestor", "descendant_concept_id")
          concept_filter <- sprintf(
            "AND t.%s IN (SELECT %s FROM \"%s\".\"concept_ancestor\" WHERE %s IN (%s))",
            cid_col, desc_col, sch, anc_col, ids_c)
        } else {
          concept_filter <- sprintf("AND t.%s IN (%s)", cid_col, ids_c)
        }
      } else {
        concept_filter <- ""
      }
      sprintf(
'WITH idx(person_id, index_date) AS (VALUES %%s),
     outcomes AS (
       SELECT t.%s AS person_id, MIN(t.%s::date) AS event_date
       FROM   "%s"."%s" t
       JOIN   idx ON idx.person_id = t.%s
       WHERE  t.%s::date >= idx.index_date %s
       GROUP  BY 1
     ),
     censoring AS (
       SELECT op.%s AS person_id, MAX(op.%s::date) AS censor_date
       FROM   "%s"."observation_period" op
       JOIN   idx ON idx.person_id = op.%s
       WHERE  op.%s::date >= idx.index_date
       GROUP  BY 1
     )
SELECT i.person_id, i.index_date,
       COALESCE(o.event_date, c.censor_date, i.index_date) AS end_date,
       CASE WHEN o.person_id IS NOT NULL THEN 1 ELSE 0 END AS status
FROM   idx i
LEFT JOIN outcomes  o ON o.person_id = i.person_id
LEFT JOIN censoring c ON c.person_id = i.person_id',
        pid_col, dat_col, sch, dom$table, pid_col, dat_col, concept_filter,
        op_pid, op_end, sch, op_pid, op_end)
    }
    .schema_death_query <- function(sch) {
      cm <- col_maps_l[[sch]] %||% omop_col_map_rv()
      dp <- ac(cm, "death", "person_id")
      dd <- ac(cm, "death", "death_date")
      sprintf(
'WITH idx(person_id, index_date) AS (VALUES %%s)
SELECT i.person_id,
       (d.%s::date - i.index_date)::int AS death_days
FROM   idx i
JOIN   "%s"."death" d ON d.%s = i.person_id
WHERE  d.%s::date > i.index_date',
        dd, sch, dp, dd)
    }

    header <- sprintf(paste0(
      "# ──────────────────────────────────────────────────────────────────────\n",
      "# Cumulative Incidence Function (competing risks: outcome vs death)\n",
      "# Cohort:    %s\n",
      "# Schemas:   %s\n",
      "# Domain:    %s%s\n",
      "# Outcomes:  %s\n",
      "# Time horizon (days): %s\n",
      "# Generated: %s\n",
      "#\n",
      "# Self-contained: builds the cohort, queries outcome event + death\n",
      "# per schema, merges them into time/status with status 1 = primary\n",
      "# event, 2 = death (competing), 0 = censored, fits cmprsk::cuminc\n",
      "# and plots. Requires DBI, xaputils, cmprsk, ggplot2.\n",
      "# ──────────────────────────────────────────────────────────────────────\n"),
      cohort_nm,
      paste(schemas, collapse = ", "),
      dom$label %||% outcome_domain,
      if (use_desc) " (with descendants)" else "",
      if (length(outcomes) == 0) "(all events in domain)" else paste(outcomes, collapse = ", "),
      if (is.null(horizon) || is.na(horizon) || horizon == "") "(all)" else as.character(horizon),
      format(Sys.time(), "%Y-%m-%d %H:%M:%S"))

    if (multi) {
      surv_lines <- vapply(schemas, function(sch) {
        sprintf('  %s = r"---(%s)---"', deparse(sch), .schema_surv_query(sch))
      }, character(1))
      death_lines <- vapply(schemas, function(sch) {
        sprintf('  %s = r"---(%s)---"', deparse(sch), .schema_death_query(sch))
      }, character(1))
      query_block <- sprintf("surv_queries  <- list(\n%s\n)\ndeath_queries <- list(\n%s\n)",
                              paste(surv_lines, collapse = ",\n"),
                              paste(death_lines, collapse = ",\n"))
      per_schema_loop <- '
per_schema_cif <- lapply(names(surv_queries), function(sch) {
  sub <- cohort_result[cohort_result$source_schema == sch, , drop = FALSE]
  if (nrow(sub) == 0) return(NULL)
  vals <- paste(
    sprintf("(%.0f, \'%s\'::date)",
            as.numeric(sub$person_id),
            as.character(as.Date(sub$index_date))),
    collapse = ", ")
  surv  <- DBI::dbGetQuery(xap.conn, sprintf(surv_queries[[sch]],  vals))
  death <- tryCatch(DBI::dbGetQuery(xap.conn, sprintf(death_queries[[sch]], vals)),
                    error = function(e) NULL)
  names(surv) <- tolower(names(surv))
  surv$time <- as.integer(as.Date(surv$end_date) - as.Date(surv$index_date))
  surv$time[surv$time < 0] <- 0
  surv$status <- as.integer(surv$status)
  if (!is.null(death) && nrow(death) > 0) {
    names(death) <- tolower(names(death))
    death_map <- setNames(as.integer(death$death_days),
                          as.character(death$person_id))
    for (i in seq_len(nrow(surv))) {
      dt <- death_map[as.character(surv$person_id[i])]
      if (!is.na(dt)) {
        if (surv$status[i] == 0L) {
          surv$time[i]   <- min(surv$time[i], dt)
          surv$status[i] <- 2L
        } else if (dt < surv$time[i]) {
          surv$time[i]   <- dt
          surv$status[i] <- 2L
        }
      }
    }
  }
  surv$source_schema <- sch
  surv[, c("person_id", "time", "status", "source_schema")]
})
cif_data <- do.call(rbind, per_schema_cif)
'
    } else {
      query_block <- sprintf('surv_query  <- r"---(%s)---"\ndeath_query <- r"---(%s)---"',
                              .schema_surv_query(schemas[1]),
                              .schema_death_query(schemas[1]))
      per_schema_loop <- '
vals <- paste(
  sprintf("(%.0f, \'%s\'::date)",
          as.numeric(cohort_result$person_id),
          as.character(as.Date(cohort_result$index_date))),
  collapse = ", ")
surv  <- DBI::dbGetQuery(xap.conn, sprintf(surv_query, vals))
death <- tryCatch(DBI::dbGetQuery(xap.conn, sprintf(death_query, vals)),
                  error = function(e) NULL)
names(surv) <- tolower(names(surv))
surv$time <- as.integer(as.Date(surv$end_date) - as.Date(surv$index_date))
surv$time[surv$time < 0] <- 0
surv$status <- as.integer(surv$status)
if (!is.null(death) && nrow(death) > 0) {
  names(death) <- tolower(names(death))
  death_map <- setNames(as.integer(death$death_days),
                        as.character(death$person_id))
  for (i in seq_len(nrow(surv))) {
    dt <- death_map[as.character(surv$person_id[i])]
    if (!is.na(dt)) {
      if (surv$status[i] == 0L) {
        surv$time[i]   <- min(surv$time[i], dt)
        surv$status[i] <- 2L
      } else if (dt < surv$time[i]) {
        surv$time[i]   <- dt
        surv$status[i] <- 2L
      }
    }
  }
}
cif_data <- surv[, c("person_id", "time", "status")]
'
    }

    horizon_block <- if (!is.null(horizon) && !is.na(suppressWarnings(as.integer(horizon)))) {
      sprintf('
# Apply time horizon
cif_data$time <- pmin(cif_data$time, %dL)
', as.integer(horizon))
    } else ""

    chart_body <- sprintf('
# ── 3. Query outcome + death per schema, compute time/status ─────────────
library(DBI)
library(cmprsk)
library(ggplot2)

%s

%s

%s
', query_block, per_schema_loop, horizon_block)

    plot_body <- '
# ── 4. Fit competing risks and plot ──────────────────────────────────────
cif_to_df <- function(fit, primary_label = "Primary event") {
  grp_names <- names(fit)
  g1 <- grp_names[grepl(" 1$", grp_names)][1]
  g2 <- grp_names[grepl(" 2$", grp_names)][1]
  make_df <- function(grp, label) {
    if (is.null(grp) || is.na(grp)) return(NULL)
    d <- fit[[grp]]
    data.frame(time = c(0, d$time), cif = c(0, d$est),
               upper = c(0, d$est + 1.96 * sqrt(d$var)),
               lower = c(0, pmax(0, d$est - 1.96 * sqrt(d$var))),
               event = label)
  }
  rbind(make_df(g1, primary_label),
        make_df(g2, "Death (competing)"))
}

fit <- cuminc(ftime = cif_data$time, fstatus = cif_data$status)
plot_df <- cif_to_df(fit)

ggplot(plot_df, aes(x = time, y = cif, colour = event, fill = event)) +
  geom_ribbon(aes(ymin = lower, ymax = upper), alpha = 0.12, colour = NA) +
  geom_step(linewidth = 1) +
  scale_y_continuous(labels = scales::percent_format(accuracy = 1),
                     limits = c(0, NA)) +
  labs(x = "Days from index", y = "Cumulative incidence",
       colour = "Event type", fill = "Event type",
       caption = "Fine-Gray CIF  |  Shaded bands: 95% CI") +
  theme_minimal()
'

    paste0(header, cohort_block, chart_body, plot_body)
  }

  chart_register("cif_curve", "Cumulative incidence (CIF)",
                 plot_fn = cif_plot_obj,
                 code_fn = .cif_code,
                 width = 12, height = 7)

  # ──────────────────────────────────────────────────────────────────────────
  # ATTRITION TAB
  # ──────────────────────────────────────────────────────────────────────────

  observeEvent(input$run_attrition_btn, {
    req(conn_valid())
    schemas <- input$schema_select %||% character(0)
    req(length(schemas) > 0)
    crits    <- criteria_rv()
    col_maps <- col_maps_rv()
    if (length(crits) == 0) {
      showNotification("Add criteria first.", type = "warning"); return()
    }
    withProgress(message = "Running attrition analysis\u2026", value = 0, {
      all_att <- lapply(seq_along(schemas), function(si) {
        sch <- schemas[si]
        cm  <- col_maps[[sch]] %||% list()
        setProgress((si-0.5)/length(schemas), detail=sprintf("%s\u2026", sch))
        steps <- tryCatch(
          build_attrition_sql(sch, crits, col_map = cm),
          error = function(e) NULL)
        if (is.null(steps)) return(list(schema=sch, steps=list()))
        results <- lapply(seq_along(steps), function(j) {
          n <- tryCatch({
            r <- db_query(steps[[j]]$sql)
            as.integer(r$n[1])
          }, error = function(e) NA_integer_)
          list(label = steps[[j]]$label, n = n,
               is_exc = grepl("Exclusion", steps[[j]]$label))
        })
        list(schema = sch, steps = results)
      })
    })
    attrition_rv(all_att)
  })

  output$attrition_ui <- renderUI({
    att_list <- attrition_rv()
    if (is.null(att_list))
      return(div(class = "empty-state",
        div(class = "es-icon", icon("filter")),
        div(class = "es-title", "No attrition data"),
        tags$p("Add criteria and click Run Attrition.")))

    render_schema_attrition <- function(att_item) {
      att   <- att_item$steps
      if (length(att) == 0)
        return(tags$p(style="color:var(--dre-muted);font-size:0.85rem;",
                      "No attrition data for this schema."))
      counts <- sapply(att, `[[`, "n")
      max_n  <- max(counts, na.rm = TRUE)
      if (is.na(max_n) || max_n == 0) max_n <- 1
      tagList(lapply(seq_along(att), function(i) {
        step <- att[[i]]; n <- step$n
        pct  <- if (!is.na(n) && max_n > 0) round(100 * n / max_n) else 0
        div(class = "attrition-step",
          div(class = "attrition-label",
            if (step$is_exc) tags$span(class="attrition-exc", step$label)
            else step$label),
          div(class = "attrition-bar-bg",
            div(class = "attrition-bar-fill",
                style = sprintf("width:%d%%;%s", pct,
                                if (step$is_exc) "background:var(--dre-error);" else ""),
                if (pct > 8) paste0(pct, "%%") else "")),
          div(class = if (step$is_exc) "attrition-count attrition-exc" else "attrition-count",
              if (!is.na(n)) format(n, big.mark=",") else "error"),
          div(class = "attrition-pct",
              if (!is.na(n)) paste0(pct, "%%") else "")
        )
      }))
    }

    if (length(att_list) == 1) {
      # Single schema - existing layout
      render_schema_attrition(att_list[[1]])
    } else {
      # Multi-schema - side by side columns
      fluidRow(lapply(att_list, function(att_item) {
        col_w <- max(4L, floor(12L / length(att_list)))
        column(col_w,
          div(style="margin-bottom:8px;",
            tags$span(class="schema-source-badge", att_item$schema)
          ),
          render_schema_attrition(att_item)
        )
      }))
    }
  })

  # ── CONSORT flowchart ─────────────────────────────────────────────────────────
  output$consort_plot <- renderPlot({
    att    <- attrition_rv()
    res    <- cohort_result_rv()
    empty_c <- function(msg)
      ggplot2::ggplot() +
        ggplot2::annotate("text",x=0.5,y=0.5,label=msg,colour="#8BA3B5",size=3.5) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA))

    if (is.null(att))
      return(empty_c("Run Attrition first, then run the Cohort Query."))

    # Flatten multi-schema attrition into a single step sequence
    # Use first schema only for CONSORT (per-schema shown in attrition tab)
    att_flat <- if (is.list(att[[1]]) && !is.null(att[[1]]$steps))
      att[[1]]$steps else att
    counts <- sapply(att_flat, function(s) s$n %||% NA_integer_)
    labels <- sapply(att_flat, `[[`, "label")
    is_exc <- sapply(att_flat, function(s) isTRUE(s$is_exc))
    final_n <- if (!is.null(res) && nrow(res) > 0) nrow(res) else NA_integer_

    # Build box sequence: start → each step → final
    # Include steps is only inclusion criteria
    inc_idx   <- which(!is_exc)
    steps_n   <- counts[inc_idx]
    steps_lbl <- labels[inc_idx]
    if (!is.na(final_n)) {
      steps_n   <- c(steps_n, final_n)
      steps_lbl <- c(steps_lbl, "Final Cohort")
    }
    n_boxes <- length(steps_n)
    if (n_boxes < 2) return(empty_c("Not enough criteria to draw flowchart."))

    # Coordinates
    bw <- 0.5; bh <- 0.08
    cx <- 0.5
    ys <- seq(0.92, 0.08, length.out = n_boxes)
    excluded_ns <- c()
    for (i in seq_len(n_boxes - 1)) {
      a <- steps_n[i]; b <- steps_n[i+1]
      if (!is.na(a) && !is.na(b)) excluded_ns[i] <- a - b
      else excluded_ns[i] <- NA_integer_
    }

    COL_BOX   <- "#0E2A4A"
    COL_BORD  <- "#00C5B5"
    COL_FINAL <- "#00C5B5"
    COL_EXCL  <- "#E05C6E"
    COL_ARROW <- "#8BA3B5"
    COL_TEXT  <- "#C8D6E0"
    COL_MUT   <- "#8BA3B5"

    p <- ggplot2::ggplot() +
      ggplot2::xlim(0,1) + ggplot2::ylim(0,1) +
      ggplot2::theme_void() +
      ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA))

    # Draw boxes and arrows
    for (i in seq_len(n_boxes)) {
      is_final <- (i == n_boxes && !is.na(final_n))
      bord_col <- if (is_final) COL_FINAL else COL_BORD
      fill_col <- if (is_final) "#0A3040" else COL_BOX
      # Box
      p <- p +
        ggplot2::annotate("rect",
          xmin=cx-bw/2, xmax=cx+bw/2,
          ymin=ys[i]-bh/2, ymax=ys[i]+bh/2,
          fill=fill_col, colour=bord_col, linewidth=0.6) +
        ggplot2::annotate("text", x=cx, y=ys[i]+0.01,
          label=steps_lbl[i], colour=COL_TEXT,
          size=3.0, hjust=0.5, vjust=0.5, fontface="bold") +
        ggplot2::annotate("text", x=cx, y=ys[i]-0.025,
          label=if(!is.na(steps_n[i])) format(steps_n[i], big.mark=",") else "?",
          colour=if(is_final) COL_FINAL else "#00C5B5",
          size=3.5, hjust=0.5, vjust=0.5, fontface="bold")

      # Downward arrow to next box
      if (i < n_boxes) {
        y_from <- ys[i]   - bh/2
        y_to   <- ys[i+1] + bh/2
        p <- p +
          ggplot2::annotate("segment", x=cx, xend=cx,
            y=y_from, yend=y_to + 0.005,
            colour=COL_ARROW, linewidth=0.5,
            arrow=ggplot2::arrow(length=ggplot2::unit(0.006,"npc"),type="closed"))

        # Excluded side box
        ex <- excluded_ns[i]
        if (!is.na(ex) && ex > 0) {
          mid_y <- (y_from + y_to) / 2
          p <- p +
            ggplot2::annotate("segment", x=cx, xend=0.82,
              y=mid_y, yend=mid_y, colour=COL_EXCL, linewidth=0.4,
              linetype="dashed") +
            ggplot2::annotate("rect",
              xmin=0.82, xmax=0.99,
              ymin=mid_y-0.035, ymax=mid_y+0.035,
              fill="#1A0A10", colour=COL_EXCL, linewidth=0.4) +
            ggplot2::annotate("text", x=0.905, y=mid_y+0.01,
              label="Excluded", colour=COL_EXCL, size=2.5, hjust=0.5) +
            ggplot2::annotate("text", x=0.905, y=mid_y-0.015,
              label=format(ex, big.mark=","), colour=COL_EXCL,
              size=3.0, hjust=0.5, fontface="bold")
        }
      }
    }
    p
  }, res = PLOT_RES, bg = "#0B2341")

  output$consort_dl_btn <- downloadHandler(
    filename = function() paste0("consort_", Sys.Date(), ".png"),
    content  = function(file) {
      p   <- output$consort_plot  # re-render
      grDevices::png(file, width=800, height=600, res=120, bg="#0B2341")
      tryCatch(print(p), error=function(e) NULL)
      grDevices::dev.off()
      dl_dir <- DOWNLOADS_DIR
      if (!dir.exists(dl_dir)) dir.create(dl_dir, recursive=TRUE, showWarnings=FALSE)
      file.copy(file, file.path(dl_dir, basename(file)))
    }
  )

  # ── Cohort entry time series (computed from cohort_result - no SQL needed) ───
  output$entry_timeseries_plot <- renderPlot({
    res <- cohort_result_rv()
    empty_ts <- function(msg)
      ggplot2::ggplot() +
        ggplot2::annotate("text",x=0.5,y=0.5,label=msg,colour="#8BA3B5",size=3.5) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA))

    if (is.null(res) || nrow(res) == 0 || !"index_date" %in% names(res))
      return(empty_ts("Run the cohort query to see entry over time."))

    dates <- tryCatch(as.Date(res$index_date), error=function(e) NULL)
    if (is.null(dates) || all(is.na(dates)))
      return(empty_ts("Could not parse index dates."))

    yr  <- as.integer(format(dates, "%Y"))
    qtr <- as.integer(ceiling(as.integer(format(dates, "%m")) / 3))
    lbl <- sprintf("%d Q%d", yr, qtr)
    # Bug 4 fix (v8.6): previously `sort(table(lbl))` ordered bars by count
    # rather than time, producing an ascending-by-frequency chart whose
    # x-axis no longer represented chronology. Now: build a true period
    # start date, count per period, order by date, and use a date x-axis.
    period_start <- as.Date(sprintf("%d-%02d-01", yr, (qtr - 1L) * 3L + 1L))
    counts       <- as.data.frame(table(period_start, lbl), stringsAsFactors = FALSE)
    counts       <- counts[counts$Freq > 0, ]
    counts$period_start <- as.Date(counts$period_start)
    counts <- counts[order(counts$period_start), ]
    df <- data.frame(
      period_start = counts$period_start,
      period_label = counts$lbl,
      n            = as.integer(counts$Freq),
      stringsAsFactors = FALSE)

    ggplot2::ggplot(df, ggplot2::aes(x = period_start, y = n)) +
      ggplot2::geom_col(fill = "#00C5B5", width = 75) +
      ggplot2::geom_text(ggplot2::aes(label = n), vjust = -0.4,
                         colour = "#C8D6E0", size = 2.8) +
      ggplot2::scale_y_continuous(expand = ggplot2::expansion(mult = c(0, 0.15))) +
      ggplot2::scale_x_date(
        breaks = function(lims) seq(
          from = as.Date(sprintf("%d-01-01", as.integer(format(lims[1], "%Y")))),
          to   = lims[2],
          by   = "1 year"),
        labels = function(x) format(x, "%Y")) +
      ggplot2::labs(x = NULL, y = "Patients entering cohort",
                    title = "Cohort Entry by Quarter",
                    caption = "Sudden drops or spikes may indicate data quality issues") +
      theme_dre() +
      ggplot2::theme(axis.text.x = ggplot2::element_text(angle = 45, hjust = 1, size = 10))
  }, res = PLOT_RES, bg = "#0B2341")

  # ── Missingness report ────────────────────────────────────────────────────────
  observeEvent(input$run_missingness_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type="warning"); return()
    }
    req(conn_valid())

    schemas    <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi      <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res)

    cohort_by_schema <- if (multi) split(res, res$source_schema)
                       else setNames(list(res), schemas[[1]] %||% "")

    n_total <- nrow(res)

    # numeric_only = TRUE means also check != 0 (valid for integer/numeric cols).
    # For date, text, or presence-only columns, IS NOT NULL alone is sufficient.
    MISS_CHECKS <- list(
      list(table="person",             col="year_of_birth",              label="Year of birth",              numeric_only=TRUE),
      list(table="person",             col="gender_concept_id",          label="Sex",                        numeric_only=TRUE),
      list(table="person",             col="race_concept_id",            label="Race",                       numeric_only=TRUE),
      list(table="person",             col="ethnicity_concept_id",       label="Ethnicity",                  numeric_only=TRUE),
      list(table="observation_period", col="observation_period_end_date",label="Observation period end",     numeric_only=FALSE),
      list(table="condition_occurrence",col="condition_concept_id",      label="Any diagnosis",             numeric_only=TRUE),
      list(table="drug_exposure",       col="drug_concept_id",           label="Any drug exposure",         numeric_only=TRUE),
      list(table="measurement",         col="value_as_number",           label="Numeric measurement value", numeric_only=TRUE)
    )

    # Count with-data persons in ONE schema for ONE check
    run_check <- function(sch, cm, pids, chk, existing) {
      if (!tolower(chk$table) %in% existing) return(NA_integer_)
      pid_c      <- ac(cm, chk$table, "person_id")
      val_c      <- ac(cm, chk$table, chk$col)
      zero_check <- if (isTRUE(chk$numeric_only)) sprintf(" AND %s != 0", val_c) else ""
      sql        <- sprintf(
        "SELECT COUNT(DISTINCT %s)::int AS n
         FROM %s
         WHERE %s IN (%s) AND %s IS NOT NULL%s",
        pid_c, fq(sch, chk$table),
        pid_c, pid_sql(pids), val_c, zero_check)
      tryCatch({
        r <- db_query(sql)
        if (is.null(r) || nrow(r) == 0 || length(r$n) == 0) NA_integer_
        else as.integer(r$n[[1]])
      }, error = function(e) NA_integer_)
    }

    # Existing tables per schema (cache)
    existing_by_sch <- setNames(lapply(names(cohort_by_schema), function(sch)
      tryCatch(tolower(get_tables(sch)), error = function(e) character(0))),
      names(cohort_by_schema))

    results <- list()
    withProgress(message="Running completeness checks...", value=0, {
      for (i in seq_along(MISS_CHECKS)) {
        chk <- MISS_CHECKS[[i]]
        setProgress(i / length(MISS_CHECKS), detail=chk$label)

        # Per-schema counts for this check
        per_sch <- setNames(vapply(names(cohort_by_schema), function(sch) {
          cm   <- col_maps_l[[sch]] %||% omop_col_map_rv()
          pids <- unique(as_pid(cohort_by_schema[[sch]]$person_id))
          run_check(sch, cm, pids, chk, existing_by_sch[[sch]])
        }, integer(1)), names(cohort_by_schema))

        # Pool counts - sum across schemas, treating NA as zero-contribution
        # but recording whether the table was absent in some schemas.
        any_observed <- any(!is.na(per_sch))
        n_pooled     <- if (any_observed) sum(per_sch, na.rm = TRUE) else NA_integer_

        results[[i]] <- list(label = chk$label, n_with = n_pooled,
                              pct   = if (!is.na(n_pooled)) 100 * n_pooled / n_total else NA_real_,
                              table = chk$table,
                              per_schema = per_sch)
      }
    })
    missingness_rv(list(results = results, n_total = n_total,
                        multi = multi, schemas = names(cohort_by_schema)))
  })

  output$missingness_ui <- renderUI({
    mv <- missingness_rv()
    if (is.null(mv))
      return(div(style="color:var(--dre-muted);font-size:0.87rem;",
                 "Click Run to check data completeness for your cohort."))
    rs    <- mv$results
    n_tot <- mv$n_total

    rows <- lapply(rs, function(r) {
      pct <- r$pct
      col <- if (is.na(pct)) "#8BA3B5"
             else if (pct >= 90) "#00C5B5"
             else if (pct >= 50) "#FFB84D"
             else "#E05C6E"
      pct_str  <- if (!is.na(pct)) sprintf("%.1f%%", pct) else "N/A (table absent)"
      bar_pct  <- if (!is.na(pct)) round(pct) else 0
      tags$div(style="margin-bottom:8px;",
        tags$div(style="display:flex;justify-content:space-between;margin-bottom:3px;",
          tags$span(style="font-size:0.84rem;color:var(--dre-text);", r$label),
          tags$span(style=sprintf("font-size:0.84rem;font-weight:700;color:%s;", col),
                    pct_str)
        ),
        tags$div(style=paste0(
          "background:var(--dre-border);border-radius:3px;height:6px;"),
          tags$div(style=sprintf(
            "width:%d%%;background:%s;height:6px;border-radius:3px;transition:width .4s;",
            bar_pct, col))
        )
      )
    })
    tagList(
      tags$p(style="font-size:0.80rem;color:var(--dre-muted);margin-bottom:10px;",
             sprintf("Cohort N = %s | %% of cohort with non-null value per variable",
                     format(n_tot, big.mark=","))),
      rows
    )
  })


  # ══════════════════════════════════════════════════════════════════════════
  # COX REGRESSION TAB
  # ══════════════════════════════════════════════════════════════════════════

  output$cox_status_ui <- renderUI({
    cv <- cox_rv()
    if (is.null(cv)) return(tags$p(style="color:var(--dre-muted);font-size:0.87rem;",
      "Configure options and click Run Cox Model. Uses the outcome domain and concepts set in the Survival tab."))
    if (identical(cv$state, "running"))
      return(div(style="color:var(--dre-muted);font-size:0.87rem;margin:8px 0;",
                 icon("spinner"), " Fitting model - extracting covariates may take 20-40 seconds..."))
    if (identical(cv$state, "error"))
      return(div(style="color:var(--dre-danger);font-size:0.87rem;margin:8px 0;",
                 icon("triangle-exclamation"), " ", cv$msg))
    if (identical(cv$state, "done"))
      return(div(style="color:var(--dre-success);font-size:0.87rem;margin:8px 0;",
        icon("circle-check"),
        sprintf(" Model fitted - N=%s | Events=%s | Concordance=%.3f | p(LRT)=%s",
                format(cv$n, big.mark=","),
                format(cv$n_events, big.mark=","),
                cv$concordance,
                ifelse(cv$lrt_p < 0.001, "<0.001", sprintf("%.3f", cv$lrt_p)))))
    NULL
  })

  observeEvent(input$run_cox_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type="warning"); return()
    }
    if (!"index_date" %in% names(res)) {
      showNotification("Cohort result has no index_date column.", type="error"); return()
    }
    req(conn_valid())

    if (overlap_gate_blocks(overlap_rv(), proceed_cox_rv())) {
      showNotification(
        "Acknowledge the no-overlap banner above to run Cox across these schemas.",
        type = "warning", duration = 6)
      return()
    }

    schema    <- primary_schema(input$schema_select %||% character(0))
    col_map   <- omop_col_map_rv()
    lookback  <- as.integer(input$cox_lookback_days %||% 365L)
    top_n     <- as.integer(input$cox_top_n_covs    %||% 20L)
    horizon   <- suppressWarnings(as.integer(input$cox_time_horizon))
    outcome_domain   <- input$km_outcome_domain %||% "condition"
    outcome_cids     <- vapply(km_concepts_rv(), `[[`, integer(1), "cid")

    # Bug 17 fix (v8.1): refuse to fit Cox when no outcome concept is selected.
    # Without this guard the outcome SQL drops its concept filter and matches
    # every record in the domain table, producing a model where almost every
    # cohort row is flagged as an event. The model fits silently and looks
    # plausible but is meaningless.
    if (length(outcome_cids) == 0) {
      showNotification(
        paste("Select at least one outcome concept on the Survival tab",
              "before running Cox. Without a specific outcome the model",
              "would treat any event in the domain as the outcome,",
              "which is rarely what you want."),
        type = "warning", duration = 8)
      cox_rv(list(state = "error",
                  msg = "No outcome concept configured. Configure outcome on the Survival tab first."))
      return()
    }

    cox_rv(list(state="running"))

    withProgress(message="Fitting Cox model...", value=0, {
      # ── Step 1: survival data ──────────────────────────────────────────────
      setProgress(0.15, detail="Querying survival data")
      surv_data <- tryCatch(
        query_survival_data(schema, col_map, res,
                            outcome_domain       = outcome_domain,
                            outcome_concept_ids  = outcome_cids),
        error = function(e) NULL)

      if (is.null(surv_data) || nrow(surv_data) == 0) {
        cox_rv(list(state="error",
                    msg="Survival data query returned no rows. Check outcome configuration in the Survival tab."))
        return()
      }

      if (!is.na(horizon) && horizon > 0)
        surv_data$time <- pmin(surv_data$time, horizon)

      # ── Step 2: covariates ────────────────────────────────────────────────
      setProgress(0.35, detail="Extracting covariates")
      cov_result <- tryCatch(
        extract_covariates_long(schema, col_map, res,
                                lookback_days      = lookback,
                                include_conditions = TRUE,
                                include_drugs      = TRUE),
        error = function(e) list(long=NULL, demo=NULL))

      # ── Step 3: CCI ───────────────────────────────────────────────────────
      setProgress(0.55, detail="Computing Charlson Comorbidity Index")
      cci_df <- tryCatch(
        compute_cci(schema, col_map, as_pid(res$person_id)),
        error = function(e) NULL)

      # ── Step 4: build model matrix ────────────────────────────────────────
      setProgress(0.70, detail="Building model matrix")
      demo <- cov_result$demo
      long <- cov_result$long

      # Start with survival data
      mat <- surv_data[, c("person_id", "time", "status")]

      # Join demographics
      if (!is.null(demo) && nrow(demo) > 0) {
        names(demo) <- tolower(names(demo))
        mat <- merge(mat, demo[, c("person_id","age_at_index","is_female")],
                     by="person_id", all.x=TRUE)
      } else {
        mat$age_at_index <- NA_real_
        mat$is_female    <- NA_integer_
      }

      # Join CCI
      if (!is.null(cci_df) && nrow(cci_df) > 0) {
        names(cci_df) <- tolower(names(cci_df))
        if ("person_id" %in% names(cci_df) && "cci_score" %in% names(cci_df))
          mat <- merge(mat, cci_df[, c("person_id","cci_score")],
                       by="person_id", all.x=TRUE)
        else mat$cci_score <- NA_real_
      } else {
        mat$cci_score <- NA_real_
      }

      # ── Step 4b: v9 covariate pruning ─────────────────────────────────────
      # Two-stage deterministic prune applied to the binary covariate set
      # before the design matrix is finalised.
      #
      # Stage 1 (EPV budget): cap binary covariate count so that
      #   total coefficients <= floor(n_events / EPV_target)
      # with EPV_target = 10. The 3 mandatory covariates (age, is_female,
      # cci_score) are subtracted from the budget first. Multi-schema runs
      # also have source_schema, reducing the binary budget further.
      #
      # Stage 2 (collinearity prune): for any pair of binary covariates
      # with phi-correlation > 0.95, drop the less prevalent one. Tie
      # broken deterministically by dropping the higher concept_id.
      #
      # Both stages record what they did to `prune_log`, displayed in a
      # collapsible details section in the diagnostics card.
      n_events_pre  <- sum(mat$status == 1L, na.rm = TRUE)
      EPV_TARGET    <- 10L
      COLLINEAR_THR <- 0.95
      MIN_EVENTS    <- 30L  # below this, Cox is too underpowered to fit at all

      prune_log <- list(
        n_events        = n_events_pre,
        epv_target      = EPV_TARGET,
        candidates_in   = 0L,  # binary candidates before pruning (set below)
        mandatory_n     = 0L,  # mandatory non-binary covariate count
        epv_dropped     = character(0),
        collinear_drops = list(),  # list of (kept, dropped, phi)
        final_n_binary  = 0L
      )

      if (n_events_pre < MIN_EVENTS) {
        cox_rv(list(state = "error",
                    msg = sprintf(paste(
                      "Only %d events observed - Cox model needs at least",
                      "%d events for any meaningful fit. Consider a broader",
                      "outcome definition or a longer follow-up window."),
                      n_events_pre, MIN_EVENTS)))
        return()
      }

      # Stage 1: identify mandatory non-binary covariates already on mat,
      # so we can compute the binary budget against them.
      mandatory_present <- intersect(
        c("age_at_index", "is_female", "cci_score", "source_schema"),
        names(mat))
      mandatory_present <- setdiff(mandatory_present,
                                    c("person_id", "time", "status"))
      prune_log$mandatory_n <- length(mandatory_present)

      budget_total      <- max(0L, as.integer(floor(n_events_pre / EPV_TARGET)))
      budget_for_binary <- max(0L, budget_total - prune_log$mandatory_n)
      effective_top_n   <- min(top_n, budget_for_binary)
      prune_log$budget_total      <- budget_total
      prune_log$budget_for_binary <- budget_for_binary
      prune_log$user_top_n        <- top_n
      prune_log$effective_top_n   <- effective_top_n

      # Binary covariate columns - top N by prevalence, capped by EPV budget
      if (!is.null(long) && nrow(long) > 0 && effective_top_n > 0) {
        prev_tbl  <- sort(table(long$covariate), decreasing = TRUE)
        prune_log$candidates_in <- length(prev_tbl)

        top_covs <- names(prev_tbl)[seq_len(min(effective_top_n, length(prev_tbl)))]
        # Anything we'd have included at user_top_n but didn't at
        # effective_top_n: recorded as "dropped for EPV" so the user can
        # see what budget pressure cost them.
        if (length(prev_tbl) > effective_top_n) {
          would_have_included <- names(prev_tbl)[seq_len(min(top_n, length(prev_tbl)))]
          prune_log$epv_dropped <- setdiff(would_have_included, top_covs)
        }
        long_top  <- long[long$covariate %in% top_covs, ]
        wide_list <- lapply(top_covs, function(cv) {
          pids_with <- unique(long_top$person_id[long_top$covariate == cv])
          as.integer(mat$person_id %in% pids_with)
        })
        wide_df <- as.data.frame(setNames(wide_list, make.names(top_covs)),
                                 stringsAsFactors = FALSE)

        # Stage 2: collinearity prune on the wide binary set.
        # Computed on the wide_df *before* it's joined to mat, so the
        # mandatory covariates can never be dropped.
        if (ncol(wide_df) >= 2) {
          M <- as.matrix(wide_df)
          # Compute phi (== Pearson for 0/1 vectors). Suppress sd=0 warnings;
          # NA rows handled by use="pairwise.complete.obs" (no NAs expected
          # in binary covariates but cheap insurance).
          phi_mat <- suppressWarnings(
            stats::cor(M, use = "pairwise.complete.obs"))
          phi_mat[!is.finite(phi_mat)] <- 0
          diag(phi_mat) <- 0

          prevalence <- colSums(M, na.rm = TRUE) / nrow(M)
          col_ids    <- colnames(wide_df)
          dropped    <- character(0)

          # Iterate while any off-diagonal exceeds threshold among remaining
          # columns. Each iteration drops one column (the less-prevalent of
          # the highest-correlation pair).
          repeat {
            keep_idx <- setdiff(seq_along(col_ids), match(dropped, col_ids))
            if (length(keep_idx) < 2) break
            sub <- phi_mat[keep_idx, keep_idx, drop = FALSE]
            sub_abs <- abs(sub)
            max_phi <- max(sub_abs)
            if (max_phi <= COLLINEAR_THR) break
            # Locate the pair: arr.ind() needs a matrix, picks first one
            pair_pos <- which(sub_abs == max_phi, arr.ind = TRUE)[1, ]
            i <- keep_idx[pair_pos[1]]; j <- keep_idx[pair_pos[2]]
            ci <- col_ids[i]; cj <- col_ids[j]
            # Drop less prevalent. Tie → drop the one whose original col
            # name sorts later (deterministic; concept_id is in the name).
            drop_col <- if (prevalence[ci] < prevalence[cj]) ci
                        else if (prevalence[ci] > prevalence[cj]) cj
                        else if (ci > cj) ci else cj
            keep_col <- if (drop_col == ci) cj else ci
            prune_log$collinear_drops[[length(prune_log$collinear_drops) + 1]] <- list(
              kept    = keep_col,
              dropped = drop_col,
              phi     = round(unname(phi_mat[i, j]), 3))
            dropped <- c(dropped, drop_col)
          }
          if (length(dropped) > 0) {
            wide_df <- wide_df[, !(names(wide_df) %in% dropped), drop = FALSE]
          }
        }

        prune_log$final_n_binary <- ncol(wide_df)
        if (ncol(wide_df) > 0) {
          mat <- cbind(mat, wide_df)
        }
      } else {
        prune_log$candidates_in <- if (is.null(long)) 0L else length(unique(long$covariate))
        prune_log$final_n_binary <- 0L
      }

      # ── Step 5: fit Cox ───────────────────────────────────────────────────
      setProgress(0.85, detail="Fitting Cox model")
      # Identify predictor columns (exclude ID, time, status)
      exclude_cols <- c("person_id", "time", "status")
      pred_cols    <- setdiff(names(mat), exclude_cols)
      # Drop columns with zero or near-zero variance
      nzv <- vapply(pred_cols, function(cv) {
        v <- mat[[cv]]
        !all(is.na(v)) && var(v, na.rm=TRUE) > 1e-8
      }, logical(1))
      pred_cols <- pred_cols[nzv]

      if (length(pred_cols) == 0) {
        cox_rv(list(state="error", msg="No usable covariates found after filtering.")); return()
      }

      formula_str <- paste("survival::Surv(time, status) ~",
                           paste(sprintf("`%s`", pred_cols), collapse=" + "))
      fit <- tryCatch(
        survival::coxph(as.formula(formula_str), data=mat, ties="efron"),
        error = function(e) NULL)

      if (is.null(fit)) {
        cox_rv(list(state="error", msg="Cox model failed to converge. Try reducing covariates or checking data quality."))
        return()
      }

      # Tidy results using broom if available, otherwise manual
      coef_df <- tryCatch({
        if (requireNamespace("broom", quietly=TRUE)) {
          td <- broom::tidy(fit, exponentiate=TRUE, conf.int=TRUE)
          names(td) <- tolower(names(td))
          data.frame(
            covariate = td$term,
            hr        = round(td$estimate,   3),
            ci_lo     = round(td$conf.low,   3),
            ci_hi     = round(td$conf.high,  3),
            p_value   = round(td$p.value,    4),
            stringsAsFactors = FALSE)
        } else {
          s   <- summary(fit)$coefficients
          ci  <- exp(confint(fit))
          data.frame(
            covariate = rownames(s),
            hr        = round(exp(s[,"coef"]),   3),
            ci_lo     = round(ci[,1],            3),
            ci_hi     = round(ci[,2],            3),
            p_value   = round(s[,"Pr(>|z|)"],    4),
            stringsAsFactors = FALSE)
        }
      }, error = function(e) NULL)

      # Bug 12 fix (v8.3): resolve human-readable concept names for binary
      # covariates whose column name is "<domain>_<concept_id>". The forest
      # plot and coefficient table previously displayed bare concept IDs
      # ("1118084") which are unreadable. The lookup is best-effort - if the
      # concept table is unavailable or any specific concept is missing, the
      # display falls back to "<domain>_<concept_id>" stripped to the bare ID.
      if (!is.null(coef_df) && nrow(coef_df) > 0) {
        coef_df$display_name <- coef_df$covariate  # default fallback
        bin_idx <- grepl("^(cond|drug|proc)_\\d+$", coef_df$covariate)
        if (any(bin_idx)) {
          bin_ids <- as.integer(sub("^(cond|drug|proc)_", "",
                                     coef_df$covariate[bin_idx]))
          existing_tbls <- tryCatch(tolower(get_tables(schema)),
                                    error = function(e) character(0))
          if ("concept" %in% existing_tbls && length(bin_ids) > 0) {
            cn_pid <- ac(col_map, "concept", "concept_id")
            cn_nm  <- ac(col_map, "concept", "concept_name")
            name_sql <- sprintf(
              "SELECT %s AS concept_id, %s AS concept_name FROM %s WHERE %s IN (%s)",
              cn_pid, cn_nm, fq(schema, "concept"), cn_pid,
              paste(bin_ids, collapse = ","))
            name_df <- tryCatch(db_query(name_sql), error = function(e) NULL)
            if (!is.null(name_df) && nrow(name_df) > 0) {
              names(name_df) <- tolower(names(name_df))
              name_map <- setNames(as.character(name_df$concept_name),
                                    as.character(as_pid(name_df$concept_id)))
              shortened <- vapply(as.character(bin_ids), function(id) {
                nm <- name_map[[id]]
                if (is.null(nm) || is.na(nm)) sprintf("Concept %s", id)
                else if (nchar(nm) > 48) paste0(substr(nm, 1, 45), "...")
                else nm
              }, character(1))
              coef_df$display_name[bin_idx] <- shortened
            }
          }
        }
      }

      s_fit <- tryCatch(summary(fit), error=function(e) NULL)
      concordance <- if (!is.null(s_fit)) tryCatch(s_fit$concordance[["C"]], error=function(e) NA_real_) else NA_real_
      lrt_p       <- if (!is.null(s_fit)) tryCatch(s_fit$logtest[["pvalue"]], error=function(e) NA_real_) else NA_real_

      # ── Diagnostics (Issue 3 - v8) ──────────────────────────────────────────
      # PH assumption via Schoenfeld residuals.
      # v8.5: cox.zph with transform="km" can fail on near-singular designs
      # (very high VIF, near-collinear covariates). When the "km" transform
      # errors, fall back to "identity" which is numerically more stable.
      # If both fail, capture the error message so the diagnostics panel can
      # tell the user *why* the PH check is empty rather than silently
      # leaving it blank.
      zph_obj    <- NULL
      zph_error  <- NULL
      for (tf in c("km", "identity")) {
        zph_try <- tryCatch(survival::cox.zph(fit, transform = tf),
                            error = function(e) e)
        if (!inherits(zph_try, "error")) {
          zph_obj <- zph_try
          break
        }
        zph_error <- conditionMessage(zph_try)
      }
      zph_table <- NULL
      ph_failures <- character(0)
      if (!is.null(zph_obj)) {
        zt <- as.data.frame(zph_obj$table)
        zt$term <- rownames(zt)
        # The GLOBAL row at the bottom is informative on its own.
        # v9.1: preserve the raw p-value; do formatting at display time so
        # tiny p-values (< 1e-4) render as "<0.0001" rather than "0".
        zph_table <- data.frame(
          term  = zt$term,
          chisq = round(zt$chisq, 3),
          df    = zt$df,
          p     = zt$p,
          stringsAsFactors = FALSE
        )
        per_term <- zph_table[zph_table$term != "GLOBAL", ]
        ph_failures <- per_term$term[!is.na(per_term$p) & per_term$p < 0.05]
      }
      ph_global_p <- if (!is.null(zph_table)) {
        g <- zph_table$p[zph_table$term == "GLOBAL"]
        if (length(g) == 1) g else NA_real_
      } else NA_real_
      ph_ok <- !is.na(ph_global_p) && ph_global_p >= 0.05 && length(ph_failures) == 0

      # VIF - only defined for multivariate models (>=2 coefficients) and only
      # for non-singular designs. car::vif throws if X'X is singular.
      vif_df    <- NULL
      vif_max   <- NA_real_
      vif_ok    <- TRUE
      n_coef    <- length(stats::coef(fit))
      if (n_coef >= 2) {
        vif_v <- tryCatch(car::vif(fit), error = function(e) NULL)
        if (!is.null(vif_v) && length(vif_v) > 0) {
          # car::vif returns a named numeric for simple Cox; matrix for terms
          # with df>1. Coerce to plain numeric vector.
          if (is.matrix(vif_v)) {
            # GVIF^(1/(2*Df)) is the comparable scalar
            vif_scalar <- vif_v[, "GVIF^(1/(2*Df))"]^2
            vif_df <- data.frame(
              covariate = rownames(vif_v),
              vif       = round(vif_scalar, 2),
              stringsAsFactors = FALSE)
          } else {
            vif_df <- data.frame(
              covariate = names(vif_v),
              vif       = round(as.numeric(vif_v), 2),
              stringsAsFactors = FALSE)
          }
          vif_max <- max(vif_df$vif, na.rm = TRUE)
          vif_ok  <- !is.finite(vif_max) || vif_max < 5
        }
      }

      # Events per variable (EPV) - ≥10 recommended (Peduzzi 1995)
      n_events <- sum(mat$status == 1L, na.rm = TRUE)
      epv      <- if (n_coef > 0) n_events / n_coef else NA_real_
      epv_ok   <- !is.na(epv) && epv >= 10

      # Influential observations via dfbeta. Flag rows where any |dfbeta_i| > 2/sqrt(n).
      dfb_summary <- tryCatch({
        db <- residuals(fit, type = "dfbeta")
        if (!is.null(db)) {
          n_rows <- if (is.matrix(db)) nrow(db) else length(db)
          thresh <- 2 / sqrt(n_rows)
          # Row-wise max abs dfbeta
          row_max <- if (is.matrix(db)) apply(abs(db), 1, max) else abs(db)
          list(n_influential = sum(row_max > thresh, na.rm = TRUE),
               threshold     = thresh,
               n_rows        = n_rows)
        } else list(n_influential = NA_integer_, threshold = NA_real_, n_rows = NA_integer_)
      }, error = function(e)
        list(n_influential = NA_integer_, threshold = NA_real_, n_rows = NA_integer_))

      diagnostics <- list(
        ph_ok          = ph_ok,
        ph_global_p    = ph_global_p,
        ph_failures    = ph_failures,
        zph_table      = zph_table,
        zph_obj        = zph_obj,
        zph_error      = zph_error,
        epv            = epv,
        epv_ok         = epv_ok,
        n_coef         = n_coef,
        vif_df         = vif_df,
        vif_max        = vif_max,
        vif_ok         = vif_ok,
        n_influential  = dfb_summary$n_influential,
        dfb_threshold  = dfb_summary$threshold,
        dfb_n_rows     = dfb_summary$n_rows,
        prune_log      = prune_log
      )
      diagnostics$any_issue <- !isTRUE(ph_ok) ||
                               !isTRUE(epv_ok) ||
                               !isTRUE(vif_ok) ||
                               (!is.na(dfb_summary$n_influential) &&
                                dfb_summary$n_influential > 0)

      cox_rv(list(
        state       = "done",
        coef_df     = coef_df,
        n           = nrow(mat),
        n_events    = sum(mat$status == 1L, na.rm=TRUE),
        concordance = concordance %||% NA_real_,
        lrt_p       = lrt_p %||% NA_real_,
        domain      = outcome_domain,
        diagnostics = diagnostics,
        fit         = fit
      ))
      setProgress(1)
    })
  })

  cox_forest_plot_obj <- reactive({
    cv <- cox_rv()
    empty_p <- function(msg) ggplot2::ggplot() +
      ggplot2::annotate("text",x=0.5,y=0.5,label=msg,colour="#8BA3B5",size=4) +
      ggplot2::theme_void() +
      ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA))

    if (is.null(cv) || !identical(cv$state,"done") || is.null(cv$coef_df))
      return(empty_p("Run the Cox model to see the forest plot."))

    df <- cv$coef_df
    df <- df[!is.na(df$hr) & is.finite(df$hr), ]
    if (nrow(df) == 0) return(empty_p("No valid coefficients to display."))

    # Bug 12 fix (v8.3): prefer the resolved concept name (display_name)
    # populated by the observer over the bare "<domain>_<concept_id>" form.
    # Falls back to the stripped concept_id if display_name is absent
    # (defensive - older cox_rv objects may not have it).
    df$label <- if ("display_name" %in% names(df)) df$display_name
                else sub("^(cond|drug|proc)_", "", df$covariate)
    # v8.4: with the forest plot now full-width we can afford longer labels.
    # v9.1: bumped to 90 chars to accommodate complex combination drug names
    # like "Amoxicillin 250 MG / Clavulanate 125 MG Oral Tablet" which fit
    # within 60 chars only marginally.
    df$label <- ifelse(nchar(df$label) > 90,
                       paste0(substr(df$label, 1, 87), "..."),
                       df$label)
    df       <- df[order(df$hr), ]
    df$label <- factor(df$label, levels = df$label)
    df$sig   <- df$p_value < 0.05

    # Cap CI display at 10 for readability
    df$ci_lo_plt <- pmax(df$ci_lo, 0.05)
    df$ci_hi_plt <- pmin(df$ci_hi, 10)

    ggplot2::ggplot(df, ggplot2::aes(x=hr, y=label, colour=sig)) +
      ggplot2::geom_vline(xintercept=1, colour="#E05C6E", linetype="dashed", linewidth=0.7) +
      ggplot2::geom_errorbarh(ggplot2::aes(xmin=ci_lo_plt, xmax=ci_hi_plt),
                               height=0.35, linewidth=0.8) +
      ggplot2::geom_point(size=3.6) +
      ggplot2::scale_colour_manual(values=c("TRUE"="#00C5B5","FALSE"="#8BA3B5"),
                                    labels=c("TRUE"="p<0.05","FALSE"="p≥0.05"),
                                    name="Significance") +
      ggplot2::scale_x_log10(labels=function(x) sprintf("%.2f",x)) +
      ggplot2::labs(x="Hazard Ratio (log scale, 95% CI)", y=NULL,
                    title="Adjusted Hazard Ratios",
                    caption="Dashed line at HR = 1  |  CIs capped at 0.05-10 for display") +
      theme_dre() +
      # v8.4: dedicated text sizing for the forest plot. The previous size
      # 8.5 was unreadable on the production render at 7/12 column width.
      # At full width these settings produce comfortably-readable labels
      # without the plot feeling sparse.
      ggplot2::theme(
        plot.title       = ggplot2::element_text(size = 16, face = "bold"),
        plot.caption     = ggplot2::element_text(size = 10, colour = "#8BA3B5"),
        axis.text.y      = ggplot2::element_text(size = 12),
        axis.text.x      = ggplot2::element_text(size = 11),
        axis.title.x     = ggplot2::element_text(size = 12),
        legend.text      = ggplot2::element_text(size = 11),
        legend.title     = ggplot2::element_text(size = 11),
        legend.position  = "bottom",
        plot.margin      = ggplot2::margin(8, 16, 8, 8)
      )
  })
  output$cox_forest_plot <- renderPlot(cox_forest_plot_obj(),
                                        height = 640, res = PLOT_RES, bg = "#0B2341")

  .cox_forest_code <- function() {
    model_block <- .cox_model_block()
    if (is.null(model_block))
      return("# Run the Cox model first to generate a forest plot code snippet.")
    cohort_block <- .cohort_sql_block()
    if (is.null(cohort_block))
      return("# Cohort SQL not available - build at least one inclusion criterion first.")

    cohort_nm <- input$cohort_name %||% "my_cohort"
    schemas   <- input$schema_select %||% character(0)
    cv        <- cox_rv()
    n_cov     <- nrow(cv$coef_df %||% data.frame())

    header <- sprintf(paste0(
      "# ──────────────────────────────────────────────────────────────────────\n",
      "# Cox proportional hazards - forest plot of adjusted HRs\n",
      "# Cohort:    %s\n",
      "# Schema:    %s (primary)\n",
      "# Covariates: %d in final model\n",
      "# Generated: %s\n",
      "#\n",
      "# Self-contained: builds cohort, queries survival data, extracts\n",
      "# condition and drug covariates with the configured lookback,\n",
      "# computes CCI, fits coxph, and plots HRs with 95%% CIs.\n",
      "# Requires DBI, xaputils, survival, ggplot2.\n",
      "# ──────────────────────────────────────────────────────────────────────\n"),
      cohort_nm,
      schemas[1] %||% "(none)",
      as.integer(n_cov),
      format(Sys.time(), "%Y-%m-%d %H:%M:%S"))

    plot_body <- '
# ── 8. Extract coefficients and plot forest ──────────────────────────────
s <- summary(fit_cox)
coef_df <- data.frame(
  covariate = rownames(s$coefficients),
  hr        = s$coefficients[, "exp(coef)"],
  ci_lo     = s$conf.int[, "lower .95"],
  ci_hi     = s$conf.int[, "upper .95"],
  p_value   = s$coefficients[, "Pr(>|z|)"],
  stringsAsFactors = FALSE
)
coef_df <- coef_df[!is.na(coef_df$hr) & is.finite(coef_df$hr), ]

# Friendly labels (strip cond_ / drug_ prefix)
coef_df$label <- sub("^(cond|drug|proc)_", "", coef_df$covariate)
coef_df$label <- ifelse(nchar(coef_df$label) > 60,
                        paste0(substr(coef_df$label, 1, 57), "..."),
                        coef_df$label)
coef_df <- coef_df[order(coef_df$hr), ]
coef_df$label <- factor(coef_df$label, levels = coef_df$label)
coef_df$sig   <- coef_df$p_value < 0.05

# Cap CIs for display
coef_df$ci_lo_plt <- pmax(coef_df$ci_lo, 0.05)
coef_df$ci_hi_plt <- pmin(coef_df$ci_hi, 10)

ggplot(coef_df, aes(x = hr, y = label, colour = sig)) +
  geom_vline(xintercept = 1, colour = "#E05C6E",
             linetype = "dashed", linewidth = 0.7) +
  geom_errorbarh(aes(xmin = ci_lo_plt, xmax = ci_hi_plt),
                 height = 0.35, linewidth = 0.8) +
  geom_point(size = 3.6) +
  scale_colour_manual(values = c("TRUE" = "#00C5B5", "FALSE" = "#8BA3B5"),
                      labels = c("TRUE" = "p<0.05", "FALSE" = "p>=0.05"),
                      name = "Significance") +
  scale_x_log10(labels = function(x) sprintf("%.2f", x)) +
  labs(x = "Hazard Ratio (log scale, 95% CI)", y = NULL,
       title = "Adjusted Hazard Ratios",
       caption = "Dashed line at HR = 1  |  CIs capped at 0.05-10 for display") +
  theme_minimal() +
  theme(legend.position = "bottom")
'
    paste0(header, cohort_block, model_block, plot_body)
  }

  chart_register("cox_forest", "Cox forest plot (HR + 95% CI)",
                 plot_fn = cox_forest_plot_obj,
                 code_fn = .cox_forest_code,
                 width = 12, height = 8)

  output$cox_coef_table <- DT::renderDataTable({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state,"done") || is.null(cv$coef_df) ||
        nrow(cv$coef_df) == 0)
      return(DT::datatable(
        data.frame(Message = "Run the Cox model to see coefficients."),
        filter = "none", rownames = FALSE,
        options = list(dom = "t")))
    df <- cv$coef_df
    # Bug 12 fix (v8.3): prefer display_name over bare concept_id label.
    df$covariate <- if ("display_name" %in% names(df)) df$display_name
                    else sub("^(cond|drug|proc)_", "", df$covariate)
    df$ci  <- sprintf("%.3f - %.3f", df$ci_lo, df$ci_hi)
    # Bug 11 fix (v8.3): the previous renderer used an empty string as the
    # final column name for the significance asterisks. Some DT versions
    # render an empty-name column with malformed metadata, causing the table
    # body to display "No matching records found" while the pagination still
    # shows non-zero page counts. Naming the column "Sig." removes the issue.
    df$sig <- ifelse(df$p_value < 0.001, "***",
              ifelse(df$p_value < 0.01,  "**",
              ifelse(df$p_value < 0.05,  "*", "")))
    out <- df[order(df$p_value), c("covariate","hr","ci","p_value","sig")]
    names(out) <- c("Covariate","HR","95% CI","p-value","Sig.")
    DT::datatable(out, filter="none", rownames=FALSE, selection="none",
                  options=list(dom="tp", pageLength=15, scrollX=TRUE)) |>
      DT::formatStyle("p-value",
        backgroundColor = DT::styleInterval(c(0.001,0.01,0.05),
          c("#1a2a1a","#1a2a1a","#222a14","transparent")))
  })

  output$cox_summary_ui <- renderUI({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state,"done")) return(NULL)
    tagList(
      tags$table(style="width:100%;font-size:0.84rem;border-collapse:collapse;",
        tags$tr(
          tags$td(style="color:var(--dre-muted);padding:3px 6px;","N"),
          tags$td(style="color:var(--dre-text);font-weight:700;padding:3px 6px;",
                  format(cv$n, big.mark=","))
        ),
        tags$tr(
          tags$td(style="color:var(--dre-muted);padding:3px 6px;","Events"),
          tags$td(style="color:var(--dre-text);font-weight:700;padding:3px 6px;",
                  format(cv$n_events, big.mark=","))
        ),
        tags$tr(
          tags$td(style="color:var(--dre-muted);padding:3px 6px;","Concordance"),
          tags$td(style="color:var(--dre-text);font-weight:700;padding:3px 6px;",
                  if (!is.na(cv$concordance)) sprintf("%.3f", cv$concordance) else "-")
        ),
        tags$tr(
          tags$td(style="color:var(--dre-muted);padding:3px 6px;","LRT p-value"),
          tags$td(style="color:var(--dre-text);font-weight:700;padding:3px 6px;",
                  if (!is.na(cv$lrt_p))
                    ifelse(cv$lrt_p < 0.001, "<0.001", sprintf("%.4f", cv$lrt_p))
                  else "-")
        ),
        tags$tr(
          tags$td(style="color:var(--dre-muted);padding:3px 6px;","Outcome"),
          tags$td(style="color:var(--dre-text);padding:3px 6px;",
                  DOMAINS[[cv$domain]]$label %||% cv$domain)
        )
      )
    )
  })

  # ── Cox diagnostics - prominent alert when something fails ──────────────────
  # Renders only when at least one diagnostic check is outside the accepted
  # threshold. Designed to be the first thing the user sees on the Cox tab.
  output$cox_diagnostics_alert_ui <- renderUI({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done") || is.null(cv$diagnostics))
      return(NULL)
    d <- cv$diagnostics
    if (!isTRUE(d$any_issue)) return(NULL)

    issues <- list()
    if (!isTRUE(d$ph_ok)) {
      if (length(d$ph_failures) > 0) {
        # v9.1: resolve concept names for the failing covariates so the
        # banner reads "drug_1127078 (Acetaminophen 325 MG Oral Tablet)"
        # rather than bare IDs. Mandatory covariates like age_at_index
        # have no name in the lookup; they fall back to the bare key.
        name_map <- cox_name_lookup(cv)
        pretty   <- function(col) {
          if (!is.null(name_map) && col %in% names(name_map))
            as.character(name_map[[col]])
          else col
        }
        failures_pretty <- vapply(d$ph_failures, pretty, character(1))
        issues[[length(issues)+1]] <- sprintf(
          "Proportional hazards assumption violated for: %s. Hazard ratios for these covariates may not be constant over time.",
          paste0("`", failures_pretty, "`", collapse = ", "))
      } else if (!is.na(d$ph_global_p) && d$ph_global_p < 0.05) {
        issues[[length(issues)+1]] <- if (d$ph_global_p < 1e-4)
          "Global proportional hazards test p < 0.0001. At least one covariate has strongly time-varying effects."
        else
          sprintf("Global proportional hazards test p = %.4f (< 0.05). At least one covariate has time-varying effects.",
                  d$ph_global_p)
      }
    }
    if (!isTRUE(d$epv_ok) && !is.na(d$epv)) {
      issues[[length(issues)+1]] <- sprintf(
        "Events per variable: %.1f (recommended ≥10). Model is likely overfit; HR estimates are unstable.",
        d$epv)
    }
    if (!isTRUE(d$vif_ok) && !is.na(d$vif_max)) {
      vif_msg <- if (d$vif_max >= 1000) {
        "Maximum VIF exceeds 1,000 - design matrix is near-singular. At least two covariates are essentially collinear; remove redundant ones before relying on hazard ratios."
      } else {
        sprintf("Maximum VIF: %.1f (> 5). Some covariates are highly correlated; consider removing redundant ones.",
                d$vif_max)
      }
      issues[[length(issues)+1]] <- vif_msg
    }
    if (!is.na(d$n_influential) && d$n_influential > 0) {
      issues[[length(issues)+1]] <- sprintf(
        "%d observation(s) flagged with |dfbeta| > 2/√n. Consider a sensitivity analysis excluding them.",
        d$n_influential)
    }
    if (length(issues) == 0) return(NULL)

    div(
      class = "overlap-panel overlap-partial",
      style = "margin-bottom:14px;",
      tags$span(
        icon("triangle-exclamation"),
        tags$strong("  Cox model diagnostics flagged ",
                    length(issues), if (length(issues) == 1) " issue." else " issues.")),
      tags$ul(style = "margin:6px 0 0 18px;font-size:0.86rem;color:inherit;",
        lapply(issues, function(msg) tags$li(HTML(msg))))
    )
  })

  # ── Full diagnostics panel - PH table, Schoenfeld plots, VIF, EPV, dfbeta ──
  # ── Cox diagnostics panel: discrete output bindings ────────────────────────
  # Bug 14 fix (v8.1): the previous v8 implementation nested `DT::renderDT({...})()`
  # and `renderPlot({...})()` inside a single `renderUI`, which is architecturally
  # wrong in Shiny - render functions produce reactive bindings that must be
  # served by dedicated outputs (`DT::dataTableOutput`, `plotOutput`), not
  # invoked inline. The trailing `()` caused the panel to error out entirely
  # with "argument 'name' is missing, with no default". This rewrite splits
  # the panel into six independent outputs, each handling its own NULL state.

  # Sub-panel 1: EPV statement (UI block, no DT/plot)
  output$cox_diag_epv_ui <- renderUI({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done") || is.null(cv$diagnostics))
      return(NULL)
    d <- cv$diagnostics
    epv_colour <- if (isTRUE(d$epv_ok)) "var(--dre-teal)" else "#E05C6E"
    div(style = "margin-bottom:10px;",
      tags$strong("Events per variable: "),
      tags$span(
        style = sprintf("color:%s;font-weight:700;", epv_colour),
        if (!is.na(d$epv)) sprintf("%.1f", d$epv) else "-"),
      tags$span(style = "color:var(--dre-muted);margin-left:8px;font-size:0.84rem;",
        sprintf("(events=%d, covariates=%d; recommended \u226510)",
                cv$n_events, d$n_coef %||% 0L))
    )
  })

  # v9 covariate-prune transparency panel: shows the user what auto-prune
  # actually did. Collapsed by default via <details>; expands on click.
  output$cox_diag_prune_ui <- renderUI({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done") ||
        is.null(cv$diagnostics) || is.null(cv$diagnostics$prune_log))
      return(NULL)
    pl <- cv$diagnostics$prune_log
    if (pl$candidates_in == 0L) return(NULL)  # nothing to say

    n_epv_dropped <- length(pl$epv_dropped %||% character(0))
    n_coll_drops  <- length(pl$collinear_drops %||% list())
    n_total_drops <- n_epv_dropped + n_coll_drops

    # Translate dropped column names to concept names where the lookup is
    # available. Falls back to the bare column name when not found.
    name_map <- cox_name_lookup(cv)
    pretty <- function(col) {
      if (!is.null(name_map) && col %in% names(name_map)) name_map[[col]]
      else col
    }

    headline <- if (n_total_drops == 0L) {
      sprintf("Covariate selection: %d candidate%s, all retained.",
              pl$candidates_in, if (pl$candidates_in == 1L) "" else "s")
    } else {
      drop_parts <- character(0)
      if (n_epv_dropped > 0L)
        drop_parts <- c(drop_parts,
                        sprintf("%d for events-per-variable", n_epv_dropped))
      if (n_coll_drops > 0L)
        drop_parts <- c(drop_parts,
                        sprintf("%d for collinearity", n_coll_drops))
      sprintf("Covariate selection: %d candidate%s, %d used (%s dropped).",
              pl$candidates_in,
              if (pl$candidates_in == 1L) "" else "s",
              pl$final_n_binary,
              paste(drop_parts, collapse = " + "))
    }

    # EPV explanation line
    epv_line <- sprintf(
      "EPV budget: %d events / %d target = %d coefficients total; %d mandatory (age, sex%s%s) leaves %d for binary covariates.",
      pl$n_events, pl$epv_target, pl$budget_total, pl$mandatory_n,
      if (pl$mandatory_n >= 3) ", CCI" else "",
      if (pl$mandatory_n >= 4) ", schema" else "",
      pl$budget_for_binary)

    # Build detail rows
    detail_blocks <- list()
    if (n_coll_drops > 0L) {
      coll_rows <- lapply(pl$collinear_drops, function(d) {
        tags$li(style = "margin-bottom:4px;",
          tags$span(style = "color:#FFB84D;", sprintf("\u00a6\u03c6\u00a6 = %.3f", abs(d$phi))),
          " \u2014 dropped ",
          tags$em(pretty(d$dropped)),
          " (less prevalent than ",
          tags$em(pretty(d$kept)),
          ")")
      })
      detail_blocks[[length(detail_blocks) + 1]] <- tagList(
        tags$h6(style = "color:var(--dre-teal);font-size:11px;margin:8px 0 4px;",
                "Dropped for collinearity (\u03c6 > 0.95)"),
        tags$ul(style = "margin:0 0 8px 18px;font-size:0.84rem;color:var(--dre-text);",
                coll_rows))
    }
    if (n_epv_dropped > 0L) {
      epv_items <- head(pl$epv_dropped, 12L)
      epv_rows <- lapply(epv_items, function(col)
        tags$li(style = "margin-bottom:2px;color:var(--dre-text);", pretty(col)))
      overflow_note <- if (length(pl$epv_dropped) > 12L)
        tags$p(style = "color:var(--dre-muted);font-size:0.78rem;margin:2px 0 0 0;",
               sprintf("\u2026 plus %d more.", length(pl$epv_dropped) - 12L))
      else NULL
      detail_blocks[[length(detail_blocks) + 1]] <- tagList(
        tags$h6(style = "color:var(--dre-teal);font-size:11px;margin:8px 0 4px;",
                sprintf("Dropped for events-per-variable budget (top %d by prevalence shown)",
                        min(12L, length(pl$epv_dropped)))),
        tags$ul(style = "margin:0 0 4px 18px;font-size:0.84rem;",
                epv_rows),
        overflow_note)
    }

    div(style = "margin-bottom:10px;",
      tags$strong("Covariates: "),
      tags$span(style = "color:var(--dre-text);", headline),
      if (n_total_drops > 0L)
        tags$details(style = "margin-top:6px;",
          tags$summary(style = paste(
            "cursor:pointer;color:var(--dre-muted);",
            "font-size:0.82rem;outline:none;"),
            "Show what was dropped and why"),
          tags$div(style = "margin-top:6px;padding:8px 12px;",
            tags$p(style = "color:var(--dre-muted);font-size:0.82rem;margin:0 0 4px 0;",
                   epv_line),
            detail_blocks))
      else NULL
    )
  })

  # Sub-panel 2: PH global summary (UI block, no DT/plot)
  output$cox_diag_ph_summary_ui <- renderUI({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done") || is.null(cv$diagnostics))
      return(NULL)
    d <- cv$diagnostics
    ph_colour <- if (isTRUE(d$ph_ok)) "var(--dre-teal)" else "#E05C6E"

    # v8.5: when cox.zph failed entirely, show the captured error so the user
    # knows *why* the PH check is missing rather than seeing a silent dash.
    if (is.null(d$zph_obj) && !is.null(d$zph_error)) {
      return(div(style = "margin-bottom:10px;",
        tags$strong("Proportional hazards (global): "),
        tags$span(style = "color:#E05C6E;font-weight:700;", "test failed"),
        tags$div(
          style = "margin-top:4px;color:var(--dre-muted);font-size:0.84rem;",
          tags$em(paste("cox.zph could not compute Schoenfeld residuals:",
                        d$zph_error)),
          tags$br(),
          "This typically indicates a near-singular design (covariates ",
          "are highly collinear). The VIF table below confirms whether ",
          "that is the cause.")
      ))
    }

    div(style = "margin-bottom:10px;",
      tags$strong("Proportional hazards (global): "),
      tags$span(
        style = sprintf("color:%s;font-weight:700;", ph_colour),
        if (!is.na(d$ph_global_p)) {
          if (d$ph_global_p < 1e-4) "p < 0.0001"
          else if (d$ph_global_p < 0.001) sprintf("p = %.5f", d$ph_global_p)
          else sprintf("p = %.4f", d$ph_global_p)
        } else "-")
    )
  })

  # Helper: resolve concept names for diagnostic-table covariate columns.
  # Reads coef_df$display_name if available and applies it by joining on the
  # bare "<domain>_<concept_id>" key. Falls back to the input value when no
  # match exists (non-binary covariates retain their original name).
  cox_name_lookup <- function(cv) {
    if (is.null(cv) || is.null(cv$coef_df) ||
        !"display_name" %in% names(cv$coef_df)) return(NULL)
    setNames(as.character(cv$coef_df$display_name),
             as.character(cv$coef_df$covariate))
  }

  # Sub-panel 3: Schoenfeld test by covariate (proper DT output binding)
  output$cox_diag_zph_table <- DT::renderDataTable({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done") ||
        is.null(cv$diagnostics) || is.null(cv$diagnostics$zph_table))
      return(DT::datatable(
        data.frame(Message = "Schoenfeld test unavailable for this model."),
        filter = "none", rownames = FALSE, options = list(dom = "t")))
    df <- cv$diagnostics$zph_table
    # Bug 12 extension (v8.5): resolve concept names on the diagnostics
    # Schoenfeld table the same way the forest plot and coefficient table do.
    name_map <- cox_name_lookup(cv)
    if (!is.null(name_map)) {
      df$term <- vapply(df$term, function(t)
        if (t %in% names(name_map)) name_map[[t]] else t,
        character(1))
    }
    # v9.1: format raw p-values for display. Tiny values render as
    # "<0.0001" rather than "0" (which is what round(p, 4) produces when
    # p < 5e-5). The underlying numeric is preserved on a hidden column
    # so formatStyle's interval colouring still works.
    df$p_raw     <- df$p
    df$`p-value` <- vapply(df$p, function(p) {
      if (is.na(p)) "-"
      else if (p < 1e-4) "<0.0001"
      else if (p < 0.001) sprintf("%.5f", p)
      else sprintf("%.4f", p)
    }, character(1))
    out <- data.frame(
      Covariate  = df$term,
      `Chi-sq`   = df$chisq,
      df         = df$df,
      `p-value`  = df$`p-value`,
      .p_num     = df$p_raw,
      check.names      = FALSE,
      stringsAsFactors = FALSE)
    DT::datatable(out,
      options    = list(pageLength = 25, dom = "t",
                        columnDefs = list(
                          list(className = "dt-right", targets = 1:3),
                          list(visible   = FALSE,      targets = 4))),
      rownames   = FALSE,
      filter     = "none",
      selection  = "none") |>
      DT::formatStyle("p-value", ".p_num",
        backgroundColor = DT::styleInterval(c(0.01, 0.05),
          c("rgba(224,92,110,.25)", "rgba(255,184,77,.18)", "transparent")))
  })

  # Sub-panel 4: Schoenfeld residual plot.
  # v9.1: replaces survminer::ggcoxzph with a custom plot that:
  #   - shows ONLY the covariates that failed the PH test (p < 0.05),
  #     because the table above already lists every covariate's p-value
  #     and the plot's value-add is the shape of the time-varying effect
  #   - uses concept names rather than bare "<domain>_<concept_id>" keys
  #   - renders p-values < 1e-4 as "<0.0001" rather than "0"
  #   - sizes facets so labels and curves stay readable
  cox_diag_zph_plot_obj <- reactive({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done"))
      return(ggplot2::ggplot() +
        ggplot2::annotate("text", x = 0.5, y = 0.5,
          label = "Run the Cox model to see Schoenfeld plots",
          colour = "#8BA3B5", size = 4) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background = ggplot2::element_rect(fill = "#0B2341", colour = NA)))

    if (is.null(cv$diagnostics) || is.null(cv$diagnostics$zph_obj)) {
      msg <- if (!is.null(cv$diagnostics) && !is.null(cv$diagnostics$zph_error))
        paste0("Schoenfeld test failed: ", cv$diagnostics$zph_error)
      else
        "Schoenfeld plot unavailable for this model"
      return(ggplot2::ggplot() +
        ggplot2::annotate("text", x = 0.5, y = 0.5,
          label = msg, colour = "#FFB84D", size = 4) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background = ggplot2::element_rect(fill = "#0B2341", colour = NA)))
    }

    zph    <- cv$diagnostics$zph_obj
    ztable <- cv$diagnostics$zph_table
    if (is.null(ztable)) return(ggplot2::ggplot() + ggplot2::theme_void())

    # Identify violators (per-covariate p < 0.05, excluding GLOBAL).
    viol_terms <- ztable$term[ztable$term != "GLOBAL" &
                              !is.na(ztable$p) & ztable$p < 0.05]
    if (length(viol_terms) == 0) {
      return(ggplot2::ggplot() +
        ggplot2::annotate("text", x = 0.5, y = 0.5,
          label = "No proportional-hazards violations to plot (all individual tests p \u2265 0.05).",
          colour = "#00C5B5", size = 4) +
        ggplot2::theme_void() +
        ggplot2::theme(plot.background = ggplot2::element_rect(fill = "#0B2341", colour = NA)))
    }

    # Resolve concept names for facet labels.
    name_map <- cox_name_lookup(cv)
    pretty   <- function(t) {
      nm <- if (!is.null(name_map) && t %in% names(name_map)) name_map[[t]] else t
      if (nchar(nm) > 40) paste0(substr(nm, 1, 37), "\u2026") else nm
    }

    # Build the residual data frame manually from the zph object:
    #   zph$x      = transformed times (vector, length n_events)
    #   zph$y      = matrix of residuals (rows = events, cols = terms)
    # When the model has only one term, zph$y is a vector; coerce.
    xs <- as.numeric(zph$x)
    Y  <- zph$y
    if (is.null(dim(Y))) Y <- matrix(Y, ncol = 1L,
                                      dimnames = list(NULL, names(zph$y) %||% "term"))

    # Keep only the violator columns
    term_cols <- intersect(colnames(Y), viol_terms)
    if (length(term_cols) == 0) {
      # Column names in zph$y don't always match $table$term exactly when
      # the model includes interactions or splines; fall back to plotting
      # everything if we can't reconcile.
      term_cols <- colnames(Y)
    }

    plot_df <- do.call(rbind, lapply(term_cols, function(t) {
      data.frame(time = xs, resid = Y[, t],
                 term = t,
                 stringsAsFactors = FALSE)
    }))

    # Facet labels include the formatted p-value so users see why each
    # panel is here without scrolling back to the table.
    p_lookup <- setNames(ztable$p, ztable$term)
    plot_df$label <- vapply(plot_df$term, function(t) {
      nm <- pretty(t)
      pv <- p_lookup[[t]]
      pv_str <- if (is.na(pv)) "NA"
                else if (pv < 1e-4) "<0.0001"
                else if (pv < 0.001) sprintf("%.5f", pv)
                else sprintf("%.4f", pv)
      sprintf("%s\np = %s", nm, pv_str)
    }, character(1))
    # Order facets by p-value (most extreme violation first)
    facet_order <- vapply(term_cols, function(t) {
      nm <- pretty(t)
      pv <- p_lookup[[t]]
      pv_str <- if (is.na(pv)) "NA"
                else if (pv < 1e-4) "<0.0001"
                else if (pv < 0.001) sprintf("%.5f", pv)
                else sprintf("%.4f", pv)
      sprintf("%s\np = %s", nm, pv_str)
    }, character(1))
    plot_df$label <- factor(plot_df$label,
      levels = facet_order[order(p_lookup[term_cols])])

    ggplot2::ggplot(plot_df, ggplot2::aes(x = time, y = resid)) +
      ggplot2::geom_hline(yintercept = 0, colour = "#8BA3B5",
                          linetype = "dashed", linewidth = 0.4) +
      ggplot2::geom_point(colour = "#00C5B5", alpha = 0.45, size = 1.4) +
      ggplot2::geom_smooth(method = "loess", formula = y ~ x,
                           se = TRUE, colour = "#FFB84D",
                           fill = "#FFB84D33", linewidth = 0.7) +
      ggplot2::facet_wrap(~ label, ncol = 2, scales = "free_y") +
      ggplot2::labs(
        x        = "Time (transformed)",
        y        = "Schoenfeld residual",
        title    = sprintf("PH-violating covariates (%d of %d)",
                           length(term_cols),
                           length(ztable$term[ztable$term != "GLOBAL"])),
        subtitle = "A flat smoother means proportional hazards holds; tilt means the effect changes over time.") +
      theme_dre() +
      ggplot2::theme(
        strip.text       = ggplot2::element_text(size = 10, lineheight = 1.0),
        plot.title       = ggplot2::element_text(size = 13, face = "bold"),
        plot.subtitle    = ggplot2::element_text(size = 10, colour = "#8BA3B5"),
        axis.text        = ggplot2::element_text(size = 9),
        panel.spacing.y  = ggplot2::unit(12, "pt"),
        panel.spacing.x  = ggplot2::unit(14, "pt"))
  })
  output$cox_diag_zph_plot <- renderPlot(cox_diag_zph_plot_obj(),
                                          res = PLOT_RES, bg = "#0B2341")

  .cox_diag_code <- function() {
    model_block <- .cox_model_block()
    if (is.null(model_block))
      return("# Run the Cox model first to generate a diagnostics code snippet.")
    cohort_block <- .cohort_sql_block()
    if (is.null(cohort_block))
      return("# Cohort SQL not available - build at least one inclusion criterion first.")

    cohort_nm <- input$cohort_name %||% "my_cohort"
    schemas   <- input$schema_select %||% character(0)

    header <- sprintf(paste0(
      "# ──────────────────────────────────────────────────────────────────────\n",
      "# Cox proportional hazards - Schoenfeld residuals diagnostic\n",
      "# Cohort:    %s\n",
      "# Schema:    %s (primary)\n",
      "# Generated: %s\n",
      "#\n",
      "# Self-contained: builds the same Cox model as the forest plot,\n",
      "# then computes Schoenfeld residuals via cox.zph() and plots them\n",
      "# for covariates with PH-violation p < 0.05. A horizontal trend in\n",
      "# the residuals indicates a violation of the proportional-hazards\n",
      "# assumption for that covariate.\n",
      "# Requires DBI, xaputils, survival, ggplot2.\n",
      "# ──────────────────────────────────────────────────────────────────────\n"),
      cohort_nm,
      schemas[1] %||% "(none)",
      format(Sys.time(), "%Y-%m-%d %H:%M:%S"))

    plot_body <- '
# ── 8. Schoenfeld residuals diagnostic ───────────────────────────────────
zph <- cox.zph(fit_cox)
ztable <- as.data.frame(zph$table)
ztable$term <- rownames(ztable)
cat("Schoenfeld test results:\\n")
print(ztable)

# Identify per-covariate violators (p < 0.05, excluding GLOBAL row)
violators <- ztable$term[ztable$term != "GLOBAL" &
                          !is.na(ztable$p) & ztable$p < 0.05]

if (length(violators) == 0) {
  message("No proportional-hazards violations (all per-covariate p >= 0.05).")
} else {
  message(sprintf("Found %d covariate(s) with PH violations: %s",
                  length(violators), paste(violators, collapse = ", ")))

  # Build a tidy residuals data frame for the violators
  xs <- as.numeric(zph$x)
  Y  <- zph$y
  if (is.null(dim(Y))) Y <- matrix(Y, ncol = 1L,
    dimnames = list(NULL, names(zph$y) %||% "term"))
  term_cols <- intersect(colnames(Y), violators)
  if (length(term_cols) == 0) term_cols <- colnames(Y)

  plot_df <- do.call(rbind, lapply(term_cols, function(t) {
    p_val <- ztable$p[ztable$term == t]
    p_lab <- if (length(p_val) > 0 && !is.na(p_val))
      sprintf("p=%s", ifelse(p_val < 1e-4, "<0.0001", sprintf("%.4f", p_val)))
    else ""
    data.frame(time = xs, resid = Y[, t],
               term = sprintf("%s (%s)", t, p_lab),
               stringsAsFactors = FALSE)
  }))

  ggplot(plot_df, aes(x = time, y = resid)) +
    geom_point(colour = "#8BA3B5", alpha = 0.5, size = 1.2) +
    geom_smooth(method = "loess", se = TRUE,
                colour = "#00C5B5", fill = "#00C5B5", alpha = 0.15,
                linewidth = 0.9, formula = y ~ x) +
    geom_hline(yintercept = 0, colour = "#E05C6E",
               linetype = "dashed", linewidth = 0.5) +
    facet_wrap(~ term, scales = "free", ncol = 2) +
    labs(x = "Time (transformed)",
         y = "Scaled Schoenfeld residual",
         title = "Schoenfeld residuals for covariates with PH violations",
         caption = paste("Each panel: PH assumption violated (p<0.05).",
                          "A non-zero loess trend indicates a time-varying effect.")) +
    theme_minimal()
}
'
    paste0(header, cohort_block, model_block, plot_body)
  }

  chart_register("cox_diag", "Cox diagnostics (Schoenfeld residuals)",
                 plot_fn = cox_diag_zph_plot_obj,
                 code_fn = .cox_diag_code,
                 width = 12, height = 8)

  # Sub-panel 5: VIF table (proper DT output binding)
  output$cox_diag_vif_table <- DT::renderDataTable({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done") ||
        is.null(cv$diagnostics) || is.null(cv$diagnostics$vif_df))
      return(NULL)
    df <- cv$diagnostics$vif_df

    # Bug 12 extension (v8.5): resolve concept names in the covariate column.
    name_map <- cox_name_lookup(cv)
    if (!is.null(name_map)) {
      df$covariate <- vapply(as.character(df$covariate), function(t)
        if (t %in% names(name_map)) name_map[[t]] else t,
        character(1))
    }

    # Bug 13 fix (v8.5): cap VIF display at a sensible threshold so the
    # number is readable. The underlying numeric is retained internally;
    # only the displayed string is truncated. Anything ≥ 1000 is rendered
    # as ">1000 (near-singular)".
    df$vif_display <- ifelse(
      is.na(df$vif) | !is.finite(df$vif), "-",
      ifelse(df$vif >= 1000,
             sprintf("> 1,000 (near-singular)"),
             sprintf("%.2f", df$vif)))
    out <- data.frame(
      Covariate = df$covariate,
      VIF       = df$vif_display,
      check.names = FALSE,
      stringsAsFactors = FALSE)
    # Need a numeric column for styleInterval. Use the original df$vif but
    # capped so styleInterval gets finite values it can compare.
    out$.vif_num <- pmin(df$vif, 1000)

    DT::datatable(out,
      options    = list(pageLength = 25, dom = "t",
                        columnDefs = list(
                          list(className = "dt-right", targets = 1),
                          list(visible   = FALSE,      targets = 2))),
      rownames   = FALSE, filter = "none", selection = "none") |>
      DT::formatStyle("VIF", ".vif_num",
        backgroundColor = DT::styleInterval(c(5, 10),
          c("transparent", "rgba(255,184,77,.18)", "rgba(224,92,110,.25)")))
  })

  # Sub-panel 6: Influential observations summary (UI block)
  output$cox_diag_infl_ui <- renderUI({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done") || is.null(cv$diagnostics))
      return(NULL)
    d <- cv$diagnostics
    if (is.na(d$n_influential)) return(NULL)
    colour <- if (d$n_influential == 0) "var(--dre-teal)" else "#FFB84D"
    div(style = "margin-top:14px;",
      tags$strong("Influential observations: "),
      tags$span(
        style = sprintf("color:%s;font-weight:700;", colour),
        sprintf("%d / %d", d$n_influential, d$dfb_n_rows %||% 0L)),
      tags$span(style = "color:var(--dre-muted);margin-left:8px;font-size:0.84rem;",
        sprintf("(|dfbeta| > %.4f threshold)", d$dfb_threshold %||% NA_real_))
    )
  })

  # VIF "not computed" notice when model has only one covariate. Renders as a
  # short notice in the same slot where the VIF table would go.
  output$cox_diag_vif_notice_ui <- renderUI({
    cv <- cox_rv()
    if (is.null(cv) || !identical(cv$state, "done") || is.null(cv$diagnostics))
      return(NULL)
    d <- cv$diagnostics
    if (!is.null(d$vif_df)) return(NULL)
    if (!is.null(d$n_coef) && d$n_coef < 2)
      tags$p(style = "color:var(--dre-muted);font-size:0.86rem;margin-top:14px;",
        "VIF: not computed (model has only one covariate).")
    else NULL
  })

  # ══════════════════════════════════════════════════════════════════════════
  # TREATMENT PATHWAYS TAB
  # ══════════════════════════════════════════════════════════════════════════

  # Concept search for treatment filter
  observeEvent(input$trt_concept_search_btn, {
    req(conn_valid(), length(input$schema_select %||% character(0)) > 0, nzchar(trimws(input$trt_concept_q %||% "")))
    res <- do_concept_search(input$trt_concept_q,
                             domain_key = input$trt_outcome_domain %||% "drug")
    concept_search_rv(list(context="trt", results=res))
  })

  output$trt_concept_results_ui <- renderUI({
    cs <- concept_search_rv()
    if (is.null(cs) || !identical(cs$context,"trt")) return(NULL)
    rs <- cs$results
    if (is.null(rs) || nrow(rs) == 0)
      return(tags$p(style="color:var(--dre-muted);font-size:0.84rem;","No concepts found."))
    tagList(lapply(seq_len(min(10L, nrow(rs))), function(i) {
      row <- rs[i,]
      tags$div(class="concept-result-row",
        onclick=sprintf("Shiny.setInputValue('trt_concept_pick',%d,{priority:'event'})",
                        as.integer(row$concept_id)),
        tags$span(class="cr-name", row$concept_name %||% ""),
        tags$span(class="cr-id",   sprintf("[%s]", row$concept_id))
      )
    }))
  })

  observeEvent(input$trt_concept_pick, {
    cid   <- as.integer(input$trt_concept_pick)
    cs    <- concept_search_rv()
    if (is.null(cs) || !identical(cs$context,"trt") || is.null(cs$results)) return()
    row   <- cs$results[cs$results$concept_id == cid, ]
    if (nrow(row) == 0) return()
    nm    <- as.character(row$concept_name[1] %||% paste("Concept", cid))
    curr  <- trt_concepts_rv()
    if (!any(vapply(curr, function(x) x$cid == cid, logical(1))))
      trt_concepts_rv(c(curr, list(list(cid=cid, name=nm))))
    concept_search_rv(NULL)
    updateTextInput(session, "trt_concept_q", value="")
  })

  output$trt_selected_concepts_ui <- renderUI({
    cs <- trt_concepts_rv()
    if (length(cs) == 0) return(NULL)
    tagList(
      tags$p(style="color:var(--dre-muted);font-size:0.80rem;margin:4px 0 2px;","Selected concepts:"),
      lapply(cs, function(x)
        tags$span(class="selected-concept-tag",
          x$name,
          tags$a(style="margin-left:4px;cursor:pointer;color:var(--dre-danger);",
                 onclick=sprintf("Shiny.setInputValue('trt_remove_concept',%d,{priority:'event'})", x$cid),
                 "✕"))
      )
    )
  })

  observeEvent(input$trt_remove_concept, {
    cid  <- as.integer(input$trt_remove_concept)
    curr <- trt_concepts_rv()
    trt_concepts_rv(Filter(function(x) x$cid != cid, curr))
  })

  output$trt_status_ui <- renderUI({
    tv <- trt_rv()
    if (is.null(tv)) return(NULL)
    if (identical(tv$state,"running"))
      return(div(style="color:var(--dre-muted);font-size:0.87rem;margin:8px 0;",
                 icon("spinner"), " Running..."))
    if (identical(tv$state,"error"))
      return(div(style="color:var(--dre-danger);font-size:0.87rem;margin:8px 0;",
                 icon("triangle-exclamation"), " ", tv$msg))
    if (identical(tv$state,"done"))
      return(div(style="color:var(--dre-success);font-size:0.87rem;margin:8px 0;",
        icon("circle-check"),
        sprintf(" %s treated within %d days | %s%% of cohort",
                format(tv$n_treated, big.mark=","),
                tv$followup_days,
                round(100*tv$n_treated/max(tv$n_cohort,1)))))
    NULL
  })

  observeEvent(input$run_trt_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type="warning"); return()
    }
    req(conn_valid())

    schemas    <- input$schema_select %||% character(0)
    col_maps_l <- col_maps_rv()
    multi      <- isTRUE(multi_mode_rv()) && "source_schema" %in% names(res)

    cohort_by_schema <- if (multi) split(res, res$source_schema)
                       else setNames(list(res), schemas[[1]] %||% "")

    domain_key   <- input$trt_outcome_domain %||% "drug"
    followup     <- as.integer(input$trt_followup_days %||% 365L)
    top_n        <- as.integer(input$trt_top_n %||% 15L)
    concept_ids  <- vapply(trt_concepts_rv(), `[[`, integer(1), "cid")

    trt_rv(list(state="running"))
    withProgress(message="Analysing treatment pathways...", value=0.3, {
      per_schema <- lapply(names(cohort_by_schema), function(sch) {
        cm  <- col_maps_l[[sch]] %||% omop_col_map_rv()
        sub <- cohort_by_schema[[sch]]
        r   <- tryCatch(
          query_trt_data(sch, cm, sub,
                         domain_key    = domain_key,
                         concept_ids   = concept_ids,
                         followup_days = followup),
          error = function(e) { message("[trt/", sch, "] ", e$message); NULL })
        if (!is.null(r)) r$schema <- sch
        r
      })
      per_schema <- Filter(Negate(is.null), per_schema)
    })

    if (length(per_schema) == 0) {
      trt_rv(list(state="error",
                  msg=sprintf("No treatment data found in %s within %d days of index (any schema).",
                              DOMAINS[[domain_key]]$label, followup)))
      return()
    }

    # Bind first_df across schemas (tagged with source_schema); pool prev_df by concept_id
    first_df_all <- do.call(rbind, Filter(Negate(is.null), lapply(per_schema, function(r) {
      if (is.null(r$first_df) || nrow(r$first_df) == 0) return(NULL)
      d <- r$first_df
      d$source_schema <- r$schema
      d
    })))
    if (is.null(first_df_all) || nrow(first_df_all) == 0) {
      trt_rv(list(state="error",
                  msg=sprintf("No first-treatment events found within %d days.", followup)))
      return()
    }

    prev_df_all <- do.call(rbind, Filter(Negate(is.null), lapply(per_schema, function(r) {
      if (is.null(r$prev_df) || nrow(r$prev_df) == 0) return(NULL)
      d <- r$prev_df
      d$source_schema <- r$schema
      d
    })))

    # Pool prev_df by concept_id and concept_name if present
    prev_df_pooled <- if (!is.null(prev_df_all) && nrow(prev_df_all) > 0) {
      if ("concept_name" %in% names(prev_df_all)) {
        # Aggregate persons by concept_id, pick first concept_name we saw per id
        ag <- aggregate(n_persons ~ concept_id, data = prev_df_all, FUN = sum)
        first_name <- tapply(as.character(prev_df_all$concept_name),
                             prev_df_all$concept_id, function(x) x[[1]])
        ag$concept_name <- first_name[as.character(ag$concept_id)]
        ag[order(-ag$n_persons), ]
      } else {
        aggregate(n_persons ~ concept_id, data = prev_df_all, FUN = sum)
      }
    } else NULL

    # Merge concept_name_map across schemas (later schemas override earlier,
    # but names for the same concept_id should be identical after vocab check).
    concept_name_map <- list()
    for (r in per_schema) {
      if (!is.null(r$concept_name_map))
        concept_name_map <- modifyList(concept_name_map, r$concept_name_map)
    }
    domain_label <- per_schema[[1]]$domain_label %||%
                    (DOMAINS[[domain_key]]$label %||% domain_key)

    trt_rv(list(
      state           = "done",
      first_df        = first_df_all,
      prev_df         = prev_df_pooled,
      concept_name_map = concept_name_map,
      domain_label    = domain_label,
      n_treated       = nrow(first_df_all),
      n_cohort        = nrow(res),
      followup_days   = followup,
      domain_key      = domain_key,
      top_n           = top_n,
      multi           = multi,
      per_schema_counts = if (multi)
        setNames(vapply(per_schema, function(r)
          if (is.null(r$first_df)) 0L else as.integer(nrow(r$first_df)),
          integer(1)), vapply(per_schema, `[[`, character(1), "schema"))
        else NULL
    ))
  })

  output$trt_km_stats_ui <- renderUI({
    tv <- trt_rv()
    if (is.null(tv) || !identical(tv$state,"done") || is.null(tv$first_df)) return(NULL)
    fd <- tv$first_df
    med <- tryCatch({
      sv <- survival::survfit(survival::Surv(days_to_trt, rep(1L, nrow(fd))) ~ 1, data=fd)
      q  <- quantile(sv, probs=0.5)
      sprintf("Median: %s days (95%% CI: %s - %s)",
              format(q$quantile, big.mark=","),
              format(q$lower, big.mark=","),
              format(q$upper, big.mark=","))
    }, error=function(e) "Median: -")
    div(style="font-size:0.84rem;color:var(--dre-teal);margin-bottom:8px;font-weight:600;", med)
  })

  output$trt_km_plot <- renderPlot({
    tv <- trt_rv()
    empty_p <- function(msg) ggplot2::ggplot() +
      ggplot2::annotate("text",x=0.5,y=0.5,label=msg,colour="#8BA3B5",size=4) +
      ggplot2::theme_void() +
      ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA))

    if (is.null(tv) || !identical(tv$state,"done") || is.null(tv$first_df))
      return(empty_p("Run the analysis to see time to first treatment."))

    fd  <- tv$first_df
    nc  <- tv$n_cohort
    # Augment with untreated persons censored at followup_days
    treated_pids <- unique(fd$person_id)
    res          <- cohort_result_rv()
    all_pids     <- if (!is.null(res)) as_pid(res$person_id) else treated_pids
    untreated    <- setdiff(all_pids, treated_pids)
    surv_df <- rbind(
      data.frame(time=fd$days_to_trt, status=1L, stringsAsFactors=FALSE),
      data.frame(time=rep(tv$followup_days, length(untreated)), status=0L,
                 stringsAsFactors=FALSE))
    surv_df$time <- pmax(surv_df$time, 1L)

    fit <- tryCatch(
      survival::survfit(survival::Surv(time, status) ~ 1, data=surv_df),
      error=function(e) NULL)
    if (is.null(fit)) return(empty_p("KM fit failed."))

    km_df <- data.frame(
      time  = c(0, fit$time),
      surv  = c(1, fit$surv),
      upper = c(1, fit$upper),
      lower = c(1, fit$lower))
    km_df <- km_df[!is.na(km_df$surv), ]

    med_t <- tryCatch(quantile(fit, 0.5)$quantile, error=function(e) NA_real_)

    p <- ggplot2::ggplot(km_df, ggplot2::aes(x=time, y=surv)) +
      ggplot2::geom_ribbon(ggplot2::aes(ymin=lower, ymax=upper),
                           fill=grDevices::rgb(0,0.77,0.71,0.12), colour=NA) +
      ggplot2::geom_step(colour="#00C5B5", linewidth=1.1)

    if (!is.na(med_t) && is.finite(med_t)) {
      p <- p +
        ggplot2::geom_vline(xintercept=med_t, colour="#FFB84D",
                            linetype="dashed", linewidth=0.7) +
        ggplot2::annotate("text", x=med_t, y=0.05,
                          label=sprintf("Median\n%d days", as.integer(med_t)),
                          colour="#FFB84D", size=3.2, hjust=-0.1)
    }

    p +
      ggplot2::scale_y_continuous(labels=scales::percent_format(accuracy=1),
                                   limits=c(0,1), expand=c(0.01,0)) +
      ggplot2::scale_x_continuous(labels=function(x) format(x, big.mark=","),
                                   expand=c(0.01,0)) +
      ggplot2::labs(x="Days from index", y="Proportion treatment-naive",
                    title=sprintf("Time to First %s", tv$domain_label),
                    subtitle=sprintf("N cohort=%s | N treated=%s (%.0f%%)",
                      format(nc, big.mark=","),
                      format(tv$n_treated, big.mark=","),
                      100*tv$n_treated/max(nc,1)),
                    caption="Untreated patients censored at end of follow-up window") +
      theme_dre()
  }, height=360, res = PLOT_RES, bg="#0B2341")

  output$trt_top_plot <- renderPlot({
    tv <- trt_rv()
    empty_p <- function(msg) ggplot2::ggplot() +
      ggplot2::annotate("text",x=0.5,y=0.5,label=msg,colour="#8BA3B5",size=4) +
      ggplot2::theme_void() +
      ggplot2::theme(plot.background=ggplot2::element_rect(fill="#0B2341",colour=NA))

    if (is.null(tv) || !identical(tv$state,"done") || is.null(tv$prev_df))
      return(empty_p("Run the analysis to see top treatments."))

    pd  <- tv$prev_df
    nc  <- tv$n_cohort
    top_n <- tv$top_n %||% 15L
    nm_map <- tv$concept_name_map %||% list()

    pd$label <- vapply(as.character(pd$concept_id), function(cid)
      nm_map[[cid]] %||% paste("Concept", cid), character(1))
    pd$label <- ifelse(nchar(pd$label) > 40,
                       paste0(substr(pd$label,1,38),"..."), pd$label)
    pd$pct   <- 100 * pd$n_persons / max(nc, 1)
    pd       <- pd[order(pd$n_persons, decreasing=TRUE), ]
    pd       <- pd[seq_len(min(top_n, nrow(pd))), ]
    pd$label <- factor(pd$label, levels=rev(pd$label))

    ggplot2::ggplot(pd, ggplot2::aes(x=pct, y=label)) +
      ggplot2::geom_col(fill="#00C5B5", width=0.7) +
      ggplot2::geom_text(ggplot2::aes(label=sprintf("%.1f%%", pct)),
                         hjust=-0.1, colour="#C8D6E0", size=3.0) +
      ggplot2::scale_x_continuous(expand=ggplot2::expansion(mult=c(0,0.18)),
                                   labels=function(x) paste0(x,"%")) +
      ggplot2::labs(x="% of cohort", y=NULL,
                    title=sprintf("Top %d %s Received", top_n, tv$domain_label),
                    subtitle=sprintf("Within %d days of index date", tv$followup_days)) +
      theme_dre() +
      ggplot2::theme(axis.text.y=ggplot2::element_text(size=10))
  }, height=360, res = PLOT_RES, bg="#0B2341")

  output$trt_detail_table <- DT::renderDataTable({
    tv <- trt_rv()
    if (is.null(tv) || !identical(tv$state,"done") || is.null(tv$prev_df))
      return(data.frame(Message="Run the analysis first."))

    pd     <- tv$prev_df
    nc     <- tv$n_cohort
    fd     <- tv$first_df
    nm_map <- tv$concept_name_map %||% list()
    top_n  <- tv$top_n %||% 15L

    pd <- pd[order(pd$n_persons, decreasing=TRUE), ]
    pd <- pd[seq_len(min(top_n * 2L, nrow(pd))), ]

    # Median days to first treatment per concept
    med_days <- vapply(as.integer(pd$concept_id), function(cid) {
      rows <- fd[fd$concept_id == cid, ]
      if (nrow(rows) == 0) NA_real_
      else median(rows$days_to_trt, na.rm=TRUE)
    }, numeric(1))

    out <- data.frame(
      Treatment         = vapply(as.character(pd$concept_id),
                                  function(cid) nm_map[[cid]] %||% paste("Concept", cid),
                                  character(1)),
      `Concept ID`      = as.integer(pd$concept_id),
      `N patients`      = as.integer(pd$n_persons),
      `% of cohort`     = round(100 * pd$n_persons / max(nc,1), 1),
      `Median days to first use` = round(med_days, 0),
      stringsAsFactors  = FALSE,
      check.names       = FALSE)

    DT::datatable(out, filter="none", rownames=FALSE, selection="none",
                  options=list(dom="tp", pageLength=20, scrollX=TRUE))
  })

  # ──────────────────────────────────────────────────────────────────────────
  # EXPORT TAB
  # ──────────────────────────────────────────────────────────────────────────

  # ── RMarkdown report download ─────────────────────────────────────────────
  observeEvent(input$export_rmd_btn, {

      # ── 1. Ensure Downloads dir exists ──────────────────────────────────────
      dl_dir <- DOWNLOADS_DIR
      if (!dir.exists(dl_dir)) dir.create(dl_dir, recursive=TRUE, showWarnings=FALSE)

      cohort_nm <- trimws(input$cohort_name %||% "cohort")
      nm_safe   <- gsub("[^A-Za-z0-9_-]", "_", cohort_nm)
      rmd_name  <- paste0(nm_safe, "_report_", format(Sys.Date(), "%Y%m%d"), ".Rmd")
      json_name <- paste0(nm_safe, "_definition_", format(Sys.Date(), "%Y%m%d"), ".json")
      rmd_path  <- file.path(dl_dir, rmd_name)
      json_path <- file.path(dl_dir, json_name)

      # ── 2. Write cohort definition JSON ─────────────────────────────────────
      json_text <- tryCatch(
        serialise_cohort_def(
          criteria          = criteria_rv(),
          cohort_name       = cohort_nm,
          index_strategy    = input$index_strategy    %||% "first_qualifying",
          prior_obs_days    = prior_obs_days_rv(),
          min_followup_days = min_followup_days_rv()
        ),
        error = function(e) {
          attr(NULL, "err") <- conditionMessage(e)
          structure(NULL, err = conditionMessage(e))
        }
      )
      json_write_err <- NULL
      json_written <- FALSE
      if (!is.null(json_text)) {
        tryCatch({
          writeLines(json_text, json_path)
          json_written <- TRUE
        }, error = function(e) {
          json_write_err <<- conditionMessage(e)
        })
      } else {
        # serialise failed - pull error attr if present
        json_write_err <- attr(json_text, "err") %||% "Could not serialise cohort definition (criteria empty?)"
      }
      if (!json_written) {
        json_path <- ""
        # CRITICAL: the Rmd silently produces a "no results" error if it
        # can't load the cohort definition. Tell the user loudly here so
        # they understand why their report won't render.
        showNotification(
          tagList(
            icon("triangle-exclamation"),
            tags$b(" Cohort definition not saved."),
            tags$br(),
            "The .Rmd template will be unable to load the cohort and the report will fail with a 'no results' error. ",
            "Cause: ", json_write_err %||% "(unknown)"
          ),
          type = "error", duration = 12)
        # Don't proceed to write the .Rmd - it would just produce a broken file.
        return()
      }

      # ── 3. Locate the .Rmd template ─────────────────────────────────────────
      search_paths <- c(
        file.path(dirname(getOption("shiny.appDir", default = getwd())), "cohort_report.Rmd"),
        file.path(dl_dir, "cohort_report.Rmd"),
        file.path(getwd(), "cohort_report.Rmd")
      )
      template_path <- Filter(file.exists, search_paths)[1]

      if (is.na(template_path) || !nzchar(template_path %||% "")) {
        showNotification(
          "cohort_report.Rmd template not found. Place it in the same folder as app.R.",
          type="error", duration=8)
        return()
      }

      # ── 4. Inject session values into YAML params ────────────────────────────
      inject_param <- function(lines, param_name, value) {
        in_param    <- FALSE
        after_label <- FALSE
        for (i in seq_along(lines)) {
          if (grepl(sprintf("^  %s:", param_name), lines[i])) {
            in_param    <- TRUE
            after_label <- FALSE
            next
          }
          if (in_param) {
            if (grepl("^    label:", lines[i])) { after_label <- TRUE; next }
            if (after_label && grepl("^    value:", lines[i])) {
              lines[i] <- paste0('    value: "', value, '"')
              return(lines)
            }
            if (grepl("^  [a-z]", lines[i])) in_param <- FALSE
          }
        }
        lines
      }

      rmd_lines <- readLines(template_path, warn=FALSE)
      rmd_lines <- inject_param(rmd_lines, "schema",           paste(input$schema_select %||% character(0), collapse=","))
      rmd_lines <- inject_param(rmd_lines, "cohort_name",      cohort_nm)
      rmd_lines <- inject_param(rmd_lines, "cohort_def_path",  json_path)
      rmd_lines <- inject_param(rmd_lines, "outcome_domain",   input$km_outcome_domain %||% "condition")

      cids <- paste(vapply(km_concepts_rv(), `[[`, integer(1), "cid"), collapse=",")
      # Always inject - even an empty string - so the Rmd surfaces the truth
      # in its Analysis Configuration table and routes to the universal-
      # outcome fallback rather than silently running a degenerate KM.
      rmd_lines <- inject_param(rmd_lines, "outcome_concept_ids", cids)

      rmd_lines <- inject_param(rmd_lines, "cox_lookback_days",
                                 as.character(input$cox_lookback_days %||% 365))
      rmd_lines <- inject_param(rmd_lines, "trt_followup_days",
                                 as.character(input$trt_followup_days %||% 365))
      horizon <- suppressWarnings(as.integer(input$cox_time_horizon))
      if (!is.na(horizon) && horizon > 0)
        rmd_lines <- inject_param(rmd_lines, "time_horizon_days", as.character(horizon))

      # Overlap-aware Survival section uses this to suppress the misleading
      # combined-overlay KM when schemas have no shared calendar window.
      ov <- overlap_rv()
      ov_status <- if (is.null(ov)) "full" else ov$overlap %||% "full"
      rmd_lines <- inject_param(rmd_lines, "overlap_status", ov_status)

      # ── 5. Write .Rmd to Downloads ───────────────────────────────────────────
      tryCatch(
        writeLines(rmd_lines, rmd_path),
        error = function(e) {
          showNotification(paste("Could not write .Rmd:", e$message), type="error")
          return()
        }
      )

      showNotification(
        tagList(
          icon("circle-check"), " Saved to Downloads: ",
          tags$br(),
          tags$code(rmd_name),
          if (json_written) tagList(tags$br(), tags$code(json_name)) else NULL
        ),
        type="message", duration=7)
  })



  # Refresh export schema list on tab switch
  observeEvent(input$main_tabs, {
    if (input$main_tabs == "tab_export") {
      df <- schemas_rv()
      if (is.data.frame(df) && nrow(df) > 0)
        updateSelectInput(session, "export_schema", choices = df$schema_name)
    }
  })

  # ════════════════════════════════════════════════════════════════════════
  # SAVE COHORT - persists multi-schema cohort to omop_browser_scratch
  # ════════════════════════════════════════════════════════════════════════

  saved_cohorts_rv <- reactiveVal(NULL)  # data.frame of cohort_registry rows

  # Save Cohort card UI - only shown when a cohort exists
  output$save_cohort_card_ui <- renderUI({
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) return(NULL)
    multi <- "source_schema" %in% names(res)
    div(class = "cb-card",
      div(class = "cb-card-title", icon("floppy-disk"), " Save Cohort to Database",
        tags$span(style = "float:right;",
          actionButton("save_cohort_btn", tagList(icon("floppy-disk"), " Save"),
                       class = "btn-dre-pri btn-sm"))
      ),
      if (multi) {
        schemas <- unique(res$source_schema)
        by_sch  <- table(res$source_schema)
        div(class = "multi-cohort-banner",
          icon("layer-group"), " Multi-schema cohort: ",
          paste(sapply(schemas, function(s)
            sprintf("%s (%s)", s, format(by_sch[s], big.mark=","))),
            collapse = " \u00b7 "),
          sprintf(" = %s total", format(nrow(res), big.mark=","))
        )
      },
      div(class = "save-cohort-panel",
        fluidRow(
          column(6,
            textInput("save_cohort_name", "Cohort name",
                      value = input$cohort_name %||% "my_cohort",
                      placeholder = "Enter a name for this cohort", width = "100%")
          ),
          column(6,
            uiOutput("save_cohort_status_ui")
          )
        )
      ),
      # ── Registry browser ─────────────────────────────────────────────
      div(style = "margin-top:10px;",
        div(style = "display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;",
          tags$span(style = "font-size:0.87rem;color:var(--dre-muted);font-weight:600;",
                    "Saved Cohorts"),
          actionButton("refresh_registry_btn", label=NULL, icon=icon("rotate"),
                       class="btn-dre-sec btn-sm", title="Refresh saved cohorts list")
        ),
        uiOutput("cohort_registry_ui")
      )
    )
  })

  output$save_cohort_status_ui <- renderUI(NULL)

  observeEvent(input$save_cohort_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type="warning"); return()
    }
    cohort_name <- trimws(input$save_cohort_name %||% "")
    if (!nzchar(cohort_name)) {
      showNotification("Enter a cohort name.", type="warning"); return()
    }
    req(conn_valid())

    # Ensure scratch schema and registry exist
    if (!isTRUE(scratch_ok_rv())) {
      ok <- ensure_scratch_schema()
      scratch_ok_rv(ok)
      if (!ok) {
        showNotification("Could not create scratch schema. Check permissions.",
                         type="error"); return()
      }
    }

    tbl_name <- paste0("cohort_",
                       gsub("[^a-z0-9]", "_", tolower(cohort_name)), "_",
                       format(Sys.time(), "%Y%m%d_%H%M%S"))
    schemas   <- if ("source_schema" %in% names(res))
                   unique(res$source_schema) else paste(input$schema_select %||% character(0), collapse=",")
    by_schema <- if ("source_schema" %in% names(res))
                   jsonlite::toJSON(as.list(table(res$source_schema)), auto_unbox=TRUE)
                 else jsonlite::toJSON(setNames(list(nrow(res)), schemas[1]), auto_unbox=TRUE)
    crit_json <- tryCatch(
      serialise_cohort_def(criteria_rv(), cohort_name,
                            primary_schema(input$schema_select %||% character(0)) %||% schemas[1]),
      error = function(e) NULL)

    # Save data table
    save_df <- res[, intersect(c("source_schema","person_id","index_date","cohort_rank"),
                               names(res)), drop=FALSE]
    if (!"source_schema" %in% names(save_df))
      save_df$source_schema <- schemas[1]
    save_df$person_id <- as.character(save_df$person_id)

    result <- tryCatch({
      DBI::dbWriteTable(DRE_CONN,
        DBI::Id(schema="omop_browser_scratch", table=tbl_name),
        save_df, overwrite=FALSE, row.names=FALSE)
      # Register in cohort_registry
      DBI::dbExecute(DRE_CONN, sprintf(
        "INSERT INTO omop_browser_scratch.cohort_registry
           (cohort_name, source_schemas, n_total, n_by_schema, criteria_json, cohort_table)
         VALUES ('%s', '%s', %d, '%s', '%s', '%s')",
        gsub("'","''",cohort_name),
        gsub("'","''", paste(schemas, collapse=",")),
        nrow(res),
        gsub("'","''", by_schema %||% "{}"),
        gsub("'","''", crit_json %||% "{}"),
        tbl_name))
      list(ok=TRUE, table=tbl_name)
    }, error = function(e) list(ok=FALSE, err=conditionMessage(e)))

    if (isTRUE(result$ok)) {
      output$save_cohort_status_ui <- renderUI(
        div(style="color:var(--dre-success);font-size:0.84rem;margin-top:22px;",
            icon("circle-check"), " Saved as ",
            tags$code(paste0("omop_browser_scratch.", result$table))))
      showNotification(sprintf("Cohort saved: %s", tbl_name), type="message", duration=5)
      # Refresh registry display
      load_registry()
    } else {
      output$save_cohort_status_ui <- renderUI(
        div(style="color:var(--dre-error);font-size:0.84rem;margin-top:22px;",
            icon("triangle-exclamation"), " Error: ", result$err))
    }
  })

  load_registry <- function() {
    r <- tryCatch(db_query(
      "SELECT cohort_id, cohort_name, created_at::text, source_schemas,
              n_total, cohort_table
       FROM omop_browser_scratch.cohort_registry
       ORDER BY created_at DESC LIMIT 20"),
      error = function(e) NULL)
    saved_cohorts_rv(r)
  }

  observeEvent(input$refresh_registry_btn, load_registry())

  output$cohort_registry_ui <- renderUI({
    reg <- saved_cohorts_rv()
    if (is.null(reg) || nrow(reg) == 0)
      return(tags$p(style="color:var(--dre-muted);font-size:0.84rem;",
                    "No saved cohorts yet. Save a cohort above to build a registry."))
    tagList(lapply(seq_len(nrow(reg)), function(i) {
      r <- reg[i,]
      div(style = paste0("padding:10px 12px;margin-bottom:6px;",
                         "background:var(--dre-mid);border-radius:6px;",
                         "border:1px solid var(--dre-border);"),
        div(style="display:flex;align-items:center;justify-content:space-between;",
          div(
            tags$span(style="font-weight:700;color:var(--dre-text);", r$cohort_name),
            tags$span(style="margin-left:10px;font-size:0.78rem;color:var(--dre-teal);",
                      format(as.integer(r$n_total), big.mark=","), " persons")
          ),
          tags$span(style="font-size:0.78rem;color:var(--dre-muted);",
                    substr(r$created_at %||% "", 1, 16))
        ),
        div(style="font-size:0.79rem;color:var(--dre-muted);margin-top:3px;",
            icon("database"), " ", r$source_schemas,
            " | ", tags$code(r$cohort_table))
      )
    }))
  })

  observeEvent(input$export_db_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type = "warning"); return()
    }
    req(conn_valid())
    target_schema <- input$export_schema
    target_table  <- trimws(input$export_table %||% "cohort_output")
    if (!nzchar(target_table)) {
      showNotification("Enter a table name.", type = "warning"); return()
    }

    out_df <- res
    out_df$cohort_name <- input$cohort_name %||% "my_cohort"

    tryCatch({
      fq_out <- fq(target_schema, target_table)
      if (input$export_overwrite) {
        tryCatch(db_execute(sprintf("DROP TABLE IF EXISTS %s", fq_out)),
                 error = function(e) NULL)
      }
      if (exists("xap.db.writeframe", mode = "function")) {
        xap.db.writeframe(out_df, sprintf("%s.%s", target_schema, target_table))
      } else {
        DBI::dbWriteTable(DRE_CONN, DBI::Id(schema = target_schema, table = target_table),
                          out_df, overwrite = input$export_overwrite, append = !input$export_overwrite)
      }
      output$export_db_status_ui <- renderUI(
        div(style = "color:var(--dre-success);font-size:13px;margin-top:8px;",
            icon("circle-check"), sprintf(" Saved %d rows to %s.%s",
                                          nrow(out_df), target_schema, target_table)))
    }, error = function(e) {
      output$export_db_status_ui <- renderUI(
        div(style = "color:var(--dre-danger);font-size:13px;margin-top:8px;",
            icon("triangle-exclamation"), " Error: ", e$message))
    })
  })

  # ── Full cohort extract - download as zip ───────────────────────────────────
  output$export_full_btn <- downloadHandler(
    filename = function() {
      nm <- trimws(input$extract_cohort_name %||% "cohort")
      if (!nzchar(nm)) nm <- "cohort"
      paste0(nm, "_", format(Sys.Date(), "%Y%m%d"), ".zip")
    },
    content = function(file) {
      res <- cohort_result_rv()
      if (is.null(res) || nrow(res) == 0) {
        writeLines("No cohort data - run the query first.", file)
        return()
      }
      nm       <- trimws(input$extract_cohort_name %||% "cohort")
      if (!nzchar(nm)) nm <- "cohort"
      tmp_dir  <- file.path(tempdir(), paste0(nm, "_", format(Sys.Date(), "%Y%m%d")))
      if (dir.exists(tmp_dir)) unlink(tmp_dir, recursive = TRUE)

      schema   <- primary_schema(input$schema_select %||% character(0))
      col_map  <- omop_col_map_rv()
      pids     <- unique(as_pid(res$person_id))

      extract_status_rv(list(state = "running", msg = "Extracting...", tables = list()))

      dict_schema <- trimws(input$extract_dict_schema %||% "")
      result <- withProgress(message = "Extracting cohort data...", value = 0, {
        extract_cohort_tables(
          schema      = schema,
          col_map     = col_map,
          person_ids  = pids,
          out_dir     = tmp_dir,
          dict_schema = dict_schema,
          progress_fn = function(tbl, i, total) {
            setProgress(i / total, detail = tbl)
          }
        )
      })

      extract_status_rv(result)

      # Zip all written files
      csv_files <- unlist(result$files)
      if (length(csv_files) == 0) {
        writeLines("No data extracted.", file); return()
      }
      old_wd <- getwd(); on.exit(setwd(old_wd))
      setwd(dirname(tmp_dir))
      utils::zip(file, files = basename(tmp_dir), flags = "-r9q")

      # Also mirror to workspace Downloads
      dl_dir <- DOWNLOADS_DIR
      if (!dir.exists(dl_dir)) dir.create(dl_dir, recursive = TRUE, showWarnings = FALSE)
      tryCatch(file.copy(file, file.path(dl_dir, basename(file))), error = function(e) NULL)
    }
  )

  # ── Full cohort extract - save to workspace files folder ────────────────────
  observeEvent(input$extract_to_files_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type = "warning"); return()
    }
    nm      <- trimws(input$extract_cohort_name %||% "cohort")
    if (!nzchar(nm)) nm <- "cohort"
    out_dir <- file.path(DOWNLOADS_DIR,
                         paste0(nm, "_", format(Sys.Date(), "%Y%m%d")))
    schema  <- primary_schema(input$schema_select %||% character(0))
    col_map <- omop_col_map_rv()
    pids    <- unique(as_pid(res$person_id))

    extract_status_rv(list(state = "running", msg = "Extracting...", tables = list()))

    dict_schema2 <- trimws(input$extract_dict_schema %||% "")
    withProgress(message = "Saving cohort tables...", value = 0, {
      result <- extract_cohort_tables(
        schema      = schema,
        col_map     = col_map,
        person_ids  = pids,
        out_dir     = out_dir,
        dict_schema = dict_schema2,
        progress_fn = function(tbl, i, total) setProgress(i / total, detail = tbl)
      )
      extract_status_rv(result)
    })

    showNotification(
      sprintf("Saved %d tables to %s", length(result$files), out_dir),
      type = "message", duration = 6)
  })

  # ── Extract status panel ─────────────────────────────────────────────────────
  output$extract_status_ui <- renderUI({
    st <- extract_status_rv()
    if (is.null(st)) return(NULL)

    if (identical(st$state, "running"))
      return(div(style = "color:var(--dre-muted);font-size:0.87rem;margin-top:8px;",
                 icon("spinner"), " Extracting..."))

    # Build table summary
    counts <- st$counts %||% list()
    errors <- st$errors %||% list()
    all_keys <- union(names(counts), names(errors))

    rows <- lapply(all_keys, function(k) {
      if (k %in% names(errors)) {
        tags$tr(
          tags$td(style = "padding:3px 8px;color:var(--dre-muted);font-family:monospace;font-size:0.84rem;", k),
          tags$td(style = "padding:3px 8px;color:var(--dre-error);font-size:0.84rem;",
                  icon("circle-xmark"), " ", errors[[k]])
        )
      } else {
        n <- counts[[k]] %||% 0L
        tags$tr(
          tags$td(style = "padding:3px 8px;color:var(--dre-muted);font-family:monospace;font-size:0.84rem;", k),
          tags$td(style = paste0("padding:3px 8px;font-size:0.84rem;",
                                 if (n == 0) "color:var(--dre-muted);" else "color:var(--dre-success);"),
                  if (n == 0) tags$span(icon("minus"), " no records")
                  else tagList(icon("circle-check"), " ", format(n, big.mark = ","), " rows"))
        )
      }
    })

    n_ok  <- sum(sapply(all_keys, function(k) k %in% names(counts) && (counts[[k]] %||% 0L) > 0))
    n_err <- length(errors)
    div(class = "extract-status-box",
      div(style = "font-weight:700;color:var(--dre-success);margin-bottom:8px;font-size:0.93rem;",
        icon("circle-check"),
        sprintf(" Extract complete - %d persons, %d tables with data",
                st$n_persons %||% 0L, n_ok)
      ),
      tags$table(style = "width:100%;border-collapse:collapse;", do.call(tags$tbody, rows)),
      if (n_err > 0)
        div(style = "color:var(--dre-muted);font-size:0.82rem;margin-top:6px;",
            sprintf("%d table(s) had errors (usually not present in this schema)", n_err))
    )
  })

  output$export_csv_btn <- downloadHandler(
    filename = function() {
      nm <- trimws(input$extract_cohort_name %||% input$cohort_name %||% "cohort")
      if (!nzchar(nm)) nm <- "cohort"
      paste0(nm, "_manifest_", format(Sys.Date(), "%Y%m%d"), ".csv")
    },
    content = function(file) {
      res <- cohort_result_rv()
      if (is.null(res)) res <- data.frame(message = "No cohort data")
      utils::write.csv(res, file, row.names = FALSE)
      dl_dir <- DOWNLOADS_DIR
      if (!dir.exists(dl_dir)) dir.create(dl_dir, recursive = TRUE, showWarnings = FALSE)
      tryCatch(file.copy(file, file.path(dl_dir, basename(file))), error = function(e) NULL)
    }
  )

  output$export_sql_btn <- downloadHandler(
    filename = function() paste0(input$cohort_name %||% "cohort", "_",
                                 format(Sys.Date(), "%Y%m%d"), ".sql"),
    content = function(file) {
      sql <- tryCatch(generated_sql(), error = function(e) "-- No SQL generated")
      writeLines(sql, file)
    }
  )

  # ── AIRA cohort drafting (v10) ────────────────────────────────────────────
  # Renders the natural-language drafting panel on the Build tab. The panel
  # is conditional on aira_is_enabled(); when AIRA is unavailable, the entire
  # block returns NULL so there's no surprise UI.
  #
  # v10.1 instrumentation: the gate decision is logged each time the renderer
  # fires. The first time the Build tab loads, you'll see exactly whether the
  # panel is being shown or hidden and why.
  .aira_render_logged <- FALSE
  output$aira_drafting_panel_ui <- renderUI({
    enabled <- aira_is_enabled(aira_cfg)
    if (!isTRUE(.aira_render_logged)) {
      message(sprintf("[AIRA] panel renderer first call: aira_is_enabled(aira_cfg) = %s",
                       enabled))
      if (!enabled) {
        # Detailed breakdown if hidden
        st <- aira_status_summary(aira_cfg)
        message(sprintf("[AIRA] panel hidden because: cfg_enabled=%s packages_ok=%s api_key_present=%s",
                         st$cfg_enabled, st$packages_ok, st$api_key_present))
      }
      .aira_render_logged <<- TRUE
    }
    if (!enabled) return(NULL)

    # v10.11: schema gate. AIRA drafting depends on do_concept_search,
    # which depends on a selected schema. If no schema is selected the
    # whole resolution path silently fails (req() abort in do_concept_search).
    # Show the panel but lock the input with a clear message rather than
    # hiding it entirely - keeps the feature discoverable.
    schema_sel  <- input$schema_select %||% character(0)
    have_schema <- length(schema_sel) > 0 && nzchar(schema_sel[[1]])
    if (!have_schema) {
      return(div(class = "global-search-bar",
        style = paste(
          "border:1px solid rgba(0,197,181,.30);",
          "background:linear-gradient(180deg, rgba(0,197,181,.04) 0%, transparent 60%);"),
        div(class = "gsb-label",
          icon("wand-magic-sparkles"),
          " Draft a cohort from a plain-English description",
          tags$span(style = paste(
            "margin-left:10px;font-size:0.7rem;",
            "color:var(--dre-muted);font-weight:400;letter-spacing:0;",
            "text-transform:none;"),
            "(AIRA-powered, optional)")
        ),
        tags$div(style = paste(
          "margin-top:10px;padding:14px 18px;",
          "border-left:3px solid var(--dre-warning);",
          "background:rgba(255,184,77,.08);border-radius:0 6px 6px 0;"),
          tags$div(style = "color:var(--dre-text);font-weight:600;margin-bottom:4px;",
            icon("circle-info"),
            " Select a workspace schema to use this feature"),
          tags$p(style = "color:var(--dre-muted);font-size:0.86rem;margin:0;",
            "AIRA needs to know which OMOP schema to search for concepts. ",
            "Choose one from the dropdown in the sidebar to enable cohort drafting."))
      ))
    }
    draft_resp <- aira_draft_rv()
    busy       <- isTRUE(aira_busy_rv())

    # Default panel (before any draft) or panel with a current draft
    panel_body <- if (is.null(draft_resp) || !identical(draft_resp$status, "ok")) {
      # Empty state - input form
      tagList(
        tags$p(class = "gsb-hint",
          style = "margin:0 0 10px;",
          "Describe your cohort in plain English. AIRA will produce a draft ",
          "for you to review and edit before applying."),
        textAreaInput("aira_input", NULL,
          placeholder = paste("e.g. 'New users of NSAIDs aged over 50",
                               "with at least 12 months of prior history,",
                               "excluding anyone with prior GI bleeding'"),
          width = "100%", height = "80px"),
        div(style = "display:flex;gap:10px;align-items:center;margin-top:6px;",
          actionButton("aira_draft_btn",
            tagList(icon("wand-magic-sparkles"), " Draft cohort"),
            class = "btn-dre-pri btn-sm",
            disabled = if (busy) NA else NULL),
          if (busy)
            tags$div(class = "gsb-hint",
              style = "color:var(--dre-teal);margin:0;flex:1;",
              tags$div(style = "display:flex;align-items:center;gap:8px;",
                icon("spinner", class = "fa-spin"),
                tags$span(style = "font-weight:600;",
                  "AIRA is drafting your cohort\u2026")),
              tags$div(style = "color:var(--dre-muted);font-size:0.78rem;margin-top:4px;",
                "Local inference typically takes 20\u201360 seconds. ",
                "You can continue browsing the app; this panel will update when ready."))
          else NULL
        ),
        # Status messages for non-ok responses
        if (!is.null(draft_resp) && !identical(draft_resp$status, "ok"))
          tags$div(style = paste(
            "margin-top:12px;padding:10px 14px;",
            "border-left:3px solid var(--dre-warning);",
            "background:rgba(255,184,77,.08);border-radius:0 6px 6px 0;",
            "color:var(--dre-text);font-size:0.88rem;"),
            tags$strong(switch(draft_resp$status,
              "timeout"     = "AIRA timed out.",
              "unavailable" = "AIRA is unavailable.",
              "malformed"   = "AIRA returned a response we couldn't parse.",
              "disabled"    = "AIRA is not enabled for this session.",
              "AIRA returned an unexpected status.")),
            tags$br(),
            tags$span(style = "color:var(--dre-muted);font-size:0.84rem;",
              switch(draft_resp$status,
                "timeout" = paste(
                  "The model didn't respond within the timeout. Try a",
                  "shorter or simpler description, or wait a few seconds",
                  "and try again \u2014 the AIRA service may be under load."),
                "malformed" = paste(
                  "The model produced output that didn't match the expected",
                  "schema. Try rephrasing your description. You can also",
                  "define the cohort manually below."),
                "You can still define the cohort manually."),
              if (nzchar(draft_resp$reason %||% ""))
                sprintf(" (detail: %s)", draft_resp$reason)
              else "")
          )
        else NULL
      )
    } else {
      # Draft preview state - show what AIRA proposed
      d <- draft_resp$draft
      resolved <- aira_resolved_rv()

      criterion_blocks <- lapply(seq_along(d$criteria), function(i) {
        crit <- d$criteria[[i]]
        res  <- if (!is.null(resolved) && length(resolved) >= i) resolved[[i]] else NULL
        type_label <- if (identical(crit$type, "exclusion")) "EXCLUDE" else "INCLUDE"
        type_colour <- if (identical(crit$type, "exclusion"))
          "var(--dre-error)" else "var(--dre-success)"
        # Concept matches found via search
        match_ui <- if (!is.null(res) && length(res$matches) > 0) {
          tagList(
            tags$div(style = "margin-top:6px;",
              tags$span(class = "gsb-hint",
                style = "color:var(--dre-muted);font-size:0.8rem;",
                sprintf("Matched %d concept%s:",
                        length(res$matches),
                        if (length(res$matches) == 1L) "" else "s")),
              tags$ul(style = "margin:4px 0 0 18px;font-size:0.84rem;color:var(--dre-text);",
                lapply(res$matches, function(m) {
                  # v10.6: show prevalence stats inline so the user can
                  # see what the descendant flag will unlock. When descendants
                  # are requested and the parent concept has more
                  # descendant-aware prevalence than exact, show both.
                  prev_bits <- character(0)
                  if (!is.na(m$n_persons) && m$n_persons > 0L)
                    prev_bits <- c(prev_bits,
                                    sprintf("%s persons exact",
                                            format(m$n_persons, big.mark = ",")))
                  if (!is.na(m$n_persons_desc %||% NA) &&
                      (m$n_persons_desc %||% 0L) > (m$n_persons %||% 0L))
                    prev_bits <- c(prev_bits,
                                    sprintf("%s with descendants",
                                            format(m$n_persons_desc, big.mark = ",")))
                  prev_str <- if (length(prev_bits) > 0)
                    paste0(" \u2014 ", paste(prev_bits, collapse = ", "))
                  else ""
                  tags$li(
                    tags$strong(m$name),
                    tags$span(style = "color:var(--dre-muted);",
                              sprintf(" (id %s, %s)",
                                      m$concept_id, m$class %||% "concept"),
                              prev_str)
                  )
                })
              )
            )
          )
        } else if (!is.null(res)) {
          tags$div(style = "margin-top:6px;color:var(--dre-warning);font-size:0.84rem;",
            icon("triangle-exclamation"),
            sprintf(" No concept matches found for search terms: %s",
                    paste(crit$search_terms, collapse = ", ")))
        } else {
          # v10.9: draft has arrived but concept resolution still in
          # progress - show a per-criterion "resolving..." indicator so
          # the user sees the draft immediately but knows that match
          # info is still being fetched. When aira_resolved_rv updates,
          # this block will be replaced by the matches list above.
          tags$div(style = "margin-top:6px;color:var(--dre-muted);font-size:0.84rem;font-style:italic;",
            icon("spinner", class = "fa-spin"),
            " Resolving concept matches\u2026")
        }

        tags$div(class = "criterion-row",
          style = sprintf("border-left:3px solid %s;", type_colour),
          tags$div(style = "display:flex;justify-content:space-between;align-items:center;",
            tags$span(style = sprintf("font-weight:700;color:%s;font-size:0.78rem;letter-spacing:.6px;",
                                       type_colour),
                      type_label),
            tags$span(style = "color:var(--dre-muted);font-size:0.78rem;",
                      sprintf("%s · descendants %s",
                              toupper(crit$domain %||% "?"),
                              if (isTRUE(crit$include_descendants)) "yes" else "no"))
          ),
          tags$div(style = "margin-top:4px;color:var(--dre-text);",
            paste(crit$search_terms, collapse = ", ")),
          match_ui
        )
      })

      # Demographics summary
      demo_ui <- {
        bits <- character(0)
        if (!is.null(d$demographics$age_at_index_min))
          bits <- c(bits, sprintf("age \u2265 %d", d$demographics$age_at_index_min))
        if (!is.null(d$demographics$age_at_index_max))
          bits <- c(bits, sprintf("age \u2264 %d", d$demographics$age_at_index_max))
        if (!is.null(d$demographics$gender) && nzchar(d$demographics$gender))
          bits <- c(bits, sprintf("gender = %s", d$demographics$gender))
        if (length(bits) > 0)
          tags$div(style = "margin:8px 0;color:var(--dre-text);",
            tags$span(class = "sb-label", "Demographics"),
            tags$div(paste(bits, collapse = " \u00b7 ")))
        else NULL
      }

      tagList(
        # Header with rationale
        tags$div(style = "margin-bottom:12px;",
          tags$div(class = "sb-label",
            sprintf("AIRA draft - '%s'", d$name %||% "cohort")),
          tags$p(style = "color:var(--dre-text);margin:6px 0 0;",
                 d$description %||% ""),
          if (!is.null(d$rationale) && nzchar(d$rationale))
            tags$details(style = "margin-top:8px;",
              tags$summary(style = paste(
                "cursor:pointer;color:var(--dre-muted);",
                "font-size:0.84rem;outline:none;"),
                "AIRA's reasoning"),
              tags$p(style = paste(
                "margin:6px 0 0;padding:10px 14px;",
                "background:rgba(167,139,250,.08);",
                "border-left:3px solid var(--dre-violet, #A78BFA);",
                "border-radius:0 6px 6px 0;color:var(--dre-text);",
                "font-size:0.88rem;"),
                d$rationale))
          else NULL
        ),
        # Settings preview
        tags$div(style = "margin-bottom:10px;",
          tags$span(class = "sb-label", "Prior observation: "),
          tags$span(style = "color:var(--dre-text);",
            sprintf("%s days",
                    format(d$prior_observation_days %||% 365L, big.mark = ",")))
        ),
        # Criterion preview blocks
        tags$div(class = "sb-label", "Proposed criteria"),
        do.call(tagList, criterion_blocks),
        demo_ui,
        # v10.9: disable Apply while concept resolution is still in flight.
        # Clicking it with NULL resolved would skip every criterion as
        # "no matches" - better to make the user wait.
        # Action buttons
        tags$div(style = "margin-top:14px;display:flex;gap:10px;align-items:center;",
          actionButton("aira_apply_btn",
            tagList(icon("check"), " Apply these criteria"),
            class = "btn-dre-pri btn-sm",
            disabled = if (is.null(resolved)) NA else NULL),
          actionButton("aira_discard_btn",
            tagList(icon("rotate-left"), " Discard and start over"),
            class = "btn-dre-sec btn-sm"),
          if (is.null(resolved))
            tags$span(class = "gsb-hint",
              style = "color:var(--dre-muted);font-size:0.78rem;margin:0;",
              "Resolving concepts before Apply can be clicked\u2026")
          else NULL
        ),
        tags$p(class = "gsb-hint",
          style = "margin-top:8px;color:var(--dre-muted);font-size:0.78rem;",
          "Apply will populate the criterion cards below - you can still ",
          "edit, remove, or add to them before running the query.")
      )
    }

    div(class = "global-search-bar",
      style = paste(
        "border:1px solid rgba(0,197,181,.30);",
        "background:linear-gradient(180deg, rgba(0,197,181,.04) 0%, transparent 60%);"),
      div(class = "gsb-label",
        icon("wand-magic-sparkles"),
        " Draft a cohort from a plain-English description",
        tags$span(style = paste(
          "margin-left:10px;font-size:0.7rem;",
          "color:var(--dre-muted);font-weight:400;letter-spacing:0;",
          "text-transform:none;"),
          "(AIRA-powered, optional)")
      ),
      panel_body
    )
  })

  # When the Draft button is clicked: send the input to AIRA asynchronously,
  # then resolve search_terms to concept IDs via the existing concept_search.
  observeEvent(input$aira_draft_btn, {
    req(aira_is_enabled(aira_cfg))
    req(nzchar(trimws(input$aira_input %||% "")))
    aira_busy_rv(TRUE)
    aira_draft_rv(NULL)
    aira_resolved_rv(NULL)

    text_local    <- input$aira_input
    input_chars   <- nchar(text_local)
    cfg_local     <- aira_cfg
    schema_local  <- primary_schema(input$schema_select %||% character(0))
    have_schema   <- length(schema_local) > 0 && nzchar(schema_local)

    # Async call. The future_promise must capture variables it needs by value,
    # not by reference to the reactive context (which won't exist in the worker).
    prom <- aira_draft_cohort_async(text_local, cfg_local)
    promises::then(prom,
      onFulfilled = function(resp) {
        aira_log_event("aira_draft_cohort", resp, input_chars = input_chars)
        # v10.9: only update draft and clear busy. Concept resolution runs
        # in a separate observer below - that observer fires when
        # aira_draft_rv changes, in a fresh reactive flush, so the UI gets
        # to render the draft preview before the resolution loop blocks.
        aira_draft_rv(resp)
        aira_busy_rv(FALSE)
      },
      onRejected = function(e) {
        # Per R-AIRA-02, rejection translates to unavailable status
        resp <- aira_empty_response("unavailable",
                                     reason = paste0("promise_rejected: ",
                                                      conditionMessage(e)))
        aira_log_event("aira_draft_cohort", resp, input_chars = input_chars)
        aira_draft_rv(resp)
        aira_busy_rv(FALSE)
      })
  })

  # v10.9: concept resolution observer. Fires when aira_draft_rv updates
  # with status=ok. Runs in a separate reactive flush from the async
  # callback that set the draft, so the draft preview renders first and
  # the resolution-in-progress indicator shows per criterion. When this
  # finishes, aira_resolved_rv updates and the preview refreshes again
  # with the matched concepts.
  observeEvent(aira_draft_rv(), {
    resp <- aira_draft_rv()
    message(sprintf("[AIRA][RESOLVE] observer fired; resp=%s status=%s",
                     if (is.null(resp)) "NULL" else "set",
                     if (is.null(resp)) "-" else (resp$status %||% "-")))
    if (is.null(resp) || !identical(resp$status, "ok")) return()
    if (!is.null(aira_resolved_rv())) {
      n_resolved <- length(aira_resolved_rv())
      n_criteria <- length(resp$draft$criteria)
      message(sprintf("[AIRA][RESOLVE] existing resolved (n=%d) vs criteria (n=%d)",
                       n_resolved, n_criteria))
      if (n_resolved == n_criteria) {
        message("[AIRA][RESOLVE] already resolved for this draft - skipping")
        return()
      }
    }
    have_schema <- length(input$schema_select %||% character(0)) > 0
    message(sprintf("[AIRA][RESOLVE] have_schema=%s", have_schema))
    if (!have_schema) return()
    d <- resp$draft
    message(sprintf("[AIRA][RESOLVE] resolving %d criteria...", length(d$criteria)))
    resolved <- lapply(seq_along(d$criteria), function(i) {
      crit <- d$criteria[[i]]
      domain_key <- as.character(crit$domain %||% "condition")
      domain_key <- switch(domain_key,
        "drug"        = "drug",
        "condition"   = "condition",
        "procedure"   = "procedure",
        "measurement" = "measurement",
        "visit"       = "visit",
        "observation" = "observation",
        domain_key)
      message(sprintf("[AIRA][RESOLVE]   crit %d domain=%s terms=[%s]",
                       i, domain_key,
                       paste(unlist(crit$search_terms), collapse=",")))
      matches <- list()
      inc_desc <- isTRUE(crit$include_descendants)
      for (term in unlist(crit$search_terms)) {
        t_q <- proc.time()[["elapsed"]]
        # v10.10: catch shiny.silent.error too - do_concept_search uses
        # req() internally which aborts the calling reactive on a failed
        # condition. From inside an observer-with-lapply that abort
        # propagates up and stops the whole resolution. Catch it
        # explicitly and continue to the next term.
        hits <- tryCatch(
          do_concept_search(term, domain_key = domain_key),
          shiny.silent.error = function(e) {
            message(sprintf("[AIRA][RESOLVE]   silent.error on term '%s'", term))
            NULL
          },
          error = function(e) {
            message(sprintf("[AIRA][RESOLVE]   error on term '%s': %s",
                             term, conditionMessage(e)))
            NULL
          })
        dt <- round((proc.time()[["elapsed"]] - t_q) * 1000)
        message(sprintf("[AIRA][RESOLVE]   term '%s' -> %s rows in %sms",
                         term,
                         if (is.null(hits)) "NULL" else nrow(hits),
                         dt))
        if (is.null(hits) || nrow(hits) == 0) next
        hits_lower <- hits
        score_desc <- if ("n_persons_desc" %in% names(hits_lower))
          pmax(as.integer(hits_lower$n_persons_desc %||% 0L),
               as.integer(hits_lower$n_persons %||% 0L),
               na.rm = TRUE)
        else as.integer(hits_lower$n_persons %||% 0L)
        score_exact <- as.integer(hits_lower$n_persons %||% 0L)
        hits_lower$.score <- if (inc_desc) score_desc else score_exact
        hits_lower <- hits_lower[order(-hits_lower$.score), , drop = FALSE]
        hits_lower <- hits_lower[hits_lower$.score > 0L, , drop = FALSE]
        if (nrow(hits_lower) == 0) next
        top <- hits_lower[1, ]
        matches[[length(matches) + 1]] <- list(
          concept_id = as.integer(top$concept_id),
          name       = as.character(top$concept_name),
          class      = as.character(top$concept_class_id %||% NA_character_),
          n_persons  = as.integer(top$n_persons %||% NA),
          n_persons_desc = if ("n_persons_desc" %in% names(top))
            as.integer(top$n_persons_desc %||% NA) else NA_integer_,
          source_term = term)
      }
      list(matches = matches, domain_key = domain_key,
           include_descendants = inc_desc)
    })
    message(sprintf("[AIRA][RESOLVE] calling aira_resolved_rv with %d entries",
                     length(resolved)))
    aira_resolved_rv(resolved)
    message("[AIRA][RESOLVE] aira_resolved_rv set; observer done")
  }, ignoreInit = TRUE)

  # Apply: convert the AIRA draft into actual criterion cards. Each criterion
  # becomes one card with the resolved concept IDs as `concept_ids`. Demographic
  # filters and prior_observation_days are pushed into the corresponding inputs.
  observeEvent(input$aira_apply_btn, {
    resp <- aira_draft_rv()
    if (is.null(resp) || !identical(resp$status, "ok")) return()
    d        <- resp$draft
    resolved <- aira_resolved_rv()

    # v10.7 instrumentation: log full state at Apply click time
    message(sprintf("[AIRA][APPLY] click; draft has %d criteria; resolved has %d entries",
                     length(d$criteria), length(resolved)))
    for (i in seq_along(d$criteria)) {
      crit <- d$criteria[[i]]
      res  <- if (!is.null(resolved) && length(resolved) >= i) resolved[[i]] else NULL
      n_matches <- if (!is.null(res)) length(res$matches) else 0L
      message(sprintf("[AIRA][APPLY] crit %d: type=%s domain_in=%s domain_resolved=%s search=%s n_matches=%d",
                       i,
                       crit$type %||% "?",
                       crit$domain %||% "?",
                       (res$domain_key %||% "?"),
                       paste(unlist(crit$search_terms), collapse=","),
                       n_matches))
      if (!is.null(res) && n_matches > 0) {
        for (j in seq_along(res$matches)) {
          m <- res$matches[[j]]
          message(sprintf("[AIRA][APPLY]   match %d: cid=%s name=%s class=%s",
                           j, m$concept_id %||% "?", m$name %||% "?",
                           m$class %||% "?"))
        }
      }
    }

    # Prior observation
    if (!is.null(d$prior_observation_days)) {
      val <- as.integer(d$prior_observation_days)
      updateNumericInput(session, "prior_obs_days", value = val)
      prior_obs_days_rv(val)
    }

    # Set cohort name
    if (!is.null(d$name) && nzchar(d$name))
      updateTextInput(session, "cohort_name", value = as.character(d$name))

    # Build criteria. For each AIRA criterion, only include if we have at
    # least one resolved concept match (otherwise the criterion would be
    # empty and useless).
    crits         <- criteria_rv()
    id_counter    <- next_id_rv()
    cn            <- concept_names_rv()
    added_count   <- 0L
    skipped_count <- 0L

    for (i in seq_along(d$criteria)) {
      crit <- d$criteria[[i]]
      res  <- if (!is.null(resolved) && length(resolved) >= i) resolved[[i]] else NULL
      cids <- if (!is.null(res) && length(res$matches) > 0)
        vapply(res$matches, function(m) as.integer(m$concept_id), integer(1))
      else integer(0)
      message(sprintf("[AIRA][APPLY] building crit %d: cids=[%s]",
                       i, paste(cids, collapse = ",")))
      if (length(cids) == 0L) {
        skipped_count <- skipped_count + 1L
        next
      }
      # Cache concept names
      for (m in res$matches) cn[[as.character(m$concept_id)]] <- m$name

      new_id <- paste0("crit_", id_counter)
      id_counter <- id_counter + 1L
      new_crit <- list(
        id = new_id,
        type = if (identical(crit$type, "exclusion")) "exclusion" else "inclusion",
        domain = res$domain_key,
        concept_ids = cids,
        occur_min = 1L, occur_max = NA_integer_,
        window_start = NA_integer_, window_end = NA_integer_,
        age_min = NA_integer_, age_max = NA_integer_,
        gender_ids = integer(0),
        value_min = NA_real_, value_max = NA_real_
      )
      # v10.8: the criterion-card UI reads `cr$use_descendants`, not
      # `include_descendants` - use the existing field name so the
      # checkbox tickbox renders correctly. Also note the observer that
      # syncs the checkbox state back to the criterion needs to be
      # triggered, which Shiny does automatically once the input is
      # rendered with value=TRUE.
      if (isTRUE(crit$include_descendants))
        new_crit$use_descendants <- TRUE
      crits <- c(crits, list(new_crit))
      added_count <- added_count + 1L
      message(sprintf("[AIRA][APPLY] appended criterion id=%s domain=%s concept_ids=[%s] descendants=%s",
                       new_id, new_crit$domain,
                       paste(new_crit$concept_ids, collapse=","),
                       isTRUE(new_crit$use_descendants)))
    }

    next_id_rv(id_counter)
    concept_names_rv(cn)
    criteria_rv(crits)
    message(sprintf("[AIRA][APPLY] done; added=%d skipped=%d; criteria_rv now has %d entries",
                     added_count, skipped_count, length(crits)))

    # Clear the AIRA panel so the user goes back to the input form
    aira_draft_rv(NULL)
    aira_resolved_rv(NULL)
    updateTextAreaInput(session, "aira_input", value = "")

    # Notify
    msg <- sprintf("Applied %d criteria from AIRA draft%s",
                    added_count,
                    if (skipped_count > 0L)
                      sprintf(" (%d skipped - no concept matches)", skipped_count)
                    else "")
    showNotification(msg, type = if (skipped_count > 0L) "warning" else "message",
                      duration = 6)
  })

  # Discard: clear the draft and return to the input form
  observeEvent(input$aira_discard_btn, {
    aira_draft_rv(NULL)
    aira_resolved_rv(NULL)
  })

  # ──────────────────────────────────────────────────────────────────────────
  # OHDSI TOOLS (v10.14) - parallel RPostgres + CDMConnector / OmopSketch
  # ──────────────────────────────────────────────────────────────────────────
  # Increment 2: plumbing (inc. 1) plus OmopSketch profiling. Opens the parallel
  # connection lazily, caches a cdm_reference for the primary schema, then runs
  # summariseOmopSnapshot and summariseConceptIdCounts and renders them. Each
  # summarise carries its own error so a snapshot failure on a non-conformant
  # schema (e.g. text-typed dates) still shows the concept counts, and vice
  # versa. States: packages missing / no connection / no schema / build error /
  # ready (with per-section amber on a profiling failure).

  # Lazily open (once per session) the parallel RPostgres connection. Reuses the
  # cached one while it stays valid.
  ensure_ohdsi_con <- function() {
    con <- ohdsi_con_rv()
    if (!is.null(con) && tryCatch(DBI::dbIsValid(con), error = function(e) FALSE))
      return(con)
    con <- ohdsi_open_connection()
    ohdsi_con_rv(con)
    con
  }

  # Build (or reuse) the cdm_reference for the primary selected schema. The
  # build inspects the schema and is slow, so it is cached in ohdsi_cdm_rv and
  # only rebuilt when the primary schema changes. Schema is read with isolate()
  # so this helper creates no reactive dependencies of its own; the two
  # observers below decide when it runs.
  refresh_ohdsi_cdm <- function() {
    schemas <- isolate(input$schema_select) %||% character(0)
    if (length(schemas) == 0) {
      ohdsi_cdm_rv(list(cdm = NULL, schema = NA_character_, error = NULL))
      return(invisible())
    }
    primary <- schemas[1]
    cur <- ohdsi_cdm_rv()
    if (!is.null(cur$cdm) && identical(cur$schema, primary)) return(invisible())

    con <- ensure_ohdsi_con()
    if (is.null(con)) {
      ohdsi_cdm_rv(list(cdm = NULL, schema = primary,
        error = "Could not open an OHDSI-compatible (RPostgres) connection in this workspace. Database credentials may not be reachable to a second driver."))
      return(invisible())
    }
    cdm <- ohdsi_build_cdm(con, primary)
    if (is.null(cdm)) {
      ohdsi_cdm_rv(list(cdm = NULL, schema = primary,
        error = sprintf("CDMConnector could not build a cdm_reference for schema '%s'. It may not be OHDSI-conformant (for example, date columns stored as text). See the app log for the underlying error.", primary)))
    } else {
      ohdsi_cdm_rv(list(cdm = cdm, schema = primary, error = NULL))
    }
  }

  # ── APP-WIDE CDM ACCESSOR (v11) ───────────────────────────────────────────
  # get_cdm() returns the CDMConnector cdm_reference for a schema (default: the
  # primary selected), so any feature - not just the OHDSI tab - can reach the
  # standards stack. Reuses the parallel RPostgres connection and the same
  # ohdsi_cdm_rv cache, so the two paths stay consistent and nothing existing
  # changes. Returns a cdm_reference or NULL. The build inspects the schema and
  # is slow; call it behind an explicit user action, never on every render.
  get_cdm <- function(schema = NULL) {
    if (!ohdsi_pkgs_available()) return(NULL)
    schema <- schema %||% (isolate(input$schema_select) %||% character(0))[1]
    if (is.null(schema) || length(schema) != 1 || is.na(schema) || !nzchar(schema))
      return(NULL)
    cur <- ohdsi_cdm_rv()
    if (!is.null(cur$cdm) && identical(cur$schema, schema)) return(cur$cdm)
    con <- ensure_ohdsi_con()
    if (is.null(con)) return(NULL)
    cdm <- ohdsi_build_cdm(con, schema)
    if (!is.null(cdm)) ohdsi_cdm_rv(list(cdm = cdm, schema = schema, error = NULL))
    cdm
  }

  # Cohort-attached sibling of get_cdm: returns a cdm_reference with a saved
  # cohort table attached, for cohort-level standards diagnostics. Works on
  # materialised cohorts (those with a table in the schema). Returns the cdm
  # (caller reads cdm[[cohort_table]]) or NULL. Built fresh, not cached, since it
  # is behind an explicit action and depends on the chosen table.
  get_cohort_cdm <- function(schema = NULL, cohort_table = NULL) {
    if (!ohdsi_pkgs_available()) return(NULL)
    schema <- schema %||% (isolate(input$schema_select) %||% character(0))[1]
    if (is.null(schema) || length(schema) != 1 || is.na(schema) || !nzchar(schema))
      return(NULL)
    if (is.null(cohort_table) || !nzchar(cohort_table)) return(NULL)
    con <- ensure_ohdsi_con()
    if (is.null(con)) return(NULL)
    ohdsi_build_cohort_cdm(con, schema, cohort_table)
  }

  # Run (or reuse) OmopSketch profiling for the primary schema. Each summarise
  # is wrapped independently so one failing does not blank the other. Cached in
  # ohdsi_profile_rv and only re-run when the schema changes. summariseOmopSnapshot
  # is the date-sensitive one (fails on text-typed dates); summariseConceptIdCounts
  # is existence-guarded against version drift.
  refresh_ohdsi_profile <- function(cdm, schema) {
    cur <- ohdsi_profile_rv()
    already <- identical(cur$schema, schema) &&
               (!is.null(cur$snapshot) || !is.null(cur$snapshot_err))
    if (already) return(invisible())

    # Isolation helpers, closing over cdm. Each keeps the summarised_result
    # object (not a data frame) so the ecosystem renderers (visOmopTable,
    # plotTrend) can be used; ohdsi_combine() binds per-table pieces into one
    # summarised_result via omopgenerics::bind, falling back to an rbind'd data
    # frame if bind is unavailable (the table renderer handles either). per_table() runs an
    # omopTableName summarise one table at a time so a bad table is a skip;
    # single() runs a cdm-only summarise. Both existence-guard the function.
    ohdsi_combine <- function(parts, skipped, empty_msg) {
      if (length(parts) == 0)
        return(list(result = NULL, skipped = skipped, err = empty_msg))
      bound <- tryCatch(do.call(omopgenerics::bind, unname(parts)),
                        error = function(e) NULL)
      if (!is.null(bound)) return(list(result = bound, skipped = skipped, err = NULL))
      dfp <- Filter(Negate(is.null), lapply(parts, ohdsi_sr_to_df))
      if (length(dfp) == 0)
        return(list(result = NULL, skipped = skipped, err = empty_msg))
      df <- tryCatch({ d <- do.call(rbind, dfp); rownames(d) <- NULL; d },
                     error = function(e) NULL)
      if (is.null(df))
        return(list(result = NULL, skipped = skipped,
          err = "Per-table results could not be combined into one result."))
      list(result = df, skipped = skipped, err = NULL)
    }
    per_table <- function(fn_name, ...) {
      if (!ohdsi_has_fn(fn_name))
        return(list(result = NULL, skipped = character(0),
          err = sprintf("%s is not available in this OmopSketch version.", fn_name)))
      tabs <- ohdsi_count_tables(cdm)
      if (length(tabs) == 0)
        return(list(result = NULL, skipped = character(0),
          err = "No countable clinical tables present in this schema's cdm_reference."))
      fn <- getExportedValue("OmopSketch", fn_name)
      parts <- list(); skipped <- character(0)
      for (tb in tabs) {
        one <- tryCatch(fn(cdm, omopTableName = tb, ...), error = function(e) NULL)
        if (!is.null(one) && nrow(one) > 0) parts[[tb]] <- one else skipped <- c(skipped, tb)
      }
      ohdsi_combine(parts, skipped,
        sprintf("OmopSketch could not run %s on any table.", fn_name))
    }
    single <- function(fn_name) {
      if (!ohdsi_has_fn(fn_name))
        return(list(result = NULL,
          err = sprintf("%s is not available in this OmopSketch version.", fn_name)))
      fn <- getExportedValue("OmopSketch", fn_name)
      e <- NULL
      r <- tryCatch(fn(cdm), error = function(err) { e <<- conditionMessage(err); NULL })
      list(result = r, err = e)
    }
    # summariseTrend replaces the deprecated summariseRecordCount. It bins record
    # counts by time interval and needs tables split into event (start date only)
    # and episode (start+end: *_era, observation_period). Called per table with
    # isolation so one table with non-conformant dates skips only itself.
    trend_build <- function() {
      if (!ohdsi_has_fn("summariseTrend"))
        return(list(result = NULL, skipped = character(0),
          err = "summariseTrend is not available in this OmopSketch version."))
      present  <- tryCatch(names(cdm), error = function(e) character(0))
      episodes <- intersect(c("observation_period", "drug_era", "condition_era",
                              "dose_era"), present)
      events   <- setdiff(ohdsi_count_tables(cdm), episodes)
      todo     <- c(setNames(events,   rep("event",   length(events))),
                    setNames(episodes, rep("episode", length(episodes))))
      if (length(todo) == 0)
        return(list(result = NULL, skipped = character(0),
          err = "No tables available for a temporal trend in this cdm_reference."))
      parts <- list(); skipped <- character(0)
      for (i in seq_along(todo)) {
        tb <- todo[[i]]
        a  <- list(cdm = cdm, output = "record", interval = "years")
        a[[names(todo)[i]]] <- tb            # event = tb  OR  episode = tb
        one <- tryCatch(do.call(OmopSketch::summariseTrend, a), error = function(e) NULL)
        if (!is.null(one) && nrow(one) > 0) parts[[tb]] <- one else skipped <- c(skipped, tb)
      }
      ohdsi_combine(parts, skipped,
        "OmopSketch could not compute a temporal trend on any table.")
    }

    snap   <- single("summariseOmopSnapshot")        # date-sensitive
    person <- single("summarisePerson")              # demographics, cdm-only
    obs    <- single("summariseObservationPeriod")   # cdm-only
    cnt    <- per_table("summariseConceptIdCounts", countBy = "person")
    trd    <- trend_build()                           # temporal record trend
    miss   <- per_table("summariseMissingData")      # field-level missingness

    ohdsi_profile_rv(list(
      schema        = schema,
      snapshot      = snap$result,   snapshot_err   = snap$err,
      person        = person$result, person_err     = person$err,
      obsperiod     = obs$result,    obsperiod_err  = obs$err,
      counts        = cnt$result,    counts_err     = cnt$err,  counts_skipped  = cnt$skipped,
      trend         = trd$result,    trend_err      = trd$err,  trend_skipped   = trd$skipped,
      missing       = miss$result,   missing_err    = miss$err, missing_skipped = miss$skipped))
  }

  # Build the cdm_reference then profile it, with a single progress bar. Called
  # when the OHDSI tab becomes active and whenever the schema changes while it
  # is active. ohdsi_activate() is a no-op when the OHDSI path is unavailable;
  # the panel then renders the not-available state.
  ohdsi_activate <- function() {
    if (!ohdsi_is_available()) return(invisible())
    withProgress(message = "OHDSI tooling\u2026", value = 0.2, {
      setProgress(0.3, detail = "Building cdm_reference")
      refresh_ohdsi_cdm()
      st <- ohdsi_cdm_rv()
      if (!is.null(st$cdm)) {
        setProgress(0.6, detail = "Profiling with OmopSketch")
        refresh_ohdsi_profile(st$cdm, st$schema)
        # Cheap cohort-table discovery for the characterisation section; clear
        # any characterisation result left over from a different schema.
        ohdsi_cohort_tables_rv(ohdsi_discover_cohort_tables(st$schema))
        if (!identical(ohdsi_cohort_result_rv()$schema, st$schema))
          ohdsi_cohort_result_rv(list())
      }
      setProgress(1)
    })
  }

  observeEvent(input$main_tabs, {
    if (identical(input$main_tabs, "tab_ohdsi")) ohdsi_activate()
  })
  observeEvent(input$schema_select, {
    if (identical(input$main_tabs, "tab_ohdsi")) ohdsi_activate()
  })

  output$ohdsi_panel_ui <- renderUI({
    muted <- "font-size:0.84rem;color:var(--dre-muted);margin-top:6px;"
    base  <- "padding:6px 2px;font-size:0.92rem;"

    if (!ohdsi_pkgs_available()) {
      return(div(style = base,
        tags$p(icon("triangle-exclamation"),
          " The OHDSI tooling packages are not installed in this workspace."),
        tags$p(style = muted,
          "This tab needs these CRAN packages: ",
          tags$code(paste(ohdsi_optional_packages, collapse = ", ")),
          ". Ask a workspace administrator to add them to the image. Every other ",
          "tab works without them.")))
    }
    if (!conn_valid()) {
      return(div(style = base,
        tags$p(icon("plug-circle-xmark"), " No database connection.")))
    }
    schemas <- input$schema_select %||% character(0)
    if (length(schemas) == 0) {
      return(div(style = base,
        tags$p(icon("database"), " Select a schema to begin."),
        tags$p(style = muted,
          "Choose an OMOP schema from the sidebar selector. The OHDSI tools ",
          "build a cdm_reference for the first selected schema.")))
    }
    st <- ohdsi_cdm_rv()
    if (!is.null(st$error)) {
      return(div(style = base,
        tags$p(style = "color:var(--dre-danger);",
          icon("circle-exclamation"), " ", st$error)))
    }
    if (is.null(st$cdm)) {
      return(div(style = base,
        tags$p(icon("hourglass-half"), " Preparing OHDSI connection\u2026")))
    }

    # cdm built - show connection status + OmopSketch profiling.
    prof <- ohdsi_profile_rv()
    tbls <- tryCatch(names(st$cdm), error = function(e) character(0))

    amber <- function(msg, hint = NULL) div(
      style = "padding:8px 10px;margin-top:6px;border-left:3px solid var(--dre-warn);background:rgba(0,0,0,0.15);border-radius:4px;",
      tags$p(style = "margin:0;color:var(--dre-warn);font-size:0.86rem;",
        icon("triangle-exclamation"), " ", msg),
      if (!is.null(hint))
        tags$p(style = "margin:4px 0 0;font-size:0.8rem;color:var(--dre-muted);", hint))

    # Collapsible section (native <details>, no JS). open = first section only.
    section <- function(open, icon_name, title, fn_label, body) {
      d <- tags$details(
        style = "margin-top:10px;border-top:1px solid var(--dre-border);padding-top:8px;",
        tags$summary(
          style = "cursor:pointer;font-size:0.95rem;color:var(--dre-text);font-weight:600;",
          icon(icon_name), " ", title,
          tags$span(style = "font-size:0.78rem;color:var(--dre-muted);font-weight:normal;",
            paste0(" ", fn_label))),
        div(style = "margin-top:8px;", body))
      if (isTRUE(open)) d <- tagAppendAttributes(d, open = NA)
      d
    }
    # Section body: amber on error, else optional blurb + skipped note + gt table.
    tbl_body <- function(err, output_id, blurb = NULL, skipped = NULL) {
      if (!is.null(err)) return(amber(err))
      tagList(
        if (!is.null(blurb)) tags$p(style = muted, blurb),
        if (length(skipped) > 0)
          tags$p(style = muted,
            sprintf("Skipped %d table(s) OmopSketch could not summarise: %s.",
                    length(skipped), paste(skipped, collapse = ", "))),
        ohdsi_tbl_out(output_id))
    }

    div(style = base,
      tags$p(style = "color:var(--dre-success);margin-bottom:2px;",
        icon("circle-check"),
        sprintf(" Connected. cdm_reference built for schema '%s'.", st$schema)),
      tags$p(style = muted,
        sprintf("%d OMOP tables visible through CDMConnector, profiled with OmopSketch. Sections are collapsible.",
                length(tbls))),
      div(style = "margin:8px 0 2px;",
        actionButton("ohdsi_export_btn",
                     tagList(icon("file-export"), " Save summaries to Downloads"),
                     class = "btn-sm"),
        tags$span(style = paste0(muted, "margin-left:8px;"),
          if (is.na(ohdsi_xlsx_writer()))
            "Writes a zip of CSVs (one per summary) to /home/workspace/files/Downloads; no Excel writer is installed."
          else
            "Writes a multi-sheet .xlsx (one sheet per summary) to /home/workspace/files/Downloads.")),

      section(TRUE, "clipboard-list", "Snapshot", "summariseOmopSnapshot()",
        if (!is.null(prof$snapshot_err))
          amber(sprintf("OmopSketch could not summarise this schema: %s", prof$snapshot_err),
                "This usually means the schema is not fully OHDSI-conformant - for example OMOP date columns stored as text rather than as a date type. The cdm_reference still built; the standard profiler cannot run over non-conformant typing. The native SQL tabs are unaffected.")
        else ohdsi_tbl_out("ohdsi_snapshot_tbl")),

      section(FALSE, "user-group", "Person", "summarisePerson()",
        tbl_body(prof$person_err, "ohdsi_person_tbl",
          blurb = "Demographic summary of the person table: sex, year of birth, and record completeness.")),

      section(FALSE, "calendar-days", "Observation periods", "summariseObservationPeriod()",
        tbl_body(prof$obsperiod_err, "ohdsi_obs_tbl",
          blurb = "Distribution of observation periods: counts, durations, and coverage.")),

      section(FALSE, "chart-line", "Record trend over time", "summariseTrend() / plotTrend()",
        if (!is.null(prof$trend_err)) amber(prof$trend_err)
        else tagList(
          tags$p(style = muted,
            "Record counts per clinical table over time (yearly). Event tables use the start date; episode tables (eras, observation periods) span start to end."),
          if (length(prof$trend_skipped) > 0)
            tags$p(style = muted,
              sprintf("Skipped %d table(s): %s.", length(prof$trend_skipped),
                      paste(prof$trend_skipped, collapse = ", "))),
          plotOutput("ohdsi_trend_plot", height = "380px"),
          tags$p(style = paste0(muted, "margin-top:10px;"), "Underlying values:"),
          ohdsi_tbl_out("ohdsi_trend_tbl"))),

      section(FALSE, "hashtag", "Concept ID counts", "summariseConceptIdCounts()",
        tbl_body(prof$counts_err, "ohdsi_counts_tbl",
          blurb = "Per-concept patient counts. A schema whose standard vocabulary has not been loaded shows source concepts that do not resolve, the diagnostic that flags an unusable schema.",
          skipped = prof$counts_skipped)),

      section(FALSE, "circle-question", "Missing data", "summariseMissingData()",
        tbl_body(prof$missing_err, "ohdsi_missing_tbl",
          blurb = "Field-level missingness per clinical table.",
          skipped = prof$missing_skipped)),

      section(FALSE, "users-rectangle", "Cohort characterisation", "CohortCharacteristics",
        local({
          tabs <- ohdsi_cohort_tables_rv()
          if (length(tabs) == 0)
            tags$p(style = muted,
              "No cohort tables found in this schema. Build and save a cohort to the schema ",
              "(a table with cohort_definition_id, subject_id, cohort_start_date, ",
              "cohort_end_date) and it will appear here for read-only characterisation.")
          else tagList(
            tags$p(style = muted,
              "Characterise a cohort already saved to this schema, read-only, with the ",
              "OHDSI standard CohortCharacteristics package. The cohort is attached to a ",
              "cdm_reference and never modified."),
            div(style = "display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin-bottom:8px;",
              selectInput("ohdsi_cohort_table", "Cohort table", choices = tabs, width = "260px"),
              checkboxInput("ohdsi_lsc", "Include large-scale characterisation (slower)", value = FALSE),
              actionButton("ohdsi_run_cohort", tagList(icon("play"), " Run characterisation"),
                           class = "btn-sm")),
            uiOutput("ohdsi_cohort_results_ui"))
        })),
      section(FALSE, "stethoscope", "Phenotype diagnostics", "PhenotypeR::cohortDiagnostics()",
        local({
          tabs <- ohdsi_cohort_tables_rv()
          if (length(tabs) == 0)
            tags$p(style = muted,
              "No cohort tables found in this schema. Save a cohort to the schema and it will appear here for PhenotypeR diagnostics.")
          else tagList(
            tags$p(style = muted,
              "Comprehensive standards diagnostics for a saved cohort via PhenotypeR: cohort counts, attrition, and characteristics stratified by sex and age group. Read-only on the attached cohort; pick a diagnostic to view after running."),
            div(style = "display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin-bottom:8px;",
              selectInput("pr_cohort_table", "Cohort table", choices = tabs, width = "260px"),
              actionButton("pr_run", tagList(icon("play"), " Run diagnostics"), class = "btn-sm")),
            uiOutput("pr_status"),
            uiOutput("pr_type_ui"),
            ohdsi_tbl_out("pr_tbl"))
        })))
  })

  # OmopSketch results rendered through the ecosystem layer: visOmopResults gt
  # tables and the OmopSketch plotTrend chart. Tables render in the active type
  # (reactable/datatable/gt) via ohdsi_table_render, degrading to a plain table
  # if the ecosystem renderer fails; the trend plot falls back to an annotated
  # blank if plotTrend cannot render.
  output$ohdsi_snapshot_tbl <- ohdsi_table_render(function() ohdsi_profile_rv()$snapshot, "snapshot")
  output$ohdsi_person_tbl   <- ohdsi_table_render(function() ohdsi_profile_rv()$person, "person")
  output$ohdsi_obs_tbl      <- ohdsi_table_render(function() ohdsi_profile_rv()$obsperiod, "obsperiod")
  output$ohdsi_counts_tbl   <- ohdsi_table_render(function() ohdsi_profile_rv()$counts, "concept_counts")
  output$ohdsi_missing_tbl  <- ohdsi_table_render(function() ohdsi_profile_rv()$missing)
  output$ohdsi_trend_tbl    <- ohdsi_table_render(function() ohdsi_profile_rv()$trend)

  output$ohdsi_trend_plot <- renderPlot({
    prof <- ohdsi_profile_rv(); res <- prof$trend; req(!is.null(res))
    p <- if (inherits(res, "summarised_result"))
           tryCatch(OmopSketch::plotTrend(res), error = function(e) NULL) else NULL
    if (is.null(p))
      p <- ggplot2::ggplot() +
        ggplot2::annotate("text", x = 1, y = 1,
          label = "Trend chart could not be rendered for this schema; see the table below.") +
        ggplot2::theme_void()
    p
  })

  # Save every available summary directly to the workspace Downloads folder as
  # one workbook (multi-sheet .xlsx, or a zip of CSVs if no Excel writer is
  # present). Direct save, not a browser download, so the file lands in
  # /home/workspace/files/Downloads with its proper name; the folder is created
  # if missing. Sheets carry the tidy (displayed) columns.
  observeEvent(input$ohdsi_export_btn, {
    prof <- ohdsi_profile_rv()
    tidy <- function(x) if (is.null(x)) NULL else ohdsi_sr_tidy(ohdsi_sr_to_df(x))
    sheets <- Filter(Negate(is.null), list(
      Snapshot           = tidy(prof$snapshot),
      Person             = tidy(prof$person),
      ObservationPeriods = tidy(prof$obsperiod),
      Trend              = tidy(prof$trend),
      ConceptIdCounts    = tidy(prof$counts),
      MissingData        = tidy(prof$missing)))
    if (length(sheets) == 0) {
      showNotification("No OHDSI summaries to export yet.", type = "warning"); return()
    }
    if (!.ensure_downloads()) {
      showNotification(sprintf("Downloads folder is not writable: %s", DOWNLOADS_DIR),
                       type = "error", duration = 8); return()
    }
    fname <- sprintf("ohdsi_profile_%s_%s.%s",
               gsub("[^A-Za-z0-9_-]", "_", prof$schema %||% "schema"),
               format(Sys.time(), "%Y%m%d_%H%M%S"), ohdsi_export_ext())
    dest  <- file.path(DOWNLOADS_DIR, fname)
    ok <- tryCatch({ ohdsi_write_export(sheets, dest); file.exists(dest) },
                   error = function(e) {
                     showNotification(paste("Export failed:", conditionMessage(e)),
                                      type = "error", duration = 8); FALSE })
    if (isTRUE(ok))
      showNotification(tagList(icon("circle-check"),
        sprintf(" Saved to Downloads: %s", fname)), type = "message", duration = 6)
  })

  # ── Cohort characterisation (v10.14) ──────────────────────────────────────
  # Read-only: attach an existing saved cohort table to a cdm_reference and run
  # CohortCharacteristics. Heavy work runs only on the Run button, never on
  # schema change. Results cached in ohdsi_cohort_result_rv until schema changes.
  run_cohort_char <- function(cohort_table, include_lsc) {
    schemas <- isolate(input$schema_select) %||% character(0)
    if (length(schemas) == 0 || !nzchar(cohort_table %||% "")) return(invisible())
    schema <- schemas[1]
    con <- ensure_ohdsi_con()
    if (is.null(con)) {
      ohdsi_cohort_result_rv(list(schema = schema, table = cohort_table,
        err = "No OHDSI-compatible connection available.")); return(invisible())
    }
    cdm <- ohdsi_build_cohort_cdm(con, schema, cohort_table)
    coh <- if (is.null(cdm)) NULL else tryCatch(cdm[[cohort_table]], error = function(e) NULL)
    if (is.null(coh)) {
      ohdsi_cohort_result_rv(list(schema = schema, table = cohort_table,
        err = sprintf("Could not attach cohort table '%s'. The schema may restrict the writes CDMConnector needs, or the table is not a valid cohort table.", cohort_table)))
      return(invisible())
    }
    char_err <- NULL
    char <- tryCatch(CohortCharacteristics::summariseCharacteristics(coh),
                     error = function(e) { char_err <<- conditionMessage(e); NULL })
    attr_err <- NULL
    attrn <- tryCatch(CohortCharacteristics::summariseCohortAttrition(coh),
                      error = function(e) { attr_err <<- conditionMessage(e); NULL })
    lsc <- NULL; lsc_err <- NULL
    if (isTRUE(include_lsc)) {
      setProgress(0.7, detail = "Large-scale characterisation")
      # eventInWindow/episodeInWindow are not time windows - they name which OMOP
      # domain tables to scan for features around the index date, and at least
      # one is required. Default to the standard clinical event tables present
      # (the CohortDiagnostics baseline), with the era tables as episodes.
      present <- tryCatch(names(cdm), error = function(e) character(0))
      ev_tabs <- intersect(c("condition_occurrence", "drug_exposure",
                             "procedure_occurrence", "measurement", "observation",
                             "device_exposure", "visit_occurrence"), present)
      ep_tabs <- intersect(c("drug_era", "condition_era"), present)
      if (length(ev_tabs) == 0 && length(ep_tabs) == 0) {
        lsc_err <- "No event or episode tables present in the cohort's cdm to characterise."
      } else {
        lsc <- tryCatch(
          CohortCharacteristics::summariseLargeScaleCharacteristics(coh,
            eventInWindow   = if (length(ev_tabs)) ev_tabs else NULL,
            episodeInWindow = if (length(ep_tabs)) ep_tabs else NULL),
          error = function(e) { lsc_err <<- conditionMessage(e); NULL })
      }
    }
    ohdsi_cohort_result_rv(list(
      schema = schema, table = cohort_table, err = NULL,
      char = char, char_err = char_err,
      attrition = attrn, attrition_err = attr_err,
      lsc = lsc, lsc_err = lsc_err, include_lsc = isTRUE(include_lsc)))
  }

  observeEvent(input$ohdsi_run_cohort, {
    withProgress(message = "Cohort characterisation\u2026", value = 0.3, {
      run_cohort_char(input$ohdsi_cohort_table %||% "", isTRUE(input$ohdsi_lsc))
    })
  })

  # Results block (separate uiOutput so running does not re-render the controls).
  output$ohdsi_cohort_results_ui <- renderUI({
    r <- ohdsi_cohort_result_rv()
    if (length(r) == 0) return(NULL)
    muted <- "font-size:0.84rem;color:var(--dre-muted);margin-top:6px;"
    amber <- function(msg) div(
      style = "padding:8px 10px;margin-top:6px;border-left:3px solid var(--dre-warn);background:rgba(0,0,0,0.15);border-radius:4px;",
      tags$p(style = "margin:0;color:var(--dre-warn);font-size:0.86rem;",
        icon("triangle-exclamation"), " ", msg))
    if (!is.null(r$err)) return(amber(r$err))
    tagList(
      tags$h5(style = "margin:10px 0 2px;color:var(--dre-text);font-size:0.9rem;",
        "Characteristics", tags$span(style = muted, sprintf(" cohort table: %s", r$table))),
      if (!is.null(r$char_err)) amber(sprintf("Characteristics unavailable: %s", r$char_err))
      else ohdsi_tbl_out("ohdsi_cohort_char_tbl"),
      tags$h5(style = "margin:14px 0 2px;color:var(--dre-text);font-size:0.9rem;", "Attrition"),
      if (!is.null(r$attrition_err))
        amber(sprintf("Attrition unavailable: %s. The cohort may have been saved without its attrition companion table.", r$attrition_err))
      else ohdsi_tbl_out("ohdsi_cohort_attr_tbl"),
      if (isTRUE(r$include_lsc)) tagList(
        tags$h5(style = "margin:14px 0 2px;color:var(--dre-text);font-size:0.9rem;",
          "Large-scale characteristics"),
        if (!is.null(r$lsc_err)) amber(sprintf("Large-scale characterisation unavailable: %s", r$lsc_err))
        else ohdsi_tbl_out("ohdsi_cohort_lsc_tbl")))
  })

  output$ohdsi_cohort_char_tbl <- ohdsi_table_render(
    function() ohdsi_cohort_result_rv()$char, "characteristics")
  output$ohdsi_cohort_attr_tbl <- ohdsi_table_render(
    function() ohdsi_cohort_result_rv()$attrition, "attrition")
  output$ohdsi_cohort_lsc_tbl <- ohdsi_table_render(
    function() ohdsi_cohort_result_rv()$lsc, "visomop")

  # ── PhenotypeR cohort diagnostics (v11) ───────────────────────────────────
  # Comprehensive standards diagnostics for a saved cohort via PhenotypeR:
  # counts, attrition, and characteristics stratified by sex and age group, in a
  # single summarised_result. The call falls back across PhenotypeR versions and
  # skips the matched diagnostic where supported, to stay fast and setup-free.
  # The multi-part result is browsed with a result-type selector and rendered
  # through the shared OHDSI table layer.
  run_phenotyper <- function(cohort_table) {
    pr_result_rv(NULL); pr_status_rv(NULL)
    if (!ohdsi_pkgs_available() || !requireNamespace("PhenotypeR", quietly = TRUE)) {
      pr_status_rv("PhenotypeR is not available in this workspace."); return(invisible())
    }
    if (!nzchar(cohort_table %||% "")) {
      pr_status_rv("Select a cohort table first."); return(invisible())
    }
    schema <- primary_schema(input$schema_select %||% character(0))
    cdm <- get_cohort_cdm(schema, cohort_table)
    coh <- if (is.null(cdm)) NULL else tryCatch(cdm[[cohort_table]], error = function(e) NULL)
    if (is.null(coh)) {
      pr_status_rv(sprintf("Could not attach cohort table '%s'. The schema may restrict the writes CDMConnector needs, or the table is not a valid cohort table.", cohort_table))
      return(invisible())
    }
    # cohortDiagnostics arguments vary across PhenotypeR versions (this workspace
    # rejects `survival`), so try progressively simpler calls and keep the first
    # that returns results. matchedSample = 0 / match = FALSE skip the matched
    # diagnostic where supported; the bare call uses whatever defaults exist.
    variants <- list(
      function() PhenotypeR::cohortDiagnostics(coh, matchedSample = 0),
      function() PhenotypeR::cohortDiagnostics(coh, match = FALSE),
      function() PhenotypeR::cohortDiagnostics(coh))
    sr <- NULL
    for (v in variants) {
      r <- tryCatch(v(), error = function(e) {
        message("[phenotyper] cohortDiagnostics variant failed: ", conditionMessage(e)); NULL })
      if (!is.null(r) && tryCatch(nrow(r) > 0, error = function(e) FALSE)) { sr <- r; break }
    }
    if (is.null(sr)) {
      pr_status_rv("PhenotypeR returned no results for this cohort. See the app log."); return(invisible())
    }
    pr_result_rv(sr)
  }

  observeEvent(input$pr_run, {
    withProgress(message = "PhenotypeR cohort diagnostics\u2026", value = 0.4, {
      run_phenotyper(input$pr_cohort_table %||% "")
    })
  })

  output$pr_status <- renderUI({
    msg <- pr_status_rv(); if (is.null(msg)) return(NULL)
    tags$div(style = "font-size:0.87rem;color:var(--dre-muted);padding:6px 0;",
      icon("circle-info"), " ", msg)
  })

  output$pr_type_ui <- renderUI({
    sr <- pr_result_rv(); req(!is.null(sr))
    types <- tryCatch(sort(unique(omopgenerics::settings(sr)$result_type)),
                      error = function(e) character(0))
    types <- types[nzchar(types)]
    if (length(types) == 0) return(NULL)
    labels <- ohdsi_humanise(types); ch <- types; names(ch) <- labels
    div(style = "margin:6px 0;",
      selectInput("pr_type", "Diagnostic", choices = ch, width = "320px"))
  })

  output$pr_tbl <- ohdsi_table_render(function() {
    sr <- pr_result_rv(); sel <- input$pr_type
    req(!is.null(sr), !is.null(sel), nzchar(sel))
    sub <- tryCatch(omopgenerics::filterSettings(sr, result_type == sel),
                    error = function(e) NULL)
    if (is.null(sub) || tryCatch(nrow(sub) == 0, error = function(e) TRUE)) NULL else sub
  }, "visomop")

  # ── Write cohort CDM to a database schema (v10.14) ────────────────────────
  # Pure core SQL (server-side CTAS over xap.conn); no OHDSI packages. The OHDSI
  # Tools tab discovers the resulting cohort table independently.
  observeEvent(input$ohdsi_write_db_btn, {
    res <- cohort_result_rv()
    if (is.null(res) || nrow(res) == 0) {
      showNotification("Run the cohort query first.", type = "warning"); return()
    }
    if (!"index_date" %in% names(res)) {
      showNotification("This cohort has no index_date, so a valid cohort table cannot be written.",
                       type = "error", duration = 8); return()
    }
    target <- trimws(input$ohdsi_write_schema %||% "")
    if (!nzchar(target)) {
      showNotification("Enter a name for the new schema.", type = "warning"); return()
    }
    schema  <- primary_schema(input$schema_select %||% character(0))
    col_map <- omop_col_map_rv()
    nm <- trimws(input$extract_cohort_name %||% "cohort"); if (!nzchar(nm)) nm <- "cohort"
    inc <- Filter(function(c) identical(c$type, "inclusion"), criteria_rv())
    def_json <- if (length(inc) > 0)
      tryCatch(serialise_cohort_def(criteria_rv(), cohort_name = nm,
                 index_strategy    = input$index_strategy %||% "first_qualifying",
                 prior_obs_days    = prior_obs_days_rv(),
                 min_followup_days = min_followup_days_rv()),
               error = function(e) NULL) else NULL
    out <- withProgress(message = "Writing cohort CDM to database\u2026", value = 0, {
      materialise_cohort_to_schema(
        source_schema = schema, col_map = col_map, cohort_result = res,
        target_schema = target, cohort_name = nm,
        include_vocab = isTRUE(input$ohdsi_write_vocab), definition_json = def_json,
        progress_fn = function(tbl, i, total) setProgress(i / total, detail = tbl))
    })
    ohdsi_write_result_rv(out)
    if (isTRUE(out$ok))
      showNotification(sprintf("Cohort CDM written to schema '%s' (%d tables).",
                               out$schema, length(out$status$created)),
                       type = "message", duration = 7)
    else
      showNotification(out$msg, type = "error", duration = 9)
  })

  output$ohdsi_write_status_ui <- renderUI({
    out <- ohdsi_write_result_rv()
    if (is.null(out)) return(NULL)
    muted <- "font-size:0.84rem;color:var(--dre-muted);margin-top:8px;"
    if (!isTRUE(out$ok))
      return(div(style = "margin-top:8px;color:var(--dre-danger);font-size:0.86rem;",
                 icon("circle-exclamation"), " ", out$msg))
    st <- out$status
    tagList(
      tags$p(style = "margin-top:10px;color:var(--dre-success);font-size:0.9rem;",
        icon("circle-check"),
        sprintf(" Wrote %d tables to schema '%s'.", length(st$created), out$schema)),
      tags$p(style = muted, tags$strong("Created: "), paste(sort(st$created), collapse = ", ")),
      if (length(st$skipped) > 0)
        tags$p(style = muted, tags$strong("Skipped: "),
          paste(sprintf("%s (%s)", st$skipped,
                        vapply(st$skipped, function(t) st$errors[[t]] %||% "", character(1))),
                collapse = "; ")),
      tags$p(style = muted,
        "Open the OHDSI Tools tab and select this schema to characterise the cohort.")
    )
  })

  # Close the parallel connection when the session ends.
  session$onSessionEnded(function() {
    con <- isolate(ohdsi_con_rv())
    if (!is.null(con)) try(DBI::dbDisconnect(con), silent = TRUE)
  })

} # end server

# ── v10: set a future plan if AIRA is enabled in this session.
# Without an explicit plan, future_promise falls back to sequential execution
# which blocks the Shiny event loop while AIRA inference runs. We only
# activate workers when AIRA is actually enabled to avoid creating unused
# worker processes in workspaces where the feature is off.
if (aira_is_enabled()) {
  tryCatch({
    if (requireNamespace("future", quietly = TRUE)) {
      future::plan(future::multisession, workers = 2L)
      message("[ cohort builder ] AIRA enabled; future::multisession plan set with 2 workers")
    }
  }, error = function(e) {
    message("[ cohort builder ] could not set future plan: ", conditionMessage(e),
            "  AIRA will run synchronously (UI may briefly block during inference)")
  })
}

shinyApp(ui, server)
